insert into public.recipes (id, doc, status) values ('turkey_black_bean_chili', '{"id":"turkey_black_bean_chili","name":"Turkey & black bean chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"black_beans","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"broth","q":400},{"f":"olive_oil","q":15}],"steps":["Warm the oil in a heavy pot over medium-high. Brown the turkey, breaking it up, about 5 minutes.","Add the diced onion and bell pepper; cook until soft, 4 minutes. Stir in the minced garlic, chili powder and cumin for 30 seconds until fragrant.","Pour in the crushed tomatoes, broth and drained beans. Bring to a simmer.","Drop the heat to low and simmer uncovered 25 minutes, stirring now and then, until thick.","Taste, season, and serve — it is even better the next day."],"tip":"Freezes beautifully in single portions for no-effort future dinners."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cobb_chicken_salad', '{"id":"cobb_chicken_salad","name":"Chopped chicken Cobb salad","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"romaine","q":1},{"f":"eggs","q":2},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":140},{"f":"cheddar","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Hard-boil the eggs (10 minutes), cool in cold water, peel and quarter.","Season the chicken and sear in a skillet over medium-high, 5–6 minutes per side, until cooked through. Rest, then slice.","Chop the romaine and arrange in wide bowls. Halve the tomatoes, dice the avocado.","Row up the chicken, eggs, avocado, tomatoes and cheddar over the lettuce.","Whisk the olive oil with the lemon’s juice, a pinch of salt and pepper; dress just before eating."],"tip":"Everything but the avocado and dressing can be prepped a day ahead."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_oat_pancakes', '{"id":"banana_oat_pancakes","name":"Banana oat pancakes","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"banana","q":2},{"f":"oats","q":120},{"f":"eggs","q":2},{"f":"milk","q":120},{"f":"cinnamon","q":2},{"f":"butter","q":10},{"f":"honey","q":20}],"steps":["Blitz the oats in a blender until floury. Add the bananas, eggs, milk and cinnamon; blend until smooth. Rest 5 minutes to thicken.","Heat a nonstick skillet over medium and slick with a little butter.","Pour quarter-cup rounds and cook until bubbles pop on top, about 2 minutes.","Flip and cook 1–2 minutes more until golden.","Stack and finish with the honey."],"tip":"Spottier bananas mean sweeter pancakes — this is what those two sad ones are for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fried_rice', '{"id":"chicken_fried_rice","name":"Better-than-takeout chicken fried rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free"],"allergens":["eggs","soy","gluten"],"time":25,"servings":2,"ing":[{"f":"rice","q":180},{"f":"chicken_thigh","q":250},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20}],"steps":["Cook the rice ahead if you can — cold, dry rice fries best.","Stir-fry the diced chicken in half the oil over high heat until golden, 4–5 minutes; set aside.","Scramble the eggs in the pan, then add the remaining oil with the diced carrot, peas, ginger and garlic; fry 2 minutes.","Add the rice, pressing it into the hot pan; let it crackle 1 minute before tossing.","Return the chicken, splash in the soy sauce, toss with sliced scallions and serve."],"tip":"High heat and a crowded-pan intolerance are the two rules of fried rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tofu_stirfry', '{"id":"ginger_tofu_stirfry","name":"Crispy ginger-garlic tofu stir-fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"broccoli","q":450},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20}],"steps":["Press the tofu 10 minutes between towels, then cube it. Start the rice.","Sear the tofu in half the oil over medium-high, undisturbed 3 minutes a side, until deeply golden. Set aside.","Stir-fry the broccoli florets and sliced pepper in the rest of the oil, 4 minutes, until crisp-tender.","Add the grated ginger and minced garlic for 30 seconds, then return the tofu with the soy sauce and toss to glaze.","Serve over the rice, showered with sliced scallions."],"tip":"A dry pan-side and patience make tofu crispy — poking it early makes it stick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_salmon_bowl', '{"id":"honey_garlic_salmon_bowl","name":"Honey-garlic salmon rice bowl","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"honey","q":30},{"f":"soy_sauce","q":30},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"broccoli","q":450},{"f":"scallions","q":0.5}],"steps":["Start the rice; steam the broccoli florets over it for the final 5 minutes.","Stir the honey, soy sauce and minced garlic into a glaze.","Sear the salmon skin-side down in a hot skillet, 4 minutes, then flip for 2.","Pour the glaze around the fish and let it bubble and thicken 1–2 minutes, spooning it over.","Build bowls: rice, broccoli, salmon, extra glaze, sliced scallions."],"tip":"Pull the salmon while its center is still deep pink — it finishes in the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_masala', '{"id":"chana_masala","name":"Chana masala","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"crushed_tomatoes","q":300},{"f":"curry_powder","q":10},{"f":"cumin","q":4},{"f":"cilantro","q":0.3},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Soften the diced onion in the oil over medium heat, 6–8 minutes, until golden at the edges.","Add the minced garlic, grated ginger, curry powder and cumin; fry 1 minute until the pan smells incredible.","Pour in the crushed tomatoes and simmer 5 minutes until slightly darkened.","Add the drained chickpeas with a splash of water; simmer 10 minutes, mashing a few against the pot to thicken the sauce.","Season, shower with chopped cilantro, and serve over the rice."],"tip":"The long onion sauté is the flavor foundation — don’t rush those first minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_chicken_curry', '{"id":"coconut_chicken_curry","name":"Coconut chicken curry","emoji":"🥥","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"coconut_milk","q":200},{"f":"curry_powder","q":12},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"tomato","q":2},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Brown the chicken pieces in the oil over medium-high, about 4 minutes; set aside.","Soften the diced onion in the same pot, 5 minutes, then add garlic, ginger and curry powder for 1 minute.","Add the chopped tomatoes and cook until they slump, 3 minutes.","Return the chicken, pour in the coconut milk, and simmer gently 15 minutes until the sauce coats a spoon.","Season and serve over rice."],"tip":"Thighs stay juicy through the simmer — this is exactly what they are for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_dal', '{"id":"spinach_dal","name":"Spinach dal","emoji":"🥬","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"cumin","q":5},{"f":"curry_powder","q":8},{"f":"rice","q":120},{"f":"olive_oil","q":15}],"steps":["Rinse the lentils and simmer in 3 cups of water until tender, 20–25 minutes, skimming any foam.","Meanwhile cook the rice, and fry the diced onion in the oil until deeply golden, 8 minutes.","Add the garlic, ginger, cumin and curry powder to the onions for 1 minute.","Fold the spiced onions into the lentils, add the spinach, and simmer 3 minutes until wilted and thick.","Season generously and serve with the rice."],"tip":"The fried-onion finish (tadka) is the difference between fine dal and great dal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('marinara_spaghetti', '{"id":"marinara_spaghetti","name":"Garlic-basil marinara spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"crushed_tomatoes","q":400},{"f":"garlic","q":0.4},{"f":"onion","q":0.5},{"f":"basil","q":0.3},{"f":"olive_oil","q":25},{"f":"parmesan","q":30}],"steps":["Sizzle the sliced garlic and diced onion in the olive oil over medium-low until soft and fragrant, 5 minutes — no color.","Add the crushed tomatoes with a pinch of salt; simmer 15 minutes until glossy.","Cook the spaghetti in well-salted water to just shy of al dente; reserve a cup of pasta water.","Drag the pasta into the sauce with a splash of its water and toss over heat 1 minute until the sauce clings.","Tear in the basil, twirl into bowls, and finish with grated parmesan."],"tip":"Finishing the pasta *in* the sauce is the entire trick of Italian pasta."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_pomodoro_mozzarella', '{"id":"chicken_pomodoro_mozzarella","name":"Skillet chicken pomodoro with mozzarella","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"crushed_tomatoes","q":300},{"f":"garlic","q":0.3},{"f":"mozzarella","q":100},{"f":"basil","q":0.3},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15}],"steps":["Halve the chicken breasts horizontally into cutlets, season, and sear in the oil 3 minutes per side; set aside.","Fry the sliced garlic in the same skillet 30 seconds, then add the crushed tomatoes and simmer 8 minutes.","Meanwhile cook the spaghetti in salted water.","Nestle the chicken back into the sauce, top each cutlet with mozzarella, cover 3 minutes until melted.","Serve over the spaghetti with torn basil."],"tip":"Thin cutlets cook fast and stay tender — thick breasts do neither."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_parmesan_frittata', '{"id":"zucchini_parmesan_frittata","name":"Zucchini-parmesan frittata","emoji":"🍳","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":1},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Sauté the thinly sliced zucchini and onion in the oil in an ovenproof skillet until soft and lightly golden, 6 minutes.","Whisk the eggs with most of the parmesan, the salt and pepper.","Pour the eggs over the vegetables on medium-low; cook undisturbed until the edges set, 4 minutes.","Scatter the remaining parmesan on top and finish under the broiler 2–3 minutes until puffed and golden.","Rest 2 minutes, slice into wedges, eat warm or room-temperature."],"tip":"A frittata is dinner insurance — any vegetable in the crisper works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chopped_pita_plate', '{"id":"greek_chopped_pita_plate","name":"Greek chopped salad pita plate","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"onion","q":0.3},{"f":"oregano","q":2},{"f":"olive_oil","q":20},{"f":"pita","q":2},{"f":"hummus","q":120},{"f":"romaine","q":0.5}],"steps":["Chop the cucumber, tomatoes and romaine; slice the onion paper-thin.","Toss the vegetables with the olive oil, oregano and a pinch of salt.","Warm the pitas in a dry skillet 30 seconds per side.","Swoosh the hummus across two plates, pile the salad over, and crumble the feta on top.","Serve with the warm pitas for scooping."],"tip":"Salting the tomatoes five minutes early deepens the whole salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_oregano_salmon', '{"id":"lemon_oregano_salmon","name":"Lemon-oregano salmon over garlicky spinach","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["fish"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"spinach","q":200},{"f":"garlic","q":0.2}],"steps":["Rub the salmon with half the oil, the oregano, salt and the zest of the lemon.","Sear skin-side down in a hot skillet 4 minutes; flip for 2 more, then rest on a plate.","In the same pan, sizzle the sliced garlic in the remaining oil for 30 seconds.","Pile in the spinach and toss just until collapsed, 1 minute.","Plate the spinach under the salmon and finish everything with the lemon’s juice."],"tip":"Zest before you juice — it is impossible the other way around."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_quinoa_bowl', '{"id":"mediterranean_quinoa_bowl","name":"Mediterranean chickpea-quinoa bowl","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","sesame"],"time":25,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"chickpeas","q":250},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":140},{"f":"feta","q":60},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"hummus","q":80}],"steps":["Rinse the quinoa and simmer in double its volume of salted water until the germ spirals out, 15 minutes. Fluff.","Crisp the drained chickpeas in a dry skillet with a pinch of salt, 5 minutes.","Dice the cucumber, halve the tomatoes, and whisk the lemon juice with the olive oil.","Build bowls: quinoa, chickpeas, vegetables, a swoosh of hummus.","Crumble the feta over and dress with the lemon oil."],"tip":"Toasting cooked chickpeas gives bean-haters something to reconsider."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salsa_chicken_tacos', '{"id":"salsa_chicken_tacos","name":"Weeknight salsa-braised chicken tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"salsa","q":200},{"f":"onion","q":0.5},{"f":"tortillas","q":6},{"f":"avocado","q":1},{"f":"cilantro","q":0.3},{"f":"lime","q":1}],"steps":["Sear the chicken thighs in a hot skillet 3 minutes per side.","Pour the salsa over with a splash of water, cover, and simmer 12 minutes until the chicken shreds easily.","Shred the chicken into the sauce and let it soak up the pan juices.","Char the tortillas directly over the flame or in a dry skillet, seconds per side.","Fill with chicken, sliced avocado, diced raw onion, cilantro, and a squeeze of lime."],"tip":"A good jarred salsa is a legitimate braising liquid — this is the shortcut that tastes like it wasn’t."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_burrito_bowls', '{"id":"black_bean_burrito_bowls","name":"Black bean burrito bowls","emoji":"🥣","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"rice","q":160},{"f":"black_beans","q":400},{"f":"corn_frozen","q":120},{"f":"salsa","q":150},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"cheddar","q":50},{"f":"sour_cream","q":60}],"steps":["Cook the rice, then fold in the lime zest and half its juice.","Warm the beans with a splash of water and a pinch of cumin or salt; char the corn in a dry skillet 3 minutes.","Halve and slice the avocado.","Build bowls: lime rice, beans, corn, salsa.","Top with cheddar, a spoon of sour cream, cilantro, avocado, and the rest of the lime."],"tip":"Charring frozen corn straight from the bag is a free flavor upgrade."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_lettuce_wraps', '{"id":"turkey_taco_lettuce_wraps","name":"Turkey taco lettuce wraps","emoji":"🥬","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"onion","q":0.5},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Brown the turkey in the oil over medium-high, breaking it up, 5 minutes.","Add the diced onion, chili powder and cumin; cook 3 minutes more, then splash in water to make it saucy.","Separate the romaine into cup-shaped leaves; dice the tomato and avocado.","Spoon the spiced turkey into the leaves.","Top with tomato and avocado and finish with lime."],"tip":"Double the filling and tomorrow’s lunch is a taco salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_tofu_scramble', '{"id":"curried_tofu_scramble","name":"Curried tofu scramble","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":["soy"],"time":15,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"spinach","q":80},{"f":"curry_powder","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":2}],"steps":["Warm the oil in a skillet over medium and soften the diced onion and pepper, 4 minutes.","Crumble in the tofu with your hands — ragged pieces catch the seasoning best.","Sprinkle over the curry powder and salt; fry 4–5 minutes until the tofu dries out a little and takes color.","Fold in the spinach until just wilted.","Taste, season harder than you think, and serve hot."],"tip":"Firm tofu, well crumbled, has scrambled-egg texture without trying to be eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pb_banana_oatmeal', '{"id":"pb_banana_oatmeal","name":"Peanut butter banana oatmeal","emoji":"🥜","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"oats","q":120},{"f":"banana","q":2},{"f":"peanut_butter","q":40},{"f":"cinnamon","q":2},{"f":"honey","q":15}],"steps":["Simmer the oats in 2 cups of water with a pinch of salt, stirring, 5 minutes.","Mash one banana straight into the pot — it sweetens and creams the oats.","Swirl in the peanut butter and cinnamon off the heat.","Slice the second banana over the top.","Finish with a thread of honey."],"tip":"Mashed banana does the work of milk and sugar in one move."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_chickpea_spinach_curry', '{"id":"coconut_chickpea_spinach_curry","name":"Coconut chickpea & spinach curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"coconut_milk","q":250},{"f":"spinach","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":10},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Fry the diced onion in the oil until golden, 6 minutes.","Add the garlic, ginger and curry powder; toast 1 minute.","Pour in the coconut milk and drained chickpeas; simmer 10 minutes until slightly thickened.","Stir in the spinach to wilt.","Season and serve over the rice."],"tip":"Simmer coconut milk gently — a hard boil splits it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_lentil_soup', '{"id":"lemon_lentil_soup","name":"Lemony Mediterranean lentil soup","emoji":"🍲","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"carrots","q":120},{"f":"celery","q":80},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":4},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Soften the diced onion, carrot and celery in the oil over medium, 6 minutes.","Add the garlic and cumin for 1 minute.","Add the rinsed lentils and 4 cups of water; simmer 25 minutes until tender.","Blend half the pot (or mash roughly) for body, leaving the rest chunky.","Finish with the lemon’s juice and a swirl of olive oil — the lemon is not optional."],"tip":"Acid at the end is what separates restaurant lentil soup from sad lentil soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_tacos', '{"id":"sweet_potato_black_bean_tacos","name":"Roasted sweet potato & black bean tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":450},{"f":"black_beans","q":300},{"f":"tortillas","q":6},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 425°F. Toss the diced sweet potatoes with oil, chili powder and cumin; roast 25 minutes until browned at the edges.","Warm the beans with a splash of water and a pinch of salt.","Mash the avocado with the lime’s juice.","Char the tortillas in a dry skillet.","Build: avocado smear, beans, sweet potatoes, cilantro."],"tip":"Sweet + smoky + creamy is why nobody misses the meat here."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quinoa_stuffed_peppers', '{"id":"quinoa_stuffed_peppers","name":"Quinoa-stuffed bell peppers","emoji":"🫑","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"quinoa","q":130},{"f":"black_beans","q":250},{"f":"corn_frozen","q":100},{"f":"crushed_tomatoes","q":200},{"f":"cumin","q":4},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Cook the quinoa. Heat the oven to 400°F.","Sauté the diced onion in oil, then stir in beans, corn, crushed tomatoes, cumin and the cooked quinoa; simmer 3 minutes.","Halve the peppers through the stem and seed them.","Pack the filling into the pepper halves, add a splash of water to the dish, cover with foil.","Bake 25 minutes covered, then 5 uncovered until the peppers are tender but standing."],"tip":"Halved peppers cook faster and hold more filling than the upright classic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hummus_veggie_pita_pockets', '{"id":"hummus_veggie_pita_pockets","name":"Hummus & crunch pita pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":10,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":160},{"f":"cucumber","q":1},{"f":"tomato","q":1},{"f":"romaine","q":0.5},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10}],"steps":["Halve the pitas and open the pockets.","Slice the cucumber and tomato thin; shred the romaine.","Toss the vegetables with lemon juice, olive oil and a pinch of salt.","Spread hummus generously inside each pocket.","Stuff with the dressed crunch and eat immediately."],"tip":"Dress the vegetables, not the bread — soggy pita is a preventable tragedy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_fried_rice', '{"id":"vegetable_fried_rice","name":"Ginger vegetable fried rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":20,"servings":2,"ing":[{"f":"rice","q":180},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"corn_frozen","q":80},{"f":"scallions","q":0.5},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"olive_oil","q":20}],"steps":["Use cold cooked rice if you have it; fresh rice should cool spread on a plate 10 minutes.","Stir-fry the diced carrots in the oil over high heat, 3 minutes.","Add peas, corn, ginger and garlic; fry 2 minutes more.","Add the rice, press flat, and let it sizzle untouched 1 minute before tossing.","Season with soy sauce, toss with scallions, serve hot."],"tip":"The untouched minute is where fried rice gets its toasty edges."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lentil_soup', '{"id":"coconut_lentil_soup","name":"Coconut red-spiced lentil soup","emoji":"🥥","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"coconut_milk","q":200},{"f":"crushed_tomatoes","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":10},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Soften the diced onion in the oil, 5 minutes; add garlic, ginger and curry powder for 1 minute.","Add the rinsed lentils, crushed tomatoes and 3 cups of water.","Simmer 20–25 minutes until the lentils collapse into the broth.","Stir in the coconut milk and warm through without boiling.","Brighten with lime juice and serve."],"tip":"Lentils + coconut is the highest comfort-per-dollar ratio in the kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_avocado_toast', '{"id":"smashed_chickpea_avocado_toast","name":"Smashed chickpea avocado toast","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"chickpeas","q":250},{"f":"avocado","q":1},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"black_pepper","q":1},{"f":"salt","q":2}],"steps":["Toast the bread properly — deep golden, not beige.","Fork-smash the drained chickpeas with the avocado, lemon juice, salt and pepper. Leave it chunky.","Pile onto the toast.","Finish with olive oil and more pepper.","Eat over a plate; this is structural-integrity-optional food."],"tip":"Chickpeas double the protein and make avocado toast an actual meal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_tofu_rice_bowl', '{"id":"peanut_tofu_rice_bowl","name":"Peanut-sauce tofu rice bowl","emoji":"🥣","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","nuts","gluten"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":25},{"f":"lime","q":1},{"f":"honey","q":15},{"f":"garlic","q":0.2},{"f":"rice","q":160},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":15}],"steps":["Start the rice. Press and cube the tofu, then sear in the oil until golden on two sides, 8 minutes total.","Whisk the peanut butter with soy sauce, lime juice, honey, grated garlic and 3–4 tablespoons of hot water into a pourable sauce.","Ribbon the carrots with a peeler; slice the cucumber.","Toss the hot tofu in half the sauce to glaze.","Bowl the rice, tofu and vegetables; drizzle the rest of the sauce over."],"tip":"Hot water is the secret to a silky peanut sauce that doesn’t seize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_tomato_ratatouille', '{"id":"zucchini_tomato_ratatouille","name":"Weeknight ratatouille skillet","emoji":"🍅","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"crushed_tomatoes","q":400},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"olive_oil","q":25}],"steps":["Brown the sliced zucchini hard in half the oil over medium-high, 5 minutes; set aside.","Soften the sliced onion and pepper in the rest of the oil, 5 minutes.","Add the garlic and oregano, then the crushed tomatoes; simmer 10 minutes.","Return the zucchini and simmer 5 more, until everything is silky but not mush.","Tear in the basil and serve — alone, over rice, or under a fried egg."],"tip":"Browning the zucchini separately keeps it from watering down the stew."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_rice_bean_skillet', '{"id":"mexican_rice_bean_skillet","name":"One-pan Mexican rice & beans","emoji":"🍳","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"black_beans","q":300},{"f":"salsa","q":200},{"f":"corn_frozen","q":100},{"f":"onion","q":0.5},{"f":"cumin","q":4},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil with the cumin, 3 minutes.","Stir in the rice to coat, then add the salsa and 1½ cups of water.","Cover and simmer low 15 minutes.","Scatter the beans and corn on top, cover again 5 minutes until the rice is tender.","Fluff, fold everything together, finish with lime and cilantro."],"tip":"The salsa is doing the work of six ingredients — buy one you would eat with a spoon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_quinoa_pilaf', '{"id":"mushroom_quinoa_pilaf","name":"Mushroom & spinach quinoa pilaf","emoji":"🍄","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Cook the quinoa in salted water, 15 minutes, and fluff.","Meanwhile brown the sliced mushrooms in the oil over medium-high — crowd them less than feels natural — 6 minutes.","Add the diced onion and garlic; soften 3 minutes.","Fold in the spinach to wilt, then the quinoa.","Season and finish with lemon juice."],"tip":"Mushrooms brown only after their water burns off — patience, then flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_chili', '{"id":"sweet_potato_chili","name":"Smoky sweet potato & bean chili","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"chili_powder","q":10},{"f":"cumin","q":5},{"f":"corn_frozen","q":100},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil, 4 minutes; add garlic and the spices for 1 minute.","Add the diced sweet potatoes, crushed tomatoes and 2 cups of water.","Simmer 20 minutes until the sweet potato is fork-tender.","Add the beans and corn; simmer 5 more minutes.","Mash a few sweet potato chunks against the pot to thicken, season, serve."],"tip":"Sweet potato rounds out chili heat the way sugar never quite does."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_oatmeal', '{"id":"apple_cinnamon_oatmeal","name":"Apple pie oatmeal","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":[],"time":15,"servings":2,"ing":[{"f":"oats","q":120},{"f":"apple","q":2},{"f":"cinnamon","q":3},{"f":"honey","q":20},{"f":"almonds","q":30}],"steps":["Dice one apple and simmer it in 2 cups of water with the cinnamon, 3 minutes.","Add the oats and a pinch of salt; simmer 5 minutes, stirring.","Grate the second apple straight into the pot and stir through.","Sweeten with honey to taste.","Top with roughly chopped almonds for crunch."],"tip":"Grated apple melts into the oats; diced apple stays tender-crisp — using both is the trick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_chickpea_greek_salad', '{"id":"crispy_chickpea_greek_salad","name":"Crispy chickpea Greek salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":140},{"f":"onion","q":0.3},{"f":"oregano","q":3},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Dry the chickpeas well, then crisp them in half the oil in a skillet with the oregano and a pinch of salt, 8–10 minutes.","Chop the romaine, cucumber and halve the tomatoes; shave the onion thin.","Whisk the lemon juice with the remaining oil.","Toss the vegetables with the dressing.","Top with the hot, crackly chickpeas and eat while they still crunch."],"tip":"Hot-on-cold is the move — warm chickpeas soften the onion’s bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_sweet_potato_soup', '{"id":"coconut_sweet_potato_soup","name":"Coconut-ginger sweet potato soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"coconut_milk","q":250},{"f":"ginger","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil, 5 minutes; add the garlic and grated ginger for 1 minute.","Add the peeled, cubed sweet potatoes and 2½ cups of water; simmer 18 minutes until completely tender.","Blend smooth (an immersion blender straight in the pot is easiest).","Stir in the coconut milk and reheat gently.","Season and finish each bowl with a hard squeeze of lime."],"tip":"Ginger and lime keep a sweet soup savory — don’t skimp on either."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_butter_shrimp_zucchini', '{"id":"garlic_butter_shrimp_zucchini","name":"Garlic-butter shrimp & zucchini","emoji":"🍤","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"zucchini","q":2},{"f":"butter","q":30},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"black_pepper","q":1},{"f":"salt","q":2}],"steps":["Halve the zucchini lengthwise and slice into half-moons; pat the shrimp very dry.","Brown the zucchini in half the butter over medium-high, 4 minutes; push to the side.","Add the rest of the butter and the shrimp in one layer; cook 90 seconds per side.","Add the sliced garlic for the final minute — it should sizzle, not scorch.","Kill the heat, season, and finish with lemon juice, scraping up the pan butter."],"tip":"Shrimp are done the instant they curl into loose Cs — tight Os are overcooked."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_pepper_chicken_broccoli', '{"id":"lemon_pepper_chicken_broccoli","name":"Lemon-pepper chicken & charred broccoli","emoji":"🍋","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"broccoli","q":450},{"f":"lemon","q":1},{"f":"black_pepper","q":3},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"salt","q":3}],"steps":["Slice the chicken into cutlets; rub with half the oil, the lemon zest, plenty of black pepper and salt.","Sear over medium-high, 3–4 minutes per side, until cooked through; rest.","Char the broccoli florets in the remaining oil in the same hot pan, 5 minutes, adding the sliced garlic at the end.","Splash in 2 tablespoons of water and cover 1 minute to steam-finish.","Serve everything doused with the lemon’s juice."],"tip":"Zest in the rub, juice at the end — lemon twice, two different jobs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('burger_bowls', '{"id":"burger_bowls","name":"Loaded burger bowls","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"cheddar","q":60},{"f":"avocado","q":1},{"f":"sour_cream","q":40},{"f":"olive_oil","q":10}],"steps":["Season the beef and brown it in the oil in crumbles, undisturbed at first for crust, 6–7 minutes.","Melt the cheddar over the beef in the pan.","Chop the romaine, dice the tomato, shave the onion, slice the avocado.","Build bowls on the lettuce with the cheesy beef and vegetables.","Thin the sour cream with a splash of water and drizzle over as the “special sauce.”"],"tip":"Everything you like about a burger, minus the part that was mostly filler anyway."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_avocado_salad', '{"id":"salmon_avocado_salad","name":"Seared salmon & avocado salad","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Season the salmon and sear skin-side down 4 minutes, flip for 2, then rest.","Chop the romaine and cucumber; slice the avocado.","Whisk the lemon juice into the olive oil with salt and pepper.","Toss the greens in most of the dressing.","Flake the warm salmon over the top and spoon on the rest of the dressing."],"tip":"Warm fish on cold crisp greens is a temperature trick worth stealing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_shrimp_stirfry', '{"id":"ginger_shrimp_stirfry","name":"Ginger-garlic shrimp stir-fry","emoji":"🦐","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["shellfish","soy","gluten"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"broccoli","q":450},{"f":"bell_pepper","q":1},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":25},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20}],"steps":["Get the pan properly hot. Stir-fry the broccoli florets and sliced pepper in half the oil, 4 minutes; set aside.","Add the rest of the oil and the dried shrimp in one layer; 90 seconds per side.","Add the ginger and garlic for 30 seconds.","Return the vegetables with the soy sauce and toss hard for 1 minute.","Finish with sliced scallions."],"tip":"Stir-fry is 80% prep, 20% cooking — everything cut and within reach before the flame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_parm_salad', '{"id":"chicken_parm_salad","name":"Grilled chicken & parmesan romaine salad","emoji":"🥬","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"romaine","q":1},{"f":"parmesan","q":40},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"garlic","q":0.1},{"f":"black_pepper","q":2}],"steps":["Pound the chicken even, season, and grill or sear 4 minutes per side; rest and slice.","Whisk the lemon juice, grated garlic and plenty of black pepper into the olive oil.","Chop the romaine into wide ribbons.","Toss the leaves with the dressing and most of the parmesan.","Top with the sliced chicken and the rest of the cheese."],"tip":"Lemon + parmesan + pepper gets you 90% of a Caesar with zero raw-egg logistics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('taco_stuffed_avocados', '{"id":"taco_stuffed_avocados","name":"Taco-stuffed avocados","emoji":"🥑","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"avocado","q":2},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"salsa","q":120},{"f":"cilantro","q":0.2},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Brown the turkey in the oil with the chili powder and cumin, 6–7 minutes.","Stir in half the salsa and simmer 2 minutes until saucy.","Halve and pit the avocados; scoop a little extra from each half to widen the bowl (eat the scoops — chef’s tax).","Pile the taco meat into the avocado halves.","Top with the remaining salsa, cilantro and lime."],"tip":"The avocado IS the tortilla. No notes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_muffin_cups', '{"id":"egg_muffin_cups","name":"Meal-prep egg muffin cups","emoji":"🧁","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":8},{"f":"bell_pepper","q":1},{"f":"spinach","q":60},{"f":"cheddar","q":60},{"f":"scallions","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 375°F and oil a muffin tin well.","Whisk the eggs with salt and pepper.","Divide the diced pepper, chopped spinach, scallions and cheddar among 8–10 cups.","Pour the egg over, filling each cup three-quarters.","Bake 18–20 minutes until puffed and set. They keep 4 days refrigerated."],"tip":"They deflate as they cool — that’s physics, not failure."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_bowl', '{"id":"chicken_burrito_bowl","name":"Chipotle-style chicken burrito bowl","emoji":"🍗","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"rice","q":160},{"f":"black_beans","q":250},{"f":"salsa","q":150},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":15}],"steps":["Cook the rice; fold in lime zest and half the juice with the chopped cilantro stems.","Rub the chicken with chili powder, cumin and salt; sear in the oil 4–5 minutes per side, rest, slice.","Warm the beans with a splash of their liquid.","Build bowls: cilantro-lime rice, beans, chicken.","Top with salsa, cilantro leaves, and the last of the lime."],"tip":"Thighs forgive the extra minute that breasts punish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_broccoli_rice', '{"id":"beef_broccoli_rice","name":"Takeout-style beef & broccoli","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"broccoli","q":450},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Stir the soy sauce, honey, and 3 tablespoons of water into a sauce.","Brown the beef hard in the oil, breaking it into large crumbles, 5 minutes; push aside.","Add the broccoli florets with a splash of water; cover 2 minutes to steam.","Add the garlic and ginger, then the sauce; toss everything 2 minutes until glossy.","Serve over the rice."],"tip":"Ground beef gives you all the flavor of the takeout classic in a third of the time and cost."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_meatballs_marinara', '{"id":"turkey_meatballs_marinara","name":"Turkey meatballs in marinara","emoji":"🧆","cuisine":"Italian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"oats","q":40},{"f":"eggs","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"basil","q":0.3},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15}],"steps":["Blitz the oats to a rough flour. Mix with the turkey, egg, half the minced garlic and a big pinch of salt; roll into 12 meatballs.","Brown the meatballs in the oil on two sides, 5 minutes total — they finish in the sauce.","Add the rest of the garlic, then the crushed tomatoes; simmer 15 minutes, turning the meatballs once.","Cook the spaghetti meanwhile in salted water.","Toss pasta with sauce, top with meatballs and torn basil."],"tip":"Oats disappear as a binder and keep lean turkey juicy — nobody will guess."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_quinoa_power_bowl', '{"id":"salmon_quinoa_power_bowl","name":"Salmon quinoa power bowl","emoji":"💪","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"quinoa","q":140},{"f":"spinach","q":80},{"f":"avocado","q":1},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Cook the quinoa; fluff and season while warm.","Sear the seasoned salmon 4 minutes skin-side, 2 on the flesh; rest and flake.","Wilt the spinach into the warm quinoa — residual heat does it.","Slice the avocado and cucumber.","Bowl everything and dress with lemon juice whisked into the olive oil."],"tip":"Seasoning grains while warm means half the dressing does twice the work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_tortilla_soup', '{"id":"chicken_tortilla_soup","name":"Chicken tortilla soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"broth","q":750},{"f":"salsa","q":200},{"f":"corn_frozen","q":100},{"f":"tortillas","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"cumin","q":4},{"f":"olive_oil","q":15}],"steps":["Cut two tortillas into strips, toss with a little oil, and crisp in a skillet or 400°F oven, 8 minutes.","Simmer the chicken in the broth with the salsa, cumin and the third tortilla torn in (it melts and thickens), 15 minutes.","Shred the chicken back into the pot with the corn; simmer 3 minutes.","Season and hit hard with lime.","Serve topped with cilantro and the crispy strips."],"tip":"The dissolved tortilla is the traditional thickener — no cream, no flour."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_pasta', '{"id":"caprese_pasta","name":"Warm caprese pasta","emoji":"🍅","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"cherry_tomatoes","q":280},{"f":"mozzarella","q":120},{"f":"basil","q":0.4},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25}],"steps":["Cook the pasta in aggressively salted water.","Meanwhile, halve the tomatoes and warm them in the oil with the sliced garlic over medium until they just slump, 4 minutes.","Drag the pasta into the tomatoes with a splash of pasta water; toss 1 minute.","Off heat, fold in the torn mozzarella so it goes creamy at the edges but keeps its shape.","Shower with basil, salt, and a final thread of oil."],"tip":"Off-heat mozzarella is the difference between creamy and squeaky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_quesadillas', '{"id":"spinach_mushroom_quesadillas","name":"Spinach-mushroom quesadillas","emoji":"🫓","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"cheddar","q":120},{"f":"mushrooms","q":200},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salsa","q":100}],"steps":["Brown the sliced mushrooms and onion in the oil until dry and golden, 6 minutes; wilt in the spinach and season.","Layer cheddar, the vegetables, and more cheddar over half of each tortilla; fold.","Toast in a dry skillet over medium, 2–3 minutes per side, pressing gently.","Rest one minute — molten cheese needs to set from lava to fudge.","Cut into wedges and serve with salsa."],"tip":"Cheese on both sides of the filling is the glue that keeps quesadillas together."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_soup_grilled_cheese', '{"id":"tomato_soup_grilled_cheese","name":"Tomato-basil soup & grilled cheese","emoji":"🥪","cuisine":"American","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"crushed_tomatoes","q":500},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"basil","q":0.3},{"f":"bread","q":4},{"f":"cheddar","q":100},{"f":"butter","q":20},{"f":"olive_oil","q":10}],"steps":["Soften the diced onion in the olive oil, add the garlic, then the crushed tomatoes and 1 cup of water; simmer 15 minutes.","Blend smooth with most of the basil.","Butter the bread on the outside, cheddar inside; toast in a skillet over medium-low, 3–4 minutes per side, lid on for the first flip.","Rest the sandwiches a minute, then halve on the diagonal (mandatory).","Serve with the soup for dunking."],"tip":"Low and slow gets the cheese melted before the bread burns — the lid is the cheat code."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_baked_sweet_potatoes', '{"id":"loaded_baked_sweet_potatoes","name":"Loaded baked sweet potatoes","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"sweet_potatoes","q":600},{"f":"black_beans","q":250},{"f":"greek_yogurt","q":100},{"f":"cheddar","q":60},{"f":"scallions","q":0.5},{"f":"chili_powder","q":4},{"f":"lime","q":0.5}],"steps":["Bake the sweet potatoes at 425°F until a knife slides through, 40–45 minutes (or microwave 8, then oven 10 for real skin).","Warm the beans with the chili powder and a splash of water.","Split the potatoes and fluff the insides with a fork and a pinch of salt.","Load with beans and cheddar so it melts into the flesh.","Top with lime-spiked yogurt and sliced scallions."],"tip":"Greek yogurt out-sours sour cream and smuggles in protein."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pita_margherita_pizzas', '{"id":"pita_margherita_pizzas","name":"Pita margherita pizzas","emoji":"🍕","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"pita","q":3},{"f":"crushed_tomatoes","q":150},{"f":"mozzarella","q":150},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1}],"steps":["Heat the oven to 475°F with a baking sheet inside.","Stir the grated garlic and oregano into the crushed tomatoes with a pinch of salt.","Sauce the pitas edge to edge, then tear the mozzarella over.","Slide onto the hot sheet and bake 7–8 minutes until blistered.","Basil and olive oil the moment they come out."],"tip":"The preheated sheet is your pizza stone — crisp bottom, no gear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bean_breakfast_burritos', '{"id":"bean_breakfast_burritos","name":"Black bean breakfast burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"eggs","q":4},{"f":"black_beans","q":200},{"f":"cheddar","q":60},{"f":"salsa","q":100},{"f":"butter","q":10},{"f":"scallions","q":0.3}],"steps":["Warm the beans; scramble the eggs soft in the butter with the scallions.","Warm the tortillas until pliable.","Lay down cheddar first (so it melts), then eggs, beans and salsa, slightly below center.","Fold the sides in, then roll tight from the bottom.","Seal seam-down in the hot pan 1 minute per side. Wrapped in foil, they survive commutes and freezers."],"tip":"The pan-seal is what separates a burrito from a pile."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('herb_roasted_chicken_potatoes', '{"id":"herb_roasted_chicken_potatoes","name":"Sheet-pan herb chicken & potatoes","emoji":"🍗","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"potatoes","q":500},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F. Halve the baby-cut potatoes (or chunk large ones).","Toss potatoes and chicken with the oil, oregano, minced garlic and salt on a sheet pan.","Arrange skin-side up with space between pieces — crowding steams, spacing roasts.","Roast 35 minutes until the chicken hits crisp and the potatoes are golden.","Squeeze the lemon over the whole pan before serving."],"tip":"One pan, one cutting board, one lemon — weeknight math that works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_potato_hash', '{"id":"beef_potato_hash","name":"Crispy beef & potato skillet hash","emoji":"🥔","cuisine":"American","meal":["dinner","breakfast"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"potatoes","q":450},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"chili_powder","q":4},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Dice the potatoes small and get them crisping in the oil over medium-high, tossing every few minutes, 12–15 minutes.","Push aside; brown the beef in the middle, 5 minutes.","Add the diced onion and pepper with the chili powder; cook 4 minutes.","Fold everything together and let it sit untouched 2 minutes for a final crust.","Season and serve — a fried egg on top converts it to breakfast."],"tip":"Small dice and patience are the whole secret to crispy skillet potatoes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_lime_chicken_rice', '{"id":"honey_lime_chicken_rice","name":"Honey-lime skillet chicken & rice","emoji":"🍯","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"honey","q":25},{"f":"lime","q":2},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":4},{"f":"olive_oil","q":15}],"steps":["Start the rice. Whisk the honey with the juice of both limes, the garlic and chili powder.","Sear the seasoned chicken in the oil, 4–5 minutes per side.","Pour the honey-lime over the chicken and let it bubble to a glaze, 2 minutes, turning to coat.","Rest the chicken briefly, then slice.","Serve over rice with the pan glaze and cilantro."],"tip":"Honey burns fast — the glaze goes in only after the chicken is basically done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_beans_greens_toast', '{"id":"garlicky_beans_greens_toast","name":"Garlicky beans & greens on toast","emoji":"🍞","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"spinach","q":150},{"f":"garlic","q":0.4},{"f":"bread","q":4},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5},{"f":"oregano","q":2}],"steps":["Sizzle the sliced garlic in the oil over medium-low until pale gold — not brown — 2 minutes.","Add the chickpeas with a splash of their liquid and the oregano; simmer 5 minutes, mashing a third of them.","Fold in the spinach to wilt.","Toast the bread dark and rub it with the cut lemon.","Pile the beans on the toast and finish with lemon juice and oil."],"tip":"Beans on toast, Mediterranean edition — pantry dinner with dignity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_avocado_rice_bowls', '{"id":"shrimp_avocado_rice_bowls","name":"Chili-lime shrimp & avocado rice bowls","emoji":"🍤","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"rice","q":160},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"chili_powder","q":6},{"f":"cilantro","q":0.3},{"f":"corn_frozen","q":100},{"f":"olive_oil","q":15}],"steps":["Cook the rice; fold in the zest and juice of one lime.","Char the corn in a dry skillet, 3 minutes; set aside.","Toss the dried shrimp with chili powder and salt; sear in the oil 90 seconds per side.","Slice the avocado.","Bowl the rice, corn, shrimp and avocado; finish with the second lime and cilantro."],"tip":"Dry shrimp sear; wet shrimp steam. A paper towel is the best marinade."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pepper_egg_breakfast_tacos', '{"id":"pepper_egg_breakfast_tacos","name":"Charred pepper & egg breakfast tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":5},{"f":"bell_pepper","q":1},{"f":"onion","q":0.3},{"f":"salsa","q":100},{"f":"cilantro","q":0.2},{"f":"olive_oil","q":15}],"steps":["Char the sliced pepper and onion in the oil over high heat, 4 minutes, until blistered at the edges.","Drop to medium-low, pour in the whisked eggs, and scramble soft through the vegetables.","Toast the tortillas over the flame or in a dry pan.","Fill with the eggs.","Top with salsa and cilantro."],"tip":"Charred peppers do for eggs what bacon usually gets credit for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_pasta', '{"id":"lemon_garlic_salmon_pasta","name":"Lemon-garlic salmon pasta","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"spaghetti","q":180},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":80},{"f":"parmesan","q":30},{"f":"olive_oil","q":25},{"f":"black_pepper","q":2}],"steps":["Cook the spaghetti; reserve a cup of pasta water.","Sear the salmon in the oil 3 minutes per side; remove and flake.","Soften the sliced garlic in the same pan, 1 minute.","Toss in the pasta, spinach, lemon zest and juice with splashes of pasta water until glossy.","Fold the salmon back in gently, finish with parmesan and black pepper."],"tip":"Flaked fish folded in at the end stays in pieces instead of becoming sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_rice_noodle_stirfry', '{"id":"veggie_rice_noodle_stirfry","name":"Pad-thai-style rice noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","soy","nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"eggs","q":2},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"peanut_butter","q":30},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"honey","q":15},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in just-boiled water until pliable but underdone, 6–7 minutes; drain.","Whisk the peanut butter, soy sauce, lime juice, honey and a splash of hot water into a sauce.","Scramble the eggs in the oil over high heat; add the ribboned carrots for 1 minute.","Add the noodles and sauce; toss 2 minutes until glossy and just tender.","Finish with scallions and extra lime."],"tip":"Undercook the soak — the noodles finish in the pan and stay springy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_chicken', '{"id":"cashew_chicken","name":"Cashew chicken","emoji":"🥜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"cashews","q":70},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Toast the cashews in the dry pan until golden; set aside.","Stir-fry the diced chicken in the oil over high heat until browned, 5–6 minutes.","Add the diced pepper, garlic and ginger; 2 minutes more.","Add the soy sauce and honey; let it bubble to a glaze, 1 minute.","Toss the cashews back in and serve over rice."],"tip":"Toasting the cashews separately keeps them crunchy against the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_fried_rice', '{"id":"edamame_fried_rice","name":"Sesame edamame fried rice","emoji":"🫛","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"rice","q":180},{"f":"edamame_frozen","q":250},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10}],"steps":["Cold cooked rice works best; make it ahead if you can.","Stir-fry the diced carrots in the neutral oil over high heat, 2 minutes.","Add the edamame straight from frozen with the garlic and ginger; 2 minutes more.","Add the rice, press it into the pan, and let it crackle before tossing with the soy sauce.","Kill the heat, finish with sesame oil and scallions — sesame is a finishing oil, not a frying oil."],"tip":"Edamame makes this a complete protein without anything having had a face."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_cabbage_stirfry', '{"id":"beef_cabbage_stirfry","name":"Ginger beef & cabbage stir-fry","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":80},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Brown the beef hard in the neutral oil, breaking it up, 5 minutes; push aside.","Add the thinly sliced cabbage and ribboned carrot; stir-fry 4 minutes until wilted but still squeaky.","Add the ginger and garlic for 1 minute.","Season with soy sauce and toss everything together.","Finish off-heat with sesame oil and scallions."],"tip":"Egg-roll filling as a bowl — everything you like about takeout minus the deep fryer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_fried_rice', '{"id":"cauliflower_fried_rice","name":"Cauliflower fried \"rice\"","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegetarian","dairy-free","low-carb"],"allergens":["eggs","soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"eggs","q":3},{"f":"peas_frozen","q":100},{"f":"scallions","q":0.5},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15}],"steps":["Grate the cauliflower on the big holes (or pulse in a processor) into rice-sized bits.","Scramble the eggs in the oil over high heat; set aside.","Stir-fry the cauliflower with the garlic and ginger, 4–5 minutes — let it catch some color and drive off moisture.","Add the peas and soy sauce for 2 minutes; fold the eggs back in.","Finish with sesame oil and scallions."],"tip":"Dry pan, high heat: wet cauliflower is the only way this goes wrong."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('aloo_gobi', '{"id":"aloo_gobi","name":"Aloo gobi","emoji":"🥔","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"potatoes","q":400},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"turmeric","q":4},{"f":"cumin","q":4},{"f":"garam_masala","q":4},{"f":"ginger","q":10},{"f":"olive_oil","q":25},{"f":"cilantro","q":0.3}],"steps":["Brown the diced potatoes in the oil over medium, lid on, stirring occasionally, 8 minutes.","Add the cauliflower florets, diced onion, ginger, turmeric and cumin; toss to stain everything gold.","Add the chopped tomatoes and a splash of water; cover and cook 12 minutes until tender.","Uncover, raise the heat, and let the edges catch a little.","Finish with garam masala and cilantro — the masala goes in last, that is the technique."],"tip":"Garam masala added at the end stays aromatic; cooked long it just goes flat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kale_chickpea_saag_style', '{"id":"kale_chickpea_saag_style","name":"Saag-style creamy greens & chickpeas","emoji":"🥬","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"kale","q":1},{"f":"spinach","q":150},{"f":"chickpeas","q":250},{"f":"coconut_milk","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"garam_masala","q":5},{"f":"cumin","q":4},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Soften the diced onion in the oil until golden, 6 minutes; add garlic, ginger and cumin for 1 minute.","Add the stripped, chopped kale with a splash of water; cover 4 minutes until collapsed.","Add the spinach to wilt, then blend the greens roughly right in the pot.","Stir in the chickpeas and coconut milk; simmer 5 minutes.","Finish with garam masala and serve over rice."],"tip":"Blending half-smooth is the saag texture — creamy but still recognizably greens."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_style_yogurt_chicken', '{"id":"tandoori_style_yogurt_chicken","name":"Tandoori-style yogurt chicken","emoji":"🍗","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"greek_yogurt","q":150},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"paprika","q":4},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"lemon","q":1},{"f":"olive_oil","q":10}],"steps":["Stir the yogurt with the garam masala, turmeric, paprika, grated garlic, ginger, half the lemon’s juice and a big pinch of salt.","Coat the chicken and marinate 15 minutes on the counter (or up to a day in the fridge).","Heat the broiler with a rack near the top; oil a foil-lined sheet.","Broil the chicken 6–7 minutes per side until charred in spots and cooked through.","Rest briefly, squeeze the rest of the lemon over, and serve — a cucumber salad on the side is traditional and correct."],"tip":"Yogurt tenderizes and chars where plain marinades just drip off — the broiler is your tandoor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_pulao', '{"id":"vegetable_pulao","name":"Vegetable pulao with cashews","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"rice","q":180},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"onion","q":1},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"cashews","q":50},{"f":"olive_oil","q":20}],"steps":["Toast the cashews in the dry pot until golden; set aside.","Fry the sliced onion in the oil until deeply golden, 8 minutes — this is the flavor base.","Stir in the cumin, turmeric and rice to coat every grain.","Add the diced carrots and 1¾ cups water; cover and simmer low 15 minutes, adding the peas for the last 5.","Rest 5 minutes off heat, fluff, and finish with garam masala and the cashews."],"tip":"Coating the rice in spiced oil before the water goes in is what makes pulao taste like pulao."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_bhurji', '{"id":"egg_bhurji","name":"Egg bhurji (Indian scrambled eggs)","emoji":"🍳","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":5},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"turmeric","q":2},{"f":"cumin","q":2},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Soften the finely diced onion in the oil over medium, 3 minutes.","Add the cumin and turmeric for 30 seconds, then the diced tomato until it slumps, 2 minutes.","Pour in the whisked, salted eggs.","Scramble in small curds, stopping while still glossy.","Shower with cilantro and serve — with toast, or wrapped in a warm tortilla."],"tip":"Bhurji is proof that scrambled eggs were never the ceiling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_chickpea_curry', '{"id":"cauliflower_chickpea_curry","name":"Cauliflower & chickpea curry","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":250},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"curry_powder","q":10},{"f":"garam_masala","q":3},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Golden the diced onion in the oil, then bloom the curry powder with the garlic, 1 minute.","Add the crushed tomatoes; cook 3 minutes.","Add the cauliflower florets, chickpeas, coconut milk and a splash of water; cover and simmer 15 minutes.","Uncover and reduce 3 minutes until the sauce coats the florets.","Finish with garam masala; serve over rice."],"tip":"Cauliflower drinks curry sauce like it was designed for the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_feta_tomato_pasta', '{"id":"baked_feta_tomato_pasta","name":"Baked feta & burst tomato pasta","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"feta","q":170},{"f":"cherry_tomatoes","q":560},{"f":"spaghetti","q":180},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"olive_oil","q":30},{"f":"oregano","q":2}],"steps":["Heat the oven to 400°F. Put the feta block in the middle of a baking dish, tomatoes around it, everything doused in the oil and oregano.","Bake 30 minutes until the tomatoes burst and the feta browns on top.","Cook the spaghetti meanwhile; reserve pasta water.","Mash the feta and tomatoes into a sauce with the roasted garlic.","Toss with the pasta, loosening with pasta water, and finish with basil."],"tip":"Yes, it is the viral one — it went viral because it works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('massaged_kale_feta_salad', '{"id":"massaged_kale_feta_salad","name":"Massaged kale salad with feta & walnuts","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"kale","q":1},{"f":"feta","q":70},{"f":"walnuts","q":50},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"honey","q":10},{"f":"apple","q":1}],"steps":["Strip the kale from its stems, tear into pieces, and — really — massage it with a pinch of salt and half the oil for 2 minutes until it darkens and softens.","Toast the walnuts in a dry pan, 3 minutes.","Whisk the lemon juice, remaining oil and honey.","Slice the apple thin.","Toss everything with the dressing and crumble the feta over."],"tip":"Massaging isn’t a food-blog affectation — it breaks down the fibers that make raw kale a chore."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_saganaki', '{"id":"shrimp_saganaki","name":"Shrimp saganaki (tomato & feta skillet)","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"crushed_tomatoes","q":350},{"f":"feta","q":100},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"oregano","q":3},{"f":"olive_oil","q":20}],"steps":["Soften the diced onion in the oil; add the garlic and oregano for 1 minute.","Add the crushed tomatoes and simmer 10 minutes until thick.","Nestle the dried shrimp into the sauce; cook 2 minutes per side.","Crumble the feta over and cover 1 minute to soften it.","Finish with more oregano and eat straight from the pan with bread or over greens."],"tip":"The feta half-melts into salty cream pockets — that is the whole dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_chickpea_stew', '{"id":"eggplant_chickpea_stew","name":"Eggplant & chickpea stew","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"chickpeas","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":30}],"steps":["Brown the cubed eggplant in most of the oil over medium-high until golden, 8 minutes; set aside.","Soften the diced onion, then add the garlic, oregano and paprika for 1 minute.","Add the crushed tomatoes and chickpeas; simmer 10 minutes.","Return the eggplant and simmer 10 more until silky.","Rest 5 minutes — this stew is better warm than hot, and better tomorrow than today."],"tip":"Eggplant browned first holds its shape; eggplant stewed raw dissolves into sludge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_salad', '{"id":"mediterranean_tuna_salad","name":"Mediterranean tuna & olive salad","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"olives","q":60},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"oregano","q":2}],"steps":["Drain the tuna and flake it into a bowl in big pieces.","Dice the cucumber and tomatoes; sliver the onion; halve the olives.","Whisk the lemon juice, olive oil and oregano.","Fold everything together gently — the tuna should stay chunky.","Season with pepper (the olives bring the salt) and serve, alone or in a pita."],"tip":"No mayo, no apology — this is what tuna salad looks like on the Aegean."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potatoes_green_beans', '{"id":"spanish_potatoes_green_beans","name":"Smoky Spanish potatoes & green beans","emoji":"🥔","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"green_beans","q":250},{"f":"paprika","q":5},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"crushed_tomatoes","q":150},{"f":"olive_oil","q":30}],"steps":["Crisp the diced potatoes in the oil over medium, tossing every few minutes, 15 minutes.","Add the onion and trimmed green beans; cook 4 minutes.","Add the garlic and smoked paprika for 30 seconds — off the heat briefly so the paprika doesn’t scorch.","Stir in the crushed tomatoes and simmer 3 minutes to a clingy sauce.","Season well; a fried egg on top is optional and excellent."],"tip":"Smoked paprika burns bitter in seconds — bloom it in oil off the flame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_tenderloin_green_beans', '{"id":"pork_tenderloin_green_beans","name":"Garlic-herb pork tenderloin & green beans","emoji":"🥩","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"green_beans","q":300},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"lemon","q":0.5},{"f":"olive_oil","q":25},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F. Rub the pork with oil, minced garlic, oregano, paprika and salt.","Sear it in an ovenproof skillet on all sides, 5 minutes total.","Scatter the green beans around, toss in the pan oil, and roast 12–15 minutes (pull the pork at 140°F).","Rest the pork 5 minutes under foil — non-negotiable for juicy slices.","Slice thick, squeeze lemon over everything, and spoon the pan juices on top."],"tip":"Tenderloin is the weeknight roast: 35 minutes start to carved."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_cabbage_skillet', '{"id":"unstuffed_cabbage_skillet","name":"Unstuffed cabbage-roll skillet","emoji":"🍲","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"cabbage","q":0.5},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"paprika","q":4},{"f":"olive_oil","q":15}],"steps":["Brown the turkey in the oil, 5 minutes; add the diced onion and garlic for 3 more.","Stir in the paprika, then the crushed tomatoes.","Pile in the chopped cabbage — it looks like too much; it is not.","Cover and simmer 12 minutes until the cabbage is tender.","Season and serve; all the flavor of cabbage rolls, none of the rolling."],"tip":"Deconstructed classics exist because weeknights do."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_asparagus_skillet', '{"id":"shrimp_asparagus_skillet","name":"Lemon shrimp & asparagus skillet","emoji":"🍋","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["shellfish"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"asparagus","q":340},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"black_pepper","q":1},{"f":"salt","q":3}],"steps":["Snap the asparagus where it wants to break and cut into thirds.","Sear it in half the oil over medium-high, 3–4 minutes, until blistered but snappy; set aside.","Sear the dried, seasoned shrimp in the rest of the oil, 90 seconds per side, adding the garlic at the flip.","Return the asparagus, toss once.","Off heat: lemon zest, lemon juice, and a final glug of oil."],"tip":"Fifteen minutes, one pan, and it looks like you tried much harder."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_berry_bowl', '{"id":"cottage_cheese_berry_bowl","name":"Whipped cottage cheese & berry bowl","emoji":"🫐","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","nuts"],"time":5,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"berries","q":200},{"f":"honey","q":15},{"f":"walnuts","q":30},{"f":"cinnamon","q":1}],"steps":["Blitz the cottage cheese 30 seconds until whipped and smooth (or embrace the curds and skip this).","Divide between bowls.","Top with the berries and toasted walnuts.","Drizzle the honey and dust with cinnamon.","That’s it — 25 grams of protein disguised as dessert."],"tip":"Blending is cottage cheese’s redemption arc."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_avocado_lettuce_boats', '{"id":"tuna_avocado_lettuce_boats","name":"Tuna-avocado lettuce boats","emoji":"🛶","cuisine":"American","meal":["lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"avocado","q":1},{"f":"romaine","q":1},{"f":"lime","q":1},{"f":"onion","q":0.2},{"f":"cilantro","q":0.2},{"f":"olive_oil","q":10}],"steps":["Mash the avocado with the lime juice and a pinch of salt.","Fold in the drained tuna, minced onion and cilantro — avocado replaces mayo entirely.","Separate the romaine into sturdy leaf-boats.","Fill each boat generously.","Finish with oil, pepper, and eat with your hands."],"tip":"Avocado-as-mayo is the upgrade canned tuna has been waiting for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pasta_e_fagioli', '{"id":"pasta_e_fagioli","name":"Pasta e fagioli","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"white_beans","q":400},{"f":"penne","q":120},{"f":"crushed_tomatoes","q":250},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"olive_oil","q":25},{"f":"parsley","q":0.3}],"steps":["Soften the diced onion, carrot and celery in the oil, 6 minutes; add the garlic and oregano for 1 more.","Add the crushed tomatoes, beans and 2½ cups of water; simmer 10 minutes.","Mash a ladleful of beans against the pot to cream the broth.","Add the pasta straight into the soup and simmer until al dente, 10–11 minutes, stirring so it doesn’t stick.","Rest 5 minutes — it thickens into the proper spoon-standing texture — and finish with parsley and good oil."],"tip":"Cooking the pasta in the soup releases its starch — that is the body of the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('walnut_pesto_penne', '{"id":"walnut_pesto_penne","name":"Walnut-basil pesto penne","emoji":"🌿","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy","nuts"],"time":20,"servings":2,"ing":[{"f":"penne","q":200},{"f":"basil","q":1},{"f":"walnuts","q":60},{"f":"parmesan","q":50},{"f":"garlic","q":0.1},{"f":"olive_oil","q":50},{"f":"lemon","q":0.5}],"steps":["Toast the walnuts in a dry pan, 3 minutes; cool slightly.","Blitz the basil leaves, walnuts, parmesan, garlic and oil into a rough pesto; season with salt and lemon juice.","Cook the penne; reserve a cup of pasta water.","Toss the pasta with the pesto OFF the heat, loosening with pasta water until it clings.","More parmesan over the top, obviously."],"tip":"Heat kills pesto’s color and perfume — it dresses pasta, it never cooks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_tomato_penne', '{"id":"bacon_tomato_penne","name":"Amatriciana-style bacon & tomato penne","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":[],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"penne","q":200},{"f":"bacon","q":120},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"parmesan","q":40},{"f":"olive_oil","q":10},{"f":"black_pepper","q":2}],"steps":["Render the chopped bacon in the oil over medium until crisp; lift it out, leaving the fat.","Soften the sliced onion in the bacon fat, 4 minutes.","Add the crushed tomatoes and plenty of black pepper; simmer 12 minutes.","Cook the penne; finish it in the sauce with a splash of pasta water and most of the bacon.","Serve with parmesan and the reserved bacon on top."],"tip":"Guanciale is traditional; bacon is Tuesday. Both are delicious."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_kale_soup', '{"id":"white_bean_kale_soup","name":"Tuscan white bean & kale soup","emoji":"🥬","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"white_beans","q":500},{"f":"kale","q":1},{"f":"carrots","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5}],"steps":["Soften the diced onion and carrots in half the oil, 6 minutes; add the garlic and oregano for 1 minute.","Add the beans and 3 cups of water; simmer 10 minutes.","Blend a third of the pot and stir it back — creamy broth, no cream.","Stir in the stripped, chopped kale; simmer 5 minutes until tender.","Finish with lemon juice and the rest of the oil in slow circles over each bowl."],"tip":"The partial blend is the oldest trick in Tuscany — body without dairy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_spinach_penne', '{"id":"ricotta_spinach_penne","name":"Creamy ricotta & spinach penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"penne","q":200},{"f":"ricotta","q":250},{"f":"spinach","q":150},{"f":"garlic","q":0.2},{"f":"parmesan","q":40},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Cook the penne; reserve a big cup of pasta water.","Sizzle the sliced garlic in the oil, then wilt the spinach, 1 minute.","Off heat, stir the ricotta with half the parmesan, lemon zest and a ladle of hot pasta water into a sauce right in the pan.","Fold in the pasta, loosening with more water until silky.","Finish with lemon juice, the rest of the parmesan and aggressive black pepper."],"tip":"Ricotta + pasta water = alfredo energy with a third of the effort."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_chicken_caprese', '{"id":"balsamic_chicken_caprese","name":"Balsamic chicken caprese","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"mozzarella","q":100},{"f":"tomato","q":2},{"f":"basil","q":0.3},{"f":"balsamic_vinegar","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2}],"steps":["Halve the breasts into cutlets, season, and sear in the oil 3–4 minutes per side.","Add the balsamic and garlic to the pan; let it bubble down to a glaze that coats the chicken, 2 minutes.","Top each cutlet with sliced tomato and mozzarella; cover 2 minutes to melt.","Rest a minute.","Serve painted with the pan glaze and covered in torn basil."],"tip":"Balsamic reduces to candy-glaze in minutes — watch it, it goes from perfect to burnt fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_minestrone', '{"id":"weeknight_minestrone","name":"Weeknight minestrone","emoji":"🍜","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":4,"ing":[{"f":"white_beans","q":400},{"f":"penne","q":120},{"f":"zucchini","q":1},{"f":"carrots","q":120},{"f":"celery","q":80},{"f":"onion","q":1},{"f":"crushed_tomatoes","q":300},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"olive_oil","q":25},{"f":"parsley","q":0.3}],"steps":["Soften the diced onion, carrot and celery in the oil, 6 minutes.","Add the garlic and oregano, then the crushed tomatoes and 4 cups of water; simmer 10 minutes.","Add the diced zucchini, beans and pasta; simmer until the pasta is just done, 10 minutes.","Season hard — vegetable soups are shy until salted.","Finish with parsley and olive oil; parmesan for the non-vegans at the table."],"tip":"Minestrone is a fridge-clearing format, not a recipe — swap in whatever vegetables are fading."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_pancakes', '{"id":"lemon_ricotta_pancakes","name":"Lemon-ricotta pancakes","emoji":"🥞","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["gluten","dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"ricotta","q":250},{"f":"flour","q":120},{"f":"eggs","q":2},{"f":"milk","q":80},{"f":"lemon","q":1},{"f":"maple_syrup","q":60},{"f":"butter","q":15},{"f":"sugar","q":20}],"steps":["Whisk the ricotta, eggs, milk, sugar and the zest of the whole lemon.","Fold in the flour just until combined — lumps are fine, tough pancakes are not.","Cook quarter-cup rounds in butter over medium, 2–3 minutes per side.","They stay custardy in the middle; that is the point, not underdone batter.","Serve with maple syrup and a squeeze of the naked lemon."],"tip":"Ricotta pancakes are what diner pancakes dream of becoming."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_souvlaki_bowls', '{"id":"chicken_souvlaki_bowls","name":"Chicken souvlaki bowls with yogurt sauce","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":1},{"f":"couscous","q":140},{"f":"oregano","q":4},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"tomato","q":1}],"steps":["Marinate the cubed chicken in half the oil, oregano, half the lemon’s juice and half the garlic, 10 minutes.","Stir grated, squeezed cucumber into the yogurt with the rest of the garlic and a pinch of salt — instant tzatziki.","Pour boiling water over the couscous (equal volume), cover 5 minutes, fluff.","Sear the chicken hard on skewers or straight in the pan, 8–10 minutes, until charred at the edges.","Bowl it: couscous, chicken, diced tomato, tzatziki, remaining lemon."],"tip":"Squeeze the grated cucumber like you mean it — watery tzatziki is the only bad tzatziki."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('couscous_tabbouleh', '{"id":"couscous_tabbouleh","name":"Couscous tabbouleh","emoji":"🌿","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"couscous","q":120},{"f":"parsley","q":1},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"scallions","q":0.3},{"f":"lemon","q":1.5},{"f":"olive_oil","q":30}],"steps":["Hydrate the couscous in an equal volume of boiling water, covered, 5 minutes; fluff and cool.","Chop the entire parsley bunch fine — in tabbouleh, parsley is a vegetable, not a garnish.","Dice the tomatoes and cucumber small; slice the scallions.","Toss everything with the lemon juice, oil and a serious pinch of salt.","Rest 10 minutes so the couscous drinks the dressing."],"tip":"The parsley-to-grain ratio should make you slightly nervous. That’s authentic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_tuna_salad', '{"id":"white_bean_tuna_salad","name":"Italian white bean & tuna salad","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"white_beans","q":400},{"f":"onion","q":0.2},{"f":"parsley","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"black_pepper","q":2}],"steps":["Rinse and drain the beans; flake in the drained tuna.","Sliver the onion paper-thin and soak it in the lemon juice 5 minutes to tame it.","Chop the parsley roughly.","Fold everything together with the oil, onion and its lemon.","Pepper hard, salt lightly, and let it sit 5 minutes before serving."],"tip":"A Tuscan classic with two cans and one lemon — pantry lunch royalty."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mezze_bowls', '{"id":"mezze_bowls","name":"Mezze plate bowls","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"hummus","q":160},{"f":"feta","q":80},{"f":"olives","q":80},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":200},{"f":"roasted_red_peppers","q":100},{"f":"pita","q":2},{"f":"olive_oil","q":15},{"f":"oregano","q":2}],"steps":["Swoosh the hummus across two wide bowls.","Arrange the halved tomatoes, sliced cucumber, olives, torn roasted peppers and feta in piles.","Warm the pitas and cut into wedges.","Drizzle everything with oil and dust with oregano.","Assemble bites at will — this is legally a cooked dinner."],"tip":"Mezze is the anti-recipe: quality ingredients, zero technique, maximum table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('artichoke_lemon_chicken', '{"id":"artichoke_lemon_chicken","name":"Artichoke-lemon chicken skillet","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"artichoke_hearts","q":240},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"parsley","q":0.3},{"f":"olive_oil","q":25},{"f":"oregano","q":2}],"steps":["Halve the breasts into cutlets, season with oregano and salt, and sear in the oil 3–4 minutes per side; set aside.","Brown the drained, halved artichokes in the same pan, cut-side down, 3 minutes.","Add the garlic for 30 seconds, then the juice of the lemon and a splash of water, scraping the pan.","Return the chicken to warm through in the sauce, 2 minutes.","Shower with parsley and serve with the pan juices."],"tip":"Canned artichokes brown beautifully if you dry them first — treat them like a vegetable, not a garnish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_baked_white_beans', '{"id":"greek_baked_white_beans","name":"Greek baked white beans (gigantes-style)","emoji":"🫘","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"white_beans","q":500},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"oregano","q":4},{"f":"honey","q":10},{"f":"olive_oil","q":40},{"f":"parsley","q":0.3}],"steps":["Heat the oven to 400°F. Soften the diced onion in half the oil; add the garlic and oregano for 1 minute.","Stir in the crushed tomatoes, honey, beans and a splash of water.","Pour into a baking dish, top with the remaining oil.","Bake 25 minutes until bubbling with caramelized edges.","Rest 10 minutes and finish with parsley — served warm, never hot."],"tip":"The whisper of honey against the tomatoes is the traditional move — sweet-savory, not sweet."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_couscous_bowl', '{"id":"salmon_couscous_bowl","name":"Lemon salmon & couscous bowl","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"couscous","q":140},{"f":"cucumber","q":0.5},{"f":"olives","q":50},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"olive_oil","q":20}],"steps":["Hydrate the couscous in boiling water, covered, 5 minutes; fluff with a fork and half the oil.","Sear the seasoned salmon 4 minutes skin-side, 2 flesh-side; rest and flake.","Dice the cucumber, halve the olives, chop the parsley.","Fold the vegetables and herbs through the couscous with the lemon juice.","Top with the salmon and the last of the oil."],"tip":"Couscous is the five-minute grain — faster than toast, fancier than rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka', '{"id":"shakshuka","name":"Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"crushed_tomatoes","q":400},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"parsley","q":0.3}],"steps":["Soften the sliced onion and pepper in the oil over medium, 8 minutes — properly soft, this is the base.","Add the garlic, cumin and paprika for 1 minute, then the crushed tomatoes; simmer 8 minutes until thick.","Nest wells in the sauce and crack an egg into each; season the yolks.","Cover and cook 5–7 minutes until the whites set but the yolks tremble.","Crumble the feta over, add parsley, and serve from the pan with bread for the non-low-carb table."],"tip":"The sauce must be thick before the eggs go in — soup poaches badly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_roasted_veg_couscous', '{"id":"balsamic_roasted_veg_couscous","name":"Balsamic roasted vegetables & couscous","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"zucchini","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"balsamic_vinegar","q":30},{"f":"couscous","q":140},{"f":"olive_oil","q":30},{"f":"oregano","q":3}],"steps":["Heat the oven to 425°F. Chunk all the vegetables evenly.","Toss with the oil, oregano and salt on a sheet pan; roast 25 minutes until charred at the corners.","Drizzle the balsamic over the hot pan and toss — it glazes on contact.","Hydrate the couscous meanwhile.","Pile the glazed vegetables over the couscous, scraping every dark sticky bit from the pan."],"tip":"Balsamic on hot-from-the-oven vegetables becomes a glaze without ever seeing a saucepan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avgolemono_soup', '{"id":"avgolemono_soup","name":"Avgolemono (Greek lemon chicken soup)","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"broth","q":1000},{"f":"rice","q":100},{"f":"eggs","q":2},{"f":"lemon","q":1.5},{"f":"parsley","q":0.2},{"f":"olive_oil","q":10}],"steps":["Simmer the chicken in the broth until cooked, 12 minutes; shred it and return it, adding the rice for 15 minutes.","Whisk the eggs with the juice of the lemons until frothy.","Temper: whisk hot broth into the eggs one ladle at a time — three ladles minimum.","Off the heat, stir the tempered eggs back into the pot; it turns velvety and pale.","Do not boil it again. Season, add parsley, serve."],"tip":"Tempering feels fussy the first time and automatic forever after — silk from two eggs and a lemon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_rice_bowls', '{"id":"ginger_pork_rice_bowls","name":"Ginger-glazed pork rice bowls","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"ginger","q":15},{"f":"soy_sauce","q":35},{"f":"honey","q":20},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"cabbage","q":0.3},{"f":"scallions","q":0.5},{"f":"olive_oil","q":15}],"steps":["Start the rice. Slice the pork thin against the grain.","Sear the pork in the oil over high heat in two batches, 2 minutes each; set aside.","Add the ginger and garlic, then the soy sauce and honey; bubble to a glaze.","Return the pork and toss to coat.","Serve over rice with a pile of thin-shaved raw cabbage and scallions for crunch."],"tip":"Thin slices against the grain make loin taste like a far more expensive cut."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_kale_edamame_salad', '{"id":"sesame_kale_edamame_salad","name":"Sesame kale & edamame crunch salad","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","sesame","nuts","gluten"],"time":15,"servings":2,"ing":[{"f":"kale","q":1},{"f":"edamame_frozen","q":250},{"f":"carrots","q":100},{"f":"cashews","q":40},{"f":"sesame_oil","q":15},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"ginger","q":8}],"steps":["Blanch the edamame in boiling water 3 minutes; drain and cool.","Massage the stripped, shredded kale with a pinch of salt until it relaxes.","Whisk the sesame oil, soy sauce, honey, lime juice and grated ginger.","Toss the kale, edamame and ribboned carrots with the dressing.","Top with toasted cashews. Keeps dressed for a day — kale does not wilt like lettuce."],"tip":"This is the salad that survives meal prep — day two is arguably better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_egg_breakfast_tacos', '{"id":"bacon_egg_breakfast_tacos","name":"Bacon & egg breakfast tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":[],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"bacon","q":120},{"f":"cheddar","q":50},{"f":"salsa","q":100},{"f":"avocado","q":0.5},{"f":"scallions","q":0.3}],"steps":["Crisp the chopped bacon; pour off all but a slick of the fat.","Scramble the eggs soft in the bacon pan.","Warm the tortillas; slice the avocado.","Fill: cheddar first (it melts under the eggs), then eggs, bacon, avocado.","Salsa and scallions over everything."],"tip":"Cheese under hot eggs is self-melting engineering."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_carnitas_bowls', '{"id":"pork_carnitas_bowls","name":"Carnitas-style pork bowls","emoji":"🍖","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"lime","q":2},{"f":"cumin","q":5},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"rice","q":160},{"f":"black_beans","q":250},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Cube the pork and toss with cumin, oregano, salt and the juice of one lime.","Brown it hard in the oil, then add the sliced onion, garlic and ½ cup water; cover and simmer 25 minutes until shreddable.","Uncover, crank the heat, and let the liquid cook off so the edges crisp — that contrast is carnitas.","Warm the beans; cook the rice.","Bowl it all with cilantro and the second lime."],"tip":"Braise then crisp: tender inside, crackly edges — the two-texture secret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_green_beans_potatoes', '{"id":"masala_green_beans_potatoes","name":"Masala green beans & potatoes","emoji":"🫛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"green_beans","q":300},{"f":"potatoes","q":400},{"f":"onion","q":0.5},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"ginger","q":8},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5}],"steps":["Brown the small-diced potatoes in the oil, covered, stirring now and then, 10 minutes.","Add the onion, ginger, turmeric and cumin; 2 minutes.","Add the trimmed, halved green beans and a splash of water; cover 6–8 minutes until just tender.","Uncover and let everything catch a little color.","Finish with garam masala and lemon."],"tip":"A dry sabzi wants a lid early and no lid late — steam, then sizzle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_tikka_masala', '{"id":"chickpea_tikka_masala","name":"Chickpea tikka masala","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":500},{"f":"crushed_tomatoes","q":300},{"f":"coconut_milk","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"garam_masala","q":6},{"f":"paprika","q":4},{"f":"cumin","q":3},{"f":"rice","q":140},{"f":"olive_oil","q":20}],"steps":["Start the rice. Golden the diced onion in the oil, 6 minutes; add garlic, ginger, cumin and paprika for 1 minute.","Add the crushed tomatoes and simmer 8 minutes until darkened and thick — this patience IS tikka masala.","Blend the sauce smooth with the coconut milk (or don’t; rustic is fine).","Add the chickpeas and simmer 8 minutes to marry.","Finish with garam masala; serve over rice."],"tip":"The long tomato reduction is the restaurant secret — thin sauce, thin flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_shrimp_curry', '{"id":"coconut_shrimp_curry","name":"Coconut shrimp curry","emoji":"🍤","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"curry_powder","q":10},{"f":"garam_masala","q":3},{"f":"rice","q":140},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Start the rice. Golden the diced onion in the oil; bloom the curry powder with the garlic and ginger, 1 minute.","Add the crushed tomatoes; cook 3 minutes.","Pour in the coconut milk and simmer 5 minutes to a light sauce.","Slide in the dried shrimp; 2–3 minutes only, until just pink and curled.","Finish with garam masala and cilantro over rice — the shrimp keep cooking in the hot sauce, so err early."],"tip":"Shrimp curries live or die in a 90-second window — sauce first, shrimp last."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turmeric_khichdi', '{"id":"turmeric_khichdi","name":"Turmeric khichdi (rice & lentil comfort pot)","emoji":"🍚","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"rice","q":120},{"f":"lentils_dry","q":120},{"f":"turmeric","q":4},{"f":"cumin","q":4},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Rinse the rice and lentils together until the water runs clearish.","Bloom the cumin and ginger in the oil, 30 seconds; add the turmeric, rice, lentils and diced carrot.","Add 4 cups of water and a big pinch of salt; simmer partially covered 25 minutes, stirring occasionally, until porridgy.","Stir in the peas for the last 3 minutes.","Finish with lemon. Loose and spoonable is correct — it thickens as it sits."],"tip":"Khichdi is what Indian kitchens make when someone needs comfort — rice-and-lentils as a hug."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_lentil_bolognese', '{"id":"mushroom_lentil_bolognese","name":"Mushroom Lentil Bolognese","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"garlic","q":0.4},{"f":"mushrooms","q":400},{"f":"lentils_dry","q":250},{"f":"crushed_tomatoes","q":800},{"f":"oregano","q":3},{"f":"spaghetti","q":400},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Finely chop the mushrooms, onion, and carrots so they mimic the texture of a classic ragu.","Heat the olive oil in a wide pot over medium-high heat and cook the mushrooms undisturbed for 5 minutes, until their liquid evaporates and they turn deeply browned at the edges.","Stir in the onion, carrots, and garlic and cook 5 minutes more, then add the tomato paste and fry it for 2 minutes until it darkens to brick red and smells sweet.","Add the lentils, crushed tomatoes, 500 milliliters of water, oregano, salt, and pepper, then simmer partially covered for 30 to 35 minutes, until the lentils are tender and the sauce is thick enough to mound on a spoon.","Meanwhile, boil the spaghetti in well-salted water until just shy of al dente, then drag it into the sauce with a splash of pasta water and toss for 1 minute so every strand is coated.","Taste, adjust the salt, and serve in warm bowls with extra black pepper."],"tip":"Brown the mushrooms like you mean it — pale mushrooms make a sauce that tastes like a missed opportunity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_shawarma_bowls', '{"id":"chickpea_shawarma_bowls","name":"Chickpea Shawarma Bowls","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"olive_oil","q":25},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"cinnamon","q":1},{"f":"rice","q":130},{"f":"cucumber","q":1},{"f":"tomato","q":1.7},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"hummus","q":100},{"f":"parsley","q":0.2},{"f":"salt","q":4}],"steps":["Heat the oven to 220C (425F) and start the rice simmering in salted water so everything finishes together.","Pat the chickpeas very dry, then toss them with the olive oil, cumin, smoked paprika, turmeric, cinnamon, and salt until every one is stained golden.","Roast the chickpeas on a sheet pan for 20 to 25 minutes, shaking the pan halfway, until they are crisp outside and creamy inside.","While they roast, dice the cucumber and tomatoes, slice the red onion into thin half-moons, and toss the lot with half the lemon''s juice and a pinch of salt.","Pile the rice into two bowls, top with hot chickpeas and the cool salad, then finish with generous swoops of hummus, chopped parsley, and the remaining lemon squeezed over everything.","Eat immediately, while the chickpeas still crackle."],"tip":"Dry chickpeas roast crisp and wet chickpeas steam sad — a clean kitchen towel is your shawarma insurance policy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_tofu', '{"id":"coconut_curry_tofu","name":"Coconut Curry Tofu","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":45,"servings":2,"ing":[{"f":"tofu","q":450},{"f":"coconut_milk","q":250},{"f":"curry_powder","q":8},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"broccoli","q":250},{"f":"rice","q":140},{"f":"lime","q":1},{"f":"maple_syrup","q":10},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Press the tofu for 10 minutes, cut it into 2-centimeter cubes, and get the rice cooking in salted water.","Sear the tofu in the oil in a hot nonstick skillet for 8 to 10 minutes, turning occasionally, until golden and crusty on most sides, then set it aside.","In the same pan, soften the sliced onion and bell pepper for 4 minutes, then add the grated ginger, minced garlic, and curry powder and stir for 60 seconds until intensely fragrant.","Pour in the coconut milk with a splash of water, add the broccoli, maple syrup, and salt, and simmer for 6 to 8 minutes until the broccoli is bright and just tender and the sauce coats a spoon.","Return the tofu to the pan, simmer 2 minutes so it drinks up the sauce, and finish with a big squeeze of lime.","Serve over the rice with more lime on the side."],"tip":"Resist stirring the tofu while it sears — it releases from the pan on its own schedule, like a cat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_sweet_potato_hash', '{"id":"black_bean_sweet_potato_hash","name":"Black Bean Sweet Potato Hash","emoji":"🍳","cuisine":"American","meal":["breakfast","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":25},{"f":"paprika","q":4},{"f":"cumin","q":3},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Dice the sweet potatoes into 1-centimeter cubes so they cook through before they burn.","Heat the oil in your largest skillet over medium heat, add the sweet potatoes with a pinch of salt, and cook covered for 8 minutes, stirring once, until nearly tender.","Uncover, raise the heat to medium-high, and add the diced onion and bell pepper, cooking 6 to 8 minutes more until the potatoes are browned and crisp-edged.","Stir in the drained black beans, smoked paprika, and cumin and cook 3 minutes, pressing the hash flat against the pan so the bottom crackles and caramelizes.","Kill the heat, squeeze the lime over the top, and shower with cilantro.","Serve topped with sliced avocado and an extra pinch of salt on the avocado itself."],"tip":"The lid is a shortcut, not a lifestyle — take it off in time for the crispy bits, which are the whole point of hash."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_tikka_bowls', '{"id":"cauliflower_tikka_bowls","name":"Cauliflower Tikka Bowls","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":240},{"f":"coconut_milk","q":200},{"f":"crushed_tomatoes","q":250},{"f":"garam_masala","q":6},{"f":"turmeric","q":2},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"rice","q":140},{"f":"cilantro","q":0.3},{"f":"lemon","q":0.5},{"f":"salt","q":5}],"steps":["Heat the oven to 230C (450F), toss the cauliflower florets with half the oil, half the garam masala, the turmeric, and a pinch of salt, and roast for 22 to 25 minutes until charred at the tips.","Meanwhile, cook the rice and soften the diced onion in the remaining oil over medium heat for 5 minutes, until translucent and sweet.","Add the grated ginger, minced garlic, and remaining garam masala and fry for 60 seconds, then pour in the crushed tomatoes and simmer 8 minutes until the sauce darkens and thickens.","Stir in the coconut milk and chickpeas and simmer gently for 5 minutes more, until the sauce is silky and coats the back of a spoon.","Fold the roasted cauliflower into the sauce, letting the charred edges soak up the gravy for a minute or two.","Serve over rice with cilantro and a squeeze of lemon to wake everything up."],"tip":"Char is flavor — if your cauliflower looks a little too brave at the edges, it is exactly right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_avocado_rice_bowls', '{"id":"edamame_avocado_rice_bowls","name":"Edamame Avocado Rice Bowls","emoji":"🥑","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"edamame_frozen","q":300},{"f":"avocado","q":1.5},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"scallions","q":3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"maple_syrup","q":5},{"f":"ginger","q":10},{"f":"lime","q":1}],"steps":["Cook the rice, and while it steams, whisk the soy sauce, sesame oil, maple syrup, grated ginger, and the juice of half the lime into a glossy dressing.","Boil the edamame in salted water for 4 minutes, until bright green and just tender, then drain well.","Slice the cucumber into thin coins, shave the carrots into ribbons with a vegetable peeler, and slice the scallions on a sharp angle.","Fluff the hot rice and divide it between two bowls, then arrange the edamame, cucumber, carrots, and fanned avocado slices in neat sections on top.","Spoon the dressing over everything, scatter with scallions, and finish with the remaining lime squeezed at the table."],"tip":"Dress the bowl right before eating — soy sauce turns cucumber into a water feature if you let it sit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_chickpea_stew', '{"id":"moroccan_spiced_chickpea_stew","name":"Moroccan Spiced Chickpea Stew","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"cumin","q":6},{"f":"cinnamon","q":2},{"f":"paprika","q":5},{"f":"crushed_tomatoes","q":800},{"f":"chickpeas","q":720},{"f":"sweet_potatoes","q":400},{"f":"spinach","q":150},{"f":"lemon","q":1},{"f":"maple_syrup","q":10},{"f":"salt","q":8}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion with a pinch of salt for 6 to 8 minutes, until soft and golden at the edges.","Add the minced garlic, grated ginger, cumin, cinnamon, and smoked paprika and stir constantly for 60 seconds, until the spices bloom and the kitchen smells like a souk.","Pour in the crushed tomatoes, 750 milliliters of water, the maple syrup, chickpeas, and the sweet potatoes cut into 2-centimeter chunks, then bring to a lively simmer.","Cook uncovered for 25 to 30 minutes, stirring occasionally, until the sweet potatoes are fork-tender and the stew has thickened enough to leave a trail when you drag a spoon through it.","Stir in the spinach in handfuls until it wilts, then season with salt and the juice of the lemon.","Ladle into deep bowls and let it sit 5 minutes before serving — it thickens and improves as it rests."],"tip":"This stew is even better on day two, so consider dinner tonight merely a quality-control check."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('grilled_veggie_hummus_wraps', '{"id":"grilled_veggie_hummus_wraps","name":"Grilled Veggie Hummus Wraps","emoji":"🌯","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"hummus","q":150},{"f":"zucchini","q":1.5},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"spinach","q":60},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"salt","q":4}],"steps":["Slice the zucchini lengthwise into half-centimeter planks, cut the bell pepper into wide flat pieces, and slice the red onion into thick rings.","Toss the vegetables with olive oil, oregano, and salt, then grill them in a screaming-hot grill pan for 3 to 4 minutes per side, until deeply striped and tender but not mushy.","Hit the hot vegetables with a squeeze of lemon the moment they come off the heat so they drink it in.","Warm the tortillas for 20 seconds per side in the same pan, then spread each one edge-to-edge with a thick layer of hummus.","Layer on the spinach and grilled vegetables in a tight log down the center, then fold in the sides and roll firmly away from you.","Return each wrap to the pan seam-side down for a minute to seal and crisp before slicing on the diagonal."],"tip":"Hummus is both sauce and glue here — spread it to the edges or your wrap will unravel at the first ambitious bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cold_peanut_noodle_salad', '{"id":"cold_peanut_noodle_salad","name":"Cold Peanut Noodle Salad","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"peanut_butter","q":80},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"cabbage","q":0.2},{"f":"carrots","q":150},{"f":"cucumber","q":0.8},{"f":"scallions","q":3},{"f":"cilantro","q":0.3}],"steps":["Cook the rice noodles according to the package until just tender, then rinse them under cold water until completely cool and drain well.","Whisk the peanut butter, soy sauce, lime juice, maple syrup, sesame oil, grated ginger, and minced garlic with 3 to 4 tablespoons of warm water until the sauce is smooth and pourable, like heavy cream.","Shred the cabbage finely, cut the carrots and cucumber into thin matchsticks, and slice the scallions.","Toss the noodles and vegetables with the sauce in your biggest bowl, using tongs and some enthusiasm, until every strand is slicked.","Chill for 10 minutes if you can bear it, then top with cilantro and extra lime wedges and serve cold."],"tip":"Peanut sauce thickens as it sits, so keep a splash of water handy to loosen leftovers back to their former glory."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_ratatouille_bake', '{"id":"white_bean_ratatouille_bake","name":"White Bean Ratatouille Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":65,"servings":4,"ing":[{"f":"eggplant","q":0.9},{"f":"zucchini","q":2},{"f":"bell_pepper","q":2},{"f":"tomato","q":3.3},{"f":"crushed_tomatoes","q":400},{"f":"white_beans","q":800},{"f":"olive_oil","q":60},{"f":"garlic","q":0.5},{"f":"onion","q":1},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"salt","q":8}],"steps":["Heat the oven to 200C (400F) and cut the eggplant, zucchini, bell peppers, and fresh tomatoes into chunky 2-centimeter pieces.","In a large baking dish, stir together the crushed tomatoes, drained white beans, sliced garlic, diced onion, half the olive oil, oregano, red pepper flakes, and salt to make the saucy base.","Tumble the cut vegetables over the top, drizzle with the remaining oil, and season generously — eggplant is a salt sponge and rewards courage.","Bake uncovered for 45 to 50 minutes, stirring once at the halfway mark, until the vegetables are collapsed and jammy and the edges of the dish are bubbling and browned.","Rest the bake for 10 minutes out of the oven so the juices settle from soup back into sauce.","Shower with parsley and serve warm, in shallow bowls, with the crusty corner bits distributed fairly."],"tip":"Ratatouille punishes impatience — undercooked eggplant is squeaky, so give it the full bake and then some."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('taco_spiced_lentil_bowls', '{"id":"taco_spiced_lentil_bowls","name":"Taco Spiced Lentil Bowls","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"olive_oil","q":15},{"f":"rice","q":100},{"f":"corn_frozen","q":120},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Start the rice in salted water, then heat the oil in a saucepan and cook the diced onion over medium heat for 5 minutes until softened and lightly golden.","Add the minced garlic, chili powder, cumin, and smoked paprika and toast for 45 seconds, then stir in the tomato paste and fry until it deepens in color.","Add the rinsed lentils and 600 milliliters of water, bring to a boil, then simmer uncovered for 22 to 25 minutes, until the lentils are tender and the mixture is thick and saucy like taco filling.","Stir the corn into the lentils for the last 3 minutes and season assertively with salt and half the lime''s juice.","Build the bowls with rice on the bottom, a generous ladle of taco lentils, sliced avocado, cilantro, and the remaining lime in wedges.","Taste one spoonful before serving and ask yourself if it needs more lime — it usually does."],"tip":"Toasting the spices in oil for under a minute does more for flavor than doubling them ever could."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kale_white_bean_garlic_penne', '{"id":"kale_white_bean_garlic_penne","name":"Kale and White Bean Garlic Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":200},{"f":"white_beans","q":400},{"f":"kale","q":1},{"f":"garlic","q":0.6},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"salt","q":6}],"steps":["Boil the penne in aggressively salted water until 2 minutes shy of al dente, reserving a cup of the starchy water before draining.","Meanwhile, warm the olive oil in a large skillet over medium-low heat and cook the thinly sliced garlic for 2 to 3 minutes, until pale gold and fragrant — pull it before it browns and turns bitter.","Add the red pepper flakes, then the stemmed and torn kale with a good splash of water, and cook 4 minutes until the kale is silky and deep green.","Stir in the drained white beans, mashing about a third of them against the pan to create a creamy base.","Add the penne with a splash of pasta water and toss vigorously over medium heat for 2 minutes, until the starchy liquid tightens into a sauce that clings to the tubes.","Finish with lemon zest and juice, taste for salt, and serve straight from the pan."],"tip":"The mashed beans are doing the parmesan''s old job here — no one at the table needs to know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_walnut_baked_oatmeal', '{"id":"maple_walnut_baked_oatmeal","name":"Maple Walnut Baked Oatmeal","emoji":"🥣","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"oats","q":300},{"f":"walnuts","q":100},{"f":"maple_syrup","q":90},{"f":"banana","q":2},{"f":"coconut_milk","q":250},{"f":"cinnamon","q":4},{"f":"salt","q":2},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C (375F) and lightly oil a 20-centimeter baking dish.","Mash the bananas to a smooth puree in a large bowl, then whisk in the coconut milk, most of the maple syrup, the cinnamon, and the salt along with 250 milliliters of water.","Stir in the oats and half the walnuts, roughly chopped, then pour the mixture into the dish and let it sit 5 minutes so the oats begin to drink.","Scatter the remaining walnuts over the top and drizzle with the last of the maple syrup for a glossy, candied crust.","Bake for 35 to 40 minutes, until the center is just set and springs back lightly and the walnuts smell toasted.","Cool for 10 minutes before cutting into squares — it firms up dramatically as it rests."],"tip":"Bake it Sunday and you have breakfast until Thursday; a square reheats beautifully and even tolerates being eaten cold over the sink."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('carrot_ginger_soup', '{"id":"carrot_ginger_soup","name":"Silky Carrot-Ginger Soup","emoji":"🥕","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"carrots","q":500},{"f":"onion","q":1},{"f":"ginger","q":25},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"coconut_milk","q":200},{"f":"chickpeas","q":200},{"f":"maple_syrup","q":15}],"steps":["Warm the olive oil in a heavy pot over medium heat, then sweat the chopped onion with a pinch of salt for 5 minutes until translucent but not browned.","Stir in the sliced carrots, grated ginger, and minced garlic and cook 3 minutes more, until the ginger smells sharp and bright.","Pour in 750 ml of water and the maple syrup, add the chickpeas, and simmer uncovered for 20 minutes, until a carrot coin smashes easily against the side of the pot.","Add the coconut milk, then blend the soup in batches (or with an immersion blender) until completely silky, at least a full minute per batch.","Return to the pot, season with salt and black pepper, and reheat gently without boiling; serve with a swirl of the reserved coconut cream on top."],"tip":"Blend longer than feels reasonable — the difference between good and restaurant-silky is about 60 extra seconds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_white_bean_basil_soup', '{"id":"tomato_white_bean_basil_soup","name":"Tomato, White Bean & Basil Soup","emoji":"🍅","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":4,"ing":[{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":800},{"f":"white_beans","q":480},{"f":"basil","q":0.5},{"f":"maple_syrup","q":10}],"steps":["Heat the olive oil in a Dutch oven over medium heat and cook the diced onion with a generous pinch of salt for 6 to 8 minutes, until soft and just golden at the edges.","Add the minced garlic and cook 60 seconds, until fragrant but not browned, then pour in the crushed tomatoes, 1 liter of water, and the maple syrup.","Bring to a simmer, add the drained beans, and cook uncovered for 15 minutes so the tomatoes lose their raw tang and the broth thickens slightly.","Ladle a third of the soup into a blender, puree until smooth, and stir it back in — this gives you body while keeping whole beans for texture.","Off the heat, tear in the basil leaves, season assertively with salt and pepper, and let it rest 5 minutes before serving so the basil perfumes the whole pot."],"tip":"Add the basil off the heat, always — boiled basil tastes like regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_vegetable_rice_soup', '{"id":"garden_vegetable_rice_soup","name":"Garden Vegetable Rice Soup","emoji":"🍲","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"garlic","q":0.3},{"f":"zucchini","q":1},{"f":"peas_frozen","q":150},{"f":"crushed_tomatoes","q":400},{"f":"rice","q":200},{"f":"spinach","q":100}],"steps":["Heat the olive oil in a large pot over medium heat and cook the diced onion, carrot, and celery with a pinch of salt for 8 minutes, stirring occasionally, until the onion turns translucent.","Stir in the garlic and rice and toast for 2 minutes, until the grains look chalky and smell faintly nutty.","Add the crushed tomatoes and 1.5 liters of water, bring to a boil, then reduce to a steady simmer and cook 15 minutes with the lid ajar.","Add the zucchini and peas and simmer 8 to 10 minutes more, until the rice is tender and the zucchini yields to a spoon but still holds its shape.","Turn off the heat, stir in the spinach until it wilts, and season with salt and plenty of black pepper before ladling into bowls."],"tip":"The rice keeps drinking broth as leftovers sit, so stash a cup of extra water or broth to loosen tomorrow''s lunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_veggie_breakfast_burritos', '{"id":"tofu_veggie_breakfast_burritos","name":"Tofu Scramble Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"tortillas","q":4},{"f":"black_beans","q":150},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"salsa","q":120},{"f":"spinach","q":60},{"f":"olive_oil","q":15}],"steps":["Press the tofu between paper towels for 10 minutes, then crumble it into rough, egg-sized curds with your hands.","Heat the olive oil in a wide skillet over medium-high heat and saute the diced onion and bell pepper for 5 minutes, until the pepper blisters at the edges.","Add the crumbled tofu and a big pinch of salt (plus turmeric and cumin if your pantry allows) and cook 6 to 8 minutes, stirring only occasionally so the tofu picks up golden patches.","Fold in the black beans and spinach and cook 2 minutes, just until the spinach collapses and the beans are warmed through.","Warm the tortillas directly over a burner flame or in a dry pan for 20 seconds a side, then load each with scramble, sliced avocado, and salsa.","Fold in the sides, roll tightly away from you, and sear the burritos seam-side down for 1 minute to weld them shut."],"tip":"That final seam-side sear is non-negotiable — it is the difference between a burrito and a lap full of filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_cinnamon_quinoa_porridge', '{"id":"maple_cinnamon_quinoa_porridge","name":"Maple-Cinnamon Quinoa Porridge","emoji":"🥣","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":25,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"coconut_milk","q":200},{"f":"maple_syrup","q":45},{"f":"cinnamon","q":3},{"f":"banana","q":1},{"f":"walnuts","q":30}],"steps":["Rinse the quinoa in a fine-mesh sieve for 30 seconds to wash off its bitter coating, then drain well.","Combine the quinoa with 350 ml of water and a pinch of salt in a saucepan, bring to a boil, then cover and simmer on low for 12 minutes, until the grains show their little spiral tails.","Stir in the coconut milk, cinnamon, and maple syrup and simmer uncovered for 3 to 4 minutes, stirring, until the porridge is creamy and coats a spoon.","Meanwhile, toast the walnuts in a dry skillet over medium heat for 3 minutes, tossing often, until fragrant and a shade darker.","Divide the porridge between bowls and top with sliced banana, toasted walnuts, and an extra thread of maple syrup."],"tip":"Do not skip the rinse — unwashed quinoa carries a soapy bitterness that no amount of maple can bribe away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_butter_overnight_oats', '{"id":"peanut_butter_overnight_oats","name":"Peanut Butter Overnight Oats","emoji":"🥜","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"oats","q":120},{"f":"peanut_butter","q":60},{"f":"maple_syrup","q":30},{"f":"coconut_milk","q":250},{"f":"banana","q":1}],"steps":["Whisk the peanut butter, maple syrup, and a pinch of salt into the coconut milk in a bowl until no streaks remain — do this first, because peanut butter refuses to blend once the oats are in.","Stir in the oats until every flake is submerged and glossy.","Divide between two jars, press the surface flat with a spoon, and seal the lids.","Refrigerate at least 6 hours or overnight, until the oats are plump and the mixture is thick enough to hold a spoon upright for a beat.","In the morning, stir well, loosen with a splash of water if needed, and crown each jar with sliced banana."],"tip":"Slice the banana in the morning, not the night before, unless brown mush is your love language."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_chickpea_salad_sandwich', '{"id":"avocado_chickpea_salad_sandwich","name":"Smashed Avocado-Chickpea Salad Sandwich","emoji":"🥪","cuisine":"American","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"chickpeas","q":240},{"f":"avocado","q":1},{"f":"onion","q":0.3},{"f":"celery","q":60},{"f":"lemon","q":0.5},{"f":"tomato","q":1},{"f":"romaine","q":0.3},{"f":"olive_oil","q":15}],"steps":["Drain the chickpeas and tip them into a wide bowl with the avocado flesh, then mash with a fork until mostly crushed but still craggy — you want texture, not paste.","Fold in the finely diced red onion and celery, the olive oil, the juice of the half lemon, and a firm seasoning of salt and black pepper.","Taste and adjust: it should be bright enough to make you blink slightly, since bread mutes everything.","Toast the bread until golden and sturdy, then layer lettuce and tomato slices on two pieces.","Pile the chickpea salad high, cap with the remaining toast, press gently, and slice on the diagonal because it genuinely tastes better that way."],"tip":"The lemon juice is doing double duty as seasoning and avocado-browning bodyguard, so be generous."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_tacos', '{"id":"crispy_tofu_tacos","name":"Crispy Tofu Tacos with Lime Slaw","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"tortillas","q":4},{"f":"cabbage","q":0.2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"salsa","q":100},{"f":"olive_oil","q":30}],"steps":["Press the tofu for 15 minutes under a heavy skillet, then tear it into rough bite-sized chunks — ragged edges crisp better than clean cubes.","Toss the tofu with the cornstarch, a big pinch of salt, and smoked paprika and cumin if you have them, until every piece wears a thin dusty coat.","Heat the olive oil in a nonstick skillet over medium-high until shimmering, then fry the tofu in a single layer for 8 to 10 minutes, turning only when each side releases easily and is deeply golden.","While the tofu fries, toss the shredded cabbage with the juice of half the lime and a pinch of salt, squeezing it with your hands until it just softens.","Char the tortillas over a flame or in a dry pan for 20 seconds per side, then build each taco with slaw, crispy tofu, salsa, and sliced avocado.","Finish with the remaining lime cut into wedges for squeezing at the table."],"tip":"Tear the tofu instead of cubing it — those craggy edges are where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_sour_eggplant_caponata', '{"id":"sweet_sour_eggplant_caponata","name":"Sweet & Sour Eggplant Caponata","emoji":"🍆","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"eggplant","q":1.3},{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":60},{"f":"balsamic_vinegar","q":45},{"f":"maple_syrup","q":20},{"f":"chickpeas","q":200}],"steps":["Cut the eggplant into 3 cm cubes, salt them, and let them sit in a colander for 15 minutes before patting dry — dry eggplant browns; wet eggplant steams.","Heat two-thirds of the olive oil in a wide skillet over medium-high and fry the eggplant in two batches for 6 to 8 minutes each, until deeply bronzed on several sides, then set aside.","Add the remaining oil and cook the diced onion and celery for 5 minutes, until softened but still with a little bite.","Stir in the crushed tomatoes, olives, raisins, vinegar, maple syrup, and chickpeas and simmer 10 minutes, until the sauce turns thick and jammy.","Return the eggplant to the pan, fold gently so the cubes stay intact, and simmer 5 minutes more so everything trades flavors.","Rest off the heat for at least 15 minutes and serve warm or at room temperature, when the sweet-sour balance is at its loudest."],"tip":"Caponata is one of those rare dishes that is genuinely better tomorrow, so consider making it yesterday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('savory_mushroom_spinach_oatmeal', '{"id":"savory_mushroom_spinach_oatmeal","name":"Savory Mushroom & Spinach Oatmeal","emoji":"🍄","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"oats","q":120},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"soy_sauce","q":15},{"f":"avocado","q":1}],"steps":["Heat the olive oil in a saucepan over medium-high heat and sear the sliced mushrooms undisturbed for 4 minutes, then stir and cook 3 more, until browned and squeaky-free.","Add the minced garlic and cook 30 seconds, then splash in the soy sauce and let it sizzle and glaze the mushrooms.","Scoop out half the mushrooms for topping, then add the oats to the pan and toast for 1 minute, stirring to coat them in the pan drippings.","Pour in 600 ml of water, bring to a simmer, and cook 8 to 10 minutes, stirring now and then, until the oats are creamy and porridge-like.","Stir in the spinach until the greens wilt, then season with black pepper.","Serve topped with the reserved mushrooms and sliced avocado."],"tip":"Oatmeal is just risotto with better PR — treat it with the same respect and stir near the end for maximum creaminess."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_chickpea_spinach_saute', '{"id":"spanish_chickpea_spinach_saute","name":"Spanish Chickpea & Spinach Saute","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":480},{"f":"spinach","q":300},{"f":"olive_oil","q":45},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"paprika","q":5},{"f":"crushed_tomatoes","q":200},{"f":"lemon","q":0.5}],"steps":["Warm the olive oil in a large skillet over medium heat and cook the diced onion for 5 minutes, until soft and turning gold at the edges.","Add the sliced garlic and cook 90 seconds, until it just begins to color, then pull the pan off the heat and stir in the smoked paprika so it blooms without scorching.","Return to the heat, add the crushed tomatoes and raisins, and simmer 5 minutes until the mixture thickens into a rusty, fragrant sofrito.","Tip in the drained chickpeas and cook 5 minutes, crushing a handful against the pan with your spoon to thicken the sauce.","Add the spinach in big handfuls, folding until each addition collapses, then season with salt and finish with a hard squeeze of lemon.","Serve straight from the skillet while the chickpeas are still glistening."],"tip":"Paprika burns in seconds and turns bitter — blooming it off the heat is the cheapest insurance in Spanish cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_corn_black_bean_salad', '{"id":"charred_corn_black_bean_salad","name":"Charred Corn & Black Bean Salad","emoji":"🌽","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"corn_frozen","q":300},{"f":"black_beans","q":400},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.4},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3}],"steps":["Heat a dry cast-iron skillet over high heat until it just starts to smoke, then add the corn in a single layer and let it sit untouched for 3 minutes, until blackened in spots.","Toss and char 3 to 4 minutes more, until about a third of the kernels wear dark freckles, then tip into a large bowl to cool slightly.","Add the drained black beans, diced bell pepper, and finely sliced red onion to the warm corn.","Whisk the olive oil with the juice of the whole lime, a pinch of cumin if you like, and a serious pinch of salt, then pour it over and toss.","Fold in the chopped cilantro and diced avocado last, gently, so the avocado stays in cubes rather than becoming dressing.","Let the salad sit 10 minutes before serving — the beans need a moment to soak up the lime."],"tip":"Resist stirring the corn early; char is just patience wearing a smoky disguise."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_carrot_hummus_bowls', '{"id":"roasted_carrot_hummus_bowls","name":"Roasted Carrot & Hummus Grain Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":45,"servings":2,"ing":[{"f":"carrots","q":400},{"f":"hummus","q":200},{"f":"quinoa","q":140},{"f":"chickpeas","q":150},{"f":"olive_oil","q":30},{"f":"cucumber","q":0.8},{"f":"spinach","q":80},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 220C (425F) and cut the carrots into long diagonal batons of even thickness so they roast at the same pace.","Toss the carrots and drained chickpeas with most of the olive oil, salt, and cumin if you have it, spread on a sheet pan without crowding, and roast 25 to 30 minutes, flipping once, until the carrots are caramelized at the tips and the chickpeas rattle when you shake the pan.","Meanwhile, rinse the quinoa, simmer it covered in 330 ml of salted water for 12 minutes, then rest it off the heat 5 minutes and fluff with a fork.","Swipe a thick crescent of hummus around one side of each bowl like you mean it, then pile in the quinoa, spinach, and diced cucumber.","Top with the roasted carrots and crispy chickpeas, drizzle with the remaining olive oil, and finish with a squeeze of lemon and black pepper over everything."],"tip":"Crowded sheet pans steam instead of roast — give the carrots personal space and they will reward you with caramel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_pesto_zoodles', '{"id":"chicken_pesto_zoodles","name":"Chicken Pesto Zoodles with Walnut-Basil Pesto","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"zucchini","q":3},{"f":"basil","q":1},{"f":"walnuts","q":40},{"f":"parmesan","q":30},{"f":"olive_oil","q":40},{"f":"garlic","q":0.2},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes until fragrant, then blitz them with the basil leaves, garlic, parmesan, a squeeze of lemon, and 30 ml of the olive oil until you have a coarse, spoonable pesto; season with salt and pepper.","Slice the chicken breasts in half horizontally, pat dry, and season generously with salt and pepper.","Heat the remaining oil in a large skillet over medium-high and sear the chicken 4 to 5 minutes per side until deeply golden and cooked through, then rest it on a board for 5 minutes before slicing.","Spiralize or julienne the zucchini into noodles, then toss them in the still-hot skillet for just 60 to 90 seconds until barely tender but still snappy.","Pull the pan off the heat, fold in the pesto and sliced chicken, and toss until everything is glossy and green.","Finish with an extra grating of parmesan and a last squeeze of lemon."],"tip":"Zoodles go from al dente to swamp in about two minutes, so treat the skillet like a hot potato and get out fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_butter_salmon_green_beans', '{"id":"garlic_butter_salmon_green_beans","name":"Garlic Butter Salmon with Blistered Green Beans","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"green_beans","q":400},{"f":"butter","q":40},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets bone-dry with paper towels and season both sides with salt and pepper; a dry fillet is the whole secret to crisp skin.","Heat the olive oil in a large skillet over medium-high until it shimmers, lay the salmon in skin-side down, and press gently for 10 seconds so the skin stays flat; cook undisturbed for 5 to 6 minutes until the sides turn opaque halfway up.","Flip the fillets, add the butter and minced garlic, and baste the fish with the foaming butter for 2 minutes until it flakes at the thickest point, then move the salmon to warm plates.","Toss the green beans into the same garlicky butter and cook over high heat for 4 to 5 minutes until blistered in spots but still crisp-tender.","Squeeze in the juice of half the lemon, scrape up the browned bits, and season the beans with salt and pepper.","Plate the beans beside the salmon, spoon over the pan butter, and shower with chopped parsley and the remaining lemon in wedges."],"tip":"If the salmon skin sticks, it is not ready to flip — the fish will politely release itself when the crust is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lc_stuffed_pepper_skillet', '{"id":"lc_stuffed_pepper_skillet","name":"Low-Carb Stuffed Pepper Skillet with Cauliflower Rice","emoji":"🫑","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"cauliflower","q":0.5},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":200},{"f":"cheddar","q":60},{"f":"olive_oil","q":15},{"f":"cumin","q":3},{"f":"paprika","q":4},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pulse the cauliflower florets in a food processor until they look like rice, or grate them on the coarse side of a box grater; set aside.","Heat the olive oil in a large skillet over medium-high, brown the ground beef for 5 to 6 minutes, breaking it into crumbles, and spoon off all but a slick of fat.","Add the diced onion and bell peppers and cook 5 minutes until the peppers soften at the edges, then stir in the garlic, cumin, paprika, and oregano for 30 seconds until fragrant.","Pour in the crushed tomatoes, fold in the cauliflower rice, season with salt and pepper, and simmer for 6 to 8 minutes until the cauliflower is tender and the mixture has thickened enough to mound on a spoon.","Scatter the cheddar over the top, cover, and cook 2 minutes until melted and bubbling.","Let the skillet rest off the heat for a few minutes so the flavors settle, then serve straight from the pan."],"tip":"All the flavor of stuffed peppers with none of the architectural engineering — nobody misses standing them upright."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_pork_medallions_cabbage', '{"id":"balsamic_pork_medallions_cabbage","name":"Balsamic Pork Medallions with Buttered Cabbage","emoji":"🥩","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"cabbage","q":0.5},{"f":"balsamic_vinegar","q":45},{"f":"olive_oil","q":30},{"f":"butter","q":20},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"broth","q":100},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into 2.5 cm medallions, flatten each slightly with the heel of your hand, and season well with salt and pepper.","Heat half the olive oil in a wide skillet over medium-high and sear the medallions 3 minutes per side until mahogany-brown and just cooked through, then move them to a plate to rest.","Add the remaining oil, the butter, sliced onion, and thinly shredded cabbage to the pan and cook 8 to 10 minutes, stirring occasionally, until the cabbage collapses and picks up golden edges.","Stir in the garlic for 30 seconds, then push the cabbage aside and pour the balsamic and broth into the pan, scraping up every browned bit.","Simmer 2 to 3 minutes until the liquid turns syrupy enough to coat a spoon, then return the medallions and their juices to glaze in the sauce for a final minute.","Serve the pork on a bed of cabbage with the balsamic pan sauce spooned over."],"tip":"Pork loin punishes overcooking, so pull it when it still has the faintest blush — carryover heat finishes the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_lettuce_cups', '{"id":"chicken_fajita_lettuce_cups","name":"Chicken Fajita Lettuce Cups","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":30},{"f":"cumin","q":4},{"f":"chili_powder","q":6},{"f":"paprika","q":3},{"f":"salt","q":3}],"steps":["Slice the chicken breasts into finger-width strips and toss them with half the olive oil, the cumin, chili powder, paprika, salt, and the juice of half the lime; let them sit while you prep the vegetables.","Slice the bell peppers and onion into thin strips, and separate, wash, and dry the sturdiest romaine leaves to use as cups.","Get a large skillet screaming hot with the remaining oil and sear the chicken in a single layer for 2 to 3 minutes per side until charred at the edges and cooked through, then set aside.","Throw the peppers and onion into the same pan and cook over high heat for 4 to 5 minutes, tossing occasionally, until softened with real char spots.","Return the chicken to the pan, squeeze over the rest of the lime, and toss everything together with the cilantro.","Pile the sizzling fajita mixture into the romaine cups and top each with slices of avocado."],"tip":"Resist the urge to stir constantly — char only happens when you leave things alone long enough to get slightly nervous."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chicken_cauliflower_rice', '{"id":"greek_chicken_cauliflower_rice","name":"Greek Chicken over Lemon Cauliflower Rice","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"cauliflower","q":0.5},{"f":"feta","q":60},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":200},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toss the chicken thighs with half the olive oil, the oregano, half the lemon''s juice, a little minced garlic, salt, and pepper, and marinate for at least 10 minutes.","Sear the thighs in a hot skillet over medium-high for 5 to 6 minutes per side until burnished and cooked through, then rest them on a board.","Pulse the cauliflower into rice-sized bits, then sauté it in the same pan with the remaining oil and garlic for 4 to 5 minutes until tender and picking up the chicken''s browned bits.","Season the cauliflower rice with the rest of the lemon juice, salt, and pepper, and spread it over a platter.","Slice the chicken and arrange it on top with the halved cherry tomatoes, diced cucumber, olives, and crumbled feta.","Shower with chopped parsley and serve with lemon wedges on the side."],"tip":"Cauliflower rice cooked in the chicken pan tastes suspiciously like effort, and no one needs to know it took five minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_cabbage_skillet', '{"id":"cheeseburger_cabbage_skillet","name":"Cheeseburger Cabbage Skillet","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"cabbage","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cheddar","q":80},{"f":"tomato","q":1},{"f":"olive_oil","q":15},{"f":"paprika","q":4},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your largest skillet over medium-high and brown the ground beef hard for 5 to 6 minutes, breaking it up but letting it develop crusty bits before you stir.","Add the diced onion and cook 3 minutes until translucent, then stir in the garlic and paprika for 30 seconds until fragrant.","Pile in the thinly sliced cabbage — it will look absurd, then shrink — and cook, tossing every couple of minutes, for 8 to 10 minutes until wilted and sweet with golden edges.","Fold in the diced tomato, season assertively with salt and pepper, and cook 2 more minutes until the tomato slumps into the beef.","Scatter the cheddar over the top, cover, and let it melt into gooey pockets for about 2 minutes.","Serve straight from the skillet like the honest one-pan dinner it is."],"tip":"It tastes like a drive-thru cheeseburger that got a promotion — the pickle-craving is normal, lean into it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_cauliflower_rice', '{"id":"lemon_shrimp_cauliflower_rice","name":"Lemon Garlic Shrimp with Buttery Cauliflower Rice","emoji":"🍤","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"cauliflower","q":0.5},{"f":"butter","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"broth","q":60},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pulse the cauliflower into rice-sized grains and pat the shrimp completely dry, seasoning them with salt and pepper.","Heat the olive oil in a large skillet over medium-high and sear the shrimp in a single layer for 90 seconds per side until pink and just curled into loose C-shapes, then transfer to a plate — a tight O-shape means overdone.","Melt the butter in the same pan, add the minced garlic, and cook 30 seconds until fragrant but not browned.","Stir in the cauliflower rice and broth and cook 4 to 5 minutes, stirring, until tender and the pan is nearly dry.","Return the shrimp with any juices, squeeze in the lemon, and toss for a final minute so everything glosses over.","Finish with chopped parsley, black pepper, and lemon wedges."],"tip":"Shrimp cook in the time it takes to find your tongs, so have everything else done before they hit the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_chicken_spinach_skillet', '{"id":"tuscan_chicken_spinach_skillet","name":"Tuscan Chicken and Spinach Skillet with Ricotta","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"spinach","q":150},{"f":"ricotta","q":150},{"f":"roasted_red_peppers","q":80},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"broth","q":100},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Halve the chicken breasts horizontally into cutlets, pat dry, and season with salt, pepper, and oregano.","Heat the olive oil in a large skillet over medium-high and sear the cutlets 4 minutes per side until golden and cooked through, then set them on a plate.","Lower the heat to medium, cook the garlic in the pan drippings for 30 seconds, then add the sliced roasted red peppers and broth, scraping up the fond.","Whisk in the ricotta and parmesan and simmer 2 to 3 minutes until the sauce is creamy and coats the back of a spoon.","Fold in the spinach a handful at a time until it wilts into the sauce, then nestle the chicken back in and spoon sauce over the top.","Simmer one more minute to reunite everything, taste for salt, and serve hot from the pan."],"tip":"Ricotta makes a gentler, lighter cream sauce than heavy cream — whisk it in off the boil so it stays silky instead of grainy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_stuffed_zucchini_boats', '{"id":"turkey_stuffed_zucchini_boats","name":"Italian Turkey Stuffed Zucchini Boats","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":3},{"f":"crushed_tomatoes","q":250},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the seedy centers with a spoon, leaving a 1 cm wall; chop the scooped flesh and reserve it.","Brush the boats with a little of the olive oil, season with salt, and roast cut-side up for 10 minutes to start them softening.","Meanwhile, brown the ground turkey in the remaining oil over medium-high for 5 to 6 minutes, then add the diced onion, reserved zucchini flesh, and garlic and cook 3 minutes more.","Stir in the crushed tomatoes, oregano, salt, and pepper and simmer 5 minutes until the filling is thick enough to hold its shape on a spoon.","Mound the filling into the boats, top with mozzarella and parmesan, and bake 15 minutes until the cheese is bubbling and spotted brown.","Rest for 5 minutes, then scatter with torn basil before serving."],"tip":"Scooping the seeds is not optional — a watery boat sinks even the best filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_ginger_pork_green_beans', '{"id":"garlic_ginger_pork_green_beans","name":"Garlic-Ginger Pork with Snappy Green Beans","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"green_beans","q":400},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":20},{"f":"scallions","q":0.5},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin against the grain into thin strips and toss with half the soy sauce and a good grind of black pepper; let it sit 10 minutes while you trim the green beans.","Heat half the olive oil in a wok or large skillet until it just starts to smoke, then stir-fry the green beans for 4 to 5 minutes until blistered and wrinkled in spots; transfer to a plate.","Add the remaining olive oil and sear the pork in a single layer for 2 minutes without touching it, then stir-fry 2 minutes more until the edges brown.","Push the pork aside and sizzle the minced garlic and ginger in the center of the pan for 30 seconds until wildly fragrant.","Return the green beans, splash in the remaining soy sauce, and toss everything over high heat for a final minute until glossy.","Kill the heat, stir in the sesame oil, and top with sliced scallions."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it off the heat or you will torch its charm."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_stuffed_avocados', '{"id":"caprese_stuffed_avocados","name":"Caprese Stuffed Avocados with Balsamic Drizzle","emoji":"🥑","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy"],"time":15,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"mozzarella","q":120},{"f":"cherry_tomatoes","q":200},{"f":"basil","q":0.5},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":20},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Simmer the balsamic vinegar in a small pan over medium heat for 3 to 4 minutes until it reduces by half and coats a spoon like thin syrup, then set aside to thicken as it cools.","Quarter the cherry tomatoes, dice the mozzarella into small cubes, and tear the basil leaves by hand.","Toss the tomatoes, mozzarella, and basil with the olive oil, salt, and a generous grind of black pepper.","Halve and pit the avocados, then scoop out a spoonful from each cavity to widen the bowl, dicing the scooped flesh into the salad.","Season the avocado halves with salt, pile the caprese mixture high into each one, and drizzle the balsamic reduction over the top.","Serve immediately, while the avocado is still bright green and smug about it."],"tip":"Reduce the balsamic while you chop — walk away and you will learn what burnt vinegar does to a kitchen''s morale."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_mushroom_chicken_thighs', '{"id":"creamy_mushroom_chicken_thighs","name":"Creamy Mushroom Chicken Thighs","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"mushrooms","q":300},{"f":"sour_cream","q":120},{"f":"broth","q":150},{"f":"butter","q":20},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"paprika","q":4},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the chicken thighs dry and season both sides with salt, pepper, and half the paprika.","Heat the olive oil in a deep skillet over medium-high and sear the thighs 5 to 6 minutes per side until deeply golden, then set them aside on a plate.","Melt the butter in the drippings, add the sliced mushrooms in a single layer, and resist stirring for 3 minutes so they brown properly before tossing; cook 3 minutes more with the diced onion until everything is bronzed.","Stir in the garlic and remaining paprika for 30 seconds, then pour in the broth and scrape up the browned bits, simmering 2 minutes to reduce slightly.","Drop the heat to low, whisk in the sour cream until the sauce is smooth and pale gold, and return the chicken with its juices to simmer gently for 5 minutes until the sauce coats a spoon.","Taste for salt, scatter with chopped parsley, and serve with plenty of sauce over each thigh."],"tip":"Sour cream splits if it boils, so once it goes in, keep the pan at a lazy murmur, not a rolling argument."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('denver_omelet_skillet', '{"id":"denver_omelet_skillet","name":"Denver Omelet Skillet","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"bacon","q":150},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":80},{"f":"butter","q":15}],"steps":["Melt the butter in a 10-inch oven-safe skillet over medium heat until it foams, then add the diced ham, bell pepper, and onion.","Saute for 5 to 6 minutes, stirring occasionally, until the ham edges brown and the peppers soften and smell sweet.","Whisk the eggs with a pinch of salt and plenty of black pepper until no streaks of white remain, then pour them over the vegetables and lower the heat.","Let the eggs set undisturbed for 2 minutes, then drag a spatula around the edges so uncooked egg flows underneath.","Scatter the cheddar on top, cover, and cook 3 to 4 more minutes until the center barely jiggles and the cheese melts into glossy pools.","Cut into wedges straight from the skillet and serve hot."],"tip":"Dice the ham and peppers the same size so every bite gets the full Denver treatment instead of a pepper ambush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fluffy_cottage_cheese_omelet', '{"id":"fluffy_cottage_cheese_omelet","name":"Fluffy Cottage Cheese Omelet","emoji":"🥚","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cottage_cheese","q":200},{"f":"spinach","q":60},{"f":"butter","q":15}],"steps":["Whisk the eggs vigorously for a full minute with a pinch of salt until frothy and pale, which is the secret to a cloud-like texture.","Melt half the butter in a nonstick skillet over medium-low heat and pour in half the eggs, tilting the pan to coat.","When the edges set but the surface still looks glossy, about 2 minutes, spoon half the cottage cheese and a handful of spinach down the center.","Cover for 60 seconds so the spinach wilts and the cheese warms, then fold the omelet over itself and slide it onto a plate.","Repeat with the remaining butter, eggs, and filling, and finish both omelets with cracked black pepper."],"tip":"Keep the heat gentle; a browned omelet is a breakfast confession, not a badge of honor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_club_lettuce_wraps', '{"id":"turkey_club_lettuce_wraps","name":"Turkey Club Lettuce Wraps","emoji":"🥬","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"bacon","q":100},{"f":"romaine","q":1},{"f":"tomato","q":2},{"f":"avocado","q":1}],"steps":["Cook the bacon in a cold skillet set over medium heat, turning occasionally, until deeply crisp, about 8 minutes, then drain on paper towels.","Separate the romaine into 8 sturdy outer leaves, rinse, and pat completely dry so the mayonnaise has something to cling to.","Slice the tomatoes thinly, season them with salt, and cut the avocado into ribbons.","Spread each leaf with a thin swipe of mayonnaise, then layer on turkey, tomato, avocado, and a shard of bacon.","Stack two leaves per wrap for structural integrity, fold like a taco, and secure with a toothpick if they get rowdy."],"tip":"Salt the tomato slices five minutes ahead so they taste like summer instead of wet cardboard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_egg_salad_wraps', '{"id":"avocado_egg_salad_wraps","name":"Avocado Egg Salad Wraps","emoji":"🥑","cuisine":"American","meal":["lunch"],"diets":["vegetarian","low-carb","gluten-free","dairy-free"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"avocado","q":1.5},{"f":"romaine","q":1},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then plunge them into ice water for 5 minutes before peeling.","Mash the avocado in a bowl with the lemon juice, a generous pinch of salt, and black pepper until creamy but still a little chunky.","Chop the eggs roughly and mince the onion finely, then fold both into the avocado until everything is coated in green.","Taste and adjust with more lemon or salt; the mixture should be bright enough to make you blink.","Separate the romaine into crisp leaves and pile the egg salad into each one just before eating so the lettuce stays snappy."],"tip":"The lemon juice is doing double duty as seasoning and avocado bodyguard, so do not skimp on it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_yogurt_chicken_salad', '{"id":"greek_yogurt_chicken_salad","name":"Greek Yogurt Chicken Salad","emoji":"🥗","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"celery","q":100},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"romaine","q":1}],"steps":["Poach the chicken breasts in barely simmering salted water for 12 to 15 minutes until they register 165F at the thickest point, then rest 5 minutes.","Shred the chicken into bite-size pieces while still warm; warm chicken drinks up dressing far better than cold.","Stir the greek yogurt with the lemon juice, salt, and pepper until smooth and tangy.","Fold in the chicken, finely diced celery, and minced onion until every shred is glossed with dressing.","Chill for 10 minutes if you can bear the wait, then spoon into crisp romaine leaves and serve."],"tip":"Keep the poaching water at a lazy shimmer, not a boil, unless you enjoy chicken with the texture of a stress ball."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_zucchini_fritters', '{"id":"parmesan_zucchini_fritters","name":"Parmesan Zucchini Fritters","emoji":"🥒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"zucchini","q":2.5},{"f":"eggs","q":2},{"f":"parmesan","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":45}],"steps":["Grate the zucchini on the large holes of a box grater, toss with a teaspoon of salt, and let it sit in a colander for 15 minutes.","Squeeze the zucchini in a clean kitchen towel with real conviction until you have wrung out nearly half a cup of liquid.","Stir the dry zucchini with the eggs, grated parmesan, minced garlic, and plenty of black pepper; the parmesan and egg act as the only binder you need.","Heat the olive oil in a wide skillet over medium heat until it shimmers, then drop in heaping tablespoons of batter and flatten gently.","Fry 3 to 4 minutes per side until deeply golden and lacy at the edges, working in batches so the pan never crowds.","Drain on a rack, sprinkle with flaky salt, and eat while the cheese is still crackly."],"tip":"Every drop of water you fail to squeeze out returns later as a soggy fritter, so channel your grievances into that towel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_salad', '{"id":"chili_lime_shrimp_salad","name":"Chili Lime Shrimp Salad","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"romaine","q":1},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3}],"steps":["Pat the shrimp bone dry, then toss with half the olive oil, the zest of one lime, chili powder, and a big pinch of salt.","Sear the shrimp in a screaming-hot skillet for 90 seconds per side until they curl into loose commas and pick up charred edges; pull them off immediately.","Whisk the remaining olive oil with the juice of both limes, salt, and a pinch of chili to make a dressing that bites back.","Chop the romaine into ribbons, dice the avocado, and toss both with most of the dressing in a wide bowl.","Pile the warm shrimp on top, drizzle with the last of the dressing, and shower with torn cilantro."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C, like it is lounging in the dressing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_egg_bites', '{"id":"caprese_egg_bites","name":"Caprese Egg Bites","emoji":"🍅","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mozzarella","q":120},{"f":"cherry_tomatoes","q":150},{"f":"basil","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 350F and brush eight muffin cups generously with the olive oil so the bites release cleanly.","Whisk the eggs with salt and pepper until completely uniform, then stir in most of the diced mozzarella and torn basil.","Halve the cherry tomatoes and drop two or three halves into each cup, cut side up, before pouring the egg mixture over them.","Top each cup with the reserved mozzarella and bake 18 to 20 minutes until puffed, set in the center, and blistered gold on top.","Cool 5 minutes in the pan; they will deflate slightly and release with a gentle twist.","Finish with fresh basil and a crack of pepper before serving warm."],"tip":"These reheat beautifully, so make a double batch unless you enjoy negotiating with future you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_stuffed_peppers', '{"id":"tuna_stuffed_peppers","name":"Mediterranean Tuna Stuffed Peppers","emoji":"🫑","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"bell_pepper","q":2},{"f":"feta","q":60},{"f":"olives","q":50},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Drain the tuna thoroughly and flake it into a bowl with a fork until no large chunks remain.","Fold in the crumbled feta, chopped olives, minced onion, olive oil, lemon juice, and a heavy grind of black pepper.","Taste before salting; between the feta and olives, the mixture may already be seasoned like the Aegean.","Halve the bell peppers through the stem, scrape out the seeds and ribs, and season the cavities lightly.","Mound the tuna mixture into each pepper half, pressing gently so it holds, and finish with a final thread of olive oil and lemon."],"tip":"Choose peppers that sit flat on their backs, because a capsized pepper takes its filling down with it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_broccoli_cheddar_bake', '{"id":"chicken_broccoli_cheddar_bake","name":"Chicken Broccoli Cheddar Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"broccoli","q":400},{"f":"cheddar","q":100},{"f":"sour_cream","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 400F and cut the chicken into bite-size chunks, seasoning them well with salt and pepper.","Sear the chicken in olive oil over medium-high heat for 3 to 4 minutes until golden on the outside but not fully cooked, then transfer to a baking dish.","Blanch the broccoli florets in boiling salted water for 2 minutes, drain hard, and scatter them among the chicken.","Stir the sour cream with the minced garlic and half the cheddar, then spoon it evenly over the dish like a duvet.","Top with the remaining cheddar and bake 18 to 20 minutes until the sauce bubbles at the edges and the top turns burnished gold.","Rest 5 minutes before serving so the sauce thickens from soupy to spoonable."],"tip":"Drain the broccoli like you mean it, because steamed florets hide a shocking amount of sauce-thinning water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_salad_cucumber_boats', '{"id":"salmon_salad_cucumber_boats","name":"Salmon Salad Cucumber Boats","emoji":"🥒","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"cucumber","q":2},{"f":"greek_yogurt","q":100},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Season the salmon with salt and pepper and roast at 400F for 10 to 12 minutes until it flakes at the nudge of a fork, then cool slightly.","Flake the salmon into a bowl, discarding any skin, and keep the pieces chunky for texture.","Stir the greek yogurt with the lemon juice, chopped dill, minced onion, salt, and pepper, then fold in the salmon gently.","Halve the cucumbers lengthwise and drag a spoon down each center to scoop out the seeds, creating sturdy boats.","Salt the hollows lightly, pile in the salmon salad, and finish with extra dill and a squeeze of lemon."],"tip":"Scoop the cucumber seeds even if you are tempted to skip it, or your boats will spring a leak by lunchtime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_mushroom_frittata', '{"id":"bacon_mushroom_frittata","name":"Bacon Mushroom Frittata","emoji":"🍄","cuisine":"American","meal":["breakfast","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":7},{"f":"bacon","q":120},{"f":"mushrooms","q":250},{"f":"parmesan","q":40},{"f":"onion","q":0.5}],"steps":["Heat the oven to 375F, then cook the chopped bacon in a 10-inch oven-safe skillet over medium heat until crisp, about 6 minutes.","Remove the bacon but leave 2 tablespoons of fat in the pan, then add the sliced mushrooms and onion.","Cook 8 minutes without fussing until the mushrooms release their liquid, the pan goes dry again, and everything turns deeply browned.","Whisk the eggs with the parmesan, salt, and pepper, stir the bacon back in, and pour the mixture over the vegetables.","Cook 2 minutes on the stovetop until the edges just set, then transfer to the oven for 10 to 12 minutes until the center is puffed and no longer wobbles.","Cool 5 minutes, run a spatula around the rim, and slide the frittata onto a board to slice into wedges."],"tip":"Mushrooms brown only after they stop steaming, so resist stirring and let the pan do its quiet work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_ricotta_breakfast_bowls', '{"id":"berry_ricotta_breakfast_bowls","name":"Berry Ricotta Breakfast Bowls","emoji":"🫐","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"ricotta","q":300},{"f":"berries","q":270},{"f":"almonds","q":30},{"f":"lemon","q":0.5}],"steps":["Whip the ricotta with the lemon zest and a tiny pinch of salt for a minute until it loosens into something silky and mousse-like.","Toast the almonds in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until fragrant and golden at the edges.","Hull and quarter the strawberries and toss them with the blueberries and a small squeeze of lemon juice to wake up their sweetness.","Divide the whipped ricotta between two bowls, swooshing it up the sides with the back of a spoon.","Spoon the berries into the center and scatter the warm almonds over everything just before serving."],"tip":"That pinch of salt in the ricotta is not optional; it is the difference between dessert and breakfast that tastes like dessert."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_shawarma_style_plates', '{"id":"chicken_shawarma_style_plates","name":"Chicken Shawarma-Style Plates","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.8},{"f":"tomato","q":1.3},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Slice the chicken breast into thin strips and toss with half the olive oil, the juice of half the lemon, and a generous shower of cumin, smoked paprika, coriander, and salt until every piece is stained brick-red.","Let the chicken sit for 10 minutes while you dice the cucumber and tomato, slice the onion into thin half-moons, and stir the remaining lemon juice and a pinch of salt into the yogurt for a quick sauce.","Heat the remaining oil in a large skillet over medium-high until it shimmers, then lay the chicken in a single layer and leave it alone for 3 minutes so the edges char and crisp.","Flip and cook 3 to 4 minutes more, until the strips are deeply browned at the corners and no longer pink in the center.","Warm the pitas directly in the empty skillet for 30 seconds per side until soft and lightly blistered.","Pile the chicken over the pitas, scatter on the cucumber, tomato, and onion, and finish with thick ribbons of the lemony yogurt."],"tip":"Resist the urge to stir the chicken constantly — shawarma flavor lives in the char you only get by leaving it alone."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_bean_chili', '{"id":"smoky_beef_bean_chili","name":"Smoky Beef and Bean Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"black_beans","q":400},{"f":"tomato","q":3.3},{"f":"onion","q":1},{"f":"bell_pepper","q":1.3},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a heavy pot over medium-high, add the ground beef in one layer, and let it sear untouched for 4 minutes until a deep brown crust forms on the bottom before breaking it up.","Stir in the diced onion and bell pepper and cook 5 minutes, scraping the browned bits off the pot floor as the vegetables soften and turn glossy.","Add a heaping spoonful each of chili powder, smoked paprika, and cumin plus a pinch of salt, and toast the spices in the fat for a full minute until the whole kitchen smells like a barbecue pit.","Chop the tomatoes and add them with the drained black beans and a splash of water, then bring everything to a lively simmer.","Drop the heat to low, cover partially, and simmer 25 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged across the bottom leaves a brief trail.","Taste, adjust the salt, and let it rest off the heat for 5 minutes so the flavors settle into each other."],"tip":"Chili is one of the few dishes that genuinely improves overnight, so make it a day early and take all the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_burrito_skillet', '{"id":"turkey_burrito_skillet","name":"Turkey Burrito Skillet","emoji":"🌯","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":1.7},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the oil in a deep skillet over medium-high and brown the ground turkey for 5 minutes, breaking it into rough crumbles and seasoning with chili powder, cumin, garlic powder, and salt.","Add the diced onion and bell pepper and cook 4 minutes more, until the onion turns translucent and the pepper edges begin to soften.","Stir in the rice, chopped tomatoes, drained black beans, and 350 ml of water, scraping any browned bits into the mix.","Bring to a boil, then cover, reduce the heat to low, and simmer 18 minutes without peeking, until the rice is tender and has drunk up nearly all the liquid.","Kill the heat, scatter the cheddar evenly over the top, and re-cover for 2 minutes so the cheese melts into molten pools.","Fluff gently at the table so everyone sees the cheese pull."],"tip":"All the burrito, none of the structural engineering — the skillet never falls apart in your hands."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_salmon_quinoa', '{"id":"maple_glazed_salmon_quinoa","name":"Maple-Glazed Salmon with Quinoa","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"quinoa","q":120},{"f":"maple_syrup","q":30},{"f":"broccoli","q":300},{"f":"olive_oil","q":15},{"f":"lemon","q":1}],"steps":["Rinse the quinoa, then simmer it in 300 ml of salted water, covered, for 15 minutes until the little spirals pop free and the water is absorbed.","Meanwhile, whisk the maple syrup with the juice of half the lemon, a pinch of salt, and plenty of black pepper to make a glaze that just coats a spoon.","Pat the salmon bone-dry, season it, and sear skin-side up in the hot oil over medium-high for 4 minutes until a golden crust releases easily from the pan.","Flip the fillets, tuck the broccoli florets around them with a splash of water, and pour the glaze over the fish.","Cook 3 to 4 minutes more, spooning the bubbling glaze over the salmon until it turns lacquered and the broccoli is bright green and crisp-tender.","Fluff the quinoa, top with the salmon and broccoli, and finish with the remaining lemon squeezed over everything."],"tip":"A dry salmon fillet is a browned salmon fillet — pat it down like you mean it before it touches the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_pepper_rice_skillet', '{"id":"beef_pepper_rice_skillet","name":"Beef and Pepper Rice Skillet","emoji":"🥩","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"rice","q":130},{"f":"bell_pepper","q":2.1},{"f":"onion","q":0.7},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Simmer the rice in 280 ml of water, covered, for 15 minutes, then let it steam off the heat while you cook everything else.","Get a large skillet ripping hot over high heat, add the sesame oil, and sear the ground beef in a flat layer for 3 minutes until the underside is crusty and browned.","Break up the beef, push it to one side, and add the sliced bell peppers and onion, stir-frying 3 to 4 minutes until the peppers blister at the edges but keep their snap.","Pour in the soy sauce and a very generous grind of black pepper — this dish wants more pepper than feels reasonable — and toss everything together for 1 minute.","Add the cooked rice, pressing it into the pan so it sizzles and picks up the sauce, then fold it through the beef and vegetables.","Serve straight from the skillet while the bottom layer of rice is still crackling."],"tip":"Black pepper is the headline act here, not a garnish — grind until your wrist complains, then add a little more."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_lentil_stew', '{"id":"chicken_lentil_stew","name":"Mediterranean Chicken and Lentil Stew","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":600},{"f":"lentils_dry","q":250},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"tomato","q":2.5},{"f":"spinach","q":150},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Cut the chicken thighs into large chunks, season well with salt, oregano, and cumin, and brown them in the olive oil over medium-high heat for 5 minutes until golden on at least two sides.","Lift the chicken out, drop the heat to medium, and cook the diced onion and carrot in the same pot for 5 minutes, scraping up the browned chicken bits as the vegetables soften.","Add the chopped tomatoes and cook 3 minutes until they slump and turn jammy, then stir in the rinsed lentils and 1 liter of water.","Return the chicken and any juices to the pot, bring to a boil, then reduce to a gentle simmer and cook uncovered for 30 minutes, until the lentils are creamy-tender and the broth has thickened to a stew.","Fold in the spinach by the handful and let it wilt for 2 minutes.","Finish with the juice of the lemon and taste for salt — the acid is what makes the whole pot snap into focus."],"tip":"If the stew looks too thick, add water; if it looks too thin, wait ten minutes — lentils always get there eventually."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_fried_rice', '{"id":"pork_fried_rice","name":"Weeknight Pork Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","eggs","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice","q":140},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 300 ml of water for 15 minutes, then spread it on a plate to cool and dry out — slightly stale rice is the secret to fried rice that doesn''t clump.","Dice the pork tenderloin into small cubes and stir-fry it in the olive oil over high heat for 3 to 4 minutes until browned at the edges and just cooked through, then push it to the side of the pan.","Crack the eggs into the cleared space and scramble them hard for 30 seconds until just set in soft curds.","Add the diced carrot and frozen peas and toss for 2 minutes until the peas turn vivid green and the carrot loses its raw crunch.","Add the cooled rice, drizzle the soy sauce around the rim of the pan so it toasts on the hot metal, and toss everything for 2 minutes until each grain is coated and lightly crisped.","Kill the heat, stir in the sesame oil last so its fragrance survives, and serve immediately."],"tip":"Fried rice punishes patience — have every ingredient chopped and within arm''s reach before the pan gets hot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_quinoa_paella_style', '{"id":"shrimp_quinoa_paella_style","name":"Shrimp Quinoa Paella-Style","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"quinoa","q":150},{"f":"peas_frozen","q":100},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"tomato","q":1.3},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Warm the olive oil in a wide, shallow skillet over medium heat and cook the diced onion and bell pepper for 5 minutes until soft and sweet.","Add the chopped tomato and a full teaspoon of smoked paprika and cook 3 minutes, stirring, until the mixture darkens into a thick, brick-colored sofrito.","Stir in the rinsed quinoa to coat it in the sofrito, pour in 350 ml of water with a good pinch of salt, and simmer uncovered for 12 minutes without stirring, paella-style.","Season the shrimp with salt and nestle them into the quinoa in a single layer along with the frozen peas.","Cover and cook 5 to 6 minutes, until the shrimp curl into loose pink commas and the quinoa at the pan''s edge crackles faintly — that''s your crust forming.","Rest off the heat for 3 minutes, then serve with lemon wedges and zero stirring, so the crispy bottom stays intact."],"tip":"That faint crackle near the end isn''t burning, it''s the socarrat-style crust — the best bite in the pan belongs to whoever scrapes it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_sweet_potato_skillet', '{"id":"turkey_sweet_potato_skillet","name":"Turkey and Sweet Potato Skillet","emoji":"🍠","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"sweet_potatoes","q":400},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"spinach","q":150},{"f":"olive_oil","q":15}],"steps":["Dice the sweet potato into small 1 cm cubes — small is non-negotiable for even cooking — and sauté them in the olive oil over medium heat for 8 minutes, stirring now and then, until the edges caramelize.","Add a splash of water, cover for 3 minutes, and steam until a fork slides through a cube with no resistance.","Push the sweet potatoes aside, raise the heat to medium-high, and brown the ground turkey for 5 minutes, seasoning with smoked paprika, garlic powder, and salt as you break it up.","Add the diced onion and bell pepper and cook 4 minutes until softened and fragrant.","Fold in the spinach a handful at a time until it wilts into dark green ribbons, then toss everything together so the sweet potato stains the turkey golden.","Taste, hit it with black pepper and more salt if needed, and serve hot from the pan."],"tip":"This reheats so well it borders on suspicious — double it and breakfast, lunch, and dinner are all handled."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_patties_with_greens', '{"id":"salmon_patties_with_greens","name":"Golden Salmon Patties with Lemony Greens","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["fish","eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"oats","q":50},{"f":"eggs","q":2},{"f":"greek_yogurt","q":100},{"f":"spinach","q":200},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Finely chop the salmon by hand until it holds together when squeezed, leaving a few larger pieces for texture.","Mix the salmon with the oats, eggs, the zest of the lemon, salt, and a pinch of black pepper, then let the mixture rest 5 minutes so the oats drink up moisture and bind everything.","Shape into four patties about 2 cm thick, pressing firmly so they hold their nerve in the pan.","Heat most of the olive oil in a skillet over medium and cook the patties 4 minutes per side, flipping only once, until deeply golden and crisp at the edges.","While they fry, stir half the lemon''s juice and a pinch of salt into the yogurt, and wilt the spinach in the remaining oil in a second pan for 2 minutes.","Plate the patties on the bed of greens with the lemon-yogurt sauce and the last lemon wedges alongside."],"tip":"Flip a patty only when it releases from the pan willingly — if it fights back, it needs another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_ricotta_penne_bake', '{"id":"turkey_ricotta_penne_bake","name":"Turkey and Ricotta Penne Bake","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"penne","q":120},{"f":"ricotta","q":150},{"f":"mozzarella","q":50},{"f":"parmesan","q":15},{"f":"tomato","q":2.5},{"f":"onion","q":0.7},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200 C and boil the penne in well-salted water for 2 minutes less than the package suggests — it finishes cooking in the oven and mushy pasta is a bake''s downfall.","Brown the ground turkey in the olive oil over medium-high for 5 minutes, then add the diced onion, oregano, and salt and cook 4 minutes more until soft.","Add the chopped tomatoes and simmer 8 minutes, crushing them with your spoon, until they collapse into a rough, clingy sauce.","Fold the drained penne into the sauce, then dollop the ricotta throughout in generous spoonfuls, swirling just once so pockets of cream stay intact.","Transfer to a baking dish, scatter the mozzarella and parmesan over the top, and bake 15 minutes until the cheese is bronzed and bubbling at the corners.","Rest 5 minutes before serving — molten ricotta shows no mercy."],"tip":"Swirl the ricotta once and walk away; overmixing turns luscious pockets into beige sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_medallions_with_apples', '{"id":"pork_medallions_with_apples","name":"Pork Medallions with Caramelized Apples","emoji":"🍎","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"apple","q":2},{"f":"onion","q":0.7},{"f":"butter","q":20},{"f":"maple_syrup","q":15},{"f":"olive_oil","q":10}],"steps":["Slice the pork tenderloin into 3 cm medallions, press each one gently flat with your palm, and season generously with salt, pepper, and a whisper of dried thyme.","Heat the olive oil in a skillet over medium-high until shimmering and sear the medallions 3 minutes per side, until golden-crusted and just blushing pink at the center, then rest them on a plate.","Drop the heat to medium, melt the butter in the same pan, and add the sliced apples and onion, scraping up the porky browned bits.","Cook 6 to 8 minutes, stirring occasionally, until the apples turn amber at the edges and the onion melts into softness.","Drizzle in the maple syrup and a splash of water, letting it bubble into a glossy pan sauce that coats the back of a spoon.","Return the medallions and their resting juices to the pan for a final minute, spooning the apples and sauce over the top."],"tip":"Those juices pooling under the resting pork are free sauce — tipping them back into the pan is the closest cooking gets to a refund."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_edamame_stirfry', '{"id":"chicken_edamame_stirfry","name":"Chicken and Edamame Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free","low-carb"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"edamame_frozen","q":200},{"f":"broccoli","q":250},{"f":"bell_pepper","q":1.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Slice the chicken breast into thin, even strips and pat them dry so they sear instead of steam.","Heat half the sesame oil in a wok or wide skillet over high heat until it just starts to smoke, then stir-fry the chicken for 4 minutes until golden at the edges and cooked through, and set it aside.","Add the remaining oil, then the broccoli florets and sliced bell pepper with a splash of water, tossing for 3 minutes until the broccoli turns emerald and the water hisses away.","Add the frozen edamame straight from the bag and stir-fry 2 minutes until heated through and glossy.","Return the chicken, pour the soy sauce down the hot side of the pan so it sizzles and reduces on contact, and toss for a final minute until everything is lacquered.","Finish with a crack of black pepper and serve immediately, while the vegetables still have their bite."],"tip":"A stir-fry is a sprint, not a marathon — if you can answer a text mid-cook, your pan isn''t hot enough."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_parmesan_skillet', '{"id":"eggplant_parmesan_skillet","name":"Eggplant Parmesan Skillet","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"olive_oil","q":30},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"mozzarella","q":100},{"f":"parmesan","q":30},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Slice the eggplant into 1-centimeter rounds, salt them generously, and let them sit 10 minutes before patting dry so they sear instead of steam.","Heat the olive oil in a large oven-safe skillet over medium-high and brown the eggplant in a single layer, about 3 minutes per side, until deeply golden at the edges.","Push the eggplant aside, soften the onion and garlic for 2 minutes, then pour in the crushed tomatoes with the oregano and simmer 8 minutes until the sauce thickens enough to mound on a spoon.","Nestle the eggplant into the sauce, scatter the mozzarella and parmesan over the top, and slide the skillet under a hot broiler for 3 to 4 minutes until the cheese blisters and bronzes.","Rest 5 minutes, shower with torn basil, and season with black pepper before serving straight from the pan."],"tip":"Salting the eggplant first is the difference between custardy slices and a sad oil sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_ziti_style_penne', '{"id":"baked_ziti_style_penne","name":"Baked Ziti-Style Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten"],"time":50,"servings":4,"ing":[{"f":"penne","q":320},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":600},{"f":"oregano","q":3},{"f":"ricotta","q":250},{"f":"mozzarella","q":150},{"f":"parmesan","q":40},{"f":"basil","q":0.3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and boil the penne in well-salted water for 2 minutes less than the package says, so it finishes cooking in the sauce without going mushy.","Meanwhile, warm the olive oil in a wide pan over medium heat and cook the onion and garlic for 5 minutes until translucent and sweet-smelling.","Add the crushed tomatoes and oregano and simmer 10 minutes until the sauce darkens a shade and loses its raw-tomato tang.","Fold the drained pasta into the sauce with dollops of ricotta, leaving visible white streaks rather than stirring it smooth.","Transfer to a baking dish, top with the mozzarella and parmesan, and bake 15 to 18 minutes until the cheese is molten with golden spots at the edges.","Rest 10 minutes so the layers set, then finish with torn basil and plenty of black pepper."],"tip":"Undercooked pasta going into the oven is the whole trick — al dente in the pot means perfect in the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_paella_style_rice', '{"id":"veggie_paella_style_rice","name":"Veggie Paella-Style Rice","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","vegan","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"paprika","q":6},{"f":"turmeric","q":2},{"f":"rice","q":300},{"f":"broth","q":750},{"f":"artichoke_hearts","q":240},{"f":"peas_frozen","q":150},{"f":"olives","q":40},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in your widest skillet over medium heat and cook the onion and bell pepper for 6 minutes until soft and beginning to caramelize at the edges.","Stir in the garlic, grated tomato, paprika, and turmeric and cook 3 minutes until the mixture darkens into a thick, jammy sofrito.","Add the rice and stir for 1 minute to coat every grain, then pour in the hot broth with the salt and shake the pan level — no stirring from here on.","Simmer uncovered over medium-low for 15 minutes, then tuck in the artichoke hearts, peas, and olives and cook 5 minutes more until the liquid is absorbed.","Raise the heat to high for 60 to 90 seconds to coax out the socarrat, that crackly caramelized crust on the bottom — listen for the faint snap.","Rest off the heat under a clean towel for 5 minutes, then finish with lemon wedges, parsley, and black pepper."],"tip":"Resist stirring after the broth goes in — the crusty bottom layer is a feature, not a mistake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_stroganoff_pasta', '{"id":"mushroom_stroganoff_pasta","name":"Mushroom Stroganoff Pasta","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":180},{"f":"butter","q":20},{"f":"olive_oil","q":15},{"f":"mushrooms","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"flour","q":10},{"f":"paprika","q":2},{"f":"broth","q":200},{"f":"sour_cream","q":120},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the penne in salted water until just al dente, reserving a mugful of the starchy cooking water before you drain.","While the pasta cooks, melt the butter with the olive oil in a large skillet over high heat and sear the mushrooms undisturbed for 4 minutes until deeply browned before stirring — crowding and fiddling are the enemies of color.","Lower the heat to medium, add the onion and garlic, and cook 4 minutes until soft, then sprinkle in the flour and paprika and stir for 1 minute to cook off the raw taste.","Pour in the broth, scraping up the browned bits, and simmer 3 minutes until the sauce thickens enough to coat a spoon.","Pull the pan off the heat, stir in the sour cream until silky, then fold in the pasta with a splash of reserved water to loosen.","Season boldly with salt and black pepper and shower with chopped parsley."],"tip":"Add the sour cream off the heat or it will curdle into cottage-cheese confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanakorizo_greek_spinach_rice', '{"id":"spanakorizo_greek_spinach_rice","name":"Spanakorizo (Greek Spinach Rice)","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"olive_oil","q":40},{"f":"onion","q":1},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"rice","q":180},{"f":"broth","q":450},{"f":"spinach","q":200},{"f":"lemon","q":1},{"f":"feta","q":80},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a deep pot over medium heat and cook the onion, scallions, and garlic for 5 minutes until soft and fragrant but not browned.","Stir in the rice and toast for 2 minutes until the grains turn faintly translucent at the edges.","Pour in the broth, season with salt, and simmer covered on low for 12 minutes until the rice is nearly tender.","Pile the spinach on top in big handfuls, cover again, and let it steam down for 3 minutes before folding it through — it will look like too much until it isn''t.","Off the heat, stir in the juice of the whole lemon and half its zest, then rest covered for 5 minutes so the rice drinks up the last of the liquid.","Serve warm rather than hot, crowned with crumbled feta, parsley, and a crack of black pepper."],"tip":"Greeks eat this closer to room temperature, when the lemon and olive oil actually taste like themselves."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('huevos_rancheros_black_beans', '{"id":"huevos_rancheros_black_beans","name":"Huevos Rancheros with Black Beans","emoji":"🍳","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","high-protein"],"allergens":["eggs","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"black_beans","q":200},{"f":"cumin","q":2},{"f":"salsa","q":200},{"f":"eggs","q":4},{"f":"avocado","q":1},{"f":"lime","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the black beans in a small saucepan with the cumin, a pinch of salt, and a splash of water, mashing a few against the side until the mixture is creamy but still chunky.","Toast the tortillas one at a time in a dry skillet over medium-high heat, about 45 seconds per side, until speckled and pliable, then keep them warm under a towel.","Simmer the salsa in the same skillet for 2 minutes until it thickens slightly and smells sweet.","Push the salsa to the edges, add the olive oil to the center, and crack in the eggs; fry 3 minutes until the whites are set but the yolks still shimmer.","Layer each plate with tortillas, beans, an egg, and a generous spoonful of the warm salsa.","Finish with sliced avocado, a squeeze of lime, cilantro, and black pepper, and serve before the yolks lose their nerve."],"tip":"Frying the eggs directly in the simmering salsa saves a pan and lets the whites soak up the sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_korma_style_curry', '{"id":"vegetable_korma_style_curry","name":"Vegetable Korma-Style Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","vegan","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"cashews","q":80},{"f":"coconut_milk","q":250},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":8},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"potatoes","q":300},{"f":"carrots","q":200},{"f":"cauliflower","q":0.5},{"f":"broth","q":300},{"f":"peas_frozen","q":150},{"f":"rice","q":250},{"f":"cilantro","q":0.3},{"f":"salt","q":6}],"steps":["Soak the cashews in boiling water for 15 minutes, then blend them with the coconut milk until completely smooth — this is your korma cream, so blend past the gritty stage.","Start the rice in a separate pot while the cashews soak, and cut the potatoes, carrots, and cauliflower into even bite-size pieces.","Heat the oil in a heavy pot over medium and cook the onion for 8 minutes until golden, then add the garlic, ginger, curry powder, garam masala, and turmeric and fry 1 minute until the spices smell toasty rather than raw.","Add the potatoes, carrots, cauliflower, broth, and salt, cover, and simmer 15 minutes until a knife slides easily into the potato.","Pour in the cashew-coconut cream and the peas and simmer gently, uncovered, for 5 minutes until the sauce is thick enough to cling to the vegetables.","Taste for salt, spoon over the rice, and finish with a flurry of cilantro."],"tip":"If the sauce breaks or looks thin, blend a ladleful and stir it back in — instant body, no cream required."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ratatouille_baked_eggs', '{"id":"ratatouille_baked_eggs","name":"Ratatouille Baked Eggs","emoji":"🍅","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"olive_oil","q":30},{"f":"eggplant","q":0.5},{"f":"zucchini","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"eggs","q":4},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Dice the eggplant, zucchini, bell pepper, and onion into even 2-centimeter pieces so they cook at the same pace.","Heat the olive oil in a large oven-safe skillet over medium-high and cook the vegetables with a good pinch of salt for 10 minutes, stirring occasionally, until browned in spots and starting to slump.","Add the garlic and oregano for the final minute, then pour in the crushed tomatoes and simmer 10 minutes until the stew is thick enough to hold a spoon trail.","Press four wells into the ratatouille with the back of a spoon and crack an egg into each one.","Cover and cook over low heat for 6 to 8 minutes, until the whites are just set and the yolks still wobble when you nudge the pan.","Season with black pepper, scatter with torn basil, and bring the skillet straight to the table."],"tip":"The eggs keep cooking in the hot vegetables, so pull the pan when they look slightly underdone."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_grilled_cheese', '{"id":"caprese_grilled_cheese","name":"Caprese Grilled Cheese","emoji":"🥪","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"mozzarella","q":150},{"f":"tomato","q":1},{"f":"basil","q":0.3},{"f":"butter","q":20},{"f":"balsamic_vinegar","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Slice the tomato thinly, salt the slices, and let them drain on a paper towel for 5 minutes so they don''t flood the sandwich.","Layer the mozzarella, blotted tomato, and basil leaves between the bread slices, seasoning the tomato layer with black pepper and a few drops of balsamic vinegar.","Butter the outside of each sandwich edge to edge — the crust corners are where regret lives.","Cook in a skillet over medium-low heat for 4 to 5 minutes per side, pressing gently with a spatula, until the bread is deep golden and the cheese sags when you lift a corner.","Rest 2 minutes before slicing on the diagonal so the molten mozzarella doesn''t make a break for it."],"tip":"Medium-low heat is non-negotiable — hot pans give you burnt bread hugging cold cheese."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_quesadillas', '{"id":"sweet_potato_black_bean_quesadillas","name":"Sweet Potato Black Bean Quesadillas","emoji":"🍠","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"sweet_potatoes","q":350},{"f":"black_beans","q":150},{"f":"cumin","q":3},{"f":"chili_powder","q":3},{"f":"lime","q":0.5},{"f":"scallions","q":0.3},{"f":"tortillas","q":4},{"f":"cheddar","q":80},{"f":"olive_oil","q":15},{"f":"salsa","q":100},{"f":"salt","q":3}],"steps":["Peel and dice the sweet potatoes, then steam or microwave them with a splash of water for 6 to 8 minutes until fork-tender.","Mash them roughly with the black beans, cumin, chili powder, lime juice, sliced scallions, and salt — aim for chunky, not baby food.","Spread the filling over half of each tortilla, top with grated cheddar, and fold into half-moons, pressing to seal.","Brush a skillet with olive oil and cook the quesadillas over medium heat for 3 minutes per side, until shatteringly crisp and stamped with golden-brown patches.","Rest 2 minutes so the filling sets, then slice into wedges and serve with salsa for dunking."],"tip":"The mash glues the quesadilla shut, so no more cheese avalanches when you flip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tomato_ricotta_soup', '{"id":"creamy_tomato_ricotta_soup","name":"Creamy Tomato Ricotta Soup","emoji":"🥣","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":600},{"f":"broth","q":400},{"f":"sugar","q":5},{"f":"oregano","q":2},{"f":"ricotta","q":150},{"f":"parmesan","q":20},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a soup pot over medium heat and cook the onion for 6 minutes until soft and sweet, adding the garlic for the last minute.","Pour in the crushed tomatoes, broth, sugar, oregano, and salt and simmer uncovered for 15 minutes, until the soup deepens from bright red to brick.","Blend until completely smooth with an immersion blender, then stir in two-thirds of the ricotta over low heat until the soup turns pale coral and velvety.","Taste and correct — a little more salt sharpens the tomato, a pinch more sugar rounds off any tinny edge.","Ladle into bowls and finish each with a dollop of the remaining ricotta, grated parmesan, torn basil, and a swirl of black pepper."],"tip":"That pinch of sugar isn''t cheating — it''s doing the job an August tomato would have done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_veggie_fried_quinoa', '{"id":"loaded_veggie_fried_quinoa","name":"Loaded Veggie Fried Quinoa","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","soy","sesame","gluten"],"time":30,"servings":2,"ing":[{"f":"quinoa","q":180},{"f":"olive_oil","q":15},{"f":"eggs","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"broccoli","q":150},{"f":"peas_frozen","q":100},{"f":"corn_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"black_pepper","q":1}],"steps":["Cook the quinoa in plenty of water for 12 minutes, drain well, and spread it on a tray to dry and cool — wet quinoa fries into porridge, so day-old is even better.","Heat half the olive oil in your largest skillet over high heat, scramble the eggs hard for 30 seconds until just set, and scrape them out onto a plate.","Add the remaining oil and stir-fry the garlic, ginger, diced carrots, and broccoli for 3 to 4 minutes until the broccoli turns vivid green with charred edges.","Add the quinoa, peas, and corn and press everything flat against the hot pan; let it sizzle undisturbed for 90 seconds so the quinoa crisps and pops.","Return the eggs, pour the soy sauce and sesame oil around the rim of the pan, and toss for a final minute until every grain is glossy.","Serve immediately, topped with sliced scallions and black pepper."],"tip":"Pressing the quinoa into the pan and leaving it alone is what buys you those crispy toasted bits."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_red_pepper_penne', '{"id":"roasted_red_pepper_penne","name":"Roasted Red Pepper Penne","emoji":"🌶️","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"olive_oil","q":30},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"roasted_red_peppers","q":250},{"f":"ricotta","q":60},{"f":"parmesan","q":40},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Boil the penne in aggressively salted water until al dente, saving a cup of pasta water before draining.","While it cooks, warm the olive oil in a skillet over medium heat and soften the onion and garlic for 4 minutes without letting them brown.","Blend the drained roasted red peppers with the onion mixture and the ricotta until completely smooth and the color of a Tuscan sunset.","Return the sauce to the skillet, simmer 3 minutes until it thickens slightly, and season with salt and black pepper.","Toss in the pasta with half the parmesan and enough reserved pasta water to make the sauce cling glossily to every tube.","Plate and finish with the remaining parmesan and torn basil."],"tip":"Jarred peppers did the roasting for you — spend the saved 40 minutes blending the sauce truly smooth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_butter_chicken_with_olives', '{"id":"lemon_butter_chicken_with_olives","name":"Lemon butter chicken with olives","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"flour","q":20},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"broth","q":150},{"f":"olives","q":50},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the chicken breasts horizontally into thin cutlets, season with salt and pepper, and dust both sides lightly with flour, shaking off the excess.","Heat the olive oil with half the butter in a wide skillet over medium-high until the foam subsides, then lay in the cutlets and cook 3 minutes per side until deeply golden; transfer to a plate.","Drop the heat to medium, add the minced garlic, and stir 30 seconds until fragrant but not browned.","Pour in the broth and the juice of the lemon, scraping up the browned bits, and simmer 2–3 minutes until the sauce reduces by half and just coats a spoon.","Swirl in the remaining butter and the halved olives, slide the chicken back in with any juices, and warm through for 1 minute.","Shower with chopped parsley and serve straight from the pan while the sauce is glossy."],"tip":"Thin cutlets cook fast — if you walk away to check your phone, you will own two chicken-flavored hockey pucks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_wedding_style_soup', '{"id":"italian_wedding_style_soup","name":"Italian wedding-style soup with turkey meatballs","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"rice","q":150},{"f":"broth","q":1500},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"spinach","q":150},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Mix the turkey with the egg, half the parmesan, a pinch of oregano, salt, and pepper, then roll into small meatballs about the size of a walnut and chill while you start the pot.","Warm the olive oil in a soup pot over medium heat and sweat the diced onion, carrots, and celery for 6–7 minutes until softened and sweet; stir in the minced garlic for 30 seconds.","Pour in the broth, bring it to a lively simmer, and stir in the rice.","Gently lower in the meatballs one at a time and simmer, uncovered, for 15–18 minutes until the rice is tender and the meatballs are cooked through.","Wilt in the spinach for the final 2 minutes, then taste and adjust the salt and pepper.","Ladle into bowls and finish each with the remaining parmesan."],"tip":"Wet your hands before rolling the meatballs and the mixture will stop treating your palms like flypaper."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_butter_salmon', '{"id":"tuscan_butter_salmon","name":"Tuscan butter salmon","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"butter","q":25},{"f":"garlic","q":0.3},{"f":"cherry_tomatoes","q":200},{"f":"spinach","q":100},{"f":"milk","q":120},{"f":"parmesan","q":30},{"f":"olive_oil","q":10},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets very dry, season with salt and pepper, and heat the olive oil in a skillet over medium-high until shimmering.","Sear the salmon skin-side up for 4 minutes until a golden crust releases easily from the pan, flip, cook 2 minutes more, and set aside on a plate.","Lower the heat to medium, melt the butter, and cook the minced garlic and halved cherry tomatoes for 3–4 minutes until the tomatoes blister and slump.","Pour in the milk, scatter in the parmesan, and simmer 2 minutes, stirring, until the sauce turns creamy and lightly thickened.","Fold in the spinach until just wilted, then nestle the salmon back in and spoon sauce over the top for a final minute of gentle heat.","Tear the basil over everything and serve straight from the skillet."],"tip":"A dry fillet and a hot pan are the whole secret — damp salmon steams, and steamed salmon sulks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_lemon_chicken_potatoes', '{"id":"greek_lemon_chicken_potatoes","name":"Greek lemon chicken and potatoes","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"potatoes","q":450},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":4},{"f":"broth","q":120},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 220°C and cut the potatoes into thick wedges so they can roast without collapsing.","Whisk the olive oil with the juice of the lemon, minced garlic, oregano, salt, and a generous grind of pepper, then toss the chicken thighs and potatoes in it until every surface is slicked.","Arrange everything in a single layer in a roasting pan, chicken skin-side up, and pour the broth into the corners so the potatoes braise from below while they brown on top.","Roast for 40–45 minutes until the chicken is burnished and the potato edges are golden and crisp.","Spoon the lemony pan juices over everything and rest 5 minutes before serving.","Finish with a last squeeze from the spent lemon halves if you like it bracing."],"tip":"Crowd the pan and everything steams — give the potatoes elbow room and they will reward you with crispy corners."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pasta_primavera', '{"id":"pasta_primavera","name":"Pasta primavera","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"penne","q":180},{"f":"zucchini","q":1},{"f":"asparagus","q":150},{"f":"bell_pepper","q":1},{"f":"peas_frozen","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"parmesan","q":40},{"f":"lemon","q":0.5},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Boil the penne in well-salted water until just shy of al dente, then scoop out a cup of the starchy cooking water before draining.","Meanwhile, heat the olive oil in a large skillet over medium-high and sauté the sliced zucchini, asparagus pieces, and bell pepper strips for 5–6 minutes until crisp-tender with browned edges.","Add the minced garlic and frozen peas and cook 1 minute more until the garlic is fragrant and the peas are bright.","Tip in the drained pasta with a good splash of the reserved water and toss over the heat until the liquid turns silky and clings to the noodles.","Off the heat, stir in the parmesan, the juice of the half lemon, and torn basil, loosening with more pasta water if it tightens up.","Season boldly with black pepper and serve in warm bowls."],"tip":"That cup of pasta water is free sauce — pour it down the drain and you will be chasing dry noodles around the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cacio_e_pepe', '{"id":"cacio_e_pepe","name":"Cacio e pepe","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"parmesan","q":80},{"f":"black_pepper","q":4},{"f":"salt","q":4}],"steps":["Toast the coarsely ground black pepper in a dry, wide skillet over medium heat for about 1 minute until it smells sharp and woodsy, then take the pan off the heat.","Boil the spaghetti in lightly salted water — less salty than usual, since the cheese carries plenty — until 1 minute shy of al dente, reserving a full cup of the cooking water.","Finely grate the parmesan into a bowl and whisk in a few spoonfuls of the hot pasta water until it forms a thick, smooth paste with no clumps.","Transfer the drained pasta to the pepper skillet with a splash of pasta water and toss over low heat for 30 seconds so every strand is coated.","Pull the pan off the heat, wait 15 seconds so the cheese will not seize, then add the parmesan paste and toss relentlessly until a glossy sauce hugs the noodles.","Loosen with extra pasta water a spoonful at a time and serve immediately in warm bowls."],"tip":"Cheese added over direct heat turns to chewing gum — patience off the flame is the entire recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('panzanella_style_bread_salad', '{"id":"panzanella_style_bread_salad","name":"Panzanella-style bread salad","emoji":"🥖","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"bread","q":6},{"f":"tomato","q":4},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"chickpeas","q":150},{"f":"olives","q":50},{"f":"olive_oil","q":40},{"f":"balsamic_vinegar","q":20},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 200°C, tear the bread into rough bite-size chunks, toss with a third of the olive oil, and toast on a tray for 10–12 minutes until golden and audibly crunchy.","Cut the tomatoes into chunky wedges over a large bowl so every drop of juice lands in the salad, then season them with salt and let them sit 5 minutes to weep.","Add the chopped cucumber, thinly sliced onion, drained chickpeas, and halved olives to the bowl.","Whisk the remaining olive oil with the balsamic vinegar and pour it over everything.","Fold in the toasted bread and torn basil and let the salad rest 10 minutes so the croutons drink up the tomato juices without going soggy.","Taste, add pepper and more salt if needed, and serve at room temperature."],"tip":"Stale bread is not a compromise here, it is the job requirement — fresh fluffy bread dissolves into regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_gyro_style_pitas', '{"id":"chicken_gyro_style_pitas","name":"Chicken gyro-style pitas with yogurt sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"garlic","q":0.2},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15},{"f":"oregano","q":3},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the chicken thighs into thin strips and toss with the olive oil, oregano, paprika, half the minced garlic, salt, pepper, and a squeeze of the lemon; marinate 10 minutes while you make the sauce.","Grate the cucumber, squeeze it dry in your fist over the sink, and stir it into the yogurt with the remaining garlic, the rest of the lemon juice, and a pinch of salt.","Sear the chicken in a screaming-hot skillet in a single layer, undisturbed for 3 minutes until charred at the edges, then toss and cook 3–4 minutes more until cooked through.","Warm the pitas in the emptied pan for 30 seconds per side until soft and pliable.","Pile each pita with chicken, sliced tomato, and slivered onion, then spoon the yogurt sauce generously over the top.","Fold, wrap the bottom in paper if you value your sleeves, and eat immediately."],"tip":"Squeezing the cucumber feels fussy until the day you skip it and your sauce becomes soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_pepper_walnut_dip_plate', '{"id":"roasted_pepper_walnut_dip_plate","name":"Roasted pepper and walnut dip plate","emoji":"🌶️","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"roasted_red_peppers","q":200},{"f":"walnuts","q":80},{"f":"bread","q":1},{"f":"pita","q":2},{"f":"garlic","q":0.1},{"f":"olive_oil","q":25},{"f":"balsamic_vinegar","q":10},{"f":"cumin","q":2},{"f":"lemon","q":0.5},{"f":"cucumber","q":1},{"f":"salt","q":3},{"f":"paprika","q":2}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3–4 minutes, shaking often, until they smell rich and nutty — pull them the moment they darken.","Tear the slice of bread into pieces and blitz it in a food processor with the walnuts until finely ground.","Add the drained roasted red peppers, garlic, balsamic vinegar, cumin, paprika, the juice of the half lemon, and a pinch of salt, then process to a thick, rustic paste, streaming in most of the olive oil as it runs.","Taste and adjust — it should be smoky, tangy, and just a little sweet from the peppers.","Warm the pitas in the skillet until soft, cut them into wedges, and slice the cucumber into spears.","Swoosh the dip across a plate, crater the center with the back of a spoon, drizzle with the last of the oil, and surround with pita and cucumber."],"tip":"The dip thickens and deepens overnight, so making it a day ahead is less a tip than an unfair advantage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_asparagus_rice_risotto_style', '{"id":"lemon_asparagus_rice_risotto_style","name":"Lemon asparagus risotto-style rice","emoji":"🍚","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"asparagus","q":250},{"f":"broth","q":750},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"butter","q":20},{"f":"parmesan","q":50},{"f":"lemon","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Keep the broth barely simmering in a small pot — cold broth added to hot rice stops the creamy magic every time.","Warm the olive oil with half the butter in a wide pan over medium heat and cook the finely diced onion 4 minutes until translucent, then stir in the garlic and the rice, toasting the grains 2 minutes until the edges look glassy.","Add the hot broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed before the next, about 20 minutes total.","When the rice is tender with the faintest chew at the center, stir in the asparagus pieces and cook 3–4 minutes until bright green and crisp-tender.","Off the heat, beat in the remaining butter, the parmesan, the zest-free juice of the lemon, salt, and plenty of pepper until the rice ripples loosely when you shake the pan.","Serve immediately in shallow bowls — it waits for no one."],"tip":"Risotto should slump lazily across the plate; if it stands at attention, loosen it with one more splash of broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sicilian_tuna_olive_pasta', '{"id":"sicilian_tuna_olive_pasta","name":"Sicilian tuna and olive pasta","emoji":"🫒","cuisine":"Italian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","fish"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"tuna_canned","q":160},{"f":"olives","q":60},{"f":"crushed_tomatoes","q":250},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Set the penne boiling in well-salted water and cook until just al dente, saving a half cup of the pasta water before draining.","While it cooks, warm the olive oil in a deep skillet over medium heat and sizzle the sliced garlic for about 1 minute until pale gold and fragrant — no darker.","Add the crushed tomatoes, oregano, and halved olives and simmer 8 minutes until the sauce thickens enough to hold a trail behind the spoon.","Fold in the drained tuna in big flakes and warm it gently for 2 minutes without stirring it to shreds.","Toss the pasta through the sauce with a splash of the reserved water until every tube is coated and glistening.","Finish with the juice of the half lemon, chopped parsley, and a heavy grind of black pepper."],"tip":"Treat the tuna like it is fragile and expensive; stir like a maniac and you will make tuna-flavored tomato paste."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_feta_olive_frittata', '{"id":"greek_feta_olive_frittata","name":"Greek feta and olive frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"feta","q":100},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":150},{"f":"spinach","q":100},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190°C and whisk the eggs with the oregano, a small pinch of salt (the feta and olives bring plenty), and a good grind of pepper.","Warm the olive oil in an ovenproof skillet over medium heat and soften the sliced onion for 4 minutes, then add the halved cherry tomatoes and cook 2 minutes until they just begin to slump.","Pile in the spinach and stir until it collapses to a glossy tangle, about 1 minute.","Pour the eggs over the vegetables, scatter with the crumbled feta and halved olives, and cook undisturbed for 2 minutes until the edges set.","Slide the skillet into the oven and bake 8–10 minutes until the center is puffed and barely jiggles when you nudge the pan.","Rest 3 minutes, then cut into wedges straight from the skillet."],"tip":"Pull it while the middle still wobbles slightly — carryover heat finishes the job, and an overbaked frittata bounces."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_balsamic_ricotta_toast', '{"id":"berry_balsamic_ricotta_toast","name":"Berry balsamic ricotta toast","emoji":"🫐","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"ricotta","q":200},{"f":"berries","q":200},{"f":"balsamic_vinegar","q":20},{"f":"honey","q":15},{"f":"basil","q":0.3},{"f":"salt","q":1},{"f":"black_pepper","q":1}],"steps":["Simmer the balsamic vinegar in a small pan over medium-low heat for 2–3 minutes until it reduces to a syrup that coats the back of a spoon, then take it off the heat — it thickens more as it cools.","Toast the bread until deeply golden and sturdy enough to hold a heavy topping without flopping.","Whip the ricotta with the honey and a tiny pinch of salt using a fork until light and spreadable.","Warm half the berries in the empty balsamic pan for a minute until they just start to burst, then fold in the remaining fresh berries.","Spread the ricotta thickly on the hot toast, spoon the berries over, and drizzle with the balsamic reduction.","Finish with torn basil and, trust the process, a single crack of black pepper."],"tip":"Watch the balsamic like a hawk in its final seconds — the line between syrup and candle wax is about one distracted text message."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_beef_tacos', '{"id":"classic_beef_tacos","name":"Classic Beef Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":4},{"f":"cheddar","q":60},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"sour_cream","q":40},{"f":"olive_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Heat the olive oil in a large skillet over medium-high heat and cook the diced onion for 3 minutes until translucent.","Add the ground beef, breaking it apart with a wooden spoon, and cook for 6 to 8 minutes until deeply browned with crispy edges.","Stir in the minced garlic with a generous pinch of chili powder, cumin, salt, and pepper, then splash in a few tablespoons of water and simmer 2 minutes until the liquid coats the meat like a glossy sauce.","Warm the tortillas directly over a low gas flame or in a dry pan for 20 seconds per side until pliable and lightly charred.","Pile the beef into the tortillas and top with grated cheddar, diced tomato, and a dollop of sour cream."],"tip":"Char the tortillas until they get a few leopard spots — pale tacos are sad tacos."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_meatballs_rice', '{"id":"honey_garlic_meatballs_rice","name":"Honey Garlic Turkey Meatballs with Rice","emoji":"🍯","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"rice","q":150},{"f":"eggs","q":1},{"f":"honey","q":45},{"f":"soy_sauce","q":35},{"f":"garlic","q":0.4},{"f":"carrots","q":120}],"steps":["Start the rice in a small pot with double its volume of salted water, cover, and simmer on low for 15 minutes, then rest off the heat.","Mix the ground turkey with the egg, one minced garlic clove, salt, and pepper, then roll into 12 golf-ball-sized meatballs with damp hands.","Sear the meatballs in a lightly oiled skillet over medium-high heat for 8 minutes, turning until browned on all sides and cooked through to 165F.","Whisk the honey, soy sauce, remaining minced garlic, and 3 tablespoons of water, pour into the pan, and simmer 3 minutes until the glaze bubbles thick enough to coat a spoon.","Toss the meatballs to lacquer them in sauce, then serve over the rice with quick-sauteed carrot coins alongside."],"tip":"Wet your hands before rolling the meatballs or the turkey will cling to you like a needy toddler."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_noodle_soup', '{"id":"chicken_noodle_soup","name":"Old-School Chicken Noodle Soup","emoji":"🍲","cuisine":"American","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"spaghetti","q":200},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":1500},{"f":"olive_oil","q":15}],"steps":["Warm the olive oil in a large pot over medium heat and sweat the diced onion and sliced carrots for 5 minutes until the onion turns glassy.","Stir in the minced garlic for 30 seconds until fragrant, then pour in the broth and bring to a gentle boil.","Slip in the whole chicken breasts, drop the heat to a bare simmer, and poach for 15 minutes until they register 165F at the thickest point.","Lift the chicken onto a cutting board, snap the spaghetti into 2-inch pieces, and boil them in the soup for 8 minutes until just tender.","Shred the chicken with two forks, return it to the pot, season assertively with salt and black pepper, and ladle into deep bowls."],"tip":"Poach the chicken at a lazy burble, not a boil — angry bubbles make rubbery chicken."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sloppy_joe_style_skillet', '{"id":"sloppy_joe_style_skillet","name":"Sloppy Joe Skillet on Toast","emoji":"🥪","cuisine":"American","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"bread","q":4},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"crushed_tomatoes","q":250},{"f":"garlic","q":0.2},{"f":"honey","q":15},{"f":"olive_oil","q":10}],"steps":["Heat the olive oil in a wide skillet over medium-high heat and brown the ground beef for 5 minutes, pressing it flat and leaving it alone so it develops a crusty sear.","Push the beef aside, add the diced onion and bell pepper, and cook 4 minutes until softened and starting to catch color at the edges.","Stir in the minced garlic, then pour in the tomato sauce with the honey, a splash of vinegar if you have it, salt, and plenty of black pepper.","Simmer uncovered for 8 minutes, stirring occasionally, until the mixture thickens to a spoonable, saucy sloppiness that mounds on a spatula.","Toast the bread until golden and sturdy, then ladle the beef generously over each slice and eat with a fork and zero shame."],"tip":"Toast the bread darker than feels polite — it is the only structural support this dinner has."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_tuna_melts', '{"id":"classic_tuna_melts","name":"Classic Tuna Melts","emoji":"🐟","cuisine":"American","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.3},{"f":"olive_oil","q":10}],"steps":["Drain the tuna thoroughly and flake it into a bowl with the Greek yogurt, finely minced onion, a squeeze of lemon if handy, salt, and black pepper.","Mash the mixture with a fork until it holds together but still has some texture, then taste and adjust the seasoning.","Brush one side of each bread slice with olive oil and lay them oiled-side down in a cold nonstick skillet.","Divide the tuna over two slices, blanket with grated cheddar, and cap with the remaining bread, oiled side out.","Cook over medium heat for 3 to 4 minutes per side, pressing gently with a spatula, until the bread is deep golden and the cheese oozes at the seams."],"tip":"Start the sandwiches in a cold pan so the cheese melts before the bread burns — patience is the secret ingredient."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_enchilada_skillet', '{"id":"chicken_enchilada_skillet","name":"Chicken Enchilada Skillet","emoji":"🫔","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"tortillas","q":3},{"f":"crushed_tomatoes","q":300},{"f":"cheddar","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Cut the chicken into bite-sized pieces, season with salt, cumin, and chili powder, and sear in the olive oil over medium-high heat for 5 minutes until golden at the edges.","Add the diced onion and cook 3 minutes until softened, then stir in the minced garlic for 30 seconds.","Pour in the tomato sauce with a half cup of water and a pinch of oregano, and simmer 5 minutes until the sauce turns brick-red and slightly thickened.","Tear the tortillas into rough triangles and fold them into the skillet, letting them soak for 2 minutes until soft and dumpling-like.","Scatter the cheddar over the top, lid the pan, and cook 2 more minutes until the cheese melts into molten pools before serving straight from the skillet."],"tip":"Slightly stale tortillas actually work better here — they drink up sauce without dissolving into mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_quesadillas', '{"id":"beef_quesadillas","name":"Crispy Beef Quesadillas","emoji":"🧀","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"tortillas","q":4},{"f":"cheddar","q":80},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":10},{"f":"sour_cream","q":40}],"steps":["Brown the ground beef in a hot skillet for 5 minutes with the diced onion and bell pepper, seasoning with salt, cumin, and smoked paprika.","Cook until the vegetables slump and the beef fat runs clear, then tip the filling into a bowl and wipe out the pan.","Lay a tortilla in the skillet over medium heat, cover half with grated cheddar, spoon on the beef, add another layer of cheese, and fold the tortilla over.","Brush the top lightly with olive oil and cook 2 to 3 minutes per side, pressing with a spatula, until the outside is crackly golden and the cheese is fully molten.","Repeat with the remaining tortillas, rest each quesadilla 1 minute so the cheese sets, then slice into wedges and serve with sour cream."],"tip":"Cheese on both sides of the filling is not indulgence, it is glue — skip it and your quesadilla falls apart in public."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_sesame_chicken', '{"id":"honey_sesame_chicken","name":"Honey Sesame Chicken","emoji":"🍗","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"rice","q":150},{"f":"honey","q":50},{"f":"soy_sauce","q":35},{"f":"sesame_oil","q":12},{"f":"garlic","q":0.3},{"f":"broccoli","q":300}],"steps":["Get the rice simmering in salted water, covered, for 15 minutes while you prep everything else.","Cut the chicken into 2-centimeter chunks, pat them bone-dry, and sear in a screaming-hot oiled skillet for 6 minutes until golden-crusted on at least two sides.","Add the broccoli florets with a splash of water, cover for 2 minutes to steam them bright green, then uncover and let the water cook off.","Stir the honey, soy sauce, minced garlic, and half the sesame oil together, pour it over the pan, and boil hard for 2 minutes until the sauce reduces to a sticky glaze that clings to every piece.","Kill the heat, drizzle with the remaining sesame oil for fragrance, and serve heaped over the rice."],"tip":"Add half the sesame oil at the end, off the heat — its perfume dies fast in a hot pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_lo_mein_style_spaghetti', '{"id":"veggie_lo_mein_style_spaghetti","name":"Veggie Lo Mein-Style Spaghetti","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"broccoli","q":250},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"maple_syrup","q":15}],"steps":["Boil the spaghetti in well-salted water for 2 minutes less than the package says, then drain, reserving a cup of the starchy water.","Meanwhile, heat a wok or your widest skillet until a drop of water skitters, add a slick of neutral oil, and stir-fry the broccoli, carrot matchsticks, and sliced bell pepper for 4 minutes until crisp-tender with charred spots.","Push the vegetables aside and sizzle the minced garlic for 30 seconds until fragrant but not brown.","Add the drained noodles with the soy sauce, maple syrup, and a splash of pasta water, and toss vigorously for 2 minutes until every strand is glossy and coffee-colored.","Finish with the sesame oil off the heat, toss once more, and serve immediately while the noodles still steam."],"tip":"Slightly undercook the spaghetti — it finishes in the wok and takeout-level chew is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_ginger_beef_rice_bowls', '{"id":"soy_ginger_beef_rice_bowls","name":"Soy Ginger Beef Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"rice","q":150},{"f":"soy_sauce","q":40},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"honey","q":20},{"f":"broccoli","q":250},{"f":"sesame_oil","q":10}],"steps":["Simmer the rice in salted water, covered, for 15 minutes, then let it rest with the lid on while you cook the beef.","Brown the ground beef in a dry hot skillet for 5 minutes without stirring much, so it forms crispy caramelized bits on the bottom.","Add the grated ginger and minced garlic and stir for 1 minute until the whole kitchen smells like a good decision.","Toss in the broccoli florets with a splash of water, cover for 2 minutes to steam, then pour in the soy sauce and honey and boil 2 minutes until the sauce reduces to a glossy coating.","Fluff the rice into two bowls, spoon the beef and broccoli over top, and finish each with a drizzle of sesame oil."],"tip":"Grate the ginger with the skin scraped off using a spoon — a peeler steals half your ginger with it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_chicken_rice_skillet', '{"id":"creamy_chicken_rice_skillet","name":"Creamy One-Pot Chicken and Rice","emoji":"🍛","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"rice","q":150},{"f":"broth","q":500},{"f":"milk","q":120},{"f":"parmesan","q":30},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Cut the chicken into chunky bites, season with salt and pepper, and sear in the olive oil over medium-high heat for 4 minutes until golden but not cooked through, then set aside.","In the same pan, soften the diced onion for 3 minutes, scraping up the browned chicken bits, then stir in the garlic and the dry rice for 1 minute until the grains turn translucent at the edges.","Pour in the broth, bring to a boil, then cover and simmer on low for 15 minutes until the rice is nearly tender and most liquid is absorbed.","Return the chicken with its juices, stir in the milk, and simmer uncovered for 5 minutes until the chicken is cooked through and the sauce turns loose and creamy.","Take the pan off the heat, stir in the grated parmesan until it melts into the sauce, and let it sit 2 minutes to thicken before serving."],"tip":"Resist lifting the lid while the rice simmers — every peek costs you steam and adds sticky-bottom risk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_breakfast_potatoes_eggs', '{"id":"diner_breakfast_potatoes_eggs","name":"Diner Breakfast Potatoes and Eggs","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"eggs","q":4},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":25},{"f":"garlic","q":0.1}],"steps":["Dice the potatoes into 1-centimeter cubes and parboil them in salted water for 5 minutes, then drain and let them steam dry for a minute.","Heat the olive oil in a large cast-iron or nonstick skillet over medium-high heat and spread the potatoes in a single layer, leaving them untouched for 4 minutes to build a crust.","Toss, then add the diced onion and bell pepper and cook another 6 to 8 minutes, flipping occasionally, until everything is deeply golden and the peppers have softened.","Stir in the minced garlic with a big pinch of smoked paprika, salt, and pepper, then push the hash to the edges and make four wells in the pan.","Crack an egg into each well, cover, and cook 3 to 4 minutes until the whites are set but the yolks still shimmy when you shake the pan."],"tip":"Parboiling first is the diner secret — creamy inside, shattering crust outside, no raw-potato roulette."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_baked_oatmeal', '{"id":"apple_cinnamon_baked_oatmeal","name":"Apple Cinnamon Baked Oatmeal","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","eggs","nuts"],"time":45,"servings":2,"ing":[{"f":"oats","q":120},{"f":"apple","q":2},{"f":"eggs","q":1},{"f":"milk","q":250},{"f":"maple_syrup","q":45},{"f":"walnuts","q":30}],"steps":["Heat the oven to 375F and grease a small baking dish while you dice one apple and slice the other into thin fans for the top.","Whisk the egg, milk, maple syrup, a teaspoon of cinnamon, and a pinch of salt in a bowl until fully combined.","Stir in the oats, diced apple, and roughly chopped walnuts, then pour the mixture into the dish and shingle the apple slices over the surface.","Bake for 30 to 35 minutes until the center is set, the edges pull away from the dish, and the top is burnished golden with bubbling syrupy spots.","Rest for 5 minutes so it firms up, then scoop into bowls and finish with an extra drizzle of maple syrup if you are feeling generous."],"tip":"Make it the night before and reheat — baked oatmeal, like gossip, is somehow even better the next day."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_pad_thai_style_noodles', '{"id":"tofu_pad_thai_style_noodles","name":"Tangy Tofu Pad Thai-Style Noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","nuts"],"time":35,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"tofu","q":450},{"f":"carrots","q":100},{"f":"scallions","q":1},{"f":"garlic","q":0.6},{"f":"lime","q":1.5},{"f":"maple_syrup","q":30},{"f":"soy_sauce","q":45},{"f":"olive_oil","q":20},{"f":"cashews","q":40},{"f":"cilantro","q":0.5}],"steps":["Soak the rice noodles in just-boiled water for 8 minutes until pliable but still slightly chewy at the center, then drain and rinse under cold water so they stop cooking.","Whisk the soy sauce, maple syrup, and the juice of one lime into a sauce that tastes bracingly sweet-salty-sour, because the noodles will mute it later.","Pat the tofu dry, tear it into rough bite-size chunks, and sear it in the oil in a large skillet over medium-high heat for 8 to 10 minutes until the craggy edges turn deep gold.","Push the tofu aside, add the minced garlic and carrot ribbons, and stir-fry for 90 seconds until the garlic smells toasty rather than raw.","Add the noodles and sauce and toss constantly with tongs for 2 to 3 minutes until every strand is glossy and the sauce has thickened into a light glaze.","Pile into bowls and shower with sliced scallions, chopped cashews, torn cilantro, and the remaining lime in wedges."],"tip":"Torn tofu beats cubed tofu here — the ragged edges grab twice as much sauce and nobody has ever complained about that."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_veggie_fried_rice', '{"id":"cashew_veggie_fried_rice","name":"Golden Cashew Veggie Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","nuts","sesame"],"time":35,"servings":2,"ing":[{"f":"rice","q":150},{"f":"cashews","q":80},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"scallions","q":1}],"steps":["Cook the rice in salted water until just tender, about 15 minutes, then spread it on a plate and let it steam off for 10 minutes so the grains dry out and firm up.","Toast the cashews in a dry wok over medium heat for 3 to 4 minutes, shaking often, until they freckle and smell like caramel, then tip them out.","Heat the olive oil in the same wok until it shimmers, then stir-fry the diced onion and carrot for 4 minutes until the onion edges brown.","Add the garlic and grated ginger and cook for 30 seconds, then add the rice, pressing it flat and letting it sit undisturbed for a full minute so it crackles and catches a little crust.","Toss in the peas and soy sauce and stir-fry for 2 minutes until every grain is stained amber, then kill the heat and fold in the cashews, sesame oil, and sliced scallions."],"tip":"Freshly cooked rice makes gummy fried rice, so if you have leftover cold rice in the fridge, this is its moment of glory."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_scallion_lo_mein', '{"id":"edamame_scallion_lo_mein","name":"Edamame Scallion Lo Mein","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"edamame_frozen","q":300},{"f":"cabbage","q":0.2},{"f":"mushrooms","q":150},{"f":"scallions","q":1.5},{"f":"garlic","q":0.6},{"f":"ginger","q":12},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":12},{"f":"maple_syrup","q":15},{"f":"olive_oil","q":15}],"steps":["Boil the spaghetti in well-salted water until barely al dente, about 8 minutes, tossing the edamame into the pot for the final 3 minutes, then drain both and reserve a splash of the cooking water.","Stir together the soy sauce, maple syrup, sesame oil, minced garlic, and grated ginger while the pasta cooks so the flavors have a minute to make friends.","Get the olive oil rippling-hot in a wide skillet and sear the sliced mushrooms in a single layer for 4 to 5 minutes until their edges brown and squeak against the pan.","Add the shredded cabbage and the white parts of the scallions and stir-fry for 2 minutes until the cabbage wilts but keeps a little crunch.","Add the noodles, edamame, and sauce and toss vigorously for 2 minutes, loosening with reserved pasta water until the sauce clings to every strand like a lacquer.","Finish with the scallion greens and serve straight from the pan while it still steams."],"tip":"Slightly undercook the spaghetti — it finishes in the sauce and lo mein noodles should chew back at you a little."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_laksa_style_noodle_soup', '{"id":"coconut_laksa_style_noodle_soup","name":"Coconut Laksa-Style Tofu Noodle Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy"],"time":45,"servings":4,"ing":[{"f":"rice_noodles","q":250},{"f":"tofu","q":400},{"f":"coconut_milk","q":400},{"f":"curry_powder","q":12},{"f":"turmeric","q":4},{"f":"ginger","q":20},{"f":"garlic","q":0.8},{"f":"onion","q":1},{"f":"mushrooms","q":200},{"f":"spinach","q":120},{"f":"lime","q":2},{"f":"maple_syrup","q":15},{"f":"salt","q":6},{"f":"olive_oil","q":20},{"f":"cilantro","q":0.5}],"steps":["Soften the sliced onion in the oil in a soup pot over medium heat for 5 minutes, then add the garlic, grated ginger, curry powder, and turmeric and fry for a full minute until the spices bloom and the kitchen smells like a hawker stall.","Pour in the coconut milk and 1 liter of water, add the salt and maple syrup, and bring to a gentle simmer — never a rolling boil, or the broth loses its silkiness.","Slide in the cubed tofu and sliced mushrooms and simmer uncovered for 12 minutes so the tofu soaks up the golden broth like a sponge.","Meanwhile, soak the rice noodles in just-boiled water for 8 minutes until tender, then drain and divide among four deep bowls.","Stir the spinach into the pot until it collapses, about 1 minute, then taste and sharpen the broth with the juice of both limes until it makes you blink.","Ladle the soup over the noodles and top each bowl with a tangle of cilantro."],"tip":"The broth should taste a touch too intense on its own — the noodles are freeloaders who dilute everything they touch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_coconut_curry_rice', '{"id":"cashew_coconut_curry_rice","name":"Creamy Cashew Coconut Curry with Rice","emoji":"🥥","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":40,"servings":2,"ing":[{"f":"cashews","q":70},{"f":"coconut_milk","q":200},{"f":"rice","q":140},{"f":"curry_powder","q":10},{"f":"ginger","q":15},{"f":"garlic","q":0.6},{"f":"onion","q":1},{"f":"green_beans","q":200},{"f":"bell_pepper","q":1},{"f":"lime","q":1},{"f":"maple_syrup","q":10},{"f":"salt","q":4},{"f":"olive_oil","q":15}],"steps":["Start the rice simmering in salted water so it finishes right as the curry does, about 15 minutes covered plus 5 off the heat.","Toast the cashews in a dry skillet over medium heat for 3 to 4 minutes until golden and fragrant, then set half aside and roughly chop the rest.","Add the oil to the skillet and cook the sliced onion for 5 minutes until soft and translucent, then stir in the garlic, grated ginger, and curry powder and fry for 60 seconds until the pan smells heady.","Pour in the coconut milk with a splash of water, add the green beans, sliced bell pepper, chopped cashews, maple syrup, and salt, and simmer for 8 to 10 minutes until the beans are tender-crisp and the sauce coats the back of a spoon.","Squeeze in the lime, taste for salt, and spoon the curry over the rice with the whole toasted cashews scattered on top for crunch."],"tip":"The chopped cashews melt into the sauce and quietly thicken it — the whole ones on top are just showing off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_ginger_edamame_rice_bowls', '{"id":"sesame_ginger_edamame_rice_bowls","name":"Sesame-Ginger Edamame Rice Bowls","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":150},{"f":"edamame_frozen","q":300},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"avocado","q":1},{"f":"scallions","q":1},{"f":"sesame_oil","q":15},{"f":"soy_sauce","q":40},{"f":"maple_syrup","q":10},{"f":"ginger","q":15},{"f":"lime","q":1}],"steps":["Simmer the rice in salted water for 15 minutes until tender, then let it rest off the heat, covered, while you build everything else.","Whisk the soy sauce, sesame oil, maple syrup, grated ginger, and lime juice into a dressing that tastes bright and nutty with a gingery bite at the end.","Blanch the edamame in boiling water for 3 minutes until vivid green and just tender, then drain and toss while warm with a third of the dressing so it drinks it in.","Slice the cucumber into thin half-moons, shave the carrots into ribbons with a vegetable peeler, and fan the avocado into slices.","Mound the warm rice into two bowls, arrange the edamame and vegetables in bright wedges on top, drizzle with the rest of the dressing, and finish with sliced scallions."],"tip":"Dressing the edamame while warm is the whole trick — cold beans just wear the sauce, warm beans absorb it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_soy_glazed_tofu_bowls', '{"id":"maple_soy_glazed_tofu_bowls","name":"Maple-Soy Glazed Tofu Rice Bowls","emoji":"🍱","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":450},{"f":"rice","q":150},{"f":"broccoli","q":300},{"f":"soy_sauce","q":50},{"f":"maple_syrup","q":40},{"f":"garlic","q":0.6},{"f":"ginger","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"scallions","q":1}],"steps":["Get the rice going in salted water — 15 minutes at a simmer, then 5 minutes resting — and press the tofu between paper towels while it cooks.","Cut the tofu into thick slabs and sear them in the olive oil in a hot nonstick skillet for 4 to 5 minutes per side until both faces are burnished and crisp.","Add the broccoli florets and a splash of water to the pan, cover, and steam for 3 minutes until the broccoli turns emerald and a knife slips in with slight resistance.","Uncover and pour in the soy sauce, maple syrup, minced garlic, and grated ginger, then simmer hard for 2 to 3 minutes, spooning the bubbling glaze over the tofu until it turns sticky and clings like varnish.","Serve the tofu and broccoli over the rice, drizzle with sesame oil and any pan glaze, and scatter with sliced scallions."],"tip":"The glaze goes from syrupy to candy in about thirty seconds, so hover over the pan like it owes you money."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cold_sesame_rice_noodle_salad', '{"id":"cold_sesame_rice_noodle_salad","name":"Cold Sesame Rice Noodle Salad with Edamame","emoji":"🥒","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":160},{"f":"edamame_frozen","q":250},{"f":"cucumber","q":1},{"f":"carrots","q":120},{"f":"cabbage","q":0.2},{"f":"cilantro","q":0.5},{"f":"scallions","q":1},{"f":"lime","q":1.5},{"f":"soy_sauce","q":35},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":15},{"f":"ginger","q":10}],"steps":["Soak the rice noodles in just-boiled water for 7 to 8 minutes until tender, adding the edamame for the last 3 minutes, then drain both and rinse under cold running water until completely cool.","Whisk the soy sauce, sesame oil, maple syrup, grated ginger, and the juice of both limes into a dressing that tastes sharp and slightly sweet, like a good vinaigrette that went traveling.","Slice the cucumber into thin batons, coarsely grate the carrots, and shave the cabbage into fine ribbons — you want everything cut thin enough to tangle with the noodles.","Toss the noodles, edamame, and vegetables with the dressing in your biggest bowl, using tongs and a lifting motion until every strand glistens.","Let the salad sit for 10 minutes so the noodles absorb the dressing, then fold in the cilantro leaves and sliced scallions just before serving."],"tip":"This salad actually improves after an hour in the fridge, making it the rare lunch that rewards procrastination."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_scallion_congee_crispy_tofu', '{"id":"ginger_scallion_congee_crispy_tofu","name":"Ginger-Scallion Congee with Crispy Tofu","emoji":"🥣","cuisine":"Asian","meal":["breakfast","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":60,"servings":4,"ing":[{"f":"rice","q":220},{"f":"tofu","q":400},{"f":"ginger","q":30},{"f":"garlic","q":0.6},{"f":"scallions","q":2},{"f":"mushrooms","q":150},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":20},{"f":"salt","q":5}],"steps":["Rinse the rice until the water runs nearly clear, then combine it in a heavy pot with 2 liters of water, half the ginger cut into coins, and the salt.","Bring to a boil, then drop to a lazy simmer and cook uncovered for 40 to 45 minutes, stirring every 10 minutes and scraping the bottom, until the grains burst and the porridge turns silky and thick enough to hold a spoon trail.","While the congee simmers, pat the tofu dry, cube it, and fry it in the olive oil over medium-high heat with the sliced mushrooms for 10 minutes until the tofu is crisp-edged and the mushrooms are deeply browned.","Mince the remaining ginger and the garlic, pile them with the sliced scallions in a small heatproof bowl, and pour the sesame oil over — warmed briefly in the tofu pan first so it sizzles the aromatics awake.","Ladle the congee into bowls, top with the crispy tofu and mushrooms, spoon over the ginger-scallion oil, and finish each bowl with a thread of soy sauce."],"tip":"Congee thickens dramatically as it sits, so keep a kettle nearby and loosen leftovers with hot water, not guilt."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('singapore_style_curry_rice_noodles', '{"id":"singapore_style_curry_rice_noodles","name":"Singapore-Style Curry Rice Noodles with Cashews","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","nuts"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"cashews","q":70},{"f":"curry_powder","q":10},{"f":"turmeric","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"cabbage","q":0.2},{"f":"peas_frozen","q":80},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":35},{"f":"olive_oil","q":25},{"f":"scallions","q":1},{"f":"lime","q":1}],"steps":["Soak the rice noodles in hot tap water for 10 minutes until bendy but still firm — they will finish cooking in the wok, so err on the side of undercooked.","Toast the cashews in a dry wok over medium heat for 3 minutes until spotted gold, then remove them and add the oil.","Crank the heat to high and stir-fry the sliced onion, bell pepper, and shredded cabbage for 3 to 4 minutes until they char slightly at the edges but stay crisp.","Add the garlic, curry powder, and turmeric and toss for 30 seconds until the spices coat everything in a yellow haze and smell toasty, not raw.","Add the drained noodles, peas, soy sauce, and a splash of water and stir-fry for 2 to 3 minutes, tossing constantly with tongs, until the noodles are stained gold and tender.","Fold in the cashews and scallions and serve with lime wedges for squeezing."],"tip":"Curry powder burns fast on high heat, so have the noodles drained and standing by before the spices hit the wok."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_edamame_ramen_style_soup', '{"id":"mushroom_edamame_ramen_style_soup","name":"Mushroom Edamame Ramen-Style Soup","emoji":"🍥","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"spaghetti","q":250},{"f":"edamame_frozen","q":350},{"f":"mushrooms","q":300},{"f":"garlic","q":0.8},{"f":"ginger","q":20},{"f":"onion","q":1},{"f":"soy_sauce","q":60},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"spinach","q":100},{"f":"scallions","q":2},{"f":"maple_syrup","q":10}],"steps":["Sear the sliced mushrooms in the olive oil in a large pot over high heat for 6 to 8 minutes, without crowding, until they are deeply browned and the pot bottom is glazed with dark fond — that fond is your broth''s backbone.","Add the sliced onion, minced garlic, and grated ginger and cook for 3 minutes until softened, then pour in 1.5 liters of water, scraping up every browned bit.","Stir in the soy sauce and maple syrup and simmer the broth, partially covered, for 15 minutes so it turns the color of strong tea and tastes savory enough to sip on its own.","Meanwhile, boil the spaghetti in a separate pot of salted water until just tender, about 8 minutes, then drain and divide among four bowls.","Add the edamame to the broth and simmer 3 minutes, then stir in the spinach until it wilts and slicks down, about 1 minute more.","Ladle the steaming broth and vegetables over the noodles, drizzle each bowl with sesame oil, and crown with a generous heap of sliced scallions."],"tip":"Cook the noodles separately or they will slurp up your hard-won broth like uninvited guests at an open bar."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sticky_ginger_eggplant_cashew_rice', '{"id":"sticky_ginger_eggplant_cashew_rice","name":"Sticky Ginger Eggplant with Cashews and Rice","emoji":"🍆","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","nuts","sesame"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"cashews","q":80},{"f":"rice","q":150},{"f":"ginger","q":20},{"f":"garlic","q":0.6},{"f":"soy_sauce","q":45},{"f":"maple_syrup","q":30},{"f":"scallions","q":1},{"f":"olive_oil","q":30},{"f":"sesame_oil","q":8}],"steps":["Set the rice simmering in salted water and cut the eggplant into chunky 3-centimeter batons while it cooks.","Heat the olive oil in your widest skillet over medium-high heat and fry the eggplant in a single layer for 10 to 12 minutes, turning every few minutes, until each piece is bronzed outside and custard-soft within — press one with a spatula and it should yield completely.","Push the eggplant to the edges, drop the minced ginger and garlic into the center, and stir for 45 seconds until fragrant and sizzling.","Pour in the soy sauce, maple syrup, and a splash of water and let the sauce bubble and reduce for 2 to 3 minutes, tossing until the eggplant is lacquered in a glossy mahogany glaze.","Fold in the cashews, drizzle with sesame oil, and serve over the rice with a flurry of sliced scallions on top."],"tip":"Eggplant is a sponge with commitment issues — let it brown fully before the sauce arrives or it will never crisp again."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('dan_dan_style_sesame_noodles', '{"id":"dan_dan_style_sesame_noodles","name":"Dan Dan-Style Sesame Noodles with Crispy Tofu Crumbles","emoji":"🌶️","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy","nuts","sesame"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"tofu","q":350},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":12},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.6},{"f":"ginger","q":12},{"f":"chili_powder","q":4},{"f":"spinach","q":100},{"f":"scallions","q":1},{"f":"olive_oil","q":15}],"steps":["Crumble the tofu into rough pebbles with your hands and fry it in the olive oil over medium-high heat for 8 to 10 minutes, stirring only occasionally, until the bits are browned and crisp like savory granola, then season with a third of the soy sauce and the chili powder.","Boil the spaghetti in salted water until al dente, about 9 minutes, dropping the spinach into the pot for the final 30 seconds, and reserve a cup of cooking water before draining.","Whisk the peanut butter, remaining soy sauce, sesame oil, maple syrup, grated ginger, and minced garlic in a large bowl, then thin with hot pasta water a spoonful at a time until the sauce is the texture of heavy cream.","Add the drained noodles and spinach to the bowl and toss with tongs until every strand wears a clinging, silky coat.","Divide between bowls, bury the noodles under the crispy tofu crumbles, and finish with sliced scallions and an extra pinch of chili powder for the brave."],"tip":"The sauce will look hopelessly broken when the hot water first hits the peanut butter — keep whisking, it always comes back."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_chana_masala', '{"id":"smoky_chana_masala","name":"Smoky Chana Masala with Creamy Coconut Finish","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":2},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"tomato","q":4},{"f":"chickpeas","q":700},{"f":"turmeric","q":4},{"f":"garam_masala","q":8},{"f":"curry_powder","q":8},{"f":"coconut_milk","q":200},{"f":"spinach","q":150},{"f":"lime","q":1},{"f":"cilantro","q":0.5}],"steps":["Heat the olive oil in a wide, heavy pot over medium heat and cook the diced onions for 10 to 12 minutes, stirring occasionally, until they turn a deep golden brown at the edges.","Stir in the minced garlic and grated ginger and cook for 1 minute until fragrant, then add the turmeric, curry powder, and half the garam masala, toasting the spices in the oil for 30 seconds until they smell nutty.","Add the chopped tomatoes and simmer for 6 to 8 minutes, mashing them with the back of your spoon, until they collapse into a thick, jammy masala that pulls away from the sides of the pot.","Tip in the chickpeas and coconut milk with a splash of water, bring to a gentle bubble, and simmer uncovered for 12 minutes until the sauce clings to the chickpeas and darkens a shade.","Fold in the spinach and remaining garam masala, letting the leaves wilt for 2 minutes, then finish with a big squeeze of lime and a shower of chopped cilantro.","Taste and adjust with more lime or salt until the sauce is bright, rich, and spoonable, then serve hot."],"tip":"Crush a few chickpeas against the pot as they simmer — it thickens the gravy better than any shortcut you could buy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_dal', '{"id":"coconut_red_lentil_dal","name":"Golden Coconut Dal with Lime and Wilted Spinach","emoji":"🥣","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"coconut_milk","q":400},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"turmeric","q":6},{"f":"curry_powder","q":10},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"lime","q":1}],"steps":["Rinse the lentils until the water runs nearly clear, then combine them in a pot with the turmeric and 800 milliliters of water and bring to a boil, skimming any foam that rises.","Reduce to a lively simmer and cook for 18 to 20 minutes, stirring now and then, until the lentils break down into a soft, porridge-like consistency.","Meanwhile, heat the olive oil in a small skillet over medium heat and fry the sliced onion for 8 minutes until browned and frizzled at the edges, then add the garlic, ginger, and curry powder and sizzle for 45 seconds until deeply aromatic.","Scrape the sizzling onion mixture into the lentils along with the chopped tomatoes and coconut milk, and simmer everything together for 8 more minutes until thick enough to hold a trail from your spoon.","Stir in the spinach until just wilted, squeeze in the lime, and season generously with salt before ladling into bowls."],"tip":"The dal thickens dramatically as it sits, so keep a splash of hot water handy to loosen it back to lava-flow consistency."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('aloo_gobi_dry_sabzi', '{"id":"aloo_gobi_dry_sabzi","name":"Aloo Gobi with Charred Cauliflower and Sweet Peas","emoji":"🥔","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"potatoes","q":400},{"f":"cauliflower","q":0.7},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"turmeric","q":5},{"f":"garam_masala","q":5},{"f":"peas_frozen","q":100},{"f":"cilantro","q":0.3},{"f":"lime","q":0.5}],"steps":["Cut the potatoes into 2-centimeter chunks and the cauliflower into similar-sized florets so everything cooks at the same pace.","Heat the olive oil in your largest skillet over medium-high heat, add the potatoes in a single layer, and let them sit undisturbed for 5 minutes until golden and crusty on the bottom before tossing.","Add the cauliflower, chopped onion, and a pinch of salt, then cover and cook for 8 minutes, shaking the pan occasionally, until the florets pick up charred spots and the potatoes yield to a knife.","Uncover and stir in the garlic, ginger, and turmeric, letting the spices coat every piece in a golden jacket for 2 minutes.","Scatter in the frozen peas and garam masala and toss for 2 to 3 minutes until the peas are bright and hot, then finish with lime juice and torn cilantro.","Serve straight from the skillet while the edges are still crisp."],"tip":"Resist the urge to stir constantly — browned, slightly blistered edges are the whole point of a dry sabzi."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('palak_tofu_curry', '{"id":"palak_tofu_curry","name":"Palak Tofu in Silky Spinach-Coconut Gravy","emoji":"🥬","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["soy"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"spinach","q":400},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"lime","q":0.5}],"steps":["Press the tofu between paper towels for 10 minutes, cut it into 2-centimeter cubes, and pan-fry in half the olive oil over medium-high heat for 8 minutes, turning until every side is golden and crackly.","Wilt the spinach in a dry pot over medium heat for 2 minutes until collapsed and glossy, then blend it with the coconut milk into a smooth, deep-green puree.","In the same pot, heat the remaining oil and soften the diced onion for 6 minutes until translucent, then add the garlic, ginger, turmeric, and garam masala and cook for 1 minute until the kitchen smells like a curry house.","Pour in the spinach puree and simmer gently for 5 minutes, stirring, until it thickens just enough to coat a spoon without turning army-green.","Slide in the fried tofu, simmer 3 more minutes so the cubes drink up the gravy, and finish with lime juice and salt to taste."],"tip":"Blend the spinach the moment it wilts — overcooked spinach trades its emerald color for swamp, and nobody orders swamp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_vegetable_korma', '{"id":"cashew_vegetable_korma","name":"Creamy Cashew Vegetable Korma","emoji":"🥥","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"cashews","q":100},{"f":"coconut_milk","q":400},{"f":"olive_oil","q":20},{"f":"onion","q":2},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"cauliflower","q":0.5},{"f":"carrots","q":200},{"f":"green_beans","q":200},{"f":"peas_frozen","q":150},{"f":"curry_powder","q":12},{"f":"garam_masala","q":6},{"f":"maple_syrup","q":15}],"steps":["Soak half the cashews in boiling water for 15 minutes while you prep the vegetables, then blend them with the coconut milk into a completely smooth, cream-colored sauce.","Heat the olive oil in a deep pot over medium heat and cook the sliced onions for 10 minutes until soft and lightly golden, then stir in the garlic, ginger, and curry powder and toast for 1 minute.","Add the cauliflower florets, sliced carrots, and trimmed green beans with a splash of water, cover, and steam for 6 minutes until just shy of tender.","Pour in the cashew-coconut cream and maple syrup, bring to a bare simmer, and cook uncovered for 8 to 10 minutes until the sauce thickens to a velvety, spoon-coating richness.","Stir in the peas and garam masala and simmer 2 final minutes, then scatter the remaining cashews on top, toasted if you have a spare minute.","Season with salt, and serve warm in wide bowls."],"tip":"Never let a cashew sauce hit a rolling boil — it goes from silk to grainy sweater faster than you can say korma."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_kale_coconut_curry', '{"id":"sweet_potato_kale_coconut_curry","name":"Sweet Potato and Kale Coconut Curry over Rice","emoji":"🍠","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"sweet_potatoes","q":800},{"f":"coconut_milk","q":400},{"f":"kale","q":0.8},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"curry_powder","q":12},{"f":"turmeric","q":4},{"f":"olive_oil","q":20},{"f":"rice","q":200},{"f":"lime","q":1}],"steps":["Start the rice in a small pot with 400 milliliters of water, bring it to a boil, then cover and simmer on low for 15 minutes before letting it rest off the heat.","Meanwhile, heat the olive oil in a large pot over medium heat and cook the diced onion for 6 minutes until soft, then add the garlic, ginger, curry powder, and turmeric and stir for 1 minute until the oil turns amber.","Add the sweet potatoes, cut into 3-centimeter chunks, and toss to coat them in the spiced oil before pouring in the coconut milk and 200 milliliters of water.","Simmer, partially covered, for 15 to 18 minutes until a fork slides easily into the sweet potato and the sauce has thickened to a gentle orange cream.","Tear the kale into bite-sized pieces, stir it in, and cook 3 minutes until tender but still vividly green, then brighten everything with lime juice and salt.","Fluff the rice with a fork and ladle the curry generously over each bowl."],"tip":"Cut the sweet potatoes big — small dice dissolves into baby food before the sauce has time to reduce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_matar_masala', '{"id":"mushroom_matar_masala","name":"Mushroom Matar in Tomato-Coconut Masala","emoji":"🍄","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"peas_frozen","q":200},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":20},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"cilantro","q":0.3}],"steps":["Heat the olive oil in a wide skillet over high heat and sear the quartered mushrooms in a single layer for 6 to 8 minutes, stirring only twice, until they are deeply browned and have stopped squeaking.","Lower the heat to medium, push the mushrooms aside, and cook the diced onion for 5 minutes until soft, then add the garlic, ginger, and turmeric and stir for 1 fragrant minute.","Add the chopped tomatoes and cook for 5 to 6 minutes, mashing occasionally, until they melt into a rusty-red paste that glistens with oil at the edges.","Pour in the coconut milk and frozen peas, bring to a simmer, and cook for 5 minutes until the peas are sweet and the sauce coats the mushrooms like a light gravy.","Stir in the garam masala, season with salt, and rest the curry off the heat for 2 minutes before showering it with chopped cilantro."],"tip":"A crowded mushroom steams and a spaced-out mushroom sears — give them elbow room or accept beige regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_sabzi_turmeric_rice', '{"id":"zucchini_sabzi_turmeric_rice","name":"Zucchini Sabzi with Turmeric Rice","emoji":"🥒","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"zucchini","q":2.5},{"f":"rice","q":120},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"turmeric","q":5},{"f":"curry_powder","q":8},{"f":"cilantro","q":0.3}],"steps":["Rinse the rice, then simmer it with 240 milliliters of water and half the turmeric in a covered pot for 15 minutes until sunshine-yellow and tender; keep it covered off the heat.","While the rice cooks, halve the zucchini lengthwise and slice it into thick half-moons so it can brown without collapsing.","Heat the olive oil in a large skillet over medium-high heat, cook the sliced onion for 4 minutes until it softens, then add the garlic, remaining turmeric, and curry powder and sizzle for 30 seconds.","Add the zucchini and a good pinch of salt and cook, tossing every couple of minutes, for 8 to 10 minutes until the edges caramelize and the centers turn silky but not mushy.","Stir in the chopped tomatoes and cook 3 more minutes until they slump into a light, clingy glaze, then fold in the cilantro.","Fluff the golden rice and pile the sabzi alongside."],"tip":"Salt the zucchini only once it hits the pan — salting early draws out water and turns your sabzi into soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('green_bean_carrot_coconut_sabzi', '{"id":"green_bean_carrot_coconut_sabzi","name":"Green Bean and Carrot Coconut Sabzi Bowls","emoji":"🫛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"green_beans","q":300},{"f":"carrots","q":300},{"f":"rice","q":150},{"f":"coconut_milk","q":100},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"turmeric","q":4},{"f":"curry_powder","q":6}],"steps":["Get the rice simmering in a covered pot with 300 milliliters of water for 15 minutes, then rest it off the heat while you cook the vegetables.","Trim the green beans and cut them into 3-centimeter lengths, and slice the carrots into thin coins so both cook in the same time.","Heat the olive oil in a wide skillet over medium heat, fry the chopped onion for 5 minutes until golden, then bloom the garlic, turmeric, and curry powder in the oil for 30 seconds until it smells toasty.","Add the beans and carrots with a pinch of salt and a splash of water, cover, and steam for 6 minutes until crisp-tender and stained gold.","Uncover, pour in the coconut milk, and cook 3 to 4 minutes more until it reduces to a rich coating rather than a puddle, then taste for salt and serve over the rice."],"tip":"The coconut milk should vanish into a glaze — if your sabzi sloshes, keep the heat on another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_rajma_style_curry', '{"id":"black_bean_rajma_style_curry","name":"Rajma-Style Black Bean Curry","emoji":"🫘","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"black_beans","q":700},{"f":"tomato","q":4},{"f":"onion","q":2},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"olive_oil","q":25},{"f":"garam_masala","q":8},{"f":"turmeric","q":4},{"f":"curry_powder","q":6},{"f":"coconut_milk","q":200},{"f":"cilantro","q":0.5}],"steps":["Heat the olive oil in a heavy pot over medium heat and cook the finely diced onions for 10 to 12 minutes, stirring, until they are the color of dark honey — this browning is the backbone of the gravy.","Add the garlic and ginger and cook for 1 minute, then stir in the turmeric and curry powder and toast for 30 seconds until fragrant.","Add the chopped tomatoes and simmer for 8 minutes, mashing them down, until the masala turns thick, glossy, and brick-red.","Stir in the black beans and coconut milk with a splash of water, then simmer gently for 15 minutes, crushing a ladleful of beans against the side of the pot to thicken the gravy naturally.","Finish with the garam masala and a generous pinch of salt, rest 5 minutes so the flavors settle into each other, and serve topped with chopped cilantro."],"tip":"This curry is like gossip — noticeably better the next day, so make it ahead if you can stand the wait."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_tikka_skillet', '{"id":"tofu_tikka_skillet","name":"Charred Tofu Tikka Skillet with Peppers and Cashews","emoji":"🔥","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy","nuts"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"garam_masala","q":8},{"f":"turmeric","q":4},{"f":"curry_powder","q":6},{"f":"lime","q":1},{"f":"maple_syrup","q":10},{"f":"cashews","q":50},{"f":"cilantro","q":0.3}],"steps":["Press the tofu for 10 minutes, tear it into rough bite-sized chunks — ragged edges catch more spice — and toss with half the oil, the turmeric, curry powder, and half the garam masala.","Heat a large skillet over medium-high heat and cook the tofu for 8 to 10 minutes, turning occasionally, until the craggy edges char and crisp.","Push the tofu to one side, add the remaining oil, and sear the thick-sliced bell peppers and onion wedges for 5 to 6 minutes until blistered but still snappy.","Toss in the cashews and cook 2 minutes until toasted and golden, then drizzle in the maple syrup and remaining garam masala and stir until everything is lacquered and glistening.","Kill the heat, squeeze the lime over the whole pan, season with salt, and finish with a handful of cilantro."],"tip":"Torn tofu beats cubed tofu every time — the shaggy surface grabs spice like velcro while cubes just slide around in it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_curried_chickpea_spinach_skillet', '{"id":"crispy_curried_chickpea_spinach_skillet","name":"Crispy Curried Chickpeas with Garlicky Spinach","emoji":"✨","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":450},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"curry_powder","q":10},{"f":"turmeric","q":4},{"f":"lime","q":1}],"steps":["Drain the chickpeas and pat them thoroughly dry with a towel — moisture is the enemy of crispness.","Heat the olive oil in a large skillet over medium-high heat and fry the chickpeas in an even layer for 8 to 10 minutes, shaking the pan every few minutes, until they pop, blister, and turn golden.","Add the sliced onion and cook 4 minutes until it softens and browns at the edges alongside the chickpeas.","Sprinkle in the curry powder and turmeric and toss for 1 minute so every chickpea wears a golden crust, then add the garlic and cook 30 seconds more.","Pile in the spinach with a pinch of salt and toss just until it wilts into dark green ribbons, about 2 minutes, then hit the whole pan with lime juice and serve immediately while the chickpeas still crunch."],"tip":"Dry your chickpeas like you mean it — a damp chickpea steams sadly while a dry one fries into a crouton."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_pea_pulao', '{"id":"vegetable_pea_pulao","name":"Fragrant Vegetable Pea Pulao with Toasted Cashews","emoji":"🍚","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":40,"servings":4,"ing":[{"f":"rice","q":300},{"f":"peas_frozen","q":200},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"olive_oil","q":25},{"f":"turmeric","q":5},{"f":"garam_masala","q":6},{"f":"cashews","q":60},{"f":"cilantro","q":0.5}],"steps":["Rinse the rice until the water runs clear and let it drain while you build the base — this keeps the grains separate instead of gluey.","Heat the olive oil in a wide, lidded pot over medium heat and toast the cashews for 2 minutes until golden, then scoop them out and set aside.","In the same fragrant oil, cook the sliced onion for 6 to 8 minutes until deeply golden, then add the garlic, ginger, turmeric, and garam masala and stir for 45 seconds until the spices bloom.","Add the diced carrots and drained rice and stir for 2 minutes so every grain is slicked with spiced oil, then pour in 600 milliliters of water with a generous teaspoon of salt.","Bring to a boil, scatter the peas on top without stirring, then cover and simmer on the lowest heat for 15 minutes before resting off the heat, still covered, for 5 more.","Fluff gently with a fork, folding in the toasted cashews and cilantro as you go, and serve steaming."],"tip":"The 5-minute covered rest is non-negotiable — lift the lid early and you trade fluffy pulao for stubborn, clumpy rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_street_tacos', '{"id":"smoky_black_bean_street_tacos","name":"Smoky Black Bean Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"black_beans","q":240},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Warm the olive oil in a skillet over medium heat and cook the diced onion for 4 to 5 minutes, until the edges turn golden and it smells sweet.","Stir in the minced garlic with a big pinch of smoked paprika and cumin, then add the drained black beans and chopped tomato.","Simmer for 6 to 8 minutes, mashing about a third of the beans against the pan until the mixture is thick enough to hold its shape on a spoon.","Toast the tortillas directly over a low flame or in a dry pan for 30 seconds per side, until speckled with char and pliable.","Pile the beans into the tortillas, top with sliced avocado, and finish with a hard squeeze of lime and flaky salt."],"tip":"Mash some beans, not all of them — a taco filling with no texture is just soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sofritas_tofu_burrito_bowl', '{"id":"sofritas_tofu_burrito_bowl","name":"Sofritas Tofu Burrito Bowl","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":35,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"rice","q":150},{"f":"black_beans","q":200},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Start the rice simmering in salted water, covered, for 15 minutes, then let it steam off the heat while you cook everything else.","Crumble the tofu into rough, ragged pieces and sear it in olive oil over medium-high heat for 8 minutes, undisturbed at first, until the bottom is deeply browned.","Add the diced onion, garlic, chopped tomato, and a generous spoonful of chili powder and smoked paprika, then simmer for 5 minutes until the tofu is stained brick-red and saucy.","Warm the black beans in their liquid with a pinch of cumin so they stay creamy rather than chalky.","Build the bowls with rice on the bottom, then beans, then sofritas, and crown with sliced avocado and plenty of lime juice."],"tip":"Crumble the tofu by hand instead of cubing it — craggy edges catch sauce, and neat cubes catch nothing but disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_fajita_skillet', '{"id":"chickpea_fajita_skillet","name":"Chickpea Fajita Skillet","emoji":"🌶️","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":240},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Heat the olive oil in your widest skillet over high heat until it shimmers, then add thick strips of bell pepper and onion in a single layer.","Leave them alone for 3 full minutes so they blister and blacken in spots before you stir, then cook 3 minutes more until crisp-tender.","Add the drained chickpeas, minced garlic, and a heavy dusting of cumin, chili powder, and oregano, tossing until the chickpeas are hot and lightly toasted, about 4 minutes.","Kill the heat and squeeze over half the lime, scraping up the browned spice bits from the pan floor.","Serve straight from the skillet topped with sliced avocado and the remaining lime cut into wedges."],"tip":"A crowded pan steams and a hot pan chars — if your peppers aren''t hissing at you, your skillet isn''t ready."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_tortilla_soup', '{"id":"lentil_tortilla_soup","name":"Lentil Tortilla Soup","emoji":"🍲","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":280},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"tortillas","q":2},{"f":"avocado","q":1},{"f":"lime","q":2}],"steps":["Sweat the diced onion in olive oil over medium heat for 5 minutes, then add the garlic, a tablespoon of chili powder, and a teaspoon of cumin and stir until fragrant, about 45 seconds.","Add the chopped tomatoes and cook them down for 5 minutes until they slump into a rough, jammy sauce.","Pour in the rinsed lentils with 1.2 liters of water, bring to a boil, then simmer uncovered for 25 to 30 minutes until the lentils are tender but still hold their shape.","Meanwhile, slice the tortillas into thin strips and toast them in a dry pan over medium heat until golden and audibly crisp, about 4 minutes.","Season the soup aggressively with salt and the juice of both limes, then ladle into bowls and top with tortilla strips and diced avocado."],"tip":"The lime goes in at the end, not the beginning — acid added early cooks into a rumor, but acid added late is a headline."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_lime_soup', '{"id":"black_bean_lime_soup","name":"Black Bean and Lime Soup","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"black_beans","q":720},{"f":"rice","q":100},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"avocado","q":1},{"f":"lime","q":2}],"steps":["Cook the diced onion in olive oil over medium heat until translucent and just catching color at the edges, about 6 minutes.","Add the garlic, a tablespoon of cumin, and a teaspoon of oregano, then stir in the chopped tomatoes and cook 4 minutes until thickened.","Add the black beans with their liquid, the rice, and 1 liter of water, then simmer gently for 20 minutes until the rice is tender and the broth has turned dark and glossy.","Ladle a third of the soup into a blender, puree until smooth, and stir it back in for a broth that coats the spoon.","Finish with the juice of both limes and a big pinch of salt, then top each bowl with cubes of cool avocado."],"tip":"Blending one-third of the pot is the lazy cook''s velvet — all the body of an all-day soup with none of the alibi."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_chili_crispy_chickpea_tacos', '{"id":"maple_chili_crispy_chickpea_tacos","name":"Maple-Chili Crispy Chickpea Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":240},{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"maple_syrup","q":10},{"f":"onion","q":0.5},{"f":"spinach","q":100},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Pat the chickpeas thoroughly dry, then fry them in olive oil over medium-high heat for 8 to 10 minutes, shaking the pan occasionally, until they rattle and turn deep golden.","Off the heat, toss them with the maple syrup, a teaspoon of chili powder, and a pinch of smoked paprika so each chickpea gets a sticky, spicy lacquer.","While they cook, slice the onion paper-thin and soak it in the juice of half the lime with a pinch of salt for a quick pickle.","Char the tortillas in a dry skillet for 30 seconds per side until warm and blistered.","Load each tortilla with a bed of spinach, mashed avocado, the glazed chickpeas, and a tangle of pickled onion, then finish with the last of the lime."],"tip":"Dry chickpeas fry and wet chickpeas spit — a clean kitchen towel now saves you a stovetop archaeology dig later."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_rancheros_skillet', '{"id":"tofu_rancheros_skillet","name":"Tofu Rancheros Breakfast Skillet","emoji":"🍳","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":25,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"black_beans","q":240},{"f":"tomato","q":2},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"avocado","q":0.5},{"f":"lime","q":1}],"steps":["Soften the diced onion and bell pepper in olive oil over medium heat for 6 minutes, until the pepper''s edges begin to wrinkle.","Add the garlic, chopped tomatoes, a teaspoon of chili powder, and a pinch of oregano, then simmer 6 to 8 minutes into a loose, brick-red ranchero sauce.","Crumble in the tofu with half a teaspoon of turmeric and a good pinch of salt, folding gently so it stains golden like soft-scrambled eggs.","Stir in the black beans and let everything bubble together for 3 minutes until the tofu has drunk up some of the sauce.","Serve hot from the pan with sliced avocado and lime wedges on the rim."],"tip":"Turmeric is doing costume work here, so measure it — half a teaspoon says scrambled eggs, a whole tablespoon says science experiment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quinoa_stuffed_bell_peppers', '{"id":"quinoa_stuffed_bell_peppers","name":"Quinoa-Stuffed Bell Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"quinoa","q":120},{"f":"black_beans","q":120},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Heat the oven to 200C and simmer the rinsed quinoa in 240 milliliters of salted water for 15 minutes, until the little spirals unfurl.","Meanwhile, cook the diced onion and garlic in olive oil until soft, then stir in the chopped tomato, black beans, a teaspoon of cumin, and a teaspoon of chili powder and simmer 5 minutes.","Fold the quinoa into the skillet mixture, taste, and season boldly with salt and half the lime juice.","Halve the peppers through the stem, scoop out the seeds, and pack each half generously with filling.","Roast on an oiled tray for 25 minutes, until the peppers slump and their edges char sweetly, then finish with the remaining lime."],"tip":"Season the filling until it tastes almost too loud on its own — a bland stuffing hides inside a pepper, but it never escapes your notice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_picadillo_tacos', '{"id":"lentil_picadillo_tacos","name":"Lentil Picadillo Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"tortillas","q":4},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"maple_syrup","q":5},{"f":"avocado","q":0.5},{"f":"lime","q":1}],"steps":["Simmer the rinsed lentils in salted water for 20 minutes until tender but not mushy, then drain well.","Cook the diced onion in olive oil over medium heat for 5 minutes, add the garlic, then stir in the chopped tomato, a teaspoon of cumin, a teaspoon of oregano, and a pinch of cinnamon.","Fold in the lentils and the maple syrup and simmer 8 minutes, mashing lightly, until the mixture is thick, glossy, and savory-sweet like a proper picadillo.","Warm the tortillas in a dry skillet until soft and lightly toasted, about 30 seconds per side.","Fill the tortillas with the lentil picadillo, top with sliced avocado, and brighten everything with lime just before eating."],"tip":"That pinch of cinnamon is the picadillo handshake — guests will taste something familiar and mysterious, and you should tell them absolutely nothing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_bowl', '{"id":"sweet_potato_black_bean_bowl","name":"Roasted Sweet Potato and Black Bean Bowl","emoji":"🍠","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":400},{"f":"black_beans","q":240},{"f":"rice","q":120},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Heat the oven to 220C, toss the sweet potato cubes with olive oil, chili powder, cumin, and salt, and roast for 25 minutes until caramelized at the corners and creamy inside.","Simmer the rice in salted water for 15 minutes, then rest it off the heat, covered, for 5 more.","Warm the black beans with the minced garlic and a splash of water in a small pan, smashing a few against the side until saucy.","Mash the avocado with the juice of half the lime and a pinch of salt into a rough, chunky crema.","Layer rice, beans, and roasted sweet potatoes into bowls, dollop the avocado over the top, and finish with the last squeeze of lime."],"tip":"Give the sweet potatoes room on the tray — crowded cubes steam into pillows, and you were promised caramel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_chickpea_chili', '{"id":"smoky_chickpea_chili","name":"Smoky Chickpea Chili","emoji":"🍛","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chickpeas","q":600},{"f":"tomato","q":4},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"corn_frozen","q":150},{"f":"maple_syrup","q":10},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Brown the diced onion and bell pepper in olive oil over medium-high heat for 7 minutes, letting them pick up dark edges that will flavor the whole pot.","Add the garlic with two tablespoons of chili powder, a tablespoon of smoked paprika, and a teaspoon of cumin, stirring for 1 minute until the spices smell toasty rather than raw.","Add the chopped tomatoes, chickpeas, corn, maple syrup, and 400 milliliters of water, then simmer uncovered for 25 minutes, until thick enough that a spoon dragged through leaves a trail.","Mash a ladleful of chickpeas against the pot wall to thicken the chili from within.","Season with salt and the lime juice, and serve each bowl topped with diced avocado."],"tip":"Chili is a dish best judged tomorrow, so make it today — the leftovers are the real recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_quinoa_fiesta_salad', '{"id":"mexican_quinoa_fiesta_salad","name":"Mexican Quinoa Fiesta Salad","emoji":"🥗","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"corn_frozen","q":150},{"f":"black_beans","q":120},{"f":"tomato","q":1},{"f":"spinach","q":100},{"f":"onion","q":0.3},{"f":"olive_oil","q":20},{"f":"avocado","q":1},{"f":"lime","q":2}],"steps":["Simmer the rinsed quinoa in 280 milliliters of salted water for 15 minutes, then spread it on a plate to cool so it stays fluffy instead of clumping.","Char the corn in a dry skillet over high heat for 4 to 5 minutes, tossing occasionally, until spotted with black and smelling like a street fair.","Whisk the olive oil with the juice of both limes, a teaspoon of cumin, and a generous pinch of salt into a sharp dressing.","Toss the quinoa with the corn, black beans, chopped tomato, spinach, and finely minced onion, then pour over the dressing.","Fold in the diced avocado last, gently, and taste for salt before serving at room temperature."],"tip":"Cool the quinoa before dressing it — warm grains drink the dressing and leave the vegetables to attend the party dry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_corn_black_bean_esquites_salad', '{"id":"charred_corn_black_bean_esquites_salad","name":"Charred Corn and Black Bean Esquites-Style Salad","emoji":"🌽","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"corn_frozen","q":400},{"f":"black_beans","q":240},{"f":"onion","q":0.3},{"f":"garlic","q":0.1},{"f":"olive_oil","q":20},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"lime","q":2}],"steps":["Get a dry skillet screaming hot, add the corn in a single layer, and let it char undisturbed for 3 minutes before tossing; repeat until most kernels have blackened freckles, about 8 minutes total.","Stir the minced garlic and olive oil into the hot corn for the final minute so the garlic toasts without burning.","Scrape everything into a bowl with the black beans, chopped tomato, and finely minced onion.","Mash half the avocado with the juice of both limes, a teaspoon of chili powder, and a big pinch of salt into a creamy dressing, then dice the other half.","Fold the dressing through the warm salad, top with the diced avocado and extra chili powder, and serve while the corn still smells smoky."],"tip":"Charring corn is a spectator sport with popping — a lid held like a shield keeps the kernels in the pan and out of your eyebrows."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_chickpea_tomato_stew', '{"id":"smoky_chickpea_tomato_stew","name":"Smoky Chickpea and Pepper Stew","emoji":"🍲","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":2},{"f":"paprika","q":6},{"f":"cumin","q":4},{"f":"oregano","q":2},{"f":"crushed_tomatoes","q":800},{"f":"chickpeas","q":700},{"f":"spinach","q":150},{"f":"lemon","q":1},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a Dutch oven over medium heat and cook the diced onion and bell peppers for 8 minutes, until the edges soften and pick up a little color.","Stir in the minced garlic, paprika, cumin, and oregano and toast for 60 seconds, until the spices smell warm and the paprika stains the oil brick red.","Pour in the crushed tomatoes with a splash of water, add the chickpeas, salt, and black pepper, and simmer uncovered for 20 minutes, until the stew thickens enough to coat a spoon.","Fold in the spinach a handful at a time and cook 2 minutes, just until it wilts glossy and dark.","Squeeze in the lemon juice off the heat, taste for salt, and ladle into bowls with a final drizzle of oil."],"tip":"Mash a spoonful of chickpeas against the pot wall if you want the stew thicker without waiting on evaporation."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_eggplant_stew', '{"id":"white_bean_eggplant_stew","name":"Braised Eggplant and White Bean Stew","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"olive_oil","q":60},{"f":"eggplant","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":600},{"f":"white_beans","q":700},{"f":"oregano","q":3},{"f":"cinnamon","q":1},{"f":"balsamic_vinegar","q":15},{"f":"parsley","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Cut the eggplant into 2-centimeter cubes, then sear it in half the olive oil in a wide pot over medium-high heat for 8 minutes, until deeply browned on at least two sides.","Push the eggplant aside, add the remaining oil, and soften the sliced onion for 5 minutes before stirring in the garlic, oregano, and cinnamon for 30 fragrant seconds.","Add the crushed tomatoes, white beans, salt, pepper, and a cup of water, then simmer partly covered for 25 minutes, until the eggplant is silky and the sauce clings to the beans.","Stir in the balsamic vinegar and let it bubble for 1 minute to mellow into a quiet sweetness.","Shower with chopped parsley and rest the stew for 5 minutes off the heat so the flavors settle before serving."],"tip":"Resist stirring the eggplant early — it only releases from the pot once it has properly browned."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_chickpea_couscous_skillet', '{"id":"lemon_chickpea_couscous_skillet","name":"Lemony Chickpea Couscous Skillet","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"chickpeas","q":350},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"cherry_tomatoes","q":150},{"f":"peas_frozen","q":100},{"f":"lemon","q":1},{"f":"scallions","q":0.5},{"f":"oregano","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a large skillet over medium heat and sizzle the sliced garlic and halved cherry tomatoes for 4 minutes, until the tomatoes blister and slump.","Add the chickpeas, peas, oregano, salt, and pepper and cook 3 minutes, shaking the pan until everything glistens.","Pour in 180 milliliters of water, bring it to a boil, then stir in the couscous, clap on a lid, and pull the pan off the heat for 5 minutes.","Fluff the couscous with a fork, working from the edges inward so the grains stay separate and light.","Finish with lemon zest and juice, sliced scallions, and a fistful of chopped parsley, tasting once more for salt."],"tip":"Zest the lemon before you juice it — nobody has ever zested a squeezed-out lemon half with dignity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_veg_hummus_quinoa_bowls', '{"id":"roasted_veg_hummus_quinoa_bowls","name":"Roasted Vegetable Hummus Quinoa Bowls","emoji":"🥣","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":40,"servings":2,"ing":[{"f":"quinoa","q":100},{"f":"hummus","q":150},{"f":"chickpeas","q":250},{"f":"zucchini","q":1},{"f":"bell_pepper","q":2},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":30},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"salt","q":5}],"steps":["Heat the oven to 220C and toss the zucchini half-moons, pepper strips, cherry tomatoes, and drained chickpeas with the olive oil, cumin, paprika, and salt on a sheet pan.","Roast for 25 minutes, stirring once halfway, until the peppers char at the tips and the chickpeas turn lightly crisp.","Meanwhile, simmer the rinsed quinoa in 250 milliliters of salted water for 15 minutes, then rest it covered for 5 minutes until the grains show their little spirals.","Swipe a thick moat of hummus around each bowl, pile in the quinoa, and top with the roasted vegetables and chickpeas.","Squeeze lemon generously over everything and scatter with chopped parsley before serving warm."],"tip":"Dry the chickpeas on a towel before roasting — wet chickpeas steam, dry chickpeas crisp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cumin_lentil_spinach_soup', '{"id":"cumin_lentil_spinach_soup","name":"Cumin-Scented Lentil and Spinach Soup","emoji":"🥄","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":320},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":100},{"f":"garlic","q":0.3},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"crushed_tomatoes","q":400},{"f":"spinach","q":200},{"f":"lemon","q":1},{"f":"salt","q":8},{"f":"black_pepper","q":2}],"steps":["Sweat the diced onion, carrots, and celery in the olive oil over medium heat for 8 minutes, until the onion turns translucent and the carrots smell sweet.","Add the garlic, cumin, and paprika and stir for 1 minute, until the spices bloom and coat the vegetables in a rusty film.","Tip in the rinsed lentils, crushed tomatoes, and 1.5 liters of water, then simmer with the lid ajar for 30 minutes, until the lentils are tender but still hold their curve.","Season with salt and pepper, then stir in the spinach and let it collapse into the broth over 2 minutes.","Brighten each bowl with a hard squeeze of lemon just before serving — it wakes the whole pot up."],"tip":"Salt lentils near the end of cooking; salting the water early makes them stubborn about softening."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_cucumber_chopped_salad', '{"id":"chickpea_cucumber_chopped_salad","name":"Chopped Chickpea and Cucumber Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"romaine","q":1},{"f":"olives","q":60},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"oregano","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Whisk the olive oil, lemon juice, oregano, salt, and pepper in the bottom of a large bowl until the dressing looks cloudy and unified.","Add the drained chickpeas and thinly sliced onion first and let them marinate for 5 minutes — they drink up the dressing better than anything else.","Chop the cucumber, tomatoes, and romaine into bite-size pieces, halve the olives, and add everything to the bowl.","Toss well, then fold in the cubed avocado gently so it stays in creamy chunks rather than smearing.","Finish with chopped parsley and one more crack of black pepper, and serve within the hour while the romaine still snaps."],"tip":"Marinating the raw onion in the dressing first tames its bite from aggressive to charming."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_white_bean_spinach_skillet', '{"id":"garlicky_white_bean_spinach_skillet","name":"Garlicky White Beans with Blistered Tomatoes and Spinach","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"white_beans","q":500},{"f":"cherry_tomatoes","q":250},{"f":"spinach","q":200},{"f":"olives","q":50},{"f":"paprika","q":2},{"f":"lemon","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a large skillet over medium-high heat and blister the whole cherry tomatoes for 5 minutes, shaking the pan until their skins split and hiss.","Lower the heat, add the sliced garlic and paprika, and cook 90 seconds, until the garlic turns pale gold at the edges — no darker.","Add the white beans with a splash of their liquid, the olives, salt, and pepper, and simmer 5 minutes, crushing a few tomatoes with your spoon to make a loose pan sauce.","Pile in the spinach and turn it through the beans until it wilts down to silky ribbons, about 2 minutes.","Squeeze the lemon over the top and serve straight from the skillet while the sauce is still bubbling at the edges."],"tip":"That starchy bean liquid you usually drain is free sauce — keep a splash and thank yourself later."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_arrabbiata_penne', '{"id":"chickpea_arrabbiata_penne","name":"Chickpea Arrabbiata Penne","emoji":"🍝","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":180},{"f":"chickpeas","q":300},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"chili_powder","q":3},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"basil","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":1}],"steps":["Drop the penne into well-salted boiling water and cook it 1 minute shy of the package time, reserving a mug of the starchy water before draining.","While the pasta cooks, warm the olive oil with the sliced garlic and chili powder in a deep skillet over medium heat until the garlic just sizzles and smells sweet, about 2 minutes.","Add the crushed tomatoes, chickpeas, and oregano and simmer for 10 minutes, until the sauce darkens and thickens enough to leave a trail behind your spoon.","Toss the drained penne into the sauce with a splash of pasta water and cook 1 more minute, stirring until every tube is glossed and coated.","Tear in the basil off the heat, season with black pepper, and serve in warm bowls immediately."],"tip":"The chili should hum in the background, not shout — you can always add heat at the table, never subtract it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_pepper_hummus_pitas', '{"id":"roasted_pepper_hummus_pitas","name":"Roasted Pepper and Hummus Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["sesame","gluten"],"time":15,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":150},{"f":"roasted_red_peppers","q":120},{"f":"cucumber","q":0.5},{"f":"romaine","q":0.3},{"f":"olives","q":40},{"f":"onion","q":0.3},{"f":"olive_oil","q":15},{"f":"lemon","q":0.5},{"f":"oregano","q":1}],"steps":["Warm the pitas in a dry skillet over medium heat for about 45 seconds per side, until soft and puffed, then halve them into pockets.","Toss the sliced roasted peppers, thin cucumber half-moons, shredded romaine, chopped olives, and slivered onion with the olive oil, lemon juice, and oregano until everything glistens.","Spread a thick layer of hummus inside each pita half, pushing it right into the corners so every bite gets some.","Stuff the pockets generously with the dressed vegetables, pressing gently so they hold together.","Serve immediately, standing over the counter like a person who has made excellent choices."],"tip":"Hummus is the glue here — spread it on both inner walls of the pita and nothing escapes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('artichoke_olive_couscous_salad', '{"id":"artichoke_olive_couscous_salad","name":"Artichoke, Olive, and White Bean Couscous Salad","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"white_beans","q":300},{"f":"artichoke_hearts","q":150},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":150},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"parsley","q":1},{"f":"oregano","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Pour 170 milliliters of boiling salted water over the couscous in a wide bowl, cover with a plate, and leave it for 5 minutes before raking it fluffy with a fork.","Whisk the olive oil, lemon zest and juice, oregano, salt, and pepper into a sharp little dressing.","Quarter the artichoke hearts, halve the olives and cherry tomatoes, and dice the cucumber into small, crunchy cubes.","Fold the vegetables, white beans, and most of the chopped parsley through the warm couscous with the dressing — warm grains absorb vinaigrette far better than cold ones.","Rest the salad for 10 minutes, taste for lemon and salt, and top with the last of the parsley before serving at room temperature."],"tip":"This salad is better after an hour in the fridge, which makes it the rare dish that rewards procrastination."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spiced_cauliflower_hummus_plate', '{"id":"spiced_cauliflower_hummus_plate","name":"Spiced Roasted Cauliflower over Hummus","emoji":"🥦","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["sesame","gluten"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":0.8},{"f":"chickpeas","q":200},{"f":"hummus","q":200},{"f":"olive_oil","q":40},{"f":"paprika","q":4},{"f":"cumin","q":4},{"f":"turmeric","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"pita","q":2},{"f":"salt","q":5}],"steps":["Heat the oven to 220C and cut the cauliflower into thick florets with plenty of flat sides for browning.","Toss the florets and drained chickpeas with the olive oil, paprika, cumin, turmeric, and salt until every piece wears a golden-orange coat.","Roast on a sheet pan for 28 to 30 minutes, flipping once, until the cauliflower edges are deeply caramelized and the chickpeas rattle when you shake the pan.","Spread the hummus in a thick swoosh across two plates and pile the hot cauliflower and chickpeas on top so the hummus softens slightly under the heat.","Shower with lemon juice and chopped parsley, and serve with pitas warmed directly over a burner flame until lightly charred."],"tip":"Crowded cauliflower steams instead of browning — give the florets personal space on the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('couscous_stuffed_bell_peppers', '{"id":"couscous_stuffed_bell_peppers","name":"Couscous and Chickpea Stuffed Peppers","emoji":"🫑","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"couscous","q":100},{"f":"chickpeas","q":250},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":30},{"f":"cumin","q":3},{"f":"cinnamon","q":1},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"salt","q":5}],"steps":["Heat the oven to 200C, halve the peppers through the stem, and pull out the seeds and ribs to make eight neat boats.","Soften the diced onion in the olive oil over medium heat for 5 minutes, then stir in the garlic, cumin, and cinnamon until fragrant, about 30 seconds.","Add the chickpeas, quartered cherry tomatoes, chopped olives, salt, and 130 milliliters of water; when it boils, stir in the couscous, cover, and rest off the heat for 5 minutes.","Fluff the filling, brighten it with lemon juice and half the parsley, and mound it into the pepper halves.","Bake in a covered dish for 25 minutes, then uncover for 5 more, until the peppers slump tender and the tops toast lightly; finish with the remaining parsley."],"tip":"A pinch of cinnamon in savory filling is the oldest Mediterranean trick in the book — nobody will name it, everybody will notice it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_lentil_walnut_salad', '{"id":"mediterranean_lentil_walnut_salad","name":"Warm Lentil and Walnut Salad","emoji":"🌿","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["nuts"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"walnuts","q":40},{"f":"cucumber","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"onion","q":0.3},{"f":"parsley","q":1},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"balsamic_vinegar","q":15},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Simmer the rinsed lentils in plenty of unsalted water for 20 to 22 minutes, until tender with just a whisper of chew, then drain well.","While they cook, toast the walnuts in a dry skillet over medium heat for 4 minutes, tossing until they smell rich and darken a shade, then chop roughly.","Whisk the olive oil, lemon juice, balsamic vinegar, oregano, salt, and pepper into a punchy dressing at the bottom of a serving bowl.","Tip the warm lentils straight into the dressing with the slivered onion and toss — the heat draws the vinaigrette deep into every lentil.","Fold in the diced cucumber, halved cherry tomatoes, walnuts, and a big handful of chopped parsley, and serve warm or at room temperature."],"tip":"Dress lentils while they are hot; a cold lentil is polite but a warm one is a sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_arrabbiata_toasted_walnuts', '{"id":"spaghetti_arrabbiata_toasted_walnuts","name":"Spaghetti all''Arrabbiata with Toasted Walnut Crumble","emoji":"🍝","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"crushed_tomatoes","q":400},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"walnuts","q":40},{"f":"chili_powder","q":2},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"sugar","q":3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes until they smell rich and nutty, then chop them fine with a pinch of salt to make your crumble.","Warm the olive oil in the same skillet over medium-low, add the thinly sliced garlic and chili powder, and cook for about 90 seconds until the garlic turns pale gold at the edges — not brown.","Pour in the crushed tomatoes with the oregano, sugar, and salt, then simmer briskly for 12 minutes until the sauce darkens a shade and thickens enough to hold a line when you drag a spoon through it.","Meanwhile, boil the spaghetti in generously salted water until just shy of al dente, about 1 minute less than the package says, and reserve a cup of the starchy cooking water.","Transfer the pasta straight into the sauce with a splash of pasta water and toss over high heat for a full minute until every strand is glossy and coated.","Plate in warm bowls, shower with the walnut crumble, torn basil, and black pepper, and serve immediately while it still steams."],"tip":"The walnut crumble is doing parmesan''s old job, so do not skimp — toast it properly or it is just sad sawdust."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ribollita_tuscan_bread_soup', '{"id":"ribollita_tuscan_bread_soup","name":"Ribollita-Style Tuscan Bread and Bean Soup","emoji":"🍲","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":50,"servings":4,"ing":[{"f":"white_beans","q":600},{"f":"kale","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"bread","q":4},{"f":"olive_oil","q":60},{"f":"oregano","q":3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Heat half the olive oil in a heavy pot over medium and sweat the diced onion, carrots, and celery with a pinch of salt for 8 to 10 minutes until soft and sweet-smelling.","Stir in the chopped garlic and oregano and cook for 1 minute, then add the crushed tomatoes and let them sizzle and reduce for 5 minutes until brick red.","Add the white beans, the stripped and torn kale leaves, and 1.2 liters of water, then simmer gently for 20 minutes, mashing a ladleful of beans against the pot wall to thicken the broth.","Tear the bread into rough chunks, stir it into the pot, and simmer 5 more minutes until the soup turns thick and spoonable, somewhere between soup and stew.","Season boldly with salt and black pepper, ladle into bowls, and finish each with a slow ribbon of the remaining olive oil."],"tip":"Ribollita means reboiled — this soup is genuinely better tomorrow, so make it tonight and thank yourself at lunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_chili_chickpea_broccoli_penne', '{"id":"lemon_chili_chickpea_broccoli_penne","name":"Lemon-Chili Penne with Chickpeas and Broccoli","emoji":"🥦","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"chickpeas","q":240},{"f":"broccoli","q":300},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"lemon","q":1},{"f":"chili_powder","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Drop the penne into well-salted boiling water, and 4 minutes before it is done, add the broccoli florets to the same pot so they turn bright green and just tender.","While the pasta cooks, warm the olive oil in a wide skillet over medium heat and fry the drained chickpeas for 5 to 6 minutes until they blister and pop at the edges.","Add the sliced garlic and chili powder to the chickpeas and cook 1 minute more, just until the garlic is fragrant and barely golden.","Scoop the pasta and broccoli into the skillet with a half cup of cooking water and toss hard over high heat until the broccoli breaks down slightly and clings to the penne like a rough sauce.","Kill the heat, squeeze in the lemon juice, add a shower of chopped parsley and black pepper, taste for salt, and serve straight from the pan."],"tip":"Overcooking the broccoli here is not a crime — the soft florets are what turn into your sauce, so relax."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_lentil_sunday_ragu', '{"id":"spaghetti_lentil_sunday_ragu","name":"Slow-Simmered Lentil Sunday Ragu with Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"spaghetti","q":320},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":80},{"f":"garlic","q":0.5},{"f":"olive_oil","q":60},{"f":"oregano","q":3},{"f":"basil","q":0.5},{"f":"balsamic_vinegar","q":15},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Finely dice the onion, carrots, and celery and cook them in the olive oil over medium heat for a patient 10 minutes, until deeply softened and starting to catch gold at the edges — this soffritto is the soul of the ragu.","Stir in the minced garlic and oregano for 1 minute, then add the rinsed lentils, crushed tomatoes, and 800 ml of water and bring to a lazy simmer.","Cook uncovered for 30 to 35 minutes, stirring now and then, until the lentils are tender and the sauce has thickened to a proper meaty-looking ragu that mounds on a spoon.","Season with salt, black pepper, and the balsamic vinegar, which sharpens the tomatoes the way a splash of wine would.","Boil the spaghetti in salted water until al dente, then toss it with the ragu and a splash of pasta water until every strand is dressed.","Serve in wide bowls topped with torn basil and a final thread of olive oil."],"tip":"If the ragu looks done at 20 minutes, it is lying — give the lentils the full simmer or they will crunch back."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pasta_e_ceci_roman_style', '{"id":"pasta_e_ceci_roman_style","name":"Roman-Style Pasta e Ceci","emoji":"🥣","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":4,"ing":[{"f":"chickpeas","q":480},{"f":"penne","q":200},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"celery","q":60},{"f":"olive_oil","q":60},{"f":"oregano","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Soften the diced onion and celery in half the olive oil over medium heat for 6 to 7 minutes, then add the minced garlic and oregano and cook until the kitchen smells like a trattoria, about 1 minute.","Add the chickpeas and crushed tomatoes, then mash roughly a third of the chickpeas right in the pot with the back of a wooden spoon to give the broth body.","Pour in 1 liter of water, bring to a boil, and simmer for 10 minutes so the flavors knit together.","Add the penne directly to the pot and cook at a steady bubble for 11 to 12 minutes, stirring often so nothing sticks, until the pasta is tender and the broth has gone silky and starch-thickened.","Rest the pot off the heat for 5 minutes — it will thicken further — then season with salt and pepper and serve with chopped parsley and the remaining oil drizzled over each bowl."],"tip":"Cooking the pasta in the soup is non-negotiable; that starch is free thickener and Roman grandmothers do not waste free things."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_norma_penne_white_beans', '{"id":"eggplant_norma_penne_white_beans","name":"Penne alla Norma with Eggplant and White Beans","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"penne","q":160},{"f":"crushed_tomatoes","q":400},{"f":"white_beans","q":200},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"basil","q":0.5},{"f":"walnuts","q":20},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Cut the eggplant into 2 cm cubes, salt them, and let them sit 10 minutes while the oven heats to 220C, then roast on an oiled sheet pan for 20 to 25 minutes until bronzed and creamy inside.","Meanwhile, warm the remaining olive oil in a skillet, sizzle the sliced garlic for a minute, and add the crushed tomatoes to simmer for 12 minutes until thick and sweet.","Fold the white beans into the sauce to warm through — they stand in for the richness the traditional ricotta salata would bring.","Cook the penne in salted boiling water until al dente and toss it into the sauce with a splash of pasta water and the roasted eggplant, folding gently so the eggplant stays in soft, jammy pieces.","Finish with torn basil, black pepper, and a scatter of finely chopped toasted walnuts over each bowl."],"tip":"Crowded eggplant steams and sulks — give the cubes real space on the sheet pan and they will reward you with bronze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_pea_olive_oil_risotto', '{"id":"mushroom_pea_olive_oil_risotto","name":"Mushroom and Sweet Pea Olive Oil Risotto","emoji":"🍚","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"rice","q":200},{"f":"mushrooms","q":300},{"f":"peas_frozen","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Sear the sliced mushrooms in a third of the olive oil over high heat for 6 to 8 minutes, without stirring too much, until deeply browned and squeaky-crisp at the edges, then set aside.","In the same pot, soften the finely diced onion in another third of the oil over medium heat for 5 minutes, add the minced garlic, then stir in the rice and toast it for 2 minutes until the grains turn translucent at the edges and click against the spoon.","Keep 1 liter of water at a bare simmer beside you and add it a ladle at a time, stirring often and waiting until each addition is nearly absorbed, about 20 minutes total.","When the rice is tender with just a whisper of bite, stir in the peas and seared mushrooms and cook 2 minutes more until the peas pop bright green.","Pull the pot off the heat and beat in the last of the olive oil vigorously — this is the mantecatura, and it makes the risotto wave and ripple instead of standing stiff.","Season with lemon juice, salt, and black pepper, and serve immediately with chopped parsley on top."],"tip":"Risotto waits for no one; call everyone to the table before you stir in that final glug of oil."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('umbrian_lentil_kale_stew', '{"id":"umbrian_lentil_kale_stew","name":"Umbrian Lentil and Kale Stew","emoji":"🥬","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"kale","q":1},{"f":"potatoes","q":300},{"f":"carrots","q":200},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"lemon","q":1},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a large pot over medium heat and cook the diced onion, carrots, and celery for 8 minutes until soft and golden, then add the minced garlic and oregano for a fragrant final minute.","Stir in the rinsed lentils, the crushed tomatoes, the potatoes cut into small cubes, and 1.4 liters of water, then bring everything to a boil.","Lower to a gentle simmer and cook for 30 minutes, until the lentils are tender and the potatoes are creamy enough to crush against the side of the pot.","Strip the kale from its stems, tear it into pieces, and stir it in for the last 5 minutes until it wilts silky but stays deep green.","Season with salt and black pepper, brighten each bowl with a good squeeze of lemon, and finish with a thread of olive oil."],"tip":"The lemon at the end is not decoration — lentils without acid taste like a rainy Tuesday, so squeeze with conviction."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_bruschetta', '{"id":"tuscan_white_bean_bruschetta","name":"Tuscan White Bean Bruschetta with Blistered Tomatoes","emoji":"🍞","cuisine":"Italian","meal":["lunch","breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"bread","q":4},{"f":"white_beans","q":300},{"f":"cherry_tomatoes","q":200},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"basil","q":0.3},{"f":"balsamic_vinegar","q":15},{"f":"lemon","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toss the cherry tomatoes with a spoonful of olive oil and roast them in a hot skillet over medium-high for 5 to 6 minutes until their skins split and they slump into jammy little bombs.","Warm the white beans in a small pan with half the remaining olive oil, one minced garlic clove, and a splash of water, then mash them roughly with a fork into a rustic, spreadable smash seasoned with lemon juice and salt.","Toast the bread until deeply golden and crisp at the edges, then rub each hot slice firmly with the cut side of a raw garlic clove — you should hear it rasp.","Pile the warm bean smash onto the toasts and crown with the blistered tomatoes and any juices from the pan.","Finish with torn basil, a drizzle of balsamic and the last of the olive oil, and a confident grind of black pepper."],"tip":"The garlic-on-toast rub is the whole personality of this dish — if your knuckles do not smell like Sunday in Florence, rub harder."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_chickpea_chopped_salad', '{"id":"italian_chickpea_chopped_salad","name":"Italian Chopped Salad with Chickpeas and Walnuts","emoji":"🥗","cuisine":"Italian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":20,"servings":2,"ing":[{"f":"romaine","q":1},{"f":"chickpeas","q":300},{"f":"cherry_tomatoes","q":200},{"f":"cucumber","q":0.5},{"f":"olives","q":60},{"f":"roasted_red_peppers","q":80},{"f":"onion","q":0.3},{"f":"walnuts","q":30},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":20},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Whisk the olive oil, balsamic vinegar, oregano, salt, and black pepper in the bottom of your biggest bowl until the dressing looks cloudy and unified.","Add the thinly sliced onion straight into the dressing and let it sit 5 minutes — the vinegar tames its bite while you chop everything else.","Chop the romaine into ribbons, halve the cherry tomatoes, dice the cucumber, slice the olives, and cut the roasted red peppers into strips, adding each to the bowl as you go.","Add the drained chickpeas and toss everything thoroughly for a solid 30 seconds so the dressing reaches every corner.","Top with roughly chopped toasted walnuts and serve within 10 minutes, while the romaine still snaps."],"tip":"Dress this salad right before eating, not before your commute — romaine forgives many things but never a soggy hour."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_lentil_stuffed_peppers', '{"id":"tuscan_lentil_stuffed_peppers","name":"Tuscan Lentil and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"bell_pepper","q":4},{"f":"lentils_dry","q":150},{"f":"rice","q":120},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Simmer the lentils and rice together in salted water for about 18 minutes until both are just tender, then drain well — the filling should be moist, not swampy.","While they cook, soften the diced onion in the olive oil over medium heat for 6 minutes, add the minced garlic and oregano, then stir in half the crushed tomatoes and simmer 5 minutes into a thick sauce.","Fold the lentil-rice mixture into the skillet sauce, season assertively with salt and black pepper, and taste — the filling must be delicious on its own.","Halve the bell peppers through the stem, pull out the seeds, and nestle them cut side up in a baking dish with the remaining crushed tomatoes and a splash of water poured around them.","Pack the peppers generously with filling, cover the dish with foil, and bake at 200C for 30 minutes, then uncover for 10 more until the pepper edges char slightly and the tops crust over.","Rest 5 minutes, then serve the peppers over spoonfuls of the pan sauce with torn basil."],"tip":"Season the filling until it tastes almost too bold in the pan — a bland stuffed pepper is just a vegetable with regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peperonata_chickpea_skillet', '{"id":"peperonata_chickpea_skillet","name":"Peperonata Chickpea Skillet with Olives","emoji":"🫒","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"chickpeas","q":300},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olives","q":40},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":15},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Slice the bell peppers and onion into thick strips and cook them in the olive oil over medium heat for a full 15 minutes, stirring occasionally, until they collapse into soft, sweet ribbons with browned edges.","Add the minced garlic and oregano and cook 1 minute, then stir in the chopped tomatoes and simmer 5 minutes until they break down and glaze the peppers.","Fold in the drained chickpeas and sliced olives and cook 5 more minutes so the chickpeas drink up the pan juices.","Splash in the balsamic vinegar and let it bubble for 30 seconds, scraping up any sticky brown bits from the bottom of the skillet.","Season with salt and black pepper, scatter with torn basil, and serve warm — or at room temperature, the way Nonna would insist tastes better anyway."],"tip":"Peperonata rewards patience — rush the peppers and you get stir-fry, wait fifteen minutes and you get silk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pappa_al_pomodoro', '{"id":"pappa_al_pomodoro","name":"Pappa al Pomodoro — Tuscan Tomato Bread Soup","emoji":"🍅","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":4,"ing":[{"f":"crushed_tomatoes","q":800},{"f":"bread","q":6},{"f":"garlic","q":0.4},{"f":"onion","q":1},{"f":"olive_oil","q":90},{"f":"basil","q":1},{"f":"sugar","q":5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Tear the bread into rough chunks and toast the pieces on a sheet pan at 180C for 8 minutes until dry and lightly golden — stale-firm bread is the backbone of this soup.","Warm half the olive oil in a heavy pot over medium-low and cook the finely diced onion and sliced garlic gently for 6 to 7 minutes, until soft and sweet but without color.","Add the crushed tomatoes, sugar, salt, and 600 ml of water, then simmer for 10 minutes until the raw tomato edge cooks off and the sauce tastes round.","Stir in the toasted bread and half the basil leaves and simmer another 10 minutes, whisking occasionally, until the bread dissolves into a thick, porridge-like soup that plops rather than pours.","Rest off the heat for 5 minutes, then serve in shallow bowls with the remaining basil torn over, plenty of black pepper, and a generous, glistening pour of the remaining olive oil on each."],"tip":"This soup is a delivery vehicle for olive oil — pour like you mean it, because that finishing glug is the entire third act."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_soup', '{"id":"coconut_red_lentil_soup","name":"Coconut Red Lentil Soup","emoji":"🍲","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"coconut_milk","q":400},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"carrots","q":150},{"f":"crushed_tomatoes","q":200},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"spinach","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":6}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion with a pinch of salt for 6 to 8 minutes, until soft and golden at the edges.","Stir in the minced garlic, grated ginger, curry powder, turmeric, and cumin and toast for 60 seconds, until the spices smell warm and the bottom of the pot looks lightly stained.","Add the rinsed lentils, diced carrots, crushed tomatoes, and 1.2 liters of water, then bring to a boil and simmer uncovered for 22 to 25 minutes, until the lentils collapse into a rough puree.","Pour in the coconut milk and simmer 5 more minutes, stirring so nothing catches; the soup should coat a spoon like thin porridge.","Take the pot off the heat, wilt in the spinach, and season with salt and a big squeeze of lime until the flavors pop.","Ladle into bowls and shower generously with chopped cilantro."],"tip":"Red-style lentil soups thicken overnight into near-hummus, so keep a splash of water handy when reheating leftovers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_lentil_walnut_chili', '{"id":"smoky_lentil_walnut_chili","name":"Smoky Lentil Walnut Chili","emoji":"🌶️","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"walnuts","q":80},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"corn_frozen","q":150},{"f":"chili_powder","q":12},{"f":"cumin","q":6},{"f":"paprika","q":6},{"f":"oregano","q":2},{"f":"maple_syrup","q":15},{"f":"salt","q":6}],"steps":["Pulse the walnuts in a food processor until they look like coarse crumbs, then heat the olive oil in a Dutch oven over medium and cook the chopped onion and bell peppers for 7 minutes, until slumped and sweet-smelling.","Add the garlic, chili powder, cumin, paprika, and oregano and stir for a minute, until the spices bloom and darken slightly.","Tip in the walnuts, rinsed lentils, crushed tomatoes, and 1 liter of water, scraping up any spiced bits stuck to the bottom.","Bring to a boil, then drop to a lazy simmer and cook uncovered for 30 to 35 minutes, stirring occasionally, until the lentils are tender and the chili is thick enough to mound on a spoon.","Stir in the corn and maple syrup, simmer 5 minutes more, and season assertively with salt until the smoky-sweet balance sings.","Rest the chili off the heat for 10 minutes before serving; it tastes noticeably rounder for the wait."],"tip":"The walnuts are your ground-beef impersonators, so do not grind them to dust unless you enjoy chili-flavored sludge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_noodle_soup', '{"id":"chickpea_noodle_soup","name":"Chickpea Noodle Soup","emoji":"🍜","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":4,"ing":[{"f":"chickpeas","q":400},{"f":"spaghetti","q":250},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"garlic","q":0.3},{"f":"peas_frozen","q":100},{"f":"oregano","q":2},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in a soup pot over medium heat and sweat the diced onion, carrots, and celery with a pinch of salt for 8 to 10 minutes, until the onion turns translucent and the pot smells like the start of something good.","Add the minced garlic and oregano and cook for 1 minute, just until fragrant.","Pour in 1.5 liters of water, add the drained chickpeas, and bring everything to a rolling boil.","Snap the spaghetti into thirds, drop it in, and simmer for 9 to 11 minutes, stirring now and then, until the noodles are tender but still have a slight chew.","Stir in the peas, simmer 2 minutes, then finish with the juice of the lemon, plenty of black pepper, and salt to taste.","Serve in deep bowls topped with a handful of chopped parsley."],"tip":"The noodles keep drinking broth as they sit, so if you are meal-prepping, cook them separately and marry them bowl by bowl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_masala_chickpea_stew', '{"id":"chana_masala_chickpea_stew","name":"Chana Masala Chickpea Stew","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"chickpeas","q":500},{"f":"rice","q":250},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":2},{"f":"garlic","q":0.5},{"f":"ginger","q":20},{"f":"olive_oil","q":45},{"f":"garam_masala","q":8},{"f":"cumin","q":5},{"f":"turmeric","q":3},{"f":"chili_powder","q":4},{"f":"lemon","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":6}],"steps":["Start the rice simmering in 500 ml of salted water, covered, for 15 minutes, then let it rest off the heat while you build the stew.","Heat the olive oil in a wide pot over medium-high and fry the finely chopped onions for 10 to 12 minutes, stirring often, until deeply golden brown; this color is the backbone of the dish, so do not rush it.","Add the minced garlic and grated ginger, cook for 1 minute, then stir in the cumin, turmeric, chili powder, and half the garam masala and toast until the paste smells rich and slightly nutty.","Pour in the crushed tomatoes and cook for 5 minutes, until the sauce darkens and the oil begins to bead at the edges.","Add the drained chickpeas and 300 ml of water, simmer uncovered for 15 minutes while mashing a few chickpeas against the side of the pot to thicken the gravy.","Finish with the remaining garam masala, a hard squeeze of lemon, and salt, then serve over the rice with a flurry of cilantro."],"tip":"Mashing a ladleful of chickpeas is the lazy cook''s thickener; nobody will suspect you skipped the hours of simmering."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cumin_lime_black_bean_soup', '{"id":"cumin_lime_black_bean_soup","name":"Cumin-Lime Black Bean Soup","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"black_beans","q":750},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"cumin","q":8},{"f":"chili_powder","q":6},{"f":"oregano","q":2},{"f":"crushed_tomatoes","q":200},{"f":"salsa","q":120},{"f":"lime","q":2},{"f":"avocado","q":2},{"f":"cilantro","q":0.5},{"f":"salt","q":5}],"steps":["Heat the olive oil in a soup pot over medium and cook the diced onion and bell pepper for 6 to 8 minutes, until soft and starting to catch color at the edges.","Stir in the garlic, cumin, chili powder, and oregano and toast for 1 minute, until the kitchen smells like a taqueria.","Add the black beans with their liquid, the crushed tomatoes, salsa, and 500 ml of water, then simmer for 15 minutes so the flavors knit together.","Blend about half the soup with an immersion blender, leaving plenty of whole beans, until it is creamy but still rugged in texture.","Season with salt and the juice of both limes, tasting until the soup is bright rather than flat.","Serve topped with diced avocado and torn cilantro."],"tip":"Lime juice added at the end does the work of an hour of extra simmering; lime juice boiled for an hour does nothing but sulk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_vegan_minestrone', '{"id":"hearty_vegan_minestrone","name":"Hearty Vegan Minestrone","emoji":"🥕","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":4,"ing":[{"f":"white_beans","q":500},{"f":"penne","q":200},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"zucchini","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"spinach","q":100},{"f":"basil","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a large pot over medium heat and cook the diced onion, carrots, and celery with a pinch of salt for 10 minutes, until the vegetables are soft and the bottom of the pot glistens.","Add the garlic and oregano and stir for 1 minute, then pour in the crushed tomatoes and 1.5 liters of water and bring to a boil.","Add the diced zucchini and the drained white beans and simmer gently for 10 minutes, until the zucchini turns tender but not mushy.","Stir in the penne and cook at a steady bubble for 10 to 12 minutes, stirring occasionally so the pasta does not glue itself to the bottom, until al dente.","Kill the heat, fold in the spinach and torn basil leaves, and let them wilt into the broth for 2 minutes.","Season boldly with salt and black pepper and serve with an extra thread of olive oil over each bowl."],"tip":"Minestrone is a fridge-cleaning philosophy, not a recipe, so swap in any tired vegetable that needs a dignified exit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_ribollita_bread_stew', '{"id":"tuscan_ribollita_bread_stew","name":"Tuscan Ribollita Bread Stew","emoji":"🍞","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"white_beans","q":500},{"f":"bread","q":6},{"f":"kale","q":1},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Heat half the olive oil in a Dutch oven over medium and cook the chopped onion, carrots, and celery for 10 minutes, until soft, sweet, and lightly golden.","Stir in the garlic and oregano for 1 minute, then add the crushed tomatoes and cook 5 minutes, until the mixture thickens and smells jammy.","Add the drained white beans, the stripped and chopped kale, and 1.2 liters of water, then simmer for 20 minutes, until the kale is completely tender and the broth tastes savory.","Tear the bread into rough chunks, stir it into the pot, and simmer 10 more minutes, mashing gently, until the stew is thick enough that a spoon stands up and thinks about it.","Season generously with salt and black pepper, then rest off the heat for 10 minutes so the bread drinks its fill.","Serve in shallow bowls with the remaining olive oil poured over the top in a slow, self-satisfied ribbon."],"tip":"Staler bread makes better ribollita, which is the only known situation where forgetting about your groceries counts as technique."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_tofu_soup', '{"id":"coconut_lime_tofu_soup","name":"Coconut-Lime Tofu Soup","emoji":"🥥","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy"],"time":35,"servings":4,"ing":[{"f":"tofu","q":400},{"f":"coconut_milk","q":800},{"f":"rice_noodles","q":150},{"f":"mushrooms","q":250},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":6},{"f":"sugar","q":8}],"steps":["Soak the rice noodles in hot tap water for 10 minutes while you cook, until pliable but not fully soft.","Heat the olive oil in a pot over medium, add the sliced mushrooms, and cook for 5 to 6 minutes, until they release their liquid and start to brown at the edges.","Add the sliced ginger and smashed garlic, stir for 30 seconds, then pour in the coconut milk and 600 ml of water and bring to a bare simmer; do not let it boil hard or the coconut milk will look curdled and sad.","Slide in the cubed tofu with the salt and sugar and poach gently for 8 minutes so the tofu warms through and soaks up the broth.","Drain the noodles, divide them among four bowls, and ladle the hot soup over the top.","Finish each bowl with a hard squeeze of lime, sliced scallions, and a tangle of cilantro; the broth should taste creamy, salty, and bracingly tart all at once."],"tip":"Treat the lime like seasoning and add it off the heat, because boiled lime juice turns from perfume into bitterness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_peanut_sweet_potato_stew', '{"id":"gingery_peanut_sweet_potato_stew","name":"Gingery Peanut Sweet Potato Stew","emoji":"🥜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"peanut_butter","q":150},{"f":"sweet_potatoes","q":700},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":25},{"f":"spinach","q":150},{"f":"olive_oil","q":30},{"f":"cumin","q":4},{"f":"chili_powder","q":4},{"f":"lime","q":1},{"f":"scallions","q":0.5},{"f":"salt","q":6}],"steps":["Heat the olive oil in a heavy pot over medium and cook the diced onion for 6 minutes, until translucent and just starting to gild.","Add the minced garlic, grated ginger, cumin, and chili powder and stir for 1 minute, until the ginger smell fills the kitchen.","Add the peeled, 2-centimeter chunks of sweet potato, the crushed tomatoes, and 900 ml of water, then bring to a boil and simmer for 15 minutes.","Whisk the peanut butter with a ladle of hot broth in a bowl until smooth, stir it back into the pot, and simmer 10 more minutes, until the sweet potatoes yield to a fork and the stew turns glossy and thick.","Fold in the spinach off the heat and let it wilt, then season with salt and the juice of the lime until the richness has a bright edge.","Serve topped with sliced scallions and an optional extra pinch of chili powder for the brave."],"tip":"Tempering the peanut butter with hot broth first spares you from chasing stubborn peanut icebergs around the pot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_corn_potato_chowder', '{"id":"golden_corn_potato_chowder","name":"Golden Corn and Potato Chowder","emoji":"🌽","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"corn_frozen","q":500},{"f":"potatoes","q":500},{"f":"coconut_milk","q":400},{"f":"cashews","q":60},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"paprika","q":4},{"f":"scallions","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Cover the cashews with boiling water and let them soak while you cook; they need about 20 minutes to soften for blending.","Heat the olive oil in a soup pot over medium and cook the diced onion and celery for 7 minutes, until soft, then add the garlic and paprika and stir for 1 minute.","Add the diced potatoes and 800 ml of water, bring to a boil, and simmer for 12 minutes, until a knife slides through a potato cube without protest.","Blend the drained cashews with the coconut milk until completely smooth, pour into the pot with the corn, and simmer 5 minutes more.","Puree about a third of the chowder and stir it back in, so it is creamy but still full of sweet corn pop and potato chunks.","Season with salt and black pepper and serve scattered with sliced scallions."],"tip":"A cheap blender needs a full five minutes to make cashew cream truly smooth, so let it run while you pretend to tidy up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_artichoke_potato_stew', '{"id":"mediterranean_artichoke_potato_stew","name":"Mediterranean Artichoke and Potato Stew","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"potatoes","q":700},{"f":"artichoke_hearts","q":300},{"f":"olives","q":100},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"oregano","q":4},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a wide pot over medium heat and cook the sliced onion for 8 minutes, until silky and pale gold.","Add the sliced garlic and oregano and stir for 1 minute, until fragrant but not browned.","Add the potatoes cut into 3-centimeter chunks, the crushed tomatoes, and 600 ml of water, then simmer covered for 18 to 20 minutes, until the potatoes are just tender at the tip of a knife.","Stir in the halved artichoke hearts and olives and simmer uncovered for 8 minutes, letting the sauce reduce until it clings to the potatoes.","Season with salt and plenty of black pepper, then brighten with the juice of the lemon; the stew should taste rich, briny, and sunny all at once.","Rest for 5 minutes off the heat and serve strewn with chopped parsley."],"tip":"The olives and artichokes bring their own salt to the party, so taste before you season or you will out-brine the sea."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_mushroom_rice_soup', '{"id":"creamy_mushroom_rice_soup","name":"Creamy Mushroom and Rice Soup","emoji":"🍄","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"mushrooms","q":500},{"f":"rice","q":200},{"f":"cashews","q":80},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"carrots","q":150},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"parsley","q":0.5},{"f":"salt","q":6},{"f":"black_pepper","q":3}],"steps":["Soak the cashews in boiling water and set them aside; meanwhile heat the olive oil in a large pot over medium-high.","Add the sliced mushrooms in a single layer and leave them alone for 4 minutes before stirring, so they sear golden instead of steaming gray, then cook 4 more minutes until browned and squeaky-tender.","Lower the heat to medium, add the diced onion, celery, and carrots, and cook for 6 minutes, then stir in the garlic for a final fragrant minute.","Add the rinsed rice and 1.4 liters of water, bring to a boil, and simmer covered for 18 to 20 minutes, until the rice is plump and the broth has turned savory and slightly silky.","Blend the drained cashews with 200 ml of the hot broth until pourable cream forms, then stir it into the soup and warm through for 3 minutes without boiling.","Season with salt and an aggressive amount of black pepper and serve topped with chopped parsley."],"tip":"Crowded mushrooms steam and sulk, so give them space in the pot even if it means browning in two batches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_vegetable_tofu_stew', '{"id":"coconut_curry_vegetable_tofu_stew","name":"Coconut Curry Vegetable and Tofu Stew","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy"],"time":50,"servings":4,"ing":[{"f":"tofu","q":350},{"f":"coconut_milk","q":400},{"f":"rice","q":200},{"f":"eggplant","q":1},{"f":"green_beans","q":200},{"f":"bell_pepper","q":2},{"f":"curry_powder","q":10},{"f":"ginger","q":20},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"maple_syrup","q":10},{"f":"lime","q":1},{"f":"basil","q":0.5},{"f":"salt","q":6}],"steps":["Simmer the rice in 400 ml of salted water, covered, for 15 minutes, then rest it off the heat with the lid on.","Pat the tofu dry, cut it into 2-centimeter cubes, and sear in the olive oil in a wide pot over medium-high for 6 to 8 minutes, turning until golden on most sides, then set aside on a plate.","In the same pot, cook the grated ginger, minced garlic, and curry powder for 1 minute, until the spices smell toasty, then add the coconut milk and 300 ml of water, scraping up the browned tofu bits.","Add the eggplant in bite-size chunks and the sliced bell peppers and simmer for 10 minutes, until the eggplant turns translucent and custardy.","Return the tofu with the trimmed green beans and simmer 6 to 8 minutes more, until the beans are crisp-tender and the sauce coats a spoon.","Season with salt, maple syrup, and lime juice, tear in the basil, and serve ladled over the rice."],"tip":"A dry-as-possible tofu block browns like a champion, so press it while you chop and thank yourself at dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_walnut_maple_oatmeal', '{"id":"banana_walnut_maple_oatmeal","name":"Creamy Banana Walnut Oatmeal","emoji":"🍌","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":15,"servings":2,"ing":[{"f":"oats","q":100},{"f":"coconut_milk","q":150},{"f":"banana","q":2},{"f":"walnuts","q":40},{"f":"maple_syrup","q":45},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Toast the oats in a dry saucepan over medium heat for 2 to 3 minutes, stirring until they smell nutty and faintly sweet.","Pour in the coconut milk plus 350 ml of water, add the salt, and bring to a gentle simmer, stirring every minute or so.","Mash one banana right into the pot and cook 5 to 6 minutes more, until the oats are thick enough that a spoon dragged through leaves a slow-closing trail.","Meanwhile, toast the walnuts in a small skillet over medium heat for 3 minutes until fragrant, then roughly chop them.","Stir the cinnamon and half the maple syrup into the oats, then divide between two bowls.","Top with the second banana in coins, the warm walnuts, and the remaining maple syrup drizzled in ribbons."],"tip":"Mashing the ripest banana into the pot sweetens the whole batch, so save your prettiest one for the top."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_banana_baked_oatmeal', '{"id":"berry_banana_baked_oatmeal","name":"Berry Banana Baked Oatmeal","emoji":"🫐","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":2,"ing":[{"f":"oats","q":120},{"f":"banana","q":2},{"f":"berries","q":150},{"f":"coconut_milk","q":200},{"f":"maple_syrup","q":60},{"f":"walnuts","q":30},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Heat the oven to 190°C and lightly oil a small baking dish, about 20 by 15 centimeters.","Mash both bananas in a mixing bowl until nearly smooth, then whisk in the coconut milk, maple syrup, cinnamon, and salt.","Fold in the oats and two-thirds of the berries, pour the mixture into the dish, and scatter the remaining berries and the walnuts over the top.","Bake for 30 to 35 minutes, until the edges pull away slightly and the center springs back when pressed.","Let it rest 5 minutes so the oats finish setting, then scoop into bowls while the berries are still bubbling and jammy."],"tip":"The rest is not optional — cut it hot and you get porridge with commitment issues instead of clean squares."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_bread_overnight_oats', '{"id":"banana_bread_overnight_oats","name":"Banana Bread Overnight Oats","emoji":"🥣","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"oats","q":100},{"f":"coconut_milk","q":250},{"f":"banana","q":2},{"f":"walnuts","q":30},{"f":"maple_syrup","q":30},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Mash one very ripe banana in a bowl until it looks like pudding, streaks and all.","Whisk in the coconut milk, maple syrup, cinnamon, and salt until the mixture turns pale and fragrant like banana bread batter.","Stir in the oats, divide between two jars, and press the surface flat so everything stays submerged.","Refrigerate at least 6 hours or overnight, until the oats are plump and spoonably thick.","Just before eating, top each jar with the second banana in slices and a shower of toasted, chopped walnuts for crunch against the creamy oats."],"tip":"A banana with leopard spots is not past it — it is exactly the banana this recipe is asking for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_berry_quinoa_porridge', '{"id":"coconut_berry_quinoa_porridge","name":"Coconut Berry Quinoa Porridge","emoji":"🍓","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"coconut_milk","q":250},{"f":"berries","q":150},{"f":"maple_syrup","q":45},{"f":"almonds","q":25},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Rinse the quinoa well under cold water to wash away its bitter coating, then drain thoroughly.","Combine the quinoa with the coconut milk, 250 ml of water, cinnamon, and salt in a saucepan and bring to a boil over medium-high heat.","Reduce to a low simmer, cover, and cook 18 to 20 minutes, until the grains uncurl their little tails and the liquid turns thick and creamy.","Stir in the maple syrup and half the berries, letting them burst and streak the porridge pink over the residual heat.","Spoon into bowls and finish with the remaining berries and a scatter of toasted, sliced almonds."],"tip":"Skip the rinse and you will learn why quinoa''s natural coating is called saponin — it tastes like soap holds grudges."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_cinnamon_breakfast_rice_pudding', '{"id":"maple_cinnamon_breakfast_rice_pudding","name":"Maple Cinnamon Breakfast Rice Pudding","emoji":"🍚","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":150},{"f":"coconut_milk","q":250},{"f":"maple_syrup","q":45},{"f":"banana","q":1},{"f":"lemon","q":0.5},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Combine the rice, coconut milk, 400 ml of water, and the salt in a heavy saucepan and bring to a boil.","Drop the heat to its lowest setting and simmer uncovered for 25 to 30 minutes, stirring every few minutes so the bottom never catches.","When the rice is tender and the liquid has turned lush and spoon-coating, stir in the maple syrup, cinnamon, and the finely grated zest of the lemon half.","Simmer 2 minutes more until it looks like loose risotto — it will thicken further as it cools.","Ladle into bowls and crown with banana slices and one last dusting of cinnamon while steam still curls off the top."],"tip":"Stirring is the whole job here — wander off and the bottom layer will file a formal complaint in the form of scorch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_maple_griddle_cakes', '{"id":"banana_maple_griddle_cakes","name":"Banana Maple Griddle Cakes","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"flour","q":150},{"f":"banana","q":2},{"f":"coconut_milk","q":200},{"f":"sugar","q":15},{"f":"olive_oil","q":15},{"f":"maple_syrup","q":45},{"f":"cinnamon","q":2},{"f":"salt","q":2}],"steps":["Mash one banana to a smooth puree in a large bowl, then whisk in the coconut milk, sugar, cinnamon, and salt.","Add the flour and stir just until no dry streaks remain — a few lumps mean tender cakes, so resist the urge to keep beating.","Heat a splash of the olive oil in a nonstick skillet over medium heat until it shimmers, then ladle in small rounds about 8 centimeters across.","Cook 2 to 3 minutes until the edges look dry and the undersides are deeply golden, then flip and cook 2 minutes more.","Keep the finished cakes warm under a towel while you cook the rest, adding oil as needed.","Stack them high and finish with the second banana in slices and a generous pour of maple syrup."],"tip":"These are dense, banana-forward little cakes by design — keep them small and they stay tender instead of turning into frisbees."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_banana_french_toast', '{"id":"maple_banana_french_toast","name":"Maple Banana French Toast","emoji":"🍞","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"bread","q":6},{"f":"banana","q":1},{"f":"coconut_milk","q":200},{"f":"cinnamon","q":3},{"f":"olive_oil","q":15},{"f":"maple_syrup","q":45},{"f":"berries","q":100},{"f":"salt","q":1}],"steps":["Mash the banana until completely smooth, then whisk it with the coconut milk, cinnamon, and salt in a shallow dish until it looks like thin custard.","Dip each slice of bread for about 20 seconds per side — long enough to soak, short enough that it does not fall apart in your hands.","Heat the olive oil in a wide skillet over medium heat until it shimmers, then lay in the slices without crowding.","Cook 3 to 4 minutes per side, until the surface is burnished golden brown and the centers puff slightly.","Serve immediately, shingled on plates with the berries and maple syrup poured over while the crusts are still crisp."],"tip":"Day-old bread drinks the banana custard without collapsing — fresh squishy bread will dissolve like a sandcastle at high tide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_peanut_sweet_potato_breakfast_bowls', '{"id":"maple_peanut_sweet_potato_breakfast_bowls","name":"Maple Peanut Sweet Potato Breakfast Bowls","emoji":"🍠","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"peanut_butter","q":50},{"f":"coconut_milk","q":100},{"f":"maple_syrup","q":30},{"f":"banana","q":1},{"f":"berries","q":100},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Peel the sweet potatoes, cut them into 3-centimeter chunks, and steam or boil them for 12 to 15 minutes until a fork slides through with no resistance.","Drain well, then mash with the coconut milk, cinnamon, and salt until fluffy and the color of a sunset.","Warm the peanut butter with the maple syrup in a small pan over low heat for a minute, stirring until it loosens into a pourable ribbon.","Divide the sweet potato mash between two bowls and swirl the warm peanut-maple sauce over the top.","Finish with banana coins and a handful of berries, and eat while the contrast between warm mash and cool fruit is at its best."],"tip":"Steam rather than boil if you can — waterlogged sweet potatoes make a bowl that eats like a swamp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('stovetop_maple_almond_granola_bowls', '{"id":"stovetop_maple_almond_granola_bowls","name":"Stovetop Maple Almond Granola Bowls","emoji":"🌰","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":20,"servings":2,"ing":[{"f":"oats","q":120},{"f":"almonds","q":30},{"f":"maple_syrup","q":60},{"f":"olive_oil","q":20},{"f":"cinnamon","q":2},{"f":"salt","q":1},{"f":"banana","q":2},{"f":"coconut_milk","q":150}],"steps":["Heat the olive oil in a wide skillet over medium heat, then add the oats and roughly chopped almonds in an even layer.","Toast for 5 to 6 minutes, stirring every minute, until the oats turn deep gold and the kitchen smells like a bakery.","Drizzle in the maple syrup with the cinnamon and salt, and keep stirring for 2 to 3 minutes as the syrup bubbles and coats every flake.","Scrape the granola onto a plate in a thin layer and let it cool 5 minutes — it crisps as it sits, going from chewy to shattering.","Slice the bananas into two bowls, pour the cold coconut milk over, and pile the warm granola on top so every spoonful crackles."],"tip":"The granola is lying to you in the pan — it feels soft until it cools, so pull it when it is golden, not when it is crunchy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_breakfast_couscous', '{"id":"apple_cinnamon_breakfast_couscous","name":"Apple Cinnamon Breakfast Couscous","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":15,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"apple","q":2},{"f":"maple_syrup","q":45},{"f":"cashews","q":30},{"f":"cinnamon","q":3},{"f":"coconut_milk","q":150},{"f":"salt","q":1}],"steps":["Dice the apples into small cubes, leaving the skin on for color and a little chew.","Simmer the apples with the coconut milk, 150 ml of water, maple syrup, cinnamon, and salt in a saucepan for 4 to 5 minutes, until the cubes soften at the edges and the liquid smells like pie filling.","Stir in the couscous, cover, and pull the pan off the heat entirely.","Let it stand 5 minutes, then uncover and fluff with a fork — every grain should be distinct, plump, and stained faintly gold.","Serve in warm bowls topped with toasted, chopped cashews and an extra pinch of cinnamon."],"tip":"Couscous cooks off the heat like it is on vacation — trust the lid and do not stir until the five minutes are up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_banana_smoothie_bowls', '{"id":"berry_banana_smoothie_bowls","name":"Berry Banana Smoothie Bowls","emoji":"🥤","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"banana","q":3},{"f":"berries","q":200},{"f":"coconut_milk","q":200},{"f":"peanut_butter","q":30},{"f":"maple_syrup","q":20},{"f":"oats","q":30},{"f":"cinnamon","q":1}],"steps":["Toast the oats in a dry skillet over medium heat for 3 to 4 minutes with the cinnamon until golden and fragrant, then set aside to crisp.","Blend two frozen bananas, 150 grams of the berries, the coconut milk, and the maple syrup until thick and completely smooth, scraping down the sides once.","The mixture should mound on a spoon like soft-serve — add coconut milk a splash at a time only if the blender stalls.","Divide between two chilled bowls and work quickly before it slackens.","Top with the last banana in slices, the remaining berries, the toasted oats, and a lazy drizzle of peanut butter loosened with a few seconds in the microwave."],"tip":"Keep a bag of peeled banana chunks in the freezer at all times — a frozen banana is the entire load-bearing wall of this recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caramelized_apple_peanut_butter_wraps', '{"id":"caramelized_apple_peanut_butter_wraps","name":"Caramelized Apple Peanut Butter Wraps","emoji":"🌯","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":15,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"apple","q":2},{"f":"peanut_butter","q":40},{"f":"maple_syrup","q":30},{"f":"cinnamon","q":3},{"f":"olive_oil","q":10}],"steps":["Cut the apples into thin wedges and warm the olive oil in a skillet over medium-high heat until it shimmers.","Add the apples in a single layer and cook 4 to 5 minutes, turning once, until the edges brown and soften.","Pour in the maple syrup and cinnamon and let it bubble for a minute, tossing until the apples are glossy and coated in loose caramel.","Spread each tortilla with peanut butter right to the edges, then spoon the hot apples down the center.","Roll snugly, then toast the wraps seam-side down in the same skillet for a minute per side until golden and crisp, and slice on the bias to serve."],"tip":"The peanut butter is your glue — spread it to the edges and the wrap holds, skimp and it unrolls itself in protest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_berry_quinoa_breakfast_bake', '{"id":"banana_berry_quinoa_breakfast_bake","name":"Banana Berry Quinoa Breakfast Bake","emoji":"🫙","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"banana","q":2},{"f":"berries","q":150},{"f":"coconut_milk","q":200},{"f":"maple_syrup","q":45},{"f":"cashews","q":30},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Rinse the quinoa, then simmer it in 280 ml of water for 12 minutes until just tender but still slightly firm at the center; drain any excess.","Heat the oven to 190°C while you mash one banana in a bowl with the coconut milk, maple syrup, cinnamon, and salt.","Fold the cooked quinoa and two-thirds of the berries into the banana mixture and pour it all into a small oiled baking dish.","Top with the second banana in slices, the remaining berries, and roughly chopped cashews.","Bake 22 to 25 minutes, until the edges bubble and the cashews turn deep gold, then rest 5 minutes before scooping into bowls."],"tip":"Undercook the quinoa on the stove just slightly — it finishes in the oven, and nobody has ever raved about a mushy bake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sunrise_turmeric_tofu_scramble', '{"id":"sunrise_turmeric_tofu_scramble","name":"Sunrise Turmeric Tofu Scramble","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein","low-carb"],"allergens":["soy"],"time":20,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"olive_oil","q":25},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"spinach","q":100},{"f":"avocado","q":1}],"steps":["Press the tofu between paper towels for 5 minutes, then crumble it with your hands into ragged, egg-sized curds — uneven pieces catch more seasoning.","Heat the olive oil in a large skillet over medium-high until it shimmers, then soften the diced onion and bell pepper for 4 minutes until the edges just begin to brown.","Stir in the minced garlic for 30 seconds, add the crumbled tofu with a generous pinch of turmeric, paprika, salt, and black pepper, and press it into an even layer.","Let it sear undisturbed for 3 minutes so the bottom turns golden and slightly crisp, then flip and repeat once more.","Fold in the spinach off the heat and let the residual warmth wilt it to a glossy dark green, about 1 minute.","Divide between two plates and top with sliced avocado and another crack of black pepper."],"tip":"A splash of the avocado''s lime juice at the end wakes up turmeric the way an alarm clock never could."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sonoran_tofu_breakfast_tacos', '{"id":"sonoran_tofu_breakfast_tacos","name":"Sonoran Tofu Breakfast Tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":25,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"tortillas","q":6},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"salsa","q":120},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3}],"steps":["Crumble the pressed tofu into small pebbles and toss with cumin, chili powder, garlic powder, and salt until every piece is rust-colored.","Heat the olive oil in a wide skillet over medium-high, add the sliced onion, and cook 3 minutes until translucent with browned tips.","Add the seasoned tofu in a single layer and cook 6 to 8 minutes, stirring only twice, until the crumbles are deeply browned and sizzle audibly.","Meanwhile, char the tortillas directly over a gas flame or in a dry pan for 20 seconds per side until puffed and freckled.","Pile the tofu into the warm tortillas and finish each taco with salsa, sliced avocado, torn cilantro, and a hard squeeze of lime."],"tip":"Resist stirring the tofu constantly — browning happens when you walk away, not when you hover."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_smoked_paprika_potato_hash', '{"id":"crispy_smoked_paprika_potato_hash","name":"Crispy Smoked Paprika Potato Hash","emoji":"🥔","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"black_beans","q":200},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"kale","q":0.4},{"f":"garlic","q":0.2}],"steps":["Dice the potatoes into 1-centimeter cubes and parboil them in salted water for 5 minutes, then drain and let them steam dry — dry surfaces are the secret to crunch.","Heat the olive oil in a cast-iron skillet over medium-high until a test cube sizzles on contact, then add the potatoes in a single layer and leave them alone for 5 full minutes.","Flip in sections once the undersides are deep golden, add the diced onion and bell pepper, and cook 6 more minutes until the peppers blister at the edges.","Stir in the garlic, paprika, salt, and pepper, then fold in the drained black beans and stripped kale.","Cook 3 minutes more, pressing everything flat once so the beans crisp slightly and the kale wilts dark and glossy, then serve straight from the pan."],"tip":"If your spatula meets resistance when you try to flip, the potatoes are politely telling you they need another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('blistered_tomato_avocado_toast', '{"id":"blistered_tomato_avocado_toast","name":"Blistered Tomato Avocado Toast","emoji":"🥑","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"avocado","q":2},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1},{"f":"lime","q":1}],"steps":["Heat the olive oil in a small skillet over high heat and add the cherry tomatoes whole; let them blister and pop for 3 to 4 minutes, shaking the pan until their skins split and they slump into jammy softness.","Toast the bread until deeply golden and audibly crisp, then rub one side of each slice with the cut garlic clove while still hot.","Halve the avocados and smash the flesh in a bowl with lime juice, flaky salt, and a pinch of red pepper flakes, keeping it chunky rather than smooth.","Spread the avocado thickly onto the garlic side of each toast, going all the way to the edges — dry corners are a moral failing.","Spoon the warm blistered tomatoes and their pan juices over the top and finish with black pepper."],"tip":"Salt the avocado, not the toast — seasoning the mash means every bite lands, not just the lucky ones."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_potato_breakfast_burritos', '{"id":"black_bean_potato_breakfast_burritos","name":"Black Bean and Potato Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"black_beans","q":300},{"f":"potatoes","q":250},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"salsa","q":100},{"f":"avocado","q":1}],"steps":["Dice the potatoes small — no bigger than a die — and pan-fry them in the olive oil over medium-high heat for 10 to 12 minutes, tossing occasionally, until crackly and golden on most sides.","Push the potatoes aside, add the diced onion, and cook 3 minutes until soft and sweet-smelling.","Stir in the black beans with cumin, oregano, and salt, mashing about a third of them against the pan so the filling binds instead of rolling around loose.","Warm the tortillas in a dry skillet for 15 seconds a side until pliable, then load each with the potato-bean filling, salsa, and sliced avocado.","Fold in the sides, roll tightly away from you, and return each burrito seam-side down to the hot dry pan for 2 minutes until sealed and lightly crisped."],"tip":"Searing the seam is not optional — an unsealed burrito is just a very ambitious salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_chickpea_breakfast_hash', '{"id":"sweet_potato_chickpea_breakfast_hash","name":"Sweet Potato and Chickpea Breakfast Hash","emoji":"🍠","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"sweet_potatoes","q":450},{"f":"chickpeas","q":250},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"kale","q":0.5}],"steps":["Cut the sweet potatoes into 1.5-centimeter cubes and toss them into a hot skillet with two-thirds of the olive oil over medium heat; cover and cook 8 minutes, stirring once, until a fork slides in easily.","Uncover, raise the heat to medium-high, and add the diced onion; cook 5 minutes until the sweet potato edges caramelize to a deep amber.","Pat the chickpeas dry, add them with the remaining oil, and fry 4 minutes until their skins tighten and turn faintly crisp.","Season with paprika, cumin, salt, and the minced garlic, cooking 1 fragrant minute more.","Fold in the stripped kale with a splash of water and cover for 2 minutes until it collapses into silky ribbons, then serve hot with plenty of black pepper."],"tip":"Damp chickpeas steam and stay sad; a thorough towel-dry is the difference between crispy and mushy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_potato_breakfast_tacos', '{"id":"crispy_potato_breakfast_tacos","name":"Crispy Potato Breakfast Tacos","emoji":"🫓","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":6},{"f":"potatoes","q":400},{"f":"olive_oil","q":25},{"f":"onion","q":1},{"f":"salsa","q":100},{"f":"avocado","q":1},{"f":"cilantro","q":0.2},{"f":"lime","q":1}],"steps":["Cut the potatoes into small half-centimeter dice, rinse them under cold water to shed surface starch, and dry them ruthlessly with a towel.","Heat the olive oil in a heavy skillet over medium-high and fry the potatoes for 12 to 14 minutes, turning every few minutes, until they rattle against the pan and are golden-crisp all over.","Add the diced onion for the last 4 minutes so it softens and picks up color, then season generously with salt, cumin, and chili powder.","Toast the tortillas in a dry pan until soft and lightly charred, about 20 seconds per side, and keep them warm under a towel.","Fill each tortilla with crispy potatoes, then top with salsa, avocado slices, torn cilantro, and a squeeze of lime just before eating."],"tip":"The rinse-and-dry step feels fussy until you taste the difference between fried potatoes and steamed regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_chickpea_smash_toast', '{"id":"lemony_chickpea_smash_toast","name":"Lime-Kissed Chickpea Smash Toast","emoji":"🥪","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"chickpeas","q":250},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15},{"f":"onion","q":0.5}],"steps":["Drain the chickpeas and smash them in a bowl with a fork until about half are broken down into a rough, craggy paste and half stay whole.","Fold in the avocado, most of the lime juice, the olive oil, finely minced onion, salt, black pepper, and a pinch of red pepper flakes until the mixture is creamy but still textured.","Toast the bread until it is sturdy enough to knock on — a floppy base will surrender under this filling.","Pile the chickpea smash generously onto the hot toast and press it down lightly so it grips.","Finish with the remaining lime juice, a thread of olive oil, and more black pepper than seems polite."],"tip":"Under-mash on purpose — whole chickpeas are texture, and texture is the whole point of toast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_breakfast_power_bowl', '{"id":"mexican_breakfast_power_bowl","name":"Mexican Breakfast Power Bowl","emoji":"🥣","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"sweet_potatoes","q":300},{"f":"black_beans","q":300},{"f":"corn_frozen","q":150},{"f":"olive_oil","q":20},{"f":"salsa","q":120},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.2}],"steps":["Cube the sweet potatoes, toss with half the olive oil, salt, and chili powder, and roast at 220C for 20 to 25 minutes until the corners char and the centers turn custardy.","While they roast, warm the black beans in a small pan with a splash of water, cumin, and garlic powder, mashing a few against the side until the liquid turns velvety.","Sear the corn in the remaining oil in a hot dry-ish skillet for 4 minutes until some kernels blacken and smell toasty-sweet.","Build each bowl with a base of beans, then roasted sweet potatoes and charred corn arranged in generous stripes.","Crown with salsa, fanned avocado, torn cilantro, and a decisive squeeze of lime over everything."],"tip":"Char the corn until you hear a few kernels pop — that little percussion section is where the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_black_bean_breakfast_quesadillas', '{"id":"mushroom_black_bean_breakfast_quesadillas","name":"Mushroom and Black Bean Breakfast Quesadillas","emoji":"🫔","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"mushrooms","q":250},{"f":"black_beans","q":200},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"salsa","q":100},{"f":"avocado","q":1}],"steps":["Slice the mushrooms thin and cook them in half the olive oil over medium-high heat for 6 to 7 minutes until their liquid evaporates and they turn deeply browned and meaty.","Add the minced garlic, cumin, and paprika for the final minute, then stir in the black beans and mash roughly so the mixture becomes a cohesive, spreadable filling.","Spread the filling over half of each tortilla, leaving a thumb-width border, and fold into half-moons, pressing firmly.","Brush the outsides lightly with the remaining oil and toast in a dry skillet over medium heat for 3 minutes per side, pressing with a spatula, until crackly and golden with dark blisters.","Rest 2 minutes so the filling sets, then slice into wedges and serve with salsa and sliced avocado for dunking."],"tip":"Mashed beans are the vegan quesadilla''s glue — skip the mashing and your filling will stage a jailbreak on the first bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('california_edamame_smash_toast', '{"id":"california_edamame_smash_toast","name":"California Edamame Smash Toast","emoji":"🌱","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"edamame_frozen","q":250},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1}],"steps":["Boil the edamame in well-salted water for 4 minutes until bright green and just tender, then drain and rinse briefly under cold water.","Pulse or fork-smash the edamame with the avocado, olive oil, lime juice, grated garlic, salt, and a pinch of red pepper flakes until it becomes a coarse, vivid-green spread with visible bean pieces.","Toast the bread until the surface is dry, golden, and crisp enough to scrape.","Spread the edamame smash thickly across each slice, dragging the fork to leave craggy peaks that catch the finishing oil.","Top with flaky salt, a final squeeze of lime, and a drizzle of olive oil, and eat while the toast still crunches."],"tip":"Taste before the final lime squeeze — edamame drinks up acid and salt faster than you would believe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('stuffed_breakfast_sweet_potatoes_rancheras', '{"id":"stuffed_breakfast_sweet_potatoes_rancheras","name":"Stuffed Breakfast Sweet Potatoes Rancheras","emoji":"🌶️","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":250},{"f":"salsa","q":120},{"f":"spinach","q":100},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Halve the sweet potatoes lengthwise, rub the cut sides with olive oil and salt, and roast cut-side down at 220C for 25 to 30 minutes until the flesh yields completely and the edges caramelize to mahogany.","While they roast, simmer the black beans with the salsa, cumin, and oregano in a small saucepan for 5 minutes until thick and ranchero-red.","Stir the spinach into the hot beans off the heat and let it wilt into the sauce, about 1 minute.","Flip the roasted halves, rough up the flesh with a fork, and season it right in the skin with salt and lime juice.","Ladle the saucy beans over each half and finish with sliced avocado and a last squeeze of lime."],"tip":"Roasting cut-side down is the cheat code — the pan does the caramelizing while you do the coffee."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_soy_glazed_tofu_rice_bowls', '{"id":"maple_soy_glazed_tofu_rice_bowls","name":"Maple-Soy Glazed Tofu Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":45,"servings":2,"ing":[{"f":"rice","q":160},{"f":"tofu","q":350},{"f":"broccoli","q":300},{"f":"carrots","q":150},{"f":"soy_sauce","q":45},{"f":"maple_syrup","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"scallions","q":0.5},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 220C and press the tofu between paper towels for 10 minutes while you start the rice simmering in a covered pot.","Tear the tofu into rough bite-size chunks, toss with olive oil and half the soy sauce, and spread on a sheet pan with the broccoli florets and thick carrot coins.","Roast for 25 minutes, flipping once, until the tofu edges are burnished and crisp and the broccoli tips are frizzled dark green.","Meanwhile whisk the remaining soy sauce, maple syrup, sesame oil, grated ginger, and minced garlic in a small saucepan and simmer 2 minutes until it coats a spoon.","Pile the rice into bowls, top with the roasted tofu and vegetables, pour the warm glaze over everything, and shower with sliced scallions and black pepper."],"tip":"Tearing tofu instead of cubing it creates craggy edges that grab twice as much glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_spiced_tofu_quinoa_bowls', '{"id":"tandoori_spiced_tofu_quinoa_bowls","name":"Tandoori-Spiced Tofu Quinoa Bowls","emoji":"🍛","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy"],"time":45,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"tofu","q":350},{"f":"cauliflower","q":0.5},{"f":"onion","q":1},{"f":"coconut_milk","q":150},{"f":"olive_oil","q":20},{"f":"curry_powder","q":6},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 230C and rinse the quinoa, then simmer it in salted water for 15 minutes until the little spirals pop free.","Cube the tofu, cut the cauliflower into small florets, and slice the onion into thick wedges, then toss everything with olive oil, curry powder, garam masala, and salt until stained deep gold.","Roast on a sheet pan for 22 to 25 minutes until the cauliflower edges char and the tofu corners turn crisp and mahogany.","While the pan works, warm the coconut milk with grated ginger, minced garlic, and turmeric in a small saucepan, simmering 3 minutes until it thickens slightly and smells fragrant.","Spoon quinoa into bowls, heap on the roasted tofu and cauliflower, drizzle generously with the golden coconut sauce, and finish with lemon juice and torn cilantro."],"tip":"Crowd the sheet pan and you will steam the cauliflower instead of charring it, so give every floret personal space."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_roasted_veggie_tofu_couscous_bowls', '{"id":"balsamic_roasted_veggie_tofu_couscous_bowls","name":"Balsamic Roasted Veggie and Tofu Couscous Bowls","emoji":"🍆","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":40,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"tofu","q":300},{"f":"zucchini","q":1},{"f":"cherry_tomatoes","q":250},{"f":"mushrooms","q":200},{"f":"balsamic_vinegar","q":45},{"f":"maple_syrup","q":15},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":2},{"f":"basil","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 220C, cube the tofu and pat it dry, and cut the zucchini into half-moons and the mushrooms into quarters.","Toss the tofu, zucchini, mushrooms, and whole cherry tomatoes with olive oil, minced garlic, oregano, and salt, then roast for 25 minutes until the tomatoes burst and slump into jammy pockets.","Meanwhile pour boiling salted water over the couscous, cover the bowl tightly, and let it steam for 5 minutes before fluffing with a fork into light, separate grains.","Simmer the balsamic vinegar with the maple syrup in a small pan for 3 to 4 minutes until it turns glossy and coats the back of a spoon.","Mound the couscous into bowls, top with the roasted vegetables and tofu, ribbon the balsamic glaze over everything, and scatter with torn basil."],"tip":"Watch the balsamic like a hawk in its final minute; it goes from syrup to candy shard with alarming enthusiasm."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_eggplant_chickpea_quinoa_bowls', '{"id":"roasted_eggplant_chickpea_quinoa_bowls","name":"Roasted Eggplant and Chickpea Quinoa Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":45,"servings":2,"ing":[{"f":"quinoa","q":130},{"f":"chickpeas","q":300},{"f":"eggplant","q":1},{"f":"cherry_tomatoes","q":200},{"f":"onion","q":1},{"f":"hummus","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and cut the eggplant into 2-centimeter cubes, salting them lightly while you slice the onion into wedges.","Toss the eggplant, onion, cherry tomatoes, and drained chickpeas with olive oil, cumin, paprika, and minced garlic, then spread across a large sheet pan.","Roast for 25 to 30 minutes, stirring halfway, until the eggplant is creamy inside with bronzed edges and the chickpeas rattle when you shake the pan.","Meanwhile simmer the rinsed quinoa in salted water for 15 minutes, then drain and fluff it while it steams dry.","Whisk the hummus with the juice of the lemon and a splash of warm water until it pours like thick cream, then spoon it over bowls of quinoa piled with the roasted vegetables and chickpeas.","Finish with chopped parsley and a final drizzle of olive oil before serving warm."],"tip":"Eggplant drinks oil like it is at an open bar, so toss thoroughly once and resist topping it up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_carrot_chickpea_couscous_bowls', '{"id":"moroccan_spiced_carrot_chickpea_couscous_bowls","name":"Moroccan-Spiced Carrot and Chickpea Couscous Bowls","emoji":"🥕","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"chickpeas","q":300},{"f":"carrots","q":350},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"cumin","q":4},{"f":"cinnamon","q":2},{"f":"paprika","q":3},{"f":"maple_syrup","q":20},{"f":"lemon","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and slice the carrots on a steep diagonal into long ovals, then cut the onion into thick petals.","Toss the carrots, onion, and drained chickpeas with olive oil, cumin, cinnamon, paprika, and salt, then roast for 25 minutes until the carrot edges caramelize and curl.","Drizzle the maple syrup over the pan for the final 5 minutes so everything picks up a sticky, burnished lacquer.","Meanwhile steep the couscous in boiling salted water under a tight cover for 5 minutes, then rake it into fluffy grains with a fork.","Squeeze the lemon over the hot roasted vegetables to wake up the spices, then serve them heaped over couscous with plenty of chopped cilantro."],"tip":"Cut the carrots thicker than feels right; skinny ones vanish into chewy wisps by minute twenty."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_chickpea_sweet_potato_rice_bowls', '{"id":"coconut_curry_chickpea_sweet_potato_rice_bowls","name":"Coconut Curry Chickpea and Sweet Potato Rice Bowls","emoji":"🍠","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"rice","q":130},{"f":"chickpeas","q":250},{"f":"sweet_potatoes","q":300},{"f":"spinach","q":100},{"f":"coconut_milk","q":120},{"f":"onion","q":1},{"f":"olive_oil","q":15},{"f":"curry_powder","q":8},{"f":"turmeric","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"lime","q":1},{"f":"salt","q":3}],"steps":["Heat the oven to 220C, cube the sweet potatoes into 2-centimeter pieces, and roast them with the drained chickpeas, half the olive oil, half the curry powder, and salt for 25 minutes until fork-tender with crackly spiced edges.","Start the rice simmering in a covered pot with a pinch of salt so it finishes alongside the pan.","Soften the diced onion in the remaining oil over medium heat for 5 minutes, then stir in the garlic, grated ginger, turmeric, and remaining curry powder until the kitchen smells like a spice market.","Pour in the coconut milk with a splash of water, simmer 3 minutes until slightly thickened, then wilt in the spinach by the handful.","Ladle the emerald-flecked sauce over bowls of rice, top with the roasted sweet potatoes and chickpeas, and brighten everything with a hard squeeze of lime."],"tip":"Bloom the spices in the onion until they smell toasty, not scorched; thirty seconds is the difference between fragrant and bitter."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_pepper_black_bean_rice_bowls', '{"id":"charred_pepper_black_bean_rice_bowls","name":"Charred Pepper and Black Bean Rice Bowls","emoji":"🌶️","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":130},{"f":"black_beans","q":320},{"f":"bell_pepper","q":2},{"f":"corn_frozen","q":150},{"f":"onion","q":1},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"salsa","q":120},{"f":"olive_oil","q":15},{"f":"cumin","q":4},{"f":"chili_powder","q":5},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 230C and slice the bell peppers into thick strips and the onion into wedges, then toss them with olive oil, cumin, chili powder, and salt.","Roast for 20 minutes, adding the corn for the final 8, until the pepper edges blister black in spots and the corn picks up toasty freckles.","Simmer the rice in salted water while the vegetables roast, and warm the black beans in a small saucepan with a spoonful of salsa and a pinch of cumin.","Mash the avocado with the juice of one lime and a pinch of salt into a rough, spoonable crema.","Layer rice, saucy beans, and charred vegetables into bowls, then crown with avocado crema, the remaining salsa, cilantro, and lime wedges for squeezing."],"tip":"Let the peppers sit undisturbed in the oven; flipping them every five minutes is how char never happens."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_maple_sweet_potato_black_bean_quinoa_bowls', '{"id":"smoky_maple_sweet_potato_black_bean_quinoa_bowls","name":"Smoky Maple Sweet Potato and Black Bean Quinoa Bowls","emoji":"🫘","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"black_beans","q":300},{"f":"sweet_potatoes","q":350},{"f":"kale","q":0.5},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"maple_syrup","q":20},{"f":"paprika","q":5},{"f":"chili_powder","q":4},{"f":"cumin","q":3},{"f":"lime","q":1},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and cube the sweet potatoes, then toss them and the onion wedges with most of the olive oil, the paprika, chili powder, cumin, and salt.","Roast for 25 to 30 minutes, turning once, until the cubes are custardy inside and crusted with dark spice at the corners.","Simmer the rinsed quinoa in salted water for 15 minutes while you strip the kale from its stems and tear it into bite-size pieces.","Massage the kale with the last of the oil and a pinch of salt until it darkens and softens, then warm the black beans with a splash of water.","Whisk the maple syrup with the lime juice and a pinch of chili powder into a quick sweet-hot dressing, then build bowls of quinoa, beans, kale, and roasted sweet potatoes and drizzle it over the top."],"tip":"Massaging kale feels ridiculous exactly once, which is the first time you taste the difference."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mujadara_style_lentil_rice_bowls', '{"id":"mujadara_style_lentil_rice_bowls","name":"Mujadara-Style Lentil Rice Bowls with Crispy Onions","emoji":"🧅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["sesame"],"time":50,"servings":2,"ing":[{"f":"rice","q":130},{"f":"lentils_dry","q":150},{"f":"onion","q":2},{"f":"zucchini","q":1},{"f":"olive_oil","q":30},{"f":"hummus","q":80},{"f":"cumin","q":4},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Simmer the lentils in plenty of salted water for 20 to 25 minutes until tender but still holding their shape, then drain them well.","Meanwhile heat the oven to 220C and roast the zucchini half-moons with a little of the olive oil and salt for 18 minutes until golden and slack.","Slice both onions into thin half-rings and fry them in the remaining oil over medium heat for 15 patient minutes, stirring now and then, until deeply bronzed and crisp at the edges.","Cook the rice in salted water, then fold it together with the lentils, cumin, minced garlic, and a third of the crispy onions, letting the residual heat marry them.","Thin the hummus with lemon juice and warm water into a drizzling sauce, then serve bowls of the lentil rice topped with roasted zucchini, the remaining crispy onions, parsley, and black pepper."],"tip":"The onions are done five minutes after you are convinced they are done, so hold your nerve."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garam_masala_lentil_quinoa_bowls', '{"id":"garam_masala_lentil_quinoa_bowls","name":"Garam Masala Lentil and Roasted Carrot Quinoa Bowls","emoji":"🥘","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"quinoa","q":130},{"f":"lentils_dry","q":130},{"f":"carrots","q":250},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"coconut_milk","q":120},{"f":"olive_oil","q":20},{"f":"garam_masala","q":5},{"f":"turmeric","q":3},{"f":"cumin","q":3},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and roast thick carrot batons tossed with half the oil, half the garam masala, and salt for 25 minutes until blistered and sweet.","Simmer the lentils in salted water for 20 minutes until just tender, and cook the rinsed quinoa in a separate pot for 15 minutes until fluffy.","Soften the diced onion in the remaining oil, then bloom the ginger, garlic, cumin, turmeric, and remaining garam masala for 30 fragrant seconds.","Add the drained lentils and coconut milk to the onion pan and simmer 5 minutes until the sauce thickens and clings, then wilt in the spinach.","Serve the saucy lentils over quinoa, pile the roasted carrots alongside, and finish with lime juice and a flurry of cilantro."],"tip":"Lentils cooked in furiously boiling water split their jackets; keep it at a gentle burble and they stay dignified."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_couscous_bowls', '{"id":"tuscan_white_bean_couscous_bowls","name":"Tuscan White Bean and Burst Tomato Couscous Bowls","emoji":"🍅","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"white_beans","q":350},{"f":"cherry_tomatoes","q":250},{"f":"zucchini","q":1},{"f":"olives","q":40},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"balsamic_vinegar","q":20},{"f":"basil","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and toss the whole cherry tomatoes and zucchini half-moons with half the olive oil, the oregano, and salt on a sheet pan.","Roast for 20 minutes until the tomatoes split and leak their juices into a rough pan sauce and the zucchini turns golden at the cut sides.","Steep the couscous in boiling salted water under a lid for 5 minutes, then fluff it with a fork and lick of olive oil.","Warm the white beans gently with sliced garlic and the remaining oil in a skillet for 4 minutes, mashing a few against the side to make them creamy.","Fold the roasted vegetables and every drop of their juices into bowls of couscous with the beans, then finish with balsamic vinegar, halved olives, and torn basil."],"tip":"Those sticky tomato juices welded to the sheet pan are the sauce; scrape them off like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_scallion_edamame_rice_bowls', '{"id":"ginger_scallion_edamame_rice_bowls","name":"Ginger-Scallion Edamame Rice Bowls with Roasted Mushrooms","emoji":"🍄","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":40,"servings":2,"ing":[{"f":"rice","q":150},{"f":"edamame_frozen","q":300},{"f":"mushrooms","q":250},{"f":"asparagus","q":250},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":12},{"f":"olive_oil","q":15},{"f":"ginger","q":20},{"f":"scallions","q":1},{"f":"garlic","q":0.3},{"f":"maple_syrup","q":15}],"steps":["Heat the oven to 230C, quarter the mushrooms, and snap the woody ends off the asparagus before cutting the spears into thirds.","Toss the mushrooms and asparagus with olive oil and a splash of the soy sauce, then roast for 18 minutes until the mushrooms are chestnut-brown and squeaky-crisp at the edges.","Simmer the rice in a covered pot, and boil the edamame for 4 minutes in the final stretch until bright green and tender.","Finely mince the scallions, ginger, and garlic, pile them in a heatproof bowl, and pour over the sesame oil warmed in a small pan until it sizzles on contact.","Stir the remaining soy sauce and maple syrup into the ginger-scallion oil, then spoon it over bowls of rice heaped with edamame and the roasted vegetables."],"tip":"Pour the hot oil over the aromatics from a safe height and enjoy the sizzle; that crackle is the sauce cooking itself."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_style_white_bean_quinoa_bowls', '{"id":"greek_style_white_bean_quinoa_bowls","name":"Greek-Style White Bean Quinoa Bowls with Roasted Peppers","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"white_beans","q":300},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"cucumber","q":0.5},{"f":"olives","q":60},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":3},{"f":"garlic","q":0.2},{"f":"parsley","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oven to 230C and cut the bell peppers into wide strips and the onion into thick wedges, then toss with a third of the olive oil, half the oregano, and salt.","Roast for 20 to 22 minutes until the pepper skins wrinkle and catch dark blisters at the edges.","Simmer the rinsed quinoa in salted water for 15 minutes, then spread it on a plate for a few minutes so it cools from steaming to warm.","Whisk the remaining olive oil with the lemon juice, minced garlic, and remaining oregano into a sharp, cloudy dressing.","Toss the quinoa with the white beans, diced cucumber, and half the dressing, then top the bowls with roasted peppers, olives, parsley, and the rest of the dressing."],"tip":"Dress the quinoa while it is still warm and it drinks in the lemon; wait until cold and the dressing just sits there sulking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_chickpea_chop_salad', '{"id":"mediterranean_chickpea_chop_salad","name":"Mediterranean Chickpea Chop Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"olive_oil","q":45},{"f":"lemon","q":1},{"f":"garlic","q":0.2}],"steps":["Drain and rinse the chickpeas, then pat them dry and tip half into a bowl; mash them roughly with a fork so the dressing has something to cling to.","Grate the garlic into a large bowl, add the juice of the whole lemon and a big pinch of salt, and whisk in the olive oil until the dressing looks cloudy and thick.","Chop the romaine into ribbons, dice the cucumber and tomatoes into even half-inch pieces, and slice the onion paper-thin so it seasons rather than shouts.","Add all the vegetables and both the whole and mashed chickpeas to the dressing bowl and toss for a full minute, until every piece glistens.","Let the salad sit for 5 minutes so the onion mellows and the chickpeas drink up the lemon, then taste and add salt and pepper until it pops."],"tip":"Mashing half the chickpeas is the difference between a salad and a dressing delivery system — do not skip it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_sesame_tofu_kale_salad', '{"id":"crispy_sesame_tofu_kale_salad","name":"Crispy Sesame Tofu and Kale Salad","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","sesame","nuts","gluten"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"kale","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":15},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"cashews","q":40}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes, then tear it into rough bite-size chunks — the craggy edges crisp far better than neat cubes.","Heat the olive oil in a large skillet over medium-high until it shimmers, add the tofu in one layer, and leave it alone for 4 minutes per side until deeply golden and crackling.","Whisk the soy sauce, maple syrup, and grated garlic together, pour it over the hot tofu, and toss for 60 seconds until the glaze bubbles and lacquers every piece.","Strip the kale from its stems, slice it thin, and massage it with the sesame oil, lime juice, and a pinch of salt for 2 minutes until it darkens and softens.","Toast the cashews in the empty skillet for 2 minutes until fragrant, then pile the tofu over the kale and shower the nuts on top.","Serve while the tofu still crackles, tossing at the table so the glaze slicks the greens."],"tip":"Massage the kale like you mean it — limp handshakes make bitter salads."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_peanut_crunch_salad', '{"id":"edamame_peanut_crunch_salad","name":"Edamame Peanut Crunch Salad","emoji":"🥜","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","nuts","gluten"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":350},{"f":"peanut_butter","q":60},{"f":"romaine","q":1},{"f":"carrots","q":2},{"f":"bell_pepper","q":1},{"f":"cucumber","q":0.5},{"f":"lime","q":2},{"f":"soy_sauce","q":20},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2}],"steps":["Boil the edamame in well-salted water for 4 minutes, drain, and rinse under cold water until completely cool so the beans stay snappy.","Whisk the peanut butter, soy sauce, maple syrup, grated garlic, the juice of both limes, and 2 to 3 tablespoons of warm water until the dressing is pourable and glossy, like thin cake batter.","Shred the romaine into thin ribbons, cut the carrots and cucumber into matchsticks, and slice the bell pepper into slivers so every forkful crunches.","Combine the vegetables and edamame in a wide bowl, pour on most of the dressing, and toss with tongs until everything wears a peanut coat.","Taste, add more lime or a splash of soy if it needs brightness, and serve with the remaining dressing drizzled over the top."],"tip":"If your peanut dressing seizes into paste, whisk in warm water a spoonful at a time — it always comes back."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_taco_crunch_salad', '{"id":"black_bean_taco_crunch_salad","name":"Black Bean Taco Crunch Salad","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lime","q":2},{"f":"tortillas","q":2},{"f":"olive_oil","q":30}],"steps":["Heat the oven to 200C, brush the tortillas lightly with a little of the olive oil, cut them into thin strips, and bake for 8 to 10 minutes until they snap like chips.","Warm the drained black beans in a skillet over medium heat with a splash of water, salt, and pepper, mashing a few against the pan until they turn creamy and smell toasty, about 5 minutes.","Chop the romaine into bite-size pieces, dice the tomatoes, and slice the onion thin, then pile everything into a wide serving bowl.","Mash the avocado with the juice of both limes, the remaining olive oil, and a generous pinch of salt until it becomes a loose, spoonable dressing.","Spoon the warm beans over the greens, dollop on the avocado dressing, and toss gently so streaks of green run through everything.","Scatter the tortilla strips over the top at the last second so they stay shatteringly crisp."],"tip":"Warm beans on cold lettuce sounds wrong until you try it — the contrast is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_lentil_spinach_walnut_salad', '{"id":"warm_lentil_spinach_walnut_salad","name":"Warm Lentil and Spinach Salad with Walnuts","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"spinach","q":150},{"f":"walnuts","q":40},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"lemon","q":1}],"steps":["Simmer the lentils in plenty of salted water for 20 to 25 minutes until tender but still holding their shape — they should give to the tooth without turning to mush — then drain well.","Meanwhile, slice the onion into thin half-moons and cook it in half the olive oil over medium heat for 8 minutes, stirring, until soft, sweet, and edged with gold.","Add the sliced garlic and the walnuts to the pan and toast for 2 minutes until the kitchen smells nutty and the garlic just turns blond.","Tip the hot lentils into the pan, add the spinach in handfuls, and fold until the leaves collapse and turn glossy, about 2 minutes.","Off the heat, stir in the remaining olive oil and the juice of the lemon, then season aggressively with salt and black pepper and serve warm."],"tip":"Salt lentil cooking water like pasta water — the myth that salt toughens them has ruined too many dinners."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_chickpea_quinoa_salad', '{"id":"lemony_chickpea_quinoa_salad","name":"Lemony Chickpea Quinoa Salad","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"chickpeas","q":240},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"spinach","q":60},{"f":"lemon","q":2},{"f":"olive_oil","q":40}],"steps":["Rinse the quinoa in a fine sieve until the water runs clear, then simmer it in 300ml of salted water, covered, for 15 minutes until the grains uncurl and show their little tails.","Spread the cooked quinoa on a plate to cool for 10 minutes — dressing hot quinoa turns it gummy, and nobody wants that.","While it cools, dice the cucumber and tomatoes small, mince the onion, and slice the spinach into thin ribbons.","Whisk the juice of both lemons with the olive oil and a half teaspoon of salt until it emulsifies into a bright, tart dressing.","Fold the quinoa, drained chickpeas, and all the vegetables together with the dressing, tossing until every grain is coated and flecked with green and red.","Rest the salad 10 minutes before serving so the flavors settle in — it tastes even better slightly chilled."],"tip":"This salad improves overnight in the fridge, making it the rare dish that rewards procrastination."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_lime_tofu_noodle_salad', '{"id":"peanut_lime_tofu_noodle_salad","name":"Peanut-Lime Tofu Noodle Salad","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","nuts","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"tofu","q":350},{"f":"peanut_butter","q":50},{"f":"lime","q":2},{"f":"soy_sauce","q":25},{"f":"maple_syrup","q":10},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.3},{"f":"carrots","q":2},{"f":"cucumber","q":1}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still chewy, then rinse under cold water and drain thoroughly.","Cut the pressed tofu into half-inch cubes and sear in the sesame oil over medium-high heat, turning every 3 minutes, until all sides are bronzed and firm, about 10 minutes total.","Whisk the peanut butter, soy sauce, maple syrup, grated garlic, juice of both limes, and 3 tablespoons of warm water into a smooth, silky dressing that ribbons off the whisk.","Shave the carrots into ribbons with a vegetable peeler and cut the cucumber into thin half-moons for cool crunch against the warm tofu.","Toss the noodles and vegetables with most of the dressing until every strand is slicked, then top with the tofu and a final drizzle.","Finish with a crack of black pepper and serve at room temperature, when the flavors are loudest."],"tip":"Cold-rinsing the noodles stops them mid-cook and keeps them from welding into a single mega-noodle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('indian_lentil_kachumber_salad', '{"id":"indian_lentil_kachumber_salad","name":"Indian Lentil Kachumber Salad","emoji":"🇮🇳","cuisine":"Indian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"lentils_dry","q":180},{"f":"cucumber","q":2},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"lime","q":2},{"f":"olive_oil","q":30},{"f":"garlic","q":0.2}],"steps":["Simmer the lentils in salted water for 18 to 20 minutes until just tender, then drain and spread them on a tray to cool — warm lentils will wilt the vegetables into sadness.","Dice the cucumbers, tomatoes, and onion into small, even pieces the size of the lentils themselves; kachumber lives or dies by the knife work.","Grate the garlic into a large bowl, add the juice of both limes and a generous half teaspoon of salt, and let it sit for 2 minutes to tame the raw bite.","Whisk in the olive oil, then fold in the cooled lentils and all the chopped vegetables until everything sparkles with dressing.","Season boldly with black pepper, rest the salad for 10 minutes so the juices mingle into a tangy pool at the bottom, and serve chilled or at room temperature."],"tip":"The juice pooling at the bottom of the bowl is the best part — serve with a spoon, not just a fork."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_walnut_penne_pasta_salad', '{"id":"italian_walnut_penne_pasta_salad","name":"Italian Walnut and Tomato Penne Salad","emoji":"🇮🇹","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"walnuts","q":60},{"f":"cherry_tomatoes","q":250},{"f":"spinach","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"lemon","q":1}],"steps":["Boil the penne in generously salted water for 1 minute less than the package says, then drain and rinse briefly with cool water so it stops cooking but stays al dente.","While the pasta boils, toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until they smell like a bakery, then chop them roughly.","In the same skillet, warm the olive oil with the sliced garlic over low heat for 2 minutes until it barely sizzles and turns fragrant — golden, never brown.","Halve the cherry tomatoes, salt them, and let them sit for 5 minutes so they release their sweet juice into the bowl.","Toss the pasta with the garlic oil, tomatoes and their juices, spinach, walnuts, and the juice and zest of the lemon until the spinach softens slightly from the residual warmth.","Season with salt and plenty of cracked pepper and serve just barely warm, when the flavors are at full volume."],"tip":"Salting the tomatoes first turns them into their own dressing — free flavor you would be foolish to refuse."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_almond_kale_crunch_salad', '{"id":"maple_almond_kale_crunch_salad","name":"Maple-Almond Kale Crunch Salad","emoji":"🌰","cuisine":"American","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":25,"servings":2,"ing":[{"f":"kale","q":1.3},{"f":"almonds","q":70},{"f":"chickpeas","q":240},{"f":"carrots","q":2},{"f":"maple_syrup","q":20},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"garlic","q":0.2}],"steps":["Pat the drained chickpeas very dry, toss them with a spoonful of the olive oil and a pinch of salt, and roast at 220C for 20 minutes until they rattle on the pan.","Toast the almonds in a dry skillet over medium heat for 4 minutes until golden at the edges, then chop them coarsely while they are still warm and fragrant.","Strip the kale from its stems, slice it into thin ribbons, and massage it with a pinch of salt and a squeeze of lemon for 2 minutes until it turns dark, glossy, and tender.","Whisk the maple syrup, remaining lemon juice, grated garlic, and olive oil into a dressing that tastes equal parts sweet and sharp.","Shave the carrots into ribbons, then toss everything — kale, carrots, chickpeas, and almonds — with the dressing until each ribbon shines.","Serve within the hour, while the chickpeas still crunch like croutons."],"tip":"Roasted chickpeas lose their crunch by morning, so this is one salad that refuses to be meal-prepped."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_sweet_potato_black_bean_salad', '{"id":"roasted_sweet_potato_black_bean_salad","name":"Roasted Sweet Potato and Black Bean Salad","emoji":"🍠","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":400},{"f":"black_beans","q":300},{"f":"spinach","q":120},{"f":"avocado","q":1},{"f":"onion","q":0.5},{"f":"lime","q":2},{"f":"olive_oil","q":40}],"steps":["Heat the oven to 220C, cut the sweet potatoes into 2cm cubes, toss them with half the olive oil and a big pinch of salt, and roast for 25 to 30 minutes until caramelized at the corners and creamy inside.","While they roast, slice the onion paper-thin and soak it in the juice of one lime with a pinch of salt — a 10-minute quick pickle that tames its sting.","Rinse and drain the black beans, then warm them briefly in a skillet with a splash of water and black pepper so they arrive at the bowl soft and seasoned.","Whisk the remaining lime juice and olive oil with salt into a sharp little dressing, and cube the avocado.","Pile the spinach in a wide bowl, top with the hot sweet potatoes so the leaves wilt slightly, then add the beans, pickled onion, and avocado.","Drizzle the dressing over everything and toss gently, keeping the avocado in recognizable pieces rather than guacamole."],"tip":"Crowded sweet potatoes steam instead of caramelize — give them personal space on the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_tofu_cobb_style_salad', '{"id":"charred_tofu_cobb_style_salad","name":"Charred Tofu Cobb-Style Salad","emoji":"🥑","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein","low-carb"],"allergens":["soy","gluten"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":200},{"f":"cucumber","q":1},{"f":"soy_sauce","q":20},{"f":"olive_oil","q":35},{"f":"lemon","q":1}],"steps":["Press the tofu for 10 minutes, slice it into thick slabs, and pat completely dry — moisture is the mortal enemy of a good char.","Sear the slabs in a scorching-hot skillet with a tablespoon of the olive oil for 4 to 5 minutes per side, undisturbed, until deep mahogany with crisp edges.","Splash the soy sauce into the pan for the last 30 seconds, letting it hiss and reduce into a salty lacquer on the tofu, then rest the slabs and cut them into batons.","Whisk the remaining olive oil with the juice of the lemon, salt, and plenty of black pepper into a bright vinaigrette.","Chop the romaine and arrange it on a platter, then lay the tofu, halved cherry tomatoes, sliced cucumber, and cubed avocado in neat cobb-style rows.","Spoon the vinaigrette over the rows at the table and toss dramatically in front of your audience."],"tip":"If the tofu sticks when you try to flip it, it is not ready — it releases itself when the crust is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hummus_dressed_couscous_salad', '{"id":"hummus_dressed_couscous_salad","name":"Hummus-Dressed Couscous Salad","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"hummus","q":120},{"f":"chickpeas","q":200},{"f":"cherry_tomatoes","q":200},{"f":"cucumber","q":1},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30}],"steps":["Pour 180ml of boiling salted water over the couscous in a bowl, cover tightly, and let it steam for 5 minutes, then fluff with a fork until every grain stands apart.","Whisk the hummus with the juice of the lemon, half the olive oil, and 2 tablespoons of warm water until it loosens into a creamy, pourable dressing.","Halve the cherry tomatoes, dice the cucumber, mince the onion, and slice the spinach into ribbons while the couscous cools slightly.","Toss the couscous with the remaining olive oil so it stays loose, then fold in the drained chickpeas and all the vegetables.","Pour the hummus dressing over the salad and fold gently until everything is coated in a creamy tan cloak, then season with salt and a heavy hand of black pepper.","Serve at room temperature, when couscous is at its fluffy, nutty best."],"tip":"Thinning hummus into a dressing is the oldest trick in the deli case — cheaper than tahini and already seasoned."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_triple_bean_chili', '{"id":"smoky_triple_bean_chili","name":"Smoky Triple-Bean Chili","emoji":"🌶️","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":2},{"f":"crushed_tomatoes","q":500},{"f":"black_beans","q":400},{"f":"chickpeas","q":300},{"f":"lentils_dry","q":180},{"f":"maple_syrup","q":15}],"steps":["Heat the olive oil in a heavy pot over medium heat and cook the diced onion and bell peppers for 8 minutes, until the edges pick up a little char and the onion turns translucent.","Stir in the minced garlic and cook 1 minute more, just until it smells toasty rather than raw.","Add the crushed tomatoes, lentils, and 750 ml of water, scraping up any browned bits, then bring to a boil and reduce to a lazy simmer.","Cover and cook 25 minutes, until the lentils are tender but still hold their shape, then stir in the black beans, chickpeas, and maple syrup.","Simmer uncovered 10 minutes, until the chili is thick enough that a spoon dragged across the bottom leaves a brief trail.","Rest off the heat for 5 minutes before ladling into bowls; the flavors settle and the texture tightens as it sits."],"tip":"Chili is one of the few dishes that rewards procrastination — make it a day ahead and it tastes like you tried twice as hard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_walnut_chili', '{"id":"mushroom_walnut_chili","name":"Mushroom-Walnut ''Meaty'' Chili","emoji":"🍄","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"mushrooms","q":500},{"f":"walnuts","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"crushed_tomatoes","q":400},{"f":"black_beans","q":250},{"f":"maple_syrup","q":10}],"steps":["Pulse the mushrooms and walnuts in a food processor (or chop finely by hand) until the mixture resembles coarse ground meat.","Heat the olive oil in a wide pot over medium-high heat and cook the mushroom-walnut crumble in an even layer for 10 minutes, stirring only occasionally, until the moisture cooks off and the bits turn deeply browned and sizzling.","Add the diced onion, bell pepper, and garlic and cook 5 minutes, until softened and fragrant.","Stir in the crushed tomatoes, black beans, maple syrup, and 500 ml of water, then simmer uncovered for 20 minutes, until thick and glossy.","Taste and adjust; the chili should be rich and savory with a gentle sweetness underneath, and thick enough to mound on a spoon."],"tip":"Resist stirring the crumble too often — browning is where the ''meaty'' flavor lives, and fidgeting steams it instead."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bbq_tofu_burger_bowl', '{"id":"bbq_tofu_burger_bowl","name":"BBQ Tofu Burger Bowl","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":150},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":1},{"f":"maple_syrup","q":20},{"f":"soy_sauce","q":20},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2}],"steps":["Simmer the rice in 300 ml of water, covered, for 15 minutes, then rest it off the heat while you cook everything else.","Press the tofu between paper towels for 10 minutes, tear it into rough bite-size chunks, and toss with the olive oil.","Sear the tofu in a hot skillet over medium-high heat for 8 to 10 minutes, turning once a deep golden crust forms on each side.","Whisk the soy sauce, maple syrup, minced garlic, and a splash of water, pour it over the tofu, and let it bubble for 2 minutes until the glaze clings like barbecue sauce.","Pile the rice into bowls and top with shredded romaine, diced tomato, sliced avocado, and the sticky glazed tofu.","Spoon any skillet glaze over the top — that sweet-salty drizzle is the whole point."],"tip":"Torn tofu has craggy edges that grab sauce far better than tidy cubes, so let it look a little rough."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_burger_smash_bowl', '{"id":"black_bean_burger_smash_bowl","name":"Black Bean Smash Burger Bowl","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":35,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"oats","q":50},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":1},{"f":"hummus","q":80},{"f":"olive_oil","q":20}],"steps":["Mash the black beans in a bowl until mostly smooth with some whole beans remaining, then work in the oats, grated onion, and minced garlic until the mixture holds together when squeezed.","Shape into 4 thin patties and chill them for 10 minutes so they firm up.","Heat the olive oil in a skillet over medium-high heat and smash-sear the patties for 4 minutes per side, until the crust is dark, crisp, and crackles when tapped with a spatula.","Meanwhile, shred the romaine and dice the tomato and avocado, dividing them between two wide bowls.","Perch the hot patties on top, breaking one in half so the steam escapes, and finish each bowl with a generous dollop of hummus as your ''special sauce''.","Eat immediately, while the contrast between crackly patty and cool crunchy lettuce is at its best."],"tip":"A thin patty with a serious crust beats a thick mushy one every time — press harder than feels polite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_coconut_potato_chowder', '{"id":"creamy_coconut_potato_chowder","name":"Creamy Coconut Potato Chowder","emoji":"🥣","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"potatoes","q":700},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"carrots","q":150},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"kale","q":0.5}],"steps":["Warm the olive oil in a soup pot over medium heat and sweat the diced onion, celery, and carrots for 6 minutes, until soft and sweet-smelling but not browned.","Add the garlic and cook 1 minute, then tip in the potatoes, cut into 2 cm chunks, along with 500 ml of water.","Simmer 15 minutes, until a knife slides through a potato chunk with no resistance.","Mash a few potato chunks against the side of the pot to thicken the broth, then stir in the coconut milk and torn kale.","Simmer gently 5 more minutes, until the kale is silky and the chowder coats the back of a spoon; season assertively before serving."],"tip":"The smashed-potato trick thickens chowder better than any flour ever did — let the spuds do the work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tomato_coconut_soup', '{"id":"creamy_tomato_coconut_soup","name":"Creamy Tomato-Coconut Soup","emoji":"🍅","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"crushed_tomatoes","q":800},{"f":"coconut_milk","q":300},{"f":"chickpeas","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"maple_syrup","q":10}],"steps":["Heat the olive oil in a pot over medium heat and cook the sliced onion for 8 minutes, until golden at the edges and jammy in the middle.","Add the garlic and cook 1 minute, then add the crushed tomatoes and let them bubble for 10 minutes, stirring as they thicken into a rough sauce.","Stir in the coconut milk, maple syrup, and half the chickpeas, then blend directly in the pot until completely smooth and pale orange.","Return to a gentle simmer, add the remaining whole chickpeas for texture, and cook 5 minutes more.","Taste — it should be plush, faintly sweet, and rich enough to feel like the tomato soup of your childhood, only better."],"tip":"Blending in half the chickpeas makes the soup luxuriously thick without anyone suspecting there is a bean in the building."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_sweet_potato_skillet', '{"id":"black_bean_sweet_potato_skillet","name":"Black Bean & Sweet Potato Skillet","emoji":"🍠","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"spinach","q":100},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Heat the olive oil in a large skillet over medium heat and add the sweet potatoes, cut into 1.5 cm cubes, in a single layer.","Cook 12 to 14 minutes, tossing every few minutes, until the cubes are caramelized at the corners and tender when pierced.","Push the potatoes to one side, add the diced onion, bell pepper, and garlic, and cook 5 minutes until softened and fragrant.","Stir in the black beans and a splash of water, scraping up the browned bits, and cook 3 minutes until everything is hot and glossy.","Fold in the spinach off the heat so it just wilts, then finish with sliced avocado and a hard squeeze of lime over the whole pan.","Serve straight from the skillet while the edges are still sizzling."],"tip":"Crowd the pan and you will steam your sweet potatoes into sadness — give the cubes elbow room and they will caramelize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_cashew_penne_skillet', '{"id":"creamy_cashew_penne_skillet","name":"Creamy Cashew ''Mac'' Skillet","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":35,"servings":2,"ing":[{"f":"penne","q":180},{"f":"cashews","q":60},{"f":"coconut_milk","q":150},{"f":"broccoli","q":300},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"lemon","q":0.5}],"steps":["Soak the cashews in boiling water for 15 minutes while you boil the penne in well-salted water, dropping the broccoli florets in for the final 3 minutes.","Drain, reserving a mug of the starchy cooking water.","Blend the drained cashews with the coconut milk, garlic, and a squeeze of lemon until utterly smooth — it should pour like heavy cream.","Soften the diced onion in olive oil in the empty pot over medium heat for 4 minutes, then pour in the cashew cream and let it bubble and thicken for 2 minutes.","Return the penne and broccoli, tossing and loosening with splashes of reserved pasta water until every tube is coated in a glossy sauce that clings but still flows.","Serve immediately — cashew sauce waits for no one."],"tip":"If the sauce tightens into paste, do not panic; pasta water is the antidote, one splash at a time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_sloppy_joe_skillet', '{"id":"lentil_sloppy_joe_skillet","name":"Lentil Sloppy Joes","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":180},{"f":"crushed_tomatoes","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"maple_syrup","q":15},{"f":"soy_sauce","q":15},{"f":"olive_oil","q":15},{"f":"bread","q":4}],"steps":["Heat the olive oil in a deep skillet over medium heat and cook the diced onion and bell pepper for 6 minutes, until soft and just starting to color.","Add the garlic and cook 1 minute, then stir in the lentils, crushed tomatoes, and 500 ml of water.","Simmer uncovered for 22 to 25 minutes, stirring occasionally, until the lentils are tender and the mixture has cooked down to a thick, spoonable sludge — sloppy, but not soupy.","Stir in the maple syrup and soy sauce and simmer 3 minutes more, until the mixture tastes tangy-sweet and deeply savory.","Toast the bread until golden and pile the lentil mixture on generously, letting it spill over the edges as tradition demands."],"tip":"A sloppy joe that stays neatly on the bread has failed at its one job — embrace the drips."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_scramble_hash_skillet', '{"id":"tofu_scramble_hash_skillet","name":"Tofu Scramble Breakfast Hash","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"potatoes","q":400},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":100},{"f":"olive_oil","q":25},{"f":"garlic","q":0.2}],"steps":["Dice the potatoes into 1 cm cubes and cook them in most of the olive oil in a large skillet over medium heat for 12 minutes, tossing occasionally, until golden and crisp on several sides.","Add the diced onion, bell pepper, and garlic and cook 4 minutes, until softened and smelling like a diner at 7 a.m.","Push everything to the edges, add the remaining oil to the center, and crumble in the tofu with your hands in ragged, egg-like curds.","Let the tofu sit undisturbed for 3 minutes to pick up color, then fold the whole skillet together and season boldly.","Wilt in the spinach for the final minute and serve hot from the pan, crispy potato bits and all."],"tip":"Crumble the tofu by hand, not with a knife — irregular curds scramble convincingly, and cubes just look like cubes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_walnut_oatmeal_bowl', '{"id":"maple_walnut_oatmeal_bowl","name":"Maple-Walnut Diner Oatmeal","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":15,"servings":2,"ing":[{"f":"oats","q":120},{"f":"coconut_milk","q":250},{"f":"maple_syrup","q":30},{"f":"walnuts","q":40}],"steps":["Toast the walnuts in a dry saucepan over medium heat for 3 minutes, shaking often, until they smell warm and nutty, then set them aside.","In the same pan, combine the oats, coconut milk, 250 ml of water, and a pinch of salt, and bring to a gentle simmer.","Cook 6 to 8 minutes, stirring lazily, until the oats are creamy and slump slowly off a tilted spoon.","Stir in most of the maple syrup, then divide between bowls and crown with the toasted walnuts and a final glossy drizzle of syrup.","Eat while steaming — good oatmeal is a race against room temperature."],"tip":"Salt in the pot and syrup on top: season the oats, sweeten the surface, and every spoonful tastes intentional."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_mushroom_rice_soup_2', '{"id":"creamy_mushroom_rice_soup_2","name":"Creamy Mushroom & Rice Soup","emoji":"🍲","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":45,"servings":4,"ing":[{"f":"mushrooms","q":400},{"f":"rice","q":120},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"carrots","q":150},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":15},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a soup pot over medium-high heat and sear the sliced mushrooms in two batches for 5 minutes each, until browned and squeaking against the spoon; set them aside.","Lower the heat, add the diced onion, celery, and carrots, and cook 6 minutes until softened.","Stir in the garlic and rice, toast 1 minute, then add 1 liter of water and simmer, covered, for 18 minutes, until the rice is tender and has lent the broth some body.","Return the mushrooms with the coconut milk and soy sauce, and simmer gently 5 minutes more, until the soup is creamy, beige, and deeply savory.","Ladle into bowls and let everyone marvel that there is no cream within a mile of it."],"tip":"Browning mushrooms in batches feels fussy until you taste the difference — crowded mushrooms weep, seared mushrooms sing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_dumpling_skillet', '{"id":"chickpea_dumpling_skillet","name":"Chickpeas & Dumplings Skillet","emoji":"🥟","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":50,"servings":4,"ing":[{"f":"chickpeas","q":500},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"coconut_milk","q":300},{"f":"flour","q":150},{"f":"olive_oil","q":20}],"steps":["Heat the olive oil in a deep skillet over medium heat and cook the diced onion, carrots, and celery for 8 minutes, until softened and sweet.","Add the garlic and 2 tablespoons of the flour, stirring for 1 minute to cook off the raw taste, then gradually whisk in 600 ml of water and the coconut milk until smooth.","Add the chickpeas and simmer 10 minutes, until the gravy thickens enough to coat a spoon like a Sunday stew.","Meanwhile, stir the remaining flour with a pinch of salt and just enough water to form a soft, shaggy dough, and drop it in rough spoonfuls over the simmering surface.","Cover and steam 12 minutes without peeking — the dumplings are done when puffed, matte, and set through when split.","Spoon into shallow bowls, making sure everyone gets their fair share of dumpling."],"tip":"Lifting the lid to check the dumplings is how you end up with gluey pucks — trust the timer, not your curiosity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('teriyaki_tofu_edamame_stirfry', '{"id":"teriyaki_tofu_edamame_stirfry","name":"Teriyaki Tofu and Edamame Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"edamame_frozen","q":200},{"f":"broccoli","q":400},{"f":"rice","q":150},{"f":"soy_sauce","q":60},{"f":"maple_syrup","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3}],"steps":["Start the rice in a small pot with plenty of water and simmer it, covered, for 15 minutes while you cook everything else.","Press the tofu between paper towels for 5 minutes, cut it into 2-centimeter cubes, and sear it in olive oil in a screaming-hot skillet for 8 to 10 minutes, turning only when each side is deeply golden and crackling.","Push the tofu to the edges, add the broccoli florets with a splash of water, and cover for 3 minutes until they turn bright green and just tender at the stem.","Whisk the soy sauce, maple syrup, and minced garlic together, pour it over the pan, and let it bubble and reduce for 2 minutes until it clings to the tofu like a glossy lacquer.","Stir in the edamame and sesame oil, toss everything for a final minute until heated through, and pile it over the drained rice."],"tip":"The tofu will stick to the pan right up until the moment it is properly seared, so stop poking it and trust the sizzle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('red_lentil_chickpea_spinach_dal', '{"id":"red_lentil_chickpea_spinach_dal","name":"Red Lentil and Chickpea Spinach Dal","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"chickpeas","q":240},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":3},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5}],"steps":["Warm the olive oil in a deep pot over medium heat and cook the diced onion for 6 to 8 minutes until it softens and turns amber at the edges.","Stir in the minced garlic with a generous pinch of cumin, turmeric, and chili flakes from your spice rack, and toast for 60 seconds until the kitchen smells unmistakably like dinner.","Add the chopped tomatoes and cook them down for 5 minutes until they slump into a jammy base, then tip in the lentils with 750 milliliters of water.","Simmer uncovered for 20 minutes, stirring occasionally, until the lentils collapse into a thick, spoon-coating porridge, adding splashes of water if it tightens too much.","Fold in the chickpeas and spinach and cook 3 more minutes until the greens wilt silky and the chickpeas are heated through.","Season boldly with salt and finish with a hard squeeze of lemon to wake the whole pot up."],"tip":"Dal thickens dramatically as it sits, so leave it looser than you think you should — it will meet you in the middle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_chickpea_lentil_chili', '{"id":"smoky_chickpea_lentil_chili","name":"Smoky Chickpea and Lentil Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":50,"servings":4,"ing":[{"f":"chickpeas","q":480},{"f":"lentils_dry","q":250},{"f":"edamame_frozen","q":200},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":5},{"f":"olive_oil","q":30},{"f":"maple_syrup","q":15}],"steps":["Heat the olive oil in your largest pot over medium-high heat and cook the chopped onion and bell peppers for 7 to 8 minutes until they soften and pick up brown, sticky patches.","Add the minced garlic along with pantry smoked paprika, cumin, and chili powder, and stir for a full minute until the spices smell toasty rather than raw.","Chop the tomatoes and crush them into the pot with the lentils, maple syrup, and 1 liter of water, scraping up every browned bit from the bottom.","Simmer partially covered for 25 minutes, stirring now and then, until the lentils are tender and the chili has thickened enough that a spoon dragged through leaves a brief trail.","Stir in the chickpeas and edamame, simmer 5 more minutes, then season aggressively with salt and ladle into deep bowls."],"tip":"Chili is one of the few dishes that genuinely improves overnight, so make it a day early and take full credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_tofu_rice_noodle_bowl', '{"id":"peanut_tofu_rice_noodle_bowl","name":"Peanut Tofu Rice Noodle Bowl","emoji":"🥜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","nuts","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"rice_noodles","q":100},{"f":"edamame_frozen","q":150},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":45},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2},{"f":"carrots","q":2},{"f":"cucumber","q":1},{"f":"lime","q":1}],"steps":["Soak the rice noodles in just-boiled water for 8 minutes until pliable but still springy, then drain and rinse under cold water so they stop cooking.","Cube the pressed tofu and pan-fry it in the sesame oil over medium-high heat for 8 minutes, turning until every side is bronzed and the edges are chewy-crisp.","Whisk the peanut butter, soy sauce, maple syrup, minced garlic, lime juice, and 60 milliliters of warm water into a sauce the texture of heavy cream, thinning with more water if it seizes.","Blanch the edamame in boiling water for 3 minutes, and shave the carrots and cucumber into ribbons with a vegetable peeler.","Toss the noodles, tofu, and edamame with the peanut sauce until every strand is coated, then top with the vegetable ribbons and an extra squeeze of lime."],"tip":"Peanut sauce always seizes into cement at first — keep whisking in warm water a spoonful at a time and it will surrender."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_lentil_chickpea_soup', '{"id":"lemony_lentil_chickpea_soup","name":"Lemony Lentil and Chickpea Soup","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":350},{"f":"chickpeas","q":240},{"f":"spinach","q":150},{"f":"onion","q":1},{"f":"carrots","q":3},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":45}],"steps":["Sweat the diced onion and carrots in the olive oil over medium heat for 8 minutes until the onion is translucent and the carrots smell sweet.","Add the minced garlic with a big pinch of cumin and black pepper and cook for 1 minute more, stirring so nothing catches.","Pour in the lentils and 1.5 liters of water, bring to a boil, then drop to a gentle simmer for 25 minutes until the lentils are completely tender and the liquid has turned golden and slightly creamy.","Add the chickpeas and simmer 5 minutes, then stir in the spinach off the heat and watch it collapse into the soup within seconds.","Season with salt, then squeeze in the whole lemon — the soup should taste bright enough to make you blink."],"tip":"Add the lemon only at the end; boiled lemon juice goes bitter and sulky, but fresh lemon at the finish sings."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_chickpea_quinoa_power_bowl', '{"id":"roasted_chickpea_quinoa_power_bowl","name":"Roasted Chickpea Quinoa Power Bowl","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy","sesame"],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"quinoa","q":120},{"f":"edamame_frozen","q":200},{"f":"hummus","q":60},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Heat the oven to 220C, pat the chickpeas thoroughly dry, and toss them with half the olive oil, salt, and smoked paprika on a sheet pan.","Roast for 25 minutes, shaking the pan halfway, until the chickpeas rattle when you shake them and are crisp and deeply golden.","Meanwhile, rinse the quinoa and simmer it in 300 milliliters of salted water for 15 minutes until the little spirals unfurl, then let it steam off the heat for 5 minutes.","Boil the edamame for 3 minutes, and dice the cucumber and tomatoes while whisking the remaining oil with the lemon juice into a sharp dressing.","Build each bowl on a bed of spinach and warm quinoa, pile on the edamame, vegetables, and crackling chickpeas, then finish with a swoosh of hummus and the dressing."],"tip":"Damp chickpeas steam instead of crisp, so dry them like you are toweling off a small angry dog."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_tofu_chopped_salad', '{"id":"sesame_edamame_tofu_chopped_salad","name":"Sesame Edamame and Tofu Chopped Salad","emoji":"🥢","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame","nuts"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"tofu","q":250},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"carrots","q":2},{"f":"almonds","q":30},{"f":"sesame_oil","q":20},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":10},{"f":"lime","q":1}],"steps":["Boil the edamame in well-salted water for 4 minutes until bright green and just tender, then drain and shock under cold water.","Cut the tofu into small cubes and sear it in a dry nonstick skillet over high heat for 6 to 7 minutes, tossing until the surfaces are golden and lightly blistered.","Whisk the sesame oil, soy sauce, maple syrup, and lime juice into a dressing that tastes equal parts salty, sweet, and sour.","Chop the romaine into ribbons, dice the cucumber, and shave the carrots thin, then toss everything in a huge bowl with the edamame and warm tofu.","Pour over the dressing, toss until every leaf glistens, and shower with roughly chopped almonds for crunch."],"tip":"Dress this salad the minute before you eat it — romaine holds its crunch like a grudge, but only until the dressing hits."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_lentil_walnut_tacos', '{"id":"smoky_lentil_walnut_tacos","name":"Smoky Lentil-Walnut Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","nuts"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":180},{"f":"walnuts","q":30},{"f":"tortillas","q":4},{"f":"avocado","q":0.5},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"romaine","q":0.3},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Simmer the lentils in salted water for 20 minutes until tender but not mushy, then drain them well.","Toast the walnuts in a dry skillet for 3 minutes until fragrant, then chop them fine so they mimic the crumble of taco meat.","Heat the olive oil in the same skillet, add the lentils and walnuts with cumin, smoked paprika, and chili powder from the pantry, and fry for 5 minutes, smashing lightly with the spoon, until the mixture is sizzling and crisp in spots.","Warm the tortillas directly over a low flame or in a hot dry pan for 20 seconds a side until soft and lightly charred.","Load each tortilla with the smoky lentil crumble, then top with diced tomato, shredded romaine, sliced onion, avocado, and a decisive squeeze of lime."],"tip":"Smash about a third of the lentils in the pan — the mix of crispy bits and whole ones is what makes people ask for the recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sofritas_tofu_chickpea_burritos', '{"id":"sofritas_tofu_chickpea_burritos","name":"Sofritas-Style Tofu and Chickpea Burritos","emoji":"🌯","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten"],"time":35,"servings":2,"ing":[{"f":"tofu","q":300},{"f":"chickpeas","q":200},{"f":"tortillas","q":4},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"avocado","q":0.5},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Crumble the pressed tofu into rough, craggy pieces with your hands and fry it in olive oil over medium-high heat for 8 minutes until the edges brown and it stops looking pale.","Add the diced onion, garlic, and chopped tomatoes with a heavy pinch of chipotle powder, cumin, and oregano, and cook 5 minutes until the tomatoes break down into a clingy, brick-red sauce.","Stir in the chickpeas, mashing a few against the pan, and simmer 3 minutes until everything is saucy but not wet, then hit it with salt and half the lime.","Warm the tortillas in a dry skillet until soft and steamy, about 20 seconds per side.","Spoon the filling down the center of each tortilla, add sliced avocado and a squeeze of the remaining lime, then fold in the sides and roll them tight, seam-side down."],"tip":"A too-full burrito is a structural failure waiting to happen — leave a modest border and your tortilla will hold the line."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('rosemary_chickpea_penne_e_ceci', '{"id":"rosemary_chickpea_penne_e_ceci","name":"Rosemary Chickpea Penne e Ceci","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"penne","q":160},{"f":"chickpeas","q":480},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"onion","q":0.5},{"f":"spinach","q":100},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5}],"steps":["Warm the olive oil in a wide pan over medium heat and cook the diced onion, sliced garlic, and a sprig of pantry rosemary for 5 minutes until soft and perfumed.","Add the chopped tomatoes and cook them down for 6 to 7 minutes until they slacken into a rustic sauce, then stir in the chickpeas with 250 milliliters of water.","Simmer 10 minutes, mashing about a third of the chickpeas with the back of a spoon so the sauce turns creamy and thick around the whole ones.","Meanwhile, boil the penne in generously salted water until one minute shy of tender, then transfer it into the sauce with a ladleful of starchy pasta water.","Toss over the heat for 2 minutes until the sauce grips every tube, wilt in the spinach, and finish with lemon juice and black pepper."],"tip":"That murky pasta water is liquid gold — it is the difference between sauce that clings and sauce that puddles."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_mushroom_ragu_spaghetti', '{"id":"lentil_mushroom_ragu_spaghetti","name":"Lentil and Mushroom Ragu with Spaghetti","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":50,"servings":2,"ing":[{"f":"spaghetti","q":160},{"f":"lentils_dry","q":180},{"f":"mushrooms","q":200},{"f":"tomato","q":5},{"f":"carrots","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20}],"steps":["Finely dice the onion and carrots and cook them in the olive oil over medium heat for 8 minutes until soft, sweet, and starting to catch color.","Add the finely chopped mushrooms and cook 6 to 7 minutes more until their water evaporates and they brown and squeak against the pan.","Stir in the minced garlic for 1 minute, then add the chopped tomatoes, lentils, 600 milliliters of water, and a pinch of dried oregano.","Simmer gently for 25 minutes, stirring occasionally, until the lentils are tender and the ragu is thick, glossy, and reluctant to fall off the spoon.","Boil the spaghetti in salted water until al dente, then toss it through the ragu with a splash of pasta water and season with salt and plenty of black pepper."],"tip":"Chop the mushrooms almost to a mince — they are doing an impression of ground meat, and small pieces sell the performance."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_edamame_tofu_fried_rice', '{"id":"garlicky_edamame_tofu_fried_rice","name":"Garlicky Edamame and Tofu Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":150},{"f":"edamame_frozen","q":300},{"f":"tofu","q":250},{"f":"carrots","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Cook the rice ahead if you can and spread it on a plate to chill — cold, dry grains fry into separate pearls instead of clumping.","Crumble the tofu into a very hot skillet with the olive oil and fry for 6 minutes, undisturbed at first, until the pieces are golden and crisp-edged.","Add the diced onion, carrots, and garlic and stir-fry 3 minutes until the garlic is fragrant and the carrots have just lost their rawness.","Tip in the rice and edamame, pressing everything flat against the pan for 2 minutes at a time so the rice picks up toasty, crackling spots.","Drizzle the soy sauce around the rim of the pan so it sizzles and caramelizes on the way in, toss well, and finish off the heat with the sesame oil."],"tip":"Fried rice rewards patience and a hot pan — stir less, listen for the crackle, and let the bottom layer toast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_edamame_hotpot_noodle_soup', '{"id":"tofu_edamame_hotpot_noodle_soup","name":"Tofu and Edamame Hot Pot Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":35,"servings":4,"ing":[{"f":"tofu","q":600},{"f":"edamame_frozen","q":300},{"f":"rice_noodles","q":200},{"f":"mushrooms","q":250},{"f":"spinach","q":150},{"f":"garlic","q":0.5},{"f":"soy_sauce","q":60},{"f":"sesame_oil","q":15}],"steps":["Slice the mushrooms and sizzle them with the garlic in the sesame oil in a large pot over medium-high heat for 5 minutes until browned and deeply savory.","Pour in 1.5 liters of water and the soy sauce, bring to a lively simmer, and let the broth take on color and depth for 10 minutes.","Cut the tofu into large 3-centimeter cubes and slide them in gently with the edamame, simmering 5 minutes so the tofu soaks up broth like a sponge.","Add the rice noodles directly to the pot and cook 4 to 5 minutes until they are slippery and tender but still have bite.","Turn off the heat, stir in the spinach until it just wilts, and taste — the broth should be savory enough to sip on its own, so adjust with soy sauce or a splash of water.","Ladle into deep bowls, making sure everyone gets a fair ratio of wobbly tofu to noodles."],"tip":"Simmer the tofu gently rather than boiling it hard — treated kindly, it turns silky; bullied, it turns to rubble."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tuscan_chicken_skillet', '{"id":"creamy_tuscan_chicken_skillet","name":"Creamy Tuscan Chicken Skillet","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"olive_oil","q":15},{"f":"butter","q":25},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"spinach","q":120},{"f":"sour_cream","q":120},{"f":"parmesan","q":40},{"f":"broth","q":120}],"steps":["Pat the chicken breasts dry, season generously with salt, pepper, and dried oregano, then sear in olive oil over medium-high heat for 5 to 6 minutes per side until deeply golden and cooked to 74C; set aside on a plate.","Drop the butter into the same skillet, lower the heat to medium, and cook the sliced garlic for 60 seconds until fragrant but not browned.","Add the diced tomatoes and cook 3 minutes until they slump and release their juices, scraping up the browned bits from the pan bottom.","Pour in the broth, whisk in the sour cream and parmesan, and simmer gently for 3 to 4 minutes until the sauce coats a spoon.","Fold in the spinach a handful at a time until just wilted, then nestle the chicken and any resting juices back in and simmer 2 minutes to reunite everything.","Serve straight from the skillet with extra parmesan and a crack of black pepper on top."],"tip":"Keep the heat gentle after the sour cream goes in, unless you enjoy sauce that looks like it has regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_egg_chicken_cauliflower_soup', '{"id":"lemon_egg_chicken_cauliflower_soup","name":"Silky Lemon-Egg Chicken Soup","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":700},{"f":"broth","q":1500},{"f":"cauliflower","q":0.8},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"eggs","q":3},{"f":"lemon","q":2},{"f":"olive_oil","q":30}],"steps":["Sweat the diced onion and garlic in olive oil in a soup pot over medium heat for 5 minutes until translucent and sweet-smelling.","Add the whole chicken breasts and broth, bring to a bare simmer, and poach 15 minutes until the chicken registers 74C; lift it out and shred it with two forks.","Stir the small cauliflower florets into the simmering broth and cook 8 minutes until just tender when pierced.","Whisk the eggs with the juice of both lemons in a bowl, then temper them by slowly whisking in two ladles of hot broth before streaming the mixture back into the pot off the heat.","Return the shredded chicken, warm gently without boiling until the soup turns pale gold and silky, and season assertively with salt and white pepper.","Ladle into bowls and finish with lemon zest and a thread of olive oil."],"tip":"Temper the eggs patiently — rush it and you have chicken-and-scrambled-egg soup, which is a different, sadder recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('saag_style_chicken_thigh_curry', '{"id":"saag_style_chicken_thigh_curry","name":"Spinach and Yogurt Chicken Thigh Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":500},{"f":"spinach","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"tomato","q":2},{"f":"greek_yogurt","q":150},{"f":"butter","q":20},{"f":"olive_oil","q":15}],"steps":["Brown the bite-size chicken thigh pieces in olive oil over medium-high heat for 5 minutes until golden at the edges, then remove to a bowl.","Melt the butter in the same pan and cook the finely chopped onion for 6 to 7 minutes until deeply golden, then add the minced garlic and ginger with a tablespoon of garam masala, turmeric, and cumin, toasting 60 seconds until the spices smell nutty.","Add the chopped tomatoes and cook 4 minutes, mashing them down until the mixture thickens into a rough, brick-red paste.","Pile in the spinach with a splash of water and let it collapse completely, about 3 minutes, then blitz the sauce roughly with an immersion blender if you like it smooth.","Return the chicken with its juices, simmer 8 to 10 minutes until tender, then stir in the yogurt off the heat one spoonful at a time.","Taste, adjust salt and a pinch of chili, and serve hot."],"tip":"Full-fat yogurt added off the heat stays creamy; cold yogurt into a boiling pot curdles faster than you can say saag."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_paprika_chicken_broccoli', '{"id":"sheet_pan_paprika_chicken_broccoli","name":"Sheet-Pan Paprika Chicken with Charred Broccoli","emoji":"🥦","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":550},{"f":"broccoli","q":400},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"parmesan","q":30}],"steps":["Heat the oven to 220C and toss the chicken thighs with half the olive oil, paprika, minced garlic, salt, and pepper until every piece is rust-colored.","Toss the broccoli florets, thick-sliced bell pepper, and onion wedges with the remaining oil on a large rimmed sheet pan, then nestle the thighs on top so their juices baste the vegetables.","Roast 25 to 28 minutes until the chicken hits 74C and the broccoli tips are crisp and charred at the edges.","Shower the hot pan with grated parmesan and let it melt into a savory crust for 2 minutes in the turned-off oven.","Squeeze the lemon over everything, scrape up the sticky pan juices, and serve straight from the pan."],"tip":"Crowd the pan and you get steamed vegetables; give them elbow room and you get char, which is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_chicken_romaine_caesar_salad', '{"id":"charred_chicken_romaine_caesar_salad","name":"Charred Chicken Romaine Salad with Yogurt Caesar Dressing","emoji":"🥗","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"romaine","q":1},{"f":"greek_yogurt","q":100},{"f":"parmesan","q":40},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20}],"steps":["Butterfly the chicken breasts into thin cutlets, rub with half the olive oil, salt, pepper, and a pinch of cayenne, and sear in a screaming-hot pan for 3 to 4 minutes per side until charred in spots and cooked through.","Rest the chicken 5 minutes on a board so the juices settle, then slice against the grain into ribbons.","Whisk the yogurt with grated garlic, the lemon''s juice and zest, half the parmesan, the remaining olive oil, and enough water to reach a drizzling consistency.","Chop the romaine head into wide ribbons, wash and spin it bone dry, and toss with most of the dressing until every leaf glistens.","Pile the chicken on top, spoon over the last of the dressing, and finish with parmesan shavings and coarse black pepper."],"tip":"Dry lettuce is non-negotiable — dressing slides off wet leaves like rain off a duck."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('yogurt_marinated_chicken_skewers', '{"id":"yogurt_marinated_chicken_skewers","name":"Yogurt-Marinated Chicken Skewers with Cucumber-Feta Salad","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"greek_yogurt","q":150},{"f":"lemon","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"cucumber","q":1},{"f":"feta","q":60}],"steps":["Stir two-thirds of the yogurt with grated garlic, lemon zest, half the lemon''s juice, paprika, cumin, and salt, then massage it into the chicken cubes and marinate at least 20 minutes.","Thread the chicken onto skewers alternating with chunks of bell pepper and onion, leaving small gaps so the heat can circulate.","Grill or broil the skewers close to high heat for 10 to 12 minutes, turning every 3 minutes, until the yogurt crust blisters and blackens in spots and the chicken reaches 74C.","While they cook, toss the diced cucumber with crumbled feta, the remaining lemon juice, olive oil, and plenty of black pepper.","Rest the skewers 3 minutes, then serve over the cucumber salad with the remaining yogurt thinned to a drizzle."],"tip":"The yogurt marinade chars beautifully but burns eagerly, so keep the skewers moving like you owe them money."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_sesame_chicken_stir_fry', '{"id":"ginger_sesame_chicken_stir_fry","name":"Ginger-Sesame Chicken and Broccoli Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"broccoli","q":400},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Slice the chicken into thin strips against the grain and toss with a tablespoon of the soy sauce while you prep the vegetables.","Get a wok or wide skillet ripping hot, add the olive oil, and stir-fry the chicken in two batches for 2 to 3 minutes each until browned but barely cooked through; transfer to a plate.","Add the broccoli florets with a splash of water, cover 2 minutes to steam, then uncover and stir-fry with the sliced mushrooms until the water evaporates and the edges blister.","Push the vegetables aside, fry the minced garlic and ginger in the center for 30 seconds until fragrant, then return the chicken with the remaining soy sauce.","Toss everything hard over high heat for a final minute until glossy, kill the heat, and finish with the sesame oil.","Serve immediately while everything still crackles."],"tip":"Sesame oil is a finishing perfume, not a frying fat — add it at the end or watch it turn bitter."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_broccoli_cheddar_bake_2', '{"id":"chicken_broccoli_cheddar_bake_2","name":"Bubbling Chicken, Broccoli, and Cheddar Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"broccoli","q":400},{"f":"cheddar","q":100},{"f":"sour_cream","q":150},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C and blanch the broccoli florets in salted boiling water for 2 minutes until bright green but still snappy; drain very well.","Cut the chicken into bite-size chunks, season with salt, pepper, and mustard powder, and sear in olive oil over high heat for 3 minutes until golden outside but not cooked through.","Stir the sour cream with the grated garlic, finely diced onion, half the cheddar, and a good grind of pepper to make a loose, tangy binder.","Fold the chicken and broccoli into the sauce, scrape into a small baking dish, and blanket with the remaining cheddar.","Bake 18 to 20 minutes until the top is bronzed and blistered and the sauce bubbles insistently at the edges, then rest 5 minutes before serving."],"tip":"Drain the broccoli like you mean it — watery florets turn a proud casserole into soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('asian_chicken_lettuce_cups', '{"id":"asian_chicken_lettuce_cups","name":"Ginger Chicken Lettuce Cups","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"romaine","q":1},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"lime","q":1}],"steps":["Chop the chicken thighs into a rough mince with a sharp knife, working until the pieces are pea-sized and slightly sticky.","Heat the olive oil in a wide skillet over high heat and fry the chicken undisturbed for 3 minutes to build a browned crust, then break it up and cook 3 minutes more.","Add the finely chopped mushrooms, garlic, and ginger and stir-fry 3 to 4 minutes until the mushrooms give up their water and the pan sizzles dry again.","Splash in the soy sauce and half the lime''s juice, tossing until the filling turns glossy and smells sweet-salty, then finish with the sesame oil off the heat.","Separate the romaine head into sturdy whole leaves, wash and dry them, and pile the hot filling into the cool cups.","Serve with the remaining lime cut into wedges for squeezing at the table."],"tip":"Hot filling, cold crisp leaves — assemble at the table, because a pre-filled lettuce cup wilts faster than your resolve at a bakery."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_chicken_stuffed_peppers', '{"id":"mexican_chicken_stuffed_peppers","name":"Cheesy Chicken-Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"bell_pepper","q":2},{"f":"chicken_breast","q":400},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":80},{"f":"olive_oil","q":15},{"f":"avocado","q":0.5},{"f":"lime","q":1}],"steps":["Heat the oven to 200C, halve the bell peppers through the stem, scoop out the seeds, and roast the empty boats cut-side up for 10 minutes to soften.","Meanwhile, cook the diced onion in olive oil over medium heat for 4 minutes, then add the garlic, cumin, chili powder, and oregano and toast 30 seconds until fragrant.","Add the finely diced chicken and chopped tomatoes and cook 8 to 10 minutes, stirring, until the chicken is cooked through and the mixture is thick and jammy rather than wet.","Pack the filling into the softened pepper halves, top each with cheddar, and bake 12 to 15 minutes until the cheese is molten and freckled brown.","Squeeze lime over the top and crown each pepper with a fan of sliced avocado before serving."],"tip":"Cook the filling until it stops steaming and starts sizzling — a wet filling makes the peppers slump like deflated party balloons."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cacciatore_braise', '{"id":"chicken_cacciatore_braise","name":"Hunter''s Chicken Thigh Braise","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"chicken_thigh","q":900},{"f":"tomato","q":4},{"f":"bell_pepper","q":2},{"f":"mushrooms","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":250},{"f":"olive_oil","q":30}],"steps":["Season the chicken thighs well and brown them in olive oil in a heavy pot over medium-high heat, 4 to 5 minutes per side, until the fat renders and the skillet floor turns amber; set them aside.","Cook the quartered mushrooms in the drippings until their edges brown, about 5 minutes, then add the sliced onion, bell peppers, and garlic and soften 5 minutes more.","Stir in the chopped tomatoes with a teaspoon of dried oregano and a pinch of chili flakes and cook until they break down into a rough sauce, about 5 minutes.","Pour in the broth, scrape up every browned bit, and nestle the thighs back in so they sit shoulder-deep in sauce.","Cover and simmer gently for 25 to 30 minutes until the chicken is spoon-tender and the sauce has thickened to a rustic, clinging gravy.","Taste for salt, rest 5 minutes off the heat, and serve in shallow bowls with the sauce spooned generously over."],"tip":"Brown the thighs properly at the start — that mahogany crust is doing more flavor work than anything you will add later."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_chicken_pepper_chili', '{"id":"smoky_chicken_pepper_chili","name":"Smoky No-Bean Chicken Chili","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"chicken_thigh","q":800},{"f":"tomato","q":4},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":500},{"f":"olive_oil","q":20},{"f":"sour_cream","q":100},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Brown the diced chicken thighs in olive oil in a Dutch oven over high heat for 5 to 6 minutes, working in batches so the meat sears instead of steams.","Lower the heat, add the chopped onion and bell peppers, and cook 5 minutes until softened, then stir in the garlic, paprika, cumin, chili powder, and a pinch of cinnamon, toasting 60 seconds until the pot smells like a taqueria.","Add the chopped tomatoes and broth, scrape the bottom clean, and simmer uncovered for 25 minutes, stirring now and then, until the chili thickens enough to mound on a spoon.","Shred a third of the chicken against the pot wall with two forks to give the chili body, then season boldly with salt and half the lime''s juice.","Ladle into bowls and top each with a dollop of sour cream, sliced avocado, and a wedge of the remaining lime."],"tip":"A pinch of cinnamon in chili is like a good bassline — nobody names it, everybody misses it when it is gone."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('grilled_lime_pork_avocado_salsa', '{"id":"grilled_lime_pork_avocado_salsa","name":"Grilled Lime Pork with Chunky Avocado Salsa","emoji":"🥑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"lime","q":2},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"cucumber","q":0.5}],"steps":["Slice the pork loin into medallions and pound them to an even 2-centimeter thickness, then rub with olive oil, grated garlic, the zest and juice of one lime, cumin, salt, and a whisper of cayenne; let sit 15 minutes.","Meanwhile, dice the avocado, tomatoes, cucumber, and onion into even chunks and toss gently with the second lime''s juice and a pinch of salt so the salsa stays bright and chunky, not mushy.","Grill the pork over direct high heat, or in a smoking-hot grill pan, for 3 to 4 minutes per side until dark grill marks form and the thickest part reaches 63C.","Rest the pork 5 minutes under loose foil so the juices redistribute instead of flooding the cutting board.","Slice on the bias, shingle onto plates, and bury the pork under generous spoonfuls of the avocado salsa."],"tip":"Fifteen minutes in a lime marinade seasons the pork; two hours ceviches it — set a timer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_beef_taco_skillet', '{"id":"mexican_beef_taco_skillet","name":"Smoky Taco Beef Skillet","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"olive_oil","q":10},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"tomato","q":2},{"f":"cheddar","q":60},{"f":"sour_cream","q":40},{"f":"lime","q":1}],"steps":["Heat the olive oil in a wide skillet over medium-high heat until it shimmers, then add the diced onion and bell pepper and cook for 4 minutes until the edges pick up a little char.","Push the vegetables to one side, add the ground beef in a single layer, and let it sear undisturbed for 3 minutes so it develops a deep brown crust before breaking it up.","Season generously with chili powder, cumin, smoked paprika, salt, and pepper, then stir in the chopped tomatoes and simmer for 8 minutes until the juices reduce to a thick, glossy coating.","Kill the heat, scatter the cheddar over the top, and cover for 2 minutes until the cheese melts into molten pockets.","Finish with dollops of sour cream and a hard squeeze of lime, and serve straight from the pan while it still sizzles."],"tip":"The lime is not decoration — that acid is what makes a taco skillet taste like tacos instead of seasoned regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_beef_feta_stuffed_peppers', '{"id":"greek_beef_feta_stuffed_peppers","name":"Greek Beef and Feta Stuffed Peppers","emoji":"🫑","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"ground_beef","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"feta","q":60},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C, halve the peppers through the stem, scoop out the seeds, rub them with a little of the olive oil, and roast cut-side up for 10 minutes to soften.","Meanwhile, brown the ground beef with the diced onion in the remaining oil over medium-high heat for 6 minutes, breaking it into rough crumbles until no pink remains.","Stir in the minced garlic, chopped tomatoes, oregano, salt, and pepper, and simmer 5 minutes until the mixture is juicy but no longer wet.","Fold in the spinach off the heat so it just wilts, then crumble in half the feta and taste for salt.","Mound the filling into the pepper halves, top with the rest of the feta, and bake for 15 minutes until the peppers slump and the feta takes on golden freckles."],"tip":"Pre-roasting the empty peppers is the difference between tender boats and crunchy raw canoes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_beef_zucchini_boats', '{"id":"italian_beef_zucchini_boats","name":"Italian Beef Zucchini Boats","emoji":"🛶","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"zucchini","q":3},{"f":"ground_beef","q":350},{"f":"tomato","q":3},{"f":"garlic","q":0.3},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the seedy centers with a spoon, leaving a sturdy half-centimeter shell; chop the scooped flesh and reserve it.","Brown the ground beef in the olive oil over medium-high heat for 5 minutes until deeply crusted, then add the garlic and reserved zucchini flesh and cook 2 minutes until fragrant.","Add the chopped tomatoes with a big pinch of salt, dried oregano, and chili flakes, and simmer about 8 minutes until the sauce is thick enough to hold its shape on a spoon.","Arrange the zucchini shells in a baking dish, fill them generously with the beef mixture, and blanket with mozzarella and a snow of parmesan.","Bake for 18 to 20 minutes until the cheese is bubbling and bronzed at the edges and a knife slides through the zucchini with no resistance."],"tip":"Scoop the boats with conviction — a flimsy shell collapses under the filling like a bad alibi."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_romaine_wraps', '{"id":"korean_beef_romaine_wraps","name":"Korean-Style Beef Romaine Wraps","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"romaine","q":1},{"f":"cucumber","q":1}],"steps":["Get a large skillet ripping hot, add the ground beef, and press it flat like a giant patty; let it sear for 3 minutes until the underside is mahogany before breaking it apart.","Add the diced onion and minced garlic and stir-fry for 2 minutes until the raw edge cooks off and the kitchen smells unmistakably like dinner.","Pour in the soy sauce and sesame oil with a pinch of chili flakes and black pepper, and toss for 1 minute so every crumble glazes and glistens.","Separate the romaine into whole crisp leaves, wash and shake them dry, and slice the cucumber into thin half-moons.","Pile the hot beef into the cold leaves, top with cucumber, and eat immediately with both hands and zero shame."],"tip":"Dry those romaine leaves thoroughly — hot beef on wet lettuce turns a wrap into a lap event."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_no_bean_beef_chili', '{"id":"smoky_no_bean_beef_chili","name":"Smoky No-Bean Beef Chili","emoji":"🍲","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"ground_beef","q":700},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":6},{"f":"broth","q":500},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a heavy pot over high heat and brown the ground beef in two batches, 4 minutes each, so it sears instead of steams; set it aside with its juices.","Drop the heat to medium, add the diced onion and bell peppers, and cook for 5 minutes until softened and sweet, scraping up the browned bits stuck to the pot.","Stir in the garlic, a heaped spoonful each of chili powder and cumin, smoked paprika, and a pinch of cinnamon, and toast the spices for 60 seconds until they smell dark and toasty.","Return the beef, add the chopped tomatoes and broth, and bring to a lazy simmer.","Cook uncovered for 30 minutes, stirring occasionally, until the chili is thick enough that a spoon dragged through it leaves a brief trail, then season boldly with salt and serve steaming."],"tip":"Chili tastes 20 percent better tomorrow, so make it tonight and take all the credit at lunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_hamburger_vegetable_soup', '{"id":"hearty_hamburger_vegetable_soup","name":"Hearty Hamburger Vegetable Soup","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"zucchini","q":2},{"f":"tomato","q":4},{"f":"spinach","q":150},{"f":"broth","q":1000},{"f":"olive_oil","q":15}],"steps":["Warm the olive oil in a soup pot over medium-high heat and brown the ground beef for 6 minutes, breaking it into bite-size crumbles and letting it crust on the bottom of the pot.","Add the diced onion and cook 4 minutes until translucent, then stir in the garlic, a bay leaf if you have one, dried thyme, salt, and plenty of cracked pepper.","Pour in the broth and chopped tomatoes, scraping the fond off the bottom, and simmer gently for 15 minutes so the flavors marry.","Add the diced zucchini and cook 8 minutes more, just until it is tender but still holds a slight bite.","Stir in the spinach off the heat until it collapses into silky ribbons, taste for salt, and ladle into deep bowls."],"tip":"Under-salt at the start and correct at the end — broth reduces, but your apology to oversalted soup will not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_kofta_with_lemon_yogurt_sauce', '{"id":"beef_kofta_with_lemon_yogurt_sauce","name":"Seared Beef Kofta with Lemon Yogurt Sauce","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"eggs","q":1},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":10}],"steps":["Grate the onion directly into the ground beef, add the minced garlic, egg, a teaspoon of cumin, coriander, salt, and a pinch of cinnamon, and knead for a full minute until the mixture turns tacky and holds together.","Shape into 8 stubby logs, flatten them slightly so they cook evenly, and chill for 10 minutes to firm up.","While they rest, stir the greek yogurt with grated cucumber, lemon zest, half the lemon''s juice, and salt to make a cool, tangy sauce.","Heat the olive oil in a heavy skillet over medium-high and sear the kofta for 3 to 4 minutes per side until deeply browned outside and just cooked through, with clear juices when pressed.","Rest the kofta 3 minutes, then serve over the yogurt sauce with the remaining lemon in wedges."],"tip":"Grate the onion instead of dicing it — the juice seasons every gram of beef and nobody bites into a raw onion cube."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('braised_beef_meatballs_marinara_spinach', '{"id":"braised_beef_meatballs_marinara_spinach","name":"Braised Meatballs in Marinara over Wilted Spinach","emoji":"🧆","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"garlic","q":0.3},{"f":"tomato","q":5},{"f":"olive_oil","q":10},{"f":"spinach","q":150}],"steps":["Mix the ground beef with the egg, two-thirds of the parmesan, one minced garlic clove, dried oregano, salt, and pepper, working it gently just until combined so the meatballs stay tender.","Roll into 10 meatballs with damp hands and brown them in the olive oil over medium-high heat for 5 minutes, turning until crusted on most sides but still raw inside.","Add the remaining garlic to the pan for 30 seconds, then tip in the chopped tomatoes with a pinch of chili flakes and salt, and bring to a simmer.","Cover and braise the meatballs in the sauce for 12 minutes over low heat, turning once, until they are cooked through and the sauce has thickened around them.","Pile the spinach into the pan and fold it through the hot sauce until just wilted, then serve showered with the last of the parmesan."],"tip":"Damp hands and a light touch make tender meatballs — squeeze them like stress balls and they will chew like them too."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_cheeseburger_bowl', '{"id":"loaded_cheeseburger_bowl","name":"Loaded Cheeseburger Bowl","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"cheddar","q":50},{"f":"romaine","q":1},{"f":"tomato","q":2},{"f":"cucumber","q":0.5},{"f":"onion","q":0.3},{"f":"avocado","q":1},{"f":"sour_cream","q":40}],"steps":["Season the ground beef with salt, pepper, and a pinch of smoked paprika, then sear it in a dry hot skillet for 5 to 6 minutes, pressing it into craggy crumbles that brown hard at the edges.","Turn off the heat, scatter the cheddar over the beef, and cover for 1 minute so it melts into the crevices.","While the beef cooks, chop the romaine into ribbons and divide between two wide bowls, then top with diced tomatoes, thin cucumber half-moons, and slivered raw onion.","Whisk the sour cream with a splash of water, a dab of mustard if you like, salt, and pepper into a pourable burger-style dressing.","Spoon the hot cheesy beef over the cold crunchy salad, fan the avocado on top, and drizzle everything with the dressing."],"tip":"Hot beef on cold romaine is the whole trick — assemble at the last second or you are eating warm salad, which is soup''s saddest cousin."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_beef_broccoli_stir_fry', '{"id":"sesame_beef_broccoli_stir_fry","name":"Sesame Ground Beef and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"broccoli","q":400},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Cut the broccoli into small florets, then stir-fry it in the olive oil over high heat for 3 minutes until the edges blister and char in spots.","Splash in a few tablespoons of water and cover for 2 minutes so the broccoli steams to bright green and crisp-tender, then tip it out onto a plate.","Add the ground beef to the empty pan and sear hard for 4 minutes, breaking it up only after the first side crusts deeply.","Stir in the minced garlic and cook 30 seconds until fragrant, then return the broccoli with the soy sauce and a pinch of chili flakes and toss for 1 minute until everything is glazed.","Kill the heat, drizzle with the sesame oil, and serve immediately while the pan still hisses."],"tip":"Sesame oil is a finisher, not a cooking fat — add it at the end or its perfume burns off before dinner hits the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheesy_beef_broccoli_bake', '{"id":"cheesy_beef_broccoli_bake","name":"Cheesy Beef and Broccoli Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"broccoli","q":350},{"f":"cheddar","q":70},{"f":"eggs","q":2},{"f":"sour_cream","q":60},{"f":"onion","q":0.5}],"steps":["Heat the oven to 190C and brown the ground beef with the diced onion in a skillet over medium-high heat for 6 minutes, seasoning with salt, pepper, and garlic powder as it crumbles.","Steam the broccoli florets for 3 minutes until just shy of tender and vividly green, then drain them well so the bake does not go watery.","Whisk the eggs with the sour cream, a pinch of salt, and half the cheddar until smooth.","Fold the beef and broccoli together in a small baking dish, pour the egg mixture over, and top with the remaining cheddar.","Bake for 20 to 22 minutes until the custard is set at the center with the barest wobble and the cheese cap is bronzed and bubbling; rest 5 minutes before scooping."],"tip":"Drain the broccoli like you mean it — hidden steam water is how casseroles turn into disappointing stews."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_keema_with_spinach', '{"id":"beef_keema_with_spinach","name":"Beef Keema with Spinach","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":3},{"f":"spinach","q":200},{"f":"olive_oil","q":20}],"steps":["Heat the olive oil in a deep skillet over medium heat and cook the finely diced onion for 8 patient minutes until golden brown at the edges — this is the backbone of the dish, so do not rush it.","Add the minced garlic with a teaspoon each of garam masala, cumin, and turmeric plus a pinch of chili, and fry the spices for 45 seconds until they darken and bloom.","Raise the heat, add the ground beef, and cook for 6 minutes, mashing and stirring until it browns in fine, even crumbles.","Stir in the chopped tomatoes with a good pinch of salt and simmer for 10 minutes until the oil separates and beads at the edges of the pan, the classic sign a keema is ready.","Fold in the spinach in handfuls until it wilts into the spiced beef, then taste, adjust the salt, and serve hot."],"tip":"When the oil visibly splits from the masala, the keema is done arguing with you — not a minute before."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lime_pork_larb_style_salad', '{"id":"lime_pork_larb_style_salad","name":"Lime-Blasted Pork Larb-Style Salad","emoji":"🥗","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"lime","q":2},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":5},{"f":"olive_oil","q":10}],"steps":["Slice the onion into paper-thin slivers and soak them in the juice of half a lime with a pinch of salt so they pickle lightly while you cook.","Slice the pork loin thin, then chop it into a rough hand-minced crumble with a heavy knife, the traditional larb texture that no grinder quite matches.","Sear the pork in the olive oil in a very hot skillet for 5 to 6 minutes, tossing occasionally, until the crumbles are cooked through and crisping at the edges rather than stewing.","Off the heat, dress the hot pork with the soy sauce, sesame oil, the juice of the remaining lime and a half, and a generous pinch of chili flakes — it should taste bright, salty, and a little fierce.","Chop the romaine into bite-size pieces, slice the cucumber thin, and spread them over a platter as a cool bed, then tumble the warm dressed pork and pickled onions over the top and toss once at the table."],"tip":"Taste the pork after dressing and add lime until you flinch slightly — larb lives one squeeze past polite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('herb_roasted_pork_loin_green_beans', '{"id":"herb_roasted_pork_loin_green_beans","name":"Garlic-Herb Roasted Pork Loin with Blistered Green Beans","emoji":"🍖","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":60,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"green_beans","q":300},{"f":"olive_oil","q":30},{"f":"garlic","q":0.4},{"f":"lemon","q":1}],"steps":["Heat the oven to 200C and pat the pork loin bone-dry, then rub it all over with half the olive oil, the minced garlic, salt, and plenty of cracked pepper.","Sear the loin in a hot ovenproof skillet for 3 minutes per side until it wears a deep mahogany crust.","Scatter the green beans around the pork, toss them in the remaining oil, and roast for 20 to 25 minutes until the meat reads 63C at the center and the beans are blistered and squeaky-tender.","Rest the pork under foil for 10 full minutes so the juices settle back into the meat instead of onto your cutting board.","Slice against the grain into thick coins, squeeze the lemon over everything, and serve with the pan drippings spooned on top."],"tip":"A resting pork loin is like a toddler at bedtime — disturb it early and everyone ends up in tears."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smothered_pork_medallions_mushrooms', '{"id":"smothered_pork_medallions_mushrooms","name":"Smothered Pork Medallions in Mushroom-Sour Cream Gravy","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"mushrooms","q":300},{"f":"butter","q":25},{"f":"sour_cream","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":150},{"f":"spinach","q":100}],"steps":["Slice the pork loin into 2.5-centimeter medallions, season generously, and sear in half the butter over medium-high heat for 2 to 3 minutes per side until golden; move them to a plate.","Melt the remaining butter in the same skillet and cook the sliced mushrooms and onion undisturbed for 5 minutes until they release their liquid and turn deeply browned at the edges.","Stir in the garlic for 30 seconds until fragrant, then pour in the broth and scrape up every browned bit stuck to the pan.","Lower the heat, whisk in the sour cream until the gravy is silky, and wilt in the spinach.","Return the medallions and their juices to the pan and simmer gently for 3 minutes until the pork reads 63C and the sauce clings to every piece."],"tip":"Add the sour cream off a rolling boil, not into one — curdled gravy has ended friendships."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_broccoli_stir_fry', '{"id":"ginger_pork_broccoli_stir_fry","name":"Ginger-Garlic Pork and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"broccoli","q":400},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":15}],"steps":["Slice the pork loin against the grain into thin strips and toss with a tablespoon of the soy sauce while you prep everything else.","Get a wok or wide skillet screaming hot with the olive oil, then sear the pork in a single layer for 2 minutes per side until browned but still juicy; scoop it out.","Stir-fry the broccoli florets in the same pan for 3 minutes, splashing in two tablespoons of water and covering briefly so they steam to a vivid, crisp-tender green.","Add the minced garlic and ginger and toss for 30 seconds until the pan smells sharp and fragrant.","Return the pork, pour in the remaining soy sauce and the sesame oil, and toss everything for a final minute until glossy and sizzling."],"tip":"Crowd the pan and you are steaming, not stir-frying — cook the pork in two batches if it starts to sweat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_pork_kale_soup', '{"id":"tuscan_pork_kale_soup","name":"Tuscan Pork and Kale Soup with Parmesan","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"pork_loin","q":600},{"f":"kale","q":1},{"f":"mushrooms","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":1250},{"f":"olive_oil","q":30},{"f":"parmesan","q":60}],"steps":["Cut the pork loin into bite-size cubes, season well, and brown them in the olive oil in a heavy pot over medium-high heat for 5 to 6 minutes until crusty on at least two sides.","Add the diced onion and sliced mushrooms and cook for 5 minutes, stirring, until the onion turns translucent and the mushrooms squeak then soften.","Stir in the garlic for 30 seconds, pour in the broth, and scrape the flavorful fond off the bottom of the pot.","Simmer gently for 20 minutes until the pork is tender and the broth has taken on a deep savory color.","Stir in the torn kale and simmer 5 more minutes until it collapses to silky ribbons, then ladle into bowls and shower each with grated parmesan."],"tip":"Save the parmesan rind if you have one lurking in the fridge — dropped into the simmering pot, it is free umami."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_pork_souvlaki_skewers', '{"id":"mediterranean_pork_souvlaki_skewers","name":"Lemon Pork Skewers with Charred Vegetables and Yogurt Sauce","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"zucchini","q":1},{"f":"olive_oil","q":45},{"f":"lemon","q":2},{"f":"greek_yogurt","q":150},{"f":"garlic","q":0.2}],"steps":["Cube the pork loin into 3-centimeter chunks and marinate for 15 minutes in two-thirds of the olive oil, the juice of one lemon, one grated garlic clove, salt, and dried oregano if your pantry allows.","Thread the pork onto skewers alternating with chunks of bell pepper, onion, and zucchini, brushing the vegetables with the remaining oil.","Grill or broil on high for 12 to 14 minutes, turning every 3 to 4 minutes, until the edges char and the pork reads 63C at its thickest cube.","Meanwhile stir the greek yogurt with the remaining garlic, a squeeze of lemon, and a pinch of salt into a quick, tangy sauce.","Rest the skewers for 5 minutes, then serve piled over the sauce with the last lemon cut into wedges for squeezing."],"tip":"Soak wooden skewers for 20 minutes first, unless you enjoy serving dinner on tiny torches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_spinach_pork_curry', '{"id":"creamy_spinach_pork_curry","name":"Creamy Spinach and Ginger Pork Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"spinach","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"butter","q":30},{"f":"greek_yogurt","q":150},{"f":"lemon","q":1}],"steps":["Melt the butter in a deep skillet over medium heat and cook the finely chopped onion for 6 to 8 minutes until soft and golden at the edges.","Add the minced garlic and ginger with a generous spoonful of curry spices and toast for 1 minute until the kitchen smells unmistakably like dinner.","Add the cubed pork loin and sear for 4 to 5 minutes, turning to coat every piece in the spiced butter.","Pile in the spinach in handfuls, letting each batch wilt down glossy and dark before adding the next, then splash in a few tablespoons of water and simmer covered for 10 minutes until the pork is just cooked through.","Off the heat, stir in the greek yogurt a spoonful at a time until the sauce turns pale and creamy, then brighten with lemon juice and salt to taste."],"tip":"Temper the yogurt off the heat or it will split faster than a bad band."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_carnitas_lettuce_cups', '{"id":"pork_carnitas_lettuce_cups","name":"Crispy Pork Carnitas Lettuce Cups with Avocado and Lime","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"romaine","q":1},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"onion","q":1},{"f":"cilantro","q":0.3},{"f":"sour_cream","q":60},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into small cubes, season aggressively with salt, cumin, and the juice of one lime, and let it sit for 10 minutes.","Simmer the pork with half the onion and a splash of water in a covered skillet over medium-low heat for 20 minutes until fork-tender.","Uncover, raise the heat, add the olive oil, and fry the pork for 6 to 8 minutes, pressing pieces against the pan until the edges crackle and turn deep golden brown.","Separate the romaine into sturdy cup-shaped leaves, wash, and pat completely dry so they stay crisp.","Pile the crispy pork into the leaves and top with diced avocado, the remaining onion finely minced, torn cilantro, a smear of sour cream, and wedges of the second lime."],"tip":"The fry-after-braise step is not optional — soft carnitas without crispy edges is just sad boiled pork."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_broccoli_cheddar_frittata', '{"id":"bacon_broccoli_cheddar_frittata","name":"Bacon, Broccoli, and Sharp Cheddar Frittata","emoji":"🍳","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":8},{"f":"bacon","q":120},{"f":"broccoli","q":250},{"f":"cheddar","q":60},{"f":"onion","q":1},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and cook the chopped bacon in an ovenproof skillet over medium heat for 6 to 8 minutes until crisp, then lift it out, leaving the fat behind.","Add the olive oil, diced onion, and small broccoli florets to the skillet and cook for 5 minutes until the broccoli is bright green and just tender at the tip of a knife.","Whisk the eggs with a big pinch of salt until uniformly yellow and slightly frothy, then stir in most of the cheddar and the crisped bacon.","Pour the eggs over the vegetables, shake the pan to settle everything, and cook undisturbed for 2 minutes until the edges begin to set.","Scatter the remaining cheddar on top and bake for 10 to 12 minutes until the center is puffed and barely jiggles; rest 5 minutes before cutting into wedges."],"tip":"Pull it when the middle still wobbles slightly — a frittata keeps cooking out of the oven and overbaked eggs bounce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_bacon_romaine_salad', '{"id":"warm_bacon_romaine_salad","name":"Warm Bacon Dressing Romaine Salad with Jammy Eggs","emoji":"🥗","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"bacon","q":150},{"f":"romaine","q":2},{"f":"eggs","q":4},{"f":"avocado","q":1},{"f":"parmesan","q":30},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then shock them in ice water so the yolks stay glossy and jammy; peel and halve.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until deeply crisp, then pull the pan off the heat, keeping every drop of fat.","Whisk the lemon juice and olive oil straight into the warm bacon fat with cracked pepper to make a smoky, tangy dressing.","Chop the romaine into wide ribbons, wash, and spin thoroughly dry so the warm dressing clings instead of sliding off.","Toss the leaves with the warm dressing and bacon, then top with sliced avocado, the halved eggs, and thick shavings of parmesan."],"tip":"Dress the romaine seconds before serving — warm bacon fat waits for no one and neither does crisp lettuce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_bacon_chowder', '{"id":"cauliflower_bacon_chowder","name":"Smoky Cauliflower and Bacon Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"bacon","q":200},{"f":"cauliflower","q":1.3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":750},{"f":"milk","q":250},{"f":"cheddar","q":80},{"f":"butter","q":20}],"steps":["Cook the chopped bacon in a heavy pot over medium heat for 8 minutes until crisp, then set it aside on paper towels, leaving two tablespoons of fat in the pot.","Add the butter, diced onion, and garlic and cook for 4 minutes until soft and fragrant, scraping up the bacon-browned bits.","Add the cauliflower florets and broth, bring to a lively simmer, and cook for 15 minutes until a fork slides through the stems with no resistance.","Blend half the pot until completely smooth and stir it back in with the milk, giving the chowder body while leaving satisfying chunks.","Stir in the cheddar off the boil until melted and velvety, season with salt and pepper, and serve each bowl crowned with the reserved crispy bacon."],"tip":"Blending only half the pot is the whole trick — all-smooth is baby food, all-chunky is just soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ribbon_carbonara_bacon', '{"id":"zucchini_ribbon_carbonara_bacon","name":"Zucchini Ribbon Carbonara with Crispy Bacon","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"bacon","q":150},{"f":"zucchini","q":3},{"f":"eggs","q":3},{"f":"parmesan","q":60},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Shave the zucchini into long ribbons with a vegetable peeler, salt them lightly, and let them sit in a colander for 10 minutes to weep out excess water; pat dry.","Whisk the eggs with the grated parmesan and an indecent amount of black pepper until the mixture looks like thick paint.","Cook the chopped bacon in the olive oil over medium heat for 7 to 8 minutes until crisp, then add the sliced garlic for 30 seconds.","Toss the zucchini ribbons in the hot pan for just 90 seconds until barely tender but still holding a slight bite.","Kill the heat, wait 30 seconds, then pour in the egg mixture and toss constantly for a minute until it thickens into a glossy sauce that coats every ribbon; serve immediately with more parmesan."],"tip":"Residual heat makes the sauce; direct heat makes scrambled eggs with vegetables — know the difference."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_bacon_cabbage_stir_fry', '{"id":"sesame_bacon_cabbage_stir_fry","name":"Sesame-Ginger Bacon and Cabbage Stir-Fry","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free"],"allergens":["gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"bacon","q":200},{"f":"cabbage","q":0.7},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cut the bacon into thick lardons and render them in a wok over medium heat for 6 to 7 minutes until crisp and golden; scoop them out, leaving the fat.","Crank the heat to high, add the minced garlic and ginger to the bacon fat, and stir for 20 seconds until they sizzle and perfume the kitchen.","Add the roughly chopped cabbage in two big handfuls and stir-fry for 5 to 6 minutes until the edges char in spots but the ribs stay crunchy.","Splash in the soy sauce and let it hiss and reduce around the cabbage for 30 seconds.","Return the bacon, drizzle with the sesame oil, toss once, and serve piping hot with extra cracked pepper."],"tip":"Charred-but-crunchy is the goal — cabbage cooked past its snap goes from stir-fry to soggy regret in about a minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_salmon_asparagus', '{"id":"sheet_pan_salmon_asparagus","name":"Sheet-Pan Lemon-Garlic Salmon with Asparagus","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"asparagus","q":400},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425F and line a sheet pan while you snap the woody ends off the asparagus.","Toss the asparagus with half the olive oil, minced garlic, salt, and pepper, then spread it in a single layer so it roasts instead of steams.","Rub the salmon fillets with the remaining oil, paprika, salt, and pepper, and nestle them skin-side down among the spears.","Roast for 12 to 14 minutes, until the asparagus tips crisp at the edges and the salmon flakes when nudged with a fork but still looks glossy in the center.","Squeeze the lemon over everything while the pan is still hot so the juice sizzles and loosens the browned bits, then serve straight from the pan."],"tip":"Thicker fillets need the full 14 minutes; skinny tail pieces are done at 10, so tuck the thin ends under themselves to even the odds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_zoodle_piccata_skillet', '{"id":"salmon_zoodle_piccata_skillet","name":"Salmon Piccata Skillet with Zucchini Noodles","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"zucchini","q":2},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":25},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Spiralize or julienne the zucchini into noodles, salt them lightly, and let them drain in a colander while you cook the fish.","Season the salmon and sear it in olive oil over medium-high heat, 4 minutes on the skin side until it crackles and releases easily, then 2 minutes on the flesh side; move it to a plate.","Drop the butter and sliced garlic into the same skillet and swirl until the butter foams and smells nutty, about 1 minute.","Add the lemon juice and the zoodles and toss for just 2 minutes, until they bend without snapping but have not gone watery.","Return the salmon to the pan, shower everything with parmesan and chopped parsley, and serve while the sauce still clings."],"tip":"Two minutes is a promise, not a suggestion — zoodles go from al dente to soup faster than you can find the tongs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_ginger_salmon_stirfry', '{"id":"sesame_ginger_salmon_stirfry","name":"Sesame-Ginger Salmon and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"broccoli","q":350},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"scallions","q":1}],"steps":["Cut the salmon into 4-centimeter chunks and pat them bone dry so they sear instead of stew.","Get a wok or wide skillet ripping hot with the olive oil, then sear the salmon pieces undisturbed for 2 minutes per side until bronzed; lift them out gently.","Stir-fry the broccoli florets and sliced bell pepper with a splash of water for 3 to 4 minutes, until the broccoli turns vivid green and the edges char slightly.","Push the vegetables aside, sizzle the grated ginger and garlic for 30 seconds until fragrant, then pour in the soy sauce and sesame oil.","Slide the salmon back in, toss once or twice to glaze without breaking the chunks, and finish with sliced scallions."],"tip":"Treat the salmon like it owes you money and leave it alone in the pan — poking is what turns chunks into flakes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_salmon_spinach', '{"id":"coconut_curry_salmon_spinach","name":"Coconut Curry Salmon with Wilted Spinach","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"coconut_milk","q":250},{"f":"spinach","q":150},{"f":"onion","q":0.5},{"f":"olive_oil","q":10},{"f":"curry_powder","q":6},{"f":"turmeric","q":2},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":3}],"steps":["Soften the diced onion in olive oil over medium heat for 4 minutes, until translucent and sweet-smelling.","Add the grated ginger, minced garlic, curry powder, and turmeric and toast for 1 minute, stirring so the spices bloom without scorching.","Pour in the coconut milk, bring it to a gentle simmer, and season with salt; the sauce should be the color of marigolds.","Slip in the salmon cut into large chunks and poach at a bare simmer for 6 to 8 minutes, until the pieces turn opaque and just flake.","Fold in the spinach by the handful until it collapses, then brighten the pot with lime juice and torn cilantro before serving."],"tip":"A bare simmer means lazy bubbles, not a rolling boil — boiled salmon is how curries end up with fish confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_cauliflower_chowder', '{"id":"salmon_cauliflower_chowder","name":"Creamy Salmon and Cauliflower Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":40,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"cauliflower","q":0.5},{"f":"onion","q":1},{"f":"celery","q":80},{"f":"broth","q":750},{"f":"milk","q":300},{"f":"butter","q":25},{"f":"garlic","q":0.3},{"f":"oregano","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Melt the butter in a soup pot and sweat the diced onion and celery over medium heat for 5 minutes, until soft but not browned.","Add the garlic and oregano, cook for 30 seconds, then tip in the cauliflower florets and the broth and simmer for 12 minutes, until a knife slides through the stems.","Ladle a third of the pot into a blender, puree until silky, and stir it back in to thicken the chowder without a speck of flour.","Pour in the milk, drop in the salmon cut into bite-size chunks, and poach gently for 6 minutes, until the fish turns pale pink and opaque.","Season generously with salt and black pepper, taste, and serve steaming, with the chunks intact and the broth just coating a spoon."],"tip":"Once the milk goes in, keep the heat below a boil unless you enjoy chowder that looks like it has already been eaten."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_taco_lettuce_cups', '{"id":"salmon_taco_lettuce_cups","name":"Chili-Lime Salmon Taco Lettuce Cups","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"salsa","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"salt","q":3}],"steps":["Rub the salmon all over with olive oil, chili powder, cumin, and salt until it wears a brick-red crust of spices.","Sear it in a hot skillet for 4 minutes on the first side and 3 on the second, until the spice crust darkens and the center flakes into big rosy petals.","While the fish rests, separate the romaine into sturdy cup-shaped leaves and mash the avocado with lime juice and a pinch of salt.","Break the salmon into chunky flakes with a fork, tasting one for quality-control purposes.","Swipe avocado into each leaf, pile on the warm salmon, spoon over salsa, and finish with cilantro and a final squeeze of lime."],"tip":"Use the inner romaine leaves for cups and save the floppy outer ones for tomorrow''s salad — structural integrity matters when dinner is handheld."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salmon_romaine_salad', '{"id":"greek_salmon_romaine_salad","name":"Seared Salmon Greek Salad with Feta and Olives","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"oregano","q":2},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Whisk the lemon juice with the olive oil, oregano, salt, and pepper until the dressing turns cloudy and thick.","Chop the romaine into ribbons, halve the cherry tomatoes, and cut the cucumber into chunky half-moons, then toss them in a wide bowl with most of the dressing.","Season the salmon and sear it in a hot, lightly oiled skillet for 4 minutes skin-side down, until the skin is shatteringly crisp, then flip for 2 minutes more.","Let the fish rest for 2 minutes so the juices settle, then break it into large warm flakes over the cold, crunchy salad.","Scatter the feta and olives on top, drizzle with the last of the dressing, and grind over black pepper at the table."],"tip":"Warm fish on cold crunchy salad is the whole trick here, so dress the greens before you even think about flipping the salmon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_glazed_salmon_cauli_rice_bowl', '{"id":"soy_glazed_salmon_cauli_rice_bowl","name":"Soy-Glazed Salmon Cauliflower Rice Bowls","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"cauliflower","q":0.5},{"f":"edamame_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"scallions","q":1}],"steps":["Pulse the cauliflower florets in a food processor until they look like rice, stopping before they turn to snow.","Sear the salmon fillets in olive oil over medium-high heat, 4 minutes skin-side down and 2 on the flesh, then pour in the soy sauce with the grated ginger and half the garlic and spoon the bubbling glaze over the fish for 1 minute until lacquered.","Move the salmon to a plate and wipe the pan, then stir-fry the cauliflower rice with the remaining garlic and the edamame over high heat for 4 to 5 minutes, until dry, fluffy, and toasted in spots.","Season the rice with the sesame oil and a spoonful of the leftover glaze from the fish plate.","Divide the cauliflower rice between bowls, perch a glazed fillet on each, and shower with sliced scallions."],"tip":"Wet cauliflower rice is sad cauliflower rice — keep the heat high and resist crowding the pan so it toasts instead of steams."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_parmesan_frittata', '{"id":"salmon_spinach_parmesan_frittata","name":"Salmon, Spinach, and Parmesan Frittata","emoji":"🍳","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"salmon","q":250},{"f":"spinach","q":100},{"f":"parmesan","q":30},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 375F and whisk the eggs with the parmesan, salt, and pepper until uniformly pale yellow.","In an ovenproof skillet, soften the diced onion in olive oil for 4 minutes, then wilt in the spinach until it hisses down to almost nothing.","Add the salmon cut into small cubes and cook for 2 minutes, just until the outsides blush opaque.","Pour the eggs over everything, drag a spatula through twice to distribute the filling, and cook undisturbed for 3 minutes until the edges set.","Transfer the skillet to the oven for 8 to 10 minutes, until the center is puffed and barely jiggles, then rest 5 minutes and slide it out with torn basil on top."],"tip":"Pull it while the middle still wobbles like it is nervous — carryover heat finishes the job and rubbery frittata has no defenders."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('walnut_crusted_salmon_green_beans', '{"id":"walnut_crusted_salmon_green_beans","name":"Walnut-Crusted Salmon with Blistered Green Beans","emoji":"🌿","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","nuts","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"walnuts","q":40},{"f":"parmesan","q":20},{"f":"green_beans","q":350},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 400F and chop the walnuts fine, then mix them with the grated parmesan, minced garlic, chopped parsley, lemon zest, and a spoonful of olive oil into a damp, sandy paste.","Season the salmon, set it on a lined sheet pan, and press the walnut mixture onto the flesh in an even cap.","Toss the green beans with the remaining oil, salt, and pepper and scatter them around the fish.","Roast for 12 to 15 minutes, until the crust turns deep golden and smells like toasted nuts and the beans blister and wrinkle at the tips.","Squeeze the lemon over the beans and serve, crust-side proudly up."],"tip":"Press the crust on like you mean it — a timid pat is how half your walnuts end up seasoning the sheet pan instead of the salmon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_style_salmon_skewers', '{"id":"tandoori_style_salmon_skewers","name":"Tandoori-Style Salmon Skewers with Cucumber Salad","emoji":"🔥","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"greek_yogurt","q":120},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"paprika","q":3},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"cucumber","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Stir two-thirds of the yogurt with the garam masala, turmeric, paprika, grated ginger, garlic, half the lemon juice, and salt into a marinade the color of a sunset.","Cut the salmon into large cubes, coat them in the marinade, and let them sit for 15 minutes while the broiler heats on high.","Thread the cubes onto skewers, brush with olive oil, and broil on a foil-lined pan for 8 to 10 minutes, turning once, until the edges char and the yogurt coating develops smoky dark spots.","Meanwhile, dice the cucumber and toss it with the remaining yogurt, lemon juice, chopped cilantro, and a pinch of salt for a cooling raita-style salad.","Serve the blistered skewers hot over the cold cucumber salad, with any pan juices drizzled on top."],"tip":"Char is the flavor here, so park the pan close to the broiler and let a few corners go properly black before you lose your nerve."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_glazed_salmon_roasted_veg', '{"id":"balsamic_glazed_salmon_roasted_veg","name":"Balsamic-Glazed Salmon with Roasted Eggplant and Tomatoes","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"balsamic_vinegar","q":40},{"f":"eggplant","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425F, cube the eggplant, and roast it with the cherry tomatoes, olive oil, salt, and pepper for 20 minutes, until the eggplant is creamy inside and the tomatoes burst.","While the vegetables roast, simmer the balsamic vinegar with the minced garlic in a small skillet for 3 to 4 minutes, until it reduces to a syrup that coats the back of a spoon.","Season the salmon and sear it in a hot skillet, 4 minutes on the skin side until crisp and 2 on the flesh side.","Brush the fillets generously with the balsamic glaze and let them sit in the warm pan for 1 minute so the syrup sets into a shiny lacquer.","Pile the roasted vegetables onto plates, top with the glazed salmon, and finish with torn basil and any stray glaze."],"tip":"Watch the reducing balsamic like a hawk in its final minute — the line between glaze and pan candy is about thirty seconds wide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_stuffed_bell_peppers', '{"id":"salmon_stuffed_bell_peppers","name":"Mexican Salmon-Stuffed Bell Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":2,"ing":[{"f":"bell_pepper","q":2},{"f":"salmon","q":300},{"f":"cauliflower","q":0.3},{"f":"salsa","q":120},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"cumin","q":3},{"f":"chili_powder","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":3}],"steps":["Heat the oven to 400F, halve the bell peppers through the stem, scoop out the seeds, and roast the empty halves cut-side up for 10 minutes to give them a head start.","Pulse the cauliflower into rice and saute it in olive oil over high heat for 4 minutes with the cumin, chili powder, and salt, until fragrant and lightly toasted.","Stir in the salmon cut into small cubes and the salsa, and cook for 2 minutes, just until the fish starts to turn opaque at the edges.","Mound the filling into the softened pepper halves, cap each with cheddar, and bake for 15 minutes, until the cheese bubbles and browns at the edges and the peppers slump agreeably.","Rest for 5 minutes, then finish with lime juice and chopped cilantro before serving two halves per person."],"tip":"Undercook the salmon filling on the stove — it finishes in the oven, and nobody has ever complained that their stuffed pepper was too juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_zoodles', '{"id":"shrimp_scampi_zoodles","name":"Shrimp Scampi Zoodles","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"zucchini","q":2},{"f":"butter","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":30},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Shave the zucchini into long ribbons with a vegetable peeler, salt them lightly, and let them drain in a colander while you cook so they stay springy instead of soggy.","Pat the shrimp bone-dry, season with salt and pepper, and sear them in the olive oil over medium-high heat for about 90 seconds per side, until they curl into loose commas and pick up golden edges; move them to a plate.","Drop the heat to medium, melt the butter in the same skillet, and stir in the sliced garlic for 60 seconds, just until it smells sweet and toasty but hasn''t browned.","Squeeze in the lemon juice, scrape up the browned bits, and return the shrimp along with any juices, tossing to glaze them in the pan sauce.","Add the zucchini ribbons and toss for one to two minutes only, until barely warmed and glossy, then shower with grated parmesan, chopped parsley, and a final crack of black pepper before serving straight from the skillet."],"tip":"Zoodles keep cooking in the residual heat, so pull the pan off the burner the moment they bend without snapping — limp zoodles have no second act."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_sheet_pan_shrimp_peppers', '{"id":"smoky_sheet_pan_shrimp_peppers","name":"Smoky Sheet-Pan Shrimp and Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"zucchini","q":1},{"f":"olive_oil","q":30},{"f":"chili_powder","q":4},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"avocado","q":1},{"f":"salt","q":3}],"steps":["Heat the oven to 230°C (450°F) with a large rimmed sheet pan inside so the vegetables hit hot metal and sizzle on contact.","Slice the peppers and onion into finger-width strips, halve the zucchini into thick half-moons, and toss everything with two-thirds of the oil, half the chili powder, the cumin, paprika, and a good pinch of salt.","Spread the vegetables on the hot pan in a single layer and roast for 12 to 14 minutes, until the pepper edges char and the onions turn silky.","Meanwhile toss the shrimp with the remaining oil and spices, then scatter them over the vegetables and roast 5 to 6 minutes more, just until the shrimp turn opaque pink and snap back when pressed.","Squeeze the lime over the whole pan while it''s still steaming, then top with sliced avocado and torn cilantro and serve right off the sheet."],"tip":"Crowded shrimp steam instead of roast, so if your pan looks like rush hour, evict the vegetables to the edges first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup', '{"id":"coconut_lime_shrimp_soup","name":"Coconut-Lime Shrimp Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"coconut_milk","q":400},{"f":"broth","q":1000},{"f":"mushrooms","q":250},{"f":"zucchini","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Warm the oil in a soup pot over medium heat and sweat the sliced ginger, minced garlic, and scallion whites for two minutes, until the kitchen smells sharp and citrusy.","Add the sliced mushrooms and cook 4 to 5 minutes, stirring, until they release their liquid and it evaporates, leaving them browned at the edges.","Pour in the broth and coconut milk, season with salt, and bring to a bare simmer — small bubbles at the edge, never a rolling boil, or the coconut milk will split.","Slide in the zucchini half-moons and simmer 4 minutes until just tender, then add the shrimp and cook 2 to 3 minutes more, until they blush pink and curl.","Kill the heat, squeeze in the juice of both limes, and taste — it should be rich, salty, and bright in equal measure — then ladle into bowls and bury each under cilantro and scallion greens."],"tip":"Lime juice goes in off the heat or it turns bitter and sulky, much like anyone else who gets boiled."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_roll_in_a_bowl', '{"id":"shrimp_egg_roll_in_a_bowl","name":"Shrimp Egg Roll in a Bowl","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["shellfish","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":100},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Get a wok or your widest skillet screaming hot over high heat, add the olive oil, and stir-fry the shrimp for about two minutes, until pink and just barely cooked; scoop them out and set aside.","Add the minced garlic and ginger to the pan and stir for 30 seconds, until fragrant but not browned.","Pile in the shredded cabbage and grated carrots and stir-fry 4 to 5 minutes, tossing constantly, until the cabbage collapses to half its volume but still keeps a little crunch at its core.","Splash in the soy sauce, letting it hiss and reduce against the hot metal for a minute so it coats rather than puddles.","Return the shrimp, toss everything with the sesame oil and plenty of black pepper, and serve in bowls topped with sliced scallions."],"tip":"It''s everything you love about an egg roll minus the wrapper, the deep fryer, and the shame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_shrimp_feta_cherry_tomatoes', '{"id":"baked_shrimp_feta_cherry_tomatoes","name":"Baked Shrimp with Feta and Cherry Tomatoes","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"cherry_tomatoes","q":300},{"f":"feta","q":100},{"f":"olives","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200°C (400°F) and set a medium baking dish or ovenproof skillet on the stovetop over medium heat with the olive oil.","Soften the sliced onion for 4 minutes until translucent, then add the garlic and oregano and cook one minute more, until fragrant.","Tumble in the cherry tomatoes and cook 5 to 6 minutes, pressing a few with the back of a spoon, until they burst and their juices bubble into a loose, brick-red sauce.","Nestle the shrimp into the sauce in one layer, scatter the olives and crumbled feta over the top, and bake 8 to 10 minutes, until the shrimp are opaque and the feta has softened into creamy pockets with browned peaks.","Finish with lemon juice, chopped parsley, and black pepper, and eat it hot from the dish while the feta is still molten."],"tip":"The feta won''t fully melt and that''s the point — you want soft, briny landmines, not cheese sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_spinach_coconut_curry', '{"id":"shrimp_spinach_coconut_curry","name":"Shrimp and Spinach Coconut Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":200},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"curry_powder","q":6},{"f":"garam_masala","q":3},{"f":"turmeric","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Warm the oil in a deep skillet over medium heat and cook the finely chopped onion for 6 to 8 minutes, stirring now and then, until soft and golden at the edges.","Stir in the garlic, ginger, curry powder, and turmeric and toast for one minute, until the spices darken a shade and the mixture smells like the good corner of a spice shop.","Pour in the crushed tomatoes and simmer 5 minutes, until the sauce thickens and the oil beads at the edges — the classic sign the base is ready.","Add the coconut milk and salt, bring back to a gentle simmer, then slide in the shrimp and cook 3 to 4 minutes, until pink and just firm.","Fold in the spinach a handful at a time so it wilts into the sauce, dust with garam masala, and let it rest two minutes off the heat before serving."],"tip":"Garam masala is a finishing spice, not a marathon runner — add it at the end so its perfume survives the trip to the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_shrimp_avocado_spinach_salad', '{"id":"warm_shrimp_avocado_spinach_salad","name":"Warm Garlic Shrimp and Avocado Spinach Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"spinach","q":200},{"f":"asparagus","q":250},{"f":"cherry_tomatoes","q":150},{"f":"avocado","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"balsamic_vinegar","q":20},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pile the spinach into a wide serving bowl and let it wait — the hot pan contents will do the dressing and wilting for you.","Sear the asparagus pieces in half the olive oil over medium-high heat for 4 to 5 minutes, until blistered in spots but still snappy, then tip them over the spinach.","Add the remaining oil to the pan with the shrimp and sliced garlic and cook 2 to 3 minutes, tossing, until the shrimp are pink and the garlic is pale gold.","Deglaze with the balsamic vinegar and a squeeze of lemon, swirling for 30 seconds until it turns syrupy, then pour the shrimp and every drop of warm pan dressing over the greens.","Toss until the spinach slumps slightly, season with salt and pepper, and crown with the halved cherry tomatoes and sliced avocado."],"tip":"Warm dressing wilts spinach in seconds, so toss at the table unless you enjoy eating your salad against the clock."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_chicken_bacon_kale_salad', '{"id":"warm_chicken_bacon_kale_salad","name":"Warm Chicken and Bacon Kale Salad","emoji":"🥓","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"bacon","q":60},{"f":"kale","q":1},{"f":"walnuts","q":30},{"f":"parmesan","q":20},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Cook the chopped bacon in a large skillet over medium heat for 6 to 8 minutes, until crisp, then lift it out and leave every drop of rendered fat behind.","Season the chicken with salt and pepper, sear it in the bacon fat with the olive oil for 5 to 6 minutes per side, until deeply browned and 74°C (165°F) inside, then rest it on a board.","Strip the kale from its stems, tear it into bite-size pieces, and add it to the still-warm pan with the garlic, tossing for one to two minutes until it turns glossy, deep green, and barely tender.","Splash in the balsamic and scrape up the browned bits so the vinegar and drippings become the dressing right in the pan.","Slice the chicken against the grain, pile it over the kale, and finish with the bacon, toasted walnuts, shaved parmesan, and a crack of pepper."],"tip":"Bacon fat is the only kale massage therapist that never asks for a tip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_spinach_bacon_egg_salad', '{"id":"warm_spinach_bacon_egg_salad","name":"Warm Wilted Spinach Salad with Bacon and Jammy Eggs","emoji":"🍳","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","dairy-free"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"spinach","q":300},{"f":"bacon","q":100},{"f":"eggs","q":4},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then shock them in ice water — you want set whites and yolks like soft amber jam.","Meanwhile, cook the chopped bacon in a wide skillet over medium heat until crisp, about 8 minutes, and set it on a plate, keeping the fat in the pan.","Add the olive oil, sliced mushrooms, and thinly sliced onion to the drippings and cook 5 to 6 minutes, until the mushrooms brown and the onion sweetens.","Pour in the balsamic, let it bubble for 20 seconds, then immediately tip the hot pan contents over the spinach in a large bowl and toss until the leaves collapse to a silky half-wilt.","Season with salt and pepper, divide between plates, and top with the bacon and the peeled, halved eggs, yolks facing up like they''re proud of themselves."],"tip":"Seven minutes means seven minutes — an egg timer is cheaper than the disappointment of a chalky yolk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_pork_apple_cabbage_salad', '{"id":"warm_pork_apple_cabbage_salad","name":"Warm Pork and Apple Cabbage Salad","emoji":"🍏","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"cabbage","q":0.4},{"f":"apple","q":1},{"f":"walnuts","q":40},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":30},{"f":"garlic","q":0.2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into medallions about 2 centimeters thick, season generously with salt and pepper, and sear in half the oil over medium-high heat for 3 to 4 minutes per side, until burnished and just faintly pink at the center; rest them under foil.","Add the remaining oil to the pan with the shredded cabbage and cook 6 to 8 minutes, stirring occasionally but not obsessively, so the edges char while the ribbons soften.","Stir in the garlic and matchstick-cut apple and cook two minutes more, until the apple warms through but keeps its crunch.","Deglaze with the balsamic, scraping up the pork drippings, and toss until the cabbage glistens in a tangy, mahogany glaze.","Pile the warm slaw onto plates, fan the pork medallions and their resting juices over the top, and scatter with toasted walnuts."],"tip":"Pork loin goes from juicy to gym-towel in about ninety seconds, so pull it early and let the resting juices finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_salmon_asparagus_feta_salad', '{"id":"warm_salmon_asparagus_feta_salad","name":"Warm Salmon and Asparagus Salad with Feta","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"asparagus","q":250},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the salmon dry, season with salt, pepper, and oregano, and lay it skin-side down in a cold skillet with half the oil; turn the heat to medium and cook 6 to 7 minutes, until the skin releases easily and crackles like parchment.","Flip and cook 2 minutes more, until the flesh flakes at the thick end but still looks glossy inside, then rest it on a plate.","Sear the asparagus in the same pan with the remaining oil over medium-high for 4 to 5 minutes, rolling occasionally, until blistered and bright green.","Toss the warm asparagus with the spinach in a serving bowl so the residual heat softens the leaves, then dress with lemon juice and the toasty oil left in the pan.","Break the salmon into large flakes over the salad and finish with crumbled feta, olives, and a last crack of black pepper."],"tip":"Starting salmon in a cold pan is the lazy path to crisp skin — the fat renders before the flesh even notices it''s cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_turkey_taco_salad', '{"id":"warm_turkey_taco_salad","name":"Warm Turkey Taco Salad","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"cheddar","q":60},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"salsa","q":120},{"f":"tomato","q":1},{"f":"scallions","q":1},{"f":"chili_powder","q":5},{"f":"cumin","q":3},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Brown the turkey in the oil over medium-high heat, breaking it into rubble and leaving it undisturbed in two-minute stretches so it develops crusty, caramelized patches instead of steaming gray.","Season with chili powder, cumin, and salt, stir in half the salsa, and simmer 3 to 4 minutes, until the mixture is saucy but not soupy.","While the meat simmers, chop the romaine into ribbons, dice the tomato, and slice the avocado and scallions.","Mound the cool, crunchy romaine into wide bowls and spoon the hot taco meat straight over the top so the cheddar you scatter next melts on contact.","Finish with tomato, avocado, scallions, the remaining salsa, and a dollop of sour cream, then toss at the table so every forkful gets hot, cold, creamy, and crisp at once."],"tip":"The hot-meat-on-cold-lettuce trick only works if you serve immediately — this salad does not believe in leftovers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_beef_larb_style_salad', '{"id":"warm_beef_larb_style_salad","name":"Warm Beef Larb-Style Lettuce Salad","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":450},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"lime","q":2},{"f":"soy_sauce","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":2},{"f":"cilantro","q":0.5},{"f":"chili_powder","q":2},{"f":"olive_oil","q":10}],"steps":["Heat the oil in a wok or heavy skillet over high heat and fry the ground beef, smashing it flat and letting it sizzle untouched for two minutes at a time, until deeply browned and crisp in spots, about 8 minutes total.","Push the beef aside, drop the minced garlic and ginger into the cleared space, and stir for 30 seconds until fragrant, then mix everything together.","Pull the pan off the heat and season the hot beef with the soy sauce, the juice of both limes, and the chili powder — it should taste aggressively salty, sour, and warm, because the lettuce will mellow it.","Fold in most of the sliced scallions and chopped cilantro while the meat still steams so the herbs bloom in the residual heat.","Spoon the warm beef over thick ribbons of romaine and cool half-moons of cucumber, top with the remaining herbs, and serve while the contrast between hot and crisp is at its loudest."],"tip":"Season the meat off the heat and taste before serving — lime juice mellows fast on a hot pan and shy larb is sad larb."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_skillet', '{"id":"turkey_taco_skillet","name":"Smoky Turkey Taco Skillet","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"tomato","q":2},{"f":"cheddar","q":80},{"f":"sour_cream","q":60},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Heat the olive oil in a large skillet over medium-high heat until it shimmers, then add the diced onion and bell pepper and cook for 4 minutes until the edges pick up a little char.","Push the vegetables aside, add the ground turkey, and let it sear undisturbed for 2 minutes before breaking it up; season generously with chili powder, cumin, smoked paprika, and salt.","Stir in the chopped tomatoes and simmer for 5 to 6 minutes, until the juices reduce into a thick, brick-red sauce that coats the back of a spoon.","Kill the heat, scatter the cheddar over the top, and cover for 2 minutes so the cheese melts into glossy pools.","Serve straight from the pan with dollops of sour cream, sliced avocado, and a hard squeeze of lime over everything."],"tip":"Let the turkey sit and sear before stirring — pale, steamed taco meat is a crime with an easy fix."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_turkey_lettuce_cups', '{"id":"ginger_turkey_lettuce_cups","name":"Ginger-Garlic Turkey Lettuce Cups","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"mushrooms","q":150},{"f":"carrots","q":1},{"f":"romaine","q":1}],"steps":["Heat the sesame oil in a wide skillet over medium-high heat and fry the minced garlic and ginger for 30 seconds, just until fragrant and sizzling but not browned.","Add the ground turkey and finely chopped mushrooms and cook for 6 to 7 minutes, breaking the meat into small crumbles, until the mushroom liquid evaporates and everything starts to brown and crackle.","Pour in the soy sauce and toss in the grated carrot, stirring for 1 minute so the sauce glazes the meat with a savory sheen.","Separate the romaine into sturdy individual leaves, rinse and pat them completely dry so they stay crisp.","Spoon the hot filling into the cool leaves at the table and eat them like tacos while the contrast of temperatures is at its best."],"tip":"Chop the mushrooms as fine as the turkey crumbles and nobody will detect your stealth vegetable operation."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_turkey_cauliflower_bowl', '{"id":"greek_turkey_cauliflower_bowl","name":"Greek Turkey and Cauliflower Rice Bowl","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":30},{"f":"cauliflower","q":0.7},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"lemon","q":1},{"f":"garlic","q":0.2}],"steps":["Pulse the cauliflower into rice-sized bits, then saute it in half the olive oil over medium-high heat for 5 minutes until it loses its raw crunch and picks up golden flecks; season with salt and scrape it into serving bowls.","Return the skillet to the heat with the remaining oil and brown the ground turkey with the minced garlic, dried oregano, salt, and pepper for 7 to 8 minutes, until deeply browned with crisp edges.","While the turkey cooks, dice the cucumber and tomatoes and toss them with a pinch of salt and half the lemon''s juice.","Pile the turkey over the cauliflower rice and spoon the juicy cucumber-tomato salad alongside so the cold and hot elements stay distinct.","Crumble the feta over everything and finish with the rest of the lemon juice and a final glug of olive oil."],"tip":"Squeeze the riced cauliflower dry in a towel first, unless soggy rice is your love language."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_stuffed_peppers', '{"id":"italian_turkey_stuffed_peppers","name":"Italian Turkey-Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"bell_pepper","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"mozzarella","q":100},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and halve the bell peppers through the stem, scooping out the seeds so you have six sturdy boats.","Brown the ground turkey in the olive oil over medium-high heat with the diced onion and garlic for 6 minutes, seasoning with dried oregano, fennel seed if you have it, salt, and plenty of black pepper.","Stir in the chopped tomatoes and spinach and cook 3 minutes more, until the spinach collapses and the mixture looks saucy but not wet.","Pack the filling into the pepper halves, top each with torn mozzarella, and bake for 22 to 25 minutes until the peppers slump slightly and the cheese is blistered and bronzed.","Rest for 5 minutes before serving so the filling sets and stops behaving like lava."],"tip":"Choose peppers that sit flat on their backs — a capsized stuffed pepper takes its cheese down with it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_parmesan_zucchini_boats', '{"id":"turkey_parmesan_zucchini_boats","name":"Turkey Parmesan Zucchini Boats","emoji":"🛶","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":3},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"parmesan","q":40},{"f":"mozzarella","q":80}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the seedy cores with a spoon, leaving a half-centimeter wall; chop the scooped flesh and save it.","Sear the ground turkey in olive oil over medium-high heat for 5 minutes until browned, then add the garlic, reserved zucchini flesh, and chopped tomatoes with a big pinch of salt, oregano, and chili flakes.","Simmer for 5 minutes until the mixture thickens into a rustic ragu, then stir in half the parmesan off the heat.","Fill the zucchini shells generously, blanket them with mozzarella and the remaining parmesan, and bake 20 minutes until the boats are tender and the cheese is spotted brown.","Finish under the broiler for 2 minutes if you want proper bubbling drama, and serve hot."],"tip":"Salt the hollowed zucchini and let them weep for ten minutes — dry boats hold sauce, wet boats sink."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('feta_turkey_meatballs_yogurt', '{"id":"feta_turkey_meatballs_yogurt","name":"Feta Turkey Meatballs with Lemon Yogurt","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"feta","q":60},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"spinach","q":150},{"f":"greek_yogurt","q":100},{"f":"lemon","q":1}],"steps":["Mix the ground turkey with the egg, crumbled feta, grated garlic, dried oregano, salt, and pepper, working it just until it holds together — overmixing makes meatballs bounce.","Roll into twelve balls with damp hands and chill them for 10 minutes so they firm up.","Brown the meatballs in olive oil over medium heat, turning every 3 minutes, for 12 to 14 minutes total, until deeply golden all over and springy to a gentle poke.","Push the meatballs to one side, pile the spinach into the pan, and let it wilt in the drippings for 2 minutes with a squeeze of lemon.","Whisk the yogurt with the remaining lemon juice and a pinch of salt, swoosh it across the plates, and top with the meatballs and greens."],"tip":"Fry one tester meatball first — seasoning regret is much cheaper at the one-ball stage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_smash_patties_romaine', '{"id":"turkey_smash_patties_romaine","name":"Turkey Smash Patties in Romaine Wraps","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":10},{"f":"cheddar","q":60},{"f":"romaine","q":0.5},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"onion","q":0.5}],"steps":["Divide the turkey into four loose balls and season them boldly with salt, pepper, and garlic powder — turkey forgives nothing bland.","Get a heavy skillet ripping hot with a slick of oil, drop in two balls, and smash them flat with a spatula; sear 3 minutes until a lacy brown crust forms before flipping.","Top each flipped patty with cheddar and thin onion rings, cook 2 minutes more until the cheese droops over the edges, then repeat with the second batch.","Strip the romaine into wide, cupped leaves and double them up so each wrap can handle the juices.","Load each leaf with a patty, sliced tomato, and mashed avocado, and eat over the plate — these drip with intent."],"tip":"Smash once, hard, at the start; pressing later just squeezes out the juices you worked for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('no_bean_turkey_chili', '{"id":"no_bean_turkey_chili","name":"No-Bean Turkey Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":700},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"broth","q":500},{"f":"zucchini","q":1},{"f":"cheddar","q":80},{"f":"sour_cream","q":100}],"steps":["Brown the ground turkey in olive oil in a heavy pot over medium-high heat for 6 to 8 minutes, letting it develop dark crusty bits on the bottom of the pot — that fond is the chili''s backbone.","Add the diced onion, bell peppers, and garlic and cook 5 minutes until softened, then bloom two tablespoons of chili powder with cumin and smoked paprika directly in the fat for 1 minute until the kitchen smells like a barbecue joint.","Stir in the chopped tomatoes and broth, scraping up the browned bits, and simmer uncovered for 25 minutes until thick enough to mound on a spoon.","Add the diced zucchini for the last 10 minutes so it stays tender-firm instead of dissolving.","Taste, correct the salt bravely, and ladle into bowls under a landslide of cheddar and sour cream."],"tip":"Chili improves overnight, so make it a day early and accept the applause tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_vegetable_soup', '{"id":"italian_turkey_vegetable_soup","name":"Italian Turkey and Greens Soup","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":2},{"f":"celery","q":2},{"f":"broth","q":1000},{"f":"tomato","q":2},{"f":"spinach","q":150},{"f":"parmesan","q":40}],"steps":["Brown the ground turkey in olive oil in a soup pot over medium-high heat for 6 minutes, seasoning with salt, fennel seed, and chili flakes so it tastes like sausage without the casing.","Add the diced onion, carrots, celery, and garlic and sweat for 5 minutes until the onion turns translucent and the bottom of the pot glazes over.","Pour in the broth and chopped tomatoes, bring to a lively simmer, and cook for 15 minutes until the carrots yield easily to a knife tip.","Stir in the spinach off the heat and let it wilt into silky green ribbons in about a minute.","Ladle into deep bowls and shower each with grated parmesan, letting it half-melt into the surface."],"tip":"Toss the parmesan rind into the pot while it simmers — it is free umami you were about to throw away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheddar_turkey_cauliflower_bake', '{"id":"cheddar_turkey_cauliflower_bake","name":"Cheddar Turkey Cauliflower Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"cauliflower","q":0.8},{"f":"cheddar","q":100},{"f":"sour_cream","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and boil the cauliflower florets in salted water for 5 minutes, until just fork-tender; drain them aggressively and let them steam dry.","Meanwhile, brown the ground turkey with the diced onion and garlic in olive oil over medium-high heat for 7 minutes, seasoning with smoked paprika, salt, and black pepper until the meat is crusty at the edges.","Fold the turkey, cauliflower, sour cream, and half the cheddar together in a baking dish, making sure every floret gets a creamy coating.","Top with the remaining cheddar and bake for 18 to 20 minutes until the top is golden and the edges bubble like a hot spring.","Rest for 5 minutes so the bake firms from molten to merely luxurious, then serve in generous scoops."],"tip":"Undercook the cauliflower on the stove — it finishes in the oven, and nobody has ever praised mushy florets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_salad_lime_crema', '{"id":"turkey_taco_salad_lime_crema","name":"Turkey Taco Salad with Lime Crema","emoji":"🥗","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"olive_oil","q":15},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"cheddar","q":60},{"f":"greek_yogurt","q":80},{"f":"lime","q":1},{"f":"onion","q":0.5}],"steps":["Brown the ground turkey in olive oil over medium-high heat for 7 to 8 minutes with cumin, chili powder, garlic powder, and salt, cooking until the crumbles are dark-edged and sizzling.","While the meat cooks, whisk the greek yogurt with the zest and juice of the lime and a pinch of salt into a pourable crema; loosen with a teaspoon of water if it resists.","Chop the romaine into bite-sized ribbons, ice-water crisp if it has gone limp, and spread it across two wide bowls.","Scatter over the diced tomatoes, thin-sliced onion, and cubed avocado, then crown with the hot turkey so the cheese-ready heat rises through the salad.","Shower with cheddar, zigzag the lime crema over the top, and toss at the table just before eating."],"tip":"Hot meat on cold lettuce is the whole trick — assemble at the last second or accept wilted consequences."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keema_saag', '{"id":"turkey_keema_saag","name":"Turkey Keema Saag","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"butter","q":20},{"f":"olive_oil","q":10},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"tomato","q":3},{"f":"spinach","q":200},{"f":"greek_yogurt","q":100}],"steps":["Melt the butter with the oil in a deep skillet over medium heat and fry the finely diced onion for 6 to 8 minutes until it turns a lazy amber at the edges.","Add the minced garlic and ginger with a tablespoon of garam masala, a teaspoon of turmeric, and a pinch of cayenne, frying for 1 minute until the spices darken and perfume the kitchen.","Raise the heat, add the ground turkey, and cook for 6 minutes, mashing it into fine crumbles as it browns in the spiced fat.","Stir in the chopped tomatoes and simmer for 8 minutes until they break down into a thick, rusty gravy, then fold in the spinach handful by handful until it wilts to a deep green.","Take the pan off the heat, swirl in the yogurt so it stays creamy rather than curdled, and season with salt to taste."],"tip":"Temper the yogurt with a spoonful of hot gravy before it meets the pan, and it will never break on you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_egg_roll_stir_fry', '{"id":"unstuffed_egg_roll_stir_fry","name":"Unstuffed Egg Roll Turkey Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame","eggs"],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"sesame_oil","q":20},{"f":"cabbage","q":0.5},{"f":"carrots","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"eggs","q":2}],"steps":["Heat half the sesame oil in your widest skillet over high heat and brown the ground turkey hard for 5 minutes, breaking it up only after it has developed color.","Add the garlic and ginger and stir for 30 seconds, then pile in the shredded cabbage and carrot — it will look like too much, and it is not.","Toss constantly for 4 to 5 minutes until the cabbage collapses to half its volume and picks up charred edges while keeping a slight crunch.","Splash in the soy sauce and let it hiss and glaze everything for a final minute.","In a separate small pan, fry the eggs in the remaining sesame oil until the whites are crisp-edged and the yolks still tremble, then slide one over each portion and break the yolk into the pile like a sauce."],"tip":"All the flavor of an egg roll, none of the deep-fryer cleanup — the runny yolk is doing the wrapper''s job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_feta_skillet_frittata', '{"id":"spinach_feta_skillet_frittata","name":"Spinach & Feta Skillet Frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"feta","q":80},{"f":"spinach","q":150},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and set an oven-safe 20cm skillet over medium heat with the olive oil.","Soften the sliced half onion for 4 minutes until translucent, then pile in the spinach and stir until it collapses into a glossy dark tangle and any liquid has cooked off.","Whisk the eggs with a pinch of salt and plenty of black pepper until no streaks of white remain, then pour them over the vegetables and scatter the crumbled feta on top.","Cook undisturbed for 3 minutes until the edges set and pull away from the pan, then transfer to the oven for 8 to 10 minutes until the center is puffed and barely jiggles.","Rest 2 minutes, then slide onto a board and cut into wedges; the feta should be soft and golden at the tips."],"tip":"If your frittata browns like a marshmallow at a bonfire, your oven runs hot — drop it 15 degrees next time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('broccoli_cheddar_breakfast_bake', '{"id":"broccoli_cheddar_breakfast_bake","name":"Broccoli Cheddar Breakfast Bake","emoji":"🥦","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":50,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cheddar","q":90},{"f":"broccoli","q":250},{"f":"milk","q":60},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 180C and rub a small baking dish with the olive oil so nothing welds itself to the corners.","Cut the broccoli into small florets and steam or blanch them for 3 minutes until bright green but still snappy, then drain thoroughly — wet broccoli makes a weepy bake.","Whisk the eggs with the milk, a generous pinch of salt, and black pepper until completely smooth and slightly frothy.","Arrange the broccoli in the dish, scatter over two-thirds of the grated cheddar, and pour the custard evenly on top, finishing with the remaining cheese.","Bake 30 to 35 minutes until the top is burnished gold and a knife inserted in the middle comes out clean; rest 5 minutes before scooping."],"tip":"Squeeze the blanched broccoli like it owes you money — trapped water is the enemy of a sliceable bake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_soft_scramble', '{"id":"salmon_soft_scramble","name":"Silky Salmon Soft Scramble","emoji":"🐟","cuisine":"American","meal":["breakfast"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy","fish"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"salmon","q":150},{"f":"butter","q":20},{"f":"sour_cream","q":40}],"steps":["Cut the salmon into 2cm chunks, season with salt, and sear in half the butter in a nonstick pan over medium heat for about 3 minutes until just opaque; lift it out onto a plate.","Wipe the pan, drop the heat to low, and melt the remaining butter until it foams gently.","Whisk the eggs with a pinch of salt, pour them in, and stir slowly and constantly with a spatula, scraping the bottom so soft curds form like loose ribbons — this takes a patient 4 to 5 minutes.","When the eggs are glossy and still slightly wet, fold in the salmon and the sour cream and pull the pan off the heat; residual warmth finishes the job.","Season with cracked black pepper and serve immediately, before the curds tighten up."],"tip":"Take the eggs off the heat when they look one minute underdone — carryover cooking is the sous-chef you never have to pay."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_silk_stirfry', '{"id":"shrimp_egg_silk_stirfry","name":"Shrimp & Egg Silk Stir-Fry","emoji":"🦐","cuisine":"Asian","meal":["breakfast"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["eggs","shellfish","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"shrimp","q":200},{"f":"onion","q":0.5},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Pat the shrimp completely dry, season lightly with salt, and get a wok or wide skillet screaming hot with the olive oil.","Sear the shrimp with the thinly sliced onion for about 2 minutes, tossing, until the shrimp curl into pink commas and the onion chars at the edges; scrape everything onto a plate.","Whisk the eggs with the soy sauce until uniform, lower the heat to medium, and pour the eggs into the same pan.","Let them set for 15 seconds, then push gently from the edges toward the center in big folds so the eggs stay in soft, wobbly sheets rather than dry crumbles.","When the eggs are 90 percent set, return the shrimp and onion, drizzle with sesame oil, give two final folds, and serve while everything still glistens."],"tip":"The wok should be hot enough that the shrimp hiss on contact — a quiet pan means steamed shrimp and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ricotta_egg_bake', '{"id":"zucchini_ricotta_egg_bake","name":"Zucchini Ricotta Egg Bake","emoji":"🥒","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":55,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"ricotta","q":150},{"f":"zucchini","q":1.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 180C, coarsely grate the zucchini, toss it with a big pinch of salt, and let it sit in a colander for 10 minutes before wringing it out in a clean towel.","Warm the olive oil in a pan over medium heat and cook the minced garlic with the zucchini for 3 to 4 minutes until fragrant and just tender.","Whisk the eggs with half the ricotta, salt, and black pepper until mostly smooth — a few ricotta flecks are charming, not a flaw.","Fold in the zucchini, pour into an oiled baking dish, and dot the surface with spoonfuls of the remaining ricotta.","Bake 30 minutes until the ricotta dollops turn golden-freckled and the center springs back when pressed; rest 5 minutes so the slices hold their shape."],"tip":"Salting and squeezing the zucchini feels fussy until you taste the difference between custard and swamp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_folded_omelet', '{"id":"caprese_folded_omelet","name":"Caprese Folded Omelet","emoji":"🍅","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mozzarella","q":100},{"f":"tomato","q":2},{"f":"olive_oil","q":15}],"steps":["Dice the tomatoes, salt them lightly, and let them drain in a sieve while you tear the mozzarella into small pieces.","Whisk 3 eggs per omelet with a pinch of salt until fully blended, and heat half the olive oil in a nonstick pan over medium heat until it shimmers.","Pour in the eggs and swirl the pan; as the edges set, drag them toward the center and tilt so raw egg flows underneath, about 90 seconds total.","While the surface is still glossy, scatter half the mozzarella and drained tomato over one side, fold the omelet over, and slide it onto a plate — the cheese will melt into soft pull-apart pockets from the residual heat.","Repeat for the second omelet, finishing each with black pepper and a thread of olive oil."],"tip":"An omelet waits for no one — plate it while the center still looks a touch underdone or eat rubber."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_parmesan_frittata', '{"id":"mushroom_parmesan_frittata","name":"Mushroom Parmesan Frittata","emoji":"🍄","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mushrooms","q":250},{"f":"parmesan","q":60},{"f":"butter","q":15},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 200C and melt the butter in an oven-safe skillet over medium-high heat until the foam subsides.","Add the sliced mushrooms in a single layer and resist stirring for 3 minutes so they brown deeply; then toss with the minced garlic and a pinch of salt and cook 2 minutes more until their liquid evaporates and the pan smells nutty.","Whisk the eggs with most of the grated parmesan and a grind of pepper, then pour over the mushrooms and shake the pan to settle everything evenly.","Cook on the stovetop 2 to 3 minutes until the edges set, dust with the remaining parmesan, and bake 7 to 9 minutes until the top is puffed and speckled gold.","Let it rest briefly, then cut into wedges — the center should be tender, not bouncy."],"tip":"Crowded mushrooms steam and sulk; give them room and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_egg_breakfast_scramble', '{"id":"tofu_egg_breakfast_scramble","name":"Savory Tofu & Egg Scramble","emoji":"🥢","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free","low-carb","high-protein"],"allergens":["eggs","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"eggs","q":5},{"f":"tofu","q":250},{"f":"onion","q":0.5},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Press the tofu between paper towels for a few minutes, then crumble it into rough bite-size pieces.","Heat the olive oil in a wide skillet over medium-high heat and fry the tofu with the sliced onion for 5 to 6 minutes, stirring occasionally, until the crumbles pick up golden crusty edges.","Splash in the soy sauce and let it sizzle and coat everything with a savory lacquer, about 30 seconds.","Reduce the heat to medium-low, pour in the whisked eggs, and fold slowly so soft curds wrap around the tofu without breaking it to dust.","When the eggs are just set but still shiny, kill the heat, finish with sesame oil and black pepper, and serve straight from the pan."],"tip":"Add the soy sauce to the hot pan, not the raw eggs — caramelized soy tastes like breakfast ambition, watery soy tastes like a spill."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_egg_muffin_cups', '{"id":"cottage_cheese_egg_muffin_cups","name":"Cottage Cheese Egg Muffin Cups","emoji":"🧁","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cottage_cheese","q":150},{"f":"spinach","q":100},{"f":"bell_pepper","q":0.5},{"f":"cheddar","q":40}],"steps":["Heat the oven to 180C and grease 8 cups of a muffin tin thoroughly — egg muffins cling to bare metal like barnacles.","Finely chop the bell pepper and roughly chop the spinach, then whisk the eggs with the cottage cheese, salt, and pepper until the curds are evenly suspended.","Stir the vegetables into the egg mixture and divide it among the cups, filling each about three-quarters full.","Top each cup with a pinch of grated cheddar and bake 18 to 20 minutes until puffed like little soufflés and set in the center.","Cool 5 minutes in the tin — they will deflate slightly and release cleanly — then run a knife around each and pop them out."],"tip":"They keep 4 days in the fridge, which makes Monday-you very grateful to Sunday-you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_style_poached_eggs', '{"id":"shakshuka_style_poached_eggs","name":"Shakshuka-Style Eggs in Tomato","emoji":"🍲","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"feta","q":60},{"f":"olive_oil","q":20}],"steps":["Warm the olive oil in a deep skillet over medium heat and cook the sliced onion for 5 minutes until soft and sweet, adding the minced garlic for the final minute.","Chop the tomatoes and add them with a good pinch of salt; simmer 10 to 12 minutes, mashing occasionally, until they collapse into a thick, bubbling sauce that holds a trail when you drag a spoon through it.","Make six wells in the sauce with the back of the spoon and crack an egg into each one.","Cover the pan and cook over low heat 6 to 8 minutes, until the whites are set opaque but the yolks still shudder when you nudge the pan.","Crumble the feta over the top, grind on black pepper, and bring the whole skillet to the table while it is still burbling."],"tip":"Undercook the yolks slightly under the lid — they keep cooking while everyone argues over who gets the middle egg."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_onion_tomato_omelet', '{"id":"masala_onion_tomato_omelet","name":"Masala Onion-Tomato Omelet","emoji":"🧅","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["eggs"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"bell_pepper","q":0.5},{"f":"olive_oil","q":25}],"steps":["Finely chop the onion, tomato, and bell pepper — the pieces should be small enough to suspend in the egg rather than sink through it.","Whisk the eggs hard with the chopped vegetables, salt, and a serious amount of black pepper until the mixture is frothy and flecked throughout.","Heat half the oil in a nonstick pan over medium heat until it shimmers, then pour in half the mixture and swirl to the edges.","Cook 2 to 3 minutes until the underside is lacy and deeply browned and the top has nearly set, then flip confidently and give the second side one more minute.","Fold in half, slide onto a plate, and repeat with the remaining oil and egg; eat hot, when the onions are still juicy inside their golden crust."],"tip":"A street-cart omelet is fried, not coddled — let the underside go properly brown and crisp before you even think about flipping."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_eggs_in_avocado_boats', '{"id":"baked_eggs_in_avocado_boats","name":"Baked Eggs in Avocado Boats","emoji":"🥑","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"tomato","q":1}],"steps":["Heat the oven to 200C, halve and pit the avocados, and scoop out a spoonful from each cavity so a whole egg can actually fit — snack on the scraps.","Nestle the halves snugly in a small baking dish so they cannot tip, and season the flesh with salt and pepper.","Crack an egg into each cavity, letting any excess white spill over rather than flooding the dish, and top each with a pinch of grated cheddar.","Bake 14 to 17 minutes until the whites are just set and the cheese is bubbling; the yolks should still have a gentle wobble.","Finish with finely diced tomato and more black pepper, and serve with spoons — this is scoop-and-savor food."],"tip":"Crack each egg into a cup first so you can pour in the yolk and just enough white — avocado boats have a strict passenger limit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_frittata', '{"id":"chicken_fajita_frittata","name":"Chicken Fajita Frittata","emoji":"🌶️","cuisine":"Mexican","meal":["breakfast"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"chicken_breast","q":200},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":50},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and cut the chicken into thin strips; season them well with salt and pepper.","Sear the chicken in the olive oil in an oven-safe skillet over high heat for 3 to 4 minutes until golden at the edges, then add the sliced bell pepper and onion and cook 3 minutes more until the peppers blister and soften.","Whisk the eggs with a pinch of salt, pour them over the sizzling fajita mixture, and shake the pan so the egg seeps into every gap.","Scatter the grated cheddar on top and cook on the stove 2 minutes until the rim sets, then bake 8 to 10 minutes until the surface is puffed, bronzed, and set in the center.","Rest 3 minutes, then slice into fat wedges — each one should show ribbons of pepper and chicken like a cross-section of a very good decision."],"tip":"Get real char on the peppers before the eggs go in; the frittata can bake, but it cannot sear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_crusted_cauliflower_steaks', '{"id":"parmesan_crusted_cauliflower_steaks","name":"Parmesan-Crusted Cauliflower Steaks","emoji":"🥦","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":40,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"olive_oil","q":45},{"f":"parmesan","q":60},{"f":"garlic","q":0.3},{"f":"eggs","q":1},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 220C and set a rack in the upper third so the crust browns hard.","Trim the cauliflower''s leaves, stand it stem-down, and slice two thick 2.5-centimeter steaks straight through the core so they hold together.","Brush both sides with olive oil and minced garlic, then roast on a hot sheet pan for 15 minutes until the undersides are deeply bronzed.","Whisk the egg, flip the steaks, paint the tops with egg, and press on a shaggy layer of grated parmesan.","Roast 10 to 12 minutes more until the cheese forms a crackly golden shell, then finish with a hard squeeze of lemon while everything is still sizzling."],"tip":"If your knife wobbles, the two crumbly end pieces are not failures — they are the cook''s roasted snack."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ricotta_lasagna_bake', '{"id":"zucchini_ricotta_lasagna_bake","name":"Zucchini Ribbon Ricotta Lasagna","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":65,"servings":2,"ing":[{"f":"zucchini","q":3},{"f":"ricotta","q":250},{"f":"mozzarella","q":120},{"f":"parmesan","q":30},{"f":"eggs","q":1},{"f":"tomato","q":3},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Slice the zucchini lengthwise into 5-millimeter planks, salt them generously, and let them weep on a rack for 15 minutes before blotting bone-dry — this is the difference between lasagna and soup.","Simmer the chopped tomatoes with garlic and olive oil in a skillet over medium heat for 10 minutes, crushing them down until the sauce is thick enough to mound on a spoon.","Beat the ricotta with the egg and parmesan until fluffy, then fold in the spinach.","Layer sauce, zucchini planks, and ricotta in a small baking dish, repeating twice and capping the top with mozzarella.","Bake at 190C for 30 minutes until the top blisters with brown spots and the edges bubble like lava, then rest 10 full minutes so the slices hold their shape."],"tip":"Skipping the salting step is the number-one cause of lasagna puddles — respect the blot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_cauliflower_cabbage_rolls', '{"id":"turkey_cauliflower_cabbage_rolls","name":"Turkey and Cauliflower-Rice Cabbage Rolls","emoji":"🌯","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"cabbage","q":1},{"f":"ground_turkey","q":400},{"f":"cauliflower","q":0.5},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":3},{"f":"broth","q":250},{"f":"olive_oil","q":15}],"steps":["Core the cabbage and dunk it into a pot of boiling water for 3 to 4 minutes, peeling off eight leaves as they turn glossy and pliable.","Pulse the cauliflower into coarse rice-sized crumbs, then mix it with the raw turkey, half the diced onion, and the garlic until just combined — overworking makes rubbery rolls.","Roll a generous handful of filling into each leaf, tucking the sides like a burrito, and nestle the rolls seam-down in a snug baking dish.","Sizzle the remaining onion in olive oil, add the chopped tomatoes and broth, and simmer 5 minutes into a loose, brick-red sauce.","Pour the sauce over the rolls, cover tightly with foil, and bake at 180C for 45 minutes until a knife slides through the cabbage with zero resistance."],"tip":"Shave down the thick rib on each leaf with a paring knife and your rolls will stop fighting you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_eggplant_shakshuka', '{"id":"smoky_eggplant_shakshuka","name":"Smoky Eggplant Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"tomato","q":4},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30}],"steps":["Cube the eggplant and sear it in olive oil in a wide skillet over medium-high heat for 8 minutes, resisting the urge to stir until each side is mahogany and creamy inside.","Push the eggplant aside, soften the onion, bell pepper, and garlic for 4 minutes until sweet and slumped.","Add the chopped tomatoes, crushing them with your spoon, and simmer 8 to 10 minutes until the sauce darkens and thickens enough to hold a trench.","Carve four wells with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes until the whites set but the yolks still shiver.","Shower with crumbled feta straight off the heat so it softens into salty pockets."],"tip":"Pull the pan when the eggs look one minute underdone — carryover heat finishes them while you find forks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cauliflower_fried_rice', '{"id":"chicken_cauliflower_fried_rice","name":"Chicken Cauliflower Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["soy","gluten","eggs","sesame"],"time":30,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chicken_breast","q":300},{"f":"eggs","q":2},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Pulse the cauliflower florets into rice-sized bits and spread them on a towel to shed surface moisture while you prep everything else.","Get a wok or large skillet screaming hot, then sear diced chicken in olive oil for 4 to 5 minutes until the edges brown; scoop it out.","Scramble the eggs hard and fast in the same pan for 30 seconds, breaking them into ribbons, and set them with the chicken.","Stir-fry the onion, carrots, and garlic for 2 minutes, then add the cauliflower rice in a single layer and let it sit untouched for 90 seconds to pick up toasty char.","Return the chicken and eggs, splash in the soy sauce around the pan''s rim so it sizzles and caramelizes, and finish off-heat with sesame oil."],"tip":"Wet cauliflower steams and sulks; dry cauliflower fries and sings — towel it like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_charred_cabbage_stir_fry', '{"id":"crispy_tofu_charred_cabbage_stir_fry","name":"Crispy Tofu and Charred Cabbage Stir-Fry","emoji":"🥬","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"cabbage","q":0.5},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":30}],"steps":["Press the tofu between towels under a heavy pan for 10 minutes, then tear it into ragged bite-sized chunks — torn edges crisp better than clean cubes.","Fry the tofu in olive oil over medium-high heat for 8 minutes, turning only when each side releases easily and turns deep gold; set aside.","Crank the heat, add the mushrooms, and cook 3 minutes until they squeak and brown.","Add thick ribbons of cabbage and let them scorch against the pan for 2 minutes before tossing, chasing blistered black-edged leaves that stay crunchy at the core.","Return the tofu with the garlic, pour the soy sauce down the hot side of the pan so it hisses and glazes everything, and finish with sesame oil off the heat."],"tip":"A crowded pan is a steamy pan — if your skillet is small, char the cabbage in two shifts."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_zucchini_noodles', '{"id":"shrimp_scampi_zucchini_noodles","name":"Shrimp Scampi with Zucchini Noodles","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"zucchini","q":3},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":20}],"steps":["Spiralize the zucchini into long noodles and pat them dry — they will release plenty of water later, so start them as dry as possible.","Melt the butter with olive oil in a wide skillet over medium heat and bloom the sliced garlic for 60 seconds until fragrant but not browned.","Raise the heat, add the shrimp in one layer, and cook 90 seconds per side until they curl into loose commas and blush pink; overcooked shrimp curl into tight Os, so pull them promptly.","Toss the zucchini noodles into the garlicky pan juices for just 2 minutes, until barely tender but still snappy.","Return the shrimp, squeeze in the lemon, and serve immediately with a light dusting of parmesan before the noodles think about weeping."],"tip":"Zoodles keep cooking on the plate, so undershoot the doneness you want by a solid minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_eggplant_tofu_curry', '{"id":"coconut_eggplant_tofu_curry","name":"Coconut Eggplant Curry","emoji":"🍆","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["soy"],"time":45,"servings":4,"ing":[{"f":"eggplant","q":2},{"f":"coconut_milk","q":400},{"f":"tomato","q":3},{"f":"tofu","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"spinach","q":150},{"f":"olive_oil","q":30}],"steps":["Cut the eggplants into chunky 3-centimeter pieces and brown them in oil over medium-high heat in two batches, about 6 minutes per batch, until the cut faces are burnished and the flesh turns silky.","Soften the onion in the same pot for 5 minutes, then add the garlic and cook until the whole kitchen smells like dinner.","Add the chopped tomatoes and simmer 8 minutes, mashing them down until the mixture thickens into a rusty, jammy base.","Pour in the coconut milk, return the eggplant with cubed tofu, and simmer gently for 12 to 15 minutes until the sauce coats a spoon and the eggplant collapses at the touch of a fork.","Wilt in the spinach during the last 2 minutes and season boldly — coconut milk drinks up salt like it is owed."],"tip":"Browned eggplant is the entire curry; pale eggplant is a spongy apology, so take the extra six minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_cauliflower_cheddar_soup', '{"id":"roasted_cauliflower_cheddar_soup","name":"Roasted Cauliflower Cheddar Soup","emoji":"🥣","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"cauliflower","q":2},{"f":"cheddar","q":200},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30}],"steps":["Break the cauliflower into florets, toss with olive oil, and roast at 220C for 25 minutes until the edges frazzle and brown — that caramelization is the soup''s backbone.","Meanwhile, melt the butter in a soup pot and sweat the onion over medium-low heat for 8 minutes until translucent and sweet, adding the garlic for the final minute.","Add the roasted cauliflower, reserving a handful of the crispiest florets for garnish, and pour in the milk plus 500 milliliters of water.","Simmer gently for 10 minutes, then blend until completely velvety, thinning with water if it stands up too stiffly.","Off the heat, stir in the cheddar a handful at a time until it melts glossy and smooth — boiling it now would break the cheese, so keep it below a simmer.","Ladle into bowls and crown with the reserved roasted florets."],"tip":"Grate the cheddar yourself; pre-shredded bags are dusted with anti-caking agents that turn silky soup grainy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_and_cabbage_soup', '{"id":"beef_and_cabbage_soup","name":"Unstuffed Cabbage Beef Soup","emoji":"🍲","cuisine":"American","meal":["dinner","lunch"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"cabbage","q":0.5},{"f":"tomato","q":3},{"f":"broth","q":1000},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"olive_oil","q":15}],"steps":["Brown the beef in olive oil over high heat in a heavy pot, letting it sit undisturbed for 3 minutes to build a crusty fond before breaking it up.","Add the onion and carrots and cook 5 minutes until the onion softens and picks up the beefy drippings, then stir in the garlic for 30 seconds.","Add the chopped tomatoes and scrape the pot bottom hard — every brown speck you free is flavor you already paid for.","Pour in the broth, slide in thick ribbons of cabbage, and simmer uncovered for 25 minutes until the cabbage turns silky and the broth tastes rich and rounded.","Season assertively and ladle into deep bowls while it steams."],"tip":"This soup is one of those rare dishes that is honestly better tomorrow, so make it tonight for the person you will be on Tuesday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_zucchini_boats', '{"id":"chicken_fajita_zucchini_boats","name":"Chicken Fajita Zucchini Boats","emoji":"🛶","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"zucchini","q":3},{"f":"chicken_breast","q":300},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":80},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Halve the zucchini lengthwise and scoop out the seedy centers with a spoon, leaving sturdy 1-centimeter walls; chop the scooped flesh and save it.","Roast the hollowed boats cut-side up at 200C for 10 minutes to drive off moisture while you build the filling.","Sear thin strips of chicken in olive oil over high heat for 4 minutes until browned at the edges, then add the bell pepper, onion, and reserved zucchini flesh and cook 4 minutes more until sizzling and slightly charred.","Hit the filling with half the lime juice, pile it into the boats, and blanket with cheddar.","Bake 12 to 15 minutes until the cheese bubbles and browns in spots, then serve with cool dollops of sour cream and the remaining lime."],"tip":"The scooped zucchini innards are free vegetables hiding in plain sight — chop them into the filling instead of the compost."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_eggplant_whipped_feta_platter', '{"id":"charred_eggplant_whipped_feta_platter","name":"Charred Eggplant with Whipped Feta","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"eggplant","q":2},{"f":"feta","q":120},{"f":"greek_yogurt","q":150},{"f":"tomato","q":1},{"f":"cucumber","q":1},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":45}],"steps":["Slice the eggplants into thick 2-centimeter rounds, brush both sides generously with olive oil, and get a grill pan ripping hot over high heat.","Grill the rounds 4 to 5 minutes per side until deep char stripes appear and the centers turn custardy — press one gently; it should give like a ripe peach.","While they cook, blitz the feta, greek yogurt, garlic, and half the lemon juice until it whips into a smooth, tangy cloud.","Swoosh the whipped feta across a platter and shingle the hot eggplant on top so the cheese softens beneath it.","Scatter with diced tomato and cucumber, then finish with the last of the lemon and a final glossy thread of olive oil."],"tip":"Hot eggplant on cold whipped feta is the whole trick — plate it straight off the grill or lose the magic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_cauliflower_rice_skillet', '{"id":"beef_taco_cauliflower_rice_skillet","name":"Beef Taco Cauliflower Rice Skillet","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"cauliflower","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"tomato","q":2},{"f":"cheddar","q":60},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Pulse the cauliflower into rice-sized crumbs and set it aside on a dry towel.","Brown the beef in olive oil over high heat for 5 minutes, leaving it alone long enough to develop crusty, deeply seasoned edges before breaking it apart.","Add the onion and bell pepper and cook 3 minutes until they soften into the beef fat and smell sweet.","Stir in the chopped tomatoes and simmer 3 minutes until saucy, then fold in the cauliflower rice and cook 4 to 5 minutes, until tender but still faintly toothsome.","Kill the heat, squeeze the lime over everything, and scatter the cheddar across the top, covering for one minute so it melts into molten pockets."],"tip":"Taste before you top — the lime does more heavy lifting here than any amount of extra cheese will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_zoodle_soup', '{"id":"chicken_zoodle_soup","name":"Chicken Zoodle Soup","emoji":"🍜","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"chicken_breast","q":700},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"carrots","q":2},{"f":"zucchini","q":3},{"f":"broth","q":1500}],"steps":["Warm the olive oil in a Dutch oven over medium heat and sweat the diced onion and sliced carrots for 6 minutes, until the onion turns translucent and smells sweet.","Stir in the minced garlic and cook 30 seconds, just until fragrant, then pour in the broth and bring it to a lively simmer.","Slip in the whole chicken breasts, drop the heat to low, and poach gently for 15 minutes, until the thickest piece registers 74C and the broth is golden.","Lift out the chicken, shred it with two forks into ragged bite-size pieces, and return it to the pot with plenty of salt and cracked pepper.","Shave the zucchini into long ribbons or noodles, stir them into the hot soup, and simmer just 2 minutes so they stay al dente rather than slumping into mush.","Taste, adjust the seasoning, and ladle into deep bowls while the zoodles still have a little snap."],"tip":"Add the zoodles at the last minute — zucchini goes from noodle to noodle soup faster than you can find the ladle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tuscan_chicken_stew', '{"id":"creamy_tuscan_chicken_stew","name":"Creamy Tuscan Chicken Stew","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":600},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":5},{"f":"spinach","q":250},{"f":"milk","q":250},{"f":"parmesan","q":60},{"f":"broth","q":500}],"steps":["Cut the chicken into 3-centimeter chunks, season generously with salt and pepper, and sear in olive oil over medium-high heat for 4 minutes, until the edges are deeply golden but the centers are still pale.","Push the chicken aside, add the diced onion, and cook 5 minutes until soft, then stir in the minced garlic for a fragrant 30 seconds.","Add the chopped tomatoes and cook 6 to 8 minutes, mashing occasionally, until they collapse into a rough, jammy sauce that coats the back of a spoon.","Pour in the broth and milk, bring to a bare simmer, and cook uncovered for 12 minutes so the stew thickens slightly and the chicken turns tender.","Off the heat, stir in the grated parmesan and spinach by the handful, letting each addition wilt into glossy dark ribbons before adding the next.","Rest the stew 5 minutes so the flavors settle, then serve in shallow bowls with an extra grating of parmesan."],"tip":"Keep the milk at a gentle simmer, not a boil — curdled Tuscan stew is a Renaissance tragedy nobody paints."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_no_bean_beef_chili_2', '{"id":"smoky_no_bean_beef_chili_2","name":"Smoky No-Bean Beef Chili","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":2},{"f":"tomato","q":6},{"f":"broth","q":500},{"f":"cheddar","q":100},{"f":"sour_cream","q":100}],"steps":["Brown the ground beef in a heavy pot over medium-high heat for 7 to 8 minutes, breaking it into rough crumbles and letting a dark fond build on the bottom of the pot.","Add the diced onion and bell peppers and cook 5 minutes, scraping up the browned bits, until the vegetables soften and pick up color.","Stir in the minced garlic along with a generous spoonful of chili seasonings, salt, and pepper, toasting for 1 minute until the whole kitchen smells smoky.","Add the chopped tomatoes and broth, bring to a boil, then reduce to a low, blipping simmer and cook uncovered for 30 minutes, until the chili is thick enough to mound on a spoon.","Taste and sharpen the seasoning, then ladle into bowls and crown each with shredded cheddar and a cool spoonful of sour cream."],"tip":"Let the beef sit untouched for the first few minutes — fiddling with it steams the meat, and steam never won a chili cook-off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_albondigas_soup', '{"id":"turkey_albondigas_soup","name":"Turkey Albondigas Soup","emoji":"🥣","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["eggs"],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"eggs","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":2},{"f":"zucchini","q":2},{"f":"tomato","q":3},{"f":"broth","q":1500},{"f":"avocado","q":2},{"f":"lime","q":1}],"steps":["Mix the ground turkey with the egg, half the minced garlic, a quarter of the onion grated fine, and a heavy pinch of salt, then roll into walnut-size meatballs with damp hands so they stay smooth.","In a large pot, simmer the broth with the remaining onion, garlic, chopped tomatoes, and sliced carrots for 10 minutes, until the tomatoes soften and tint the broth a pale orange.","Lower the meatballs into the barely simmering broth one at a time and poach gently for 12 minutes without stirring, until they float and feel springy when pressed.","Add the half-moons of zucchini and simmer 5 more minutes, just until they turn glossy and tender at the edges.","Season the broth boldly with salt and pepper, then ladle into bowls and finish each with diced avocado and a hard squeeze of lime."],"tip":"A gentle simmer is meatball insurance — a rolling boil will shake your albondigas apart like a piñata."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_cauliflower_chowder_2', '{"id":"salmon_cauliflower_chowder_2","name":"Salmon and Cauliflower Chowder","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["fish","dairy"],"time":40,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"cauliflower","q":0.7},{"f":"milk","q":600},{"f":"butter","q":40},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":500}],"steps":["Melt the butter in a soup pot over medium heat and cook the diced onion for 5 minutes, until soft and just turning gold at the edges, then add the minced garlic for 30 seconds.","Add the cauliflower florets and broth, bring to a simmer, and cook 10 minutes, until a knife slides through a floret with no resistance.","Ladle a third of the cauliflower into a blender with a splash of the liquid, puree until silky, and stir it back in — this gives the chowder body without a speck of flour.","Pour in the milk, bring back to the barest simmer, and slide in the salmon cut into 3-centimeter chunks; poach 5 to 6 minutes, until the fish turns opaque and flakes at a nudge.","Season assertively with salt and pepper, let the chowder rest 3 minutes off the heat, and serve steaming with the salmon chunks still intact."],"tip":"Stir like you mean it before the salmon goes in and barely at all after — flaky fish is the goal, salmon confetti is not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_shrimp_feta_stew', '{"id":"greek_shrimp_feta_stew","name":"Greek Shrimp and Feta Stew","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["shellfish","dairy"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"tomato","q":6},{"f":"spinach","q":150},{"f":"feta","q":120},{"f":"lemon","q":1}],"steps":["Heat the olive oil in a wide, deep skillet over medium heat and cook the diced onion for 6 minutes, until soft and sweet, then add the sliced garlic and cook 1 minute more.","Add the chopped tomatoes with a good pinch of salt and simmer 12 to 15 minutes, crushing them against the pan, until they break down into a thick, brick-red sauce that sizzles at the edges.","Stir in the spinach a handful at a time and let it wilt completely into the sauce, about 2 minutes.","Nestle the shrimp into the sauce in a single layer, scatter the crumbled feta over the top, cover, and cook 4 to 5 minutes, until the shrimp curl into pink commas and the feta softens into creamy pockets.","Finish with the juice of half the lemon and black pepper, then serve straight from the pan with the remaining lemon in wedges."],"tip":"Pull the pan off the heat the second the shrimp curl — they keep cooking in the sauce, and rubbery shrimp file formal complaints."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_tofu_cabbage_stew', '{"id":"peanut_tofu_cabbage_stew","name":"Spicy Peanut Tofu Cabbage Stew","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["soy","gluten","nuts","sesame"],"time":40,"servings":4,"ing":[{"f":"tofu","q":600},{"f":"peanut_butter","q":120},{"f":"cabbage","q":0.3},{"f":"bell_pepper","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"lime","q":1}],"steps":["Press the tofu for 10 minutes, cut it into 2-centimeter cubes, and sear in the sesame oil over medium-high heat for 6 to 8 minutes, turning until the faces are burnished and crisp.","Add the minced ginger and garlic to the pot and stir for 30 seconds, until the aroma blooms and hits the back of your throat.","Whisk the peanut butter and soy sauce into 1 liter of hot water until smooth, pour it over the tofu, and bring to a gentle simmer.","Add the shredded cabbage and sliced bell pepper and simmer uncovered for 10 minutes, until the cabbage is silky and the broth has thickened to the texture of thin cream.","Squeeze in the lime juice, taste for salt and heat, and serve in deep bowls while the broth still clings to every cube of tofu."],"tip":"The peanut broth thickens as it sits, so keep a kettle of hot water nearby to loosen leftovers back into stew instead of dip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('silky_egg_drop_tofu_soup', '{"id":"silky_egg_drop_tofu_soup","name":"Silky Egg Drop Soup with Tofu and Mushrooms","emoji":"🥚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","soy","gluten","sesame"],"time":30,"servings":4,"ing":[{"f":"eggs","q":8},{"f":"tofu","q":500},{"f":"mushrooms","q":300},{"f":"spinach","q":150},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"broth","q":1500},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":45}],"steps":["Bring the broth to a simmer with the sliced ginger and smashed garlic and let it steep for 5 minutes, until the steam smells warm and peppery.","Add the sliced mushrooms and simmer 5 minutes, until they darken and sink, then stir in the soy sauce and cubed tofu to heat through.","Beat the eggs thoroughly in a spouted measuring cup so they pour in a thin, controllable stream.","With the soup at a bare simmer, stir slowly in one direction and drizzle in the eggs in a lazy spiral; give them 30 undisturbed seconds so they set into wide, silky ribbons.","Turn off the heat, fold in the spinach until it just wilts, and finish each bowl with a fragrant spoonful of sesame oil and black pepper."],"tip":"The slower you pour and the less you stir, the wider the egg ribbons — patience is the only thickener this soup needs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_cheddar_soup', '{"id":"cauliflower_cheddar_soup","name":"Cauliflower Cheddar Soup","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"cauliflower","q":1.3},{"f":"cheddar","q":200},{"f":"milk","q":500},{"f":"butter","q":40},{"f":"onion","q":1},{"f":"garlic","q":0.3}],"steps":["Melt the butter in a soup pot over medium heat and cook the diced onion with a pinch of salt for 6 minutes, until translucent and sweet, then stir in the minced garlic for 30 seconds.","Add the cauliflower florets and 750 milliliters of water, bring to a boil, then cover and simmer 12 minutes, until the florets crush easily against the side of the pot.","Pour in the milk and puree the soup with an immersion blender until completely smooth and glossy, like a pale velvet.","Over the lowest heat, add the shredded cheddar one handful at a time, whisking each addition until fully melted before adding the next so the soup stays silky instead of grainy.","Season with salt and plenty of black pepper, thin with a splash of water if it tightens up, and serve hot with extra cheddar on top."],"tip":"Grate your own cheddar — the anti-caking dust on pre-shredded cheese turns velvet soup into something suspiciously gritty."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_cabbage_beef_stew', '{"id":"unstuffed_cabbage_beef_stew","name":"Unstuffed Cabbage and Beef Stew","emoji":"🥬","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"cabbage","q":0.6},{"f":"tomato","q":5},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":750},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a Dutch oven over medium-high heat and brown the ground beef for 6 to 7 minutes, breaking it up and letting it crisp in spots before you stir.","Add the diced onion and cook 5 minutes until soft, then stir in the minced garlic and a generous hit of salt and pepper for 30 seconds.","Add the chopped tomatoes and cook 5 minutes, until they slump and release their juices to deglaze the browned bottom of the pot.","Pile in the roughly chopped cabbage, pour in the broth, and bring to a boil; it will look like too much cabbage, but press it down and trust the wilt.","Cover and simmer 20 minutes, stirring once halfway, until the cabbage is tender and translucent and the broth tastes deeply savory.","Taste for seasoning and serve in wide bowls with the juices ladled generously over the top."],"tip":"All the flavor of cabbage rolls with none of the rolling — your fingers can send a thank-you card."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_stroganoff_soup', '{"id":"mushroom_stroganoff_soup","name":"Mushroom Stroganoff Soup","emoji":"🍄","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"mushrooms","q":600},{"f":"butter","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"sour_cream","q":250},{"f":"milk","q":300},{"f":"parmesan","q":50}],"steps":["Melt the butter in a wide pot over medium-high heat and cook the thickly sliced mushrooms in two batches, 6 minutes per batch without crowding, until they are deeply browned and squeak-free.","Return all the mushrooms to the pot with the diced onion and cook 5 minutes, until the onion softens in the mushroom butter, then add the minced garlic for 30 seconds.","Pour in the milk and 500 milliliters of water, season with salt and a heavy grind of pepper, and simmer gently for 10 minutes so the broth takes on the mushrooms'' woodsy depth.","Reduce the heat to its lowest setting and whisk in the sour cream and grated parmesan until the soup turns pale, tangy, and just thick enough to coat a spoon.","Warm through without boiling for 2 minutes, taste for salt, and serve with more pepper cracked over each bowl."],"tip":"Brown the mushrooms like you hold a grudge — the crusty batch-two patience is where all the stroganoff flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('indian_yogurt_cauliflower_curry_stew', '{"id":"indian_yogurt_cauliflower_curry_stew","name":"Indian Yogurt and Cauliflower Curry Stew","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","nuts"],"time":45,"servings":4,"ing":[{"f":"cauliflower","q":1},{"f":"spinach","q":200},{"f":"tomato","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"butter","q":60},{"f":"greek_yogurt","q":300},{"f":"almonds","q":80}],"steps":["Melt the butter in a heavy pot over medium heat and fry the sliced onion for 8 to 10 minutes, until deeply golden at the edges, then add the minced garlic, ginger, and your curry spices and toast 1 fragrant minute.","Add the chopped tomatoes and cook 8 minutes, mashing as they soften, until the mixture thickens into a rusty paste and the butter beads at the edges.","Add the cauliflower florets with 500 milliliters of water and a big pinch of salt, cover, and simmer 12 minutes, until the florets are tender but still hold their shape.","Stir in the spinach until it wilts, then pull the pot off the heat and fold in the greek yogurt one spoonful at a time so it melts into a creamy, pale-orange sauce without splitting.","Scatter with toasted sliced almonds and serve hot, with the sauce thick enough to eat with a fork but worth chasing with a spoon."],"tip":"Always add yogurt off the heat — a boiled yogurt curry splits into curds and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('provencal_ratatouille_stew', '{"id":"provencal_ratatouille_stew","name":"Provencal Ratatouille Stew with Walnuts","emoji":"🍅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"zucchini","q":3},{"f":"bell_pepper","q":2},{"f":"tomato","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"olive_oil","q":80},{"f":"walnuts","q":80},{"f":"spinach","q":100}],"steps":["Heat half the olive oil in a Dutch oven over medium-high heat and brown the chunked zucchini in a single layer for 5 minutes, until golden on the cut faces, then set it aside so it does not stew into mush too early.","Add the remaining oil, the diced onion, and the bell pepper strips and cook 8 minutes, until soft and sweet with a few caramelized edges, then stir in the sliced garlic for 1 minute.","Add the chopped tomatoes with a serious pinch of salt and simmer 15 minutes, uncovered, until they collapse into a thick, glossy sauce slicked with red-gold oil.","Return the zucchini to the pot with 250 milliliters of water, reduce the heat, and simmer gently for 10 minutes, until every vegetable is tender but still distinct.","Fold in the spinach to wilt, season with salt and pepper, and serve warm with toasted walnuts scattered over each bowl for crunch."],"tip":"Ratatouille tastes even better tomorrow, so make it today and accept the compliments on a delay."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_chicken_lettuce_wraps', '{"id":"ginger_chicken_lettuce_wraps","name":"Ginger Chicken Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"mushrooms","q":150},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10},{"f":"cashews","q":30},{"f":"romaine","q":1},{"f":"black_pepper","q":1}],"steps":["Dice the chicken breast into pea-sized pieces and mince the mushrooms so they nearly disappear into the filling.","Heat the olive oil in a large skillet over medium-high until shimmering, then add the chicken in a single layer and let it sear undisturbed for 2 minutes before stirring.","Add the mushrooms, grated ginger, and minced garlic and cook 4 to 5 minutes more, until the pan looks dry and the chicken is golden at the edges.","Pour in the soy sauce and sesame oil, scraping up the browned bits, and simmer 1 minute until the liquid clings to the meat like a glaze.","Stir in most of the sliced scallions and the roughly chopped cashews, then taste for pepper.","Separate the romaine into sturdy cup-shaped leaves, pile the hot filling inside, and scatter the remaining scallions over the top."],"tip":"Chill the romaine in ice water for five minutes first — a crisp, cold cup against the hot filling is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_avocado_cucumber_boats', '{"id":"shrimp_avocado_cucumber_boats","name":"Chili-Lime Shrimp Cucumber Boats","emoji":"🥒","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"cucumber","q":2},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"salt","q":3}],"steps":["Halve the cucumbers lengthwise and drag a spoon down the center of each to scoop out the seeds, leaving four sturdy boats; sprinkle the hollows with a little salt and set them cut-side down to drain.","Pat the shrimp bone-dry, then toss with chili powder, cumin, minced garlic, and half the olive oil until evenly rusty red.","Sear the shrimp in a hot skillet over medium-high for about 90 seconds per side, until they curl into loose Cs and turn opaque — pull them the moment they do.","Chop the shrimp roughly and fold with diced avocado, quartered cherry tomatoes, chopped cilantro, the remaining oil, and a generous squeeze of lime.","Blot the cucumber boats dry, mound the shrimp mixture into each, and finish with more lime and cilantro."],"tip":"A shrimp shaped like an O has already told you it''s overcooked — stop at the C."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_salad_avocado_halves', '{"id":"tuna_salad_avocado_halves","name":"Lemon-Herb Tuna Avocado Halves","emoji":"🥑","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"greek_yogurt","q":100},{"f":"celery","q":60},{"f":"scallions","q":0.3},{"f":"lemon","q":0.5},{"f":"avocado","q":2},{"f":"olive_oil","q":10},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2},{"f":"salt","q":2}],"steps":["Drain the tuna thoroughly and flake it into a bowl with a fork until no large chunks remain.","Stir in the Greek yogurt, olive oil, finely diced celery, thinly sliced scallions, and chopped parsley until the salad is creamy but still has crunch.","Season assertively with lemon juice, salt, and plenty of black pepper — cold salads need louder seasoning than you think.","Halve and pit the avocados, then scoop out an extra spoonful from each half to widen the crater and fold that flesh into the tuna.","Pile the tuna salad high into the avocado halves and finish with a last squeeze of lemon and a scatter of parsley."],"tip":"Squeeze lemon over the avocado craters the second you open them, or they will brown faster than you can set the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_salmon_asparagus_plate', '{"id":"seared_salmon_asparagus_plate","name":"Crispy-Skin Salmon with Lemon Butter Asparagus","emoji":"🐟","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"asparagus","q":350},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the salmon fillets very dry, season with salt and pepper, and let them sit at room temperature while you snap the woody ends off the asparagus.","Heat the olive oil in a heavy skillet over medium-high until it just starts to smoke, then lay the salmon in skin-side down and press gently for 10 seconds so the skin stays flat.","Cook without moving for 5 to 6 minutes, until the flesh turns opaque two-thirds of the way up the sides, then flip and cook 1 minute more before resting on a plate.","In the same pan, melt the butter with the sliced garlic and toss in the asparagus, rolling the spears for 3 to 4 minutes until bright green and blistered in spots.","Squeeze in the juice of half the lemon, swirl the pan into a quick sauce, and shower with parsley.","Plate the asparagus, set the salmon on top skin-side up so it stays shatteringly crisp, and serve with lemon wedges."],"tip":"If the salmon resists when you try to flip it, it is not ready — properly seared skin releases on its own."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_lettuce_boats', '{"id":"beef_taco_lettuce_boats","name":"Smoky Beef Taco Lettuce Boats","emoji":"🌮","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":2},{"f":"romaine","q":1},{"f":"cheddar","q":50},{"f":"salsa","q":100},{"f":"avocado","q":1},{"f":"sour_cream","q":40},{"f":"lime","q":0.5},{"f":"salt","q":3}],"steps":["Brown the ground beef in a dry skillet over medium-high heat, breaking it into small crumbles and letting it sizzle until the edges crisp, about 6 minutes.","Push the beef aside, add the diced onion to the rendered fat, and cook 3 minutes until translucent before stirring in the garlic, chili powder, cumin, paprika, and salt.","Splash in a few tablespoons of water and simmer 2 minutes, stirring, until the spices bloom into a glossy sauce that coats every crumble.","Trim the romaine into a dozen cupped leaves, doubling up thinner ones so each boat holds its cargo.","Spoon the hot beef into the leaves and top with grated cheddar so it slumps slightly, then finish with salsa, diced avocado, sour cream, and a squeeze of lime."],"tip":"Season the beef until it tastes almost too bold on its own — cool lettuce and cream mute everything by half."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_turkey_meatball_plate', '{"id":"greek_turkey_meatball_plate","name":"Greek Turkey Meatballs with Yogurt Sauce","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"eggs","q":1},{"f":"feta","q":60},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"onion","q":0.3},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Grate the onion directly into the ground turkey, then add the egg, crumbled feta, two minced garlic cloves, oregano, salt, and pepper, mixing with your hands just until combined — overworking makes them tough.","Roll the mixture into 12 golf-ball-sized meatballs with damp hands and chill them for 10 minutes so they hold their shape.","Heat the olive oil in a skillet over medium and brown the meatballs on all sides, about 10 to 12 minutes total, until deeply golden and an inner peek shows no pink.","While they cook, grate half the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the last garlic clove, lemon juice, and a pinch of salt.","Dice the remaining cucumber and plate it with halved cherry tomatoes and olives, then nestle the meatballs alongside and spoon the yogurt sauce generously over everything."],"tip":"Wring that grated cucumber like it owes you money, or your sauce will be soup by noon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_sesame_slaw', '{"id":"crispy_tofu_sesame_slaw","name":"Crispy Tofu and Sesame-Lime Slaw","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","high-protein","vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy","sesame","nuts"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"edamame_frozen","q":100},{"f":"cabbage","q":0.3},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.3},{"f":"sesame_oil","q":20},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"ginger","q":10},{"f":"garlic","q":0.1},{"f":"cashews","q":40},{"f":"salt","q":4}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough bite-sized chunks — ragged edges crisp better than clean cubes.","Heat the olive oil in a wide skillet over medium-high and fry the tofu, turning every 2 to 3 minutes, until all sides are burnished and crackly, about 10 minutes; salt it while hot.","Meanwhile, shave the cabbage into thin ribbons and grate the carrots, tossing both with a pinch of salt to soften slightly.","Whisk the sesame oil, lime juice, grated ginger, minced garlic, and a pinch of salt into a sharp dressing, then pour it over the slaw with the thawed edamame, scallions, and most of the cilantro.","Pile the slaw into bowls, crown with the hot crispy tofu, and finish with toasted chopped cashews and the remaining cilantro."],"tip":"Tear the tofu, don''t cube it — those craggy surfaces are where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_parmesan_frittata_2', '{"id":"zucchini_parmesan_frittata_2","name":"Zucchini Parmesan Frittata","emoji":"🍳","cuisine":"Italian","meal":["lunch"],"diets":["low-carb","high-protein","vegetarian","gluten-free"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":1},{"f":"parmesan","q":40},{"f":"onion","q":0.3},{"f":"garlic","q":0.1},{"f":"basil","q":0.3},{"f":"cherry_tomatoes","q":100},{"f":"olive_oil","q":20},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 190C and slice the zucchini into thin coins, salting them lightly in a colander for 5 minutes to shed excess water.","Warm the olive oil in an ovenproof skillet over medium heat and cook the onion until soft, then add the blotted zucchini and garlic and saute until the coins turn golden at the edges, 5 to 6 minutes.","Whisk the eggs with most of the parmesan, salt, and pepper until uniformly yellow, then pour them over the vegetables and drop in the halved cherry tomatoes.","Cook undisturbed on the stove for 3 minutes, until the edges set and pull slightly from the pan while the center still wobbles.","Slide the skillet into the oven for 8 to 10 minutes, until the top is puffed and just set — a knife in the center should come out clean but glossy.","Shower with the remaining parmesan and torn basil, rest 5 minutes, and cut into wedges."],"tip":"Pull it while the center still trembles a little; a frittata keeps cooking in the pan and rubbery eggs have no appeal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_salad_plate', '{"id":"pork_souvlaki_salad_plate","name":"Pork Souvlaki-Style Plate with Cucumber Yogurt","emoji":"🍢","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"lemon","q":1},{"f":"oregano","q":4},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":1},{"f":"romaine","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"olives","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Cut the pork loin into 3-centimeter cubes and toss with half the olive oil, the juice of half the lemon, two minced garlic cloves, oregano, salt, and pepper; let it marinate 15 minutes while you prep the rest.","Grate half the cucumber, squeeze it firmly dry, and stir it into the yogurt with the last garlic clove, a squeeze of lemon, and a pinch of salt.","Heat a skillet or grill pan over high until properly hot, then sear the pork in a single layer for 2 to 3 minutes per side, until charred at the corners and just barely blushing inside.","Rest the pork for 3 minutes so the juices settle instead of flooding the plate.","Slice the remaining cucumber, chop the romaine and tomato, and shave the onion thin, then arrange it all with the olives, pile the pork on top, and drop a thick spoonful of the yogurt sauce alongside with the rest of the oil drizzled over."],"tip":"Crowd the pan and you steam the pork — sear in two batches if your skillet is small, the char is non-negotiable."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_cottage_cheese_plate', '{"id":"mediterranean_cottage_cheese_plate","name":"Mediterranean Cottage Cheese Lunch Plate","emoji":"🧀","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":200},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":100},{"f":"avocado","q":1},{"f":"walnuts","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"black_pepper","q":2}],"steps":["Divide the cottage cheese between two shallow bowls and swoosh it into a wide bed with the back of a spoon, the way you would hummus.","Halve the cherry tomatoes, slice the cucumber into half-moons, and cut the roasted red peppers into ribbons, arranging everything in generous piles over the cheese.","Fan slices of avocado alongside and scatter the olives and roughly crushed walnuts across the top for briny crunch.","Whisk the olive oil with lemon juice, oregano, and black pepper into a quick dressing and spoon it over the whole plate so it pools into the cottage cheese.","Finish with torn basil and one more twist of pepper, and eat with a spoon that catches a bit of everything."],"tip":"Toast the walnuts in a dry pan for two minutes first — raw walnuts whisper, toasted ones sing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_chicken_cucumber_salad', '{"id":"tandoori_chicken_cucumber_salad","name":"Tandoori-Spiced Chicken with Cucumber Raita Salad","emoji":"🍗","cuisine":"Indian","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"greek_yogurt","q":150},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"cucumber","q":1},{"f":"spinach","q":100},{"f":"onion","q":0.3},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Stir two-thirds of the yogurt with the garam masala, turmeric, cumin, paprika, grated ginger, minced garlic, half the lime juice, and salt, then coat the chicken thighs and let them marinate at least 20 minutes — the yogurt tenderizes as the spices soak in.","Heat the olive oil in a heavy skillet over medium-high and lay the chicken in, letting the marinade char into a burnished crust, 5 to 6 minutes per side, until the juices run clear.","Rest the chicken 5 minutes, then slice it thickly against the grain.","Meanwhile, grate half the cucumber, squeeze it dry, and mix it into the remaining yogurt with chopped cilantro and a pinch of salt for a quick raita.","Toss the spinach, sliced remaining cucumber, and shaved onion with the rest of the lime juice, plate the salad, top with the sliced chicken, and spoon the raita over the smoky edges."],"tip":"Let the marinade char in spots and resist the urge to scrape — those blackened yogurt edges are the closest a skillet gets to a tandoor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_crunch_salad', '{"id":"sesame_edamame_crunch_salad","name":"Sesame Edamame Crunch Salad","emoji":"🥢","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy","nuts","sesame"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"cabbage","q":0.3},{"f":"cucumber","q":1},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.3},{"f":"avocado","q":1},{"f":"almonds","q":40},{"f":"sesame_oil","q":20},{"f":"olive_oil","q":10},{"f":"lime","q":1},{"f":"ginger","q":10},{"f":"salt","q":4}],"steps":["Simmer the edamame in well-salted water for 4 minutes, then drain and rinse under cold water until completely cool.","Shave the cabbage into fine ribbons, seed and slice the bell pepper into matchsticks, and halve the cucumber lengthwise before cutting it into thin half-moons.","Whisk the sesame oil, olive oil, lime juice, grated ginger, and a solid pinch of salt into a dressing that tastes bright and a touch too sharp on its own.","Toss the vegetables and edamame with the dressing and let the salad sit 5 minutes so the cabbage relaxes and drinks it in.","Fold in the sliced scallions and cilantro, top with diced avocado and toasted sliced almonds, and serve cold while everything still snaps."],"tip":"Dress it five minutes early and not fifty — cabbage that marinates through lunch prep is perfect, cabbage that marinates overnight is coleslaw''s sad cousin."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_cauliflower_bacon_soup', '{"id":"loaded_cauliflower_bacon_soup","name":"Loaded Cauliflower Soup with Bacon and Cheddar","emoji":"🥣","cuisine":"American","meal":["lunch"],"diets":["low-carb","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"cauliflower","q":1},{"f":"bacon","q":150},{"f":"broth","q":1000},{"f":"onion","q":1},{"f":"celery","q":60},{"f":"garlic","q":0.3},{"f":"butter","q":15},{"f":"milk","q":100},{"f":"cheddar","q":120},{"f":"sour_cream","q":100},{"f":"scallions","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":3}],"steps":["Chop the bacon and cook it in a soup pot over medium heat until the fat renders and the pieces turn shatteringly crisp, about 8 minutes, then lift them out and leave the drippings behind.","Add the butter, diced onion, and celery to the pot and sweat for 5 minutes until soft and fragrant, stirring in the garlic for the final minute.","Break the cauliflower into small florets, add them with the broth, salt, and pepper, and simmer for 15 minutes until a fork slides through the stems with no resistance.","Blend the soup until silky — an immersion blender right in the pot is easiest — then stir in the milk and most of the cheddar off the heat so the cheese melts smoothly instead of breaking.","Taste and season boldly with black pepper, then ladle into bowls and finish each with a swirl of sour cream, the crispy bacon, the reserved cheddar, and sliced scallions."],"tip":"Add the cheese off the boil or it will split — patience here is the difference between velvet and grit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_sheet_pan_chicken_olives', '{"id":"greek_sheet_pan_chicken_olives","name":"Sheet-pan Greek chicken with artichokes & olives","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"artichoke_hearts","q":240},{"f":"olives","q":60},{"f":"cherry_tomatoes","q":150},{"f":"lemon","q":1},{"f":"garlic","q":0.6},{"f":"oregano","q":4},{"f":"olive_oil","q":30},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 220C and pat the chicken thighs bone-dry so they brown instead of steam.","Toss the chicken with half the oil, the minced garlic, oregano, salt and pepper, then spread it skin-side up on a sheet pan with the drained artichoke hearts.","Roast 20 minutes, then scatter on the olives and cherry tomatoes, squeeze over half the lemon and drizzle with the remaining oil.","Roast 12-15 minutes more until the chicken edges are burnished and the tomatoes have slumped and split.","Rest 5 minutes on the pan, then finish with the last lemon squeeze and spoon the salty pan juices over everything."],"tip":"Crowd the pan and you get poached chicken — leave breathing room and the artichoke edges crisp like chips."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_oregano_skewers', '{"id":"shrimp_oregano_skewers","name":"Oregano shrimp skewers with cucumber-feta salad","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"cucumber","q":1},{"f":"feta","q":80},{"f":"olives","q":40},{"f":"cherry_tomatoes","q":150},{"f":"salt","q":2}],"steps":["Toss the shrimp with half the oil, the grated garlic, oregano, salt and the zest of the lemon; let them sit 10 minutes while you make the salad.","Chop the cucumber into chunky half-moons, halve the cherry tomatoes and toss with the olives, crumbled feta and remaining oil.","Thread the shrimp onto skewers and get a grill pan smoking hot over high heat.","Sear the skewers 2 minutes per side until the shrimp curl into loose commas with charred edges — pull them the moment they turn opaque.","Squeeze the lemon over the hot skewers so it sizzles, and serve them right on top of the cold salad."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C that still snaps."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_roasted_pepper_feta', '{"id":"salmon_roasted_pepper_feta","name":"Roast salmon on roasted red peppers with feta crumble","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"roasted_red_peppers","q":200},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and slice the roasted red peppers into wide ribbons.","Toss the peppers with the sliced garlic, half the oil and the oregano, then spread them in a baking dish as a bed.","Set the salmon fillets on top, rub with the remaining oil and plenty of black pepper, and roast 12-14 minutes until the fish flakes at the thick end but still looks glossy inside.","Scatter the crumbled feta and halved olives over the hot fish so the cheese softens without melting.","Shower with chopped parsley and a hard squeeze of lemon, and serve straight from the dish with the sweet pepper juices."],"tip":"The peppers underneath catch every drop of salmon fat — do not leave them behind in the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_feta_zucchini_boats', '{"id":"turkey_feta_zucchini_boats","name":"Turkey & feta stuffed zucchini boats","emoji":"🥒","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":2},{"f":"crushed_tomatoes","q":250},{"f":"feta","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise and scoop out the seedy cores with a spoon, leaving sturdy quarter-inch walls.","Brown the turkey in the oil over medium-high heat, breaking it into rubble, until it sizzles rather than steams, about 6 minutes.","Add the diced onion, garlic and oregano and cook 3 minutes, then stir in the crushed tomatoes and the chopped zucchini cores; simmer until thick enough to mound on a spoon.","Pile the filling into the zucchini shells, set them in a baking dish and top with crumbled feta.","Bake 20 minutes until the zucchini is tender when pierced and the feta has golden freckles, then rest 5 minutes before serving."],"tip":"Scoop like a surgeon, not a gravedigger — thin walls collapse under the filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_keftedes_olive_tomato', '{"id":"beef_keftedes_olive_tomato","name":"Beef keftedes simmered in olive-tomato sauce","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"parsley","q":0.4},{"f":"cumin","q":2},{"f":"oregano","q":3},{"f":"crushed_tomatoes","q":400},{"f":"olives","q":50},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Grate the onion half straight into the beef, then add the egg, most of the chopped parsley, half the garlic, the cumin, half the oregano and the salt.","Knead briefly and roll into 12 walnut-sized meatballs; wet hands keep the mix from clinging to you.","Brown the keftedes in the oil over medium-high heat until deeply crusted on two sides, about 5 minutes — they will not be cooked through yet.","Push them aside, bloom the remaining garlic and oregano in the pan fat for 30 seconds, then pour in the crushed tomatoes and olives.","Simmer uncovered 12-15 minutes, turning the meatballs once, until the sauce darkens and clings; finish with the reserved parsley."],"tip":"Grated onion is the secret keeper of juicy meatballs — diced onion just pokes holes in them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_medallions_peppers_artichokes', '{"id":"pork_medallions_peppers_artichokes","name":"Pork medallions with balsamic peppers & artichokes","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"roasted_red_peppers","q":150},{"f":"artichoke_hearts","q":200},{"f":"balsamic_vinegar","q":30},{"f":"broth","q":120},{"f":"olive_oil","q":25},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Slice the pork loin into medallions about an inch thick, season with salt, pepper and oregano, and let them lose their fridge chill for 10 minutes.","Sear in the oil over medium-high heat 3 minutes per side until mahogany-crusted, then move to a plate to rest.","In the same pan, sizzle the sliced garlic, drained artichokes and pepper strips until the artichoke edges catch some color, about 4 minutes.","Pour in the balsamic and broth, scraping up the browned bits, and let it bubble down to a glossy glaze that coats the vegetables.","Return the medallions and any resting juices for a final minute, turning them in the glaze until lacquered and just blushing at the center."],"tip":"Pork loin has zero forgiveness — pull it while faintly pink or eat it as a cautionary tale."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_spinach_feta_frittata', '{"id":"greek_spinach_feta_frittata","name":"Spinach, feta & roasted pepper frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":150},{"f":"feta","q":90},{"f":"roasted_red_peppers","q":100},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"black_pepper","q":2}],"steps":["Heat the broiler and set an oven-safe skillet over medium heat with the oil.","Wilt the spinach with the sliced scallions until the pan is nearly dry — watery spinach means a weepy frittata.","Whisk the eggs with the oregano and black pepper, pour them over the greens, and scatter on the chopped roasted peppers and crumbled feta.","Cook undisturbed 4-5 minutes until the edges are set and puffing but the center still shimmies like custard.","Slide under the broiler 2-3 minutes until the top is golden-blistered and just set, then rest 3 minutes before cutting into fat wedges."],"tip":"The feta stays in proud salty pockets if you crumble it big — pea-sized bits vanish into the eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_artichoke_romaine_boats', '{"id":"tuna_artichoke_romaine_boats","name":"Tuna & artichoke romaine boats","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"artichoke_hearts","q":150},{"f":"greek_yogurt","q":100},{"f":"olives","q":40},{"f":"roasted_red_peppers","q":80},{"f":"romaine","q":1},{"f":"lemon","q":0.5},{"f":"olive_oil","q":20},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Drain the tuna hard and flake it into a bowl with the yogurt, olive oil, lemon juice and a generous grind of pepper.","Chop the artichoke hearts, olives and roasted peppers into confetti and fold them through until the salad is streaked red and green.","Taste and sharpen with more lemon — canned tuna drinks acid like it has been at sea for months.","Separate the romaine into whole crisp leaves, keeping the sturdy inner ones for boats.","Pile the salad into the leaves, shower with parsley and eat with your hands while the lettuce still cracks."],"tip":"Assemble at the table, not in the fridge — loaded romaine goes limp faster than a Monday handshake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_chicken_cauliflower_soup', '{"id":"lemon_chicken_cauliflower_soup","name":"Lemony chicken & cauliflower rice soup","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"cauliflower","q":1},{"f":"broth","q":1500},{"f":"eggs","q":2},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":100},{"f":"garlic","q":0.6},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":3},{"f":"parsley","q":0.4},{"f":"salt","q":4}],"steps":["Sweat the diced onion, carrot and celery in the oil over medium heat until soft and sweet-smelling, about 6 minutes, then stir in the garlic and oregano.","Add the broth and whole chicken breasts, bring to a bare simmer, and poach gently 15 minutes — bubbles should whisper, not roll.","Pulse the cauliflower florets in a processor to rice-sized bits, lift out the chicken, and simmer the cauliflower rice in the pot 6-8 minutes until tender.","Shred the chicken with two forks and return it to the pot with the salt.","Whisk the eggs with the lemon juice, temper with a ladle of hot broth while whisking, then stir the mixture back in off the heat until the soup turns silky and pale gold; finish with parsley."],"tip":"Boil after adding the egg-lemon and you get chicken soup with scrambled regrets — keep it off the heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('savory_cottage_cheese_mezze_bowl', '{"id":"savory_cottage_cheese_mezze_bowl","name":"Savory cottage cheese mezze bowl","emoji":"🥣","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":450},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":80},{"f":"walnuts","q":40},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"black_pepper","q":2}],"steps":["Divide the cottage cheese between two shallow bowls and swirl it out to the edges like a savory canvas.","Dice the cucumber small, halve the cherry tomatoes and slice the olives and roasted peppers into slivers.","Arrange the vegetables in bright wedges over the cheese rather than stirring them in, so every spoonful is different.","Toast the walnuts in a dry pan 2-3 minutes until fragrant and scatter them over for crunch.","Finish with a ribbon of olive oil, a pinch of oregano crushed between your fingers and an aggressive grind of black pepper."],"tip":"Cold cottage cheese plus warm toasted walnuts is the temperature contrast breakfast has been missing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_baked_tofu_peppers', '{"id":"mediterranean_baked_tofu_peppers","name":"Baked oregano tofu with peppers, olives & artichokes","emoji":"🫒","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["soy"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"roasted_red_peppers","q":150},{"f":"artichoke_hearts","q":150},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":30},{"f":"balsamic_vinegar","q":15},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"paprika","q":3},{"f":"basil","q":0.3},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and press the tofu between towels under a heavy pan for 10 minutes so it can actually absorb flavor.","Tear the tofu into rough bite-sized chunks — ragged edges crisp better than clean cubes — and toss with half the oil, the paprika, oregano and salt.","Roast the tofu on one side of a sheet pan for 15 minutes until the edges turn golden and leathery.","Toss the pepper strips, artichokes, olives and cherry tomatoes with the remaining oil, add them to the pan and roast 12 minutes more until the tomatoes blister and burst.","Slide everything into a bowl, splash with the balsamic and the minced raw garlic while hot, and finish with torn basil."],"tip":"Torn tofu is craggy and crisp; cubed tofu is a bounce house — tear it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_feta_stacks', '{"id":"eggplant_feta_stacks","name":"Grilled eggplant & feta stacks with balsamic","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"tomato","q":2},{"f":"feta","q":120},{"f":"olive_oil","q":40},{"f":"balsamic_vinegar","q":20},{"f":"garlic","q":0.3},{"f":"basil","q":0.4},{"f":"oregano","q":2},{"f":"salt","q":3}],"steps":["Slice the eggplant into thick rounds, salt both sides and let them sweat 10 minutes, then blot dry — this is the difference between creamy and spongy.","Brush the rounds with most of the oil and grill in a screaming-hot pan 4 minutes per side until soft-centered with dark char stripes.","Slice the tomatoes thick and mash the feta with the remaining oil, minced garlic and oregano into a rough spread.","Build stacks on plates: eggplant, a smear of feta, tomato, and repeat, ending with a crown of feta.","Drizzle the balsamic over and around, scatter with torn basil, and serve while the eggplant is still steaming under its cheese."],"tip":"Undercooked eggplant is a punishment; cook it until it surrenders completely."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('horiatiki_village_salad', '{"id":"horiatiki_village_salad","name":"Village-style Greek salad with a feta slab","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":15,"servings":2,"ing":[{"f":"tomato","q":3},{"f":"cucumber","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olives","q":80},{"f":"feta","q":160},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":15},{"f":"oregano","q":3},{"f":"salt","q":2}],"steps":["Cut the tomatoes into fat irregular wedges over the serving bowl so none of the juice escapes.","Add the cucumber in thick half-moons, the pepper in rings and the onion in whisper-thin slices, then season with salt and toss gently.","Scatter the olives over and let the salad sit 5 minutes — the salt pulls out tomato juice that becomes half the dressing.","Lay the feta on top in two unapologetic slabs rather than crumbling it.","Flood with the olive oil, add a small splash of balsamic, and dust the feta heavily with oregano; serve with spoons for the pink juice at the bottom."],"tip":"The slab is non-negotiable — crumbled feta is a garnish, a slab is a commitment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_chicken_broccoli_stir_fry', '{"id":"seared_chicken_broccoli_stir_fry","name":"Seared Chicken & Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"broccoli","q":400},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10}],"steps":["Slice the chicken breast against the grain into thin strips and pat them bone-dry so they sear instead of steam.","Heat the olive oil in your largest skillet over high heat until it shimmers, then lay the chicken in a single layer and leave it alone for 2 minutes until deeply golden on one side.","Toss the chicken for another 2 minutes until just cooked through, then scrape it onto a plate.","Add the broccoli florets to the hot pan with a splash of water and cover for 3 minutes until they turn brilliant green and just barely tender.","Return the chicken with the minced garlic and soy sauce, tossing for 60 seconds until everything is glossy and the garlic smells toasty.","Kill the heat, drizzle with sesame oil, and serve while the broccoli still has some bite."],"tip":"A crowded pan boils, an uncrowded pan browns — sear the chicken in two batches if your skillet is small."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_cashew_lettuce_wraps', '{"id":"turkey_cashew_lettuce_wraps","name":"Crispy Turkey & Cashew Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":500},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cashews","q":30},{"f":"romaine","q":1},{"f":"olive_oil","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Finely chop the mushrooms and onion so they nearly disappear into the filling.","Heat the olive oil in a wide skillet over medium-high and brown the turkey for 5 to 6 minutes, breaking it into small crumbles and letting it crisp at the edges before you stir.","Add the onion, mushrooms, and minced garlic and cook 4 minutes more, until the mushroom liquid has evaporated and the pan sounds like it is sizzling again rather than simmering.","Stir in the soy sauce and sesame oil and toss for 1 minute until the filling is glossy and deeply savory.","Off the heat, fold in roughly chopped cashews for crunch.","Separate the romaine into whole leaves, pile the hot filling into the crisp cups, and eat immediately with plenty of napkins."],"tip":"Chill the romaine leaves in ice water for five minutes first — cold, snappy lettuce against hot filling is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_shrimp_zucchini_stir_fry', '{"id":"garlic_shrimp_zucchini_stir_fry","name":"Garlic Shrimp & Zucchini Stir-Fry","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["shellfish","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Pat the shrimp very dry and cut the zucchini into thick half-moons and the bell pepper into wide strips.","Heat half the olive oil in a large skillet over high heat and sear the shrimp for about 90 seconds per side, just until they curl into loose commas and turn pink, then remove them.","Add the remaining oil and stir-fry the zucchini and pepper for 3 to 4 minutes until blistered in spots but still firm at the center.","Push the vegetables aside, drop the minced garlic into the empty spot, and stir for 30 seconds until fragrant but not browned.","Return the shrimp with the soy sauce, toss everything for a final minute, then finish with sesame oil off the heat and serve hot."],"tip":"Shrimp go from succulent to rubber bands in about a minute — pull them the moment they curl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_pepper_onion_stir_fry', '{"id":"beef_pepper_onion_stir_fry","name":"Sizzling Beef, Pepper & Onion Stir-Fry","emoji":"🫑","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":500},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Set a large skillet over high heat until a drop of water skitters across it, then add the ground beef in one flat layer with no oil needed.","Let it sear untouched for 3 minutes to build a browned crust, then break it up and cook 3 minutes more, spooning off all but a tablespoon of the rendered fat.","Add the sliced onion and bell peppers and stir-fry 4 minutes, until the onion turns translucent at the edges and the peppers pick up charred spots.","Stir in the minced garlic and soy sauce and toss for 1 minute until the pan juices reduce to a glaze that clings to the beef.","Drizzle with sesame oil, give one last toss, and serve straight from the screaming-hot pan."],"tip":"That beef fat you spooned off is free flavor — save a spoonful for tomorrow''s eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_edamame_stir_fry', '{"id":"crispy_tofu_edamame_stir_fry","name":"Crispy Tofu & Edamame Stir-Fry","emoji":"🌱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":300},{"f":"mushrooms","q":200},{"f":"edamame_frozen","q":150},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then cut it into 2-centimeter cubes.","Heat the olive oil in a wide nonstick pan over medium-high and fry the tofu for 8 minutes, turning only when each face releases easily and is deep golden brown.","Remove the tofu and stir-fry the broccoli and mushrooms in the same pan for 4 to 5 minutes, until the mushrooms brown and the broccoli is crisp-tender.","Add the edamame and minced garlic and cook 2 minutes more, until the garlic is fragrant and the edamame is heated through.","Return the tofu with the soy sauce and toss until every cube is lacquered and glossy.","Finish with sesame oil off the heat and serve in warm bowls."],"tip":"Patience beats fiddling — tofu tells you it''s ready to flip by letting go of the pan on its own."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_mushroom_lettuce_cups', '{"id":"chicken_mushroom_lettuce_cups","name":"Chicken & Mushroom Lettuce Cups","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"mushrooms","q":200},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"romaine","q":1},{"f":"olive_oil","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Dice the chicken breast into small, even cubes about the size of a fingernail so they cook fast and tuck neatly into lettuce.","Heat the olive oil in a skillet over medium-high and cook the chicken 4 to 5 minutes, stirring occasionally, until the pieces are golden at the edges and opaque throughout.","Add the finely chopped mushrooms and onion and cook 5 minutes more, until their moisture cooks off and the mixture starts to sizzle and brown again.","Stir in the garlic and soy sauce and simmer 1 minute, scraping up the browned bits so the sauce turns savory and dark.","Drizzle with sesame oil, then spoon the filling into cold, crisp romaine leaves and serve stacked on a platter.","Fold each leaf around its filling like a small taco and eat while the lettuce is still icy-crisp against the hot chicken."],"tip":"Dice everything the same small size — a lettuce cup is not the place for a chunk of chicken staging an escape."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_salmon_broccoli', '{"id":"sesame_glazed_salmon_broccoli","name":"Sesame-Glazed Salmon with Charred Broccoli","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["fish","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"broccoli","q":350},{"f":"garlic","q":0.2},{"f":"olive_oil","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Pat the salmon fillets dry and let them sit at room temperature while you cut the broccoli into flat-sided florets.","Heat the olive oil in a heavy skillet over medium-high and sear the broccoli cut-side down for 4 minutes without moving it, until deeply charred, then add a splash of water, cover for 2 minutes, and set aside.","Wipe the pan, return it to medium-high, and lay the salmon in skin-side up; sear 4 minutes until a golden crust forms and the sides turn opaque halfway up.","Flip gently, add the soy sauce, sesame oil, and minced garlic, and spoon the bubbling glaze over the fish for 2 to 3 minutes until it flakes at the thickest point.","Plate the salmon over the charred broccoli and pour every drop of pan glaze on top."],"tip":"If the salmon sticks when you try to flip it, it''s telling you to wait thirty more seconds — listen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_drop_tofu_soup', '{"id":"egg_drop_tofu_soup","name":"Silky Egg Drop Soup with Tofu","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"broth","q":1000},{"f":"eggs","q":4},{"f":"tofu","q":300},{"f":"mushrooms","q":150},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a gentle simmer in a soup pot with the sliced mushrooms and smashed garlic, and let it burble for 5 minutes so the mushrooms perfume the liquid.","Add the tofu in small cubes along with the soy sauce and simmer 3 minutes more, until the tofu is heated through and bobbing.","Beat the eggs thoroughly in a spouted cup, then reduce the soup to the barest simmer — bubbles just kissing the surface.","Pour the eggs in a thin, steady stream while stirring the soup slowly in one direction, and watch them bloom into soft golden ribbons.","Stir in the spinach until it wilts, about 30 seconds, then finish each bowl with a generous drizzle of sesame oil."],"tip":"The slower you pour and the gentler the simmer, the silkier the ribbons — a rolling boil turns them to confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_style_beef_lettuce_wraps', '{"id":"korean_style_beef_lettuce_wraps","name":"Korean-Style Beef Lettuce Wraps","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":450},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Slice the cucumber into paper-thin coins and toss with a teaspoon of the soy sauce; let it sit so it turns into a quick crunchy relish while you cook.","Brown the beef in a dry skillet over high heat for 5 to 6 minutes, pressing it flat first for a proper crust, then breaking it into crumbles.","Add the diced onion and minced garlic and cook 3 minutes, until the onion softens and the garlic smells sweet rather than sharp.","Pour in the remaining soy sauce and half the sesame oil and toss until the beef is glossy and the pan is nearly dry.","Spoon the beef into whole romaine leaves, top each with cucumber relish and a few drops of the remaining sesame oil, and serve while the contrast of hot and cold is at its best."],"tip":"Build wraps at the table, not in the kitchen — pre-filled lettuce goes limp faster than your dinner guests arrive."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_egg_zucchini_stir_fry', '{"id":"garlic_egg_zucchini_stir_fry","name":"Golden Egg & Zucchini Stir-Fry","emoji":"🍳","cuisine":"Asian","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","low-carb"],"allergens":["eggs","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":2},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":10}],"steps":["Beat the eggs until completely uniform and cut the zucchini into chunky batons that will hold their shape.","Heat half the olive oil in a wok or large skillet over high heat, pour in the eggs, and let them puff and set for 30 seconds before folding into large soft curds; scoop them out while still slightly glossy.","Add the remaining oil and stir-fry the zucchini and mushrooms for 4 minutes, until browned at the edges but still juicy inside.","Toss in the minced garlic for 30 seconds, then return the eggs with the soy sauce and fold gently so the curds stay pillowy.","Finish with sesame oil off the heat and serve immediately, while the eggs are still trembling."],"tip":"Undercook the eggs on their first pass — they take a second lap around the pan and nobody likes an egg that''s been to the gym twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tuna_edamame_salad', '{"id":"sesame_tuna_edamame_salad","name":"Sesame Tuna & Edamame Crunch Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["fish","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"edamame_frozen","q":200},{"f":"avocado","q":1},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":20}],"steps":["Boil the edamame in well-salted water for 4 minutes, then drain and rinse under cold water until fully cooled.","Whisk the sesame oil and soy sauce in the bottom of a large bowl to make a glossy two-ingredient dressing.","Chop the romaine into wide ribbons, slice the cucumber into thin half-moons, and cube the avocado.","Drain the tuna thoroughly and flake it into big, satisfying chunks rather than shreds.","Add everything to the bowl and toss gently but completely, so each ribbon of lettuce carries dressing and every bite gets tuna, edamame, and a soft hit of avocado.","Serve within minutes, while the romaine still crackles."],"tip":"Drain the tuna like you mean it — a watery salad forgives nothing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_chicken_mushroom_soup', '{"id":"gingery_chicken_mushroom_soup","name":"Restorative Chicken & Mushroom Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"chicken_breast","q":700},{"f":"broth","q":1500},{"f":"mushrooms","q":300},{"f":"carrots","q":200},{"f":"spinach","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a simmer in a large pot with the halved onion, smashed garlic cloves, and olive oil, and let it steep for 10 minutes to build a fragrant base.","Slide in the whole chicken breasts and poach at a bare, lazy simmer for 12 to 15 minutes, until just cooked through, then lift them out to rest.","Fish out the onion halves, then add the sliced mushrooms and carrot coins and simmer 8 minutes, until the carrots are tender but not mushy.","Shred the rested chicken with two forks and return it to the pot with the soy sauce.","Stir in the spinach until it collapses into silky ribbons, about 1 minute, then ladle into deep bowls and crown each with a swirl of sesame oil."],"tip":"Poach the chicken at a whisper, not a boil — furious bubbles are how tender breasts become packing material."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_foo_young_omelets', '{"id":"shrimp_egg_foo_young_omelets","name":"Shrimp Egg Foo Young Omelets","emoji":"🦐","cuisine":"Asian","meal":["breakfast","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["eggs","shellfish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"shrimp","q":300},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"broth","q":200},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":10}],"steps":["Chop the shrimp into rough chunks and saute them with the sliced mushrooms and onion in half the olive oil over medium-high heat for 3 minutes, until the shrimp are barely pink; cool slightly.","Beat the eggs well, then fold in the shrimp mixture so every ladleful carries plenty of filling.","Simmer the broth with the soy sauce and minced garlic in a small pan for 3 to 4 minutes until slightly reduced, then whisk in the sesame oil to make a savory drizzling sauce.","Heat the remaining oil in a skillet over medium-high and ladle in half the egg mixture, cooking 2 minutes per side until the omelet is puffed, golden brown, and set at the center.","Repeat with the second omelet, keeping the first warm, then stack both on plates and pour the hot garlicky sauce over the top so it seeps into every craggy edge."],"tip":"A slightly-too-hot pan is your friend here — those lacy browned edges are the difference between egg foo young and a sad frittata."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_broccoli_cheddar_bake_3', '{"id":"chicken_broccoli_cheddar_bake_3","name":"Chicken Broccoli Cheddar Bake","emoji":"🥦","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"broccoli","q":400},{"f":"cheddar","q":80},{"f":"sour_cream","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and cut the chicken into bite-size chunks, seasoning them generously with salt and pepper.","Sear the chicken in olive oil over medium-high heat for 4 minutes until the edges turn golden but the centers stay slightly underdone.","Blanch the broccoli florets in boiling salted water for 2 minutes, then drain them well so the casserole does not turn watery.","Stir the sour cream, minced garlic, and half the cheddar together, then fold in the chicken and broccoli until everything glistens.","Scrape the mixture into a baking dish, blanket it with the remaining cheddar, and bake for 20 minutes until the top bubbles and browns at the edges.","Rest the bake for 5 minutes so the sauce thickens from soupy to spoonable before serving."],"tip":"Drain that broccoli like it owes you money — a wet floret is the silent assassin of every casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_beef_lasagna_bake', '{"id":"zucchini_beef_lasagna_bake","name":"Zucchini Beef Lasagna Bake","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":65,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"zucchini","q":2},{"f":"ricotta","q":150},{"f":"mozzarella","q":80},{"f":"parmesan","q":30},{"f":"tomato","q":3},{"f":"eggs","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Slice the zucchini lengthwise into thin planks, salt them, and let them weep on paper towels for 15 minutes while the oven heats to 190C.","Brown the beef with garlic in olive oil over high heat until deeply crusted, about 6 minutes, then add the chopped tomatoes and simmer until the sauce turns thick and jammy.","Whisk the ricotta with the egg and a pinch of salt until it loosens into a spreadable cream.","Layer the dish like lasagna: meat sauce, zucchini planks, ricotta, repeating until everything is used, finishing with mozzarella and parmesan on top.","Bake uncovered for 30 minutes until the cheese blisters bronze and the edges bubble like lava.","Rest for 10 full minutes so the layers set and slice cleanly instead of sliding apart."],"tip":"Salting the zucchini is non-negotiable unless you enjoy lasagna soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_feta_frittata', '{"id":"salmon_spinach_feta_frittata","name":"Salmon Spinach Feta Frittata","emoji":"🐟","cuisine":"Mediterranean","meal":["breakfast","lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":250},{"f":"eggs","q":6},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and warm the olive oil in an ovenproof skillet over medium heat.","Soften the sliced onion for 4 minutes until translucent, then wilt the spinach in handfuls until it collapses and its liquid cooks off.","Nestle in the salmon, broken into rough chunks, and let it turn opaque at the edges for 2 minutes.","Whisk the eggs with salt and pepper, pour them over everything, and scatter the feta so it studs the surface like white pebbles.","Cook undisturbed for 3 minutes until the edges set, then transfer to the oven for 12 minutes until the center is puffed and just barely wobbles.","Slide the frittata onto a board and cut into fat wedges while it is still steaming."],"tip":"Pull it when the middle still jiggles slightly — carryover heat finishes the job while overbaking finishes your reputation."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_cauliflower_melt_casserole', '{"id":"tuna_cauliflower_melt_casserole","name":"Tuna Cauliflower Melt Casserole","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"cauliflower","q":0.8},{"f":"cheddar","q":90},{"f":"sour_cream","q":120},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C and cut the cauliflower into small, even florets so they cook through by the time the top browns.","Steam the florets for 5 minutes until just fork-tender, then drain and pat them dry with real intent.","Saute the diced onion in olive oil until golden at the edges, about 5 minutes, then stir in the drained tuna and warm it through.","Fold the cauliflower, sour cream, and half the cheddar into the tuna mixture, seasoning boldly with salt and plenty of black pepper.","Spread everything into a baking dish, cap it with the remaining cheddar, and bake for 18 minutes until the cheese bubbles and spots of mahogany appear.","Let it stand 5 minutes so the sauce clings to the florets instead of the spoon."],"tip":"Squeeze the tuna dry first — the can juice is for cats, not casseroles."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_zucchini_parmesan_gratin', '{"id":"shrimp_zucchini_parmesan_gratin","name":"Shrimp Zucchini Parmesan Gratin","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"zucchini","q":2},{"f":"parmesan","q":50},{"f":"butter","q":30},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 220C and slice the zucchini into thin coins, tossing them with olive oil, salt, and pepper.","Shingle the zucchini across a gratin dish and roast for 10 minutes to drive off moisture and concentrate their sweetness.","Melt the butter with minced garlic in a small pan until it foams and smells nutty, about 2 minutes, watching it does not brown past golden.","Toss the shrimp in the garlic butter, arrange them over the zucchini in a single layer, and shower everything with parmesan.","Bake for 10 to 12 minutes until the shrimp curl into loose commas and the cheese forms a lacy golden crust.","Serve straight from the dish while the butter still sizzles at the edges."],"tip":"A shrimp curled into a tight O is overcooked — you want commas, not full stops."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_stuffed_bell_peppers', '{"id":"turkey_stuffed_bell_peppers","name":"Cheesy Turkey Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"bell_pepper","q":3},{"f":"cauliflower","q":0.4},{"f":"tomato","q":2},{"f":"cheddar","q":70},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C, halve the peppers through the stem, and scoop out the seeds to make six sturdy boats.","Pulse or grate the cauliflower into rice-sized bits while the olive oil heats in a wide skillet.","Brown the turkey with the onion and garlic over medium-high heat for 6 minutes, breaking it into crumbles and seasoning with cumin, chili powder, and salt.","Stir in the chopped tomatoes and cauliflower rice and cook 4 more minutes until the mixture is juicy but not wet.","Pack the filling into the pepper halves, top each with cheddar, and bake for 25 minutes until the peppers slump slightly and the cheese bronzes.","Rest 5 minutes before serving so the filling firms enough to eat without an avalanche."],"tip":"Pick squat, flat-bottomed peppers — the tall elegant ones tip over and dump their dinner every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crustless_spinach_feta_quiche', '{"id":"crustless_spinach_feta_quiche","name":"Crustless Spinach Feta Quiche","emoji":"🥬","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":45,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":200},{"f":"feta","q":100},{"f":"milk","q":100},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 180C and oil a pie dish or small baking dish thoroughly, corners included.","Sweat the sliced onion in olive oil over medium heat for 5 minutes until soft and sweet, then wilt the spinach until every leaf collapses and the pan looks nearly dry.","Whisk the eggs with the milk, a pinch of salt, and a heavy grind of pepper until fully unified with no streaks of white.","Spread the spinach mixture over the dish, crumble the feta on top, and pour the custard over everything so it seeps into the gaps.","Bake for 28 to 32 minutes until the top is golden, the edges pull from the dish, and the center springs back to a gentle poke.","Cool for 10 minutes — this quiche slices like a dream warm and shatters like one straight from the oven."],"tip":"Cook the spinach until the pan is dry; feta brings enough brine that soggy quiche has no alibi."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_cheddar_gratin', '{"id":"cauliflower_cheddar_gratin","name":"Golden Cauliflower Cheddar Gratin","emoji":"🧈","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"cheddar","q":100},{"f":"parmesan","q":40},{"f":"milk","q":150},{"f":"butter","q":25},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 200C and boil the cauliflower florets in well-salted water for 4 minutes, until a knife meets slight resistance at the core.","Drain the florets and let them steam-dry in the colander for a full 5 minutes — moisture is the enemy of a proper gratin.","Melt the butter with the minced garlic in a saucepan, pour in the milk, and warm it to a bare simmer before stirring in the cheddar off the heat until glossy.","Tumble the cauliflower into a baking dish, pour the cheese sauce over every floret, and dust the top with parmesan.","Bake for 22 minutes until the surface freckles deep gold and the sauce bubbles up the sides like a cheese tide.","Rest briefly, then serve while the top still crackles."],"tip":"Undercook the cauliflower on the stove — it finishes in the oven, and nobody has ever praised a gratin for its mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_broccoli_bake', '{"id":"sesame_tofu_broccoli_bake","name":"Sesame Garlic Tofu Broccoli Bake","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["soy","sesame"],"time":45,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":350},{"f":"bell_pepper","q":1},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 220C and press the tofu between paper towels under a heavy pan for 10 minutes to squeeze out its water.","Tear the tofu into rough, craggy chunks — torn edges crisp far better than clean cubes ever will.","Toss the tofu, broccoli florets, and sliced bell pepper with olive oil, minced garlic, salt, and a good pinch of chili flakes on a sheet pan.","Roast for 25 minutes, flipping once halfway, until the tofu edges turn deep amber and the broccoli tips char and crisp.","Drizzle the sesame oil over the hot pan the moment it leaves the oven so its aroma blooms without burning.","Serve immediately while the contrast between crackly tofu and tender pepper is at its peak."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it after the oven or mourn its flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_mushroom_florentine_bake', '{"id":"ricotta_mushroom_florentine_bake","name":"Ricotta Mushroom Florentine Bake","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":55,"servings":2,"ing":[{"f":"ricotta","q":250},{"f":"spinach","q":200},{"f":"mushrooms","q":200},{"f":"eggs","q":3},{"f":"parmesan","q":40},{"f":"mozzarella","q":60},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C and sear the sliced mushrooms in olive oil over high heat until their water evaporates and they squeak then brown, about 8 minutes.","Add the garlic and spinach to the pan in handfuls, cooking until the leaves wilt to a dark tangle and the pan runs dry.","Beat the ricotta with the eggs, parmesan, salt, pepper, and a whisper of nutmeg until the mixture turns light and creamy.","Fold the vegetables through the ricotta base and spread it into an oiled baking dish, smoothing the top like frosting.","Scatter the mozzarella over the surface and bake for 30 minutes until puffed at the edges, golden in patches, and just set in the center.","Rest 8 minutes — the bake firms as it cools and rewards your patience with clean squares."],"tip":"Crowded mushrooms steam and sulk; give them room and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_broccoli_egg_bake', '{"id":"cottage_cheese_broccoli_egg_bake","name":"Cottage Cheese Broccoli Egg Bake","emoji":"🍳","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":45,"servings":2,"ing":[{"f":"cottage_cheese","q":300},{"f":"eggs","q":4},{"f":"broccoli","q":300},{"f":"cheddar","q":60},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 180C and chop the broccoli into small, pea-to-marble-sized pieces so they soften fully in the custard.","Saute the diced onion in olive oil until golden, about 5 minutes, then add the broccoli and cook 3 minutes more until bright green.","Whisk the eggs with the cottage cheese, salt, pepper, and half the cheddar until the curds are evenly suspended.","Stir the vegetables into the custard, pour into an oiled baking dish, and top with the remaining cheddar.","Bake for 30 minutes until the top is burnished gold and a knife inserted at the center comes out clean and hot.","Cool 5 minutes; it slices into tidy squares that reheat beautifully all week."],"tip":"Cottage cheese skeptics never notice it here — the curds melt into custard and take all the credit as ''creaminess''."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_zucchini_boats', '{"id":"beef_taco_zucchini_boats","name":"Beef Taco Zucchini Boats","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"zucchini","q":3},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"sour_cream","q":60},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the centers with a spoon to leave sturdy quarter-inch walls.","Chop the scooped flesh and set it aside — it is filling, not trash.","Brown the beef with the onion and garlic in olive oil over high heat, seasoning with cumin, paprika, chili powder, and salt until deeply fragrant, about 7 minutes.","Stir in the chopped tomatoes and reserved zucchini flesh and simmer 5 minutes until the mixture thickens to a spoonable taco filling.","Load the boats, crown them with cheddar, and bake for 20 minutes until the zucchini is tender and the cheese bubbles with brown speckles.","Finish each boat with a cool dollop of sour cream against the spiced, molten filling."],"tip":"Leave those walls thick — a thin-hulled zucchini boat sinks under a full cargo of beef."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_chicken_cauliflower_traybake', '{"id":"tandoori_chicken_cauliflower_traybake","name":"Tandoori-Style Chicken Cauliflower Traybake","emoji":"🍗","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":60,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"cauliflower","q":0.7},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Whisk the yogurt with minced garlic, garam masala, paprika, turmeric, cayenne, and salt into a brick-red marinade.","Cut the chicken into large chunks, coat them completely in two-thirds of the marinade, and let them sit at least 20 minutes while the oven heats to 220C.","Toss the cauliflower florets and thick onion wedges with olive oil, salt, and the remaining marinade on a large sheet pan.","Nestle the chicken among the vegetables in a single layer with breathing room so everything roasts instead of steams.","Roast for 25 to 28 minutes until the yogurt crust chars at the edges and the cauliflower tips blacken sweetly.","Rest 5 minutes and serve with the scorched pan juices spooned over the top."],"tip":"Those charred, almost-burnt yogurt edges are the whole point — resist the urge to rescue them early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_artichoke_olive_chicken', '{"id":"sheet_pan_artichoke_olive_chicken","name":"Sheet-pan chicken with artichokes & olives","emoji":"🫒","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"potatoes","q":450},{"f":"artichoke_hearts","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and cut the potatoes into 2 cm chunks so they cook in step with the chicken.","Toss the potatoes, drained artichoke hearts, and olives on a rimmed sheet pan with half the oil, the oregano, minced garlic, salt, and pepper.","Rub the chicken thighs with the remaining oil, nestle them among the vegetables skin-side up, and tuck thin lemon slices around the edges.","Roast 35–40 minutes until the chicken skin is deeply bronzed and the potatoes yield easily to a fork.","Squeeze the remaining roasted lemon over the pan and let everything rest 5 minutes so the juices settle back into the meat."],"tip":"Roasted lemon slices are edible gold — eat them, rind and all, with the crispy chicken bits."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_turkey_meatballs_broccoli', '{"id":"sheet_pan_turkey_meatballs_broccoli","name":"Sheet-pan turkey meatballs with charred broccoli","emoji":"🍢","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"broccoli","q":400},{"f":"cherry_tomatoes","q":200},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 450°F and line a sheet pan so cleanup stays a rinse, not a scrub.","Mix the turkey with the egg, grated parmesan, minced garlic, oregano, salt, and pepper, then roll into twelve golf-ball meatballs with damp hands to keep them from sticking.","Toss the broccoli florets and cherry tomatoes with the olive oil and a pinch of salt, spread them on the pan, and space the meatballs among them.","Roast 18–20 minutes until the meatballs are firm and browned on the bottom and the broccoli tips are frizzled and dark at the edges.","Crush a few of the blistered tomatoes with the back of a spoon and drag the meatballs through that instant pan sauce before serving."],"tip":"Charred broccoli is a feature, not a mistake — those crispy black edges are the best part."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_beef_mini_meatloaf_sheet_pan', '{"id":"chili_beef_mini_meatloaf_sheet_pan","name":"Chili-rubbed mini meatloaves with sweet potato wedges","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"sweet_potatoes","q":450},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":15},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F and cut the sweet potatoes into thick wedges, tossing them with the oil, half the chili powder, and a good pinch of salt on one side of a sheet pan.","Mix the beef with the egg, finely grated onion, cumin, remaining chili powder, and salt until just combined — overworking makes tough loaves.","Shape the mixture into two oval mini meatloaves and set them on the open side of the pan.","Roast 25–28 minutes, flipping the wedges halfway, until the loaves are browned with an internal temp of 160°F and the wedges are caramelized at the tips.","Shower everything with chopped cilantro and a hard squeeze of lime to cut through the richness."],"tip":"Grate the onion instead of dicing it — it vanishes into the meat and keeps the loaves juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_ginger_salmon_green_beans_sheet_pan', '{"id":"soy_ginger_salmon_green_beans_sheet_pan","name":"Soy-ginger glazed salmon with blistered green beans","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"green_beans","q":350},{"f":"soy_sauce","q":30},{"f":"honey","q":20},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and whisk the soy sauce, honey, grated ginger, minced garlic, and sesame oil into a glossy glaze.","Toss the trimmed green beans with a spoonful of the glaze and spread them over most of a sheet pan, leaving room for the fish.","Lay the salmon fillets skin-side down in the gap, brush them generously with glaze, and roast 12–14 minutes until the fish flakes at a nudge but still looks rosy in the center.","Switch to broil for the final 2 minutes so the glaze bubbles and lacquers and the beans pick up dark blisters.","Scatter thin-sliced scallions over the pan and spoon any pooled glaze back over the salmon before serving."],"tip":"Pull salmon when it still looks slightly underdone — carryover heat finishes it while you find the plates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_shrimp_fajitas', '{"id":"sheet_pan_shrimp_fajitas","name":"Sheet-pan shrimp fajitas","emoji":"🦐","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"bell_pepper","q":3},{"f":"onion","q":1},{"f":"tortillas","q":4},{"f":"olive_oil","q":20},{"f":"cumin","q":4},{"f":"chili_powder","q":4},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and slice the peppers and onion into thin strips so they soften and char quickly.","Toss the vegetables with the oil, cumin, chili powder, and salt, spread them in a single layer, and roast 15 minutes until the edges catch color.","Pat the shrimp very dry, toss them in the residual spiced oil in the bowl, and scatter them over the vegetables for a final 6–7 minutes — they are done the instant they curl into loose commas.","Warm the tortillas directly on the oven rack for the last 2 minutes.","Pile the pan''s contents into the tortillas with sliced avocado, torn cilantro, and a squeeze of lime, then serve with the pan drippings on the side."],"tip":"Shrimp go from succulent to rubber bands in about ninety seconds, so set a timer and trust it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_broccoli_sheet_pan', '{"id":"sesame_tofu_broccoli_sheet_pan","name":"Crispy sesame tofu and broccoli sheet pan","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":40,"servings":2,"ing":[{"f":"tofu","q":450},{"f":"broccoli","q":400},{"f":"rice","q":150},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":12},{"f":"maple_syrup","q":15},{"f":"ginger","q":8},{"f":"garlic","q":0.3},{"f":"scallions","q":0.5}],"steps":["Heat the oven to 450°F while you press the tofu between towels under a heavy skillet for 10 minutes — dry tofu is the only tofu that crisps.","Tear the tofu into rough bite-size chunks (craggy edges brown better than clean cubes), toss with half the sesame oil, and spread on one side of a sheet pan with the broccoli florets on the other.","Roast 25 minutes, turning once, until the tofu is golden and the broccoli tips are toasty; meanwhile simmer the rice in double its volume of water until tender, about 15 minutes.","Whisk the soy sauce, maple syrup, grated ginger, garlic, and remaining sesame oil, pour it over the hot pan, and toss so the sauce sizzles and clings.","Serve over the rice with a flurry of sliced scallions."],"tip":"Tearing tofu instead of cubing it is the cheapest texture upgrade in your kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_baked_egg_veggie_nests', '{"id":"sheet_pan_baked_egg_veggie_nests","name":"Sheet-pan baked eggs in roasted vegetable nests","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"zucchini","q":1},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"cherry_tomatoes","q":250},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and slice the zucchini, peppers, and onion into strips of roughly equal thickness so nothing lags behind.","Toss the vegetables and cherry tomatoes with the oil, oregano, salt, and pepper, and roast 22–25 minutes until slumped, sweet, and browned at the edges.","Pull the pan out, push the vegetables into four loose nests, and crack an egg into each hollow.","Crumble the feta over the top and return the pan for 7–9 minutes, until the whites are just set but the yolks still shiver when you shake the pan.","Serve straight from the pan while the yolks are still runny enough to sauce the vegetables."],"tip":"Crack each egg into a cup first — fishing shell shards out of a hot sheet pan builds character you don''t need."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_chickpea_cauliflower_sheet_pan', '{"id":"curried_chickpea_cauliflower_sheet_pan","name":"Curried chickpea and cauliflower sheet pan","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"cauliflower","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"garam_masala","q":3},{"f":"lemon","q":1},{"f":"cilantro","q":0.4},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and cut the cauliflower into small florets, saving the sliced core — it roasts into sweet, nutty coins.","Pat the chickpeas thoroughly dry with a towel, then toss them, the cauliflower, and thick onion wedges with the oil, curry powder, turmeric, and salt.","Spread everything in a single layer across the pan; crowding steams, and steam is the enemy of crunch.","Roast 28–30 minutes, shaking the pan once, until the chickpeas rattle when you jostle them and the cauliflower is deeply browned in spots.","Dust with garam masala the moment the pan comes out, then finish with lemon juice and a big handful of chopped cilantro."],"tip":"Adding garam masala after roasting keeps its perfume bright instead of baking it into the background."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_pork_apple_carrot_sheet_pan', '{"id":"maple_pork_apple_carrot_sheet_pan","name":"Maple-roasted pork loin with apples and carrots","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"apple","q":1},{"f":"carrots","q":300},{"f":"onion","q":0.5},{"f":"maple_syrup","q":25},{"f":"olive_oil","q":15},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and cut the carrots into thick batons, the apple into eighths, and the onion into wedges.","Toss the vegetables and apple with the oil, half the maple syrup, the cinnamon, and salt, and spread them around the edges of a sheet pan.","Season the pork loin aggressively with salt and pepper, set it in the center, and brush it with the remaining maple syrup.","Roast 30–35 minutes until the pork reads 140°F at its thickest point and the apples have collapsed into jammy, caramel-edged wedges.","Rest the pork 8 full minutes before slicing thick, then drag each slice through the syrupy pan juices."],"tip":"Pork loin punishes impatience — pull it at 140°F and let the rest do the last five degrees."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_white_bean_zucchini_sheet_pan', '{"id":"crispy_white_bean_zucchini_sheet_pan","name":"Crispy white beans with zucchini and parmesan","emoji":"🫘","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"white_beans","q":400},{"f":"zucchini","q":2},{"f":"cherry_tomatoes","q":250},{"f":"parmesan","q":40},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"balsamic_vinegar","q":15},{"f":"basil","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and pat the white beans dry — moisture is the difference between crispy and mushy.","Cut the zucchini into thick half-moons and toss them, the beans, and the cherry tomatoes with the oil, sliced garlic, oregano, and salt.","Spread in a single layer and roast 22–25 minutes until the beans'' skins split and crackle and the tomatoes slump into jammy pockets.","Shower the hot pan with grated parmesan and return it to the oven for 3 minutes so the cheese melts into a lacy crust.","Drizzle with balsamic, tear the basil over the top, and serve straight from the pan with a spoon for the crispy cheese bits."],"tip":"The parmesan that fuses to the pan is the cook''s tax — scrape it off and eat it standing up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_sheet_pan', '{"id":"sweet_potato_black_bean_sheet_pan","name":"Smoky sweet potato and black bean sheet pan","emoji":"🍠","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"bell_pepper","q":2},{"f":"olive_oil","q":20},{"f":"cumin","q":4},{"f":"chili_powder","q":5},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.4},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F and dice the sweet potatoes into 2 cm cubes so they turn creamy inside before the outsides burn.","Toss the sweet potatoes and sliced peppers with the oil, cumin, chili powder, and salt, and roast 20 minutes until the cubes take on dark caramel corners.","Pat the black beans dry, scatter them over the pan, and roast 8–10 minutes more until their skins tighten and a few begin to pop.","Mash the avocado with lime juice and a pinch of salt into a rough, chunky crema while the pan finishes.","Pile everything into bowls, dollop with the avocado mash, and finish with chopped cilantro and any lime left in the shell."],"tip":"Give the sweet potatoes a head start — beans only need minutes, but pale sweet potato is a broken promise."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_feta_pepper_sheet_pan', '{"id":"baked_feta_pepper_sheet_pan","name":"Sheet-pan baked feta with blistered peppers and pita","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"feta","q":200},{"f":"bell_pepper","q":2},{"f":"cherry_tomatoes","q":300},{"f":"olives","q":50},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"pita","q":2},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 425°F and slice the peppers into wide strips, keeping the feta in one proud slab in the center of the pan.","Surround the cheese with the peppers, cherry tomatoes, olives, and sliced garlic, then douse everything with the olive oil, oregano, and plenty of black pepper.","Roast 25 minutes until the tomatoes burst, the peppers wilt and char at the tips, and the feta turns golden and soft enough to spread.","Slide the pitas onto the oven rack for the last 3 minutes to warm and puff.","Smash the feta gently into the burst tomatoes to make a creamy, briny sauce and scoop it all up with torn pita."],"tip":"Feta doesn''t melt like mozzarella — it softens into a spreadable cloud, which is honestly better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_eggplant_mozzarella', '{"id":"sheet_pan_eggplant_mozzarella","name":"Sheet-pan eggplant parm-style bake","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"crushed_tomatoes","q":300},{"f":"mozzarella","q":150},{"f":"parmesan","q":20},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":5}],"steps":["Heat the oven to 450°F and slice the eggplant into rounds a generous centimeter thick, salting both sides and letting them sweat 10 minutes before blotting dry.","Brush the rounds with most of the olive oil, arrange them in a single layer, and roast 20 minutes, flipping once, until they are supple and mahogany on both faces.","Stir the minced garlic and oregano into the crushed tomatoes and spoon a thick layer onto each round.","Top with torn mozzarella and grated parmesan, then roast 8–10 minutes more until the cheese is molten with bronze freckles.","Rest 5 minutes — the eggplant firms as it cools — then finish with torn basil and the last thread of olive oil."],"tip":"Salting and sweating the eggplant first means roasted silk instead of oil-soaked sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_cheeseburger_penne', '{"id":"one_pot_cheeseburger_penne","name":"One-Pot Cheeseburger Penne","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":160},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":300},{"f":"broth","q":450},{"f":"cheddar","q":50},{"f":"paprika","q":3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Brown the ground beef in a wide, deep skillet over medium-high heat for 6 to 7 minutes, breaking it into pebbly crumbles and letting it develop dark, crusty edges before you stir.","Add the diced onion and cook 4 minutes until translucent, then stir in the minced garlic and paprika for 30 seconds until the pan smells like a burger joint.","Pour in the crushed tomatoes and broth, season with salt and pepper, and scrape up every browned bit stuck to the bottom.","Stir in the dry penne, bring to a lively simmer, then cover and cook 12 to 14 minutes, stirring every few minutes so nothing sticks, until the pasta is al dente and the sauce clings like a chili.","Kill the heat, shower the shredded cheddar over the top, and cover for 2 minutes until it melts into glossy pockets before serving."],"tip":"Resist stirring the beef for the first few minutes — the crust you build there is doing the flavor work the drive-thru never could."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_turkey_ragu_spaghetti', '{"id":"one_pot_turkey_ragu_spaghetti","name":"One-Pot Turkey Ragu Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":500},{"f":"oregano","q":2},{"f":"parmesan","q":30},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a deep saute pan over medium-high heat and brown the ground turkey for 5 to 6 minutes, pressing it flat like a patty first so it sears instead of steams.","Stir in the diced onion and cook 4 minutes until soft, then add the garlic and oregano and cook 30 seconds until fragrant.","Add the crushed tomatoes, broth, salt, and pepper, and bring the ragu to a rolling simmer.","Nestle the spaghetti in whole, submerging it as it softens over the first minute, then cook uncovered 11 to 13 minutes, tossing with tongs often, until the noodles are glossy and the sauce has thickened to coat them.","Turn off the heat, rain in the grated parmesan while tossing, and finish with torn basil leaves just before the bowls hit the table."],"tip":"Fan the spaghetti into the pan like a crosshatch so the strands don''t fuse into one heroic mega-noodle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_tuscan_chicken_penne', '{"id":"one_pot_tuscan_chicken_penne","name":"One-Pot Creamy Tuscan Chicken Penne","emoji":"🐔","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"penne","q":170},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"cherry_tomatoes","q":150},{"f":"broth","q":500},{"f":"milk","q":150},{"f":"parmesan","q":40},{"f":"spinach","q":100},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Cut the chicken into bite-size chunks, season with salt, pepper, and oregano, and sear in olive oil over medium-high heat for 4 to 5 minutes until golden at the edges but not yet cooked through.","Add the diced onion, garlic, and halved cherry tomatoes and cook 3 minutes until the tomatoes start to slump and release their juices.","Pour in the broth and milk, stir in the dry penne, and bring to a steady simmer.","Cover and cook 12 to 14 minutes, stirring every 3 minutes, until the pasta is tender and the liquid has turned into a light cream sauce.","Off the heat, stir in the parmesan and spinach by the handful, letting each addition wilt and the sauce turn silky before serving."],"tip":"The sauce will look too loose at minute 12 — give it two minutes off the heat and the parmesan will tighten it up like a good editor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_shrimp_scampi_spaghetti', '{"id":"one_pot_shrimp_scampi_spaghetti","name":"One-Pot Shrimp Scampi Spaghetti","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy","shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"spaghetti","q":170},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.5},{"f":"broth","q":550},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"chili_powder","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Melt half the butter with the olive oil in a wide skillet over medium heat, add the sliced garlic and chili powder, and cook 1 minute until the garlic turns pale gold and smells sweet, not sharp.","Pour in the broth, season with salt and pepper, and bring it to a brisk simmer.","Lay in the spaghetti, pressing it under the liquid as it relaxes, and cook uncovered 10 to 12 minutes, tossing frequently, until the noodles are just shy of al dente and the liquid has reduced to a loose glaze.","Scatter the shrimp over the pasta, cover, and cook 3 to 4 minutes until they curl into loose commas and turn opaque pink.","Finish off the heat with the remaining butter, the juice and zest of the lemon, and a flurry of chopped parsley, tossing until every strand shines."],"tip":"Shrimp go from succulent to eraser in about ninety seconds, so add them late and trust the residual heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lemon_salmon_spaghetti', '{"id":"one_pot_lemon_salmon_spaghetti","name":"One-Pot Creamy Lemon Salmon Spaghetti","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy","fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":280},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3},{"f":"broth","q":500},{"f":"milk","q":150},{"f":"peas_frozen","q":100},{"f":"parmesan","q":30},{"f":"lemon","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Season the salmon with salt and pepper and sear it skin-side down in olive oil over medium-high heat for 3 minutes until the skin crisps, then flip for 1 minute and lift it out — it should still be rare in the middle.","Lower the heat, add the minced garlic to the same pan, and cook 30 seconds in the salmon-scented oil.","Pour in the broth and milk, add the spaghetti, and simmer uncovered 10 to 12 minutes, tossing often, until the pasta is tender and the liquid has become a light cream.","Stir in the peas and parmesan, then flake the salmon into big blushing pieces and fold it back in gently so it finishes cooking in the sauce, about 2 minutes.","Brighten everything with the lemon''s zest and juice, grind over black pepper, and serve straight from the pan."],"tip":"Pull the salmon while it still looks underdone — it will finish in the sauce, and flaky beats chalky every night of the week."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_creamy_tuna_penne', '{"id":"one_pot_creamy_tuna_penne","name":"One-Pot Creamy Tuna Penne","emoji":"🥫","cuisine":"American","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["gluten","dairy","fish"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"penne","q":170},{"f":"butter","q":15},{"f":"onion","q":0.5},{"f":"celery","q":80},{"f":"broth","q":450},{"f":"milk","q":250},{"f":"peas_frozen","q":120},{"f":"cheddar","q":60},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Melt the butter in a deep skillet over medium heat and sweat the diced onion and celery for 5 minutes until soft and sweet, seasoning with salt and pepper as they go.","Add the broth, milk, and dry penne, bring to a gentle simmer, and cook 12 to 14 minutes, stirring every few minutes so the milk doesn''t catch, until the pasta is tender and the liquid is creamy.","Stir in the peas and drained tuna in big flakes and let them heat through for 2 minutes without aggressive stirring, so the tuna stays in real pieces.","Off the heat, fold in the cheddar until it melts into a glossy sauce that coats the back of a spoon.","Rest the pot 3 minutes with the lid on — the sauce settles from soupy to spoon-clinging — then serve with more black pepper."],"tip":"This is the casserole of your childhood minus the oven and the mystery — keep the simmer gentle or the milk will remind you who''s boss."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_amatriciana_style_spaghetti', '{"id":"one_pot_amatriciana_style_spaghetti","name":"One-Pot Bacon Amatriciana-Style Spaghetti","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":[],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"bacon","q":100},{"f":"spaghetti","q":170},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":450},{"f":"chili_powder","q":1},{"f":"parmesan","q":40},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Cut the bacon into thin strips and render it in a cold, wide pan brought slowly up to medium heat, about 6 minutes, until the pieces are bronzed and the fat has pooled.","Spoon off all but a couple tablespoons of fat, then cook the sliced onion in what remains for 4 minutes until golden at the edges, adding the garlic and chili powder for the last 30 seconds.","Pour in the crushed tomatoes and broth, season lightly with salt (the bacon and parmesan carry plenty), and bring to a simmer.","Add the spaghetti, pushing it under as it bends, and cook uncovered 11 to 13 minutes, tossing often, until the sauce is brick-red, glossy, and hugging every strand.","Toss in most of the parmesan off the heat until creamy, then top each bowl with the rest and a bold grind of black pepper."],"tip":"Starting bacon in a cold pan is the difference between rendered and cremated — patience pays in fat, and fat pays in flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_white_bean_basil_penne', '{"id":"one_pot_white_bean_basil_penne","name":"One-Pot White Bean & Basil Penne","emoji":"🌿","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"white_beans","q":350},{"f":"penne","q":170},{"f":"olive_oil","q":25},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"zucchini","q":1},{"f":"crushed_tomatoes","q":400},{"f":"basil","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a wide pot over medium heat and cook the diced onion for 5 minutes until soft and translucent, then add the garlic and oregano for a fragrant 30 seconds.","Add the diced zucchini and cook 3 minutes until it starts to brown at the corners.","Stir in the crushed tomatoes, 500 ml of water, the salt, and the dry penne, and bring everything to a steady simmer.","Cook uncovered 12 to 14 minutes, stirring regularly and mashing a spoonful of the white beans against the pot''s side to thicken the sauce, adding the rest whole halfway through.","When the penne is tender and the sauce is velvety, tear in the basil, grind over black pepper, and drizzle each bowl with any olive oil left in your conscience."],"tip":"That smashed spoonful of beans is your secret thickener — creamy sauce, zero cream, and nobody needs to know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_pasta_e_ceci', '{"id":"one_pot_pasta_e_ceci","name":"One-Pot Pasta e Ceci","emoji":"🫘","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"spaghetti","q":150},{"f":"olive_oil","q":25},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":250},{"f":"spinach","q":80},{"f":"oregano","q":2},{"f":"chili_powder","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a heavy pot over medium heat and cook the diced onion 4 minutes until soft, then add the garlic, oregano, and chili powder and stir for 30 seconds until the kitchen smells like a Roman trattoria.","Add the chickpeas and crushed tomatoes and simmer 5 minutes, crushing about a third of the chickpeas with the back of your spoon to give the broth body.","Pour in 600 ml of water, season with salt, and bring to a boil.","Snap the spaghetti into rough 3 cm pieces, stir them in, and cook uncovered 10 to 12 minutes, stirring often, until the pasta is tender and the pot has turned into something between a stew and a sauce.","Wilt in the spinach for the final minute, then rest 3 minutes off the heat — it thickens beautifully — and serve with black pepper and a defiant drizzle of olive oil."],"tip":"Snapping spaghetti is a crime in Naples and a technique in pasta e ceci — this is the one dish where you break noodles with pride."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_creamy_paprika_pork_penne', '{"id":"one_pot_creamy_paprika_pork_penne","name":"One-Pot Creamy Paprika Pork Penne","emoji":"🐷","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"penne","q":170},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"mushrooms","q":150},{"f":"paprika","q":5},{"f":"broth","q":550},{"f":"sour_cream","q":100},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the pork loin into thin strips, season with salt and pepper, and sear in olive oil over high heat for 2 to 3 minutes until browned but still juicy, then set aside on a plate.","Drop the heat to medium and cook the sliced onion and mushrooms in the same pan for 6 minutes until the mushrooms release their liquid and it evaporates, leaving them golden.","Stir in the garlic and paprika for 30 seconds — just until the paprika blooms brick-red and fragrant, no longer or it turns bitter.","Add the broth and dry penne, bring to a simmer, cover, and cook 12 to 14 minutes with occasional stirring until the pasta is tender and only a slick of liquid remains.","Off the heat, stir in the sour cream and the pork with its resting juices, warm through for 2 minutes without boiling, and finish with chopped parsley."],"tip":"Sour cream added at a boil will split into sad little curds — kill the flame first and it stays silky as a jazz standard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_mushroom_garlic_spaghetti', '{"id":"one_pot_mushroom_garlic_spaghetti","name":"One-Pot Garlicky Mushroom Spaghetti","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"spaghetti","q":160},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"balsamic_vinegar","q":15},{"f":"spinach","q":100},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your widest pan over medium-high and cook the sliced mushrooms in a single layer, undisturbed, for 4 minutes until deeply browned on one side, then stir and cook 3 minutes more.","Add the sliced onion and cook 4 minutes until golden, then stir in the garlic and oregano for 30 seconds.","Deglaze with the balsamic vinegar, scraping up the sticky brown film on the pan floor, then add 650 ml of water and the salt and bring to a boil.","Lay in the spaghetti and cook uncovered 10 to 12 minutes, tossing constantly toward the end, until the starchy water reduces to a glossy pan sauce that grips the noodles.","Fold in the spinach until it collapses, hit everything with a heavy grind of black pepper, and serve while the mushrooms are still swaggering."],"tip":"Crowded mushrooms steam and sulk; give them room and silence and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lemon_ricotta_zucchini_penne', '{"id":"one_pot_lemon_ricotta_zucchini_penne","name":"One-Pot Lemon Ricotta Zucchini Penne","emoji":"🍋","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ricotta","q":200},{"f":"penne","q":170},{"f":"zucchini","q":2},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"parmesan","q":30},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a deep skillet over medium-high and saute the half-moon zucchini slices for 5 to 6 minutes until browned and tender, seasoning with salt as they cook.","Add the sliced garlic for 30 seconds, then pour in 650 ml of water with the remaining salt and bring to a boil.","Stir in the dry penne and cook uncovered 12 to 14 minutes, stirring often, until the pasta is al dente and the water has reduced to a few starchy spoonfuls.","Off the heat, stir in the ricotta, parmesan, and the zest and juice of the lemon, tossing until the starchy liquid and cheese emulsify into a pale, creamy sauce.","Tear in the basil, grind over black pepper, and serve immediately, while the sauce is at peak cling."],"tip":"That murky pasta water you almost boiled away is the glue of this sauce — guard the last half-cup with your life."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lentil_ragu_spaghetti', '{"id":"one_pot_lentil_ragu_spaghetti","name":"One-Pot Lentil Ragu Spaghetti","emoji":"🥕","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":2,"ing":[{"f":"lentils_dry","q":120},{"f":"spaghetti","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":60},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the finely diced onion, carrot, and celery for 7 to 8 minutes until soft and sweet — this soffritto is the ragu''s whole personality.","Add the garlic and oregano for 30 seconds, then stir in the rinsed lentils, crushed tomatoes, and 700 ml of water.","Simmer partially covered for 20 minutes, stirring occasionally, until the lentils are just tender with a slight bite, then season with the salt.","Snap the spaghetti in half, stir it into the pot, and cook uncovered 11 to 13 minutes, stirring often and adding a splash of water if it thickens faster than the pasta cooks.","When the noodles are tender and the ragu is thick enough to mound on a spoon, rest it 3 minutes off the heat and serve with black pepper and a thread of olive oil."],"tip":"Salt lentils after they soften, not before — early salt keeps them stubborn, and nobody wants a ragu with attitude."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_chicken_skillet', '{"id":"lemon_garlic_chicken_skillet","name":"Lemon-Garlic Chicken Skillet with Wilted Spinach","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"broth","q":200},{"f":"butter","q":15}],"steps":["Halve the chicken breasts horizontally into thin cutlets, pat them bone-dry, and season generously with salt and pepper.","Heat the olive oil in a large skillet over medium-high until it shimmers, then sear the cutlets 3 to 4 minutes per side until deeply golden and just cooked through; transfer to a plate.","Drop the heat to medium, add the sliced garlic, and stir for 30 seconds until fragrant but not browned.","Pour in the broth and the juice of the lemon, scraping up the browned bits, and simmer 2 to 3 minutes until the liquid reduces by half.","Swirl in the butter until the sauce turns glossy, then pile in the spinach and let it wilt for 1 minute.","Return the chicken and any juices to the pan, spoon the sauce over the top, and serve straight from the skillet."],"tip":"Thin cutlets are the whole secret to weeknight speed — a thick breast will still be sulking raw in the middle when the sauce is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_soy_chicken_broccoli_stir_fry', '{"id":"honey_soy_chicken_broccoli_stir_fry","name":"Honey-Soy Chicken and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"broccoli","q":400},{"f":"soy_sauce","q":45},{"f":"honey","q":20},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3},{"f":"rice","q":150}],"steps":["Get the rice simmering first: rinse it, cover with water by a knuckle, and cook covered on low for 15 minutes while you stir-fry.","Slice the chicken into thin strips against the grain and whisk the soy sauce and honey together in a small bowl.","Heat half the sesame oil in a wok over high heat until it just smokes, then sear the chicken in a single layer for 2 minutes without touching it, toss, and cook 2 minutes more until browned at the edges; scoop it out.","Add the remaining oil, the broccoli florets, and a splash of water, and stir-fry 3 to 4 minutes until the broccoli is bright green with charred spots but still snappy.","Return the chicken with the minced garlic, pour in the sauce, and toss for 1 minute until everything is lacquered and sticky.","Serve immediately over the hot rice while the glaze still clings."],"tip":"A screaming-hot wok and an untouched first sear buy you restaurant char — fiddling with the chicken buys you gray steamed sadness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quick_chicken_tortilla_soup', '{"id":"quick_chicken_tortilla_soup","name":"Quick Chicken Tortilla Soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":30,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"broth","q":1000},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"black_beans","q":240},{"f":"corn_frozen","q":200},{"f":"tortillas","q":4},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"olive_oil","q":15}],"steps":["Cut two tortillas into thin strips, toss with a little of the oil, and toast in a dry skillet over medium heat for 4 to 5 minutes until crisp and golden; set aside.","Heat the remaining oil in a soup pot over medium, then soften the diced onion for 3 minutes and stir in the garlic, cumin, and chili powder until fragrant.","Add the chopped tomatoes, broth, and whole chicken breasts, bring to a lively simmer, and cook 12 minutes until the chicken registers 165°F.","Pull the chicken onto a board, shred it with two forks, and return it to the pot with the beans, corn, and the remaining two tortillas torn into pieces to thicken the broth.","Simmer 5 minutes more, squeeze in the lime, and taste for salt — the broth should be tangy and faintly smoky.","Ladle into bowls and crown with diced avocado and the crispy tortilla strips."],"tip":"The torn tortillas melting into the broth are doing quiet thickening work — skip them and you have chicken soup wearing a sombrero."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_lime_chicken_tacos', '{"id":"charred_lime_chicken_tacos","name":"Charred Lime Chicken Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"tortillas","q":4},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"olive_oil","q":15}],"steps":["Toss the chicken thighs with the oil, the juice of one lime, and a bold shower of chili powder, cumin, and salt; let them sit 5 minutes while a heavy skillet gets ripping hot.","Lay the thighs in the dry, hot pan and cook 4 to 5 minutes per side until the edges char and the thickest part hits 170°F — thighs forgive you, so lean into the color.","While the chicken rests, char the tortillas directly over the flame or in the skillet for 20 seconds per side until blistered and pliable.","Chop the rested chicken into bite-size pieces, catching every drop of juice on the board.","Pile the chicken into the warm tortillas and top with thin-sliced onion, avocado, a swipe of sour cream, and wedges of the second lime.","Serve immediately, ideally standing over the counter."],"tip":"Resting the thighs before chopping keeps the juice in the taco instead of on your cutting board, where it helps no one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tomato_chicken_penne', '{"id":"creamy_tomato_chicken_penne","name":"Creamy Tomato Chicken Penne with Spinach","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"penne","q":180},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"milk","q":120},{"f":"parmesan","q":40}],"steps":["Drop the penne into well-salted boiling water and cook until just shy of al dente, about 10 minutes; reserve a cup of the starchy water before draining.","Meanwhile, cube the chicken, season with salt and dried oregano, and brown it in the olive oil over medium-high heat for 5 to 6 minutes until golden and cooked through.","Add the garlic and chopped tomatoes to the pan and cook 3 to 4 minutes, mashing gently, until the tomatoes slump into a rough sauce.","Pour in the milk and a splash of pasta water, simmer 2 minutes until slightly thickened, then stir in the spinach to wilt.","Tumble in the drained penne with most of the parmesan and toss vigorously for a minute until the sauce turns silky and coats every tube.","Plate with the last of the parmesan grated over the top."],"tip":"That reserved pasta water is free sauce insurance — the starch marries milk and cheese into something that tastes suspiciously like heavy cream."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chicken_chopped_salad', '{"id":"greek_chicken_chopped_salad","name":"Greek Chicken Chopped Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"lemon","q":1}],"steps":["Butterfly the chicken breasts thin, rub with a spoonful of the olive oil, dried oregano, salt, and pepper, and sear in a hot skillet 3 to 4 minutes per side until golden with crisp edges.","Let the chicken rest on a board while you build the salad — cutting too soon floods your bowl with juice.","Chop the romaine into ribbons and toss it in a wide bowl with the diced cucumber, chopped tomatoes, and paper-thin slices of onion.","Whisk the remaining olive oil with the juice of the lemon, a pinch of salt, and a crack of pepper until it looks cloudy and emulsified.","Slice the rested chicken against the grain, lay it over the salad, and crumble the feta on top in craggy chunks.","Pour the dressing over everything and toss once, gently, at the table."],"tip":"Soak the sliced onion in cold water for five minutes if you enjoy conversation with other humans later tonight."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_coconut_chicken_curry', '{"id":"weeknight_coconut_chicken_curry","name":"Weeknight Coconut Chicken Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"coconut_milk","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"rice","q":120},{"f":"olive_oil","q":10}],"steps":["Start the rice: rinse, cover with water, and simmer lidded on low for 15 minutes, then rest off the heat.","Heat the oil in a deep skillet over medium and cook the sliced onion 4 to 5 minutes until soft and golden at the edges.","Stir in the minced garlic with a heaped spoonful of curry powder and a pinch of salt, toasting for 30 seconds until the kitchen smells unmistakably like dinner.","Add the chopped tomatoes and cook 3 minutes until they break down, then pour in the coconut milk and bring to a gentle bubble.","Slide in the cubed chicken and simmer 8 to 10 minutes, stirring occasionally, until the chicken is cooked through and the sauce coats a spoon.","Taste, adjust the salt, and ladle the curry over the fluffy rice."],"tip":"Toasting the curry powder in the onions for thirty seconds does more for flavor than doubling the amount ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sticky_honey_soy_chicken_bowl', '{"id":"sticky_honey_soy_chicken_bowl","name":"Sticky Glazed Chicken Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"rice","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2},{"f":"carrots","q":150},{"f":"cucumber","q":0.8}],"steps":["Set the rinsed rice to simmer, covered, over low heat for 15 minutes while everything else comes together.","Shave the carrots into ribbons with a peeler, slice the cucumber thin, and toss both with a splash of the soy sauce to lightly pickle.","Cut the chicken thighs into large chunks and brown them in the sesame oil over medium-high heat, 6 to 7 minutes, until the fat renders and the edges crisp.","Stir the honey, remaining soy sauce, and grated garlic together, pour it over the chicken, and let it bubble 2 minutes until it reduces to a dark, sticky glaze that clings to every piece.","Fluff the rice into two bowls, arrange the glazed chicken on one side and the cool vegetable ribbons on the other.","Drizzle any pan glaze over the top — that is the good stuff."],"tip":"Take the glaze off the heat the moment it turns syrupy; honey goes from lacquer to lollipop in about forty-five seconds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_black_bean_quesadillas', '{"id":"chicken_black_bean_quesadillas","name":"Crispy Chicken and Black Bean Quesadillas","emoji":"🧀","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"tortillas","q":4},{"f":"cheddar","q":100},{"f":"black_beans","q":150},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":10},{"f":"sour_cream","q":60}],"steps":["Dice the chicken small and sauté it in half the oil over medium-high heat with cumin, paprika, and salt for 4 to 5 minutes until cooked through and lightly browned.","Stir in the diced bell pepper and drained black beans, cooking 2 minutes more and mashing a few beans so the filling holds together.","Scatter cheddar over half of each tortilla, top with the chicken mixture and more cheese, and fold into half-moons — cheese on both sides of the filling is the glue.","Wipe out the skillet, film it with the remaining oil, and cook the quesadillas over medium heat 2 to 3 minutes per side until the tortillas are deeply golden and audibly crisp.","Rest them one minute so the molten cheese sets from lava to lush, then slice into wedges.","Serve with cool sour cream for dragging."],"tip":"Medium heat is non-negotiable — high heat gives you a burnt tortilla hugging cold cheese, and nobody deserves that."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_gyro_style_pitas_2', '{"id":"chicken_gyro_style_pitas_2","name":"Gyro-Style Chicken Pitas with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.8},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Slice the chicken into thin strips and toss with the olive oil, half the lemon''s juice, oregano, paprika, salt, and pepper.","Make the sauce: coarsely grate a third of the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the grated garlic, the remaining lemon juice, and a pinch of salt.","Sear the chicken in a very hot skillet for 5 to 6 minutes, tossing once, until the strips are browned at the edges and cooked through.","Warm the pitas in the same pan for 30 seconds per side so they turn soft and floppy.","Slice the tomato and remaining cucumber, shave the onion thin, and pile everything into the warm pitas with the sizzling chicken.","Spoon the garlicky yogurt sauce generously over the top and wrap tightly in foil or paper for structural integrity."],"tip":"Squeezing the grated cucumber dry is the difference between tzatziki and a sad yogurt puddle escaping down your wrist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_stovetop_chicken_chili', '{"id":"smoky_stovetop_chicken_chili","name":"Smoky 30-Minute Chicken Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"black_beans","q":400},{"f":"broth","q":750},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"sour_cream","q":80},{"f":"cheddar","q":60}],"steps":["Heat the oil in a Dutch oven over medium-high and sauté the diced onion and bell pepper for 4 minutes until softened and starting to color.","Add the garlic with a hefty spoonful each of chili powder, cumin, and paprika, stirring 30 seconds until the spices darken and bloom.","Stir in the diced chicken and cook 3 minutes until the outside turns opaque, then add the chopped tomatoes, beans, and broth.","Bring to a boil, then simmer briskly, uncovered, for 15 minutes until the chicken is tender and the chili has thickened enough to mound on a spoon.","Mash a ladleful of beans against the pot wall and stir it back in for body, then season with salt to taste.","Serve in deep bowls topped with grated cheddar and a cool spoonful of sour cream."],"tip":"Simmering uncovered is the whole trick — a lid traps steam and turns your chili into soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('better_than_takeout_chicken_fried_rice', '{"id":"better_than_takeout_chicken_fried_rice","name":"Better-Than-Takeout Chicken Fried Rice","emoji":"🍳","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","eggs","sesame"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"rice","q":150},{"f":"eggs","q":2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Cook the rice first and spread it on a plate for 10 minutes to steam off surface moisture — slightly dried rice is what fries instead of steams.","Dice the chicken small, then stir-fry it in half the sesame oil over high heat for 3 to 4 minutes until golden and cooked through; push it to one side.","Add the diced carrot and onion and stir-fry 2 minutes until the onion turns translucent and the carrot loses its rawness.","Pour the beaten eggs into the empty side of the pan, scramble them into soft curds, then break up everything together.","Add the remaining oil and the rice, pressing it flat against the hot pan for 30-second stretches so it crackles and picks up toasty spots.","Drizzle the soy sauce down the hot pan wall so it sizzles and caramelizes, toss with the garlic for a final minute, and serve steaming."],"tip":"Pouring soy sauce onto the hot pan instead of the rice caramelizes it on contact — that whiff of wok smoke is the takeout flavor you thought required a restaurant."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('broiled_chicken_souvlaki_skewers', '{"id":"broiled_chicken_souvlaki_skewers","name":"Broiled Chicken Souvlaki Skewers with Yogurt Dip","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"zucchini","q":1.5},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"greek_yogurt","q":100}],"steps":["Set the broiler to high with a rack about 6 inches from the element, and line a sheet pan with foil.","Cut the chicken, zucchini, and bell pepper into even 3-centimeter chunks and toss with the olive oil, half the lemon''s juice, two minced garlic cloves, oregano, salt, and pepper.","Thread the pieces onto skewers, alternating chicken and vegetables snugly but not crushed together, and arrange them on the pan.","Broil 6 to 7 minutes, flip, and broil 6 minutes more, until the edges char and the chicken registers 165°F at its thickest chunk.","While they cook, stir the yogurt with the last garlic clove, the remaining lemon juice, and a pinch of salt for the dip.","Rest the skewers 2 minutes, then serve hot with the cool garlicky yogurt alongside."],"tip":"Cut everything the same size or accept that your zucchini will be jam by the time the chicken is safe — the broiler shows no mercy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_penne_skillet', '{"id":"cheeseburger_penne_skillet","name":"Cheeseburger Penne Skillet","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":140},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":200},{"f":"broth","q":250},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"paprika","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in a deep 12-inch skillet over medium-high and brown the beef with the diced onion for 6 to 7 minutes, breaking it into rubble until deeply crusted at the edges.","Stir in the minced garlic, paprika, salt, and pepper and cook 30 seconds, just until the pan smells like a burger joint.","Pour in the crushed tomatoes and broth, scrape up the browned bits, and stir in the dry penne so every piece is submerged.","Cover and simmer over medium-low for 12 to 14 minutes, stirring twice, until the pasta is al dente and the sauce clings like a good chili.","Kill the heat, scatter the cheddar over the top, and lid it for 2 minutes until glossy and molten before serving straight from the pan."],"tip":"The pasta drinks the sauce as it sits, so if you dawdle, loosen it with a splash of broth rather than an apology."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_potato_cottage_pie', '{"id":"beef_potato_cottage_pie","name":"Weeknight Beef Cottage Pie","emoji":"🥧","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":55,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"potatoes","q":500},{"f":"milk","q":60},{"f":"butter","q":25},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"peas_frozen","q":80},{"f":"broth","q":150},{"f":"flour","q":10},{"f":"salt","q":5},{"f":"black_pepper","q":2},{"f":"oregano","q":1}],"steps":["Boil the peeled, chunked potatoes in well-salted water for 15 minutes until a knife slides in without resistance, then mash with the butter and warm milk until fluffy.","Meanwhile, brown the beef in a skillet over medium-high for 6 minutes, then add the diced onion and carrots and cook 5 more until the onion turns translucent and sweet.","Sprinkle the flour over the meat, stir for 1 minute to cook off the raw taste, then add the broth, oregano, salt, and pepper and simmer until it thickens to a gravy that coats a spoon.","Fold in the frozen peas, transfer the filling to a small baking dish, and rake the mash over the top with a fork so it ridges like a plowed field.","Bake at 400 F for 20 minutes until the peaks are bronzed and the gravy bubbles up the sides like lava at the edges."],"tip":"Those fork ridges on the mash are not decoration — more edges means more crispy brown bits, which is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tex_mex_bean_stuffed_peppers', '{"id":"tex_mex_bean_stuffed_peppers","name":"Tex-Mex Black Bean Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":2},{"f":"black_beans","q":250},{"f":"rice","q":70},{"f":"corn_frozen","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salsa","q":120},{"f":"cheddar","q":60},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":4}],"steps":["Simmer the rice in salted water for 15 minutes until just tender, and halve the peppers through the stem, pulling out the seeds and ribs to make four boats.","Soften the diced onion in the olive oil over medium heat for 4 minutes, then stir in the garlic, cumin, chili powder, and salt for 30 seconds until the pan smells toasty.","Add the black beans and corn, mashing a few beans against the pan so the filling binds, then fold in the cooked rice and salsa so everything turns brick-red and juicy.","Pack the filling into the pepper halves, nestle them in a baking dish with a splash of water on the bottom, and cover with foil.","Bake at 400 F for 25 minutes, then uncover, cap each with cheddar, and bake 5 more until the cheese blisters; shower with cilantro before serving."],"tip":"The splash of water in the dish steams the peppers tender — skip it and you will be sawing through raw pepper with a butter knife."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_rice_cabbage_rolls', '{"id":"beef_rice_cabbage_rolls","name":"Lemony Beef and Rice Cabbage Rolls","emoji":"🥬","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"ground_beef","q":250},{"f":"rice","q":60},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2},{"f":"sugar","q":5}],"steps":["Blanch 8 large cabbage leaves in boiling salted water for 3 minutes until they drape like wet silk, then drain and shave down the thick center rib of each so it rolls without cracking.","Mix the raw beef with the uncooked rice, grated onion, minced garlic, half the parsley, oregano, salt, and pepper until just combined — overworking makes them tough.","Roll a few spoonfuls of filling snugly in each leaf, tucking the sides in like a burrito, and shingle the rolls seam-side down in a wide pot.","Whisk the crushed tomatoes with the olive oil, sugar, lemon juice, and a cup of water, pour it over, and weigh the rolls down with a small plate so they stay submerged.","Cover and simmer gently for 45 minutes until the rice is swollen and tender and the sauce has thickened; finish with the remaining parsley and a fresh squeeze of lemon."],"tip":"The plate on top is non-negotiable — unweighted rolls float, unravel, and become very expensive cabbage soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_bean_chili_2', '{"id":"smoky_beef_bean_chili_2","name":"Smoky Beef and Black Bean Chili","emoji":"🌶️","cuisine":"American","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"black_beans","q":250},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":250},{"f":"corn_frozen","q":100},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"oregano","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":6}],"steps":["Heat the oil in a Dutch oven over medium-high and brown the beef hard for 8 minutes, leaving it alone in patches so it sears instead of steams.","Add the diced onion and bell pepper and cook 5 minutes until softened, then stir in the garlic, chili powder, cumin, paprika, and oregano and toast for 1 minute until the spices smell dusky and rich.","Pour in the crushed tomatoes and broth, scraping the fond off the bottom, and bring to a lazy bubble.","Simmer uncovered for 25 minutes, stirring occasionally, until the chili darkens a shade and thickens enough to mound on a spoon.","Stir in the beans and corn, simmer 5 more minutes to heat through, and season with salt until the flavors snap into focus."],"tip":"Chili judges its cook by patience — it tastes noticeably better tomorrow, so make it tonight and take credit twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_meatball_spaghetti', '{"id":"beef_meatball_spaghetti","name":"Sunday Beef Meatballs and Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"eggs","q":1},{"f":"parmesan","q":25},{"f":"flour","q":20},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"crushed_tomatoes","q":400},{"f":"spaghetti","q":130},{"f":"olive_oil","q":15},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Mix the beef gently with the egg, grated parmesan, flour, one minced garlic clove, oregano, salt, and pepper, then roll into 8 golf-ball meatballs with damp hands so nothing sticks.","Brown the meatballs in olive oil over medium heat for 6 minutes, turning until crusted on all sides but still pink inside — they finish in the sauce.","In the same pan, soften the diced onion and remaining garlic in the drippings for 3 minutes, then add the crushed tomatoes and a splash of water.","Slide the meatballs back in, cover, and simmer gently for 15 minutes until they are tender all the way through and the sauce has gone glossy and brick-red.","Boil the spaghetti in aggressively salted water until al dente, toss it through the sauce with torn basil, and serve with the meatballs perched on top."],"tip":"Roll the meatballs like you are handling a soap bubble — a tight squeeze today is a bouncy meatball tonight."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_style_beef_rice_bowls', '{"id":"korean_style_beef_rice_bowls","name":"Korean-Style Ground Beef Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten","sesame","eggs"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"sugar","q":15},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":0.5},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"eggs","q":2}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with a scant double volume of water for 15 minutes and let it rest off the heat.","Sear the beef in a hot skillet for 5 to 6 minutes, breaking it up, until the edges frizzle and brown; pour off all but a slick of fat.","Stir in the garlic, grated ginger, soy sauce, and sugar and let it bubble for 2 minutes until the meat glazes and turns lacquered and sticky.","Fry the eggs in the sesame oil until the whites are crisp-edged and the yolks still tremble.","Pile the beef over the rice, add shredded carrot and thin cucumber half-moons alongside, crown each bowl with an egg, and shower with sliced scallions."],"tip":"Break the yolk and stir it through everything immediately — it is the sauce you did not have to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_keema_matar', '{"id":"beef_keema_matar","name":"Beef Keema with Peas","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"crushed_tomatoes","q":200},{"f":"peas_frozen","q":120},{"f":"coconut_milk","q":100},{"f":"olive_oil","q":15},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Cook the finely diced onion in the oil over medium heat for 8 to 10 minutes, stirring often, until it turns deep golden — this slow start is where keema gets its backbone.","Add the minced garlic and grated ginger and fry 1 minute, then stir in the cumin, turmeric, and half the garam masala until the kitchen smells like a spice shop.","Crumble in the beef and cook over medium-high for 6 minutes, breaking it fine, until no pink remains and the fat runs golden and fragrant.","Add the crushed tomatoes and salt and simmer 10 minutes until the sauce thickens and the oil beads at the edges of the pan.","Stir in the peas and coconut milk, simmer 3 minutes more, then finish with the remaining garam masala and a fistful of chopped cilantro."],"tip":"When the oil separates and pools at the edges, that is not greasy — that is the curry telling you it is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_beef_zucchini_boats_2', '{"id":"italian_beef_zucchini_boats_2","name":"Italian Beef Zucchini Boats","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"ground_beef","q":250},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":200},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"olive_oil","q":15},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Halve the zucchini lengthwise and scoop out the seedy cores with a spoon, leaving quarter-inch walls; chop the scooped flesh and save it.","Brown the beef with the onion in olive oil over medium-high for 6 minutes until crusty, then add the garlic, chopped zucchini flesh, oregano, salt, and pepper and cook 3 more minutes.","Stir in the crushed tomatoes and simmer 5 minutes until the filling is thick enough to hold its shape on a spoon.","Arrange the boats in a baking dish, salt their insides lightly, mound in the filling, and top with mozzarella and parmesan.","Bake at 400 F for 20 to 25 minutes until the zucchini yields to a fork and the cheese is bubbling with brown freckles; scatter torn basil over the top."],"tip":"Quarter-inch walls are the sweet spot — thinner collapses into a puddle, thicker eats like raw squash with a meat hat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cuban_style_beef_picadillo', '{"id":"cuban_style_beef_picadillo","name":"Cuban-Style Beef Picadillo","emoji":"🥘","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"potatoes","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"olives","q":60},{"f":"broth","q":200},{"f":"cumin","q":5},{"f":"oregano","q":2},{"f":"cinnamon","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":6}],"steps":["Dice the potatoes into half-inch cubes and brown them in the olive oil over medium-high heat for 5 minutes until their edges turn golden; scoop them out and set aside.","In the same pot, brown the beef for 6 to 7 minutes, then add the diced onion and bell pepper and cook until soft and sweet, about 5 minutes more.","Stir in the garlic, cumin, oregano, and cinnamon and toast 30 seconds — the cinnamon should whisper, not shout.","Return the potatoes with the crushed tomatoes, broth, and salt, and simmer partially covered for 15 minutes until the potatoes are tender and the stew is thick and savory.","Stir in the sliced olives, simmer 2 final minutes so their brine ripples through the sauce, and serve in shallow bowls."],"tip":"The olives go in last on purpose — simmered too long they surrender their salty punch, and the punch is why they were invited."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_eggplant_moussaka_bake', '{"id":"beef_eggplant_moussaka_bake","name":"Weeknight Beef and Eggplant Moussaka Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy","eggs"],"time":70,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"ground_beef","q":250},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":250},{"f":"cinnamon","q":1},{"f":"oregano","q":2},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":150},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Slice the eggplant into half-inch rounds, brush both sides with most of the olive oil, and roast on a sheet pan at 425 F for 20 minutes until browned and collapsing.","Meanwhile, brown the beef with the onion in the remaining oil for 7 minutes, then add the garlic, cinnamon, oregano, salt, and pepper and cook until fragrant.","Pour in the crushed tomatoes and simmer 10 minutes until the sauce is thick, jammy, and barely wet.","Whisk the greek yogurt with the egg, half the parmesan, and a pinch of salt to make a quick tangy topping.","Layer half the eggplant in a small baking dish, spread on the meat sauce, shingle the rest of the eggplant over, spoon on the yogurt layer, and bake at 400 F for 20 minutes until puffed and gilded; rest 10 minutes before cutting."],"tip":"The 10-minute rest is the difference between clean, proud layers and an eggplant landslide on your plate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_beef_lettuce_wraps', '{"id":"ginger_beef_lettuce_wraps","name":"Ginger Beef Lettuce Wraps","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"romaine","q":1},{"f":"mushrooms","q":100},{"f":"carrots","q":80},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"sugar","q":10},{"f":"lime","q":0.5}],"steps":["Separate the romaine into whole leaves, rinse, and chill them so they stay snappy while you cook.","Sear the beef in a screaming-hot skillet for 5 minutes without crowding until it browns and crackles, then add the finely chopped mushrooms and cook 3 minutes until their moisture cooks off.","Add the garlic and grated ginger for 30 seconds, then splash in the soy sauce and sugar and toss until the meat glazes dark and glossy.","Off the heat, stir in the sesame oil, grated carrot, most of the scallions, and a hard squeeze of lime.","Spoon the hot filling into the cold leaves, top with the remaining scallions, and eat immediately with both hands and zero dignity."],"tip":"Cold crisp lettuce against hot glazed beef is the entire dish — lukewarm leaves turn it into a sad, floppy salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salisbury_beef_patties_mash', '{"id":"salisbury_beef_patties_mash","name":"Salisbury Beef Patties with Mushroom Gravy","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"eggs","q":1},{"f":"flour","q":15},{"f":"onion","q":1},{"f":"mushrooms","q":200},{"f":"broth","q":300},{"f":"butter","q":30},{"f":"potatoes","q":400},{"f":"milk","q":50},{"f":"balsamic_vinegar","q":10},{"f":"salt","q":6},{"f":"black_pepper","q":3}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until tender, then mash with half the butter and the warm milk until smooth and cloud-soft.","Mix the beef with the egg, a third of the onion grated fine, salt, and pepper, shape into two thick oval patties, and dust them lightly with some of the flour.","Sear the patties in a hot skillet for 3 minutes per side until mahogany-crusted, then move them to a plate — they will finish in the gravy.","Melt the remaining butter in the drippings, cook the sliced mushrooms and remaining onion for 6 minutes until browned and squeaky-soft, then stir in the rest of the flour for 1 minute.","Whisk in the broth and balsamic and simmer until the gravy coats a spoon, then return the patties and simmer 8 minutes, spooning gravy over, until cooked through and glistening.","Serve the patties over the mash with every last drop of gravy from the pan."],"tip":"Do not scrub that skillet between patties and gravy — the brown crust on the bottom is flavor you already paid for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_parm_meatballs_spaghetti', '{"id":"turkey_parm_meatballs_spaghetti","name":"Turkey Parmesan Meatballs with Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"flour","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"sugar","q":3},{"f":"spaghetti","q":120},{"f":"basil","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Mix the turkey with the egg, grated parmesan, flour, one minced garlic clove, half the salt, and a good grind of pepper, then roll into 12 balls with damp hands so nothing sticks.","Sear the meatballs in olive oil over medium-high heat for 6 to 8 minutes, turning until deeply browned on at least two sides — that crust is where the flavor lives.","Push the meatballs aside, soften the diced onion and remaining garlic for 3 minutes, then pour in the crushed tomatoes with the oregano and sugar.","Simmer gently, partially covered, for 15 minutes until the sauce darkens to brick red and the meatballs register cooked through at 74C.","Meanwhile boil the spaghetti in well-salted water until just shy of tender, then finish it in the sauce for a minute with a splash of pasta water.","Shower with torn basil and serve while the sauce still clings glossily to every strand."],"tip":"Wet hands and a light touch make tender meatballs; squeeze them like stress balls and they will eat like them too."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_street_tacos', '{"id":"turkey_street_tacos","name":"Smoky Turkey Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":2},{"f":"salsa","q":120},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oil in a wide skillet until shimmering, then press the turkey into an even layer and leave it alone for 3 full minutes so the underside browns and crisps at the edges.","Break the meat into rubble, stir in the diced onion and minced garlic, and cook 3 minutes more until the onion turns translucent.","Season with chili powder, cumin, paprika, and salt, toast the spices for 30 seconds until fragrant, then stir in the salsa and simmer 2 minutes so the filling turns saucy but not wet.","Char the tortillas directly over a burner flame or in a dry pan for 20 seconds a side until blistered and pliable.","Pile the filling into the tortillas and top with sliced avocado, a hard squeeze of lime, and a flurry of chopped cilantro."],"tip":"The three minutes of not touching the turkey is the whole recipe — stir early and you get gray steam-meat instead of crispy taco gold."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_larb_lettuce_cups', '{"id":"turkey_larb_lettuce_cups","name":"Thai-Style Turkey Larb Lettuce Cups","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"rice","q":30},{"f":"ground_turkey","q":450},{"f":"olive_oil","q":10},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":30},{"f":"lime","q":2},{"f":"honey","q":10},{"f":"chili_powder","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":1},{"f":"romaine","q":1},{"f":"cucumber","q":0.5}],"steps":["Toast the raw rice in a dry skillet over medium heat for 5 to 7 minutes, shaking often, until it turns deep golden and smells like popcorn, then grind it to a coarse powder.","Cook the turkey in the oil over high heat for 5 to 6 minutes, breaking it up finely and letting the pan juices evaporate until the meat sizzles rather than simmers.","Stir in the garlic and ginger for 30 seconds, then pull the pan off the heat and dress the warm meat with soy sauce, the juice of both limes, honey, and chili powder.","Fold in the sliced scallions, most of the cilantro, and the toasted rice powder, which gives the larb its signature nutty crunch.","Spoon into crisp romaine leaves, top with thin cucumber half-moons and the last of the cilantro, and eat immediately with extra lime on the side."],"tip":"Do not skip the toasted rice powder — it takes seven minutes and is the difference between larb and sad taco meat in a leaf."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_kofta_pita_plates', '{"id":"turkey_kofta_pita_plates","name":"Turkey Kofta Plates with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"parsley","q":0.8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2},{"f":"olive_oil","q":15},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"tomato","q":1}],"steps":["Grate the onion on the coarse holes and squeeze out the excess juice, then knead it into the turkey with two minced garlic cloves, most of the parsley, cumin, paprika, cinnamon, salt, and pepper until tacky.","Shape the mixture into 8 torpedo-shaped kofta and chill them for 10 minutes so they hold their shape on the heat.","Sear the kofta in olive oil over medium-high heat for 8 to 10 minutes, rolling them every few minutes, until mahogany-crusted on all sides and firm to the touch.","While they cook, stir the grated cucumber, remaining garlic, half the lemon juice, and a pinch of salt into the yogurt to make a quick cooling sauce.","Warm the pitas in the empty corner of the pan until soft and lightly toasted, then plate the kofta over them with tomato wedges, the yogurt sauce, and the rest of the parsley and lemon."],"tip":"Grated onion vanishes into the meat and keeps it juicy; chopped onion just gives you kofta that crack open like fault lines."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keema_matar', '{"id":"turkey_keema_matar","name":"Turkey Keema Matar with Basmati-Style Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":120},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"ground_turkey","q":400},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"chili_powder","q":2},{"f":"crushed_tomatoes","q":200},{"f":"peas_frozen","q":150},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Start the rice in a small pot with double its volume of salted water, cover, and let it steam on low for 15 minutes while you build the keema.","Fry the finely diced onion in the oil over medium heat for 8 to 10 minutes until it turns deep golden at the edges — this slow browning is the backbone of the dish, so do not rush it.","Stir in the minced garlic and ginger for a minute, then add the turkey and cook 5 minutes, mashing it into fine crumbles.","Bloom the garam masala, turmeric, cumin, chili powder, and salt in the fat for 30 seconds until the kitchen smells unmistakably like dinner, then pour in the crushed tomatoes.","Simmer 10 minutes until the sauce thickens and pools of oil break at the surface, then fold in the peas for the final 3 minutes so they stay sweet and bright green.","Serve the keema over the fluffed rice with a generous handful of chopped cilantro."],"tip":"When the oil separates and beads on top of the sauce, the keema is done — that shimmer is Indian home cooking''s built-in doneness thermometer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_white_bean_chili', '{"id":"turkey_white_bean_chili","name":"White Bean Turkey Chili","emoji":"🍲","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"cumin","q":8},{"f":"oregano","q":4},{"f":"chili_powder","q":4},{"f":"broth","q":750},{"f":"white_beans","q":400},{"f":"corn_frozen","q":150},{"f":"lime","q":1},{"f":"cilantro","q":1},{"f":"sour_cream","q":100},{"f":"salt","q":5}],"steps":["Brown the turkey in the oil in a Dutch oven over medium-high heat for 5 to 6 minutes, breaking it into bite-size crumbles and letting it pick up golden spots.","Add the diced onion, bell pepper, and garlic and cook 5 minutes until softened, then toast the cumin, oregano, chili powder, and salt in the mixture for 30 seconds.","Pour in the broth, scrape up every browned bit from the bottom, and add the white beans; mash about a third of them against the pot wall to give the chili body.","Simmer uncovered for 20 minutes, stirring occasionally, until the liquid reduces to a loose, spoon-coating stew and the flavors taste rounded rather than sharp.","Stir in the corn and lime juice for the last 3 minutes, then ladle into bowls topped with a swirl of sour cream and plenty of cilantro."],"tip":"Mashing a few beans thickens the chili better than any starch, and nobody at the table will ever know your secret was violence."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_smash_burgers', '{"id":"turkey_smash_burgers","name":"Crispy-Edge Turkey Smash Burgers","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"salt","q":4},{"f":"black_pepper","q":2},{"f":"paprika","q":2},{"f":"olive_oil","q":10},{"f":"cheddar","q":60},{"f":"bread","q":4},{"f":"butter","q":15},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.5},{"f":"romaine","q":0.2},{"f":"tomato","q":1}],"steps":["Divide the turkey into 4 loose balls, season the outsides with salt, pepper, and paprika, and get a cast-iron skillet screaming hot with a slick of oil.","Drop in two balls at a time and smash them flat with a sturdy spatula, pressing hard for 10 seconds so maximum meat kisses the metal.","Cook undisturbed for 2 to 3 minutes until the edges turn lacy and deep brown, then flip, lay cheddar on each patty, and give them 2 minutes more to melt and finish cooking through.","Butter the bread slices and toast them in the same skillet until golden, soaking up all the savory drippings.","Stir the paprika into the yogurt for a two-second sauce, then stack each burger with shaved onion, romaine, and thick tomato slices between the toasted bread."],"tip":"Turkey has no fat to spare, so the ripping-hot pan is non-negotiable — a timid skillet gives you a beige frisbee, not a burger."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_stuffed_peppers_2', '{"id":"italian_turkey_stuffed_peppers_2","name":"Italian Turkey and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":80},{"f":"ground_turkey","q":350},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"oregano","q":3},{"f":"basil","q":0.5},{"f":"mozzarella","q":60},{"f":"parmesan","q":20},{"f":"salt","q":4}],"steps":["Heat the oven to 200C, halve the peppers through the stem, scoop out the seeds, and roast the empty shells cut-side up for 10 minutes so they get a head start on softening.","Meanwhile simmer the rice in salted water until just tender, and brown the turkey in olive oil with the onion and garlic for 6 minutes, seasoning with oregano and salt.","Stir two-thirds of the crushed tomatoes and the cooked rice into the meat and let it bubble 3 minutes until the filling is juicy but holds together on a spoon.","Mound the filling into the pepper halves, spoon the remaining tomatoes over the top, and cap each with torn mozzarella and a snowfall of parmesan.","Bake 20 to 25 minutes until the cheese is bronzed and bubbling and a knife slides through the pepper walls with no resistance, then rest 5 minutes and finish with basil."],"tip":"Pre-roasting the empty peppers is the cure for that classic stuffed-pepper tragedy: molten filling trapped inside a raw, crunchy shell."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_turkey_rice_soup', '{"id":"ginger_turkey_rice_soup","name":"Ginger Turkey and Rice Soup","emoji":"🥣","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"sesame_oil","q":10},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"mushrooms","q":150},{"f":"broth","q":1500},{"f":"rice","q":120},{"f":"soy_sauce","q":20},{"f":"spinach","q":100},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Sizzle the julienned ginger and sliced garlic in the sesame oil over medium heat for a minute until fragrant, then add the turkey and cook 5 minutes, breaking it into small nubs.","Add the sliced carrots and mushrooms and stir for 2 minutes until the mushrooms start to release their juices and slump.","Pour in the broth and rice, bring to a boil, then lower to a gentle simmer for 20 minutes until the rice grains swell and start to fray at the edges, thickening the soup slightly.","Season with soy sauce and black pepper, tasting as you go — the broth should be savory enough to make you take a second sip immediately.","Wilt in the spinach off the heat and serve steaming, showered with sliced scallions."],"tip":"Let the rice overcook a little on purpose; those blown-out grains turn the broth silky, like a congee that still respects your schedule."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_picadillo_rice', '{"id":"turkey_picadillo_rice","name":"Turkey Picadillo over Rice","emoji":"🫒","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"rice","q":120},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"cumin","q":5},{"f":"oregano","q":3},{"f":"cinnamon","q":1},{"f":"chili_powder","q":3},{"f":"crushed_tomatoes","q":250},{"f":"olives","q":50},{"f":"honey","q":5},{"f":"salt","q":4}],"steps":["Get the rice simmering in salted water, covered, on your back burner — it will land at the same time as the picadillo if you start it first.","Soften the diced onion and bell pepper in olive oil over medium heat for 5 minutes until sweet and slack, then stir in the garlic for 30 seconds.","Add the turkey and cook 5 to 6 minutes, crumbling it fine, until no pink remains and the pan bottom is glazed brown.","Season with cumin, oregano, cinnamon, chili powder, and salt, then stir in the crushed tomatoes, sliced olives, and honey.","Simmer uncovered for 10 minutes until the mixture is thick enough to mound on a spoon, tasting for the salty-sweet-briny balance that makes picadillo addictive, then serve over the fluffy rice."],"tip":"The pinch of cinnamon and drizzle of honey are doing the job raisins usually do — sweet whispers, not a dessert takeover."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_broccoli_stirfry', '{"id":"turkey_broccoli_stirfry","name":"Honey-Garlic Turkey and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":120},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":10},{"f":"broccoli","q":400},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":40},{"f":"honey","q":15},{"f":"sesame_oil","q":10},{"f":"scallions","q":1}],"steps":["Set the rice to steam, then stir the soy sauce, honey, and sesame oil together in a cup so the sauce is ready before anything hits the pan.","Heat a wok or your widest skillet over high heat with the olive oil until it just smokes, then add the broccoli florets with a splash of water and stir-fry 3 to 4 minutes until they turn vivid green with charred tips; scoop them out.","Add the turkey to the empty pan and press it flat, letting it sear untouched for 2 minutes before breaking it up and cooking 3 minutes more.","Stir in the minced garlic and ginger for 30 seconds, return the broccoli, and pour the sauce over everything, tossing for a minute until it bubbles and glazes each crumble and floret.","Serve over the rice, topped with sliced scallions while the glaze is still glossy."],"tip":"Cook the broccoli and the meat separately — a crowded pan steams instead of sears, and stir-fry is a game of elbow room."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_shepherds_pie', '{"id":"turkey_shepherds_pie","name":"Skillet Turkey Shepherd''s Pie","emoji":"🥧","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":55,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"milk","q":60},{"f":"butter","q":25},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"carrots","q":150},{"f":"garlic","q":0.2},{"f":"flour","q":10},{"f":"broth","q":200},{"f":"peas_frozen","q":100},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until a fork slides in without protest, then mash them with the butter, warm milk, and a good pinch of salt until smooth and spoonable.","Meanwhile brown the turkey in oil in an ovenproof skillet over medium-high heat for 5 minutes, then add the onion, diced carrots, and garlic and cook 5 minutes more until softening.","Sprinkle the flour and oregano over the meat, stir for a minute to cook off the raw taste, then pour in the broth and simmer 3 to 4 minutes until it thickens into a glossy gravy that coats the vegetables.","Fold in the peas, season with salt and pepper, then spread the mash over the filling in an even blanket and drag a fork across the top to raise ridges.","Broil 5 to 8 minutes until the ridges brown like toasted marshmallow and the gravy bubbles up around the edges; rest 5 minutes before serving so it slices instead of slides."],"tip":"Those fork ridges on the mash are not decoration — every peak is a future crispy bit, so rake generously."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_dan_dan_noodles', '{"id":"turkey_dan_dan_noodles","name":"Turkey Dan Dan-Style Peanut Noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"ground_turkey","q":350},{"f":"olive_oil","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":35},{"f":"peanut_butter","q":45},{"f":"sesame_oil","q":15},{"f":"sugar","q":5},{"f":"chili_powder","q":3},{"f":"spinach","q":100},{"f":"scallions","q":1}],"steps":["Soak or boil the rice noodles according to the package until just tender, then rinse briefly and reserve a cup of their cooking water.","Whisk the peanut butter, soy sauce, sesame oil, sugar, chili powder, and 100 ml of the hot noodle water into a sauce the texture of heavy cream.","Fry the turkey in olive oil over high heat for 6 to 7 minutes, pressing and scraping until the crumbles turn deeply browned and almost crispy — this is the crunchy topping, so push past golden.","Add the minced garlic and ginger to the meat for the last minute, then wilt the spinach into the pan just until it collapses.","Toss the noodles with the peanut sauce, loosening with extra noodle water if it tightens, then pile the crispy turkey and spinach on top and finish with sliced scallions."],"tip":"The sauce will seize into paste the moment it cools, so keep that noodle water close like a sous chef with a squeeze bottle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_pork_stir_fry', '{"id":"honey_garlic_pork_stir_fry","name":"Honey-Garlic Pork Loin Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"broccoli","q":400},{"f":"rice","q":120},{"f":"soy_sauce","q":45},{"f":"honey","q":30},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.4},{"f":"olive_oil","q":15}],"steps":["Start the rice in simmering water so it finishes while you cook, and slice the pork loin against the grain into thin strips no thicker than a pencil.","Heat the olive oil in your widest skillet over high heat until it shimmers, then sear the pork in a single layer for 2 minutes per side until the edges brown and crisp; work in two batches so it sizzles instead of steams.","Push the pork aside, add the broccoli florets with a splash of water, and cover for 3 minutes until they turn vivid green and just tender at the stem.","Whisk the soy sauce, honey, and minced garlic together, pour it over everything, and toss for 90 seconds until the sauce bubbles, thickens, and clings glossily to the meat.","Kill the heat, drizzle in the sesame oil for that toasty finishing aroma, and pile it all over the steamed rice."],"tip":"Freeze the pork for 15 minutes before slicing and it cuts into ribbons instead of squirming under your knife."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_loin_street_tacos', '{"id":"pork_loin_street_tacos","name":"Charred Pork Loin Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"tortillas","q":4},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into small half-inch cubes and season them aggressively with salt, cumin, and chili powder so every piece wears a rusty red coat.","Get the olive oil ripping hot in a cast-iron skillet over high heat, then spread the pork out and leave it alone for 3 minutes until the bottoms are deeply charred before tossing.","Add the sliced onion and bell pepper and cook 4 to 5 minutes more, until the peppers blister and the onions pick up sweet blackened edges.","Warm the tortillas directly over a burner flame for 20 seconds a side until they puff and catch a few toasty spots.","Pile the pork mixture into the tortillas, crown with mashed avocado, and finish with a hard squeeze of lime over everything."],"tip":"A screaming-hot pan is your marinade substitute — char is a flavor, and it works in half the time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_pork_penne', '{"id":"tuscan_pork_penne","name":"Tuscan Pork Loin Penne with Spinach","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"penne","q":160},{"f":"spinach","q":100},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"parmesan","q":30},{"f":"olive_oil","q":20}],"steps":["Drop the penne into well-salted boiling water and cook until just shy of al dente, reserving a cup of the starchy water before you drain.","Meanwhile, slice the pork loin into thin medallions, season with salt, pepper, and dried oregano, and sear in olive oil over medium-high heat for 2 to 3 minutes per side until golden with a blush of pink inside.","Lower the heat, add the sliced garlic and chopped tomatoes, and cook 4 minutes until the tomatoes slump into a rough, jammy sauce.","Tumble in the spinach by the handful and stir until it wilts to a silky dark green, about 1 minute.","Add the penne with a splash of pasta water and half the parmesan, tossing until the sauce turns creamy and coats every tube, then serve with the rest of the cheese showered on top."],"tip":"That reserved pasta water is liquid gold — it turns three ingredients into a sauce that tastes like it took all afternoon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_loin_yogurt_curry', '{"id":"pork_loin_yogurt_curry","name":"Pork Loin Tikka-Style Yogurt Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"spinach","q":100},{"f":"rice","q":120},{"f":"olive_oil","q":15}],"steps":["Cube the pork loin and toss it with a third of the yogurt, salt, garam masala, and turmeric, letting it sit while you prep — even 15 minutes tenderizes noticeably.","Cook the rice, then heat the olive oil in a deep pan over medium heat and fry the finely chopped onion for 8 minutes until deeply golden and smelling sweet, not just soft.","Add the minced garlic and chopped tomatoes and cook them down for 5 minutes, mashing occasionally, until the mixture darkens and the oil separates at the edges.","Add the pork with its marinade and simmer gently for 12 to 15 minutes, stirring now and then, until the meat is just cooked through and the sauce thickens to coat a spoon.","Stir in the spinach and remaining yogurt off the heat so it stays creamy rather than curdling, then serve the curry over the rice."],"tip":"Take the yogurt off direct heat before stirring it in — a broken curry tastes fine but looks like a science experiment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_pita_wraps', '{"id":"pork_souvlaki_pita_wraps","name":"Pork Souvlaki Pitas with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":0.5},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into one-inch chunks and marinate with olive oil, half the lemon''s juice, dried oregano, salt, and pepper for at least 15 minutes.","Grate the cucumber, squeeze it dry in your fist like you mean it, and stir it into the yogurt with a pinch of salt and the remaining lemon juice for a quick tzatziki-style sauce.","Thread the pork onto skewers and grill or broil on high for 10 to 12 minutes, turning twice, until the edges char and the centers are just barely blush.","Warm the pitas in a dry skillet for 30 seconds a side until soft and steamy.","Slather each pita with the yogurt sauce, pile on the pork, sliced tomatoes, and thin half-moons of onion, then fold and eat over a plate — there will be drips."],"tip":"Squeeze the grated cucumber until your forearm complains; watery tzatziki is the number-one wrap crime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_pork_potato_stew', '{"id":"mexican_pork_potato_stew","name":"Smoky Mexican Pork and Potato Stew","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"pork_loin","q":600},{"f":"broth","q":1000},{"f":"potatoes","q":500},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"lime","q":1},{"f":"olive_oil","q":20}],"steps":["Cube the pork loin, season with salt, paprika, and cumin, and brown it in olive oil over medium-high heat in a heavy pot until every side has a mahogany crust, about 6 minutes total.","Lift the pork out, then soften the chopped onion, bell peppers, and garlic in the same pot for 5 minutes, scraping up the browned bits stuck to the bottom — that fond is the soul of the stew.","Return the pork, pour in the broth, and bring to a simmer, skimming any foam that rises.","Add the potatoes cut into bite-size chunks and simmer uncovered for 25 to 30 minutes, until they are fork-tender and the broth has reduced to something silky.","Squeeze in the lime juice, taste for salt, and ladle into bowls while it steams."],"tip":"Brown the pork in batches even when you''re hungry — a crowded pot makes gray stew meat and gray stew meat makes sad soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_pork_sheet_pan', '{"id":"maple_glazed_pork_sheet_pan","name":"Maple-Glazed Pork Loin Sheet-Pan Dinner","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"sweet_potatoes","q":400},{"f":"broccoli","q":300},{"f":"maple_syrup","q":40},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 425°F (220°C) and cut the sweet potatoes into one-inch chunks, tossing them with half the olive oil and a big pinch of salt on a large sheet pan.","Roast the sweet potatoes alone for 15 minutes to get a head start — they always take longer than they claim.","Rub the pork loin with the remaining oil, minced garlic, salt, and plenty of black pepper, then nestle it in the center of the pan and scatter the broccoli florets around it.","Brush the pork with maple syrup and roast 20 to 25 minutes more, brushing once again halfway, until the glaze lacquers to a bronze shine and a thermometer in the center reads 145°F (63°C).","Rest the pork for 5 minutes before slicing thick — the juices need a moment to settle back where they belong."],"tip":"That 5-minute rest is not optional; carve early and you''ll watch your dinner''s juices run away across the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_pork_noodle_soup', '{"id":"gingery_pork_noodle_soup","name":"Pork Loin and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"pork_loin","q":500},{"f":"rice_noodles","q":200},{"f":"broth","q":1500},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15}],"steps":["Slice the pork loin into paper-thin strips and the mushrooms into thick slabs while the broth comes to a gentle simmer in a large pot.","Add the smashed garlic and soy sauce to the broth and let it burble for 10 minutes so the liquid picks up a deep, savory backbone.","Slide in the mushrooms and simmer 5 minutes until they turn slippery and bob willingly in the broth.","Add the pork strips and cook just 2 to 3 minutes — thin slices poach fast, and overcooked loin turns to erasers — then stir in the spinach until it collapses.","Meanwhile, soak the rice noodles in hot water until pliable, divide them among four bowls, ladle the soup over top, and finish each bowl with a fragrant drizzle of sesame oil."],"tip":"Keep the noodles out of the pot until serving time, or by tomorrow your soup will be a casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_pork_milanese', '{"id":"crispy_pork_milanese","name":"Crispy Pork Loin Milanese with Lemony Spinach","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"flour","q":60},{"f":"eggs","q":2},{"f":"parmesan","q":40},{"f":"spinach","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":30}],"steps":["Slice the pork loin into four cutlets and pound each between plastic wrap to a quarter-inch thickness — you want them thin enough to cook before the crust burns.","Set up two dishes: seasoned flour mixed with half the grated parmesan in one, beaten eggs in the other, then dredge each cutlet through flour, egg, and flour again, pressing so the coating hugs the meat.","Heat the olive oil in a large skillet over medium-high until a pinch of flour sizzles instantly, then fry the cutlets 2 to 3 minutes per side until deeply golden, crackly, and cooked through.","Drain them on a rack, not paper towels, and hit them with flaky salt while they''re still glistening.","Toss the fresh spinach with lemon juice, a thread of oil, and the remaining parmesan, then pile it right on top of the hot cutlets so it wilts ever so slightly."],"tip":"A rack keeps the crust crisp; paper towels steam the underside and undo all your good frying work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smothered_pork_mushroom_skillet', '{"id":"smothered_pork_mushroom_skillet","name":"Smothered Pork Loin with Mushroom Gravy and Mash","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"mushrooms","q":250},{"f":"potatoes","q":500},{"f":"onion","q":1},{"f":"broth","q":250},{"f":"butter","q":30},{"f":"milk","q":100}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 to 18 minutes until a knife slides through without resistance, then mash with the milk and half the butter until fluffy and keep warm.","Season two thick pork loin steaks with salt and pepper and sear them in the remaining butter over medium-high heat for 3 to 4 minutes per side, until burnished brown, then set aside on a plate.","In the same skillet, cook the sliced mushrooms and onion for 8 minutes, resisting the urge to stir constantly, until the mushrooms release their water and then brown at the edges.","Pour in the broth and scrape the skillet clean, simmering 5 minutes until the liquid reduces by half into a loose, savory gravy.","Return the pork and its plate juices, spoon the mushrooms over top, and simmer 2 gentle minutes before serving the whole affair over the mash."],"tip":"Mushrooms brown only after their water cooks off, so let them sputter and shrink in peace before you judge them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_black_bean_rice_bowl', '{"id":"pork_black_bean_rice_bowl","name":"Cumin Pork and Black Bean Rice Bowl","emoji":"🥑","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"rice","q":120},{"f":"black_beans","q":200},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Get the rice simmering, then dice the pork loin into small cubes and toss with salt, cumin, and a little chili powder until evenly dusted.","Heat the olive oil in a skillet over medium-high and cook the pork with the diced onion for 6 to 8 minutes, stirring occasionally, until the cubes are browned outside and just cooked through.","Add the black beans with a splash of water and warm them 2 minutes, mashing a few against the pan so they get creamy and bind to the pork.","Dice the tomatoes and toss with lime juice and a pinch of salt for a thirty-second salsa.","Build the bowls: rice on the bottom, the pork and beans in the middle, then the tomato salsa and fanned slices of avocado on top with a last squeeze of lime."],"tip":"Mash a spoonful of the beans into the pan and suddenly your bowl has a sauce nobody had to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_herb_pork_loin_roast', '{"id":"lemon_herb_pork_loin_roast","name":"Lemon-Herb Pork Loin Roast with Vegetables","emoji":"🍖","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"potatoes","q":400},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Heat the oven to 400°F (200°C) and rub the pork loin all over with half the olive oil, minced garlic, lemon zest, dried rosemary, salt, and cracked pepper.","Sear the roast in a hot ovenproof pan for 2 to 3 minutes per side until the whole surface is golden and your kitchen smells like a taverna.","Toss the chunked potatoes, thick carrot coins, and onion wedges with the rest of the oil and scatter them around the pork.","Roast for 35 to 45 minutes, turning the vegetables once, until the potatoes are crusty at the edges and the pork''s center hits 145°F (63°C) on a thermometer.","Rest the roast under foil for 10 minutes, squeeze the lemon over the pan vegetables, and carve into thick, juicy slices."],"tip":"Buy a meat thermometer; pork loin gives you about a five-degree window between succulent and shoe leather."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_pork_feta_spinach_salad', '{"id":"warm_pork_feta_spinach_salad","name":"Warm Pork Loin, Feta, and Spinach Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Slice the pork loin into medallions, season with salt, pepper, and dried oregano, and sear in half the olive oil over medium-high heat for 3 minutes per side until golden with just a whisper of pink inside.","While the pork rests, pile the spinach into a wide bowl with the chopped tomatoes, sliced cucumber, and paper-thin onion.","Whisk the remaining olive oil with the lemon juice, a pinch of salt, and pepper until it emulsifies into a cloudy dressing.","Slice the rested pork and lay it warm over the salad so the spinach softens slightly under the heat.","Drizzle the dressing over everything, crumble the feta on top, and toss gently at the table so the cheese stays in proud chunks."],"tip":"Warm meat plus cold crisp salad is the whole trick here, so dress and serve it the minute the pork is sliced."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_salmon_sheet_pan', '{"id":"maple_glazed_salmon_sheet_pan","name":"Maple-Glazed Salmon Sheet Pan with Sweet Potatoes","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":40,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"sweet_potatoes","q":450},{"f":"broccoli","q":300},{"f":"olive_oil","q":20},{"f":"maple_syrup","q":30},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 425F and cut the sweet potatoes into 2cm cubes, tossing them on a rimmed sheet pan with half the olive oil and a good pinch of salt.","Roast the sweet potatoes alone for 15 minutes until the edges just start to caramelize, then push them to one side of the pan.","Add the broccoli florets tossed in the remaining oil, nestle the salmon fillets skin-side down in the center, and brush the fish with maple syrup whisked with the minced garlic.","Roast everything for 12 to 14 minutes more, until the glaze is bubbling at the edges and the salmon flakes when nudged with a fork but still looks rosy in the thickest part.","Rest the pan for 3 minutes so the juices settle, then spoon any syrupy pan drippings back over the fish before serving."],"tip":"Give the sweet potatoes their 15-minute head start or you will eat perfect salmon with crunchy disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('teriyaki_salmon_rice_bowl', '{"id":"teriyaki_salmon_rice_bowl","name":"Sticky Teriyaki Salmon Rice Bowl","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"rice","q":150},{"f":"broccoli","q":300},{"f":"soy_sauce","q":30},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Rinse the rice until the water runs clear, then simmer it covered with 300ml of water for 15 minutes and let it steam off the heat while you cook everything else.","Whisk the soy sauce, honey, and minced garlic in a small bowl until the honey dissolves into a glossy glaze.","Sear the salmon fillets skin-side down in the sesame oil over medium-high heat for 4 minutes, until the skin crackles and releases from the pan on its own.","Flip the fish, pour in the glaze, and let it bubble and reduce for 2 to 3 minutes, spooning it over the salmon until it coats the fillets like lacquer.","Steam the broccoli florets for 4 minutes until bright green with a slight bite, then pile everything over the rice and drizzle with the pan sauce."],"tip":"Do not touch the salmon while the skin sears; it will release from the pan the moment it is actually crisp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_yogurt_curry', '{"id":"salmon_spinach_yogurt_curry","name":"Salmon and Spinach Yogurt Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":40,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"greek_yogurt","q":150},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"butter","q":15},{"f":"rice","q":120}],"steps":["Start the rice simmering in salted water, then melt the butter in a deep skillet and cook the sliced onion over medium heat for 8 minutes until deeply golden and sweet-smelling.","Stir in the minced garlic with a generous spoonful of curry spices and toast for 60 seconds, until the pan smells warm and slightly nutty.","Add the spinach in handfuls with a splash of water, letting each batch collapse into a silky green tangle before adding the next.","Cut the salmon into large chunks, nestle them into the greens, cover, and simmer gently for 6 to 7 minutes until the fish turns opaque and flakes at a poke.","Pull the pan off the heat, wait 2 minutes, then stir in the yogurt until the sauce turns pale and creamy, and serve it spooned over the rice."],"tip":"Stir the yogurt in off the heat or it will split into curds and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_salmon_penne', '{"id":"lemon_salmon_penne","name":"Lemon Salmon Penne with Wilted Spinach","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"penne","q":150},{"f":"spinach","q":100},{"f":"parmesan","q":40},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1}],"steps":["Boil the penne in aggressively salted water until just shy of al dente, and scoop out a mugful of the starchy cooking water before you drain.","Meanwhile, sear the salmon in olive oil over medium-high heat for 3 minutes per side until golden outside and barely translucent within, then break it into large flakes on a plate.","Soften the sliced garlic in the same pan for 30 seconds, add the spinach, and toss until it wilts into glossy ribbons.","Return the pasta to the pan with the lemon zest, lemon juice, and a generous splash of pasta water, tossing over the heat until the liquid turns silky.","Fold in the grated parmesan and the flaked salmon gently, loosening with more pasta water until the sauce clings to every tube, and serve immediately."],"tip":"Fold the salmon in last and gently, unless you enjoy expensive fish confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salmon_couscous_plate', '{"id":"greek_salmon_couscous_plate","name":"Greek Salmon and Feta Couscous Plate","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"couscous","q":120},{"f":"cucumber","q":1},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Pour 150ml of boiling salted water over the couscous, cover the bowl with a plate, and leave it for 5 minutes before fluffing with a fork into light, separate grains.","Rub the salmon with half the olive oil, salt, and dried oregano, and roast at 400F for 12 minutes until it flakes but still glistens at the center.","Dice the cucumber small and toss it through the couscous with the lemon zest, lemon juice, and the remaining olive oil.","Crumble the feta over the couscous so it stays in creamy, briny pockets rather than dissolving.","Set the salmon fillets on top, spoon over any roasting juices, and finish with a final squeeze of lemon and a crack of black pepper."],"tip":"Fluff couscous with a fork, never a spoon, unless your dinner plans include edible spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('blackened_salmon_tacos', '{"id":"blackened_salmon_tacos","name":"Blackened Salmon Tacos with Avocado Crema","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"romaine","q":0.5},{"f":"lemon","q":1}],"steps":["Mash the avocado with the sour cream, half the lemon juice, and a pinch of salt until it is smooth enough to drizzle but thick enough to cling.","Coat the salmon generously with paprika, cumin, and salt, pressing the spices on so they form a crust.","Sear the fillets in a screaming-hot dry skillet for 3 minutes per side, until the spice crust turns nearly black and fragrant and the fish flakes into big juicy pieces.","Char the tortillas directly over a flame or in the empty skillet for 20 seconds a side, until puffed and speckled brown.","Shred the romaine finely, pile it into the warm tortillas, top with chunks of blackened salmon, and finish with the crema and the last squeeze of lemon."],"tip":"Blackened means bold and smoky, not a smoke-alarm serenade, so open a window before the skillet gets loud."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_salmon_potato_chowder', '{"id":"smoky_salmon_potato_chowder","name":"Smoky Salmon and Potato Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"potatoes","q":600},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3}],"steps":["Melt the butter in a heavy pot and sweat the diced onion with a pinch of salt over medium heat for 6 minutes, until translucent and sweet but not browned.","Stir in the minced garlic and a big pinch of paprika, then add the potatoes cut into 2cm chunks with 400ml of water and a teaspoon of salt.","Simmer for 15 minutes until a knife slides through the potatoes, then mash a few chunks against the side of the pot to thicken the broth naturally.","Pour in the milk, bring it back to a bare shiver of a simmer, and slide in the salmon cut into large bite-sized pieces.","Poach gently for 5 to 6 minutes, until the fish turns pale pink and flakes without resistance, then season with black pepper and serve while it steams."],"tip":"Chowder rewards patience: keep it at a whisper of a simmer after the milk goes in and it will keep its silk instead of curdling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_salmon_noodle_stirfry', '{"id":"sesame_salmon_noodle_stirfry","name":"Sesame Salmon Noodle Stir-Fry","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice_noodles","q":150},{"f":"broccoli","q":250},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":12},{"f":"honey","q":15},{"f":"garlic","q":0.3}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly firm, then drain and rinse under cold water so they do not clump.","Cut the salmon into 3cm cubes and sear them in half the sesame oil over high heat for 2 minutes per side, until golden at the edges, then set them aside.","Stir-fry the broccoli florets and sliced bell pepper in the remaining oil for 3 to 4 minutes, until the pepper blisters and the broccoli turns emerald with charred tips.","Add the minced garlic for 30 seconds, then toss in the noodles with the soy sauce and honey, dragging everything through the pan until the noodles turn glossy.","Return the salmon cubes, toss once or twice with a light hand so they stay intact, and serve straight from the smoking-hot pan."],"tip":"A stir-fry waits for no one, so chop everything before the pan even thinks about heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('herbed_salmon_burgers', '{"id":"herbed_salmon_burgers","name":"Herbed Salmon Burgers with Lemon-Yogurt Sauce","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","eggs","gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"eggs","q":1},{"f":"bread","q":2},{"f":"greek_yogurt","q":100},{"f":"romaine","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Tear the bread into crumbs and pulse or finely chop the salmon until it holds together like coarse ground meat, leaving a few larger flakes for texture.","Mix the salmon with the crumbs, egg, lemon zest, salt, and pepper, then chill the mixture for 10 minutes so the patties firm up.","Shape two thick patties and pan-fry them in the olive oil over medium heat for 4 minutes per side, until deeply golden with an interior that is just cooked through and still moist.","Stir the yogurt with the lemon juice and a pinch of salt into a bright, tangy sauce while the burgers rest for 2 minutes.","Serve the patties on crisp romaine leaves with the sauce spooned generously on top."],"tip":"Chill the patties before frying; warm salmon mix flops like a handshake from a jellyfish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_souvlaki_skewers', '{"id":"salmon_souvlaki_skewers","name":"Salmon Souvlaki Skewers with Yogurt Sauce and Pita","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"greek_yogurt","q":120},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2},{"f":"pita","q":2}],"steps":["Cut the salmon into 3cm cubes and toss them with the olive oil, lemon zest, half the minced garlic, oregano, and salt, marinating for 15 minutes while you prep the rest.","Grate the cucumber, squeeze out the water with your fists, and stir it into the yogurt with the remaining garlic and a squeeze of lemon for a quick tzatziki-style sauce.","Thread the salmon onto skewers alternating with chunks of bell pepper and onion, packing them snugly so nothing spins.","Grill or broil the skewers 4 minutes per side, until the edges char and the fish turns opaque but still yields to gentle pressure.","Warm the pitas on the grill for 30 seconds a side and serve the skewers on top with the cold yogurt sauce and the last lemon wedges."],"tip":"Squeeze the grated cucumber like it owes you money, or your sauce becomes soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_kedgeree_skillet', '{"id":"salmon_kedgeree_skillet","name":"Salmon Kedgeree with Soft-Boiled Eggs","emoji":"🍳","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice","q":140},{"f":"eggs","q":2},{"f":"butter","q":20},{"f":"onion","q":1},{"f":"spinach","q":100}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then plunge them into cold water so the yolks stay jammy, and peel and halve them.","Simmer the rice in salted water until just tender, drain it well, and spread it out to steam dry so the grains stay distinct.","Melt the butter in a wide skillet and fry the sliced onion with a heaped teaspoon of curry powder for 8 minutes, until golden and intensely fragrant.","Lay the salmon on top of the onions with a splash of water, cover, and steam for 6 minutes until it flakes, then break it into chunks right in the pan.","Fold in the rice and spinach and toss over medium heat until the leaves wilt and every grain turns turmeric-gold, then crown with the halved eggs and plenty of black pepper."],"tip":"Seven minutes for the eggs, not eight; kedgeree deserves yolks that flow, not sulk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_salmon_avocado_salad', '{"id":"seared_salmon_avocado_salad","name":"Seared Salmon and Avocado Salad","emoji":"🥑","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"cucumber","q":1},{"f":"olive_oil","q":25},{"f":"lemon","q":1}],"steps":["Pat the salmon bone-dry, season it boldly with salt and pepper, and sear it skin-side down in a hot skillet with a third of the olive oil for 5 minutes, until the skin shatters like a chip.","Flip and cook 2 minutes more, until the sides look opaque but the center stays blushing, then rest the fillets on a plate.","Whisk the remaining olive oil with the lemon juice, a pinch of salt, and black pepper until the dressing looks cloudy and unified.","Chop the romaine into ribbons and toss it with the sliced cucumber and the dressing until every leaf glistens.","Fan the sliced avocado over the salad, break the warm salmon into large pieces on top, and grate over the lemon zest to finish."],"tip":"Warm fish plus cold crisp lettuce is the whole trick, so dress the leaves before the salmon cools."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_foil_packets', '{"id":"lemon_garlic_salmon_foil_packets","name":"Lemon-Garlic Salmon Foil Packets with Baby Potatoes","emoji":"🔥","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":45,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"potatoes","q":450},{"f":"spinach","q":100},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lemon","q":1}],"steps":["Heat the oven to 425F and parboil the potatoes, halved, in salted water for 10 minutes so they finish cooking in step with the fish.","Lay out two large sheets of foil and divide the potatoes, a handful of spinach, and the sliced garlic between them, drizzling each pile with olive oil.","Set a salmon fillet on each mound, top with thin lemon slices, season with salt, pepper, and dried herbs, and crimp the foil into tightly sealed packets.","Bake the packets on a sheet pan for 15 to 17 minutes, until they puff slightly and hiss with steam.","Open each packet at the table carefully, letting the lemony garlic steam billow out, and spoon the pooled juices over everything."],"tip":"Crimp the foil like you mean it; a leaky packet steals both the steam and the drama."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baja_shrimp_tacos', '{"id":"baja_shrimp_tacos","name":"Baja Shrimp Tacos with Lime Crema","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"tortillas","q":4},{"f":"cabbage","q":0.3},{"f":"avocado","q":1},{"f":"greek_yogurt","q":60},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Pat the shrimp bone-dry, then toss with chili powder, cumin, minced garlic, and half the salt until every curl is rusty red.","Stir the greek yogurt with the zest and juice of half the lime plus a pinch of salt to make a quick crema, and shred the cabbage into fine ribbons.","Heat the olive oil in a heavy skillet over medium-high until it shimmers, then sear the shrimp in a single layer for 90 seconds per side, until pink with charred edges.","Warm the tortillas directly over a burner flame or in a dry pan for 20 seconds a side until puffed and lightly blistered.","Pile each tortilla with cabbage, shrimp, sliced avocado, a drizzle of crema, torn cilantro, and a squeeze of the remaining lime, and serve while everything is still steaming."],"tip":"Shrimp go from succulent to eraser in about 45 seconds, so pull them the instant the tails curl into a loose C."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_spaghetti', '{"id":"shrimp_scampi_spaghetti","name":"Garlic Butter Shrimp Scampi Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":170},{"f":"shrimp","q":300},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.5},{"f":"lemon","q":1},{"f":"broth","q":100},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the spaghetti in generously salted water until just shy of al dente, about 9 minutes, and scoop out a mug of the starchy cooking water before draining.","Meanwhile, warm the olive oil and half the butter in a wide skillet over medium heat, add the thinly sliced garlic, and cook 60 to 90 seconds until fragrant and pale gold, not brown.","Raise the heat, add the shrimp with the salt and black pepper, and sear about 2 minutes total until they blush pink, then lift them out to a plate.","Pour the broth and the juice of the lemon into the pan, scraping up any golden bits, and simmer 2 minutes until slightly reduced.","Return the shrimp with the drained pasta, remaining butter, and a splash of pasta water, tossing hard over the heat until the sauce turns glossy and clings to every strand.","Shower with chopped parsley and lemon zest, and serve straight from the skillet."],"tip":"If your garlic goes brown, start over — burnt garlic will bully every other flavor in the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_lime_shrimp_noodles', '{"id":"peanut_lime_shrimp_noodles","name":"Peanut-Lime Shrimp Rice Noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"shrimp","q":300},{"f":"peanut_butter","q":45},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"honey","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"bell_pepper","q":1},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly chewy, then drain and rinse under cool water so they stop cooking.","Whisk the peanut butter, soy sauce, honey, lime juice, and 3 tablespoons of warm water into a sauce the texture of heavy cream.","Heat the sesame oil in a wok over high heat and stir-fry the shrimp with the grated ginger and garlic for about 2 minutes, until pink and fragrant.","Add the sliced bell pepper and julienned carrots and toss another 2 minutes, keeping them crisp enough to snap.","Add the noodles and peanut sauce and toss with tongs for a final minute until every noodle is slicked and the sauce bubbles at the edges, then finish with sliced scallions and extra lime."],"tip":"Rice noodles keep drinking sauce after plating, so leave the mixture looking a touch too saucy in the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_masala_skillet_curry', '{"id":"shrimp_masala_skillet_curry","name":"Shrimp Masala with Fragrant Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"rice","q":140},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"crushed_tomatoes","q":300},{"f":"coconut_milk","q":150},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Start the rice simmering in salted water so it finishes alongside the curry, about 15 minutes covered, then rest it off the heat.","Cook the finely diced onion in the olive oil over medium heat for 8 to 10 minutes, stirring, until deeply golden at the edges — this is where the sauce gets its sweetness.","Add the grated ginger, minced garlic, garam masala, turmeric, cumin, and chili powder and fry 60 seconds until the spices smell toasty and darken a shade.","Pour in the crushed tomatoes and simmer 8 minutes until the sauce thickens and the oil beads at the edges, then stir in the coconut milk.","Slide in the shrimp and poach gently for 3 to 4 minutes, just until opaque, then scatter with cilantro and serve over the fluffed rice."],"tip":"The curry is only as good as the onions — if they are pale, you quit five minutes too early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup_2', '{"id":"coconut_lime_shrimp_soup_2","name":"Coconut-Lime Shrimp Noodle Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":500},{"f":"broth","q":1000},{"f":"coconut_milk","q":400},{"f":"rice_noodles","q":120},{"f":"mushrooms","q":200},{"f":"ginger","q":25},{"f":"garlic","q":0.4},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Warm the oil in a soup pot over medium heat and sizzle the sliced ginger and smashed garlic for a minute until the kitchen smells sharp and citrusy.","Pour in the broth and coconut milk, bring to a bare simmer, and let the aromatics steep for 10 minutes — do not boil hard or the coconut milk will split.","Add the sliced mushrooms and simmer 5 minutes until they turn silky and sink.","Drop in the rice noodles and cook 4 to 5 minutes until tender, then add the shrimp and poach 3 minutes, just until they curl and go opaque.","Kill the heat, season with salt and the juice of both limes until the broth tastes bright as well as rich, and ladle into bowls topped with scallions and cilantro."],"tip":"Add the lime juice off the heat — boiled lime turns bitter and sulky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_couscous_sunshine_bowl', '{"id":"shrimp_couscous_sunshine_bowl","name":"Mediterranean Shrimp Couscous Bowls","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"shrimp","q":300},{"f":"cherry_tomatoes","q":150},{"f":"cucumber","q":0.5},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":3}],"steps":["Pour boiling salted water over the couscous, cover, and let it steam for 5 minutes, then fluff with a fork and dress with a third of the olive oil and half the lemon juice.","Toss the shrimp with the minced garlic, oregano, and a pinch of salt while a skillet gets hot over medium-high heat.","Sear the shrimp in a little of the oil for about 2 minutes per side until they take on golden freckles and smell sweet.","Halve the cherry tomatoes, dice the cucumber, and fold them through the couscous with the olives, chopped parsley, and remaining oil and lemon.","Mound the couscous into bowls, crown with the hot shrimp and crumbled feta, and grind black pepper generously over the top."],"tip":"Dress the couscous while it is warm — cold grains absorb dressing about as well as gravel does."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_shrimp_greek_salad', '{"id":"charred_shrimp_greek_salad","name":"Charred Shrimp Greek Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein","gluten-free","low-carb"],"allergens":["shellfish","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"romaine","q":1},{"f":"feta","q":50},{"f":"olives","q":40},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toss the shrimp with a spoonful of the olive oil, half the oregano, salt, and pepper, and let them sit while you get a cast-iron pan screaming hot.","Sear the shrimp without moving them for 2 minutes until deeply charred on one side, flip, and give them 60 seconds more, then set aside.","Chop the romaine into wide ribbons and pile it into a big bowl with the sliced cucumber, tomato wedges, paper-thin onion, and olives.","Whisk the remaining olive oil with the lemon juice, remaining oregano, and a pinch of salt until it looks cloudy and thick.","Toss the salad with the dressing until every leaf glistens, top with the warm shrimp and big crumbles of feta, and eat before the lettuce loses its crunch."],"tip":"A hot dry pan and patient hands make the char — poke the shrimp early and you get steam, not sear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_boil_sheet_pan', '{"id":"shrimp_boil_sheet_pan","name":"Sheet-Pan Shrimp Boil with Corn and Potatoes","emoji":"🍤","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"potatoes","q":400},{"f":"corn_frozen","q":200},{"f":"butter","q":40},{"f":"olive_oil","q":15},{"f":"paprika","q":5},{"f":"chili_powder","q":2},{"f":"oregano","q":2},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 425F and cut the potatoes into 2-centimeter chunks so they cook through in the time allotted.","Toss the potatoes on a sheet pan with the olive oil, half the paprika, and half the salt, and roast 20 minutes until the edges start to brown and crisp.","Melt the butter with the minced garlic, remaining paprika, chili powder, and oregano until it smells like a seafood shack in the best way.","Push the potatoes to one side, add the shrimp and corn to the pan, pour the spiced butter over everything, and toss to coat.","Roast 8 to 10 minutes more, until the shrimp are pink and the corn has toasty spots, then squeeze the lemon over the whole pan and shower with parsley.","Serve straight off the sheet pan with plenty of napkins."],"tip":"Give the potatoes their 20-minute head start — shrimp and raw potatoes finish on completely different clocks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_shrimp_lettuce_cups', '{"id":"ginger_shrimp_lettuce_cups","name":"Ginger Shrimp Lettuce Cups with Cashews","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free","low-carb"],"allergens":["shellfish","soy","gluten","sesame","nuts"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"romaine","q":1},{"f":"mushrooms","q":150},{"f":"carrots","q":100},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"cashews","q":30}],"steps":["Chop the shrimp into rough thumbnail-sized pieces and finely dice the mushrooms and carrots so everything spoons neatly into a leaf.","Separate the romaine into whole leaves, keeping the crisp inner cups for serving and saving floppy outer leaves for another salad.","Heat the olive oil in a wok over high heat, stir-fry the mushrooms 3 minutes until their moisture cooks off and they brown, then add the carrots, ginger, and garlic for 1 minute more.","Add the shrimp and soy sauce and stir-fry 2 minutes until the shrimp turn opaque and the sauce reduces to a light glaze.","Take the pan off the heat, stir in the sesame oil and sliced scallions, then spoon into the lettuce cups and top with roughly chopped cashews for crunch."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it off the heat or it goes flat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_parmesan_risotto', '{"id":"lemon_shrimp_parmesan_risotto","name":"Lemon Shrimp Risotto-Style Rice","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":150},{"f":"shrimp","q":300},{"f":"broth","q":700},{"f":"butter","q":20},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Keep the broth warm in a small pot on the back burner — cold broth stalls the rice every time you add it.","Soften the finely diced onion in the olive oil over medium heat for 4 minutes, add the garlic and rice, and toast, stirring, until the grains turn translucent at the edges, about 2 minutes.","Add the warm broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed, for 18 to 20 minutes until the rice is creamy but still has a gentle bite.","Stir in the peas and the raw shrimp with the last ladle of broth and cook 3 to 4 minutes, until the shrimp are pink and the peas bright green.","Off the heat, beat in the butter, grated parmesan, lemon zest, and juice until the rice ripples like slow lava, then season with salt and plenty of black pepper.","Serve immediately in warm bowls — risotto waits for no one."],"tip":"Proper risotto should spread lazily when you shake the bowl; if it stands in a proud mound, loosen it with one more splash of broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_veracruz_style_skillet', '{"id":"salmon_veracruz_style_skillet","name":"Salmon Veracruz-Style Skillet","emoji":"🫒","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":50},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"rice","q":130},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Get the rice simmering in salted water, covered, for 15 minutes, then let it rest off the heat while the sauce comes together.","Warm the olive oil in a deep skillet over medium heat and cook the sliced onion and bell pepper for 6 minutes until soft and just starting to caramelize.","Stir in the garlic, oregano, and chili powder for 30 seconds, then add the crushed tomatoes and sliced olives and simmer 8 minutes until the sauce thickens enough to hold a spoon-trail.","Nestle the salmon pieces into the sauce, cover, and cook 6 to 8 minutes, until they flake easily and turn opaque all the way through.","Brighten with lime juice, taste for salt — the olives carry plenty — and serve ladled over the rice with cilantro on top."],"tip":"Taste before salting; olives are little sodium grenades and they already went off in your sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_pea_pulao', '{"id":"shrimp_pea_pulao","name":"One-Pot Shrimp and Pea Pulao","emoji":"🍚","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"rice","q":160},{"f":"shrimp","q":300},{"f":"peas_frozen","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"turmeric","q":3},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"cinnamon","q":1},{"f":"olive_oil","q":20},{"f":"broth","q":400},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3}],"steps":["Rinse the rice in a sieve until the water runs nearly clear — this is the difference between distinct grains and porridge.","In a lidded pot, fry the sliced onion in the olive oil over medium heat for 8 minutes until golden brown and sweet, then bloom the ginger, garlic, cumin, turmeric, garam masala, and cinnamon for 45 seconds.","Stir in the rice to coat every grain in the spiced oil, pour in the broth, and bring to a boil.","Cover, drop the heat to its lowest setting, and cook 12 minutes without peeking, then quickly scatter the shrimp and peas over the surface and re-cover for 5 minutes more so they steam through.","Rest the pot off the heat for 5 minutes, then fold everything together gently with a fork, finishing with lemon juice and chopped cilantro."],"tip":"Every lid-lift costs you steam and even cooking, so trust the timer and keep your curiosity to yourself."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('new_england_shrimp_rolls', '{"id":"new_england_shrimp_rolls","name":"New England-Style Shrimp Salad Rolls","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"bread","q":4},{"f":"greek_yogurt","q":80},{"f":"celery","q":60},{"f":"scallions","q":0.3},{"f":"lemon","q":1},{"f":"butter","q":15},{"f":"romaine","q":0.2},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Poach the shrimp in barely simmering salted water for 2 to 3 minutes, just until pink and curled, then plunge them into ice water so they stay snappy.","Pat the shrimp very dry, chop into chunky bites, and fold with the greek yogurt, finely diced celery, sliced scallions, lemon zest and juice, salt, and a heavy grind of black pepper.","Chill the salad for 10 minutes while you butter the bread on both sides.","Toast the buttered bread in a skillet over medium heat until golden and crisp, about 2 minutes per side, folding each slice gently into a roll shape while warm.","Line each toasted roll with a crisp romaine leaf, pile the shrimp salad high, and serve cold filling against warm bread — the contrast is the whole point."],"tip":"Wet shrimp make weepy salad, so blot them like you are drying evidence."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('open_face_tuna_melt', '{"id":"open_face_tuna_melt","name":"Broiler-Blistered Open-Face Tuna Melt","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":220},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.5},{"f":"lemon","q":0.5},{"f":"butter","q":20}],"steps":["Set the broiler to high and position a rack about 15 centimeters below the element.","Drain the tuna firmly, then fold it with the greek yogurt, finely minced onion, a squeeze of lemon, and a good pinch of salt and black pepper until it holds together like a rough spread.","Butter the bread slices and toast them under the broiler for 2 minutes, until the edges turn golden and crisp so they can carry the filling without sagging.","Pile the tuna mixture onto the toasted sides, blanket each slice with cheddar all the way to the crust, and broil 3 to 4 minutes until the cheese bubbles and blisters with brown freckles.","Rest the melts for 1 minute so the cheese sets, then finish with cracked pepper and eat while the toast still crackles."],"tip":"Cheese to the very edge is non-negotiable — naked crust burns while covered crust caramelizes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tuna_oat_patties', '{"id":"crispy_tuna_oat_patties","name":"Crispy Lemon-Herb Tuna Patties","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["fish","eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"eggs","q":2},{"f":"oats","q":60},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":100}],"steps":["Pulse the oats briefly or crush them in a bag until they resemble coarse crumbs, then stir them with the well-drained tuna, eggs, grated onion, minced garlic, the zest of the lemon, and a generous pinch of salt.","Rest the mixture for 10 minutes so the oats drink up the moisture — it should pack like damp sand, not batter.","Shape into 6 patties about 2 centimeters thick, pressing firmly so they survive the flip.","Heat the olive oil in a heavy skillet over medium heat until it shimmers, then fry the patties 3 to 4 minutes per side until deeply golden and crusted, flipping only once.","Whisk the greek yogurt with the lemon''s juice and a pinch of salt, and serve the hot patties dolloped with the tangy sauce."],"tip":"If a test patty falls apart in the pan, the fix is patience, not more egg — give the oats five more minutes to hydrate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_nicoise_potato_salad', '{"id":"tuna_nicoise_potato_salad","name":"Pantry Nicoise-Style Tuna and Potato Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"potatoes","q":400},{"f":"eggs","q":3},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"broccoli","q":150},{"f":"olive_oil","q":40},{"f":"lemon","q":1}],"steps":["Simmer the potatoes whole in well-salted water for 15 to 18 minutes until a knife slides in without resistance, adding the eggs for the final 9 minutes and the broccoli florets for the final 3.","Drain everything, shock the eggs and broccoli in cold water, then slice the still-warm potatoes into thick coins so they soak up dressing greedily.","Whisk the olive oil with the lemon''s juice, a pinch of salt, and plenty of black pepper into a sharp, glossy dressing.","Toss the warm potatoes and broccoli with half the dressing and let them sit 5 minutes to absorb it.","Arrange torn romaine and sliced cucumber on a platter, mound the potatoes, flaked tuna, and quartered eggs on top, and spoon over the remaining dressing so every layer glistens."],"tip":"Dress the potatoes while warm — cold potatoes shrug off vinaigrette like a raincoat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_tuna_spaghetti', '{"id":"lemon_garlic_tuna_spaghetti","name":"Lemon-Garlic Tuna Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"tuna_canned","q":200},{"f":"olive_oil","q":40},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":40},{"f":"spinach","q":100}],"steps":["Boil the spaghetti in aggressively salted water until just shy of al dente, about 8 minutes, and reserve a full cup of the starchy cooking water before draining.","Meanwhile, warm the olive oil and thinly sliced garlic in a wide skillet over medium-low heat for 2 to 3 minutes until the garlic turns pale gold and smells sweet, not sharp.","Add the drained tuna in large flakes with the lemon zest and a pinch of chili flakes if you have them, warming it gently so it stays tender.","Tip in the spaghetti with a generous splash of pasta water and the spinach, tossing vigorously over medium heat until the sauce turns silky and clings to every strand, about 2 minutes.","Kill the heat, shower in the parmesan and lemon juice, toss once more, and serve immediately while the sauce is still glossy."],"tip":"The pasta water is the sauce — hoard it like it costs money."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheesy_tuna_broccoli_rice_bake', '{"id":"cheesy_tuna_broccoli_rice_bake","name":"Cheesy Tuna and Broccoli Rice Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":45,"servings":2,"ing":[{"f":"rice","q":150},{"f":"tuna_canned","q":220},{"f":"broccoli","q":300},{"f":"cheddar","q":100},{"f":"milk","q":200},{"f":"butter","q":20},{"f":"flour","q":15},{"f":"onion","q":0.5}],"steps":["Heat the oven to 200C and cook the rice in salted water until just tender, about 12 minutes, since it will bake again.","Melt the butter in a saucepan over medium heat, soften the diced onion for 4 minutes until translucent, then stir in the flour and cook 1 minute until it smells faintly nutty.","Whisk in the milk gradually and simmer 3 minutes until the sauce coats the back of a spoon, then melt in two-thirds of the cheddar with a big pinch of salt and pepper.","Fold the sauce through the rice, flaked tuna, and raw broccoli florets, spread the mixture into a baking dish, and top with the remaining cheddar.","Bake 18 to 20 minutes until the edges bubble furiously and the top turns golden and crusty, then rest 5 minutes so the sauce thickens before serving."],"tip":"Raw broccoli going into the oven is the move — pre-cooked florets emerge as sad green mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_couscous_bowl', '{"id":"mediterranean_tuna_couscous_bowl","name":"Mediterranean Tuna Couscous Bowl with Feta","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"tuna_canned","q":200},{"f":"cucumber","q":1},{"f":"feta","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":80}],"steps":["Pour boiling salted water over the couscous just to cover, clamp on a lid, and let it steam for 5 minutes off the heat until every grain is tender.","While it steams, soak the thinly sliced onion in the lemon''s juice with a pinch of salt for 5 minutes to tame its bite into something bright and pickled.","Fluff the couscous thoroughly with a fork, breaking up any clumps, then fold in the olive oil while the grains are still warm.","Add the flaked tuna, diced cucumber, roughly chopped spinach, and the onion with all its lemony juices, tossing until everything is evenly distributed.","Crumble the feta over the top in big craggy chunks, grind over black pepper, and serve at room temperature when the flavors are loudest."],"tip":"Fluff couscous like you mean it — timid forking leaves you with one sad grain-brick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_edamame_fried_rice', '{"id":"tuna_edamame_fried_rice","name":"Tuna and Edamame Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","eggs","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":150},{"f":"tuna_canned","q":200},{"f":"eggs","q":2},{"f":"edamame_frozen","q":150},{"f":"carrots","q":150},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cook the rice, spread it on a plate, and chill it for at least 15 minutes — dry, cold grains fry, wet ones steam.","Get a large skillet or wok screaming hot, add half the sesame oil, and scramble the beaten eggs for 30 seconds until just set in soft folds, then scoop them out.","Add the remaining oil with the diced onion, carrots, and garlic and stir-fry 3 minutes until the carrots blister at the edges but keep a little crunch.","Tip in the cold rice and edamame, pressing the rice against the hot pan and letting it sit 60 seconds at a time so it crackles and toasts.","Return the eggs, add the drained tuna and soy sauce around the edge of the pan so it sizzles and caramelizes, toss for a final minute, and serve straight from the skillet."],"tip":"Day-old rice is the secret handshake of fried rice — plan tonight''s leftovers for tomorrow''s triumph."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_stuffed_avocados', '{"id":"tuna_stuffed_avocados","name":"Zesty Tuna-Stuffed Avocados","emoji":"🥑","cuisine":"Mexican","meal":["lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"tuna_canned","q":200},{"f":"greek_yogurt","q":80},{"f":"lemon","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.3}],"steps":["Halve and pit the avocados, then scoop a spoonful of flesh from each half to widen the crater, saving what you remove.","Mash the scooped avocado with the greek yogurt, half the lemon''s juice, and a pinch of salt until creamy but still a little chunky.","Fold in the drained tuna, finely diced bell pepper, and minced onion, tasting and sharpening with more lemon and a whisper of chili powder or cumin if you like heat.","Brush the avocado halves with the remaining lemon juice so they stay vividly green, then mound the filling high into each one.","Finish with cracked pepper and serve immediately, while the contrast between cool creamy filling and buttery avocado is at its best."],"tip":"Buy avocados that yield like a stress ball, not a stone — no filling can rescue an unripe one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spicy_tuna_tortilla_tacos', '{"id":"spicy_tuna_tortilla_tacos","name":"Ten-Minute Spicy Tuna Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"tuna_canned","q":220},{"f":"sour_cream","q":80},{"f":"avocado","q":1},{"f":"romaine","q":0.5},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Stir the drained tuna with the olive oil, half the lemon''s juice, a big pinch of chili powder, cumin, and salt, breaking it into rough shreds seasoned all the way through.","Warm a dry skillet over medium-high heat and toast each tortilla 30 to 45 seconds per side until puffed in spots and lightly charred at the edges.","Whisk the sour cream with the remaining lemon juice and a pinch of salt into a pourable crema.","Sear the tuna mixture in the hot skillet for 2 minutes without stirring so the bottom crisps and catches golden-brown edges.","Load each tortilla with shredded romaine, the crisped tuna, sliced avocado, and minced onion, then zigzag the crema over the top and serve while the tortillas are still warm and pliable."],"tip":"A tortilla straight from the bag is a sad handshake — thirty seconds on a hot pan turns it into a proper greeting."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_hummus_pita_pockets', '{"id":"tuna_hummus_pita_pockets","name":"Tuna and Hummus Pita Pockets","emoji":"🫓","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","sesame"],"time":10,"servings":2,"ing":[{"f":"pita","q":2},{"f":"tuna_canned","q":200},{"f":"hummus","q":100},{"f":"cucumber","q":1},{"f":"spinach","q":60},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10}],"steps":["Warm the pitas in a dry skillet or toaster for about a minute per side until soft and steamy, then halve them and gently open the pockets.","Toss the drained tuna with the olive oil, a squeeze of lemon, and plenty of black pepper so every flake is seasoned.","Slice the cucumber into thin half-moons and pat them dry — wet cucumber is the number one cause of soggy pockets.","Spread a thick layer of hummus inside each pita half, working it into the corners like mortar.","Pack the pockets with spinach leaves, the lemony tuna, and cucumber, pressing gently so each bite gets all three, and eat immediately over a plate."],"tip":"Hummus on both inner walls is structural engineering — it waterproofs the bread and glues the filling in place."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_spinach_yogurt_curry', '{"id":"tuna_spinach_yogurt_curry","name":"Creamy Tuna and Spinach Curry with Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":35,"servings":2,"ing":[{"f":"tuna_canned","q":220},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"greek_yogurt","q":150},{"f":"butter","q":25},{"f":"rice","q":140}],"steps":["Start the rice in salted water so it finishes as the curry does, about 12 minutes at a gentle simmer.","Melt the butter in a deep skillet over medium heat and cook the finely diced onion for 8 to 10 minutes, stirring occasionally, until deeply golden and jammy — this is the backbone of the sauce, so do not rush it.","Add the minced garlic with a tablespoon of curry powder or garam masala and a pinch of salt, toasting 60 seconds until intensely fragrant.","Pile in the spinach with a splash of water and cook 3 minutes until fully wilted and glossy, then fold in the drained tuna in large chunks.","Pull the pan off the heat, stir in the greek yogurt one spoonful at a time so it stays creamy instead of splitting, warm through gently, and serve ladled over the rice."],"tip":"Yogurt added over raging heat curdles into cottage-cheese regret — off the flame, one spoonful at a time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_noodle_bowl', '{"id":"sesame_tofu_noodle_bowl","name":"Cold Sesame Tofu Noodle Bowl","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"tofu","q":300},{"f":"cucumber","q":1},{"f":"carrots","q":150},{"f":"peanut_butter","q":30},{"f":"sesame_oil","q":20},{"f":"soy_sauce","q":25},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2}],"steps":["Cook the rice noodles according to the package, usually 4 to 6 minutes, then rinse them under cold water until completely cool and toss with a teaspoon of the sesame_oil so they do not weld together.","Pat the tofu very dry, cut it into 2-centimeter cubes, and sear it in a hot nonstick skillet with a teaspoon of the sesame oil for 6 to 8 minutes, turning until every side is golden and crisp.","Whisk the peanut butter, soy sauce, maple syrup, remaining sesame oil, grated garlic, and 2 to 3 tablespoons of warm water into a dressing the texture of heavy cream.","Cut the cucumber and carrots into thin matchsticks — the crunch against the slippery noodles is the whole point.","Toss the noodles with two-thirds of the dressing until every strand is coated and glossy, then top with the crisp tofu and vegetables, drizzle over the rest of the dressing, and finish with a pinch of chili flakes if you want a slow burn."],"tip":"Peanut sauce always seizes into cement at first — keep whisking in warm water a spoonful at a time and it will loosen into silk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_potato_breakfast_hash', '{"id":"tuna_potato_breakfast_hash","name":"Crispy Tuna and Potato Breakfast Hash","emoji":"🍳","cuisine":"American","meal":["breakfast","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":30,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"tuna_canned","q":180},{"f":"eggs","q":4},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":30}],"steps":["Dice the potatoes into 1-centimeter cubes and parboil them in salted water for 5 minutes, then drain and let them steam dry — dry surfaces are what crisp.","Heat the olive oil in a large cast-iron or heavy skillet over medium-high heat and spread the potatoes in a single layer, leaving them untouched for 4 minutes until the undersides are deeply browned.","Toss, then add the diced bell pepper and onion and cook 5 more minutes, stirring occasionally, until the vegetables soften and the potatoes are crusty on most sides.","Fold in the drained tuna with a generous pinch of paprika or black pepper and press everything flat to crisp for 2 minutes.","Make four wells in the hash, crack an egg into each, cover the pan, and cook 3 to 4 minutes until the whites are set but the yolks still shiver, then serve straight from the skillet."],"tip":"Resist the urge to stir — a hash gets its crust from neglect, not attention."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_chili', '{"id":"smoky_black_bean_chili","name":"Smoky Black Bean Chili","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"black_beans","q":800},{"f":"lime","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion and bell peppers for 8 minutes, until the edges pick up a little char and the onion turns translucent.","Stir in the minced garlic with a generous pinch of smoked seasoning and toast for 60 seconds, just until the pot smells sweet and heady rather than raw.","Add the chopped tomatoes and cook 5 minutes, mashing them against the side of the pot until they collapse into a rough, brick-red sauce.","Tip in the black beans with a splash of their liquid, bring to a lazy simmer, and cook uncovered for 20 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged across the bottom leaves a trail.","Crush a ladleful of beans against the pot wall to thicken things further, then finish with lime juice and taste for salt before serving hot."],"tip":"A chili that tastes flat almost always needs acid, not more heat, so squeeze before you spice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_saag_chickpea_curry', '{"id":"chana_saag_chickpea_curry","name":"Chana Saag Chickpea Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"tomato","q":3},{"f":"chickpeas","q":700},{"f":"spinach","q":300},{"f":"greek_yogurt","q":100},{"f":"rice","q":300}],"steps":["Rinse the rice and simmer it, covered, in double its volume of salted water for 15 minutes, then let it steam off the heat while you build the curry.","Heat the oil in a wide pan over medium-high and fry the sliced onion for 10 minutes until deeply golden at the edges, because that browning is where the curry''s sweetness lives.","Add the minced garlic and grated ginger and sizzle for 1 minute, then stir in the chopped tomatoes and cook 6 to 8 minutes until the oil separates and pools at the edges of the sauce.","Fold in the chickpeas with a splash of water and simmer 10 minutes so they drink up the masala, then pile in the spinach by the handful and let it wilt to a glossy dark green.","Pull the pan off the heat, swirl in the yogurt so it stays silky instead of splitting, and serve ladled over the fluffed rice."],"tip":"Yogurt curdles when boiled, so treat it like a guest who arrives after the party calms down."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_kale_soup', '{"id":"tuscan_white_bean_kale_soup","name":"Tuscan White Bean and Kale Soup","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"white_beans","q":700},{"f":"kale","q":1},{"f":"parmesan","q":40}],"steps":["Sweat the diced onion, carrot, and celery in the olive oil over medium heat for 8 to 10 minutes, until the vegetables are soft and the bottom of the pot glistens.","Add the sliced garlic and chopped tomatoes and cook 4 minutes, until the tomatoes slump and stain everything a pale coral.","Pour in the white beans with about a liter of water, season assertively with salt, and simmer gently for 15 minutes so the flavors knit together.","Mash a cupful of beans right in the pot to give the broth a creamy body, then stir in the torn kale and cook 5 more minutes until it is tender but still forest green.","Ladle into bowls and shower each with grated parmesan and a final thread of good olive oil."],"tip":"The soup is even better tomorrow, so consider making it yesterday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_tacos', '{"id":"black_bean_avocado_tacos","name":"Black Bean and Avocado Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"black_beans","q":400},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"tomato","q":1},{"f":"romaine","q":0.3}],"steps":["Heat the oil in a skillet over medium and cook half the diced onion with the minced garlic for 4 minutes, until soft and fragrant.","Add the black beans with a splash of water and a big pinch of cumin-style seasoning, simmer 6 to 8 minutes, then smash roughly half of them with a fork so the filling is creamy with plenty of whole beans left for texture.","While the beans bubble, mash the avocado with lime juice and salt, and toss the remaining raw onion with the diced tomato for a quick pico.","Char the tortillas directly over a flame or in a dry pan for 30 seconds per side, until blistered and pliable with dark freckles.","Swipe each tortilla with avocado, pile on the smashed beans, and finish with pico and shredded romaine while everything is still hot."],"tip":"A cold tortilla is a sad envelope, so char them last and serve immediately."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_feta_shakshuka', '{"id":"chickpea_feta_shakshuka","name":"Chickpea and Feta Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":4},{"f":"chickpeas","q":300},{"f":"eggs","q":4},{"f":"feta","q":60}],"steps":["Soften the sliced onion and bell pepper in olive oil over medium heat for 7 minutes, until sweet and slightly caught at the edges.","Stir in the minced garlic with a pinch of paprika-style seasoning, cook 1 minute, then add the chopped tomatoes and simmer 8 to 10 minutes until they break down into a thick, spoonable sauce.","Fold in the chickpeas and let them warm through for 3 minutes so they soak up the pepper-stained sauce.","Make four wells with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes, until the whites are just set but the yolks still shiver when you nudge the pan.","Crumble the feta over the top, let it slump in the residual heat, and bring the whole skillet to the table."],"tip":"Pull the pan when the eggs look one minute underdone, because carryover heat has no mercy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_white_bean_spinach_penne', '{"id":"lemony_white_bean_spinach_penne","name":"Lemony White Bean and Spinach Penne","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"white_beans","q":300},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"spinach","q":150},{"f":"lemon","q":1},{"f":"parmesan","q":40}],"steps":["Boil the penne in well-salted water until just shy of al dente, about 9 minutes, and scoop out a cup of the starchy cooking water before draining.","Meanwhile, warm the olive oil with the thinly sliced garlic in a wide skillet over medium-low heat until the slices turn pale gold and smell nutty, about 2 minutes.","Add the white beans with a splash of pasta water and simmer 4 minutes, crushing about a third of them so they melt into a light, creamy sauce.","Tumble in the drained penne and the spinach, tossing over medium heat until the leaves wilt and the sauce clings glossily to every tube, loosening with more pasta water as needed.","Off the heat, stir in the lemon zest, a big squeeze of juice, and the parmesan, tossing until the sauce turns silky, then serve straight away."],"tip":"Pasta water is free sauce insurance, so hoard it like a nonna."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_black_bean_burgers', '{"id":"crispy_black_bean_burgers","name":"Crispy Black Bean Burgers","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"oats","q":50},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"bread","q":4},{"f":"cheddar","q":60},{"f":"tomato","q":1},{"f":"romaine","q":0.3}],"steps":["Spread the drained black beans on a tray and blot them very dry, then mash three-quarters of them to a coarse paste, leaving the rest whole for texture.","Mix the mash with the oats, egg, finely grated onion, minced garlic, and a confident amount of salt and smoky seasoning, then chill the mixture for 10 minutes so it firms up.","Shape two thick patties and sear them in the olive oil over medium heat for 4 to 5 minutes per side, resisting the urge to move them until a deep, crackly crust forms.","Lay the cheddar on the patties for the final minute and cover the pan so it melts into every crevice.","Toast the bread in the same pan, then stack each burger with romaine and thick tomato slices and press gently before the first bite."],"tip":"Wet beans make sad, steamy burgers, so dry them like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_couscous_mezze_bowls', '{"id":"chickpea_couscous_mezze_bowls","name":"Chickpea Couscous Mezze Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy","sesame"],"time":25,"servings":2,"ing":[{"f":"couscous","q":120},{"f":"chickpeas","q":350},{"f":"olive_oil","q":20},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"feta","q":60},{"f":"hummus","q":80}],"steps":["Pour boiling salted water over the couscous just to cover, seal the bowl with a plate, and let it steam for 5 minutes before fluffing with a fork into light, separate grains.","Sizzle the chickpeas in half the olive oil over medium-high heat for 6 to 8 minutes, shaking the pan until they turn golden and lightly crisp at the seams.","Dice the cucumber, tomatoes, and onion into small, even pieces and dress them with lemon juice, the remaining oil, and a pinch of salt so they release their juices.","Build each bowl with a bed of couscous, a generous swoosh of hummus up one side, the crisped chickpeas, and the chopped salad.","Crumble feta over everything and finish with lemon zest and a last drizzle of oil."],"tip":"The swoosh of hummus is not decoration, it is the sauce, so be generous with the swoosh."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_soy_chickpea_stirfry', '{"id":"ginger_soy_chickpea_stirfry","name":"Ginger-Soy Chickpea Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"chickpeas","q":300},{"f":"broccoli","q":400},{"f":"edamame_frozen","q":150},{"f":"garlic","q":0.3},{"f":"ginger","q":20},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed rice, covered, in one and a half times its volume of water for 12 minutes, then rest it off the heat with the lid on.","Get a wok or large skillet screaming hot, add the olive oil, and sear the drained chickpeas for 5 minutes until they blister and pop like tiny popcorn.","Add the broccoli florets with a splash of water and stir-fry 4 minutes, until the water evaporates and the florets are bright green with charred tips but still snappy.","Toss in the edamame, minced garlic, and grated ginger and cook 2 minutes, keeping everything moving so the aromatics never scorch.","Pour in the soy sauce, let it bubble and glaze everything for 30 seconds, then kill the heat, finish with sesame oil, and serve over the steamed rice."],"tip":"Sesame oil is a finishing perfume, not a frying fat, so add it after the flames are out."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_sweet_potato_hash_2', '{"id":"black_bean_sweet_potato_hash_2","name":"Black Bean and Sweet Potato Hash","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"eggs","q":4}],"steps":["Dice the sweet potatoes into 1-centimeter cubes and cook them in the olive oil in a large cast-iron skillet over medium heat for 12 to 15 minutes, turning only occasionally so they develop caramelized, crusty faces.","Add the diced onion and bell pepper and cook 5 more minutes, until the onion softens and picks up color from the fond in the pan.","Stir in the garlic and black beans with a pinch of smoked seasoning and cook 3 minutes, pressing the hash flat so the bottom crisps.","Nestle four wells into the hash, crack in the eggs, cover, and cook 4 to 6 minutes, until the whites set opaque while the yolks stay molten.","Season generously and serve straight from the skillet while the edges are still sizzling."],"tip":"Flipping the hash constantly is how you get mush, so channel your inner statue."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_white_bean_toasts', '{"id":"garlicky_white_bean_toasts","name":"Garlicky White Bean Toasts with Wilted Spinach","emoji":"🍞","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"bread","q":4},{"f":"white_beans","q":400},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"tomato","q":1}],"steps":["Warm two-thirds of the olive oil with the sliced garlic in a skillet over medium-low heat until the garlic just turns golden and the kitchen smells like an Italian grandmother''s, about 2 minutes.","Add the white beans with a splash of water, simmer 5 minutes, then smash them roughly with a fork into a rustic, creamy spread and brighten with lemon zest, juice, and plenty of salt.","In the same pan, wilt the spinach in 1 minute flat with a pinch of salt, then set it aside.","Toast the bread until deeply golden and audibly crisp, then rub each slice with the cut tomato so it soaks in like a quick pan con tomate.","Pile the warm bean smash onto the toasts, drape the spinach over the top, and finish with the remaining oil and a crack of pepper."],"tip":"Toast pale enough to fold is toast that will collapse under beans, so aim for crouton-adjacent."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_stuffed_peppers', '{"id":"white_bean_stuffed_peppers","name":"White Bean and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":120},{"f":"white_beans","q":300},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"mozzarella","q":80}],"steps":["Heat the oven to 200C and simmer the rice in salted water for 12 minutes until just tender, then drain well.","Halve the peppers through the stem, scoop out the seeds, rub with a little of the oil, and roast cut-side up for 10 minutes so they get a head start on softening.","Meanwhile, cook the diced onion and garlic in the remaining oil for 4 minutes, then add the chopped tomatoes and white beans and simmer 5 minutes into a thick, saucy filling.","Fold the rice into the beans, taste for salt, and mound the filling into the pepper halves, packing it in with the back of a spoon.","Cap each pepper with torn mozzarella and bake 18 to 20 minutes, until the cheese is bronzed and bubbling and a knife slides through the pepper walls without resistance."],"tip":"Par-roasting the empty peppers is the difference between tender boats and crunchy disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_baked_white_beans_feta', '{"id":"greek_baked_white_beans_feta","name":"Greek Baked White Beans with Feta","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"white_beans","q":800},{"f":"tomato","q":5},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"feta","q":100},{"f":"spinach","q":150}],"steps":["Heat the oven to 190C and, in an ovenproof pot, cook the sliced onion in most of the olive oil over medium heat for 8 minutes until soft and sweet.","Add the minced garlic, then the chopped tomatoes with a big pinch of salt and a whisper of dried herbs, and simmer 10 minutes until the sauce thickens and turns a deep, jammy red.","Stir in the white beans and a splash of water, fold through the spinach until it wilts, and level the surface with a spoon.","Slide the pot uncovered into the oven and bake 25 to 30 minutes, until the top is blistered in spots and the sauce bubbles thickly at the edges.","Crumble the feta over the hot beans, drizzle with the reserved oil, and rest 5 minutes so the sauce settles from lava to luscious."],"tip":"Gigantes-style beans reward patience, so let the bake go until the edges genuinely caramelize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_lentil_bolognese', '{"id":"spaghetti_lentil_bolognese","name":"Spaghetti with Lentil Bolognese","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"spaghetti","q":340},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"parmesan","q":40},{"f":"oregano","q":2},{"f":"basil","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Finely dice the onion, carrots, and celery, then sweat them in the olive oil over medium heat for 8 minutes until the onion turns translucent and the carrots smell sweet.","Stir in the minced garlic and oregano and cook 1 minute more, just until fragrant but not browned.","Add the lentils, crushed tomatoes, and 750 ml of water, season with salt and pepper, and simmer uncovered for 30 to 35 minutes, stirring occasionally, until the lentils are tender and the sauce is thick enough to hold a spoon trail.","Meanwhile, boil the spaghetti in well-salted water until just shy of al dente, then reserve a cup of the starchy water before draining.","Toss the spaghetti with the lentil ragu, loosening with splashes of pasta water until the sauce clings glossily to every strand.","Serve in warm bowls showered with grated parmesan and torn basil leaves."],"tip":"The ragu tastes even better tomorrow, so make a double batch and let the fridge do the seasoning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_lentil_kale_soup', '{"id":"tuscan_lentil_kale_soup","name":"Tuscan Lentil and Kale Soup","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":400},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"kale","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"salt","q":6},{"f":"black_pepper","q":2},{"f":"lemon","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion, carrots, and celery for 8 to 10 minutes until softened and just starting to catch golden at the edges.","Add the minced garlic and oregano and stir for 1 minute until the kitchen smells like a trattoria.","Pour in the lentils, crushed tomatoes, and 1.5 liters of water, bring to a boil, then lower the heat and simmer partly covered for 30 minutes until the lentils are creamy-tender.","Strip the kale from its stems, tear it into bite-size pieces, and stir it in for the final 5 minutes so it wilts to a deep glossy green.","Season with salt and pepper, then brighten the whole pot with the juice of the lemon just before ladling into bowls."],"tip":"That squeeze of lemon at the end is not optional; it is the difference between brown soup and dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_curry', '{"id":"coconut_red_lentil_curry","name":"Creamy Coconut Lentil Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":350},{"f":"coconut_milk","q":300},{"f":"rice","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"crushed_tomatoes","q":250},{"f":"spinach","q":150},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"garam_masala","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Start the rice in a small pot with 400 ml of water, cover, and let it steam quietly on low while you build the curry.","Heat the oil in a deep skillet over medium heat and fry the diced onion for 6 minutes until golden, then add the garlic, grated ginger, curry powder, and turmeric and stir for 1 minute until the spices bloom and darken slightly.","Add the lentils, crushed tomatoes, coconut milk, and 900 ml of water, then simmer uncovered for 25 to 30 minutes, stirring now and then, until the lentils collapse into a thick, spoon-coating stew.","Fold in the spinach by the handful and let it wilt into the curry, about 2 minutes.","Turn off the heat, stir in the garam masala and salt, and rest the pot 5 minutes so the spices settle in before serving over the rice."],"tip":"Adding garam masala off the heat keeps its perfume intact instead of boiling it away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_sloppy_joes', '{"id":"lentil_sloppy_joes","name":"Lentil Sloppy Joes","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"chili_powder","q":5},{"f":"cumin","q":3},{"f":"maple_syrup","q":15},{"f":"balsamic_vinegar","q":15},{"f":"bread","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Simmer the lentils in plenty of water for about 20 minutes until tender but still holding their shape, then drain.","Meanwhile, sauté the diced onion and bell pepper in the olive oil over medium-high heat for 6 minutes until the edges char slightly and the pepper smells sweet.","Stir in the garlic, chili powder, and cumin for 30 seconds, then add the crushed tomatoes, maple syrup, balsamic, and drained lentils.","Simmer for 10 minutes, mashing a few lentils against the pot wall, until the mixture is thick, glossy, and sloppy in the technical sense.","Toast the bread until golden and pile the lentil mixture high on top, letting it cascade over the edges as tradition demands."],"tip":"Napkins are an ingredient here; the drips down your wrist are proof you seasoned it right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_walnut_burgers', '{"id":"lentil_walnut_burgers","name":"Lentil Walnut Burgers","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free","high-protein"],"allergens":["gluten","eggs","nuts"],"time":50,"servings":2,"ing":[{"f":"lentils_dry","q":120},{"f":"walnuts","q":30},{"f":"oats","q":40},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":15},{"f":"bread","q":4},{"f":"avocado","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Boil the lentils for 22 to 25 minutes until fully soft, then drain them very well and spread on a plate for 10 minutes to dry out, because wet lentils make sad, crumbly burgers.","Toast the walnuts and oats in a dry skillet for 3 minutes until nutty-smelling, then chop the walnuts fine.","Mash the lentils roughly with a fork, then mix in the walnuts, oats, egg, finely minced onion and garlic, cumin, paprika, salt, and pepper until the mixture holds together when squeezed.","Shape into two thick patties and chill for 10 minutes so they firm up.","Pan-fry in the olive oil over medium heat for 4 to 5 minutes per side until deeply browned and crusty, flipping only once.","Serve each patty between toasted bread slices with fanned avocado on top."],"tip":"Resist the urge to poke and flip; a patty left alone builds the crust that keeps it in one piece."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_lentil_tacos', '{"id":"smoky_lentil_tacos","name":"Smoky Lentil Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":130},{"f":"tortillas","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":3},{"f":"salsa","q":100},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Simmer the lentils in salted water for about 20 minutes until just tender, then drain thoroughly.","Heat the olive oil in a skillet over medium-high heat, fry the diced onion for 4 minutes until browned at the edges, then add the garlic, chili powder, cumin, and paprika and toast for 30 seconds until the spices smell smoky and rich.","Add the lentils and salsa and cook for 5 minutes, mashing lightly, until the filling sizzles and darkens like good taco meat should.","Char the tortillas directly over a flame or in a dry pan for 20 seconds per side until blistered and pliable.","Fill each tortilla with the lentil mixture, top with sliced avocado and torn cilantro, and finish with a hard squeeze of lime over everything."],"tip":"A slightly ugly, charred tortilla beats a pale steamed one every single Tuesday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('campfire_lentil_chili', '{"id":"campfire_lentil_chili","name":"Campfire Lentil Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"black_beans","q":250},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"chili_powder","q":12},{"f":"cumin","q":6},{"f":"paprika","q":4},{"f":"corn_frozen","q":150},{"f":"olive_oil","q":20},{"f":"salt","q":6}],"steps":["Heat the oil in your biggest pot over medium-high heat and cook the diced onion and bell peppers for 7 minutes until softened and flecked with brown.","Add the garlic, chili powder, cumin, and paprika and stir constantly for 1 minute; the spices should coat the vegetables in a brick-red paste and smell almost like barbecue.","Pour in the lentils, crushed tomatoes, and 1.2 liters of water, bring to a boil, then simmer partly covered for 30 minutes, stirring occasionally so nothing sticks.","Stir in the black beans and corn and simmer 10 minutes more, until the chili is thick enough that a wooden spoon stands up for a second before falling.","Season with salt, then let the pot rest off the heat for 5 minutes; chili always tastes better after it has had a moment to think."],"tip":"If your spoon falls over immediately, keep simmering; proper chili has structural integrity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_lentil_feta_salad', '{"id":"greek_lentil_feta_salad","name":"Greek Lentil and Feta Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":140},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":80},{"f":"olives","q":40},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Simmer the lentils in generously salted water for 18 to 20 minutes until tender but still distinct and slightly firm to the bite, then drain and spread them out to cool for 10 minutes.","While they cool, dice the cucumber, halve the cherry tomatoes, and roughly chop the olives and parsley.","Whisk the lemon juice, olive oil, oregano, salt, and pepper into a sharp dressing that makes you wince slightly when you taste it straight.","Toss the warm lentils with the dressing first so they drink it in, then fold in the vegetables, olives, and parsley.","Crumble the feta over the top in big craggy chunks and give one final gentle toss before serving."],"tip":"Dressing the lentils while warm is the whole trick; cold lentils absorb nothing and forgive nothing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_lentil_rice_bowl', '{"id":"ginger_lentil_rice_bowl","name":"Ginger-Scallion Lentil Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"rice","q":150},{"f":"carrots","q":100},{"f":"cabbage","q":0.3},{"f":"scallions","q":0.5},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"maple_syrup","q":10}],"steps":["Cook the rice in 300 ml of water, covered, on low for 15 minutes, then let it steam off the heat while you handle everything else.","Simmer the lentils in water for 20 minutes until tender, then drain well.","Stir-fry the shredded cabbage and julienned carrots in the olive oil over high heat for 3 to 4 minutes until the cabbage picks up charred spots but keeps its crunch.","Add the grated ginger, minced garlic, and lentils, then pour in the soy sauce and maple syrup and toss for 2 minutes until everything glistens and the pan hisses.","Pile the mixture over the rice, drizzle with sesame oil, and shower with thinly sliced scallions before serving."],"tip":"Sesame oil is a finishing perfume, not a cooking fat; add it at the end or lose it entirely."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_rice_stuffed_peppers', '{"id":"lentil_rice_stuffed_peppers","name":"Lentil and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":60,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"lentils_dry","q":100},{"f":"rice","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salsa","q":120},{"f":"corn_frozen","q":80},{"f":"cheddar","q":60},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Heat the oven to 200 C and simmer the lentils and rice together in salted water for 18 minutes until both are just tender, then drain.","Halve the peppers through the stem, scoop out the seeds, rub with a little of the oil, and roast cut-side down for 10 minutes until they begin to slump and blister.","Meanwhile, sauté the diced onion in the remaining oil for 5 minutes, add the garlic, cumin, and chili powder for 30 seconds, then stir in the lentil-rice mixture, salsa, and corn until everything is stained brick red.","Flip the peppers over, pack them generously with the filling, and top each with a handful of cheddar.","Bake for 15 minutes until the cheese is bubbling and bronzed at the edges, then scatter with cilantro and serve hot."],"tip":"Pre-roasting the empty peppers is the secret handshake; nobody likes a stuffed pepper that crunches like a raw one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_eggplant_lentil_stew', '{"id":"greek_eggplant_lentil_stew","name":"Greek Eggplant and Lentil Stew","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"eggplant","q":1},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Cut the eggplant into 2 cm cubes and brown it in batches in most of the olive oil over medium-high heat, about 4 minutes per batch, until golden and creamy at the center; set aside.","In the same pot, soften the diced onion for 6 minutes, then add the garlic, oregano, and cinnamon and stir for 1 minute until the cinnamon makes the kitchen smell faintly of a Greek taverna.","Add the lentils, crushed tomatoes, and 1 liter of water, bring to a boil, and simmer partly covered for 25 minutes until the lentils are tender.","Return the eggplant to the pot and simmer gently for 10 more minutes so it soaks up the tomato broth without falling apart.","Season with salt and pepper, finish with lemon juice and a flood of chopped parsley, and serve in deep bowls with the remaining oil drizzled over the top."],"tip":"Brown the eggplant properly and it turns to silk; rush it and it turns to sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mujadara_lentils_rice', '{"id":"mujadara_lentils_rice","name":"Mujadara with Crispy Onions","emoji":"🧅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"rice","q":120},{"f":"onion","q":2},{"f":"olive_oil","q":30},{"f":"cumin","q":4},{"f":"cinnamon","q":1},{"f":"greek_yogurt","q":100},{"f":"parsley","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Slice both onions into thin half-moons and cook them in the olive oil over medium heat for 20 to 25 minutes, stirring occasionally, until deep mahogany and crisp at the edges; patience here is the entire dish.","Meanwhile, simmer the lentils in water for 15 minutes until just shy of tender.","Add the rice, cumin, cinnamon, salt, and enough fresh water to cover by 2 cm, then cover and cook on low for 15 minutes until both grains are tender and the water is absorbed.","Let the pot rest off the heat for 5 minutes, then fluff and fold in half the crispy onions.","Serve mounded on plates, topped with cool dollops of yogurt, the remaining onions, chopped parsley, and a grind of black pepper."],"tip":"The onions are done five minutes after you think they are done; hold your nerve until they are truly bronze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_mushroom_lettuce_wraps', '{"id":"lentil_mushroom_lettuce_wraps","name":"Lentil Mushroom Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame","nuts"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"mushrooms","q":150},{"f":"romaine","q":1},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"maple_syrup","q":10},{"f":"cashews","q":30},{"f":"lime","q":1}],"steps":["Simmer the lentils for 18 to 20 minutes until tender but intact, then drain very well.","Finely chop the mushrooms and sear them in the olive oil over high heat for 5 minutes without stirring much, until their water evaporates and they brown and squeak against the pan.","Add the minced garlic and grated ginger for 30 seconds, then tip in the lentils, soy sauce, and maple syrup and toss for 2 to 3 minutes until the mixture is glossy and sticky.","Off the heat, stir in the sesame oil, grated carrot, sliced scallions, and roughly chopped cashews.","Separate the romaine into cup-shaped leaves, spoon the warm filling into each, and finish with wedges of lime for squeezing at the table."],"tip":"Dry lentils and dry lettuce are the difference between a wrap and a lap full of filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_satay_rice_bowl', '{"id":"chicken_satay_rice_bowl","name":"Chicken satay rice bowl","emoji":"🥜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["nuts","soy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"rice","q":160},{"f":"peanut_butter","q":40},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":8},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Start the rice so it finishes as the chicken does, about 15 minutes at a bare simmer.","Whisk the peanut butter, soy sauce, honey, half the lime juice, minced garlic and grated ginger with 3–4 tablespoons of hot water until it pours like heavy cream.","Cut the chicken thighs into bite-size pieces and sear them in the oil over medium-high heat, 6–7 minutes, until deeply browned at the edges and cooked through.","Pour half the peanut sauce into the skillet and toss for 30 seconds, just until it clings and bubbles at the rim.","Pile rice into bowls, top with the glazed chicken, ribbons of cucumber and shaved carrot, then drizzle the remaining sauce over everything.","Finish with torn cilantro and the last lime wedge squeezed over the top."],"tip":"If your peanut sauce seizes into paste, don''t panic — hot water and patient whisking will loosen it every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_salmon_rice_bowl', '{"id":"chili_lime_salmon_rice_bowl","name":"Chili-lime salmon rice bowl","emoji":"🐟","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":280},{"f":"rice","q":150},{"f":"corn_frozen","q":120},{"f":"avocado","q":1},{"f":"lime","q":1.5},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":10},{"f":"cilantro","q":0.3},{"f":"scallions","q":0.5}],"steps":["Get the rice simmering, then rub the salmon all over with chili powder, cumin, a pinch of salt and half the lime juice.","Char the corn in a dry skillet over high heat, 4–5 minutes without stirring much, until it smells toasty and picks up blackened spots; tip it into a bowl.","Add the oil to the same skillet and sear the salmon over medium-high, 4 minutes on the first side until a spiced crust forms, then 2–3 minutes on the second.","Toss the charred corn with sliced scallions, chopped cilantro and a squeeze of lime to make a quick salsa.","Flake the salmon into big pieces over bowls of rice, spoon on the corn salsa, and fan sliced avocado alongside with the last lime wedge."],"tip":"A fish fillet will tell you when to flip — if it fights the spatula, give it another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_rice_bowl', '{"id":"shrimp_scampi_rice_bowl","name":"Shrimp scampi rice bowl","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":160},{"f":"butter","q":30},{"f":"olive_oil","q":10},{"f":"garlic","q":0.8},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"parmesan","q":20},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Cook the rice while you pat the shrimp bone-dry and season them with salt and plenty of black pepper.","Melt the butter with the olive oil over medium heat and sizzle the sliced garlic 60–90 seconds, until fragrant and barely golden — not brown.","Raise the heat, add the shrimp in one layer, and cook about 90 seconds per side until they curl into loose commas and turn pink.","Squeeze in the lemon juice, add the spinach by the handful, and toss just until it collapses into the garlicky butter.","Spoon everything over the rice, making sure the pan juices soak in, then shower with grated parmesan and chopped parsley."],"tip":"Shrimp curled into a tight O are overcooked — pull them at the C stage and let the pan finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_tofu_rice_bowl', '{"id":"sesame_glazed_tofu_rice_bowl","name":"Sesame-glazed crispy tofu rice bowl","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":20},{"f":"sesame_oil","q":15},{"f":"ginger","q":10},{"f":"garlic","q":0.4},{"f":"broccoli","q":300},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Press the tofu between towels under a heavy pan for 10 minutes while the rice cooks, then tear it into craggy bite-size chunks.","Stir the soy sauce, maple syrup, sesame oil, grated ginger and minced garlic into a glaze.","Sear the tofu in the olive oil over medium-high heat, undisturbed 3–4 minutes per side, until the ragged edges turn deep golden and crackly.","Push the tofu aside, add the broccoli florets with a splash of water, cover, and steam 3 minutes until vivid green with a little bite.","Pour the glaze over everything and toss 60 seconds until it bubbles, thickens and lacquers the tofu.","Serve over rice with shaved carrots and a flurry of sliced scallions."],"tip":"Torn tofu beats cubed — all those rough edges are extra real estate for the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bulgogi_style_beef_rice_bowl', '{"id":"bulgogi_style_beef_rice_bowl","name":"Bulgogi-style beef rice bowl","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"sugar","q":15},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.6},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"spinach","q":150},{"f":"carrots","q":100}],"steps":["Set the rice going, then stir together the soy sauce, sugar, sesame oil, minced garlic and grated ginger until the sugar dissolves.","Brown the ground beef in a hot, dry skillet over high heat, pressing it flat and leaving it alone 2–3 minutes so it develops a crusty, sizzling underside before you break it up.","Pour in the sauce and let it bubble hard for 2 minutes, until it reduces to a glossy coating that clings to every crumble.","Stir in the spinach and most of the scallions off the heat, letting the residual warmth wilt the greens.","Serve over rice with matchstick carrots on one side and the remaining scallions scattered over the top."],"tip":"Resist the urge to stir early — the crusty browned bits are where all the bulgogi magic lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_rice_bowl', '{"id":"turkey_taco_rice_bowl","name":"Turkey taco rice bowl","emoji":"🌮","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":320},{"f":"rice","q":160},{"f":"salsa","q":150},{"f":"chili_powder","q":8},{"f":"cumin","q":4},{"f":"corn_frozen","q":100},{"f":"cheddar","q":40},{"f":"sour_cream","q":60},{"f":"romaine","q":0.3},{"f":"lime","q":0.5},{"f":"olive_oil","q":10}],"steps":["Simmer the rice while you heat the oil in a wide skillet over medium-high heat.","Brown the turkey with the chili powder, cumin and a big pinch of salt, breaking it into small crumbles, 6–7 minutes until no pink remains and the spices smell toasted.","Stir in the salsa and corn and simmer 4–5 minutes, until the mixture thickens from soupy to spoonable and coats the meat like a proper taco filling.","Loosen the sour cream with the lime juice and a spoonful of water until it drizzles from a spoon.","Layer bowls with rice, the saucy turkey, shredded romaine and cheddar, then zigzag the lime crema over the top."],"tip":"Taste the turkey before assembling — under-salted taco meat is the silent killer of otherwise great bowls."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_balsamic_pork_rice_bowl', '{"id":"maple_balsamic_pork_rice_bowl","name":"Maple-balsamic pork rice bowl","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"rice","q":160},{"f":"maple_syrup","q":30},{"f":"balsamic_vinegar","q":30},{"f":"garlic","q":0.4},{"f":"green_beans","q":250},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Start the rice, then slice the pork loin into thin medallions and season generously with salt and pepper.","Sear the pork in half the oil over medium-high heat, about 2 minutes per side until golden with a blush of pink inside, then rest it on a plate.","In the same pan, soften the sliced onion and green beans in the remaining oil, 5–6 minutes, until the beans blister and the onion turns sweet at the edges.","Add the minced garlic, then the maple syrup and balsamic; let the mixture boil 1–2 minutes until it turns syrupy and coats the back of a spoon.","Return the pork and its juices to the pan, turning each piece through the dark, glossy glaze, and serve over the rice."],"tip":"The glaze goes from syrup to candy fast — pull it the moment your spoon leaves a trail across the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_egg_donburi_bowl', '{"id":"mushroom_egg_donburi_bowl","name":"Soy-butter mushroom and egg donburi","emoji":"🍳","cuisine":"Asian","meal":["dinner","breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"mushrooms","q":300},{"f":"rice","q":160},{"f":"soy_sauce","q":25},{"f":"butter","q":20},{"f":"sugar","q":5},{"f":"sesame_oil","q":5},{"f":"scallions","q":1}],"steps":["Cook the rice, then sear the thickly sliced mushrooms in the butter over high heat, undisturbed for 3 minutes, until their cut sides are mahogany and the pan hisses.","Add the soy sauce and sugar and toss 1 minute, letting the mushrooms drink up the salty-sweet glaze until barely any liquid remains.","Beat the eggs loosely with a fork — streaky, not uniform — and pour them over the mushrooms.","Drop the heat to low and drag a spatula slowly through the eggs, 60–90 seconds, stopping while they are still glossy and slightly wet on top.","Slide the whole soft tangle over bowls of hot rice, drizzle with sesame oil, and bury it in sliced scallions."],"tip":"Take the eggs off when they look one minute undercooked — the ride from pan to bowl finishes them perfectly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_crema_bowl', '{"id":"black_bean_avocado_crema_bowl","name":"Cumin black bean bowl with avocado crema","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"rice","q":160},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"cumin","q":6},{"f":"chili_powder","q":4},{"f":"garlic","q":0.4},{"f":"onion","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Get the rice cooking, then sweat the diced onion in the oil over medium heat, 4–5 minutes, until translucent and sweet-smelling.","Add the minced garlic, cumin and chili powder and fry 30 seconds until the spices bloom and darken a shade.","Tip in the black beans with a splash of water and simmer 8 minutes, mashing about a third of them against the pan so the pot turns thick and creamy.","Meanwhile blend or mash the avocado with the sour cream, lime juice and a pinch of salt into a smooth, pale-green crema.","Build bowls of rice and beans, spoon the crema generously over the top, and finish with halved cherry tomatoes and torn cilantro."],"tip":"Mashing a few beans is free thickener — never let a watery bean pot happen to good rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_chickpea_rice_bowl', '{"id":"mediterranean_chickpea_rice_bowl","name":"Crispy chickpea rice bowl with lemon-hummus sauce","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["sesame","dairy"],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"rice","q":140},{"f":"hummus","q":70},{"f":"lemon","q":1},{"f":"cucumber","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":50},{"f":"olives","q":40},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":10}],"steps":["Start the rice, then dry the chickpeas thoroughly on a towel — wet chickpeas steam instead of crisp.","Fry them in the oil over medium-high heat with the paprika, oregano and a pinch of salt, shaking the pan occasionally for 8–10 minutes, until they rattle and blister golden.","Whisk the hummus with the lemon juice and 2–3 tablespoons of warm water into a pourable, silky sauce.","Dice the cucumber and halve the cherry tomatoes, seasoning them with a little salt so they glisten.","Spread the lemon-hummus sauce over bowls of rice, pile on the hot crackly chickpeas, then top with the salad, crumbled feta and olives."],"tip":"Sauce under the toppings, not over — every forkful of rice drags through it on the way up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_lentil_rice_bowl', '{"id":"curried_lentil_rice_bowl","name":"Coconut-curried lentil rice bowl","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":140},{"f":"rice","q":130},{"f":"coconut_milk","q":120},{"f":"curry_powder","q":10},{"f":"turmeric","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"tomato","q":1},{"f":"spinach","q":150},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed lentils in plenty of water with the turmeric for 20–22 minutes, until tender but not mushy, then drain; cook the rice alongside.","Meanwhile fry the diced onion in the oil over medium heat, 6–8 minutes, until golden at the edges and jammy in the middle.","Add the minced garlic, grated ginger and curry powder and sizzle 1 minute, until the whole kitchen smells like a curry house.","Stir in the chopped tomato and cook 3–4 minutes until it slumps, then add the lentils and coconut milk and simmer 5 minutes into a loose, spoonable curry.","Fold in the spinach until it wilts, season with salt, and ladle over the rice with a shower of cilantro."],"tip":"Lentils keep drinking liquid as they sit — leave the curry a touch soupier than seems right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_sesame_tuna_rice_bowl', '{"id":"soy_sesame_tuna_rice_bowl","name":"Soy-sesame tuna rice bowl","emoji":"🍱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"rice","q":160},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":12},{"f":"honey","q":10},{"f":"ginger","q":8},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"scallions","q":0.5}],"steps":["Cook the rice and let it steam off the heat for 5 minutes so the grains stay distinct and fluffy.","Whisk the soy sauce, sesame oil, honey and finely grated ginger into a dressing that tastes sharp, nutty and a little sweet.","Drain the tuna well and flake it into big chunks, folding in a third of the dressing so every piece gets seasoned.","Slice the cucumber into thin half-moons and shave the carrots into ribbons with a peeler.","Mound the warm rice into bowls, arrange the tuna and vegetables in neat piles, then spoon the remaining dressing over and finish with sliced scallions."],"tip":"Warm rice plus cold crunchy vegetables is the whole point — don''t let either side go lukewarm."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('green_goddess_edamame_rice_bowl', '{"id":"green_goddess_edamame_rice_bowl","name":"Green goddess edamame rice bowl","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["soy","dairy"],"time":25,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"rice","q":150},{"f":"greek_yogurt","q":150},{"f":"basil","q":0.5},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"cucumber","q":0.5},{"f":"spinach","q":100},{"f":"cherry_tomatoes","q":100}],"steps":["Cook the rice, then blanch the edamame in salted boiling water for 3–4 minutes until bright green and just tender; drain and toss with a pinch of salt.","Blend the greek yogurt, basil leaves, lemon juice, garlic, olive oil and a pinch of salt until the sauce turns a pale spring green and tastes bright and herbal.","Fold the spinach into the hot rice so it wilts into silky ribbons.","Dice the cucumber and halve the cherry tomatoes for crunch and acidity.","Swoosh a thick layer of green goddess sauce around each bowl, mound in the spinach rice, and top with edamame, cucumber and tomatoes."],"tip":"Blend the sauce longer than feels necessary — flecks of basil are pretty, but pale green velvet is better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_herb_chicken_quinoa_bowl', '{"id":"lemon_herb_chicken_quinoa_bowl","name":"Lemon Herb Chicken Quinoa Bowl","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_breast","q":320},{"f":"quinoa","q":140},{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"spinach","q":100},{"f":"feta","q":50}],"steps":["Heat the oven to 425°F and rinse the quinoa until the water runs clear, then simmer it in double its volume of water for 15 minutes until the germ spirals loose.","Toss thick half-moons of zucchini, strips of bell pepper, and onion wedges with half the olive oil, then roast 20 minutes until the edges char and turn sweet.","Season the chicken breasts generously, sear them in the remaining oil over medium-high heat for 5 to 6 minutes per side until deeply golden and 165°F inside, then rest 5 minutes before slicing against the grain.","Squeeze the lemon over the warm quinoa along with the minced garlic and a big pinch of salt, folding until fragrant and glossy.","Pile quinoa into bowls, wilt the spinach under the hot roasted vegetables, fan the chicken on top, and finish with crumbled feta and any resting juices."],"tip":"Resting the chicken is not optional — slice it early and you will watch your sauce run away across the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_soy_glazed_salmon_quinoa_bowl', '{"id":"honey_soy_glazed_salmon_quinoa_bowl","name":"Honey-Soy Glazed Salmon Quinoa Bowl","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"quinoa","q":140},{"f":"broccoli","q":300},{"f":"carrots","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Start the quinoa simmering in salted water for 15 minutes while the oven heats to 425°F.","Spread broccoli florets and thin carrot coins on a sheet pan with half the sesame oil and roast 18 minutes until the broccoli tips crisp and brown.","Whisk the soy sauce, honey, minced garlic, and remaining sesame oil into a glaze, then simmer it in a small pan for 2 minutes until it coats a spoon.","Sear the salmon fillets skin-side down in a hot skillet for 4 minutes until the skin crackles and releases, flip, and cook 2 minutes more.","Brush the glaze thickly over the salmon in its last minute so it turns lacquered and sticky, then serve everything over the fluffed quinoa with extra glaze drizzled around the bowl."],"tip":"If the salmon fights you when you try to flip it, it is not ready — patience releases the skin, spatula violence does not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_quinoa_bowl', '{"id":"chili_lime_shrimp_quinoa_bowl","name":"Chili-Lime Shrimp Quinoa Bowl","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"quinoa","q":140},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"olive_oil","q":25}],"steps":["Simmer the quinoa in salted water for 15 minutes, then fluff it with the zest and juice of one lime.","Roast the bell pepper strips and onion wedges at 450°F with half the olive oil for 18 minutes until blistered and sweet at the edges.","Pat the shrimp bone-dry, toss them with minced garlic, a heavy dusting of chili powder and paprika, and the remaining oil.","Sear the shrimp in a screaming-hot skillet for 90 seconds per side, just until they curl into loose Cs and turn opaque pink.","Build bowls of citrusy quinoa, charred peppers, and shrimp, then crown with sliced avocado and wedges of the second lime for squeezing at the table."],"tip":"A shrimp curled into a tight O is overcooked and telling on you — pull them at a relaxed C every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_sesame_tofu_quinoa_bowl', '{"id":"maple_sesame_tofu_quinoa_bowl","name":"Maple-Sesame Crispy Tofu Quinoa Bowl","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame","nuts"],"time":45,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"quinoa","q":140},{"f":"mushrooms","q":200},{"f":"carrots","q":150},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":20},{"f":"garlic","q":0.3},{"f":"cashews","q":40}],"steps":["Press the tofu between paper towels under a heavy pan for 15 minutes, then tear it into rough bite-size chunks — the craggy edges crisp better than clean cubes.","Roast the tofu, halved mushrooms, and carrot coins on a sheet pan at 425°F with the sesame oil for 25 minutes, flipping once, until the tofu is golden and the mushrooms have shrunk and concentrated.","Meanwhile simmer the quinoa in salted water for 15 minutes and toast the cashews in a dry pan until they smell nutty.","Whisk the soy sauce, maple syrup, and minced garlic, then pour it over the hot sheet pan for the final 3 minutes so it bubbles into a sticky glaze.","Spoon everything over the quinoa, scraping up every dark caramelized bit from the pan, and scatter the cashews on top for crunch."],"tip":"Torn tofu has more surface area than cubed tofu, and surface area is just a nerdy word for crispiness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_chickpea_couscous_bowl', '{"id":"moroccan_spiced_chickpea_couscous_bowl","name":"Moroccan-Spiced Chickpea Couscous Bowl","emoji":"🥕","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","nuts"],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"couscous","q":140},{"f":"carrots","q":250},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"maple_syrup","q":15},{"f":"lemon","q":1},{"f":"almonds","q":25}],"steps":["Heat the oven to 425°F and toss the drained chickpeas, carrot batons, zucchini half-moons, and onion wedges with the olive oil, cumin, cinnamon, and a pinch of cayenne.","Roast for 25 minutes until the chickpeas rattle drily on the pan and the carrots wrinkle and caramelize at the tips.","Drizzle the maple syrup over the vegetables for the last 5 minutes so it bubbles into a light glaze rather than burning.","Pour boiling water over the couscous with a pinch of salt, cover for 5 minutes, then rake it with a fork until every grain separates.","Fold the lemon zest and juice into the couscous, top with the spiced vegetables and chickpeas, and shower with toasted sliced almonds."],"tip":"Couscous rewards a fork and punishes a spoon — stir it and you get paste, rake it and you get clouds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_quinoa_burrito_bowl', '{"id":"smoky_black_bean_quinoa_burrito_bowl","name":"Smoky Black Bean Quinoa Burrito Bowl","emoji":"🌯","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"quinoa","q":140},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":20}],"steps":["Simmer the quinoa in salted water for 15 minutes, then fluff and hold it covered off the heat.","Roast the bell pepper strips and onion wedges at 450°F with half the oil for 18 minutes until the edges blacken fajita-style.","Warm the remaining oil in a saucepan, bloom the minced garlic with paprika and cumin for 30 seconds until fragrant, then add the black beans and diced tomatoes.","Simmer the beans for 8 minutes, mashing a few against the pot wall so the mixture thickens into something saucy and glossy.","Layer quinoa, smoky beans, and charred vegetables into bowls, then finish with sliced avocado and a hard squeeze of lime to wake everything up."],"tip":"Mashing a quarter of the beans is the free thickener nobody talks about — no cream, no flour, just physics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_turkey_couscous_bowl', '{"id":"tuscan_turkey_couscous_bowl","name":"Tuscan Turkey and Tomato Couscous Bowl","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"couscous","q":140},{"f":"tomato","q":3},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"parmesan","q":40}],"steps":["Brown the ground turkey in half the olive oil over medium-high heat for 6 minutes, pressing it flat and leaving it alone so it develops a deep golden crust before you break it up.","Add the diced onion and cook 4 minutes until translucent, then stir in the minced garlic, fennel seed, and chili flakes until fragrant.","Tumble in the chopped tomatoes and simmer 8 minutes until they collapse into a rough, rusty sauce that coats the meat.","Steep the couscous in boiling salted water, covered, for 5 minutes, then fluff it with a fork and a thread of the remaining oil.","Fold the spinach into the hot turkey sauce until it just wilts, spoon everything over the couscous, and grate the parmesan generously over the top while it steams."],"tip":"Fennel seed is the cheat code that makes plain turkey taste like Italian sausage without the sausage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spiced_beef_couscous_bowl_with_yogurt', '{"id":"spiced_beef_couscous_bowl_with_yogurt","name":"Spiced Beef Couscous Bowl with Garlic Yogurt","emoji":"🥩","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"couscous","q":140},{"f":"zucchini","q":1},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"greek_yogurt","q":150},{"f":"lemon","q":0.5}],"steps":["Stir one grated garlic clove and the lemon juice into the yogurt with a pinch of salt and let it sit so the raw bite mellows.","Roast the zucchini half-moons at 425°F with the olive oil for 15 minutes until bronzed and tender.","Brown the beef hard in a dry skillet over high heat for 5 minutes until crusty, then stir in the diced onion, remaining garlic, cinnamon, cumin, and allspice.","Add the chopped tomatoes and simmer 6 minutes until the pan smells like a spice market and the juices turn thick and dark.","Steep the couscous in boiling water for 5 minutes, fluff, then bowl it up with the spiced beef, roasted zucchini, and generous swoops of the cold garlic yogurt."],"tip":"Cinnamon in savory beef feels wrong right up until the first bite, at which point it feels like a secret you should have known years ago."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sunrise_quinoa_breakfast_bowl', '{"id":"sunrise_quinoa_breakfast_bowl","name":"Sunrise Quinoa Breakfast Bowl","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"quinoa","q":120},{"f":"sweet_potatoes","q":300},{"f":"kale","q":0.5},{"f":"avocado","q":1},{"f":"olive_oil","q":20},{"f":"garlic","q":0.1}],"steps":["Roast small cubes of sweet potato at 425°F with half the olive oil and paprika for 22 minutes until the corners caramelize and give easily to a fork.","Simmer the quinoa in salted water for 15 minutes while the potatoes roast, then fluff and keep warm.","Sauté the torn kale with the minced garlic in the remaining oil for 3 minutes until it turns glossy and deep green, seasoning with salt and a pinch of chili flakes.","Fry the eggs in the same skillet over medium heat until the whites are set and lacy at the edges but the yolks still tremble.","Assemble bowls of quinoa, sweet potatoes, and kale, slide two eggs onto each, and fan the avocado alongside so the yolk becomes the sauce."],"tip":"The runny yolk is the dressing — cook it hard and you will be eating a perfectly nice bowl that is missing its whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_quinoa_bowl', '{"id":"sesame_edamame_quinoa_bowl","name":"Sesame Edamame Quinoa Bowl","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"quinoa","q":140},{"f":"carrots","q":200},{"f":"cucumber","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2}],"steps":["Simmer the quinoa in salted water for 15 minutes until the grains uncurl, then spread it on a plate to cool slightly so it stays distinct rather than gummy.","Roast the carrot coins at 425°F with a third of the sesame oil for 18 minutes until browned and bendy-sweet.","Blanch the edamame in boiling water for 3 minutes, drain well, and pat dry.","Whisk the soy sauce, maple syrup, remaining sesame oil, and grated garlic into a dressing that tastes salty-sweet with a raw garlicky edge.","Toss the quinoa, edamame, roasted carrots, and thin cucumber half-moons with the dressing, tasting as you go until every bite pops."],"tip":"Dress this bowl while the quinoa is still warm — warm grains drink dressing, cold grains just wear it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_couscous_bowl_2', '{"id":"mediterranean_tuna_couscous_bowl_2","name":"Mediterranean Tuna Couscous Bowl","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"couscous","q":140},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"hummus","q":100}],"steps":["Roast the quartered tomatoes at 450°F with half the olive oil for 15 minutes until their edges blister and their juices turn jammy.","Steep the couscous in boiling salted water, covered, for 5 minutes, then fluff it with a fork and the remaining oil.","Fold the lemon zest, half the juice, and plenty of black pepper into the couscous while it is still steaming.","Drain the tuna well and flake it into big shameless chunks with a splash of the remaining lemon juice.","Swipe hummus around each bowl, mound the lemony couscous in the center, and top with tuna, roasted tomatoes, and cool cucumber half-moons for contrast."],"tip":"Roasting the tomatoes takes 15 minutes and upgrades canned tuna from desk lunch to something you would photograph."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_tomato_mozzarella_quinoa_bowl', '{"id":"roasted_tomato_mozzarella_quinoa_bowl","name":"Roasted Tomato and Mozzarella Quinoa Bowl","emoji":"🧀","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"mozzarella","q":150},{"f":"quinoa","q":140},{"f":"tomato","q":4},{"f":"zucchini","q":2},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"spinach","q":100}],"steps":["Heat the oven to 450°F and toss the quartered tomatoes and thick zucchini half-moons with the olive oil, smashed garlic, dried oregano, and salt.","Roast for 22 minutes until the tomatoes slump and leak sweet, concentrated juice and the zucchini picks up brown spots.","Simmer the quinoa in salted water for 15 minutes while the vegetables roast, then fluff it well.","Fold the spinach into the hot quinoa so it wilts from residual heat alone.","Top the bowls with the roasted vegetables and every drop of pan juice, then tear the mozzarella over the top so it softens into milky pockets against the heat."],"tip":"The pan juice is the sauce — tip the sheet pan over each bowl like you mean it, because that is where the flavor went."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_cauliflower_chickpea_quinoa_bowl', '{"id":"curried_cauliflower_chickpea_quinoa_bowl","name":"Curried Cauliflower Quinoa Bowl","emoji":"🍛","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":0.8},{"f":"chickpeas","q":200},{"f":"quinoa","q":140},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":150},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 450°F and toss the cauliflower florets, drained chickpeas, and onion wedges with the oil, curry powder, turmeric, and salt until everything is stained gold.","Roast for 25 to 28 minutes, flipping halfway, until the cauliflower tips char nearly black in places — that bitterness against the sweet spice is the whole dish.","Simmer the quinoa in salted water for 15 minutes while the pan roasts, then fluff.","Stir the grated garlic and lemon juice into the yogurt with a pinch of salt to make a cool, tangy raita-style sauce.","Spoon the roasted cauliflower and chickpeas over the quinoa and drape the garlic yogurt across the top, letting it melt into the hot spiced edges."],"tip":"Crowd the sheet pan and the cauliflower steams instead of chars — give the florets personal space and they will reward you with crispy edges."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avgolemono_chicken_rice_soup', '{"id":"avgolemono_chicken_rice_soup","name":"Lemon Chicken and Rice Soup (Avgolemono)","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"rice","q":180},{"f":"broth","q":1200},{"f":"eggs","q":2},{"f":"lemon","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"olive_oil","q":30}],"steps":["Warm the olive oil in a heavy pot over medium heat and sweat the diced onion, carrots, and celery for 6 to 8 minutes, until the onion turns translucent and smells sweet.","Pour in the broth, bring it to a gentle boil, then slide in the whole chicken breasts and the rice; simmer uncovered for 18 minutes, until the chicken registers 165F and the rice is tender.","Lift out the chicken, shred it with two forks, and return it to the pot off the heat.","Whisk the eggs with the juice of the lemon in a bowl, then ladle in hot broth a splash at a time while whisking, so the eggs warm gently instead of scrambling.","Stir the egg mixture back into the pot and heat over low, stirring, for 2 to 3 minutes until the soup turns pale gold and coats a spoon like thin custard; season generously and serve steaming."],"tip":"If your egg mixture scrambles, you rushed it — avgolemono rewards patience the way a cat rewards ignoring it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_beef_vegetable_soup', '{"id":"hearty_beef_vegetable_soup","name":"Hearty Beef and Potato Vegetable Soup","emoji":"🥣","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"potatoes","q":400},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"corn_frozen","q":150},{"f":"broth","q":1000}],"steps":["Brown the ground beef in a dry Dutch oven over medium-high heat for 6 to 7 minutes, breaking it into rough crumbles and letting it develop deep mahogany edges before you stir.","Add the chopped onion, carrots, and celery to the rendered fat and cook 5 minutes, scraping up the browned bits, until the vegetables soften slightly.","Stir in the minced garlic and chopped tomatoes and cook 2 minutes, until the tomatoes slump and turn jammy.","Pour in the broth, add the diced potatoes, and simmer partially covered for 20 minutes, until a fork slides through a potato cube with no resistance.","Stir in the corn, simmer 3 more minutes, then season boldly with salt and plenty of black pepper and serve in wide bowls."],"tip":"Resist stirring the beef too early — the crust it forms is the flavor deposit that pays this soup''s rent."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_kidney_bean_chili_soup', '{"id":"turkey_kidney_bean_chili_soup","name":"Turkey and Kidney Bean Chili Soup","emoji":"🌶️","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"black_beans","q":400},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"corn_frozen","q":150},{"f":"broth","q":750},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large pot over medium-high and sear the ground turkey for 5 to 6 minutes, pressing it flat and leaving it alone until it browns and releases from the pan.","Add the diced onion and bell pepper and cook 5 minutes, until the pepper''s edges soften and the onion picks up a little color.","Stir in the garlic and chopped tomatoes with a big pinch of salt and let them cook down for 5 minutes, until the mixture thickens and smells sweet and roasty.","Pour in the broth and the drained kidney beans and simmer uncovered for 15 minutes, until the liquid reduces slightly and turns brick red.","Add the corn, simmer 3 minutes more, then taste — it should be smoky-sweet with a gentle burn — and adjust the seasoning before ladling it out."],"tip":"Chili soup improves overnight, so make it today and take the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_lentil_coconut_dal_soup', '{"id":"golden_lentil_coconut_dal_soup","name":"Golden Lentil and Coconut Dal Soup","emoji":"🥥","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"olive_oil","q":15}],"steps":["Warm the oil in a wide pot over medium heat and fry the diced onion for 6 minutes, until it turns golden at the edges and smells faintly of caramel.","Add the minced garlic and grated ginger and sizzle 1 minute, then stir in the chopped tomatoes and cook 4 to 5 minutes, until they break down into a rough, glossy paste.","Add the rinsed lentils and 1 liter of water, bring to a boil, then reduce to a lively simmer for 20 minutes, skimming any foam, until the lentils collapse into a rough puree.","Stir in the coconut milk and simmer 5 minutes, until the soup is creamy and thick enough to briefly hold the trail of a spoon.","Fold in the spinach off the heat, let it wilt for 1 minute in the residual warmth, season with salt, and serve with the coconut fat glistening on top."],"tip":"Whisk the pot hard for ten seconds at the end — it fakes an immersion blender and nobody will audit you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_kale_potato_soup', '{"id":"chickpea_kale_potato_soup","name":"Rustic Chickpea, Kale, and Potato Soup","emoji":"🍲","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chickpeas","q":480},{"f":"kale","q":0.8},{"f":"potatoes","q":300},{"f":"tomato","q":2},{"f":"carrots","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45}],"steps":["Heat two-thirds of the olive oil in a soup pot over medium heat and cook the chopped onion and carrots for 7 minutes, until soft and sweet-smelling.","Add the sliced garlic and cook 1 minute, just until fragrant, then tip in the chopped tomatoes and simmer 5 minutes, until they slump into a loose sauce.","Add the diced potatoes, drained chickpeas, and 1 liter of water; bring to a boil and simmer 18 minutes, until the potatoes are creamy inside and the broth tastes savory.","Mash a ladleful of chickpeas and potato against the side of the pot to thicken the broth to a silky, rustic body.","Stir in the torn kale and simmer 4 minutes, until it turns deep green and tender, then finish each bowl with the remaining olive oil poured over in a shameless golden ribbon."],"tip":"That final drizzle of raw olive oil is not decoration — it is the soup''s paycheck, so do not skim it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_rice_soup', '{"id":"smoky_black_bean_rice_soup","name":"Smoky Black Bean and Rice Soup","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"black_beans","q":700},{"f":"rice","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"tomato","q":1.5},{"f":"lime","q":1},{"f":"olive_oil","q":30}],"steps":["Heat the olive oil in a Dutch oven over medium heat and cook the diced onion and bell pepper for 6 to 7 minutes, until the pepper chars slightly at the edges and the kitchen smells sweet.","Add the minced garlic and chopped tomatoes and cook 3 minutes, mashing the tomatoes with your spoon until they melt into the vegetables.","Add the drained black beans, rice, and 1.2 liters of water; bring to a boil, then simmer partly covered for 18 minutes, until the rice is tender and the broth has darkened to deep violet-black.","Ladle about a quarter of the soup into a bowl, mash it thoroughly, and stir it back in so the broth turns thick and velvety while whole beans still pop between your teeth.","Squeeze in the lime juice, season assertively with salt, and simmer 2 final minutes before serving — the acid should make the whole pot taste suddenly brighter."],"tip":"Lime at the end is non-negotiable; black beans without acid are a bass line with no melody."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tofu_noodle_soup', '{"id":"ginger_tofu_noodle_soup","name":"Ginger Tofu and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":4,"ing":[{"f":"tofu","q":450},{"f":"rice_noodles","q":200},{"f":"mushrooms","q":200},{"f":"edamame_frozen","q":150},{"f":"spinach","q":100},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":30}],"steps":["Heat half the sesame oil in a large pot over medium-high and sear the sliced mushrooms for 5 minutes without crowding, until their edges brown and they squeak less against the spoon.","Add the julienned ginger and sliced garlic and stir for 1 minute, until the pot smells sharp and citrusy.","Pour in 1.4 liters of water and the soy sauce, bring to a rolling simmer, and slide in the tofu cut into large cubes along with the edamame; simmer gently for 8 minutes so the tofu drinks in the broth.","Add the rice noodles and cook 4 to 5 minutes, until they turn silky and translucent but still have a slight chew.","Turn off the heat, wilt in the spinach, and finish with the remaining sesame oil; the broth should taste savory, gingery, and just salty enough to make you go back for more."],"tip":"Cube the tofu big and handle it once — it is delicate, and this soup is not the place for confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup_3', '{"id":"coconut_lime_shrimp_soup_3","name":"Coconut-Lime Shrimp and Rice Soup","emoji":"🦐","cuisine":"Asian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":["shellfish"],"time":40,"servings":4,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":400},{"f":"rice","q":150},{"f":"mushrooms","q":150},{"f":"bell_pepper","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"broth","q":750}],"steps":["Combine the broth, sliced ginger, and minced garlic in a pot and bring to a simmer over medium heat, letting the aromatics steep for 5 minutes until the broth smells warm and peppery.","Add the rice, sliced mushrooms, and thinly sliced bell pepper and simmer 15 minutes, until the rice is tender and the mushrooms have gone plush.","Stir in the coconut milk and heat until it barely trembles at the edges — do not let it boil hard or it will look curdled and sulky.","Add the shrimp and poach 3 to 4 minutes, until they curl into loose commas and turn opaque pink all the way through.","Kill the heat, squeeze in the juice of both limes, season with salt, and serve immediately while the broth is fragrant, creamy, and just tart enough to wake you up."],"tip":"Shrimp go from tender to eraser in about ninety seconds, so set a timer and trust it over your optimism."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_corn_chowder', '{"id":"salmon_corn_chowder","name":"Creamy Salmon and Corn Chowder","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":450},{"f":"potatoes","q":500},{"f":"corn_frozen","q":300},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"broth","q":500}],"steps":["Melt the butter in a heavy pot over medium heat and cook the diced onion and celery for 6 minutes, until soft and translucent but not browned.","Add the diced potatoes and broth, bring to a simmer, and cook 15 minutes, until the potato cubes yield completely to a fork.","Mash roughly a third of the potatoes against the pot wall to thicken the base, then stir in the milk and corn and bring back to a bare simmer — small bubbles at the edge, never a boil.","Nestle in the salmon cut into large chunks and poach gently for 5 to 6 minutes, until the fish flakes into rosy petals when nudged.","Season with salt and a heavy hand of black pepper, let the chowder rest off the heat for 5 minutes to settle and thicken, then serve in deep bowls."],"tip":"A chowder that boils is a chowder that breaks — keep it at a lazy shimmer and it will stay silky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_drop_corn_rice_soup', '{"id":"egg_drop_corn_rice_soup","name":"Silky Egg Drop and Corn Soup","emoji":"🥚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":["eggs","sesame"],"time":30,"servings":4,"ing":[{"f":"eggs","q":5},{"f":"corn_frozen","q":300},{"f":"rice","q":180},{"f":"broth","q":1200},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"spinach","q":100},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a boil with the sliced ginger and smashed garlic, then add the rice and simmer 15 minutes, until the grains are tender and the broth has taken on a faint gingery heat.","Add the corn and simmer 3 minutes, until the kernels taste sweet and pop cleanly.","Beat the eggs thoroughly in a spouted cup, then reduce the soup to the gentlest simmer and pour the eggs in a thin, slow stream while stirring the pot in one lazy circle.","Watch the eggs bloom into soft golden ribbons — about 30 seconds — then immediately stop stirring so they stay wispy instead of shredding.","Wilt in the spinach, season with salt, and finish each bowl with a few drops of sesame oil, which should hit your nose before the spoon does."],"tip":"Pour the eggs slow and stir slower — egg drop soup punishes enthusiasm and rewards the half-asleep."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spicy_peanut_sweet_potato_soup', '{"id":"spicy_peanut_sweet_potato_soup","name":"Spicy Peanut and Sweet Potato Soup","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":40,"servings":4,"ing":[{"f":"peanut_butter","q":120},{"f":"sweet_potatoes","q":500},{"f":"coconut_milk","q":200},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":20},{"f":"spinach","q":150}],"steps":["Simmer the diced onion, minced garlic, and grated ginger in a splash of water in a large pot for 4 minutes, until softened and fragrant.","Add the chopped tomatoes and cook 5 minutes, crushing them down until they thicken into a rough, brick-colored base.","Add the sweet potatoes in 2-centimeter cubes and 1 liter of water, bring to a boil, and simmer 15 minutes, until the cubes are fudgy-soft at the center.","Whisk the peanut butter with a ladle of hot broth in a bowl until smooth, then stir it into the pot along with the coconut milk and simmer 5 minutes, until the soup turns thick, glossy, and the color of caramel.","Fold in the spinach until it collapses, season with salt and as much chile heat as you dare, and serve — it should taste rich, nutty, and quietly fiery."],"tip":"Temper the peanut butter with hot broth first, or you will spend ten minutes chasing a stubborn blob around the pot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_potato_cheddar_soup', '{"id":"loaded_potato_cheddar_soup","name":"Loaded Potato and Cheddar Soup","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"potatoes","q":800},{"f":"cheddar","q":120},{"f":"milk","q":500},{"f":"butter","q":40},{"f":"sour_cream","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broccoli","q":200}],"steps":["Melt the butter in a Dutch oven over medium heat and cook the diced onion for 6 minutes, until soft and pale gold, then stir in the garlic for a final fragrant minute.","Add the diced potatoes and 600 ml of water, cover, and simmer 18 minutes, until the potatoes crush effortlessly against the side of the pot.","Mash about half the potatoes right in the pot, then stir in the milk and the broccoli cut into small florets and simmer 5 minutes, until the broccoli is bright green and just tender.","Drop the heat to low and stir in the grated cheddar a handful at a time, letting each melt fully before the next, until the soup is thick, orange-flecked, and glossy.","Remove from the heat, swirl in the sour cream, season with salt and black pepper, and serve before anyone can ask what is taking so long."],"tip":"Add the cheese off a boil and in stages — dump it all in at once and it will seize into a mozzarella-stick impression."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_minestrone_penne_soup', '{"id":"garden_minestrone_penne_soup","name":"Garden Minestrone with Penne","emoji":"🇮🇹","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":50,"servings":4,"ing":[{"f":"black_beans","q":400},{"f":"penne","q":200},{"f":"tomato","q":3},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"parmesan","q":40}],"steps":["Warm the olive oil in a big pot over medium heat and cook the diced onion, carrots, and celery for 8 minutes, until they soften and the bottom of the pot glazes lightly.","Add the minced garlic and chopped tomatoes with a good pinch of salt and simmer 6 to 7 minutes, until the tomatoes collapse into a loose, sweet sauce.","Pour in 1.25 liters of water, add the drained kidney beans, and simmer 10 minutes so the broth picks up body and a rosy color.","Add the penne and diced zucchini and cook 10 to 11 minutes at a steady bubble, until the pasta is al dente and the zucchini is tender but not slumped.","Taste and season — it should be savory and faintly sweet — then ladle into bowls and shower each with grated parmesan while the steam is still rising."],"tip":"Minestrone thickens as it sits, so if you are meal-prepping, keep a little water back and loosen each reheat like a risotto in reverse."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_and_kidney_bean_chili', '{"id":"smoky_beef_and_kidney_bean_chili","name":"Smoky Beef and Kidney Bean Chili","emoji":"🌶️","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"black_beans","q":480},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"broth","q":250}],"steps":["Heat the olive oil in a heavy Dutch oven over medium-high heat and brown the ground beef for 6 to 8 minutes, breaking it into rough crumbles and letting it develop deep mahogany edges before stirring.","Add the diced onion and bell pepper and cook 5 minutes until the onion turns translucent and the pan smells sweet, then stir in the minced garlic for 30 seconds until fragrant.","Pour in the crushed tomatoes and broth, scraping up the browned bits stuck to the bottom, and bring everything to a lively simmer.","Stir in the drained kidney beans, reduce the heat to low, and simmer uncovered for 35 to 40 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged through leaves a brief trail.","Rest the pot off the heat for 5 minutes so the flavors settle, then taste and ladle into deep bowls."],"tip":"Chili is one of the few dishes that improves by ignoring it overnight, so make it a day ahead and take all the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hunter_style_chicken_mushroom_stew', '{"id":"hunter_style_chicken_mushroom_stew","name":"Hunter-Style Chicken and Mushroom Stew","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_breast","q":600},{"f":"mushrooms","q":250},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"olive_oil","q":30},{"f":"broth","q":250}],"steps":["Cut the chicken breast into generous 4-centimeter chunks and sear them in the olive oil over medium-high heat for 3 minutes per side until golden, then transfer to a plate.","Add the sliced mushrooms to the same pot and cook 6 minutes without crowding until their moisture evaporates and they turn nutty brown at the edges.","Stir in the sliced onion, carrots, and garlic and soften for 4 minutes, then pour in the crushed tomatoes and broth and scrape the fond off the bottom.","Return the chicken and its juices to the pot, cover partially, and simmer gently for 25 minutes until the sauce turns glossy and the chicken pulls apart with light fork pressure.","Simmer uncovered for a final 5 minutes to concentrate the sauce, then serve steaming in shallow bowls."],"tip":"Resist stirring the mushrooms early — browning is flavor, and fidgeting is the enemy of browning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_red_lentil_dal_stew', '{"id":"golden_red_lentil_dal_stew","name":"Golden Red Lentil Dal Stew","emoji":"🍛","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"spinach","q":150}],"steps":["Rinse the lentils in a sieve until the water runs nearly clear, which keeps the finished dal silky rather than gluey.","Warm the olive oil in a wide pot over medium heat and cook the finely chopped onion for 8 minutes until deeply golden and sweet-smelling, then add the minced garlic for 1 minute more.","Stir in the crushed tomatoes and cook 5 minutes until they darken and the oil separates slightly at the edges, a sign the base is properly cooked down.","Add the lentils and 900 milliliters of water, bring to a boil, then simmer uncovered for 20 to 25 minutes, stirring now and then, until the lentils collapse into a thick, spoonable porridge.","Fold in the spinach off the heat and let it wilt for 2 minutes, then whisk the dal briefly to make it creamy before serving."],"tip":"Dal thickens dramatically as it sits, so keep a cup of hot water nearby and loosen it like you''re negotiating with pudding."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_chickpea_spinach_stew', '{"id":"mediterranean_chickpea_spinach_stew","name":"Mediterranean Chickpea and Spinach Stew","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"chickpeas","q":720},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"spinach","q":200},{"f":"feta","q":100}],"steps":["Heat the olive oil in a deep skillet over medium heat and cook the sliced onion for 6 minutes until soft and lightly bronzed at the edges.","Add the thinly sliced garlic and stir for 1 minute until it perfumes the kitchen, taking care it does not brown and turn bitter.","Pour in the crushed tomatoes and simmer 8 minutes until the sauce thickens and turns brick red, then stir in the drained chickpeas and 200 milliliters of water.","Simmer gently for 15 minutes, lightly crushing a few chickpeas against the pan to give the stew body, until the broth clings to the back of a spoon.","Fold in the spinach by the handful until just wilted and glossy, then crumble the feta over the top and serve straight from the pan."],"tip":"Crushing a third of the chickpeas is the difference between a stew and chickpeas floating in disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('midnight_black_bean_sweet_potato_chili', '{"id":"midnight_black_bean_sweet_potato_chili","name":"Midnight Black Bean and Sweet Potato Chili","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"black_beans","q":720},{"f":"sweet_potatoes","q":400},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":30}],"steps":["Warm the olive oil in a large pot over medium heat and sweat the diced onion and bell pepper for 6 minutes until soft and fragrant.","Stir in the minced garlic for 30 seconds, then add the sweet potatoes cut into 2-centimeter cubes and toss to coat them in the aromatics.","Pour in the crushed tomatoes plus 250 milliliters of water, bring to a boil, then reduce to a steady simmer for 15 minutes until the sweet potato yields slightly to a knife tip.","Add the drained black beans and simmer 15 minutes more, stirring occasionally, until the chili turns thick and glossy and the sweet potatoes are fully tender.","Mash a few sweet potato cubes against the side of the pot to thicken the pot naturally, rest 5 minutes off the heat, and serve."],"tip":"Cut the sweet potatoes evenly unless you enjoy a chili where half the cubes are mush and the other half fight back."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_white_chicken_chili', '{"id":"creamy_white_chicken_chili","name":"Creamy White Chicken Chili","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"chickpeas","q":240},{"f":"broth","q":750},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"sour_cream","q":120},{"f":"cheddar","q":60}],"steps":["Heat the olive oil in a Dutch oven over medium heat and soften the diced onion and bell pepper for 5 minutes until they smell sweet and lose their crunch.","Add the minced garlic and stir 30 seconds, then nestle in the whole chicken breasts and pour the broth over the top.","Simmer gently, partially covered, for 18 to 20 minutes until the chicken registers cooked through and shreds easily, then lift it out and pull it apart with two forks.","Return the shredded chicken to the pot with the drained chickpeas, mashing a handful of chickpeas first so they thicken the broth, and simmer 8 minutes until slightly creamy.","Take the pot off the heat, stir in the sour cream until the chili turns pale and velvety, and finish each bowl with a snowfall of grated cheddar."],"tip":"Add the sour cream off the heat or it will curdle and your chili will look like it has regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('brothy_shrimp_and_feta_tomato_stew', '{"id":"brothy_shrimp_and_feta_tomato_stew","name":"Brothy Shrimp and Feta Tomato Stew","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["shellfish","dairy"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"feta","q":100}],"steps":["Warm the olive oil in a wide, deep skillet over medium heat and cook the finely chopped onion for 6 minutes until soft and translucent.","Add the sliced garlic and stir 1 minute until fragrant, then pour in the crushed tomatoes and simmer briskly for 12 minutes until the sauce thickens and tastes concentrated rather than tinny.","Season the shrimp, then slide them into the bubbling sauce in a single layer and cook 3 to 4 minutes, turning once, until they curl into loose commas and turn opaque pink.","Scatter the feta over the surface, cover, and let it soften for 2 minutes so the cheese slumps into creamy pockets throughout the stew.","Pull the pan off the heat immediately and serve in warm bowls before the shrimp can even think about overcooking."],"tip":"A shrimp curled into a tight O is overcooked; aim for a relaxed C, like it''s lounging in the sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_salmon_potato_chowder_stew', '{"id":"smoky_salmon_potato_chowder_stew","name":"Smoky Salmon and Potato Chowder Stew","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"potatoes","q":500},{"f":"milk","q":500},{"f":"broth","q":250},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"carrots","q":100},{"f":"butter","q":30}],"steps":["Melt the butter in a heavy pot over medium heat and sweat the diced onion, celery, and carrots for 6 minutes until soft and sweet-smelling, without letting them color.","Add the potatoes cut into 2-centimeter cubes, pour in the broth and milk, and bring to the barest simmer with lazy bubbles just breaking the surface.","Cook gently for 15 minutes, stirring occasionally so the milk does not catch, until the potato cubes are tender enough to crush against the pot wall.","Mash a few potatoes into the liquid to thicken the chowder, then lower in the salmon cut into large chunks and poach 5 to 6 minutes until it flakes into rosy petals.","Rest the pot off the heat for 3 minutes, taste for seasoning, and ladle up, keeping the salmon pieces as intact as your patience allows."],"tip":"Keep the heat whisper-low once the milk goes in, because a boiled chowder breaks and no amount of stirring apologizes for that."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_mushroom_hotpot_stew', '{"id":"tofu_mushroom_hotpot_stew","name":"Savory Tofu and Mushroom Hotpot Stew","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":45,"servings":4,"ing":[{"f":"tofu","q":450},{"f":"mushrooms","q":300},{"f":"rice","q":250},{"f":"carrots","q":150},{"f":"spinach","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3}],"steps":["Start the rice in a small pot with 500 milliliters of water, cover, and simmer on low for 15 minutes, then rest it off the heat while the stew comes together.","Press the tofu briefly between paper towels, cut it into thick 3-centimeter cubes, and set aside so it holds its shape in the broth.","In a large pot, sizzle the minced garlic in the sesame oil over medium heat for 30 seconds, then add the sliced mushrooms and carrots and cook 5 minutes until the mushrooms release their juices and smell earthy.","Pour in 900 milliliters of water and the soy sauce, bring to a gentle simmer, and slide in the tofu cubes to poach for 10 minutes so they swell and soak up the savory broth.","Stir in the spinach until it wilts to a silky green, then ladle the hotpot over scoops of rice in deep bowls."],"tip":"Treat the tofu cubes like sleeping houseguests — move them gently or they will fall apart and haunt your broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_peanut_butter_stew', '{"id":"sweet_potato_peanut_butter_stew","name":"Sweet Potato and Peanut Butter Stew","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"sweet_potatoes","q":600},{"f":"peanut_butter","q":120},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"spinach","q":150},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large pot over medium heat and cook the chopped onion for 6 minutes until golden at the edges, then add the minced garlic for 1 minute more.","Stir in the crushed tomatoes and simmer 5 minutes until they thicken slightly and lose their raw tang.","Add the sweet potatoes cut into 3-centimeter chunks along with 700 milliliters of water, bring to a boil, and simmer 15 minutes until a knife slips into the largest piece with only slight resistance.","Whisk the peanut butter with a ladleful of the hot broth in a bowl until smooth, then stir it back into the pot and simmer 5 minutes until the stew turns thick, glossy, and the color of terracotta.","Fold in the spinach until just wilted, rest the pot for a few minutes off the heat, and serve while the aroma is still doing its best work."],"tip":"Tempering the peanut butter with hot broth first saves you from chasing stubborn peanut clumps around the pot like a carnival game."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_kidney_bean_penne_stew', '{"id":"tuscan_kidney_bean_penne_stew","name":"Tuscan Bean and Penne Stew","emoji":"🍝","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":45,"servings":4,"ing":[{"f":"black_beans","q":480},{"f":"penne","q":250},{"f":"crushed_tomatoes","q":400},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"parmesan","q":40}],"steps":["Warm the olive oil in a large pot over medium heat and cook the finely diced onion, carrots, and celery for 8 minutes until soft, sweet, and lightly golden — this soffritto is the stew''s whole personality.","Add the minced garlic for 1 minute, then stir in the crushed tomatoes and simmer 5 minutes until the sauce darkens a shade.","Add the drained kidney beans and 1 liter of water, mash a quarter of the beans against the pot to lend creaminess, and bring everything to a rolling simmer.","Tip in the penne and cook 11 to 13 minutes, stirring often as the pasta drinks the broth, until the penne is tender and the stew is thick enough to mound gently on a spoon.","Rest for 3 minutes off the heat, then serve with parmesan grated generously over each bowl."],"tip":"The pasta keeps drinking broth after the heat goes off, so serve promptly or embrace the fact that you have made a very noble casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_style_pepper_egg_stew', '{"id":"shakshuka_style_pepper_egg_stew","name":"Shakshuka-Style Pepper and Egg Stew","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":35,"servings":4,"ing":[{"f":"eggs","q":8},{"f":"crushed_tomatoes","q":800},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"feta","q":80}],"steps":["Heat the olive oil in a wide, deep skillet over medium heat and cook the sliced onion and bell peppers for 8 minutes until slumped, sweet, and lightly charred in spots.","Add the minced garlic and stir 1 minute, then pour in the crushed tomatoes and simmer 10 to 12 minutes until the sauce thickens enough to hold a spoon-drawn trench.","Use the back of a spoon to press 8 wells into the sauce, then crack an egg into each hollow.","Cover the pan and cook 6 to 8 minutes over low heat until the whites are just set but the yolks still shimmy when you nudge the pan.","Scatter the crumbled feta over the top, rest 2 minutes off the heat, and bring the whole pan to the table like the trophy it is."],"tip":"The eggs keep cooking under the lid even off the heat, so pull them when they look one minute underdone and trust the physics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_mushroom_black_bean_potato_stew', '{"id":"hearty_mushroom_black_bean_potato_stew","name":"Hearty Mushroom, Black Bean, and Potato Stew","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":55,"servings":4,"ing":[{"f":"mushrooms","q":500},{"f":"black_beans","q":400},{"f":"potatoes","q":600},{"f":"carrots","q":200},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"soy_sauce","q":30}],"steps":["Heat half the olive oil in a Dutch oven over medium-high heat and brown the quartered mushrooms in two batches for 5 to 6 minutes each, until deeply golden and meaty-smelling, then set them aside.","Add the remaining oil with the diced onion, carrots, and celery and cook 6 minutes until softened, then stir in the minced garlic for 30 seconds.","Add the potatoes in 3-centimeter chunks, 900 milliliters of water, and the soy sauce, and bring the pot to a steady simmer.","Cook 20 minutes until the potatoes are fork-tender, then return the mushrooms with the drained black beans and simmer 10 minutes more so the flavors knit together.","Crush a few potato chunks against the side of the pot to thicken the gravy, taste for salt, and serve in wide bowls with plenty of that dark, savory broth."],"tip":"Browning mushrooms in batches feels fussy until you taste the difference between seared and steamed — one is dinner, the other is regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cobb_crunch_salad', '{"id":"chicken_cobb_crunch_salad","name":"Grilled Chicken Cobb Crunch Salad","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"bacon","q":60},{"f":"eggs","q":2},{"f":"romaine","q":1},{"f":"cherry_tomatoes","q":150},{"f":"avocado","q":1},{"f":"cheddar","q":40},{"f":"greek_yogurt","q":60},{"f":"lemon","q":0.5},{"f":"garlic","q":0.1},{"f":"olive_oil","q":15},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Simmer the eggs in boiling water for 9 minutes, then shock them in ice water and peel once cool enough to handle.","Meanwhile, cook the bacon in a cold skillet over medium heat for 8 to 10 minutes until deeply crisp, then drain on a plate and pour off all but a slick of fat.","Season the chicken with salt and pepper, rub with olive oil, and sear in the same skillet over medium-high for 5 to 6 minutes per side until golden and 165F inside; rest 5 minutes before slicing against the grain.","Whisk the greek yogurt with lemon juice, grated garlic, a pinch of salt, and a spoonful of water until it drizzles like heavy cream.","Chop the romaine and spread it over a platter, then arrange the sliced chicken, halved eggs, crumbled bacon, halved tomatoes, diced avocado, and cheddar in neat rows.","Drizzle the dressing over everything, grind on more black pepper, and serve while the chicken is still faintly warm."],"tip":"The neat rows are for the photo; toss it all together before eating like an honest person."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_parmesan_salmon_kale_salad', '{"id":"lemon_parmesan_salmon_kale_salad","name":"Lemon-Parmesan Salmon Kale Salad","emoji":"🐟","cuisine":"Italian","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"kale","q":0.8},{"f":"parmesan","q":30},{"f":"bread","q":2.5},{"f":"cherry_tomatoes","q":100},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Tear the bread into rough cubes, toss with a third of the olive oil and a pinch of salt, and toast in a 400F oven for 8 to 10 minutes until golden and rattling-dry.","Strip the kale from its stems, chop it fine, and massage it firmly with a pinch of salt and a squeeze of lemon for a full minute until it darkens and slumps.","Whisk the remaining olive oil with the rest of the lemon juice, grated garlic, half the parmesan, and plenty of black pepper to make a sharp, cloudy dressing.","Season the salmon and sear it skin-side down in a hot skillet over medium-high for 4 minutes until the skin crackles, then flip and cook 2 to 3 minutes more until just opaque at the center.","Toss the kale with the dressing, croutons, and halved tomatoes, then flake the warm salmon over the top in big glossy pieces.","Shower with the remaining parmesan and serve immediately, while the croutons still crunch."],"tip":"Massaging kale feels ridiculous right up until you taste the difference, so commit to the full minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_couscous_salad', '{"id":"lemon_shrimp_couscous_salad","name":"Lemon Shrimp and Couscous Salad","emoji":"🍤","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"couscous","q":120},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"olive_oil","q":25},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pour the couscous into a bowl with a pinch of salt, cover with an equal volume of boiling water, seal with a plate, and let it steam for 5 minutes before fluffing with a fork.","Pat the shrimp very dry, toss with minced garlic, oregano, salt, and pepper, and sear in a splash of the olive oil over high heat for about 90 seconds per side until pink and curled into loose commas.","Whisk the remaining olive oil with the lemon juice and zest and a good grind of pepper to make a bright dressing.","Fold the diced cucumber, halved tomatoes, olives, and chopped parsley into the fluffed couscous with most of the dressing.","Pile the shrimp on top, crumble over the feta, and finish with the last spoonful of dressing.","Taste and adjust with more lemon or salt; it should taste like a beach vacation, not a grain bowl."],"tip":"Shrimp go from perfect to pencil erasers in about 40 seconds, so pull them the moment they curl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_tuna_white_bean_salad', '{"id":"tuscan_tuna_white_bean_salad","name":"Tuscan Tuna and White Bean Salad","emoji":"🫘","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"white_beans","q":300},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"celery","q":60},{"f":"olives","q":50},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Slice the onion into paper-thin half moons and soak them in ice water for 10 minutes to tame their bite while you prep everything else.","Whisk the olive oil with the lemon juice and zest, salt, and a heavy grind of black pepper in the bottom of a wide serving bowl.","Add the drained white beans, thinly sliced celery, olives, and the drained onions, and toss gently so the beans slick up without breaking apart.","Flake the drained tuna over the top in large chunks and fold it in just once or twice, keeping the pieces bold and visible.","Add the spinach and chopped parsley, toss lightly, and let the salad sit for 5 minutes so the beans drink in the dressing.","Serve at room temperature, when the flavors are loudest."],"tip":"Resist the urge to stir enthusiastically; mashed tuna and bean paste is a different, sadder recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_peanut_crunch_salad', '{"id":"crispy_tofu_peanut_crunch_salad","name":"Crispy Tofu Peanut Crunch Salad","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","nuts","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":30},{"f":"lime","q":1.5},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"ginger","q":10}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough bite-size chunks; the craggy edges crisp better than neat cubes ever will.","Toss the tofu with half the soy sauce, then pan-fry in the olive oil over medium-high heat for 10 to 12 minutes, turning occasionally, until the pieces are deeply golden and sound hollow when tapped with a spatula.","Whisk the peanut butter with the remaining soy sauce, lime juice, maple syrup, sesame oil, grated ginger, and enough warm water to reach a pourable, ribbon-off-the-whisk consistency.","Shred the cabbage as thin as you can manage, julienne the carrots, and slice the bell pepper and scallions into slivers.","Toss the vegetables with two-thirds of the dressing until everything glistens, then top with the hot tofu and torn cilantro.","Drizzle the remaining dressing over the top and serve while the tofu still crackles against the cold crunch."],"tip":"Torn tofu is the rare case where being lazy and sloppy actively improves the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_kachumber_salad', '{"id":"chickpea_kachumber_salad","name":"Chickpea Kachumber Salad","emoji":"🥒","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":1.5},{"f":"ginger","q":10},{"f":"cumin","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Toast the cumin in a dry skillet over medium heat for about 60 seconds, swirling constantly, until it smells warm and nutty; tip it out immediately so it does not scorch.","Dice the cucumber, tomatoes, and onion into small, even pieces so every spoonful carries a bit of each.","Warm the olive oil in the same skillet, add the drained chickpeas with the chili powder and a pinch of salt, and fry for 5 to 6 minutes until they blister and turn lightly golden at the edges.","Whisk the lime juice with the grated ginger, toasted cumin, and remaining salt in a large bowl.","Add the warm chickpeas and diced vegetables and toss well, letting the heat of the chickpeas coax the juices out of the tomatoes.","Fold in the chopped cilantro just before serving and taste; it should be bright, spicy, and a little bit rowdy."],"tip":"Warm chickpeas plus cold crunchy vegetables is the whole trick, so do not let the chickpeas sit around cooling off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_feta_walnut_salad', '{"id":"lentil_feta_walnut_salad","name":"Lentil, Feta, and Walnut Salad","emoji":"🌿","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":180},{"f":"feta","q":80},{"f":"walnuts","q":40},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.1},{"f":"balsamic_vinegar","q":20},{"f":"olive_oil","q":25},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Simmer the lentils in well-salted water for 20 to 25 minutes until tender but still holding their shape with a gentle pop, then drain well.","While they cook, toast the walnuts in a dry skillet over medium heat for 4 to 5 minutes until fragrant, then chop them roughly.","Whisk the balsamic vinegar with the olive oil, grated garlic, oregano, salt, and pepper into a glossy dressing.","Toss the warm lentils with the dressing right away so they absorb it as they cool, about 10 minutes.","Fold in the finely diced carrots, celery, and onion, then the spinach, letting the residual warmth barely wilt the leaves.","Crumble the feta over the top, scatter on the walnuts, and finish with a last grind of pepper."],"tip":"Dressing lentils while warm is non-negotiable; cold lentils absorb flavor about as well as gravel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_lime_salad', '{"id":"black_bean_avocado_lime_salad","name":"Black Bean and Avocado Lime Salad","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"avocado","q":1},{"f":"corn_frozen","q":150},{"f":"bell_pepper","q":1},{"f":"romaine","q":0.5},{"f":"onion","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":2},{"f":"cumin","q":2},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Char the corn in a dry skillet over high heat for 4 to 5 minutes without stirring too often, until a good scattering of kernels turns toasty brown.","Whisk the lime juice with the olive oil, cumin, chili powder, and salt in a large bowl until the dressing looks slightly thickened.","Add the drained black beans, charred corn, diced bell pepper, and finely diced onion, and toss until everything is coated.","Let the mixture marinate for 10 minutes so the beans soak up the lime while you chop the romaine.","Fold in the diced avocado and chopped cilantro gently, keeping the avocado in proud green chunks.","Pile the bean mixture over the chopped romaine and serve with extra lime wedges on the side."],"tip":"Char the corn until you are slightly nervous about it; timid corn is just warm corn."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_crunch_salad', '{"id":"beef_taco_crunch_salad","name":"Beef Taco Crunch Salad","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"romaine","q":1},{"f":"tortillas","q":2},{"f":"cheddar","q":50},{"f":"salsa","q":120},{"f":"sour_cream","q":50},{"f":"avocado","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"lime","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Slice the tortillas into thin strips, toss with the olive oil and a pinch of salt, and bake at 400F for 6 to 8 minutes until golden and shatteringly crisp.","Brown the ground beef in a dry skillet over medium-high heat for 6 to 7 minutes, breaking it into small crumbles and letting it sit undisturbed at the end so it picks up crusty edges.","Add the diced onion, minced garlic, cumin, chili powder, and salt, and cook 3 minutes more until the onion softens and the spices smell toasty, then stir in half the salsa and simmer until it clings.","Whisk the sour cream with the lime juice and a splash of water into a drizzly crema.","Chop the romaine and mound it into bowls, then top with the hot beef, remaining salsa, cheddar, and diced avocado.","Drizzle with the lime crema and crown with the tortilla strips at the very last second so they stay loud."],"tip":"Add the tortilla strips at the table, not in the kitchen, unless you enjoy chewing on regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_noodle_salad', '{"id":"ginger_pork_noodle_salad","name":"Ginger Pork Rice Noodle Salad","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice_noodles","q":120},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"cilantro","q":0.5},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"honey","q":20},{"f":"lime","q":1.5},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Slice the pork loin thin, then toss it with half the soy sauce, half the honey, the grated ginger, and the minced garlic; let it sit 10 minutes while you handle the noodles.","Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still springy, then rinse under cold water and drain thoroughly.","Whisk the remaining soy sauce, honey, and lime juice with the sesame oil to make a sweet-sharp dressing.","Sear the pork in the olive oil over high heat in a single layer for about 2 minutes per side, until the edges caramelize and the marinade lacquers into a sticky glaze.","Toss the cold noodles with the dressing, julienned cucumber and carrots, and sliced scallions.","Top with the hot glazed pork and a generous handful of torn cilantro, and eat while the temperatures are still arguing."],"tip":"Crowd the pan and the pork steams; give the slices personal space and they caramelize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_bacon_egg_spinach_salad', '{"id":"warm_bacon_egg_spinach_salad","name":"Warm Bacon and Egg Spinach Salad","emoji":"🍳","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"bacon","q":100},{"f":"spinach","q":200},{"f":"mushrooms","q":150},{"f":"cherry_tomatoes","q":100},{"f":"onion","q":0.5},{"f":"balsamic_vinegar","q":20},{"f":"olive_oil","q":10},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Simmer the eggs for 7 minutes for jammy centers, then plunge them into ice water and peel once cool.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until crisp, then scoop it out, leaving every drop of fat behind.","Sear the sliced mushrooms in the bacon fat over medium-high heat for 5 minutes until browned and squeaky-tender, adding the sliced onion for the last 2 minutes.","Pull the pan off the heat, whisk the balsamic vinegar and olive oil into the warm fat with salt and pepper, and let it bubble into a glossy warm dressing.","Pour the hot dressing and mushrooms over the spinach and halved tomatoes in a large bowl, tossing quickly so the leaves wilt just at the edges.","Top with the halved jammy eggs and crisp bacon, and serve immediately, before the wilt turns to surrender."],"tip":"This salad has a five-minute window of greatness, so seat your dinner guests before you dress it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_crunch_salad_2', '{"id":"sesame_edamame_crunch_salad_2","name":"Sesame Edamame Crunch Salad","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","nuts","sesame"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"almonds","q":40},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":10},{"f":"lime","q":1},{"f":"ginger","q":10}],"steps":["Blanch the edamame in boiling water for 3 to 4 minutes until bright green and tender, then drain and rinse briefly under cold water.","Toast the almonds in a dry skillet over medium heat for 4 minutes, shaking often, until golden and fragrant, then chop them coarsely.","Whisk the soy sauce, sesame oil, maple syrup, lime juice, and grated ginger into a dressing that tastes assertively salty-sweet on its own.","Shred the cabbage into fine ribbons and julienne the carrots and bell pepper so everything is thin enough to tangle together.","Toss the vegetables and edamame with the dressing, squeezing and tossing for a good 30 seconds so the cabbage starts to relax.","Let it sit 5 minutes, then finish with sliced scallions and the toasted almonds right before serving."],"tip":"This salad is actually better after an hour in the fridge, which makes it the rare make-ahead that keeps its crunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_larb_style_salad', '{"id":"turkey_larb_style_salad","name":"Turkey Larb-Style Lettuce Salad","emoji":"🌶️","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":2},{"f":"soy_sauce","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"chili_powder","q":2},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large skillet over high heat until it shimmers, then add the ground turkey and press it flat like a burger.","Let it sear undisturbed for 3 minutes until deeply browned underneath, then break it into crumbles and stir in the minced garlic and grated ginger for the final 2 minutes.","Kill the heat and stir in the soy sauce, the juice of both limes, and the chili powder; the mixture should taste sharp, salty, and a little too intense on its own.","Fold in the sliced scallions and most of the cilantro while the turkey is still steaming, letting the herbs wilt slightly into the meat.","Chop the romaine into a wide bowl, scatter over the thinly sliced cucumber, and spoon the hot turkey and all its juices on top.","Finish with the remaining cilantro and serve immediately, scooping the salad up so every bite has hot, cold, and crunch."],"tip":"The dressing should make you wince slightly in the pan, because the mountain of lettuce will dilute it to perfect."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_tuna_melt', '{"id":"classic_tuna_melt","name":"Golden-Crusted Classic Tuna Melt","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"tomato","q":1},{"f":"butter","q":20}],"steps":["Drain the tuna well and fold it with the greek yogurt, finely minced onion, and a big squeeze of lemon until creamy but still chunky.","Butter one side of each bread slice and lay two slices butter-side down in a cold skillet.","Pile the tuna salad onto the bread, shingle on thin tomato slices, blanket with cheddar, and cap with the remaining slices butter-side up.","Set the skillet over medium heat and cook for 4 to 5 minutes per side, pressing gently with a spatula, until the crust is deep golden and crackles when tapped.","Rest the sandwiches for 2 minutes so the molten cheddar sets slightly, then slice on the diagonal and serve hot."],"tip":"A cold skillet start gives the butter time to crisp the bread before the cheese panics and leaks out."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_smash_toast_with_fried_eggs', '{"id":"avocado_smash_toast_with_fried_eggs","name":"Avocado Smash Toast with Crispy-Edged Eggs","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"avocado","q":1},{"f":"eggs","q":4},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15}],"steps":["Toast the bread until it is deeply bronzed and sturdy enough to knock on the counter, about 3 to 4 minutes in a hot toaster or dry skillet.","Halve the avocado and smash the flesh in a bowl with the lemon juice and a pinch of salt, leaving it rubbly rather than smooth.","Heat the olive oil in a nonstick skillet over medium-high until it shimmers, then crack in the eggs and fry for about 3 minutes, until the whites are lacy and crisp at the edges but the yolks still wobble.","Spread the avocado thickly to the very edges of each toast so every bite gets some.","Slide an egg onto each slice, season generously with salt and pepper, and eat immediately while the yolk is still runny enough to sauce the toast."],"tip":"Salt the avocado, not the naked toast, or the seasoning will bounce right off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_hummus_pita_pockets', '{"id":"mediterranean_hummus_pita_pockets","name":"Loaded Mediterranean Hummus Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","sesame","dairy"],"time":15,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":150},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"feta","q":60},{"f":"spinach","q":40},{"f":"olive_oil","q":10},{"f":"lemon","q":0.5}],"steps":["Warm the pitas in a dry skillet over medium heat for about a minute per side until they puff slightly and smell toasty, then halve them into pockets.","Dice the cucumber and tomato, slice the onion paper-thin, and toss everything with the olive oil, lemon juice, and a pinch of salt so the vegetables glisten.","Swipe a thick layer of hummus inside each pita half, reaching all the way into the seam so no bite is dry.","Stuff the pockets with spinach leaves and the dressed vegetables, packing them snugly but not to bursting.","Crumble the feta over the filling, press the pockets gently closed, and serve while the pita is still warm against the cool crunch inside."],"tip":"Dress the vegetables before stuffing, not after, unless you enjoy chasing lemon juice down your wrist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('grilled_chicken_pita_with_yogurt_sauce', '{"id":"grilled_chicken_pita_with_yogurt_sauce","name":"Charred Lemon Chicken Pitas with Garlicky Yogurt","emoji":"🍗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"greek_yogurt","q":120},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"cucumber","q":0.5},{"f":"pita","q":2},{"f":"olive_oil","q":15},{"f":"onion","q":0.3},{"f":"tomato","q":1}],"steps":["Slice the chicken into thick strips and toss with the olive oil, the juice of half the lemon, one grated garlic clove, and plenty of salt and pepper.","Sear the chicken in a screaming-hot skillet over medium-high heat for 3 to 4 minutes per side until deeply charred at the edges and cooked through to 165F.","While the chicken rests, grate the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the remaining garlic and lemon juice to make a quick cooling sauce.","Warm the pitas directly over the skillet''s residual heat for 30 seconds per side until soft and pliable.","Slather the yogurt sauce down the center of each pita, pile on the chicken, sliced onion, and chopped tomato, then fold and wrap the bottom in foil or parchment so nothing escapes."],"tip":"Squeezing the cucumber dry feels fussy until the day you skip it and your sauce turns into soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('skillet_tomato_grilled_cheese', '{"id":"skillet_tomato_grilled_cheese","name":"Double-Cheese Grilled Cheese with Jammy Tomato","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"cheddar","q":100},{"f":"mozzarella","q":60},{"f":"tomato","q":1},{"f":"butter","q":30}],"steps":["Slice the tomato thin and let the slices drain on a paper towel for 5 minutes so they concentrate instead of steaming the bread soggy.","Butter the outsides of all four bread slices right to the corners, because a pale corner is a broken promise.","Layer cheddar, tomato, then mozzarella between the slices, putting cheese on both sides of the tomato so it glues the sandwich shut.","Cook in a skillet over medium-low heat for 4 to 5 minutes per side, pressing lightly, until the bread is mahogany and the cheese sighs out at the seams.","Rest for 2 minutes on a rack so the bottom stays crisp, then slice and pull apart slowly to admire the cheese stretch you earned."],"tip":"Medium-low heat is the whole secret; high heat gives you burnt bread hugging cold cheese."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_salmon_flake_toast', '{"id":"lemony_salmon_flake_toast","name":"Lemony Flaked Salmon Toasts with Yogurt Schmear","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"bread","q":4},{"f":"greek_yogurt","q":80},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"spinach","q":60},{"f":"onion","q":0.3}],"steps":["Season the salmon with salt and sear it in half the olive oil over medium-high heat, 4 minutes skin-side down until crisp, then 2 to 3 minutes more until it flakes at a nudge.","While the salmon rests, wilt the spinach in the same pan for about a minute, letting it pick up the savory fond left behind.","Toast the bread until golden and firm, then rub each slice lightly with the cut lemon for a whisper of brightness.","Stir the lemon zest and a squeeze of juice into the yogurt and spread it thickly over the toasts.","Top with the wilted spinach, big flakes of warm salmon, and paper-thin onion, then finish with the remaining olive oil and a crack of black pepper."],"tip":"If the salmon skin sticks, it is not done crisping; give it thirty more seconds and it will release like a gentleman."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('deli_style_egg_salad_sandwich', '{"id":"deli_style_egg_salad_sandwich","name":"Deli-Style Egg Salad Sandwich on Toasted Bread","emoji":"🥚","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"greek_yogurt","q":80},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"bread","q":4},{"f":"romaine","q":0.3}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then shock them in ice water until fully cool so the yolks stay sunny with no gray ring.","Peel and chop the eggs roughly, leaving some yolk chunks the size of dice for a properly rustic texture.","Fold the eggs with the greek yogurt, finely minced onion, lemon juice, and a firm hand of salt and pepper until just combined and creamy.","Toast the bread lightly so it holds its spine against the soft filling.","Lay crisp romaine leaves on two slices, mound the egg salad generously on top, cap with the remaining toast, and press just enough to commit."],"tip":"Chill the egg salad for ten minutes if you can wait; the flavors get friendlier and the sandwich stops sliding around."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_patty_melt', '{"id":"diner_patty_melt","name":"Diner Patty Melt with Deeply Caramelized Onions","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"onion","q":1},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"butter","q":25}],"steps":["Slice the onion thin and cook it slowly in a third of the butter over medium-low heat for 12 to 15 minutes, stirring now and then, until it turns the color of caramel and smells sweet.","Shape the beef into two thin, bread-sized patties, season aggressively with salt and pepper, and sear in a hot skillet for about 3 minutes per side until crusty and just cooked through.","Butter the outsides of the bread slices and build each melt with cheddar, a patty, a tangle of onions, more cheddar, and the top slice.","Griddle the sandwiches over medium heat for 3 to 4 minutes per side, pressing with a spatula, until the bread crackles and the cheese fuses everything into one unit.","Slice in half and serve immediately, while the middle is still molten and slightly indecent."],"tip":"Thin patties are the law here; a thick burger turns a patty melt into a construction project."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('blistered_caprese_style_toast', '{"id":"blistered_caprese_style_toast","name":"Blistered Tomato and Mozzarella Toast","emoji":"🍅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"mozzarella","q":150},{"f":"tomato","q":2},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2}],"steps":["Halve the tomatoes and sear them cut-side down in half the olive oil over high heat for 3 to 4 minutes, undisturbed, until the edges blister and blacken in spots.","Meanwhile, toast the bread until deeply golden, then rub each hot slice with the cut garlic clove so it melts invisibly into the crumb.","Tear the mozzarella into ragged pieces and distribute it over the garlic toasts.","Crush the blistered tomatoes gently on top so their hot juices seep into the cheese and bread.","Drizzle with the remaining olive oil, season with flaky salt and black pepper, and serve while the mozzarella is just beginning to slump."],"tip":"Rub the garlic on the toast while it is still hot; cold toast grates the garlic, warm toast absorbs it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_butter_banana_honey_toast', '{"id":"peanut_butter_banana_honey_toast","name":"Griddled Peanut Butter, Banana, and Honey Toast","emoji":"🍌","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"peanut_butter","q":80},{"f":"banana","q":2},{"f":"honey","q":20}],"steps":["Toast the bread in a dry skillet over medium heat for 2 to 3 minutes per side until golden and fragrant, which gives a crunchier base than a pop-up toaster.","Spread the peanut butter generously over the hot toast so it loosens and turns glossy.","Slice the bananas into thick coins and shingle them over the peanut butter in overlapping rows.","Return the toasts to the skillet for one minute, covered, so the bananas warm and soften at their edges.","Drizzle with honey, add a small pinch of salt to sharpen the sweetness, and serve while everything is warm and slightly melty."],"tip":"That tiny pinch of salt at the end is the difference between a snack and a dessert you would defend in court."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('whipped_ricotta_walnut_honey_toast', '{"id":"whipped_ricotta_walnut_honey_toast","name":"Whipped Ricotta Toast with Toasted Walnuts and Honey","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"ricotta","q":200},{"f":"honey","q":30},{"f":"walnuts","q":40},{"f":"lemon","q":0.5}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until they smell rich and take on a shade of color, then chop them roughly.","Whip the ricotta vigorously with the lemon zest and a pinch of salt until it turns light, glossy, and spreadable like frosting.","Toast the bread until the surface is crisp and deeply golden but the center still has a little chew.","Swoop the whipped ricotta over each slice in thick, dramatic waves.","Scatter the warm walnuts on top, drizzle with honey, and finish with a few drops of lemon juice to keep the richness honest."],"tip":"Whipping ricotta takes ninety seconds and upgrades it from grainy to cloud; do not skip it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_salad_sandwich', '{"id":"smashed_chickpea_salad_sandwich","name":"Smashed Chickpea Salad Sandwich with Lemon and Hummus","emoji":"🌱","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"hummus","q":60},{"f":"lemon","q":0.5},{"f":"onion","q":0.3},{"f":"cucumber","q":0.3},{"f":"olive_oil","q":10},{"f":"bread","q":4},{"f":"spinach","q":30}],"steps":["Smash the chickpeas in a bowl with a fork until about half are crushed into a rough paste and half remain whole, giving the salad both body and bite.","Fold in the hummus, olive oil, lemon juice, finely minced onion, and diced cucumber, then season boldly with salt and pepper.","Taste and adjust; chickpeas drink up lemon and salt, so it usually needs more of both than you expect.","Toast the bread until golden so it can stand up to the hearty filling.","Layer spinach on two slices, pile the chickpea smash high, top with the remaining toast, and press gently before slicing in half."],"tip":"Leave half the chickpeas whole on purpose; a fully smooth mash eats like spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_mushroom_parmesan_toast', '{"id":"garlicky_mushroom_parmesan_toast","name":"Garlicky Mushroom Toast with Parmesan and Spinach","emoji":"🍄","cuisine":"American","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"garlic","q":0.3},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"bread","q":4},{"f":"parmesan","q":40},{"f":"spinach","q":60}],"steps":["Slice the mushrooms thick and sear them in the olive oil over high heat in a single layer, resisting the urge to stir for the first 3 minutes so they brown instead of steam.","Once the mushrooms are deeply golden and squeaking has turned to sizzling, add the butter and minced garlic and toss for one fragrant minute.","Pile in the spinach and stir until it just collapses into the buttery mushrooms, then season with salt and plenty of black pepper.","Toast the bread until sturdy and golden, because these toppings show no mercy to flimsy bread.","Heap the mushroom mixture onto the toasts, shower generously with grated parmesan, and serve while the cheese softens into the steam."],"tip":"Crowded mushrooms weep and boil; give them room in the pan or cook them in two proud batches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_shawarma_pita_pockets', '{"id":"chicken_shawarma_pita_pockets","name":"Weeknight Chicken Shawarma Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.5}],"steps":["Slice the chicken into thin strips and toss with half the olive oil, the juice of half the lemon, two minced garlic cloves, and a bold shower of salt, pepper, and any warm spices you love; let it sit 10 minutes while you prep the vegetables.","Heat a heavy skillet over medium-high until a drop of water skitters across it, then lay the chicken in a single layer and cook undisturbed for 3 minutes until deeply browned at the edges.","Flip and cook 3 to 4 minutes more, until the strips are firm to the touch and the pan juices have reduced to a sticky glaze that coats each piece.","Stir the remaining garlic and lemon juice into the yogurt with a pinch of salt to make a quick white sauce, and dice the cucumber, tomato, and onion.","Warm the pitas directly over a low flame or in the dry skillet for 30 seconds per side until puffed and pliable, then halve them into pockets.","Stuff each pocket with chicken and vegetables, spoon the garlicky yogurt generously over the top, and eat while the bread is still warm."],"tip":"Resist the urge to stir the chicken early — those crusty browned edges are the whole personality of a shawarma."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_street_taco_wraps', '{"id":"smoky_beef_street_taco_wraps","name":"Smoky Skillet Beef Taco Wraps","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":1},{"f":"cheddar","q":40},{"f":"sour_cream","q":40},{"f":"romaine","q":0.3},{"f":"lime","q":1}],"steps":["Set a wide skillet over medium-high heat, add the beef, and press it flat like a burger; leave it alone for 3 minutes so the underside develops a crackly brown crust.","Break the meat into rubble, stir in the diced onion and minced garlic, and cook 4 minutes more until the onion turns translucent and the kitchen smells like taco night.","Add the chopped tomato with a firm pinch of salt and a smoky spice of your choosing, and simmer 3 to 4 minutes until the mixture is juicy but no longer watery.","Warm the tortillas in a dry pan for 20 seconds per side until they smell toasty and bend without cracking.","Pile the beef down the center of each tortilla, then finish with shredded romaine, grated cheddar, a swipe of sour cream, and a hard squeeze of lime before folding."],"tip":"Char one side of each tortilla just past comfortable — a few black freckles do more for flavor than any extra topping."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_wraps', '{"id":"chili_lime_shrimp_wraps","name":"Chili-Lime Shrimp Wraps with Cool Crema","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"olive_oil","q":15},{"f":"greek_yogurt","q":80},{"f":"romaine","q":0.3},{"f":"garlic","q":0.2}],"steps":["Pat the shrimp bone-dry with paper towels, then toss them with the olive oil, minced garlic, the zest and juice of one lime, and enough chili-forward seasoning to make them blush.","Whisk the yogurt with the juice of the second lime and a pinch of salt until it is pourable, and shred the romaine into thin ribbons.","Heat a skillet over high until it is smoking faintly, then sear the shrimp in a single layer for 90 seconds per side, until they curl into loose commas and turn opaque pink.","Warm the tortillas in the same pan, letting them soak up the garlicky drippings for a few seconds on each side.","Layer romaine, sliced avocado, and shrimp onto each tortilla, drizzle with the lime crema, and fold while everything is still hot."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the C shape and they will finish in the wrap."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_hummus_pitas', '{"id":"smashed_chickpea_hummus_pitas","name":"Smashed Chickpea and Hummus Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"hummus","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"pita","q":2},{"f":"spinach","q":60}],"steps":["Tip the drained chickpeas into a wide bowl and crush them with a fork until roughly half are mashed and half are still whole, giving the filling both creaminess and bite.","Fold in the olive oil, the juice and zest of the lemon, the finely diced onion, and a generous pinch of salt and pepper, tasting until it makes you squint happily.","Dice the cucumber and tomato small so they tuck neatly into the pockets rather than tumbling out with the first bite.","Toast the pitas until warm and just barely crisp at the edges, about 1 minute per side in a dry skillet, then slice each into two pockets.","Paint the inside of every pocket with a thick layer of hummus, stuff with spinach, the chickpea smash, and the diced vegetables, and press gently to seal."],"tip":"The hummus is not just flavor, it is mortar — a full coat on both inner walls keeps the pocket from springing a leak."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_tofu_crunch_wraps', '{"id":"sesame_glazed_tofu_crunch_wraps","name":"Sesame-Glazed Tofu Crunch Wraps","emoji":"🌯","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"maple_syrup","q":15},{"f":"tortillas","q":4},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes, then cut it into finger-length batons; dry tofu is the difference between crisp and sad.","Whisk the soy sauce, maple syrup, sesame oil, and minced garlic into a glossy glaze.","Sear the tofu in a hot nonstick skillet over medium-high for 3 minutes per side until every face is golden and crackled, then pour in the glaze and toss for 60 seconds as it bubbles down to a lacquer that clings to each baton.","While the tofu cooks, shave the carrots into ribbons with a peeler and slice the cucumber into thin planks for cool crunch.","Warm the tortillas, lay in the glazed tofu and raw vegetables, drizzle any pan syrup over the top, and roll them tight like sleeping bags."],"tip":"If your tofu sticks, your pan was not hot enough or your patience was not long enough — usually the second one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_style_tuna_melt_pitas', '{"id":"diner_style_tuna_melt_pitas","name":"Diner-Style Tuna Melt Pita Pockets","emoji":"🫓","cuisine":"American","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"cheddar","q":80},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"pita","q":2},{"f":"tomato","q":1}],"steps":["Drain the tuna firmly and flake it into a bowl, then fold in the yogurt, finely minced onion, a squeeze of lemon, and enough black pepper to make it interesting.","Halve the pitas into pockets and slip a thin layer of sliced tomato against one inner wall of each.","Divide the tuna salad among the pockets and tuck the grated cheddar right on top of the filling so it melts into every crevice.","Toast the stuffed pitas in a dry skillet over medium heat for 2 to 3 minutes per side, pressing gently with a spatula, until the bread is crisp and golden and cheese peeks out molten at the seams.","Rest them for one full minute before biting — the interior is lava, and it needs a moment to settle into gooey perfection."],"tip":"Greek yogurt gives you the creaminess of mayo with an alibi, and nobody at the table will file a complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sunrise_pepper_egg_burrito_wraps', '{"id":"sunrise_pepper_egg_burrito_wraps","name":"Sunrise Pepper and Egg Breakfast Wraps","emoji":"🌅","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","high-protein"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tortillas","q":2},{"f":"cheddar","q":60},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":60},{"f":"olive_oil","q":10}],"steps":["Warm the olive oil in a nonstick skillet over medium heat and cook the diced bell pepper and onion for 4 to 5 minutes until soft and sweet at the edges.","Add the spinach in handfuls and stir just until it collapses into glossy green ribbons, about 1 minute.","Whisk the eggs with a pinch of salt until uniformly yellow, pour them over the vegetables, and drop the heat to low; drag a spatula slowly through the curds every 20 seconds until they are softly set and still glistening.","Kill the heat and scatter the cheddar over the eggs so it melts on residual warmth while you toast the tortillas.","Spoon the eggs down the center of each warm tortilla, fold the sides in, roll from the bottom, and sear the burritos seam-side down for 1 minute to weld them shut."],"tip":"Take the eggs off the heat when they look one minute underdone — carryover cooking is the ghost chef who always finishes the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_pitas', '{"id":"lemon_garlic_salmon_pitas","name":"Lemon-Garlic Salmon Pitas with Yogurt Sauce","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":120},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":15},{"f":"spinach","q":50}],"steps":["Rub the salmon with olive oil, salt, pepper, and the zest of the lemon, and let it sit skin-side down while a skillet heats over medium-high.","Sear the salmon skin-side down for 4 minutes without moving it, until the skin releases easily and the sides turn opaque halfway up the fillet.","Flip and cook 2 to 3 minutes more until the flesh flakes under gentle pressure but still looks blushing at the center, then break it into large chunks.","Grate the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the minced garlic, the lemon''s juice, and a pinch of salt for a two-minute tzatziki.","Warm the pitas, halve them into pockets, and layer in spinach, salmon chunks, and thick spoonfuls of the cucumber-yogurt sauce.","Serve immediately, with napkins standing by, because the good ones always drip."],"tip":"Squeeze that grated cucumber like it owes you money, or your sauce will be a puddle by dinnertime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_fiesta_wraps', '{"id":"black_bean_avocado_fiesta_wraps","name":"Black Bean and Avocado Fiesta Wraps","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"black_beans","q":350},{"f":"avocado","q":1},{"f":"tortillas","q":4},{"f":"lime","q":1},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"spinach","q":50},{"f":"olive_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Warm the olive oil in a skillet over medium heat and cook the diced onion and minced garlic for 3 minutes until fragrant and just golden.","Add the drained black beans with a splash of water and a confident pinch of salt and smoky seasoning, then simmer 5 minutes, mashing about a third of them so the mixture turns thick and spoonable.","Mash the avocado with the lime''s juice and a pinch of salt until creamy with a few proud lumps remaining.","Warm the tortillas until soft and steamy, then spread each with the lime-avocado mash edge to edge.","Spoon the beans down the middle, top with diced tomato and spinach, and roll firmly, tucking the ends so nothing escapes on the first bite."],"tip":"Mashing some beans is not cheating — it is the free glue that separates a wrap from a lap full of beans."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_spiced_chicken_wraps', '{"id":"tandoori_spiced_chicken_wraps","name":"Tandoori-Spiced Yogurt Chicken Wraps","emoji":"🌯","cuisine":"Indian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":40,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"tortillas","q":4},{"f":"onion","q":0.5},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":10}],"steps":["Stir two-thirds of the yogurt with the minced garlic, the juice of half the lemon, salt, and a heavy hand of warm spices — the marinade should be tinted and thick enough to cling.","Cut the chicken into bite-size chunks, coat them completely in the marinade, and let them sit at least 15 minutes while the yogurt quietly tenderizes.","Heat the oil in a skillet over medium-high and cook the chicken in a single layer for 8 to 10 minutes, turning occasionally, until the yogurt coating chars in spots and the pieces feel springy.","Slice the onion paper-thin and toss it with the remaining lemon juice and a pinch of salt for a quick pickle, and slice the cucumber into cool half-moons.","Warm the tortillas until pliable, then load each with charred chicken, pickled onion, cucumber, and dollops of the reserved yogurt before rolling snugly."],"tip":"Those blackened yogurt patches are not mistakes, they are the closest a home skillet gets to a tandoor — chase them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salad_stuffed_pitas', '{"id":"greek_salad_stuffed_pitas","name":"Greek Salad Stuffed Pita Pockets","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"feta","q":120},{"f":"pita","q":2},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.3},{"f":"romaine","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"hummus","q":80}],"steps":["Chop the cucumber and tomatoes into hearty chunks, slice the onion whisper-thin, and shred the romaine into forkable ribbons.","Toss the vegetables with the olive oil, a hard squeeze of lemon, salt, and pepper, and let them sit 5 minutes so the tomatoes release their sweet juices into the dressing.","Crumble in the feta and fold gently, keeping the pieces craggy rather than pulverized.","Toast the pitas until warm and barely golden, halve them into pockets, and swipe hummus thickly along the inside walls.","Pack the salad into the pockets with a spoon, pressing lightly, and pour any bowl juices over the filling like a tiny finishing sauce."],"tip":"Salting the tomatoes five minutes early turns the bottom of your bowl into a vinaigrette you did not have to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_egg_salad_pita_pockets', '{"id":"creamy_egg_salad_pita_pockets","name":"Creamy Lemon Egg Salad Pita Pockets","emoji":"🥚","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"greek_yogurt","q":80},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"romaine","q":0.3},{"f":"pita","q":2}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then plunge them into ice water for 5 minutes so the shells slip off cleanly and the yolks stay sunny, not gray.","Chop the peeled eggs roughly, leaving some yolk pieces large enough to stay creamy islands in the salad.","Fold in the yogurt, finely minced onion, a squeeze of lemon, salt, and enough black pepper that you can see it working.","Warm the pitas briefly so they open without tearing, then halve them into pockets and line each with crisp romaine leaves.","Spoon in the egg salad generously, letting the lettuce act as a crunchy raincoat between bread and filling."],"tip":"The lettuce lining is structural engineering — it keeps the pita crisp long enough to survive a lunchbox."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_style_mozzarella_wraps', '{"id":"caprese_style_mozzarella_wraps","name":"Caprese-Style Mozzarella and Tomato Wraps","emoji":"🍅","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"mozzarella","q":150},{"f":"tomato","q":2},{"f":"spinach","q":60},{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1},{"f":"lemon","q":0.5}],"steps":["Slice the tomatoes thick, salt them well, and let them sit on a plate for 5 minutes so the seasoning draws out their sweetest juice.","Tear the mozzarella into ragged pieces, which grab dressing far better than tidy slices ever will.","Whisk the olive oil with the grated garlic clove, a squeeze of lemon, and cracked pepper into a sharp little dressing.","Warm the tortillas in a dry skillet until soft and faintly blistered, about 20 seconds per side.","Layer spinach, tomatoes, and mozzarella down each tortilla, spoon the dressing over everything, then roll tightly and slice on a sharp diagonal.","Return the wraps to the hot pan for 1 minute per side if you want the cheese warm and the outside crackly."],"tip":"Salt the tomatoes, not the cheese — tomatoes reward seasoning with juice, while mozzarella just gets salty and sulks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_street_tacos', '{"id":"chicken_street_tacos","name":"Charred Chicken Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"tortillas","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"olive_oil","q":15}],"steps":["Slice the chicken breast into thin strips, toss with half the olive oil, the grated garlic, and the juice of one lime, and let it sit for 10 minutes while you prep everything else.","Heat a cast-iron skillet over high heat until it just begins to smoke, then lay the chicken in a single layer and leave it alone for 3 minutes so it develops deep brown, charred edges.","Flip and cook 2 to 3 minutes more until the juices run clear, then transfer to a board and chop into rough, taco-sized bits.","Wipe the skillet, film it with the remaining oil, and toast the tortillas 30 seconds per side until they puff slightly and pick up leopard spots.","Pile the chicken onto the warm tortillas, top with finely diced onion and slices of avocado, and finish with a hard squeeze of the second lime so every bite is bright and smoky."],"tip":"A screaming-hot dry skillet is your al pastor stand-in — if the chicken sizzles politely instead of roaring, the pan was not ready."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crunchy_beef_tacos_classic', '{"id":"crunchy_beef_tacos_classic","name":"Crunchy Weeknight Beef Tacos","emoji":"🥩","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":352},{"f":"tortillas","q":5.3},{"f":"cheddar","q":52.8},{"f":"romaine","q":0.4},{"f":"tomato","q":0.9},{"f":"sour_cream","q":52.8},{"f":"onion","q":0.4},{"f":"olive_oil","q":8.8}],"steps":["Heat the olive oil in a wide skillet over medium-high, add the diced onion, and cook 3 minutes until translucent and fragrant at the edges.","Crumble in the ground beef and press it flat against the pan, letting it sear undisturbed for 2 minutes before breaking it up so you get crispy browned bits, not gray steam-cooked pebbles.","Season aggressively, splash in a few tablespoons of water, and simmer 5 minutes until the liquid reduces to a glossy coating on the meat.","Meanwhile, drape the tortillas directly over the oven rack at 200C for 4 to 5 minutes so they crisp into taco shells that shatter when you bite them.","Load each shell with hot beef, then layer on shredded romaine, diced tomato, grated cheddar, and a cool spoonful of sour cream in strict bottom-to-top order."],"tip":"Cheese goes directly on the hot meat so it melts into glue that holds the whole precarious operation together."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_tacos_lime_crema', '{"id":"shrimp_tacos_lime_crema","name":"Seared Shrimp Tacos with Lime Crema","emoji":"🍤","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"tortillas","q":6},{"f":"greek_yogurt","q":100},{"f":"lime","q":2},{"f":"romaine","q":0.5},{"f":"avocado","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Stir the greek yogurt with the zest and juice of one lime and a pinch of salt, then park the crema in the fridge to thicken while you cook.","Pat the shrimp bone-dry with paper towels, toss with olive oil and grated garlic, and season well — wet shrimp steam, dry shrimp sear.","Get a skillet ripping hot over high heat and cook the shrimp in a single layer, 90 seconds per side, until they curl into loose Cs with pink, blistered edges.","Warm the tortillas in a dry pan for 30 seconds a side until soft and steamy, stacking them under a towel to stay pliable.","Shred the romaine finely and lay it down first as a crunchy bed, then add shrimp, sliced avocado, a drizzle of crema, and a squeeze from the second lime."],"tip":"Shrimp go from succulent to eraser in about 40 seconds, so pull them the moment they curl and trust the carryover heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_avocado_tacos', '{"id":"salmon_avocado_tacos","name":"Blackened Salmon and Avocado Tacos","emoji":"🐟","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"tortillas","q":6},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Rub the salmon fillets with olive oil and a heavy coat of smoky spices, pressing the seasoning on so it forms a crust rather than falling off in the pan.","Sear the salmon skin-side down in a hot skillet over medium-high for 4 minutes, until the skin crackles and releases without a fight.","Flip and cook 2 to 3 minutes more until the flesh flakes at a gentle nudge but still looks glossy in the center, then break it into big, juicy chunks with a fork.","While the salmon rests, mash the avocado with the juice of one lime and a pinch of salt into a rough, chunky smear.","Toast the tortillas over a gas flame or dry pan until spotted, swipe each with avocado mash, top with salmon and thin-sliced onion, and finish with the second lime cut into wedges."],"tip":"The avocado mash is doing crema''s job for free — spread it edge to edge so no bite goes undressed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_tacos_2', '{"id":"crispy_tofu_tacos_2","name":"Crispy Golden Tofu Tacos","emoji":"🌱","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"tortillas","q":6},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"onion","q":0.5}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough, craggy chunks — torn edges crisp far better than neat cubes.","Toss the pieces with a spoonful of the olive oil, grated garlic, and plenty of salt and smoky seasoning until every ragged surface is coated.","Heat the remaining oil in a wide skillet over medium-high and fry the tofu 8 to 10 minutes, turning only when each side is deeply golden and audibly crunchy.","Warm the tortillas in a dry pan for 30 seconds per side until soft and steaming, keeping them wrapped in a clean towel.","Fill the tortillas with crispy tofu, sliced avocado, and slivered onion, then squeeze lime generously over the top so the richness gets a sharp counterpoint."],"tip":"Tearing tofu instead of cubing it is the single cheapest texture upgrade in the plant-based universe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_tacos', '{"id":"smoky_black_bean_tacos","name":"Smoky Mashed Black Bean Tacos","emoji":"🫘","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"black_beans","q":480},{"f":"tortillas","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a skillet over medium and cook half the onion, diced, for 4 minutes until soft and just starting to caramelize at the edges.","Add the minced garlic and cook 30 seconds until fragrant, then tip in the black beans with a splash of water and a big pinch of smoky spice.","Simmer 5 minutes, then mash roughly with the back of a spoon until the mixture is creamy but still studded with whole beans, loosening with water if it tightens up.","Char the tortillas directly over a flame or in a scorching dry pan until they smell toasty and carry black-flecked blisters.","Spread the beans thickly on each tortilla and top with diced tomato, the remaining raw onion, avocado slices, and a bright squeeze of lime."],"tip":"Refried-ish beans thicken as they sit, so keep them a little looser than seems right — they will meet you in the middle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_egg_tacos', '{"id":"breakfast_egg_tacos","name":"Soft-Scrambled Breakfast Tacos","emoji":"🍳","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tortillas","q":6},{"f":"cheddar","q":60},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Dice the tomato and onion and cook them in the olive oil over medium heat for 4 minutes, until the onion softens and the tomato slumps into a loose, jammy salsa.","Whisk the eggs with a pinch of salt until no streaks remain, then pour them into the pan and drop the heat to medium-low.","Push the eggs slowly across the pan with a spatula, letting soft folds form, and pull them off the heat while they still look slightly glossy — they finish cooking on the way to the table.","Fold in the grated cheddar so it melts into molten ribbons through the curds.","Warm the tortillas in a dry skillet for 30 seconds per side, fill with the cheesy eggs, and eat immediately while everything is soft, steamy, and drippy."],"tip":"Eggs cooked to perfection in the pan are overcooked on the plate, so bail out early and let physics finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_taco_salad_bowl', '{"id":"chicken_taco_salad_bowl","name":"Chicken Taco Salad Bowl","emoji":"🥗","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"romaine","q":1},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"cheddar","q":50},{"f":"lime","q":2},{"f":"olive_oil","q":20},{"f":"onion","q":0.5}],"steps":["Season the chicken breasts generously with taco spices and sear in half the olive oil over medium-high heat, 5 to 6 minutes per side, until the crust is mahogany and the thickest part reads 74C.","Rest the chicken on a board for 5 full minutes — cutting early sends the juices onto the board instead of into your salad.","Chop the romaine into bite-sized ribbons and toss it in a big bowl with the remaining olive oil, the juice of one lime, and a pinch of salt until every leaf glistens.","Slice the chicken against the grain and arrange it over the greens with diced tomato, slivered onion, and fanned avocado.","Shower the bowl with grated cheddar and serve with wedges of the second lime for squeezing at the table."],"tip":"Salting the lettuce itself, not just the toppings, is what separates a taco salad from sad lettuce with stuff on it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_rice_skillet', '{"id":"beef_taco_rice_skillet","name":"One-Pan Beef Taco Rice Skillet","emoji":"🍚","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Brown the ground beef in the olive oil over medium-high heat for 5 minutes, breaking it into crumbles and letting the bottom crust before you stir.","Add the diced onion, bell pepper, and garlic and cook 4 minutes more until the vegetables soften and the pan smells sweet and toasty.","Stir in the rice, chopped tomato, black beans, taco spices, and 300 ml of water, scraping up the browned bits stuck to the pan — that is the flavor deposit paying out.","Cover, drop the heat to low, and simmer 18 minutes without peeking, until the rice is tender and has drunk up the liquid.","Kill the heat, scatter the cheddar over the top, and re-cover for 2 minutes so it melts into a bubbling blanket before serving straight from the skillet."],"tip":"Every time you lift the lid to check the rice, it adds two minutes and subtracts one friendship with dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_taco_lettuce_cups', '{"id":"shrimp_taco_lettuce_cups","name":"Garlic Shrimp Taco Lettuce Cups","emoji":"🥬","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":1},{"f":"lime","q":2},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Separate the romaine into whole leaves, rinse, and dry them thoroughly — a wet cup makes a soggy taco, and the sturdy inner leaves make the best boats.","Pat the shrimp dry, toss with half the olive oil, the minced garlic, and a pinch of chili and salt.","Sear the shrimp in a very hot skillet for about 90 seconds per side, until pink, curled, and flecked with golden garlic bits, then hit them with the juice of one lime right in the pan.","Dice the avocado and tomato and toss them gently with the remaining oil and a squeeze of the second lime for a quick chunky salsa.","Spoon shrimp into each romaine cup, top with the avocado salsa, and serve immediately while the leaves still snap."],"tip":"Double up the romaine leaves per cup unless you enjoy garlic-lime shrimp escaping into your lap."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_feta_tacos', '{"id":"sweet_potato_feta_tacos","name":"Roasted Sweet Potato and Feta Tacos","emoji":"🍠","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":450},{"f":"tortillas","q":6},{"f":"feta","q":70},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Heat the oven to 220C and cut the sweet potatoes into 1.5 cm cubes — small enough to caramelize, big enough not to vanish in a tortilla.","Toss the cubes with olive oil, minced garlic, smoky spices, and salt, then spread them on a sheet pan with breathing room between pieces.","Roast 25 minutes, flipping once halfway, until the edges are burnished and sticky and a fork slides in with no resistance.","While they roast, slice the onion paper-thin and soak it in the lime juice with a pinch of salt to make a two-minute quick pickle.","Warm the tortillas in a dry skillet until pliable, pile in the roasted sweet potatoes, crumble the feta over the top, and finish with the tangy pickled onions."],"tip":"A crowded sheet pan steams instead of roasts — give the sweet potatoes personal space and they will reward you with caramel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zesty_tuna_tacos', '{"id":"zesty_tuna_tacos","name":"Zesty Pantry Tuna Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"tortillas","q":6},{"f":"greek_yogurt","q":80},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"romaine","q":0.5}],"steps":["Drain the tuna well and flake it into a bowl, breaking up any dense chunks so the dressing can reach everything.","Fold in the greek yogurt, the zest and juice of one lime, finely diced onion, and a good pinch of chili and salt until the mixture is creamy but not soupy.","Taste and adjust — canned tuna drinks acid, so it probably wants more lime than you think.","Toast the tortillas in a dry skillet over medium-high for 30 seconds per side until warm, spotted, and flexible.","Layer shredded romaine on each tortilla for crunch, mound the tuna salad on top, add avocado slices, and serve with wedges of the second lime."],"tip":"This is the taco you make when the fridge is empty and dinner is in 15 minutes — keep the canned tuna hidden from your future self."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_taco_soup', '{"id":"chicken_taco_soup","name":"Shredded Chicken Taco Soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"broth","q":1000},{"f":"black_beans","q":400},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"lime","q":2},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a soup pot over medium and cook the diced onion and bell pepper for 5 minutes, until soft and starting to catch color at the edges.","Add the minced garlic and a heavy spoonful of taco spices and toast for 60 seconds, until the whole kitchen smells like a taqueria.","Add the chopped tomatoes, black beans, broth, and whole chicken breasts, bring to a boil, then reduce to a gentle simmer for 20 minutes.","Lift out the chicken, shred it with two forks into ragged strands, and return it to the pot for 5 more minutes so it soaks up the smoky broth.","Squeeze in the juice of one lime, taste for salt, and serve steaming with the second lime in wedges — the acid at the end is what makes the flavors snap into focus."],"tip":"Simmer means lazy bubbles, not a rolling boil — boiled chicken breast shreds into packing material instead of soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_enchilada_skillet_2', '{"id":"chicken_enchilada_skillet_2","name":"Skillet Chicken Enchiladas with Charred Tomato Sauce","emoji":"🍗","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"tortillas","q":3},{"f":"cheddar","q":70},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"sour_cream","q":40}],"steps":["Halve the tomatoes and sear them cut-side down in a dry 10-inch skillet over high heat for 4 minutes, until blistered and blackened in spots, then blend them with the garlic and a splash of water into a loose, brick-red sauce.","Wipe out the skillet, heat the olive oil over medium-high, and cook the chicken breast, cut into 2-centimeter chunks, with the sliced onion for 6 to 7 minutes until the edges brown and the onion softens.","Pour in the tomato sauce and simmer for 5 minutes, until it thickens enough to coat the back of a spoon and turns a shade darker.","Tear the tortillas into rough wedges and fold them through the sauce so every piece is slicked and starting to soften, about 2 minutes.","Scatter the cheddar over the top, cover, and let it melt for 3 minutes until glossy and pulling into strands.","Dollop with sour cream straight from the skillet while the cheese is still bubbling at the edges."],"tip":"Tearing the tortillas instead of rolling them is not laziness, it is strategy: more sauce-soaked edges per bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_rice_bake', '{"id":"chicken_burrito_rice_bake","name":"Cheesy Chicken Burrito Rice Bake","emoji":"🧀","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"rice","q":140},{"f":"black_beans","q":120},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"broth","q":350}],"steps":["Heat the oven to 200C and film a medium baking dish with the olive oil, tilting it so the corners are coated.","Stir together the rinsed rice, diced tomatoes, chopped onion, minced garlic, black beans, and hot broth in the dish until the rice is evenly submerged.","Nestle the chicken breast, sliced into thick strips, on top so the pieces sit half-buried in the liquid like rafts.","Cover tightly with foil and bake for 35 minutes, until the rice has drunk up the broth and the chicken registers 74C at its thickest point.","Uncover, shower the cheddar over everything, and bake 8 more minutes until the top is molten with a few bronzed patches.","Rest for 5 minutes before serving so the rice sets from soupy to spoonable."],"tip":"Resist peeking under the foil before 35 minutes; every peek costs you steam, and steam is what cooks the rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_burrito_tortilla_bake', '{"id":"beef_burrito_tortilla_bake","name":"Layered Beef Burrito Bake","emoji":"🌯","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":3},{"f":"black_beans","q":120},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"sour_cream","q":50}],"steps":["Brown the ground beef in a hot skillet for 6 to 8 minutes, pressing it flat and leaving it alone until a deep crust forms before breaking it up with the onion and garlic.","Add the chopped tomatoes and black beans and simmer for 8 minutes, mashing a few tomatoes against the pan until the mixture is thick, jammy, and no longer weeping liquid.","In a small baking dish, layer one tortilla, half the beef mixture, and a third of the cheddar, then repeat, finishing with the last tortilla like a lid.","Spread the sour cream over the top tortilla and cap it with the remaining cheddar so it bakes into a tangy, golden crown.","Bake at 190C for 18 to 20 minutes, until the edges bubble audibly and the top is freckled brown.","Cool for 5 minutes, then cut into wedges like a savory cake."],"tip":"A watery filling makes a slumpy bake, so simmer the beef until a spoon dragged through it leaves a clean trail."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_enchilada_skillet', '{"id":"beef_enchilada_skillet","name":"Weeknight Beef Enchilada Skillet","emoji":"🥘","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":3},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the olive oil in a wide skillet over medium-high and sear the ground beef in one flat layer for 4 minutes until deeply browned underneath, then break it apart.","Add the diced onion, bell pepper, and garlic and cook 4 minutes more, until the pepper slumps and the onion turns translucent at the edges.","Grate the tomatoes directly into the pan on the coarse holes of a box grater, discarding the skins, and simmer 6 minutes until the sauce thickens and stains everything red.","Slice the tortillas into ribbons and stir them in, letting them soften for 2 minutes so they go silky like fresh noodles.","Top with the cheddar, cover, and cut the heat, letting residual warmth melt the cheese into pools for 3 minutes.","Serve straight from the skillet while the edges still sizzle."],"tip":"Grating tomatoes into the pan gives you instant enchilada sauce and leaves the skins behind in your hand, not your dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_enchilada_skillet', '{"id":"sweet_potato_black_bean_enchilada_skillet","name":"Sweet Potato and Black Bean Enchilada Skillet","emoji":"🍠","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":300},{"f":"black_beans","q":240},{"f":"tortillas","q":3},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Cut the sweet potatoes into 1-centimeter cubes and sizzle them in the olive oil over medium heat for 10 minutes, stirring only occasionally so they caramelize at the corners.","Add the chopped onion and garlic and cook 3 minutes until fragrant, then stir in the diced tomatoes and a splash of water, scraping up any stuck browned bits.","Fold in the black beans and simmer 5 minutes, until the sweet potatoes yield to a fork and the sauce clings rather than pools.","Tear in the tortillas and toss for 2 minutes so they soak up the sauce and soften into pliable ribbons.","Kill the heat and finish with fanned avocado slices and a hard squeeze of lime over the whole pan.","Taste one cube of sweet potato before serving; it should be creamy inside with a toasted, candy-like edge."],"tip":"Crowd the pan and your sweet potatoes will steam sadly instead of caramelizing, so give them elbow room."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_burrito_rice_bake', '{"id":"black_bean_burrito_rice_bake","name":"Black Bean Burrito Bake with Crispy Cheddar Top","emoji":"🫘","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"black_beans","q":300},{"f":"rice","q":120},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":80},{"f":"sour_cream","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C and sweat the onion, bell pepper, and garlic in the olive oil in an ovenproof skillet for 5 minutes, until soft and sweet-smelling.","Add the rinsed rice, chopped tomatoes, black beans, and 300 milliliters of water, stir once, and bring to a lively simmer.","Cover the skillet and slide it into the oven for 25 minutes, until the rice is tender and has absorbed the liquid completely.","Uncover, blanket the surface with cheddar, and bake 10 minutes more until the cheese sets into a crackly, amber-edged crust.","Rest 5 minutes, then serve big spoonfuls with cool dollops of sour cream melting into the heat.","Scrape up the browned cheese at the skillet edge; that lacy frico is the cook''s rightful bonus."],"tip":"The person who washes the skillet gets first claim on the crispy cheese edges, so plan your household negotiations accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_enchilada_tortilla_bake', '{"id":"turkey_enchilada_tortilla_bake","name":"Turkey and Spinach Enchilada Bake","emoji":"🦃","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"tortillas","q":3},{"f":"spinach","q":100},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"mozzarella","q":70},{"f":"olive_oil","q":10}],"steps":["Brown the ground turkey in the olive oil over medium-high heat for 6 minutes, letting it sit undisturbed at first so it picks up color instead of just going gray.","Add the onion and garlic and cook 3 minutes, then stir in the chopped tomatoes and simmer 8 minutes until the sauce is thick enough to mound on a spoon.","Fold in the spinach by the handful, letting each addition collapse and darken before adding the next.","Layer torn tortillas and the turkey mixture in a small baking dish, ending with sauce, then scatter the mozzarella over the top.","Bake at 190C for 18 minutes, until the cheese is blistered and the sauce bubbles up around the edges like lava at the rim.","Let it stand 5 minutes so the layers firm up enough to serve in tidy scoops."],"tip":"Turkey is a flavor sponge, so season the meat aggressively at the browning stage, not apologetically at the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_burrito_bowl_skillet', '{"id":"turkey_burrito_bowl_skillet","name":"One-Pan Turkey Burrito Skillet with Rice and Beans","emoji":"🍚","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"rice","q":130},{"f":"black_beans","q":120},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"broth","q":300},{"f":"greek_yogurt","q":60},{"f":"lime","q":1}],"steps":["Brown the ground turkey with the chopped onion and garlic in a deep skillet over medium-high heat for 6 minutes, until no pink remains and the pan bottom is glazed brown.","Stir in the rinsed rice and toast it for 1 minute so the grains turn faintly chalky and smell nutty.","Add the diced tomatoes, black beans, and hot broth, scrape the bottom clean, then cover and simmer on low for 18 minutes without stirring.","Check that the rice is tender and the liquid absorbed; if it still slurps, cover and give it 3 more minutes.","Rest off-heat for 5 minutes, then fluff, squeeze the lime over, and crown each portion with a cold spoonful of Greek yogurt.","The contrast of steaming rice and cool tangy yogurt is the whole point, so do not stir it in prematurely."],"tip":"Stirring simmering rice is how you make risotto by accident; hands off until the timer says so."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_enchilada_skillet', '{"id":"shrimp_enchilada_skillet","name":"Shrimp Enchilada Skillet with Zucchini","emoji":"🦐","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"tortillas","q":3},{"f":"zucchini","q":1},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"mozzarella","q":60},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Heat the olive oil in a wide skillet over high heat and sear the shrimp for 90 seconds per side, just until they curl into loose commas, then lift them out.","In the same pan, soften the onion, garlic, and half-moons of zucchini for 4 minutes, until the zucchini edges turn golden but the centers stay firm.","Add the chopped tomatoes and simmer 6 minutes, crushing them with the spoon until they slump into a rustic, pulpy sauce.","Fold in torn tortillas to soak for 2 minutes, then return the shrimp and any pooled juices to the pan.","Scatter the mozzarella over, cover, and let it melt off the heat for 3 minutes so the shrimp finish gently without toughening.","Finish with lime squeezed over the top; the acid wakes up everything."],"tip":"Shrimp go from succulent to rubber bands in about a minute, so pull them early and let the cheese-melting rest finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_sofritas_burrito_bake', '{"id":"tofu_sofritas_burrito_bake","name":"Crispy Tofu Sofritas Burrito Bake","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":50,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"avocado","q":1}],"steps":["Press the tofu between paper towels for 10 minutes, then crumble it into rough, craggy chunks with your hands rather than cutting neat cubes.","Fry the crumbles in the olive oil over medium-high heat for 8 minutes, undisturbed in stretches, until the edges are golden and crisp like scrambled eggs left to brown.","Add the onion, bell pepper, garlic, and chopped tomatoes and simmer 6 minutes until the vegetables collapse into a chunky, spoon-coating sauce.","Spread the cooked rice and black beans in a baking dish, spoon the sofritas mixture over the top, and bake at 190C for 15 minutes until the surface is sizzling and lightly browned.","Rest for 5 minutes, then fan avocado slices over each portion so they soften slightly in the rising steam.","Serve hot; the crisp tofu edges against the creamy avocado is the bite to chase."],"tip":"Crumbled tofu has more surface area than cubed, and surface area is just a math word for crispiness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_burrito_egg_skillet', '{"id":"breakfast_burrito_egg_skillet","name":"Breakfast Burrito Skillet with Eggs and Beans","emoji":"🍳","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"tortillas","q":2},{"f":"black_beans","q":150},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"cheddar","q":50},{"f":"olive_oil","q":10},{"f":"avocado","q":1}],"steps":["Warm the olive oil in a medium skillet over medium heat and soften the chopped onion for 3 minutes until translucent.","Add the diced tomatoes and black beans and simmer 5 minutes, mashing a few beans to thicken the mixture into a loose, saucy hash.","Slice the tortillas into strips, stir them in, and cook 2 minutes so they half-crisp, half-soften like chilaquiles.","Press four wells into the mixture with the back of a spoon and crack an egg into each one.","Scatter the cheddar around the eggs, cover, and cook 4 to 5 minutes until the whites are set but the yolks still shudder when you nudge the pan.","Top with sliced avocado and serve immediately, yolks intact for maximum drama at the table."],"tip":"The lid is doing the cooking here, so if your yolks keep overcooking, blame your peeking, not your stove."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quinoa_pepper_burrito_skillet', '{"id":"quinoa_pepper_burrito_skillet","name":"Smoky Quinoa and Pepper Burrito Skillet","emoji":"🫑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"black_beans","q":180},{"f":"bell_pepper","q":2},{"f":"zucchini","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Char the bell peppers, cut into wide strips, in the olive oil over high heat for 5 minutes until their skins blister black in spots, then add the onion, zucchini, and garlic for 3 minutes more.","Stir in the rinsed quinoa and chopped tomatoes with 300 milliliters of water and bring to a boil, scraping the charred bits into the liquid.","Cover and simmer on low for 15 minutes, until the quinoa uncurls its little tails and the water is gone.","Fold in the black beans and let them heat through for 3 minutes with the lid back on.","Rest 5 minutes off the heat, then fluff and finish with diced avocado and lime squeezed over everything.","Taste and add another squeeze of lime if it does not make you blink slightly."],"tip":"Those blackened pepper spots are not a mistake, they are the smoky backbone of the whole dish, so let them happen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chilaquiles_style_egg_tortilla_bake', '{"id":"chilaquiles_style_egg_tortilla_bake","name":"Chilaquiles-Style Baked Eggs in Tortilla Tomato Sauce","emoji":"🍅","cuisine":"Mexican","meal":["breakfast","dinner"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":45,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"tomato","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"spinach","q":80},{"f":"cheddar","q":60},{"f":"olive_oil","q":15}],"steps":["Cut the tortillas into triangles, toss with half the olive oil, and bake at 200C for 8 minutes until they crisp into pale-gold chips.","Meanwhile, cook the onion and garlic in the remaining oil for 3 minutes, add the chopped tomatoes, and simmer 10 minutes until the sauce is thick, glossy, and reduced by a third.","Wilt the spinach into the sauce, then fold in the baked chips so they soften at the edges but keep some crunch in the middle.","Transfer everything to a baking dish, make four hollows, and crack an egg into each.","Scatter the cheddar between the eggs and bake at 190C for 10 to 12 minutes, until the whites are opaque but the yolks still glow and wobble.","Serve within minutes, because the chips are on a countdown from crisp to tender and the sweet spot is now."],"tip":"Chilaquiles are a texture race against time, so have the table set before this bake leaves the oven."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_ragu_penne', '{"id":"beef_ragu_penne","name":"Weeknight Beef Ragu with Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"penne","q":150},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a wide skillet over medium-high heat and brown the ground beef hard for 6 to 7 minutes, breaking it into rubble and leaving it alone long enough to develop crusty, deeply browned edges.","Add the diced onion and minced garlic and cook 4 minutes more, scraping the fond off the bottom, until the onion turns translucent and the pan smells sweet.","Pour in the crushed tomatoes with the oregano, salt, and pepper, then lower the heat and let the ragu burble gently for 20 minutes until it thickens enough to hold a spoon-trail.","Meanwhile, boil the penne in well-salted water until just shy of al dente, about 9 minutes, and reserve a cup of the starchy cooking water before draining.","Toss the penne into the ragu with a splash of pasta water and simmer 1 minute so the sauce clings glossily to every tube.","Serve showered with grated parmesan and torn basil leaves."],"tip":"The splash of pasta water is not optional — it is the glue that turns sauce-next-to-pasta into an actual ragu."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cacciatore', '{"id":"chicken_cacciatore","name":"Hunter''s Chicken Cacciatore","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":700},{"f":"crushed_tomatoes","q":500},{"f":"bell_pepper","q":2},{"f":"mushrooms","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"broth","q":200},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Pat the chicken thighs bone-dry, season generously with salt and pepper, and sear them in the olive oil over medium-high heat for 5 minutes per side until the skin side is burnished mahogany; transfer to a plate.","In the same fat, saute the sliced onion, bell peppers, and mushrooms for 8 minutes, until the mushrooms have released their liquid and everything is picking up brown edges.","Stir in the minced garlic and oregano for 30 seconds until fragrant, then pour in the broth and scrape up every dark bit stuck to the pan.","Add the crushed tomatoes, nestle the chicken back in along with any accumulated juices, and simmer partially covered over low heat for 25 minutes until the thighs are fork-tender and the sauce has thickened to a rustic gravy.","Taste for salt, then scatter chopped parsley over the top and serve straight from the pan."],"tip":"Crowded chicken steams instead of sears, so brown in two batches even when your patience files a formal complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_fra_diavolo', '{"id":"shrimp_fra_diavolo","name":"Shrimp Fra Diavolo Spaghetti","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","gluten"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"spaghetti","q":160},{"f":"crushed_tomatoes","q":350},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"chili_powder","q":4},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toss the shrimp with the chili powder and a pinch of salt, then sear them in half the olive oil over high heat for barely 1 minute per side, until pink and curled but not fully cooked; scoop them out.","Lower the heat, add the remaining oil and the sliced garlic, and cook 1 minute until the edges turn pale gold and the kitchen smells dangerous.","Pour in the crushed tomatoes and oregano and simmer briskly for 10 minutes, until the sauce darkens a shade and loses its raw tang.","Meanwhile, boil the spaghetti in salted water until 1 minute shy of al dente and drag it straight into the sauce with tongs, letting some pasta water come along for the ride.","Return the shrimp and finish everything together for 2 minutes, then hit it with a squeeze of lemon and a handful of chopped parsley before serving."],"tip":"Fra diavolo means brother devil, so if your nose is not tingling from the chili, go back and add more."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_parmesan_bake', '{"id":"eggplant_parmesan_bake","name":"Skillet-to-Oven Eggplant Parmesan","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":75,"servings":4,"ing":[{"f":"eggplant","q":2},{"f":"flour","q":60},{"f":"eggs","q":2},{"f":"bread","q":2},{"f":"olive_oil","q":60},{"f":"crushed_tomatoes","q":500},{"f":"mozzarella","q":200},{"f":"parmesan","q":40},{"f":"garlic","q":0.3},{"f":"basil","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":6},{"f":"black_pepper","q":1}],"steps":["Slice the eggplants into 1-centimeter rounds, salt them on both sides, and let them weep on a rack for 20 minutes before blotting dry; toast the bread until brittle and blitz or crush it into fine crumbs.","Simmer the crushed tomatoes with the minced garlic and oregano for 10 minutes until slightly thickened, then heat the oven to 200C.","Dredge each eggplant round in flour, dip in beaten egg, press into the breadcrumbs, and shallow-fry in olive oil over medium heat for 3 minutes per side until deeply golden and crisp at the edges.","Layer a baking dish with sauce, eggplant, torn basil, mozzarella, and parmesan, repeating until everything is used and finishing with a snowy cheese layer.","Bake for 25 minutes until the top is blistered and bronzed and the sauce bubbles up the sides, then rest 10 minutes so the layers set instead of sliding."],"tip":"Salting the eggplant is the difference between silky layers and a dish that tastes like a wet sponge with ambitions."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_baked_penne', '{"id":"turkey_baked_penne","name":"Baked Penne with Turkey and Ricotta","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":55,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"penne","q":280},{"f":"crushed_tomatoes","q":600},{"f":"ricotta","q":200},{"f":"mozzarella","q":125},{"f":"parmesan","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190C and set a big pot of salted water to boil for the penne, cooking it 2 full minutes short of the package time so it stays sturdy through the bake.","Brown the ground turkey in olive oil over medium-high heat for 6 minutes, then add the diced onion and garlic and cook until soft and sweet-smelling, about 4 minutes more.","Stir in the crushed tomatoes, oregano, salt, and pepper and simmer 10 minutes until the sauce turns a deep brick red.","Fold the drained penne into the sauce along with dollops of ricotta, leaving visible creamy pockets rather than stirring them smooth.","Scrape into a baking dish, top with mozzarella and parmesan, and bake 20 minutes until the cheese is molten with browned freckles; scatter torn basil over the top before serving."],"tip":"Undercooked pasta going into the oven is correct pasta — it finishes cooking in the sauce instead of turning to mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_pizzaiola', '{"id":"pork_pizzaiola","name":"Pork Pizzaiola","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Slice the pork loin into 4 thin cutlets, pound them gently to even thickness, and season both sides with salt and pepper.","Sear the cutlets in olive oil over high heat for 2 minutes per side until golden at the edges but not cooked through, then move them to a plate.","Soften the sliced onion in the same pan for 3 minutes, add the garlic and oregano for 30 seconds, then pour in the crushed tomatoes and the olives and scrape up the browned bits.","Simmer the sauce 8 minutes until it thickens and turns glossy, then slide the pork back in with its juices and braise gently for 4 minutes, just until the cutlets are cooked through but still juicy.","Spoon the herby red sauce over the top and finish with torn basil."],"tip":"Thin cutlets overcook in the time it takes to find your phone, so pull them the moment they lose their blush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_pomodoro', '{"id":"tuscan_white_bean_pomodoro","name":"Tuscan White Beans in Tomato Sugo","emoji":"🫘","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":4,"ing":[{"f":"white_beans","q":700},{"f":"crushed_tomatoes","q":500},{"f":"kale","q":0.8},{"f":"carrots","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and sweat the diced onion and carrots with a pinch of salt for 8 minutes, until soft and just beginning to color.","Add the sliced garlic and oregano and stir for 1 minute until the oil smells like an Italian grandmother''s kitchen.","Pour in the crushed tomatoes plus a splash of water, bring to a lazy simmer, and cook 10 minutes so the sauce loses its metallic edge and sweetens.","Stir in the white beans and stripped, torn kale and simmer 8 minutes more, mashing a spoonful of beans against the pot wall to thicken the broth to a creamy, stew-like body.","Season boldly with salt and pepper and finish each bowl with a defiant extra drizzle of olive oil."],"tip":"Mashing a few beans is free thickener — no cream, no flour, no regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_puttanesca', '{"id":"spaghetti_puttanesca","name":"Pantry Spaghetti Puttanesca","emoji":"🫒","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":160},{"f":"crushed_tomatoes","q":350},{"f":"olives","q":80},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"chili_powder","q":2},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Set the spaghetti boiling in aggressively salted water while you build the sauce, since this dish moves fast.","Warm the olive oil with the sliced garlic and chili powder in a wide pan over medium heat for 2 minutes, until the garlic turns pale gold and the oil is stained brick red.","Add the roughly chopped olives and oregano, sizzle 1 minute, then pour in the crushed tomatoes and simmer 8 minutes until the sauce is thick, briny, and unapologetic.","Drag the spaghetti from its pot straight into the pan a minute early, add a ladle of pasta water, and toss vigorously over the heat until the strands are lacquered.","Shower with chopped parsley, grind over black pepper, and serve immediately while it still steams."],"tip":"Taste before salting — the olives arrived at this party pre-seasoned and they are not shy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_chicken_parmesan', '{"id":"classic_chicken_parmesan","name":"Crispy Chicken Parmesan","emoji":"🍽️","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"flour","q":40},{"f":"eggs","q":1},{"f":"bread","q":2},{"f":"olive_oil","q":30},{"f":"crushed_tomatoes","q":300},{"f":"mozzarella","q":80},{"f":"parmesan","q":30},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toast the bread until dry and shatter it into fine crumbs, mixing in half the parmesan; halve each chicken breast horizontally and pound to an even 1-centimeter thickness.","Simmer the crushed tomatoes with minced garlic and oregano for 10 minutes while you set up a dredging line of seasoned flour, beaten egg, and the cheesy crumbs.","Coat each cutlet fully — flour, egg, crumbs, pressing firmly — then pan-fry in olive oil over medium-high heat for 3 minutes per side until the crust is deep golden and audibly crisp.","Top each cutlet with a spoonful of sauce, the mozzarella, and remaining parmesan, then slide under a hot broiler for 3 minutes until the cheese bubbles and browns in spots.","Serve on a pool of the remaining sauce with torn basil, cutting in to hear that crunch give way to juicy chicken."],"tip":"Sauce goes on in a modest stripe, not a flood — drowned breading is a crime the Italians prosecute vigorously."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_bolognese_spaghetti', '{"id":"lentil_bolognese_spaghetti","name":"Lentil Bolognese with Spaghetti","emoji":"🌱","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":50,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"spaghetti","q":300},{"f":"crushed_tomatoes","q":500},{"f":"carrots","q":100},{"f":"celery","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Finely dice the onion, carrots, and celery and sweat them in olive oil over medium heat for 10 minutes, until soft, sweet, and lightly golden — this soffritto is the soul of the sauce, so do not rush it.","Stir in the minced garlic and oregano for 1 minute, then add the rinsed lentils, crushed tomatoes, and 700 milliliters of water.","Simmer uncovered over low heat for 30 minutes, stirring occasionally, until the lentils are tender and the sauce has thickened to a proper ragu that mounds on a spoon.","Cook the spaghetti in salted boiling water until al dente, reserving a cup of the starchy water before draining.","Toss the pasta with the lentil bolognese and enough pasta water to make it glossy, season assertively, and top with torn basil."],"tip":"Lentils drink salt like they have been lost in the desert, so season at the end and taste twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_polpette_al_sugo', '{"id":"beef_polpette_al_sugo","name":"Beef Polpette in Sunday Sauce","emoji":"🥩","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"eggs","q":1},{"f":"bread","q":1},{"f":"parmesan","q":25},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Soak the torn bread in a splash of water until soggy, squeeze it out, and knead it gently with the beef, egg, parmesan, half the parsley, a little minced garlic, salt, and pepper — stop the moment it comes together.","Roll the mixture into 8 golf-ball meatballs with damp hands and brown them in olive oil over medium-high heat for about 6 minutes, turning until crusted on most sides but still raw inside.","Push the meatballs aside, soften the diced onion and remaining garlic in the drippings for 3 minutes, then pour in the crushed tomatoes and oregano.","Cover partially and simmer over low heat for 20 minutes, turning the meatballs once, until they are tender all the way through and the sauce has thickened and gone brick red.","Rest 5 minutes off the heat, then serve the polpette blanketed in sauce with the rest of the parsley on top."],"tip":"Overworked meatballs bounce; mix like you are folding laundry you actually care about."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggs_in_purgatory', '{"id":"eggs_in_purgatory","name":"Eggs in Purgatory","emoji":"🍳","cuisine":"Italian","meal":["breakfast","dinner"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"crushed_tomatoes","q":400},{"f":"bread","q":2},{"f":"parmesan","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"chili_powder","q":3},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a skillet over medium heat and soften the diced onion for 4 minutes, then add the sliced garlic, chili powder, and oregano and stir until the oil turns rusty and fragrant.","Pour in the crushed tomatoes with a pinch of salt and simmer 8 minutes, until the sauce thickens enough that a spoon leaves a brief trail.","Make four wells in the sauce with the back of the spoon and crack an egg into each, seasoning the yolks with salt and pepper.","Cover and cook over low heat for 5 to 7 minutes, until the whites are just set but the yolks still shimmy when you shake the pan.","Shower with parmesan and torn basil and serve with thick toasted bread for dragging through the fiery sauce."],"tip":"The pan-shake wobble test beats any timer — set whites, liquid gold yolks, no exceptions."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_basil_risotto', '{"id":"tomato_basil_risotto","name":"Tomato-Basil Risotto","emoji":"🍚","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"crushed_tomatoes","q":300},{"f":"butter","q":25},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"basil","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Keep a kettle of about 1 liter of hot salted water at the ready, and warm the crushed tomatoes in a small pan so nothing cold shocks the rice.","Sweat the finely diced onion in olive oil over medium heat for 4 minutes until translucent, then stir in the garlic and the rice and toast 2 minutes until the grains turn pearly and click against the pan.","Add the warm tomatoes and stir until absorbed, then begin adding hot water one ladle at a time, stirring often and waiting until each addition is nearly drunk up before the next — about 18 to 20 minutes total.","Taste at the 18-minute mark: the rice should be tender with a faint chalky whisper at the center and the whole pot should flow like slow lava.","Off the heat, beat in the butter and parmesan hard for 30 seconds until the risotto turns glossy and creamy, then fold in torn basil and serve immediately in warm bowls."],"tip":"Risotto waits for no one — call everyone to the table before the final stir, not after."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_gnudi_lemon_butter', '{"id":"ricotta_gnudi_lemon_butter","name":"Ricotta Gnudi with Lemon-Basil Butter","emoji":"🥟","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ricotta","q":350},{"f":"parmesan","q":50},{"f":"flour","q":60},{"f":"eggs","q":1},{"f":"butter","q":40},{"f":"spinach","q":100},{"f":"lemon","q":1},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Spread the ricotta on a paper-towel-lined plate for 10 minutes to wick away moisture, because wet ricotta makes gummy gnudi.","Stir the drained ricotta with the egg, grated parmesan, a pinch of salt, and just enough flour to form a soft, barely-holds-itself dough, then roll it into 16 walnut-sized balls with floured hands.","Slide the gnudi into a wide pot of gently simmering salted water and poach for 3 to 4 minutes, scooping them out with a slotted spoon about 30 seconds after they bob to the surface.","Meanwhile, melt the butter in a large skillet over medium heat and let it foam and turn hazelnut-brown and nutty-smelling, about 3 minutes, then wilt in the spinach and torn basil.","Tumble the gnudi into the brown butter, add a squeeze of lemon juice and a little grated zest, and swirl the pan until each dumpling is glossy.","Serve immediately with black pepper and the remaining parmesan showered over the top."],"tip":"If your first test gnudi dissolves in the water, add a spoonful more flour to the dough and forgive yourself."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_asparagus_spaghetti', '{"id":"lemon_ricotta_asparagus_spaghetti","name":"Lemon Ricotta Spaghetti with Asparagus","emoji":"🍝","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"ricotta","q":200},{"f":"parmesan","q":40},{"f":"asparagus","q":250},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Boil the spaghetti in aggressively salted water until just shy of al dente, about 9 minutes, and reserve a full cup of the starchy cooking water before draining.","While the pasta cooks, snap the woody ends off the asparagus, slice the spears on the bias into bite-sized pieces, and sizzle them in olive oil with the sliced garlic over medium-high heat until crisp-tender and lightly blistered, 3 to 4 minutes.","In a large bowl, whisk the ricotta with most of the parmesan, the lemon zest, half the lemon''s juice, and enough hot pasta water to loosen it into a silky, pourable cream.","Add the drained spaghetti and asparagus to the bowl and toss vigorously, adding splashes of pasta water until the sauce clings to every strand like a light satin robe.","Taste for salt and lemon, then plate with the remaining parmesan and a heavy grind of black pepper."],"tip":"The ricotta sauce tightens as it sits, so keep that pasta water within arm''s reach like a fire extinguisher."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_ricotta_polpette_marinara', '{"id":"turkey_ricotta_polpette_marinara","name":"Turkey-Ricotta Polpette in Marinara","emoji":"🧆","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"ricotta","q":80},{"f":"parmesan","q":25},{"f":"eggs","q":1},{"f":"bread","q":1},{"f":"milk","q":40},{"f":"spaghetti","q":120},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"oregano","q":1},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Tear the bread into bits, soak it in the milk for 5 minutes, then mash it to a paste with a fork.","Gently combine the turkey, ricotta, egg, parmesan, bread paste, half the minced garlic, oregano, salt, and pepper, mixing only until it just comes together, then roll into 10 plump meatballs with damp hands.","Brown the polpette in olive oil in a wide skillet over medium-high heat until deeply golden on two sides, about 5 minutes total, then move them to a plate.","Soften the diced onion and remaining garlic in the same skillet, pour in the crushed tomatoes, and simmer for 5 minutes before nestling the meatballs back in to finish cooking gently, covered, for 12 minutes.","Boil the spaghetti in salted water until al dente, drain, and toss it with a few spoonfuls of the sauce so the strands turn rosy.","Pile the polpette and remaining sauce over the pasta and finish with torn basil and a final dusting of parmesan."],"tip":"The ricotta keeps lean turkey from turning into hockey pucks, so resist the urge to overmix the meat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_shrimp_pea_risotto', '{"id":"parmesan_shrimp_pea_risotto","name":"Parmesan Risotto with Shrimp and Peas","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"shrimp","q":250},{"f":"parmesan","q":40},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"broth","q":900},{"f":"peas_frozen","q":100},{"f":"lemon","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the broth in a saucepan and keep it at a bare steam on a back burner; cold broth shocks risotto into stubbornness.","Sweat the finely diced onion in olive oil and half the butter in a heavy pot over medium heat until translucent, about 4 minutes, then stir in the garlic and rice and toast until the grains turn pearly at the edges and smell faintly nutty.","Add the hot broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed before the next, about 20 minutes, until the rice is creamy but still has a whisper of bite at its center.","Stir in the peas and the shrimp for the final 4 minutes, cooking just until the shrimp curl into loose commas and turn opaque pink.","Pull the pot off the heat and beat in the remaining butter, the parmesan, and a squeeze of lemon until the risotto ripples like slow lava when you shake the pot.","Season, then serve immediately in warm shallow bowls with black pepper."],"tip":"Risotto waits for no one — call everyone to the table before you stir in the parmesan, not after."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_ricotta_crespelle', '{"id":"spinach_ricotta_crespelle","name":"Spinach and Ricotta Crespelle","emoji":"🥞","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten","eggs"],"time":50,"servings":2,"ing":[{"f":"flour","q":80},{"f":"eggs","q":2},{"f":"milk","q":200},{"f":"butter","q":15},{"f":"ricotta","q":250},{"f":"spinach","q":200},{"f":"parmesan","q":40},{"f":"mozzarella","q":40},{"f":"crushed_tomatoes","q":200},{"f":"garlic","q":0.2},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Whisk the flour, eggs, milk, and a pinch of salt into a thin, lump-free batter and let it rest for 15 minutes while you make the filling.","Wilt the spinach with the garlic in a knob of the butter over medium heat, squeeze it bone-dry once cool, chop it, and fold it into the ricotta with half the parmesan, salt, and pepper.","Swirl a little butter in a nonstick skillet over medium heat and cook the batter into 6 thin crepes, about 1 minute per side, until freckled gold and floppy.","Heat the oven to 200C, spread a spoonful of crushed tomatoes over a baking dish, then roll each crespella around a generous ribbon of filling and lay them seam-side down in a snug row.","Spoon the remaining tomatoes over the top, scatter with mozzarella and the last of the parmesan, and bake for 15 minutes until the cheese bubbles and the edges crisp.","Rest for 5 minutes before serving so the filling settles from molten to merely luxurious."],"tip":"Your first crepe is legally the cook''s snack, so budget the batter accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_ricotta_frittata', '{"id":"mushroom_ricotta_frittata","name":"Mushroom and Ricotta Frittata","emoji":"🍳","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"ricotta","q":120},{"f":"parmesan","q":30},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"olive_oil","q":15},{"f":"scallions","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven''s broiler and set a rack in the upper third while you sear the sliced mushrooms in olive oil in a 25cm ovenproof skillet over high heat until their water evaporates and they turn deeply browned, about 7 minutes.","Lower the heat to medium, wilt in the spinach and sliced scallions, and season everything with salt and pepper.","Whisk the eggs with the parmesan and pour them over the vegetables, tilting the pan so the egg flows into every gap, then cook undisturbed until the edges set, about 3 minutes.","Dot the surface with spoonfuls of ricotta, pushing them halfway into the custardy top like little snowdrifts.","Slide the skillet under the broiler for 2 to 3 minutes until the frittata puffs proudly and the ricotta caps turn golden at their peaks.","Let it sit for a couple of minutes, then cut into wedges straight from the pan."],"tip":"A frittata that jiggles slightly in the center when it leaves the oven will be perfect by the time you find the plates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_parmesan_chicken_ricotta_penne', '{"id":"creamy_parmesan_chicken_ricotta_penne","name":"Creamy Parmesan Chicken Penne","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":160},{"f":"chicken_breast","q":300},{"f":"ricotta","q":120},{"f":"parmesan","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3},{"f":"spinach","q":100},{"f":"broth","q":120},{"f":"lemon","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Drop the penne into boiling salted water and cook until al dente, about 10 minutes, reserving a cup of pasta water before draining.","While it boils, cut the chicken into bite-sized pieces, season with salt and pepper, and sear in olive oil in a large skillet over medium-high heat until golden at the edges and just cooked through, 6 to 7 minutes.","Add the sliced garlic for the last minute until fragrant, then pour in the broth and scrape up the browned bits stuck to the pan — that fond is free flavor.","Reduce the heat to low and stir in the ricotta and parmesan with a splash of pasta water, whisking until the sauce turns pale, glossy, and smooth.","Fold in the spinach and drained penne, tossing until the leaves collapse and the sauce coats each tube, loosening with more pasta water as needed.","Brighten with a squeeze of lemon and serve with extra parmesan and black pepper."],"tip":"Keep the heat gentle once the ricotta goes in, because a boiled cheese sauce breaks faster than a New Year''s resolution."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_parmesan_zuppa', '{"id":"white_bean_parmesan_zuppa","name":"White Bean and Parmesan Zuppa","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"white_beans","q":600},{"f":"broth","q":1200},{"f":"parmesan","q":60},{"f":"ricotta","q":120},{"f":"olive_oil","q":40},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.3},{"f":"kale","q":0.5},{"f":"crushed_tomatoes","q":200},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Sweat the diced onion, carrots, and celery in half the olive oil in a soup pot over medium heat until soft and sweet-smelling, about 8 minutes, then stir in the minced garlic and oregano for one fragrant minute.","Add the crushed tomatoes, white beans, and broth, bring everything to a lively simmer, and cook uncovered for 15 minutes so the flavors get acquainted.","Ladle out a cup of the soup, mash or blend it smooth, and stir it back in to give the broth a creamy, clinging body without a drop of cream.","Stir in the stripped and torn kale along with most of the grated parmesan and simmer 5 more minutes until the greens are silky but still forest-green.","Season boldly with salt and pepper, then serve each bowl crowned with a fat spoonful of ricotta, a drizzle of the remaining olive oil, and the last of the parmesan."],"tip":"The ricotta dollop melts into the hot soup as you eat, so stir it in slowly and pretend you planned the drama."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_lemon_ricotta_skillet', '{"id":"salmon_lemon_ricotta_skillet","name":"Seared Salmon with Lemon-Ricotta Cream and Green Beans","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":320},{"f":"green_beans","q":300},{"f":"ricotta","q":100},{"f":"parmesan","q":20},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"butter","q":10},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets thoroughly dry, season with salt and pepper, and lay them skin-side down in hot olive oil in a heavy skillet over medium-high heat, pressing gently for 10 seconds so the skin doesn''t buckle.","Cook without moving for 5 to 6 minutes until the skin releases easily and crisps like a cracker, then flip and cook 2 minutes more before resting the fillets on a warm plate.","Add the butter, garlic, and trimmed green beans to the same skillet and saute over medium heat until the beans blister in spots but keep their snap, about 5 minutes.","Whisk the ricotta with the parmesan, lemon zest, half the lemon''s juice, a pinch of salt, and a spoonful of warm water until it loosens into a smooth, pourable cream.","Swoosh the lemon-ricotta cream across two plates, pile on the green beans, and perch the salmon on top, crispy skin skyward.","Shower with chopped parsley and finish with the remaining lemon in wedges."],"tip":"If the salmon resists when you try to flip it, it''s not stuck, it''s just not ready — give it another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_ricotta_involtini', '{"id":"eggplant_ricotta_involtini","name":"Eggplant Involtini with Ricotta","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":55,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"ricotta","q":300},{"f":"parmesan","q":40},{"f":"mozzarella","q":60},{"f":"eggs","q":1},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 220C, slice the eggplant lengthwise into 8 thin planks, brush both sides with olive oil, season with salt, and roast on a sheet pan for 15 minutes until floppy and golden at the edges.","While the eggplant roasts, simmer the crushed tomatoes with the sliced garlic, a glug of olive oil, and a pinch of salt for 10 minutes until slightly thickened and sweet.","Stir the ricotta with the egg, most of the parmesan, torn basil, salt, and plenty of black pepper until fluffy.","Lower the oven to 190C, spread half the tomato sauce in a baking dish, then place a fat spoonful of filling at the wide end of each eggplant plank and roll it up like a sleeping bag, nestling each roll seam-side down in the sauce.","Spoon the remaining sauce over the involtini, top with torn mozzarella and the last parmesan, and bake for 20 minutes until the sauce bubbles at the edges and the cheese turns molten and spotted bronze.","Rest for 5 minutes and serve with more basil scattered over the top."],"tip":"Thin eggplant slices roll; thick ones crack and file complaints, so channel your inner deli slicer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_ricotta_ragu_penne', '{"id":"beef_ricotta_ragu_penne","name":"Beef Ragu Penne with Ricotta","emoji":"🥩","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":140},{"f":"crushed_tomatoes","q":300},{"f":"ricotta","q":80},{"f":"parmesan","q":30},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"carrots","q":60},{"f":"garlic","q":0.2},{"f":"oregano","q":1},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Brown the ground beef in olive oil in a wide skillet over medium-high heat, breaking it into rubble and leaving it alone long enough to develop crusty, caramelized patches, about 6 minutes.","Add the finely diced onion and carrot and cook until softened, 5 minutes, then stir in the minced garlic and oregano until fragrant.","Pour in the crushed tomatoes with a splash of water, season with salt and pepper, and simmer gently for 15 minutes until the ragu thickens enough to hold a trail when you drag a spoon through it.","Meanwhile, boil the penne in salted water until al dente, reserving a half cup of pasta water before draining.","Toss the penne through the ragu with the parmesan and enough pasta water to make everything cling, then divide between bowls.","Crown each serving with spoonfuls of cold ricotta and torn basil, letting the cheese melt lazily into the hot sauce."],"tip":"Cold ricotta on hot ragu is the poor man''s burrata, and honestly nobody at the table will investigate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_parmesan_ricotta_gratin', '{"id":"cauliflower_parmesan_ricotta_gratin","name":"Cauliflower Gratin with Ricotta and Parmesan","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"ricotta","q":200},{"f":"parmesan","q":60},{"f":"milk","q":100},{"f":"eggs","q":1},{"f":"butter","q":15},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and boil the cauliflower florets in well-salted water for 5 minutes until a knife slides in with slight resistance, then drain them thoroughly — soggy florets make a weepy gratin.","Whisk the ricotta with the egg, milk, minced garlic, two-thirds of the parmesan, salt, and a generous grind of black pepper into a loose, creamy custard.","Butter a baking dish, tumble in the cauliflower in a single crowded layer, and pour the ricotta mixture over so it seeps into every crevice.","Dot the surface with the remaining butter and scatter the last of the parmesan evenly over the top.","Bake for 25 minutes until the edges bubble furiously and the top blisters into golden-brown patches that smell like toasted cheese.","Rest 5 minutes, then shower with chopped parsley and serve straight from the dish."],"tip":"The crispy corner pieces are the currency of this dish, so serve yourself first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_parmesan_mushroom_skillet', '{"id":"pork_parmesan_mushroom_skillet","name":"Pork Medallions in Parmesan-Mushroom Cream","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"mushrooms","q":250},{"f":"ricotta","q":100},{"f":"parmesan","q":30},{"f":"butter","q":15},{"f":"olive_oil","q":10},{"f":"broth","q":100},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into medallions about 2cm thick, pat dry, season with salt and pepper, and sear in olive oil in a hot skillet over medium-high heat for 3 minutes per side until burnished gold with a blush of pink inside, then set aside under foil.","Melt the butter in the same skillet and cook the sliced mushrooms without stirring for 3 minutes, then toss and cook 4 minutes more until browned and squeaking against the spoon.","Add the minced garlic for 30 seconds, then pour in the broth and scrape up every browned bit as it steams and reduces by half.","Lower the heat and whisk in the ricotta and parmesan until the sauce turns pale, creamy, and just thick enough to coat the mushrooms.","Return the medallions and their resting juices to the pan and warm them gently in the sauce for 2 minutes without letting it boil.","Scatter with chopped parsley and serve hot from the skillet."],"tip":"Those juices pooling under the resting pork are the sauce''s missing ingredient, not a mess to wipe up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moussaka_style_beef_eggplant_bake', '{"id":"moussaka_style_beef_eggplant_bake","name":"Weeknight Moussaka Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy","eggs"],"time":75,"servings":2,"ing":[{"f":"ground_beef","q":280},{"f":"eggplant","q":1},{"f":"potatoes","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":250},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":120},{"f":"eggs","q":1},{"f":"parmesan","q":25},{"f":"oregano","q":2},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 425°F, slice the eggplant and potatoes into 1/2-inch rounds, and roast them on an oiled sheet pan for 20 minutes until golden at the edges and tender in the middle.","Meanwhile, brown the ground beef with the diced onion in a skillet over medium-high heat until deeply crusty, about 8 minutes, then stir in the garlic, oregano, cinnamon, salt, and pepper until fragrant.","Pour in the crushed tomatoes and simmer 10 minutes until the sauce thickens enough that a spoon dragged through it leaves a clear trail.","Layer the potatoes, then the meat sauce, then the eggplant in a small baking dish, pressing each layer down gently.","Whisk the yogurt with the egg and most of the parmesan, spread it over the top, and bake at 400°F for 20 minutes until the topping is puffed and bronzed in spots.","Rest 10 minutes before cutting so the layers set instead of sliding apart on the plate."],"tip":"The 10-minute rest is not optional unless you enjoy eating moussaka soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fakes_greek_lentil_soup', '{"id":"fakes_greek_lentil_soup","name":"Fakes (Greek Lentil Soup)","emoji":"🥣","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":200},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":20},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Warm half the olive oil in a soup pot over medium heat and sweat the diced onion, carrots, and celery for 6 to 8 minutes until soft and sweet-smelling.","Stir in the sliced garlic and oregano and cook 1 minute until the kitchen smells like a Greek grandmother''s apartment.","Add the rinsed lentils, crushed tomatoes, and about 1.2 liters of water, bring to a boil, then drop to a lazy simmer.","Cook uncovered for 30 to 35 minutes, stirring occasionally, until the lentils are creamy-tender and the broth has thickened to a spoon-coating body.","Season with salt and pepper, then finish off the heat with the remaining olive oil and the vinegar, stirring until the surface turns glossy.","Taste and add another splash of vinegar if it needs brightness; ladle into bowls while steaming."],"tip":"The vinegar at the end is the whole personality of this soup — do not skip it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fasolada_white_bean_soup', '{"id":"fasolada_white_bean_soup","name":"Fasolada White Bean Soup","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"white_beans","q":800},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":60},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat half the olive oil in a heavy pot over medium and cook the chopped onion, carrots, and celery for 8 minutes until the edges turn translucent and lightly golden.","Add the minced garlic and oregano, stir for 30 seconds, then pour in the crushed tomatoes and let them sizzle and darken for 3 minutes.","Tip in the beans with about 800 ml of water, season with salt and pepper, and simmer gently for 20 minutes so the flavors marry.","Mash a ladleful of beans against the side of the pot and stir it back in until the broth turns silky and slightly creamy.","Off the heat, stir in the remaining olive oil, a big squeeze of lemon, and the chopped parsley, tasting until it snaps into balance.","Serve hot with extra lemon wedges on the side for the acid-obsessed."],"tip":"This is the national dish of Greece, so resist the urge to add anything fancy — the olive oil does the talking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_pita_wraps_2', '{"id":"pork_souvlaki_pita_wraps_2","name":"Pork Souvlaki Pitas with Tzatziki","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Cube the pork into 1-inch pieces and toss with the olive oil, half the lemon juice, oregano, one minced garlic clove, salt, and pepper; let it sit 15 minutes while you make the sauce.","Grate the cucumber, squeeze it hard in your fist until it stops dripping, and stir it into the yogurt with the remaining garlic and a squeeze of lemon for a quick tzatziki.","Thread the pork onto skewers or scatter it straight into a screaming-hot skillet and cook 3 to 4 minutes per side until charred at the corners and just cooked through.","Warm the pitas in the empty pan for 30 seconds a side until soft and blistered.","Pile each pita with tzatziki, pork, sliced tomato, and thin half-moons of onion, then roll it up tight and eat over a plate — the drips are part of the experience."],"tip":"Squeeze that cucumber like it owes you money, or your tzatziki becomes tza-tsunami."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_kapama_cinnamon_braise', '{"id":"chicken_kapama_cinnamon_braise","name":"Chicken Kapama over Spaghetti","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":55,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"spaghetti","q":140},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cinnamon","q":2},{"f":"oregano","q":2},{"f":"olive_oil","q":20},{"f":"parmesan","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Season the chicken thighs with salt and pepper and sear them in the olive oil over medium-high heat for 4 minutes per side until deeply golden; set them aside.","In the same pot, soften the diced onion in the chicken drippings for 5 minutes, then add the garlic, cinnamon, and oregano and toast until the spices bloom and smell warm and sweet.","Pour in the crushed tomatoes with a splash of water, scrape up the browned bits, and nestle the chicken back in.","Cover and braise at a gentle bubble for 25 minutes until the chicken is fork-tender and the sauce has turned brick-red and thick.","Boil the spaghetti in well-salted water until just shy of al dente, then finish it for a minute in the kapama sauce so every strand gets stained red.","Plate the pasta, top with chicken, and shower generously with grated parmesan."],"tip":"Cinnamon in tomato sauce sounds like a dare, but it''s the secret handshake of Greek home cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_tomato_feta_rice', '{"id":"shrimp_tomato_feta_rice","name":"Shrimp with Tomato, Feta and Rice","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":150},{"f":"crushed_tomatoes","q":300},{"f":"feta","q":80},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"broth","q":350},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"black_pepper","q":2}],"steps":["Soften the diced onion in olive oil in a wide skillet over medium heat for 5 minutes, then add the garlic and oregano and cook until fragrant.","Stir in the rice to coat every grain in oil, pour in the crushed tomatoes and broth, and simmer covered for 15 minutes until the rice is nearly tender and the liquid mostly absorbed.","Season the shrimp with black pepper and tuck them into the rice in a single layer, pushing them halfway down into the sauce.","Crumble the feta over everything, cover, and cook 4 to 5 minutes more until the shrimp curl into loose commas and turn opaque pink.","Kill the heat, squeeze the lemon over the pan, and scatter with chopped parsley before bringing the whole skillet to the table."],"tip":"Shrimp go from perfect to pencil erasers in about 90 seconds, so hover accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('strapatsada_tomato_feta_eggs', '{"id":"strapatsada_tomato_feta_eggs","name":"Strapatsada (Greek Tomato Eggs)","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","high-protein"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":4},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"pita","q":2},{"f":"garlic","q":0.2},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Grate the tomatoes on the coarse side of a box grater, discarding the skins, so you end up with a bowl of fresh pulp.","Warm the olive oil with the sliced garlic in a nonstick skillet over medium heat until it just sizzles, then pour in the tomato pulp with the oregano and a pinch of salt.","Simmer 8 to 10 minutes, stirring now and then, until the tomato reduces to a thick jammy sauce and the oil pools at the edges.","Beat the eggs, pour them into the pan, and fold slowly with a spatula in big lazy strokes until they set into soft, glossy curds — pull them off the heat while they still look slightly underdone.","Crumble the feta over the top, grind on black pepper, and serve straight from the pan with warm pita for scooping."],"tip":"The eggs finish cooking on the walk to the table, so bail out early or accept rubber."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gemista_rice_stuffed_peppers', '{"id":"gemista_rice_stuffed_peppers","name":"Gemista (Rice-Stuffed Peppers)","emoji":"🫑","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":140},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"potatoes","q":200},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 375°F, slice the tops off the peppers, and pull out the seeds and ribs, saving the tops as little lids.","Grate the tomatoes into a bowl and stir in the rice, finely diced onion, minced garlic, chopped parsley, oregano, salt, pepper, and two-thirds of the olive oil.","Spoon the filling into the peppers only three-quarters full — the rice swells as it cooks — and cap them with their tops.","Stand the peppers in a baking dish, tuck potato wedges into the gaps, drizzle everything with the remaining oil, and pour a half cup of water into the bottom of the dish.","Cover with foil and bake 40 minutes, then uncover and bake 15 more until the peppers slump and blister and the rice is tender all the way through.","Let them rest 10 minutes; gemista is famously better warm than hot, and better still tomorrow."],"tip":"Underfill the peppers or the rice will stage a jailbreak all over your oven floor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('briam_roasted_summer_vegetables', '{"id":"briam_roasted_summer_vegetables","name":"Briam (Greek Roasted Vegetables)","emoji":"🥔","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"potatoes","q":350},{"f":"zucchini","q":2},{"f":"eggplant","q":1},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":60},{"f":"oregano","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and slice the potatoes, zucchini, and eggplant into 1/4-inch rounds and the onion into thin half-moons.","Grate two of the tomatoes into a large bowl, add all the vegetables, sliced garlic, oregano, salt, pepper, and the olive oil, and toss until every slice glistens.","Layer everything into a wide baking dish, shingling the rounds loosely, and top with the last tomato cut into thin slices.","Roast uncovered for 50 to 60 minutes, stirring once halfway, until the potatoes are tender to a knife tip and the top layer is caramelized and crinkled at the edges.","Rest 10 minutes, shower with chopped parsley, and serve warm with the pan juices spooned over each plate."],"tip":"That amount of olive oil is not a typo — briam is a vegetable delivery vehicle for olive oil, and Greece is correct."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('horiatiki_village_salad_plate', '{"id":"horiatiki_village_salad_plate","name":"Horiatiki Village Salad with Toasted Pita","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tomato","q":4},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"olives","q":80},{"f":"feta","q":150},{"f":"olive_oil","q":45},{"f":"pita","q":2},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Cut the tomatoes into fat irregular wedges, the cucumber into thick half-moons, and the bell pepper into rings; slice the onion paper-thin.","Pile everything into a wide bowl with the olives, season with salt, and toss gently just once or twice — this salad hates being fussed over.","Lay the feta over the top in two big slabs rather than crumbling it, the way every taverna in the Cyclades does.","Drizzle generously with the olive oil, dust with oregano, and grind over black pepper.","Toast the pitas in a dry skillet until spotted and warm, cut into wedges, and use them to chase the salty, tomato-stained oil at the bottom of the bowl."],"tip":"No lettuce ever, and no vinegar needed — ripe tomatoes bring their own acid to the party."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keftedes_yogurt_dip', '{"id":"turkey_keftedes_yogurt_dip","name":"Turkey Keftedes with Lemon Yogurt","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"eggs","q":1},{"f":"oats","q":30},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":200},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Grate the onion straight into a bowl with the turkey, then add the minced garlic, chopped parsley, oregano, egg, oats, salt, and pepper.","Knead the mixture briefly with damp hands and let it rest 10 minutes so the oats drink up the moisture and the meatballs hold together.","Roll into golf-ball-sized keftedes and flatten each slightly into a plump patty.","Pan-fry in the olive oil over medium heat for 3 to 4 minutes per side until mahogany-crusted and cooked to 165°F in the center.","While they sizzle, stir the yogurt with grated squeezed cucumber, a pinch of salt, and half the lemon''s juice for a bright dipping sauce.","Serve the keftedes hot with the yogurt sauce and the remaining lemon in wedges for squeezing."],"tip":"Grated onion instead of chopped means juicy meatballs and zero crunchy onion surprises."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_plaki_tomato_bake', '{"id":"salmon_plaki_tomato_bake","name":"Salmon Plaki with Potatoes","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":55,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"potatoes","q":300},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and slice the potatoes into thin rounds, the onion into half-moons, and the tomatoes into slices.","Toss the potatoes and onion with two-thirds of the olive oil, salt, and pepper, spread them in a baking dish, and roast 25 minutes until the edges start to color.","Season the salmon with salt, pepper, and oregano, lay it over the potatoes, and shingle the tomato and lemon slices on top with the sliced garlic scattered between.","Drizzle with the remaining oil and bake 12 to 15 minutes until the salmon flakes at the thick end but still looks glossy inside.","Scatter with chopped parsley and spoon the lemony, tomato-slicked pan juices over everything before serving."],"tip":"Pull the salmon when it flakes reluctantly, not eagerly — carryover heat handles the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('yiaourti_me_meli_breakfast_bowls', '{"id":"yiaourti_me_meli_breakfast_bowls","name":"Yogurt with Honey, Walnuts and Berries","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"greek_yogurt","q":450},{"f":"honey","q":50},{"f":"walnuts","q":50},{"f":"oats","q":40},{"f":"berries","q":200},{"f":"cinnamon","q":1}],"steps":["Toast the oats and roughly chopped walnuts in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until they smell nutty and turn a shade darker.","Divide the cold yogurt between two bowls and smooth the tops with the back of a spoon like frosting.","Scatter the berries over the yogurt, then rain down the warm toasted oats and walnuts so they crackle against the cold.","Drizzle the honey over each bowl in slow ribbons and finish with a whisper of cinnamon.","Eat immediately, while the contrast between warm crunch and cool cream is at its peak."],"tip":"Warm honey pours in elegant ribbons; cold honey pours in one embarrassing glob — 10 seconds in warm water fixes it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_paprika_chicken_rice_skillet', '{"id":"spanish_paprika_chicken_rice_skillet","name":"Spanish Paprika Chicken & Rice Skillet","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"rice","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"crushed_tomatoes","q":100},{"f":"peas_frozen","q":100},{"f":"broth","q":500},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":1},{"f":"lemon","q":1}],"steps":["Season the chicken thighs with salt, pepper, and half the paprika, then sear them in olive oil in a wide skillet over medium-high heat for 4 minutes per side until deeply golden; set them aside on a plate.","Lower the heat to medium and soften the diced onion and bell pepper in the same pan for 5 minutes, scraping up the browned bits, then stir in the minced garlic, remaining paprika, and turmeric until fragrant, about 30 seconds.","Add the crushed tomatoes and cook 2 minutes until they darken and thicken, then stir in the rice so every grain is slicked and stained brick-red.","Pour in the broth, nestle the chicken back on top, and simmer uncovered without stirring for 18 to 20 minutes, until the rice is tender and the liquid has vanished into it.","Scatter the peas over the surface for the last 3 minutes, then pull the pan off the heat, cover, and rest 5 minutes so a light crust forms on the bottom.","Squeeze lemon wedges over everything at the table and serve straight from the skillet."],"tip":"Resist the urge to stir once the broth goes in — the crusty bottom layer is the prize, not a mistake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_olive_lemon_tagine_couscous', '{"id":"chicken_olive_lemon_tagine_couscous","name":"Chicken, Olive & Lemon Tagine with Couscous","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":600},{"f":"olive_oil","q":25},{"f":"onion","q":1.5},{"f":"garlic","q":0.4},{"f":"lemon","q":1.5},{"f":"olives","q":100},{"f":"broth","q":350},{"f":"paprika","q":5},{"f":"cumin","q":5},{"f":"turmeric","q":3},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"couscous","q":200},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Toss the chicken thighs with cumin, paprika, turmeric, cinnamon, salt, and pepper, then brown them in olive oil in a Dutch oven over medium-high heat until the spices smell toasty and the edges are burnished, about 3 minutes per side.","Push the chicken aside and slide in the sliced onions, cooking them down for 6 to 8 minutes until silky and golden, then stir in the minced garlic for a final minute.","Pour in the broth, add the zest and juice of one lemon plus the olives, and scrape the bottom of the pot clean before covering and simmering gently for 25 minutes, until the chicken yields easily to a fork.","Meanwhile, pour 250 milliliters of boiling water over the couscous with a pinch of salt, cover for 5 minutes, then rake it fluffy with a fork.","Uncover the pot and simmer 5 more minutes to thicken the sauce to a glossy, spoon-coating consistency, tasting for salt and brightening with the remaining lemon juice.","Mound the couscous on a platter, spoon the chicken, olives, and sauce over the top, and shower generously with chopped parsley."],"tip":"Zest the lemon before you juice it — nobody has ever successfully zested a squeezed-out lemon husk with their dignity intact."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gambas_garlic_paprika_shrimp_tapas', '{"id":"gambas_garlic_paprika_shrimp_tapas","name":"Sizzling Garlic-Paprika Shrimp with Crusty Bread","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"olive_oil","q":45},{"f":"garlic","q":0.6},{"f":"paprika","q":4},{"f":"chili_powder","q":1},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"bread","q":4},{"f":"salt","q":3}],"steps":["Pat the shrimp bone-dry with paper towels and season with salt — wet shrimp steam instead of sizzle, and sizzle is the whole point here.","Warm the olive oil in a heavy skillet over medium-low heat with the thinly sliced garlic, letting it bubble lazily for 2 to 3 minutes until the slices turn pale gold and the kitchen smells like a Sevilla tapas bar.","Stir in the paprika and chili powder, then immediately raise the heat to medium-high and add the shrimp in a single layer, cooking 90 seconds per side until they curl into loose commas and blush pink.","Pull the pan off the heat, squeeze in the lemon juice, and shower with chopped parsley, swirling so the juices and oil emulsify into a rusty, garlicky slick.","Toast the bread until crackling and serve the shrimp straight from the hot pan, with every last drop of oil for dunking."],"tip":"The garlic oil is the dish and the shrimp are the garnish — anyone who skips the bread-dunking has missed the assignment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kefta_meatball_egg_tagine', '{"id":"kefta_meatball_egg_tagine","name":"Moroccan Kefta Meatball Tagine with Poached Eggs","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["eggs","gluten"],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"cumin","q":6},{"f":"paprika","q":6},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"crushed_tomatoes","q":600},{"f":"olive_oil","q":15},{"f":"eggs","q":4},{"f":"pita","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Knead the ground beef with half the grated onion, half the cumin and paprika, the cinnamon, a fistful of chopped parsley, salt, and pepper, then roll it into walnut-sized meatballs with lightly oiled hands.","Brown the meatballs in olive oil in a deep skillet over medium-high heat for about 5 minutes, turning until crusted on all sides but still rare inside, then transfer to a plate.","Soften the remaining onion in the same pan for 4 minutes, add the minced garlic and remaining spices for 30 seconds, then pour in the crushed tomatoes and simmer 10 minutes until the sauce turns deep brick-red and slightly sweet.","Return the meatballs and simmer gently, partially covered, for 10 minutes so they finish cooking and the sauce reduces to a lazy blup-blup thickness.","Crack the eggs into wells in the sauce, cover, and cook 4 to 6 minutes until the whites set but the yolks still shimmy when you shake the pan.","Finish with more parsley and serve blazing hot with warm pita torn into scoops."],"tip":"Set a timer for the eggs — the line between molten yolk and sad rubber ball is about ninety seconds wide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_smoky_lentil_bacon_potage', '{"id":"spanish_smoky_lentil_bacon_potage","name":"Smoky Spanish Lentil & Bacon Potage","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"bacon","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"celery","q":80},{"f":"potatoes","q":300},{"f":"paprika","q":8},{"f":"crushed_tomatoes","q":200},{"f":"broth","q":1000},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Render the chopped bacon in olive oil in a soup pot over medium heat for 5 minutes, until the fat runs and the pieces crisp at the edges, then scoop out half for garnish.","Tumble in the diced onion, carrots, and celery and sweat them in the smoky fat for 6 minutes until softened, then stir in the garlic, paprika, and oregano just until the paprika blooms and stains everything rust-orange — do not let it scorch.","Add the crushed tomatoes, rinsed lentils, cubed potatoes, and broth, bring to a boil, then drop to a lazy simmer and cook partially covered for 30 to 35 minutes, until the lentils are creamy and the potatoes yield to a spoon.","Mash a few potato chunks against the side of the pot to thicken the broth to a velvety, stew-like body, then season boldly with salt and black pepper.","Ladle into bowls, crown with the reserved crispy bacon, and let it sit 5 minutes — this potage, like most Spaniards, refuses to be rushed."],"tip":"It tastes even better the next day, so make it tonight and take credit for tomorrow''s lunch twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_seven_vegetable_chickpea_tagine', '{"id":"moroccan_seven_vegetable_chickpea_tagine","name":"Moroccan Vegetable & Chickpea Tagine over Couscous","emoji":"🥕","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":4,"ing":[{"f":"chickpeas","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"carrots","q":250},{"f":"zucchini","q":1},{"f":"sweet_potatoes","q":350},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":30},{"f":"cumin","q":6},{"f":"paprika","q":6},{"f":"cinnamon","q":2},{"f":"turmeric","q":2},{"f":"cilantro","q":0.5},{"f":"couscous","q":250},{"f":"salt","q":5}],"steps":["Sweat the sliced onion in olive oil in a wide pot over medium heat for 5 minutes until translucent, then stir in the garlic, cumin, paprika, cinnamon, and turmeric and toast 45 seconds until the spices smell warm and bakery-sweet.","Add the crushed tomatoes, chunked carrots, and cubed sweet potatoes with 400 milliliters of water and a good pinch of salt, cover, and simmer 15 minutes until the roots are halfway tender.","Slide in the thick zucchini half-moons and the chickpeas and simmer uncovered 12 to 15 minutes more, until every vegetable is tender and the sauce has reduced to a glossy, spiced gravy.","While the pot burbles, pour 300 milliliters of boiling water over the couscous with a pinch of salt and a drizzle of olive oil, cover 5 minutes, then fluff with a fork into a fine golden heap.","Taste the tagine and adjust the salt — sweet potatoes drink seasoning greedily — then ladle it over the couscous and finish with a flurry of chopped cilantro."],"tip":"Cut the vegetables chunky and confident; a tagine full of timid little dice cooks to mush before the flavors get acquainted."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('espinacas_spinach_chickpea_saute', '{"id":"espinacas_spinach_chickpea_saute","name":"Andalusian Spinach & Chickpeas with Fried Bread","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"spinach","q":200},{"f":"olive_oil","q":30},{"f":"garlic","q":0.4},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"bread","q":2},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Tear the bread into rough chunks and fry it in half the olive oil over medium heat with the sliced garlic until both are deeply golden and crunchy, about 4 minutes, then transfer to a mortar or small food processor.","Pound or pulse the fried bread and garlic with the cumin, paprika, and a splash of water into a coarse, rust-colored paste — this is the old Moorish trick that thickens the whole dish.","Wilt the spinach in the remaining oil in the same skillet over medium-high heat, handfuls at a time, until it collapses and its water evaporates, about 3 minutes.","Stir in the chickpeas and the bread paste with another splash of water and simmer 5 minutes, until everything binds into a creamy, spoonable tangle that smells of smoke and cumin.","Season with salt and black pepper, hit it with a squeeze of lemon, and serve hot in shallow bowls with a final thread of olive oil."],"tip":"The bread paste looks like a strange move until you taste it — trust six centuries of Sevillian bartenders over your instincts."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potato_onion_tortilla', '{"id":"spanish_potato_onion_tortilla","name":"Classic Spanish Potato & Onion Tortilla","emoji":"🥔","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"potatoes","q":450},{"f":"onion","q":1},{"f":"olive_oil","q":50},{"f":"salt","q":4},{"f":"tomato","q":1}],"steps":["Slice the potatoes into thin coins and the onion into half-moons, then poach them gently in the olive oil in a 20-centimeter nonstick skillet over medium-low heat for 15 to 18 minutes — they should soften and turn sweet without ever browning.","Drain the potatoes and onions in a colander set over a bowl, reserving the fragrant oil, and let them cool for a few minutes so they don''t scramble the eggs on contact.","Whisk the eggs with a generous pinch of salt, fold in the warm potatoes, and let the mixture rest 5 minutes so the eggs seep into every layer.","Heat a tablespoon of the reserved oil in the skillet over medium heat, pour in the mixture, and cook 4 to 5 minutes, shaking occasionally, until the edges set but the center still wobbles like a custard.","Clap a plate over the pan, flip with conviction, slide the tortilla back in raw-side down, and cook 2 to 3 minutes more — the middle should stay just barely juicy.","Rest 5 minutes, then cut into wedges and serve warm or room temperature with sliced tomato."],"tip":"The flip is 90 percent confidence and 10 percent physics; hesitate mid-air and you will be renaming the dish ''Spanish scramble''."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('paprika_salmon_almond_romesco', '{"id":"paprika_salmon_almond_romesco","name":"Paprika-Seared Salmon with Almond Romesco","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["fish","nuts"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"roasted_red_peppers","q":150},{"f":"almonds","q":30},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"balsamic_vinegar","q":10},{"f":"paprika","q":3},{"f":"green_beans","q":250},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toast the almonds in a dry skillet over medium heat for 3 minutes, shaking until they smell nutty and take on golden freckles, then tip them into a blender.","Add the roasted red peppers, garlic, balsamic vinegar, a third of the olive oil, half the paprika, and a pinch of salt, and blitz into a coarse, brick-orange romesco with a little pleasing grit left in it.","Pat the salmon dry, season with the remaining paprika, salt, and pepper, and sear skin-side down in olive oil over medium-high heat for 4 minutes without touching it, until the skin crackles and releases on its own.","Flip and cook 2 to 3 minutes more, until the flesh flakes at the thickest point but still glistens rosy in the center.","Meanwhile, blister the green beans in the hot pan alongside or after the fish for 4 minutes, until spotty-charred but still squeaky-crisp.","Spoon a generous swoosh of romesco onto each plate and perch the salmon and beans on top."],"tip":"Make a double batch of romesco — it improves everything it touches and disappears from the fridge with suspicious speed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_carrot_olive_couscous_salad', '{"id":"moroccan_carrot_olive_couscous_salad","name":"Moroccan Couscous Salad with Carrots, Olives & Feta","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"olives","q":60},{"f":"cherry_tomatoes","q":150},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"cumin","q":3},{"f":"paprika","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":3}],"steps":["Pour 180 milliliters of boiling water over the couscous with a pinch of salt, cover the bowl tightly, and walk away for 5 minutes before fluffing it into light, separate grains with a fork.","Whisk the lemon juice with the olive oil, cumin, paprika, and salt into a dressing that tastes a touch too punchy on its own — the couscous will mellow it.","Halve the cherry tomatoes, dice the cucumber, and grate the carrots coarsely, then fold them through the warm couscous so the grains drink up their juices.","Add the halved olives and most of the dressing, tossing until every grain glistens amber, then taste and add the rest if it needs more brightness.","Crumble the feta over the top in craggy chunks, scatter with a storm of chopped parsley, and serve at room temperature, when the flavors are loudest."],"tip":"Dress the couscous while it is still warm — cold couscous accepts a dressing the way a cat accepts a bath."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pinchos_morunos_pork_skewers', '{"id":"pinchos_morunos_pork_skewers","name":"Pinchos Morunos: Cumin-Paprika Pork Skewers","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"paprika","q":5},{"f":"cumin","q":5},{"f":"oregano","q":2},{"f":"lemon","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"cucumber","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Cut the pork loin into 3-centimeter cubes and massage them with olive oil, minced garlic, paprika, cumin, oregano, salt, pepper, and the juice of half the lemon; let the meat marinate at least 15 minutes while you prep the rest.","Thread the pork onto skewers alternating with chunks of bell pepper and onion, packing them snugly so the meat stays juicy.","Get a grill pan or heavy skillet screaming hot over high heat, then cook the skewers 2 to 3 minutes per side, turning a quarter-turn at a time, until the spice crust darkens to mahogany and the pork is just cooked through with a blush of char.","Rest the skewers 5 minutes under loose foil — cutting early lets all those cumin-scented juices escape to the plate instead of your mouth.","Toss the diced tomato and cucumber with a pinch of salt and the remaining lemon juice, and serve the skewers over this cool, crunchy salad with lemon wedges alongside."],"tip":"A screaming-hot pan and dry meat are non-negotiable — a lukewarm skillet turns these tapas-bar legends into gray cafeteria cubes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_loubia_white_bean_stew', '{"id":"moroccan_loubia_white_bean_stew","name":"Loubia: Moroccan Stewed White Beans in Spiced Tomato","emoji":"🫘","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"white_beans","q":700},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"crushed_tomatoes","q":500},{"f":"olive_oil","q":40},{"f":"cumin","q":8},{"f":"paprika","q":8},{"f":"chili_powder","q":2},{"f":"cilantro","q":0.5},{"f":"carrots","q":150},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Sweat the grated onion and finely diced carrots in olive oil in a heavy pot over medium heat for 6 minutes, until the onion melts into the oil and turns pale gold.","Add the minced garlic, cumin, paprika, and chili powder and stir for a full minute, until the oil turns deep red and the spices smell rich rather than raw.","Pour in the crushed tomatoes and 300 milliliters of water, bring to a simmer, and cook 10 minutes so the sauce loses its tinny edge and sweetens.","Tip in the white beans and simmer uncovered for 15 to 20 minutes, mashing a spoonful against the pot wall to thicken the broth until it clings to the beans like a spiced velvet coat.","Season assertively with salt and black pepper, stir in most of the chopped cilantro, and rest the pot 5 minutes off the heat.","Serve in deep bowls with a final swirl of olive oil and the remaining cilantro scattered on top."],"tip":"Loubia is street food that thinks it is a hug — make extra, because it thickens overnight into something you will fight your family for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_tuna_couscous_bowl', '{"id":"moroccan_spiced_tuna_couscous_bowl","name":"Spiced Tuna & Couscous Bowl with Olives and Peppers","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"couscous","q":140},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":100},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"cumin","q":3},{"f":"paprika","q":2},{"f":"parsley","q":0.5},{"f":"scallions","q":0.5},{"f":"salt","q":3}],"steps":["Steep the couscous in 170 milliliters of boiling water with a pinch of salt under a tight lid for 5 minutes, then fluff it with a fork until every grain stands apart.","Whisk the olive oil with the lemon juice, cumin, paprika, and salt into a smoky-bright dressing, and fold half of it through the warm couscous.","Drain the tuna well and break it into big, plush flakes — crumbling it to dust makes the bowl taste like sad desk lunch, and we are better than that.","Slice the roasted red peppers into ribbons, dice the cucumber, halve the olives, and thinly slice the scallions.","Pile the couscous into two bowls, arrange the tuna and vegetables in generous stripes on top, and spoon over the remaining dressing.","Finish with chopped parsley and an extra crack of lemon just before eating."],"tip":"Buy the best oil-packed tuna you can afford — it is the difference between a Marrakech café and a vending machine."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('butter_chicken_simmer', '{"id":"butter_chicken_simmer","name":"Weeknight Butter Chicken","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"greek_yogurt","q":150},{"f":"rice","q":130}],"steps":["Toss bite-size chunks of chicken with half the yogurt, a pinch of salt, and a teaspoon each of garam masala and turmeric, then let it sit while you start the rice in double its volume of salted water.","Melt the butter in a wide skillet over medium heat and cook the diced onion for 6 to 8 minutes until deeply golden at the edges, then stir in the minced garlic for 30 fragrant seconds.","Add the chopped tomatoes with a teaspoon of paprika and simmer 10 minutes, mashing occasionally, until the sauce thickens and the butter pools orange at the edges.","Nestle in the marinated chicken and simmer gently for 10 to 12 minutes until the pieces are opaque all the way through and register 165F.","Pull the pan off the heat, swirl in the remaining yogurt until the sauce turns silky and blush-colored, and taste for salt.","Spoon over the fluffy rice and let everything sit 2 minutes so the sauce clings."],"tip":"Add the yogurt off the heat unless you enjoy sauce with the texture of scrambled regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_tikka_pepper_skillet', '{"id":"chicken_tikka_pepper_skillet","name":"Chicken Tikka Pepper Skillet","emoji":"🍗","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"greek_yogurt","q":100},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Stir the yogurt with minced garlic, a teaspoon of garam masala, half a teaspoon of paprika, and a good pinch of salt, then coat the chicken chunks and marinate 15 minutes at room temperature.","Heat the olive oil in a heavy skillet over medium-high until it shimmers, then lay the chicken in a single layer and leave it alone for 3 minutes to build charred, tikka-style edges.","Flip the pieces, push them to one side, and add the thick-sliced peppers and onion wedges, tossing until they blister and soften but keep a little crunch, about 5 minutes.","Toss everything together and cook 2 to 3 minutes more until the chicken hits 165F and the yogurt crust turns burnished and spotty brown.","Finish with a squeeze of lemon if you have one and a shower of black pepper straight from the pan."],"tip":"Crowd the pan and you will steam your tikka into sadness — give every piece its personal space."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mulligatawny_chicken_soup', '{"id":"mulligatawny_chicken_soup","name":"Mulligatawny Chicken and Lentil Soup","emoji":"🥣","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"lentils_dry","q":150},{"f":"carrots","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":1000},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":15},{"f":"rice","q":80}],"steps":["Warm the olive oil in a soup pot over medium heat and sweat the diced onion, sliced carrots, and garlic with a tablespoon of curry powder for 5 minutes until the kitchen smells like a spice shop.","Pour in the broth, add the rinsed lentils and rice, and bring to a lively simmer, skimming any foam that rises.","Slide in the whole chicken breasts, drop the heat to low, and simmer gently for 18 to 20 minutes until the chicken is just cooked and the lentils have collapsed into creaminess.","Lift out the chicken, shred it with two forks, and return it to the pot along with the coconut milk.","Simmer 5 more minutes until the soup is thick enough to coat a spoon, then season assertively with salt and a crack of black pepper."],"tip":"This soup thickens overnight like it is trying to become a curry — thin tomorrow''s bowl with a splash of water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('goan_shrimp_coconut_curry', '{"id":"goan_shrimp_coconut_curry","name":"Goan-Style Shrimp Coconut Curry","emoji":"🍤","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"olive_oil","q":15},{"f":"rice","q":120}],"steps":["Start the rice simmering in salted water, then heat the oil in a deep skillet over medium and cook the finely chopped onion for 5 to 6 minutes until soft and lightly bronzed.","Stir in the minced garlic, a teaspoon of turmeric, a teaspoon of ground coriander, and a pinch of cayenne, toasting for 30 seconds until the spices darken a shade.","Add the chopped tomatoes and cook 4 minutes until they slump, then pour in the coconut milk and simmer 8 minutes until the sauce reduces slightly and turns a sunset orange.","Season the shrimp with salt, slip them into the sauce, and poach at a bare simmer for 3 to 4 minutes until they curl into loose commas and turn pink.","Brighten with a splash of vinegar or lemon if handy, taste for salt, and ladle generously over the rice."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the C stage and let carryover do the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tawa_shrimp_masala_skillet', '{"id":"tawa_shrimp_masala_skillet","name":"Tawa Shrimp Masala Skillet","emoji":"🌶️","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["shellfish"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25}],"steps":["Pat the shrimp bone-dry and toss with salt, half a teaspoon of turmeric, and a teaspoon of garam masala so the spices form a thin rusty jacket.","Get the olive oil rippling-hot in your widest skillet over high heat, sear the shrimp 90 seconds per side until blistered pink, and set them aside on a plate.","In the same pan, char the sliced onion and peppers for 4 to 5 minutes, letting them catch dark spots before you stir, then add the garlic and chopped tomatoes.","Cook 3 minutes more until the tomatoes break down into a rough, clingy masala that coats the vegetables.","Return the shrimp with any juices, toss for one final minute over the heat, and serve straight from the skillet while everything still sizzles."],"tip":"Wet shrimp steam and sulk; dry shrimp sear and sing, so pat them like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_masala_classic', '{"id":"chana_masala_classic","name":"Chana Masala with Steamed Rice","emoji":"🫘","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"tomato","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"rice","q":130}],"steps":["Set the rice simmering, then heat the oil in a deep skillet over medium and fry the finely diced onion for 8 to 10 minutes until it turns a deep caramel brown — this color is the backbone of the dish, so do not rush it.","Add the minced garlic with a tablespoon of ground cumin and coriander plus half a teaspoon of turmeric, and toast 30 seconds until the oil stains gold.","Tip in the chopped tomatoes and cook 8 minutes, mashing with your spoon, until they melt into a thick paste that pulls away from the pan.","Stir in the drained chickpeas with a splash of water, crushing a handful against the pan wall to thicken the gravy, and simmer 10 minutes uncovered.","Finish with a pinch of garam masala and a squeeze of lemon if available, then pile onto the rice."],"tip":"Mash a few chickpeas on purpose — that is the difference between gravy and chickpeas floating in tomato water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_dal_2', '{"id":"coconut_red_lentil_dal_2","name":"Creamy Coconut Red Lentil Dal","emoji":"🍲","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"coconut_milk","q":250},{"f":"spinach","q":100},{"f":"olive_oil","q":20}],"steps":["Rinse the lentils until the water runs mostly clear, then simmer them in 900 ml of salted water for 15 minutes, skimming foam, until they slump and lose their shape.","Meanwhile, heat the oil in a small skillet over medium and fry the diced onion for 6 minutes until golden, then add the garlic, a teaspoon of cumin, and half a teaspoon of turmeric for 30 seconds.","Add the chopped tomatoes to the skillet and cook 5 minutes until jammy, then scrape this tadka into the pot of lentils.","Pour in the coconut milk and simmer everything together for 8 to 10 minutes until the dal is thick enough to mound softly on a spoon.","Stir in the spinach off the heat until it wilts glossy and green, then season boldly with salt — dal is shy without it."],"tip":"Dal has two settings, underseasoned and glorious, and the only dial between them is salt."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('aloo_gobi_dry_curry', '{"id":"aloo_gobi_dry_curry","name":"Aloo Gobi Dry-Fried Curry","emoji":"🥔","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"cauliflower","q":0.8},{"f":"potatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"olive_oil","q":30}],"steps":["Cut the potatoes into 2 cm cubes and the cauliflower into floret halves so they cook at the same pace, then heat the oil in your largest lidded skillet over medium-high.","Fry the potatoes for 5 minutes until their edges pick up golden crusts, then add the cauliflower, a teaspoon of turmeric, a teaspoon of cumin seeds if you have them, and a solid pinch of salt.","Stir to stain everything yellow, add the diced onion and garlic, then cover and cook 10 to 12 minutes, lifting the lid to toss every few minutes so nothing scorches.","When a knife slides through the potatoes without resistance, add the chopped tomatoes and cook uncovered 5 minutes until they melt into a rough coating rather than a sauce.","Finish with half a teaspoon of garam masala and let the pan sit off heat for 2 minutes so the flavors settle in."],"tip":"Stir aloo gobi with a flip of the wrist, not a spoon-lashing — mushy cauliflower has ended friendships."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('saag_tofu_curry', '{"id":"saag_tofu_curry","name":"Saag Tofu in Spiced Spinach Gravy","emoji":"🥬","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["soy"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"spinach","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":25}],"steps":["Press the tofu between paper towels for 10 minutes, cube it, then pan-fry in half the oil over medium-high for 8 minutes, turning until every face is crisp and deeply golden; set aside.","Wilt the spinach in the same pan with a splash of water for 2 minutes, then blitz it in a blender with the coconut milk into a rough, vividly green puree.","Add the remaining oil to the pan and cook the diced onion for 6 minutes until soft and browning, then stir in the garlic, a teaspoon of garam masala, and half a teaspoon of cumin for 30 seconds.","Pour the spinach puree back in and simmer 5 minutes until it thickens from soup to gravy and turns a shade darker.","Fold in the crisp tofu, simmer 3 minutes so the cubes drink up the sauce, and season with salt to taste."],"tip":"Crisp the tofu like it owes you money — soft tofu vanishes into saag without a trace."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_korma_cashew', '{"id":"vegetable_korma_cashew","name":"Cashew Vegetable Korma","emoji":"🥕","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":50,"servings":2,"ing":[{"f":"carrots","q":3},{"f":"potatoes","q":300},{"f":"cashews","q":50},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"rice","q":120}],"steps":["Soak the cashews in hot water for 15 minutes while the rice cooks, then blend them with the soaking water into a smooth, pourable cream.","Heat the oil in a deep pan over medium and cook the sliced onion for 7 to 8 minutes until pale gold, then add the garlic, a teaspoon of ground coriander, and half a teaspoon each of turmeric and cinnamon.","Add the carrot coins and potato cubes with 250 ml of water, cover, and simmer 15 minutes until a fork slides in easily.","Stir in the cashew cream and simmer gently 5 minutes until the sauce turns ivory and thick enough to nap the vegetables.","Off the heat, whisk in the yogurt one spoonful at a time so it stays silky, season with salt, and serve over the rice."],"tip":"Korma is a low-and-slow diplomat — boil the yogurt and the peace talks collapse into curds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_egg_curry', '{"id":"punjabi_egg_curry","name":"Punjabi-Style Egg Curry","emoji":"🥚","cuisine":"Indian","meal":["dinner","breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":20},{"f":"rice","q":120}],"steps":["Boil the eggs for 9 minutes, plunge them into cold water, peel, and score each one lightly so the gravy can sneak inside; start the rice at the same time.","Heat the oil in a skillet over medium and brown the finely diced onion for 8 minutes until it reaches a deep amber — pale onions make a flat curry.","Add the garlic, a teaspoon of cumin, a teaspoon of garam masala, and a pinch of cayenne, toast 30 seconds, then add the chopped tomatoes and cook 7 to 8 minutes into a thick, rust-colored masala.","Pour in the coconut milk, simmer 5 minutes until the sauce coats the back of a spoon, and season with salt.","Roll the eggs in the gravy, cut them in half so the yolks face up like little suns, and simmer 2 final minutes before spooning over rice."],"tip":"Score the egg whites before saucing — an unslit boiled egg repels curry like a raincoat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_spinach_coconut_curry', '{"id":"sweet_potato_spinach_coconut_curry","name":"Sweet Potato and Spinach Coconut Curry","emoji":"🍠","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"spinach","q":200},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20}],"steps":["Heat the oil in a deep pot over medium and soften the diced onion for 5 to 6 minutes until translucent with golden edges.","Stir in the minced garlic with a tablespoon of curry powder and a pinch of red pepper flakes, toasting 30 seconds until the spices bloom and smell toasty rather than raw.","Add the sweet potatoes in 2 cm cubes, pour in the coconut milk plus 150 ml of water, and simmer covered for 15 to 18 minutes until a fork slides through without a fight.","Mash a few cubes against the pot wall to thicken the sauce into something spoon-coating and orange as a monsoon sunset.","Fold in the spinach by the handful until it collapses glossy and dark, then season with salt and serve steaming."],"tip":"Cube the sweet potatoes evenly or you will be serving a curry of mush and rocks in the same bowl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bengali_salmon_tomato_curry', '{"id":"bengali_salmon_tomato_curry","name":"Bengali-Inspired Salmon Curry","emoji":"🐟","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"coconut_milk","q":150},{"f":"olive_oil","q":15},{"f":"rice","q":110}],"steps":["Rub the salmon chunks with salt and half a teaspoon of turmeric and let them sit while the rice simmers — this quick cure firms the fish and stains it a beautiful gold.","Heat the oil in a wide pan over medium-high and sear the salmon 1 minute per side, just to set the outside, then move it to a plate.","Lower the heat, cook the sliced onion for 5 to 6 minutes until soft and browning, then add the garlic, a teaspoon of cumin, and a pinch of cayenne for 30 seconds.","Add the chopped tomatoes and simmer 6 to 7 minutes until they collapse into a loose gravy, then stir in the coconut milk and season with salt.","Return the salmon and poach at a gentle burble for 4 to 5 minutes until it flakes at the nudge of a spoon, then serve over rice without stirring — the fish is delicate and deserves dignity."],"tip":"Once the salmon goes back in, retire your spoon to shaking-the-pan duty or you will be eating salmon crumble."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_cashew_rice', '{"id":"lemon_cashew_rice","name":"Lemon Cashew Rice","emoji":"🍋","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"rice","q":180},{"f":"cashews","q":50},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"ginger","q":10},{"f":"turmeric","q":3},{"f":"cumin","q":3},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Rinse the rice until the water runs clear, then simmer it covered with 350ml water and half the salt for 15 minutes; let it steam off the heat for 5 more so the grains stay separate.","Meanwhile, heat the olive oil in a wide skillet over medium and fry the cashews for 2 to 3 minutes, stirring constantly, until they turn deep golden and smell toasty.","Add the cumin and minced ginger to the same oil and sizzle for 30 seconds, then stir in the turmeric and peas and cook 2 minutes until the peas are bright green.","Tip in the cooked rice and toss gently with a fork until every grain is stained sunshine yellow and coated in the fragrant oil.","Pull the pan off the heat, squeeze in the lemon juice, season with the remaining salt, and shower with chopped cilantro before serving warm."],"tip":"Add the lemon juice off the heat or its bright zing cooks away into bitterness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_chickpea_masala_rice', '{"id":"tomato_chickpea_masala_rice","name":"Tomato Chickpea Masala Rice","emoji":"🍅","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"chickpeas","q":240},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Heat the olive oil in a deep pot over medium and sizzle the cumin for 30 seconds until it crackles and perfumes the kitchen.","Add the sliced onion with a pinch of salt and cook 6 to 8 minutes until the edges brown, then stir in the minced garlic for 1 minute more.","Add the chopped tomatoes, turmeric, chili powder, and garam masala and cook 5 minutes, mashing occasionally, until the tomatoes collapse into a thick, glossy masala that pulls away from the pot.","Stir in the rinsed rice and chickpeas to coat every grain in the spiced paste, then pour in 375ml water and the remaining salt.","Bring to a boil, cover, and simmer on low for 15 minutes, then rest off the heat 5 minutes before fluffing with a fork and finishing with chopped cilantro."],"tip":"Let the tomatoes fry until the oil pools at the edges; rushing the masala is how bland rice happens."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tempered_curd_rice', '{"id":"ginger_tempered_curd_rice","name":"Ginger-Tempered Curd Rice","emoji":"🍚","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"greek_yogurt","q":300},{"f":"milk","q":100},{"f":"cucumber","q":0.5},{"f":"ginger","q":12},{"f":"olive_oil","q":15},{"f":"cumin","q":3},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Simmer the rice in 400ml water for 18 minutes until slightly overcooked and soft — curd rice should be creamy, not fluffy — then mash it lightly with a spoon.","Let the rice cool until just warm to the touch, about 10 minutes, then fold in the yogurt, milk, and salt until it looks like loose risotto.","Stir in the finely diced cucumber and half the minced ginger for cool crunch against the creamy rice.","Heat the olive oil in a small pan over medium-high, add the cumin and remaining ginger, and fry 45 seconds until the seeds pop and the ginger frizzles golden.","Pour the sizzling tempering over the rice, scatter with cilantro, and serve at room temperature or lightly chilled."],"tip":"Mix the yogurt into warm, not hot, rice unless you enjoy grainy, split curd."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('anda_masala_fried_rice', '{"id":"anda_masala_fried_rice","name":"Anda Masala Fried Rice","emoji":"🍳","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free","gluten-free"],"allergens":["eggs"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"eggs","q":4},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"onion","q":1},{"f":"ginger","q":10},{"f":"olive_oil","q":25},{"f":"garam_masala","q":3},{"f":"turmeric","q":2},{"f":"scallions","q":0.5},{"f":"salt","q":4}],"steps":["Cook the rice in 350ml water for 15 minutes, then spread it on a plate to cool and dry out — slightly stale-feeling rice fries far better than steamy fresh grains.","Heat half the oil in your largest skillet over high, pour in the beaten eggs with a pinch of salt, and scramble 1 minute into large soft curds; scoop them out just before they look done.","Add the remaining oil, then stir-fry the diced onion, carrots, and ginger for 3 to 4 minutes until the onion picks up brown spots at the edges.","Add the peas, turmeric, and garam masala and toss 1 minute until the pan smells warmly spiced, then add the rice and press it flat to sear for 30-second stretches.","Return the eggs, season with the remaining salt, toss everything twice more, and serve topped with sliced scallions."],"tip":"Pull the eggs while they still glisten; they finish cooking when they rejoin the hot rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_omelette', '{"id":"masala_omelette","name":"Masala Omelette","emoji":"🥚","cuisine":"Indian","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"cilantro","q":0.5},{"f":"chili_powder","q":2},{"f":"turmeric","q":1},{"f":"olive_oil","q":25},{"f":"salt","q":3}],"steps":["Whisk the eggs hard for a full minute with the salt, chili powder, and turmeric until pale and slightly frothy — the air is what makes a street-stall omelette puff.","Fold in the finely diced onion, deseeded chopped tomato, and most of the cilantro so every bite carries crunch and spice.","Heat half the oil in a nonstick skillet over medium until it shimmers, then pour in half the egg mixture and swirl to the edges.","Cook 2 to 3 minutes until the underside is lacy and golden brown and the top is barely set, then fold in half and slide onto a plate; repeat with the remaining oil and eggs.","Scatter the last of the cilantro over both omelettes and serve immediately, while the edges are still crisp."],"tip":"Dice the onion truly fine — big chunks weep water and turn your omelette into a sad puddle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('street_style_masala_egg_toast', '{"id":"street_style_masala_egg_toast","name":"Street-Style Masala Egg Toast","emoji":"🍞","cuisine":"Indian","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"bread","q":4},{"f":"cheddar","q":60},{"f":"butter","q":20},{"f":"scallions","q":1},{"f":"chili_powder","q":2},{"f":"black_pepper","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":2}],"steps":["Whisk the eggs with the salt, half the chili powder, and most of the sliced scallions until evenly combined.","Melt half the butter in a wide skillet over medium and toast the bread slices 2 minutes per side until golden; set them aside on plates.","Add the remaining butter, pour in the eggs, and scramble slowly for 2 to 3 minutes, dragging a spatula through as soft, custardy folds form — stop while they still shine.","Pile the eggs onto the toasts, top with grated cheddar, and cover the pan lidded over low heat for 1 minute so the cheese slumps and melts.","Finish with black pepper, the remaining chili powder, cilantro, and the last scallions, and eat while the cheese still stretches."],"tip":"Low and slow on the scramble — brown eggs belong in nobody''s street food memories."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baingan_bharta', '{"id":"baingan_bharta","name":"Baingan Bharta","emoji":"🍆","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"olive_oil","q":45},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"chili_powder","q":2},{"f":"peas_frozen","q":100},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Prick the eggplant all over with a fork, rub with a spoonful of the oil, and roast at 230C for 30 to 35 minutes, turning once, until the skin is blackened and the flesh collapses when pressed.","Let it cool 5 minutes, then peel away the charred skin and roughly mash the smoky flesh with a fork, saving every drop of juice.","Heat the remaining oil in a skillet over medium, crackle the cumin for 30 seconds, then cook the diced onion 7 to 8 minutes until deeply golden before adding the garlic and ginger for 1 minute.","Add the chopped tomatoes, chili powder, and salt and fry 5 minutes until the masala thickens and the oil separates at the edges.","Stir in the mashed eggplant and peas and cook 5 minutes more, stirring often, until everything melds into a rustic, smoky mash; finish with garam masala and a big handful of cilantro."],"tip":"The blacker the eggplant skin, the smokier the bharta — cowardly roasting yields baby food."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('jeera_aloo', '{"id":"jeera_aloo","name":"Jeera Aloo","emoji":"🥔","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"potatoes","q":650},{"f":"olive_oil","q":45},{"f":"cumin","q":6},{"f":"turmeric","q":3},{"f":"chili_powder","q":2},{"f":"ginger","q":8},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.5},{"f":"salt","q":5}],"steps":["Cut the potatoes into 2cm chunks and boil in well-salted water for 8 to 10 minutes until just fork-tender but not falling apart; drain and let them steam dry for 5 minutes.","Heat the oil in your widest skillet over medium-high until it shimmers, then add the cumin and let it crackle and darken for 30 seconds.","Add the minced ginger, turmeric, and chili powder, swirl for 10 seconds, then tumble in the potatoes and toss to coat them golden.","Spread the potatoes in one layer and leave them alone for 3 to 4 minutes at a time, flipping only when the undersides are crusty and browned — about 12 minutes total.","Season with the remaining salt, squeeze the lemon over, and toss with chopped cilantro before serving hot."],"tip":"Fight the urge to stir; potatoes only crisp when you leave them alone long enough to feel neglected."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cabbage_peas_poriyal', '{"id":"cabbage_peas_poriyal","name":"Cabbage and Pea Poriyal","emoji":"🥬","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["nuts"],"time":25,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"peas_frozen","q":150},{"f":"cashews","q":50},{"f":"olive_oil","q":25},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"ginger","q":10},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Shred the cabbage into thin ribbons no wider than your pinky so it cooks fast and stays sweet rather than sulfurous.","Heat the oil in a wok or wide skillet over medium-high, fry the cashews 2 minutes until golden, then add the cumin and minced ginger and sizzle 30 seconds.","Stir in the turmeric, then add the cabbage with the salt and toss vigorously to coat every ribbon yellow.","Stir-fry 5 to 6 minutes until the cabbage wilts and picks up light brown edges but still keeps a gentle crunch, then add the peas and cook 2 minutes more.","Kill the heat, squeeze the lemon over the pan, and finish with cilantro; serve hot as a side or heap it over rice."],"tip":"Stop cooking while the cabbage still squeaks a little — mush is the enemy of a good poriyal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_matar_sabzi', '{"id":"mushroom_matar_sabzi","name":"Mushroom Matar Sabzi","emoji":"🍄","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"peas_frozen","q":200},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"coconut_milk","q":150},{"f":"olive_oil","q":20},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Heat the oil in a wide skillet over high and sear the quartered mushrooms in a single layer for 5 to 6 minutes, tossing only twice, until browned and squeaky-firm; set aside.","Lower to medium, crackle the cumin 30 seconds, then cook the diced onion 6 minutes until golden before adding the garlic and ginger for 1 minute.","Add the chopped tomatoes, turmeric, and salt and fry 5 minutes, mashing as they soften, until the masala turns jammy and the oil beads at the edges.","Return the mushrooms with the peas and coconut milk and simmer 4 to 5 minutes until the sauce clings thickly rather than pooling.","Stir in the garam masala, rest the pan 2 minutes off the heat, and serve strewn with cilantro."],"tip":"Crowded mushrooms steam instead of sear, so give them elbow room even if it means two batches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_gobi_sabzi', '{"id":"tandoori_gobi_sabzi","name":"Tandoori Roasted Gobi with Chickpeas","emoji":"🌶️","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":240},{"f":"greek_yogurt","q":150},{"f":"olive_oil","q":30},{"f":"garam_masala","q":5},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 220C and whisk the yogurt with half the oil, the grated garlic and ginger, garam masala, paprika, turmeric, chili powder, and salt into a thick brick-red marinade.","Cut the cauliflower into large florets, toss them in the marinade until every craggy surface is coated, and let them sit 10 minutes while the oven heats.","Spread the florets on a parchment-lined sheet pan with space between them and roast 20 minutes until the yogurt crust starts to char at the tips.","Toss the chickpeas with the remaining oil, scatter them around the cauliflower, and roast 12 to 15 minutes more until the florets are tender inside their smoky shell and the chickpeas crackle.","Squeeze the lemon over the hot pan and shower with cilantro; serve straight from the tray while the edges are still crisp."],"tip":"Charred yogurt tips are the whole point — if nothing is blackened, your oven is being too polite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('green_bean_carrot_thoran', '{"id":"green_bean_carrot_thoran","name":"Green Bean and Carrot Thoran","emoji":"🥕","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"green_beans","q":300},{"f":"carrots","q":250},{"f":"coconut_milk","q":200},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"cumin","q":4},{"f":"turmeric","q":3},{"f":"black_pepper","q":1},{"f":"salt","q":4}],"steps":["Chop the green beans into 1cm pieces and dice the carrots the same size — thoran is all about small, even cuts that cook quickly and catch the coconut.","Heat the oil in a wide skillet over medium-high and sizzle the cumin for 30 seconds until fragrant and popping.","Add the diced onion and garlic and cook 3 minutes until translucent, then stir in the turmeric, beans, carrots, and salt.","Splash in 60ml water, cover, and steam 5 to 6 minutes until the vegetables are tender-crisp and vividly colored.","Uncover, pour in the coconut milk, and simmer hard for 3 to 4 minutes, stirring, until it reduces to a rich coating rather than a sauce; finish with black pepper and serve."],"tip":"Reduce the coconut milk until it clings — a thoran should be dressed, not drowning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('palak_cottage_cheese_sabzi', '{"id":"palak_cottage_cheese_sabzi","name":"Palak Cottage Cheese Sabzi","emoji":"🌿","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"spinach","q":350},{"f":"cottage_cheese","q":450},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"salt","q":4}],"steps":["Wilt the spinach in a dry pot over high heat for 2 to 3 minutes, stirring, until it collapses to a fraction of its volume, then blitz it to a coarse, flecked puree with a splash of water.","Heat the olive oil with half the butter in a deep skillet over medium, crackle the cumin 30 seconds, then cook the diced onion 6 to 7 minutes until golden brown at the edges.","Add the garlic and ginger for 1 minute, then the chopped tomato and salt, frying 4 minutes until the masala turns soft and jammy.","Pour in the spinach puree and simmer 5 minutes, stirring, until it darkens and thickens enough to hold a spoon trail.","Fold in the cottage cheese and garam masala, warm gently for 2 minutes without boiling so the curds stay creamy, and finish with the remaining butter swirled on top."],"tip":"Keep the heat gentle after the cottage cheese goes in — boiled curds turn squeaky and sulk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kung_pao_style_chicken', '{"id":"kung_pao_style_chicken","name":"Kung Pao-Style Chicken with Cashews","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","nuts","sesame"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"rice","q":120},{"f":"cashews","q":40},{"f":"bell_pepper","q":2},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"soy_sauce","q":45},{"f":"honey","q":20},{"f":"sugar","q":5},{"f":"chili_powder","q":4},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"salt","q":2}],"steps":["Start the rice in a small pot with 300ml of salted water, cover, and simmer on low for 15 minutes while you cook everything else.","Cut the chicken into 2cm cubes, toss with half the soy sauce, and let it sit 10 minutes while you dice the peppers and stir the remaining soy sauce together with the honey, sugar, and chili powder into a glossy sauce.","Heat the olive oil in a wok or large skillet over high heat until it shimmers, then sear the chicken in a single layer for 2 minutes per side until deeply golden at the edges; transfer to a plate.","Toast the cashews, garlic, and grated ginger in the same pan for 60 seconds until fragrant and lightly bronzed, then add the peppers and stir-fry 2 minutes so they blister but stay crisp.","Return the chicken with the sauce and let it bubble hard for 90 seconds until it clings to every piece like lacquer, then kill the heat and stir in the sesame oil and sliced scallions.","Spoon over the rice and serve immediately, while the cashews still crunch."],"tip":"Get every ingredient chopped and sauced before the pan gets hot — a wok waits for no one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_fried_rice_takeout_style', '{"id":"shrimp_fried_rice_takeout_style","name":"Takeout-Style Shrimp Fried Rice","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":150},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"scallions","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":20},{"f":"black_pepper","q":2}],"steps":["Cook the rice in 350ml of water for 15 minutes, then spread it on a tray to cool and dry out — dry grains fry, wet grains steam.","Heat half the olive oil in a wide skillet over high heat and sear the shrimp 90 seconds per side until pink and curled with a hint of char, then set them aside.","Add the remaining oil and scramble the eggs for 30 seconds until just barely set, pushing them to one side of the pan.","Tip in the diced carrots, garlic, and grated ginger and stir-fry 2 minutes until the carrots soften slightly and the garlic smells toasty.","Add the cooled rice and peas, pressing the rice against the hot pan in stages so it crackles and picks up golden spots, about 3 minutes.","Return the shrimp, splash in the soy sauce around the pan''s edge so it sizzles and caramelizes, then finish with sesame oil, black pepper, and sliced scallions."],"tip":"Day-old rice from the fridge is the fried-rice cheat code — cook it in the morning if you''re planning ahead."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_beef_broccoli_stirfry', '{"id":"ginger_beef_broccoli_stirfry","name":"Ginger Beef and Broccoli over Rice","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"broccoli","q":450},{"f":"rice","q":120},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"broth","q":100},{"f":"sesame_oil","q":10},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Set the rice simmering in 300ml of water with the lid on for 15 minutes, then leave it covered off the heat to steam.","Brown the beef in a dry, screaming-hot skillet for 5 to 6 minutes, breaking it into rough crumbles and letting it sit undisturbed between stirs so it develops crusty, caramelized edges.","Push the beef aside and bloom the minced garlic and ginger in the rendered fat for 45 seconds until your kitchen smells like the good takeout place.","Add the broccoli florets and broth, cover, and steam 3 minutes until the broccoli turns vivid green and just tender at the stem.","Uncover, stir in the soy sauce and honey, and boil hard for 2 minutes until the liquid reduces to a glossy coating that clings to the florets.","Finish with sesame oil, black pepper, and scallions, and pile it all over the steamed rice."],"tip":"Resist stirring the beef constantly — the brown crust it forms while you ignore it is where all the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_pork_stirfry', '{"id":"honey_garlic_pork_stirfry","name":"Honey-Garlic Pork Stir-Fry","emoji":"🍯","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"rice","q":140},{"f":"bell_pepper","q":1},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"honey","q":30},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Get the rice going in 350ml of water, covered on low, for 15 minutes while you slice the pork into thin strips against the grain.","Whisk the honey, soy sauce, and minced garlic into a sticky sauce and set it within arm''s reach of the stove.","Heat the olive oil in a large skillet over high heat and sear the pork in two batches, 2 minutes per batch, until the strips are golden and just cooked through; crowd the pan and you''ll boil it instead.","Stir-fry the sliced onion, pepper, and half-moons of zucchini in the same pan for 3 minutes until charred in spots but still snappy.","Return the pork, pour in the sauce, and toss over high heat for 2 minutes until it bubbles down to a lacquered glaze that coats everything.","Turn off the heat, add the sesame oil and a big grind of black pepper, and serve over the rice while the glaze is still glossy."],"tip":"Freeze the pork for 20 minutes before slicing and it cuts into tidy, paper-thin strips like a butcher did it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_corn_egg_drop_soup', '{"id":"chicken_corn_egg_drop_soup","name":"Chicken and Sweet Corn Egg Drop Soup","emoji":"🥣","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"chicken_thigh","q":350},{"f":"corn_frozen","q":300},{"f":"eggs","q":3},{"f":"broth","q":1200},{"f":"rice","q":80},{"f":"ginger","q":15},{"f":"scallions","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"black_pepper","q":3},{"f":"salt","q":3}],"steps":["Bring the broth to a gentle boil with the sliced ginger, then add the chicken thighs whole and simmer 15 minutes until they''re cooked through and the broth tastes rich.","Lift out the chicken, shred it with two forks, and return it to the pot along with the rice; simmer 12 minutes more until the grains are tender and the soup thickens slightly.","Stir in the corn and soy sauce and let everything bubble for 3 minutes until the corn is sweet and hot.","Beat the eggs well, then pour them into the simmering soup in a thin stream while stirring slowly in one direction — they will bloom into silky golden ribbons.","Kill the heat, season with salt and plenty of black pepper, and finish with sesame oil and sliced scallions.","Ladle into deep bowls and serve steaming, when the egg ribbons are at their softest."],"tip":"Stir slowly and pour slower — dump the eggs in fast and you get scrambled soup instead of silk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_lo_mein_takeout_style', '{"id":"chicken_lo_mein_takeout_style","name":"Chicken Lo Mein with Charred Cabbage","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"chicken_thigh","q":300},{"f":"cabbage","q":0.3},{"f":"carrots","q":100},{"f":"mushrooms","q":100},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"soy_sauce","q":50},{"f":"sugar","q":8},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10}],"steps":["Boil the spaghetti 2 minutes shy of the package time, drain, and toss with a third of the sesame oil so the strands stay loose and springy.","Slice the chicken thighs into thin strips and stir the soy sauce and sugar together into a quick lo mein sauce.","Heat the olive oil in your widest skillet over high heat and sear the chicken 4 to 5 minutes until browned at the edges and cooked through, then push it to the side.","Add the shredded cabbage, carrot matchsticks, and sliced mushrooms and stir-fry 3 minutes until the cabbage picks up charred spots but keeps its crunch.","Add the garlic and ginger for 30 fragrant seconds, then tumble in the noodles and sauce and toss with tongs for 2 minutes until every strand is slick and mahogany-brown.","Finish with the remaining sesame oil and scallions and eat straight from the pan if no one is watching."],"tip":"Undercooked pasta is the secret — it finishes in the sauce and gets that chewy takeout-noodle bounce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mapo_style_tofu_skillet', '{"id":"mapo_style_tofu_skillet","name":"Mapo-Style Tofu with Turkey over Rice","emoji":"🌶️","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"ground_turkey","q":200},{"f":"rice","q":140},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"scallions","q":1},{"f":"soy_sauce","q":40},{"f":"chili_powder","q":6},{"f":"sugar","q":5},{"f":"broth","q":200},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rice in 350ml of water, covered, for 15 minutes, and cut the tofu into 2cm cubes while it cooks.","Heat the olive oil in a deep skillet over medium-high and brown the turkey for 4 minutes, pressing it into small crumbles until it sizzles and turns golden.","Add the minced garlic, ginger, and chili powder and fry 60 seconds until the oil turns brick-red and smells warm and spicy.","Pour in the broth, soy sauce, and sugar, slide in the tofu cubes, and simmer gently for 6 to 8 minutes so the tofu drinks up the sauce — stir by shaking the pan, not with a spoon, to keep the cubes whole.","When the sauce has reduced to a loose, spoonable gravy, turn off the heat and drizzle in the sesame oil.","Shower with scallions and ladle generously over the hot rice."],"tip":"Treat the tofu like it''s fragile china — swirl the pan instead of stirring and every cube arrives at the table intact."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_foo_young_mushroom_gravy', '{"id":"egg_foo_young_mushroom_gravy","name":"Egg Foo Young with Mushroom Gravy","emoji":"🍳","cuisine":"Asian","meal":["breakfast","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mushrooms","q":150},{"f":"cabbage","q":0.2},{"f":"carrots","q":50},{"f":"scallions","q":1},{"f":"broth","q":250},{"f":"soy_sauce","q":20},{"f":"flour","q":12},{"f":"sesame_oil","q":5},{"f":"olive_oil","q":20},{"f":"black_pepper","q":2}],"steps":["Make the gravy first: whisk the flour into the cold broth with the soy sauce, then simmer 3 to 4 minutes, whisking, until it thickens enough to coat a spoon; stir in the sesame oil and keep warm.","Sauté half the mushrooms in a dry pan for 3 minutes until browned and add them to the gravy.","Beat the eggs in a big bowl and fold in the remaining sliced mushrooms, finely shredded cabbage, grated carrot, most of the scallions, and a good grind of pepper.","Heat the olive oil in a skillet over medium-high until it ripples, then ladle in half-cup portions of the egg mixture to form thick pancakes.","Fry each patty 2 to 3 minutes per side until puffed, golden brown, and set in the middle — they should jiggle slightly, not slosh.","Stack the patties, drown them in the hot mushroom gravy, and top with the last of the scallions."],"tip":"A slightly overcrowded egg batter is the goal here — you want pancakes that are mostly vegetables held together by sheer eggy willpower."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_egg_roll_bowls', '{"id":"turkey_egg_roll_bowls","name":"Egg Roll in a Bowl with Ground Turkey","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"soy_sauce","q":45},{"f":"sugar","q":8},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your largest skillet over high heat and brown the turkey for 5 to 6 minutes, breaking it up and letting it crisp at the edges before you stir.","Add the minced garlic and ginger and cook 60 seconds until fragrant enough to make the neighbors curious.","Pile in the shredded cabbage and carrot matchsticks — it will look like too much, and it is not — and toss for 4 to 5 minutes until the cabbage wilts to half its volume but keeps a squeak of crunch.","Stir the soy sauce and sugar together, pour it over, and toss for 1 minute more so everything glistens.","Off the heat, add the sesame oil, sliced scallions, and a heavy grind of black pepper.","Serve in deep bowls — all the flavor of an egg roll, none of the deep fryer."],"tip":"Shred the cabbage as thin as you can manage; wide ribbons steam, thin ribbons fry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('teriyaki_style_salmon_rice_bowls', '{"id":"teriyaki_style_salmon_rice_bowls","name":"Honey-Soy Glazed Salmon Rice Bowls","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"rice","q":140},{"f":"broccoli","q":300},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"sesame_oil","q":8},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 350ml of water, covered on low, for 15 minutes while you simmer the soy sauce, honey, grated ginger, and minced garlic in a small pan for 3 to 4 minutes until it reduces to a syrup that coats a spoon.","Pat the salmon dry and cut it into two portions — dry skin is the difference between crisp and sad.","Heat the olive oil in a nonstick skillet over medium-high and lay the salmon in skin-side down, pressing gently for the first 20 seconds so the skin sears flat; cook 4 minutes until the sides turn opaque halfway up.","Flip, add the broccoli florets around the fish with a splash of water, cover, and cook 3 minutes so the broccoli steams bright green while the salmon finishes to a blushing medium.","Brush the glaze thickly over the salmon and let it bubble in the pan for 30 seconds until sticky and lacquered.","Build bowls of rice, broccoli, and glazed salmon, drizzle any remaining sauce over the top, and finish with sesame oil and scallions."],"tip":"The glaze goes on at the very end — honey in a hot pan too early turns from lacquer to charcoal with alarming speed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('singapore_curry_rice_noodles', '{"id":"singapore_curry_rice_noodles","name":"Singapore-Style Curry Rice Noodles","emoji":"🍛","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":160},{"f":"edamame_frozen","q":200},{"f":"bell_pepper","q":1},{"f":"cabbage","q":0.2},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"scallions","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"soy_sauce","q":40},{"f":"sugar","q":6},{"f":"lime","q":1},{"f":"sesame_oil","q":12},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly firm, then drain and snip them once or twice with scissors for easier tossing.","Heat the olive oil in a wok over high heat and stir-fry the sliced onion, pepper strips, shredded cabbage, and carrot matchsticks for 3 minutes until the edges char but the centers stay crisp.","Add the garlic, ginger, curry powder, and turmeric and toast for 45 seconds, stirring constantly, until the spices bloom golden and the whole pan smells like a hawker stall.","Tip in the edamame, noodles, soy sauce, and sugar and toss vigorously with tongs for 2 to 3 minutes until every strand turns sunset-yellow and the edamame is heated through.","Turn off the heat, squeeze the lime over everything, and stir in the sesame oil and scallions.","Taste for balance — it should hit salty, tangy, and warm all at once — and serve piping hot."],"tip":"Toast the curry powder in the oil, not the sauce — 45 seconds of direct heat unlocks flavors that simmering never will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hot_sour_mushroom_tofu_soup', '{"id":"hot_sour_mushroom_tofu_soup","name":"Hot and Sour Mushroom Tofu Soup","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"tofu","q":550},{"f":"mushrooms","q":300},{"f":"broth","q":1200},{"f":"rice","q":200},{"f":"eggs","q":3},{"f":"carrots","q":100},{"f":"balsamic_vinegar","q":30},{"f":"soy_sauce","q":45},{"f":"ginger","q":15},{"f":"black_pepper","q":4},{"f":"sesame_oil","q":20},{"f":"scallions","q":1}],"steps":["Bring the broth to a boil with the sliced ginger, add the rice, and simmer 12 minutes until the grains are nearly tender and the broth has body.","Add the sliced mushrooms and carrot matchsticks and simmer 5 minutes until the mushrooms turn silky and darken the broth.","Cut the tofu into thin batons, slide them in gently, and season with the soy sauce, balsamic vinegar, and an aggressive amount of black pepper — the pepper is the ''hot'' and it should tickle the back of your throat.","Simmer 3 more minutes, then stream in the beaten eggs while stirring slowly in one direction so they set into wispy ribbons.","Off the heat, stir in the sesame oil and taste: add another splash of vinegar if it doesn''t make you pucker just a little.","Serve in deep bowls buried under sliced scallions."],"tip":"Black pepper, not chili, carries this soup — grind in more than feels reasonable and then add one more twist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_garlic_sauce_stirfry', '{"id":"eggplant_garlic_sauce_stirfry","name":"Takeout-Style Eggplant in Garlic Sauce","emoji":"🍆","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"eggplant","q":1.5},{"f":"rice","q":150},{"f":"garlic","q":0.6},{"f":"ginger","q":12},{"f":"scallions","q":1},{"f":"soy_sauce","q":45},{"f":"sugar","q":12},{"f":"balsamic_vinegar","q":15},{"f":"chili_powder","q":3},{"f":"olive_oil","q":30},{"f":"sesame_oil","q":10},{"f":"salt","q":3}],"steps":["Start the rice in 350ml of salted water, covered on low, for 15 minutes while you cut the eggplant into fat 3cm wedges and salt them for 10 minutes to draw out moisture; pat them very dry.","Stir the soy sauce, sugar, balsamic vinegar, chili powder, and 60ml of water into a sweet-savory sauce.","Heat the olive oil in a wide skillet over medium-high until shimmering and fry the eggplant in a single layer, turning every 2 minutes, for 8 to 10 minutes total until deeply browned, collapsed, and custardy inside.","Clear a space in the pan and sizzle the minced garlic and ginger for 45 seconds until golden and heady.","Pour in the sauce and simmer 2 minutes, turning the eggplant gently, until the liquid reduces to a dark, sticky glaze that clings to every wedge.","Finish with sesame oil and scallions and serve over the rice, spooning any stray glaze on top."],"tip":"Salting and drying the eggplant first means it fries instead of drinking the entire bottle of oil — your wedges and your wallet will thank you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_chicken_satay_skillet', '{"id":"peanut_chicken_satay_skillet","name":"Skillet Chicken Satay with Peanut Sauce","emoji":"🍗","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["nuts","gluten","soy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"peanut_butter","q":40},{"f":"coconut_milk","q":120},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"rice","q":110},{"f":"cucumber","q":0.5},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Slice the chicken into long, thumb-width strips and toss them with half the soy sauce, the grated ginger, and one minced garlic clove; let them sit for 10 minutes while the rice simmers in salted water for 15 minutes until tender.","Whisk the peanut butter, coconut milk, remaining soy sauce, honey, remaining garlic, and the juice of half the lime in a small saucepan over low heat until the sauce is glossy and coats a spoon, about 3 minutes.","Heat the olive oil in a large skillet over medium-high heat until it shimmers, then lay the chicken strips in a single layer and cook undisturbed for 3 minutes until deeply golden on the first side.","Flip and cook 2 to 3 minutes more until the strips are firm and cooked through, then pull the pan off the heat.","Pile the rice into bowls, fan the chicken over the top, spoon on the warm peanut sauce, and finish with thin cucumber half-moons, torn cilantro, and the remaining lime cut into wedges."],"tip":"If your peanut sauce seizes into paste, whisk in warm water a spoonful at a time — it forgives faster than a group chat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_chicken_curry', '{"id":"thai_peanut_chicken_curry","name":"Peanut Coconut Chicken Thigh Curry","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":["nuts"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":280},{"f":"coconut_milk","q":150},{"f":"peanut_butter","q":25},{"f":"curry_powder","q":8},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Start the rice in simmering salted water and set a timer for 15 minutes, then cut the chicken thighs into bite-size chunks and season them with salt.","Heat the oil in a deep skillet over medium-high heat and brown the chicken hard for 4 minutes per side until the edges caramelize, then push it aside and soften the sliced onion and bell pepper for 3 minutes.","Stir in the minced garlic, grated ginger, and curry powder and toast for 30 seconds until the pan smells like a spice market.","Pour in the coconut milk, whisk in the peanut butter, and simmer gently for 8 to 10 minutes until the sauce thickens enough to leave a trail behind a spoon and the chicken is cooked through.","Squeeze in half the lime, taste for salt, and serve over the rice with cilantro leaves and lime wedges."],"tip":"Brown the thighs like you mean it — pale chicken makes a curry that tastes apologetic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_noodle_soup', '{"id":"coconut_lime_shrimp_noodle_soup","name":"Coconut-Lime Shrimp Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","gluten-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":400},{"f":"broth","q":750},{"f":"rice_noodles","q":150},{"f":"mushrooms","q":200},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Warm the oil in a soup pot over medium heat and sizzle the sliced ginger and smashed garlic for 1 minute until fragrant but not browned.","Add the sliced mushrooms and cook for 4 minutes until they release their liquid and start to squeak against the spoon, then pour in the broth and coconut milk and bring to a bare simmer.","Season with salt and let the broth steep for 10 minutes at a gentle bubble so the ginger perfumes every drop; do not boil hard or the coconut milk will look curdled.","Slide in the shrimp and simmer 2 to 3 minutes, just until they curl into loose commas and turn opaque pink.","Meanwhile soak the rice noodles in boiling water for 5 minutes until pliable, drain, and divide among four bowls, then ladle the soup over and finish with lime juice, sliced scallions, and a generous handful of cilantro."],"tip":"Add the lime juice off the heat — boiled lime goes bitter and sulky, like anyone forced to work in a hot kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_peanut_stirfry', '{"id":"crispy_tofu_peanut_stirfry","name":"Crispy Tofu Stir-Fry with Peanut-Maple Glaze","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":300},{"f":"carrots","q":100},{"f":"peanut_butter","q":40},{"f":"soy_sauce","q":25},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"rice","q":110},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes, then tear it into rough chunks — ragged edges crisp better than neat cubes — while the rice cooks in salted water for 15 minutes.","Whisk the peanut butter, soy sauce, maple syrup, sesame oil, and the juice of half the lime with 3 tablespoons of warm water until pourable and smooth.","Heat the olive oil in a wide skillet over medium-high heat and fry the tofu without moving it for 4 minutes per side until the crust is deep golden and crackles when nudged; transfer to a plate.","Add the broccoli florets and sliced carrots with a splash of water, cover for 3 minutes to steam them bright green, then uncover and stir-fry with the minced garlic and ginger for 2 minutes more.","Return the tofu, pour in the peanut glaze, and toss for 1 minute until everything is lacquered, then serve over rice with sliced scallions and the remaining lime."],"tip":"Torn tofu shrugs off sogginess; cubed tofu files a complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_peanut_rice_noodle_salad', '{"id":"shrimp_peanut_rice_noodle_salad","name":"Chilled Peanut Shrimp Rice Noodle Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","nuts","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":130},{"f":"shrimp","q":300},{"f":"peanut_butter","q":35},{"f":"soy_sauce","q":20},{"f":"lime","q":2},{"f":"sugar","q":8},{"f":"garlic","q":0.2},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"cashews","q":30},{"f":"cilantro","q":0.5},{"f":"scallions","q":1},{"f":"sesame_oil","q":10}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until tender but still springy, then rinse under cold water until fully chilled and drain well.","Whisk the peanut butter, soy sauce, sugar, minced garlic, sesame oil, and the juice of both limes with 2 tablespoons of warm water into a dressing the texture of heavy cream.","Sear the shrimp in a hot dry nonstick skillet for 90 seconds per side until they blush pink with a few char spots, then slide them onto the noodles to cool slightly.","Toss the noodles and shrimp with the dressing, thin cucumber ribbons, coarsely grated carrot, and most of the cilantro until every strand is coated.","Mound onto plates and shower with chopped cashews, sliced scallions, and the last of the cilantro just before serving."],"tip":"Rinse those noodles cold and mean it — lukewarm noodle salad is just soup that gave up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_pork_noodles', '{"id":"thai_peanut_pork_noodles","name":"Peanut Pork and Cabbage Rice Noodles","emoji":"🍝","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["nuts","gluten","soy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice_noodles","q":130},{"f":"peanut_butter","q":30},{"f":"coconut_milk","q":100},{"f":"soy_sauce","q":25},{"f":"cabbage","q":0.3},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Slice the pork loin into thin strips across the grain and toss with a spoonful of the soy sauce; soak the rice noodles in boiling water for 6 minutes until just tender, then drain.","Stir the peanut butter, coconut milk, remaining soy sauce, and the juice of half the lime into a smooth sauce and set it within arm''s reach of the stove.","Get the oil ripping hot in your largest skillet over high heat and sear the pork in a single layer for 2 minutes per side until browned at the edges; transfer to a plate.","Throw the shredded cabbage, minced garlic, and grated ginger into the same pan and stir-fry for 3 minutes until the cabbage wilts but keeps a little crunch.","Return the pork with the noodles and sauce and toss over the heat for 1 to 2 minutes until everything is slick and steaming, then top with scallions and the remaining lime in wedges."],"tip":"Slice the pork while it''s still fridge-cold — floppy room-temperature loin cuts like a rumor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_salmon_curry', '{"id":"coconut_lime_salmon_curry","name":"Coconut-Lime Salmon Curry with Spinach","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"coconut_milk","q":200},{"f":"curry_powder","q":6},{"f":"turmeric","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"spinach","q":100},{"f":"rice","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Simmer the rice in salted water for 15 minutes while you cut the salmon into large 5-centimeter chunks and season them with salt.","Soften the diced onion in the oil over medium heat for 4 minutes until translucent, then add the garlic, ginger, curry powder, and turmeric and stir for 30 seconds until the spices bloom and darken slightly.","Pour in the coconut milk with a splash of water, bring to a gentle simmer, and let it thicken for 5 minutes until it coats the back of a spoon.","Nestle the salmon chunks into the sauce, cover, and poach at the barest bubble for 5 to 6 minutes until the fish flakes at a fork''s suggestion — resist the urge to stir or it will shred.","Fold in the spinach until it collapses, brighten with lime juice, and spoon over rice with a scatter of cilantro."],"tip":"Poach the salmon like it owes you nothing — a violent boil turns silky fish into coconut-flavored erasers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_turkey_lettuce_wraps', '{"id":"peanut_turkey_lettuce_wraps","name":"Peanut-Ginger Turkey Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["nuts","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"peanut_butter","q":30},{"f":"soy_sauce","q":20},{"f":"sugar","q":8},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"carrots","q":80},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"sesame_oil","q":8},{"f":"olive_oil","q":10}],"steps":["Whisk the peanut butter, soy sauce, sugar, sesame oil, and the juice of half the lime with a tablespoon of warm water into a spoonable sauce.","Heat the olive oil in a large skillet over medium-high heat and brown the ground turkey for 6 to 7 minutes, breaking it into small crumbles and letting it sit long enough between stirs to pick up golden crusty bits.","Add the grated ginger and minced garlic and cook 1 minute until fragrant, then pour in the peanut sauce and toss until the turkey glistens and the pan sizzles quietly.","Stir in the grated carrot and most of the scallions off the heat so they stay crisp.","Separate the romaine into sturdy cup-shaped leaves, spoon in the warm filling, and finish with the remaining scallions and lime wedges for squeezing at the table."],"tip":"Use the romaine''s inner leaves as cups and shred the floppy outer ones into the filling — no leaf left behind."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_sweet_potato_chickpea_curry', '{"id":"peanut_sweet_potato_chickpea_curry","name":"Peanut Sweet Potato and Chickpea Curry","emoji":"🍠","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"sweet_potatoes","q":600},{"f":"chickpeas","q":350},{"f":"coconut_milk","q":300},{"f":"peanut_butter","q":45},{"f":"crushed_tomatoes","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":10},{"f":"spinach","q":100},{"f":"rice","q":180},{"f":"lime","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Sweat the diced onion in the oil in a Dutch oven over medium heat for 5 minutes until soft and sweet, then stir in the garlic, ginger, and curry powder and toast for 45 seconds until the bottom of the pot looks rusty and smells intense.","Add the sweet potatoes in 3-centimeter chunks, the crushed tomatoes, coconut milk, and 250 ml of water, season with salt, and bring to a simmer.","Cover and cook for 15 minutes, then whisk the peanut butter into a ladleful of the hot liquid and stir it back in along with the chickpeas.","Simmer uncovered for 8 to 10 minutes more until the sweet potato yields to a fork and the sauce has thickened to a lazy blip-blip bubble.","Fold in the spinach until just wilted, wake the whole pot up with lime juice, and serve over rice cooked in salted water for 15 minutes."],"tip":"Temper the peanut butter in a ladleful of the hot sauce first — dropped in cold, it clings to the spoon like a toddler at daycare drop-off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_coconut_chicken_rice_soup', '{"id":"thai_coconut_chicken_rice_soup","name":"Gingery Coconut Chicken and Rice Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":400},{"f":"rice","q":120},{"f":"coconut_milk","q":300},{"f":"broth","q":1000},{"f":"ginger","q":20},{"f":"garlic","q":0.4},{"f":"carrots","q":150},{"f":"mushrooms","q":150},{"f":"lime","q":2},{"f":"cilantro","q":0.5},{"f":"scallions","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Warm the oil in a soup pot over medium heat and cook the sliced ginger, minced garlic, and sliced carrots for 3 minutes until the kitchen smells sharp and warm.","Pour in the broth and rice, bring to a boil, then drop to a simmer and lay the whole chicken breasts into the liquid.","Poach gently for 15 minutes until the chicken registers firm and the rice grains have swollen and softened, then lift the chicken onto a cutting board and shred it with two forks.","Stir the sliced mushrooms and coconut milk into the pot and simmer 5 minutes more until the broth turns ivory and the mushrooms are tender.","Return the shredded chicken, season with salt and the juice of one lime, and ladle into bowls topped with cilantro, scallions, and extra lime wedges."],"tip":"Shred the chicken while it''s warm — cold chicken fights the fork, and you have soup to eat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_fried_rice', '{"id":"thai_peanut_fried_rice","name":"Peanut and Cashew Fried Rice with Eggs","emoji":"🍳","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","nuts","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"eggs","q":3},{"f":"peanut_butter","q":25},{"f":"soy_sauce","q":25},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"cashews","q":30},{"f":"scallions","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Cook the rice in salted water for 15 minutes, then spread it on a plate to steam dry for 10 minutes — dry, cooled grains fry into distinct nuggets instead of paste.","Whisk the peanut butter with the soy sauce, sesame oil, and 2 tablespoons of warm water into a thin, pourable sauce.","Heat half the olive oil in your widest skillet over high heat, scramble the eggs into soft, glossy curds in about 45 seconds, and scoop them out just shy of set.","Add the remaining oil with the diced carrots, garlic, and ginger and stir-fry for 2 minutes, then add the rice and press it flat, letting it sizzle untouched for 90 seconds to pick up toasty spots.","Toss in the peas, peanut sauce, eggs, and cashews and fry for 2 minutes more until everything is hot and coated, then finish with scallions and lime wedges."],"tip":"Yesterday''s cold rice is this dish''s dream candidate — freshly cooked rice needs that plate-drying intermission or it clumps like wet snow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_beef_green_bean_stirfry', '{"id":"peanut_beef_green_bean_stirfry","name":"Peanut-Basil Beef and Green Bean Stir-Fry","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["nuts","gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"green_beans","q":300},{"f":"peanut_butter","q":30},{"f":"coconut_milk","q":100},{"f":"soy_sauce","q":20},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"basil","q":0.5},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Stir the peanut butter, coconut milk, soy sauce, and the juice of half the lime into a smooth sauce and keep it by the stove.","Heat the oil in a large skillet over high heat and add the trimmed green beans in a single layer, letting them blister and char in spots for 4 to 5 minutes with only occasional tossing, then move them to a plate.","Brown the ground beef in the same screaming-hot pan for 5 minutes, breaking it into rough crumbles and pouring off excess fat once it''s deeply seared.","Add the minced garlic and grated ginger and cook 1 minute, then return the beans, pour in the peanut sauce, and toss until it bubbles and clings, about 2 minutes.","Kill the heat, tear in the basil leaves so they wilt in the residual steam, and serve with the remaining lime in wedges."],"tip":"Blistered beans need a hot, crowded-free pan — give them elbow room or they steam into sadness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_banana_rice_porridge', '{"id":"coconut_banana_rice_porridge","name":"Coconut Rice Porridge with Banana and Peanut Butter","emoji":"🍌","cuisine":"Asian","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"rice","q":100},{"f":"coconut_milk","q":250},{"f":"banana","q":2},{"f":"peanut_butter","q":30},{"f":"maple_syrup","q":20},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Combine the rice, coconut milk, 300 ml of water, and the salt in a small saucepan and bring to a boil, then drop to the lowest simmer.","Cook uncovered for 20 to 25 minutes, stirring every few minutes and scraping the bottom, until the grains burst open and the porridge turns thick and creamy enough to hold a spoon trail for a second.","Mash one banana and stir it in with the maple syrup and cinnamon, letting it melt into the porridge for a final 2 minutes of gentle heat.","Ladle into bowls and top with the second banana in coins and a generous swirl of peanut butter loosened with a teaspoon of warm water.","Rest the bowls for 2 minutes before eating — the porridge thickens as it cools and the peanut butter swirl goes pleasantly fudgy."],"tip":"The spottier the banana, the sweeter the porridge — save the pristine yellow ones for people who like disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_honey_chicken_donburi', '{"id":"soy_honey_chicken_donburi","name":"Soy-Honey Glazed Chicken Donburi","emoji":"🍱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"rice","q":160},{"f":"soy_sauce","q":45},{"f":"honey","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with 400ml water for 15 minutes and let it rest off the heat while you cook.","Slice the cucumber into thin coins, toss with the sugar, half the salt, and the sesame oil, and let it sit until the slices go floppy and glassy, about 15 minutes.","Pat the chicken thighs bone-dry, season with the remaining salt, and sear them skin-side down in olive oil over medium-high heat until deeply bronzed, 6 to 7 minutes per side.","Stir the soy sauce, honey, grated ginger, and minced garlic together, pour it over the chicken, and let it bubble and reduce for 2 to 3 minutes until it coats the meat like lacquer.","Slice the chicken against the grain, fan it over bowls of rice, spoon on every drop of glaze, and finish with the pickled cucumber and a flurry of sliced scallions."],"tip":"The glaze goes from lacquer to charcoal in about 30 seconds, so stand guard with your spatula."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('glazed_salmon_pickle_bowl', '{"id":"glazed_salmon_pickle_bowl","name":"Honey-Soy Salmon Bowl with Quick Pickles","emoji":"🍣","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"rice","q":160},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.1},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Start the rice first: rinse 160g well, simmer covered with 400ml water for 15 minutes, then rest it off the heat with the lid on.","Shave the cucumber into ribbons with a peeler, massage with sugar and salt, and set aside until it weeps and turns translucent, about 10 minutes.","Whisk the soy sauce, honey, grated ginger, and minced garlic into a glaze, then brush half of it over the salmon fillets.","Sear the salmon skin-side down in sesame oil over medium heat for 4 minutes until the skin crackles, flip, pour in the remaining glaze, and baste for 2 more minutes until the fish flakes at a nudge but stays blush-pink inside.","Pile the rice into bowls, break the salmon over the top in big glossy shards, drain and add the cucumber ribbons, and shower with sliced scallions."],"tip":"If the salmon skin sticks to the pan, it just needs 30 more seconds — it releases itself when it''s properly crisp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_maple_soy_bowl', '{"id":"crispy_tofu_maple_soy_bowl","name":"Crispy Tofu Bowl with Maple-Soy Glaze","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":160},{"f":"broccoli","q":300},{"f":"soy_sauce","q":45},{"f":"maple_syrup","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"scallions","q":0.5}],"steps":["Press the tofu between paper towels under a heavy skillet for 15 minutes while the rinsed rice simmers, covered, in 400ml water for 15 minutes.","Slice the cucumber thin, toss with sugar and salt, and let it soften into crunchy-tart pickles while everything else cooks.","Tear the pressed tofu into ragged bite-size chunks — the craggy edges crisp better than neat cubes — and pan-fry in olive oil over medium-high heat, undisturbed for 3 minutes per side, until deeply golden.","Push the tofu aside, add the broccoli florets with a splash of water, and steam-sear for 3 minutes until the stems turn vivid green but still snap.","Pour in the soy sauce, maple syrup, grated ginger, and minced garlic, and toss for 90 seconds until the glaze bubbles thick and clings to every craggy edge.","Serve over rice with the drained pickles, a drizzle of sesame oil, and sliced scallions on top."],"tip":"Torn tofu has three times the surface area of cubed tofu, and surface area is where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_shrimp_rice_bowl', '{"id":"sesame_shrimp_rice_bowl","name":"Sesame Shrimp Rice Bowl","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"rice","q":160},{"f":"peas_frozen","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":15},{"f":"scallions","q":0.5}],"steps":["Get the rinsed rice simmering, covered, with 400ml water for 15 minutes, then leave it to steam off the heat.","Slice the cucumber into half-moons, scrunch with sugar and salt, and set aside to pickle — it should taste bright and sweet-salty by serving time.","Pat the shrimp very dry and sear them in sesame oil over high heat for 90 seconds per side, just until they curl into loose commas and blush pink.","Add the minced garlic and grated ginger for 30 fragrant seconds, then pour in the soy sauce and honey and let it reduce to a syrup that coats the shrimp, about 1 minute.","Stir the frozen peas straight into the hot pan to warm through, then spoon everything over the rice and top with pickles and scallions."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C that still has somewhere to be."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_rice_bowl', '{"id":"ginger_pork_rice_bowl","name":"Ginger-Soy Pork Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"rice","q":160},{"f":"onion","q":1},{"f":"cabbage","q":0.3},{"f":"ginger","q":20},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"black_pepper","q":1}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes, and shred the cabbage into fine, feathery threads for a cool raw nest on the side.","Freeze the pork loin for 10 minutes, then slice it into whisper-thin sheets — the thinner the slice, the more glaze each piece carries.","Whisk the soy sauce, honey, and a full 20 grams of grated ginger into a punchy, throat-warming sauce.","Sear the pork and thinly sliced onion in olive oil over high heat for 3 to 4 minutes until the edges catch and caramelize, then add the minced garlic for 30 seconds.","Pour in the sauce and toss for 2 minutes until it bubbles down to a glossy coat and the onions turn amber and slumped.","Mound the rice into bowls, lean the shredded cabbage against one side, pile on the pork, and grind black pepper over everything."],"tip":"Ten minutes in the freezer turns pork loin from wobbly to sliceable — patience here is basically a knife skill."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_soboro_rice_bowl', '{"id":"beef_soboro_rice_bowl","name":"Beef Soboro Bowl with Green Beans","emoji":"🥩","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"rice","q":160},{"f":"green_beans","q":200},{"f":"soy_sauce","q":40},{"f":"sugar","q":15},{"f":"ginger","q":12},{"f":"garlic","q":0.1},{"f":"cucumber","q":1},{"f":"lime","q":0.5},{"f":"salt","q":3},{"f":"scallions","q":0.5}],"steps":["Set the rinsed rice to simmer, covered, in 400ml water for 15 minutes while you slice the cucumber thin and toss it with lime juice, a pinch of the sugar, and salt to pickle.","Trim the green beans, blanch them in salted boiling water for 2 minutes until squeaky-crisp, and shock them under cold water.","Crumble the ground beef into a dry skillet over medium-high heat and cook, chopping constantly with your spatula, until it breaks into fine, sandy crumbles and browns at the edges, about 5 minutes.","Add the soy sauce, remaining sugar, grated ginger, and minced garlic, and simmer for 3 minutes, stirring, until the liquid vanishes and every crumble is dark and lacquered.","Spoon the soboro over one half of each rice bowl, arrange the green beans and drained pickles over the other, and finish with sliced scallions."],"tip":"Two forks held side by side chop the beef into finer soboro crumbles than any spatula ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_tsukune_glaze_bowl', '{"id":"turkey_tsukune_glaze_bowl","name":"Turkey Meatball Bowl with Soy-Honey Lacquer","emoji":"🍡","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["eggs","gluten","soy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"eggs","q":1},{"f":"rice","q":160},{"f":"scallions","q":1},{"f":"ginger","q":12},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":40},{"f":"honey","q":30},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"olive_oil","q":15}],"steps":["Start the rinsed rice simmering, covered, in 400ml water for 15 minutes, and quick-pickle thin cucumber coins with the sugar and half the salt.","Mix the ground turkey with the egg, half the sliced scallions, half the grated ginger, one minced garlic clove, and the remaining salt, then knead for a full minute until the mixture turns tacky — that stickiness is what keeps the meatballs plush.","With wet hands, roll the mixture into 12 golf-ball meatballs and brown them in olive oil over medium heat, turning every 2 minutes, until golden all over and cooked through, about 10 minutes.","Add the soy sauce, honey, and remaining ginger and garlic to the pan and roll the meatballs through the bubbling glaze for 2 minutes until they gleam like polished amber.","Serve five to six meatballs per rice bowl, spoon over the extra glaze, and top with the pickles and the rest of the scallions."],"tip":"Wet hands are the difference between rolling meatballs and wearing them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_egg_donburi', '{"id":"mushroom_egg_donburi","name":"Soft-Scrambled Mushroom Donburi","emoji":"🍄","cuisine":"Asian","meal":["breakfast","lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"mushrooms","q":300},{"f":"onion","q":1},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"honey","q":10},{"f":"sugar","q":5},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes and keep it warm under the lid.","Sear the thickly sliced mushrooms in olive oil over high heat without stirring for 3 minutes, until their cut faces turn mahogany, then add the sliced onion and cook 4 more minutes until soft and sweet.","Pour in the soy sauce, honey, sugar, and 60ml of water, and simmer for 2 minutes so the mushrooms drink up the savory-sweet broth.","Beat the eggs just until the whites and yolks marble together, drizzle them over the simmering pan in a spiral, cover, and cook for 90 seconds — the eggs should be barely set on top, trembling like custard.","Slide the whole silky mixture over bowls of hot rice, drizzle with sesame oil, and finish with scallions."],"tip":"Under-beaten eggs give you ribbons of white and gold; over-beaten eggs give you a uniform yellow blanket, and where''s the drama in that?"}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_soy_edamame_sweet_potato_bowl', '{"id":"maple_soy_edamame_sweet_potato_bowl","name":"Maple-Soy Sweet Potato and Edamame Bowl","emoji":"🍠","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":45,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"edamame_frozen","q":300},{"f":"rice","q":150},{"f":"soy_sauce","q":40},{"f":"maple_syrup","q":25},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"cucumber","q":1},{"f":"lime","q":0.5},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"scallions","q":0.5}],"steps":["Heat the oven to 220C, cube the sweet potatoes into 2cm chunks, toss with half the sesame oil and a pinch of salt, and roast for 25 minutes until the edges caramelize and the centers yield to a fork.","Meanwhile, simmer the rinsed rice, covered, in 375ml water for 15 minutes, and pickle thin cucumber slices in lime juice, sugar, and the remaining salt.","Whisk the soy sauce, maple syrup, grated ginger, minced garlic, and remaining sesame oil into a glossy dressing.","Boil the edamame for 4 minutes, drain well, and toss the hot beans and roasted sweet potatoes with two-thirds of the dressing so they soak it up while steaming.","Build the bowls on a bed of rice, spoon over the remaining dressing, and top with drained pickles and scallions."],"tip":"Crowded sweet potatoes steam and sulk; give them space on the pan and they''ll caramelize like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_avocado_sesame_donburi', '{"id":"tuna_avocado_sesame_donburi","name":"Tuna and Avocado Sesame Rice Bowl","emoji":"🥑","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"tuna_canned","q":280},{"f":"avocado","q":1},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"honey","q":10},{"f":"sesame_oil","q":15},{"f":"cucumber","q":1},{"f":"lime","q":1},{"f":"sugar","q":5},{"f":"salt","q":2},{"f":"scallions","q":0.5},{"f":"ginger","q":5}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes, then fluff it with a fork and let the steam escape for 2 minutes so it isn''t gummy under the toppings.","Slice the cucumber into thin half-moons and toss with sugar, salt, and the juice of half the lime; it should taste like a bright, crunchy counterpoint in 10 minutes.","Whisk the soy sauce, honey, sesame oil, grated ginger, and remaining lime juice into a dressing that tastes sweet, salty, and sharp all at once.","Drain the tuna thoroughly, break it into large flakes, and fold it gently through half the dressing without mashing it to paste.","Fan thin slices of avocado over each bowl of warm rice, mound the tuna alongside, add the drained pickles, and finish with the rest of the dressing and a scattering of scallions."],"tip":"Warm rice plus cold toppings is the whole point — do not refrigerate the assembled bowl into sad uniformity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_scallion_chicken_noodle_soup', '{"id":"ginger_scallion_chicken_noodle_soup","name":"Ginger-Scallion Chicken and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"broth","q":1500},{"f":"rice_noodles","q":240},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"scallions","q":1},{"f":"carrots","q":200},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"salt","q":3}],"steps":["Slice the ginger into coins and smash them, then simmer with the broth, minced garlic, and the white halves of the scallions for 10 minutes until the kitchen smells like a noodle shop.","Slide in the whole chicken breasts, lower the heat until the surface barely shivers, and poach for 12 to 14 minutes; gentle heat is what keeps them silky instead of stringy.","Lift out the chicken to rest, then add the carrot coins and sliced mushrooms to the broth and simmer for 5 minutes until just tender.","Soak the rice noodles in boiling water for 4 to 6 minutes until pliable but still springy, then drain and divide among four deep bowls.","Shred the chicken with two forks, stir it back into the pot with the soy sauce and spinach, and simmer for 1 minute until the leaves collapse into emerald ribbons.","Ladle the soup over the noodles, drizzle each bowl with sesame oil, and shower with the sliced green scallion tops."],"tip":"If the broth is boiling hard enough to watch, it''s boiling hard enough to ruin the chicken — aim for a lazy shimmer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_yakisoba_rice_noodles', '{"id":"veggie_yakisoba_rice_noodles","name":"Vegetable Yakisoba-Style Rice Noodles","emoji":"🥡","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":200},{"f":"eggs","q":3},{"f":"cabbage","q":0.3},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":1},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in boiling water for 4 minutes until bendy but still a touch firm, then drain and toss with the sesame oil so they don''t weld together.","Stir the soy sauce, honey, grated ginger, and minced garlic into a sauce and keep it within arm''s reach — stir-frying waits for no one.","Scramble the beaten eggs in half the olive oil over medium-high heat until just set in soft, glossy curds, about 1 minute, and slide them out onto a plate.","Crank the heat to high, add the remaining oil, and stir-fry the shredded cabbage, carrot matchsticks, and sliced bell pepper for 3 to 4 minutes until charred at the edges but still crunchy.","Add the noodles and sauce and toss with tongs for 2 minutes until every strand is glossed and the sauce sizzles at the pan''s edge, then fold the eggs back in.","Pile into bowls and bury under a generous handful of sliced scallions."],"tip":"Chop everything before the pan gets hot, because a smoking wok has zero respect for your knife skills."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_chicken_cabbage_salad', '{"id":"sesame_chicken_cabbage_salad","name":"Sesame-Soy Chicken and Cabbage Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"cucumber","q":1},{"f":"cashews","q":60},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"soy_sauce","q":30},{"f":"honey","q":15},{"f":"sesame_oil","q":20},{"f":"lime","q":1},{"f":"ginger","q":8},{"f":"salt","q":3}],"steps":["Poach the chicken breasts in barely simmering salted water for 14 minutes, then rest them for 5 minutes and shred into long, juicy strands with two forks.","Toast the cashews in a dry skillet over medium heat, shaking often, for 3 to 4 minutes until they smell buttery and turn freckled gold, then roughly chop.","Shred the cabbage into fine ribbons, cut the carrots into matchsticks, and slice the cucumber into thin half-moons; toss all three with a pinch of salt and let them sit 5 minutes to season and soften slightly.","Whisk the soy sauce, honey, sesame oil, lime juice, and grated ginger into a dressing that tastes assertively sweet-sharp — the mountain of cabbage will mellow it.","Toss the vegetables, chicken, and dressing together until everything glistens, then fold in the torn cilantro and top with cashews and sliced scallions just before serving."],"tip":"Dress this salad a full 10 minutes before eating — cabbage is the rare green that gets better as it sits and marinates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_bulgogi_rice_bowls', '{"id":"beef_bulgogi_rice_bowls","name":"Bulgogi-Style Beef Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"onion","q":0.5},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with 300ml water over low heat for 15 minutes and let it steam off the heat while you cook the beef.","Whisk the soy sauce, honey, grated ginger, and minced garlic into a glossy sauce that coats the back of a spoon.","Set a large skillet over high heat, brown the ground beef with the sliced onion for 6 to 7 minutes, and resist stirring until the bottom crisps into dark, lacy edges.","Pour in the sauce and let it bubble hard for 2 minutes until it reduces to a sticky glaze that clings to every crumble of beef.","Stir in the sesame oil off the heat, then pile the beef over the rice with ribbons of shaved carrot and thin cucumber half-moons.","Serve while the glaze is still shiny and the cucumber is cold for that hot-cold contrast that makes the bowl sing."],"tip":"Let the beef sit untouched in the pan longer than feels polite — those crusty bits are where the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_ginger_beef_lettuce_wraps', '{"id":"soy_ginger_beef_lettuce_wraps","name":"Soy-Ginger Beef Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"onion","q":0.5},{"f":"carrots","q":80},{"f":"cucumber","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Separate the romaine into whole leaves, rinse them, and chill them in ice water so they turn crackling-crisp while you cook.","Brown the ground beef with the diced onion in a dry skillet over medium-high heat for 7 to 8 minutes, breaking it into small crumbles that pick up color on every side.","Stir together the soy sauce, honey, grated ginger, and minced garlic, then pour it over the beef and simmer for 2 minutes until it turns dark and syrupy.","Kill the heat and stir in the sesame oil so its aroma blooms without burning off.","Dry the lettuce leaves, spoon in the glazed beef, and top each cup with matchstick carrots and thin cucumber slices for crunch.","Eat immediately, folded taco-style, over a plate to catch the inevitable drips."],"tip":"The ice-water bath is non-negotiable — limp lettuce turns a wrap into a sad, warm handshake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_broccoli_stir_fry', '{"id":"korean_beef_broccoli_stir_fry","name":"Sticky Soy-Honey Beef and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"broccoli","q":400},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cut the broccoli into small florets and steam them in a covered skillet with a splash of water for 3 minutes until bright green but still snappy, then set aside.","Wipe the pan dry, add the olive oil over high heat, and brown the ground beef for 6 to 7 minutes, pressing it flat like a giant patty so it develops a proper crust before you break it up.","Add the minced garlic and grated ginger to the beef and stir for 30 seconds until your kitchen smells like the best takeout place in town.","Return the broccoli, pour in the whisked soy sauce and honey, and toss over high heat for 2 minutes until the sauce reduces to a sticky sheen on every floret.","Drizzle with sesame oil off the heat and serve straight from the skillet while everything still crackles."],"tip":"The smash-then-break-up beef trick doubles your browning — patience for four minutes, chaos afterward."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_fried_rice', '{"id":"korean_beef_fried_rice","name":"Soy-Honey Beef Fried Rice","emoji":"🍳","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","eggs"],"time":30,"servings":2,"ing":[{"f":"rice","q":130},{"f":"ground_beef","q":250},{"f":"eggs","q":2},{"f":"soy_sauce","q":35},{"f":"honey","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"edamame_frozen","q":100},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 260ml water, then spread it on a plate to cool and dry for 10 minutes — slightly stale-feeling rice fries, wet rice smears.","Brown the ground beef in a large skillet over high heat for 5 to 6 minutes until crisp-edged, then push it to one side.","Add the olive oil, diced carrots, and edamame, and stir-fry for 3 minutes until the carrots lose their raw crunch.","Scrape everything aside, crack the eggs into the empty side, and scramble them hard for 30 seconds until just set in soft curds.","Add the rice, breaking clumps with the back of your spoon, then pour the soy sauce, honey, garlic, and ginger over the top and toss for 2 minutes until every grain is glossy and lightly toasted.","Kill the heat, stir through the sesame oil, and taste — the rice should crackle faintly at the bottom of the pan."],"tip":"Day-old rice from the fridge is the fried-rice cheat code; plan tonight''s leftovers like tomorrow''s victory."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_ginger_beef_meatballs', '{"id":"honey_ginger_beef_meatballs","name":"Honey-Ginger Glazed Beef Meatballs","emoji":"🧆","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"eggs","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"soy_sauce","q":40},{"f":"honey","q":30},{"f":"rice","q":130},{"f":"broccoli","q":200},{"f":"sesame_oil","q":8}],"steps":["Mix the ground beef with the egg, half the grated ginger, and half the minced garlic, working the mixture just until it holds together — overmixing makes meatballs bounce.","Roll into 12 golf-ball-sized meatballs with damp hands and chill them for 10 minutes while the rice simmers in 260ml of water.","Sear the meatballs in a hot, lightly oiled skillet for 8 minutes, turning to brown three sides until they are burnished and crusty.","Add the broccoli florets and a splash of water, cover for 3 minutes, then pour in the soy sauce, honey, and remaining ginger and garlic.","Roll the meatballs through the bubbling glaze for 2 to 3 minutes until it thickens enough to leave a trail when you drag a spoon across the pan.","Finish with sesame oil and serve the meatballs and broccoli heaped over the steamed rice."],"tip":"Damp hands are the difference between rolling meatballs and wearing them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_rice_soup', '{"id":"korean_beef_rice_soup","name":"Gingery Beef and Rice Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free"],"allergens":["gluten","soy","sesame"],"time":45,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"broth","q":1500},{"f":"rice","q":120},{"f":"spinach","q":150},{"f":"carrots","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"ginger","q":20},{"f":"soy_sauce","q":50},{"f":"sesame_oil","q":15}],"steps":["Brown the ground beef in a large pot over medium-high heat for 6 to 7 minutes until deeply crusted, then spoon off all but a tablespoon of fat.","Add the diced onion, sliced carrots, minced garlic, and grated ginger, and cook for 4 minutes until the onion turns translucent and the ginger perfumes the whole pot.","Pour in the broth and soy sauce, scrape up the browned bits from the bottom, and bring everything to a rolling boil.","Stir in the rice, drop to a gentle simmer, and cook uncovered for 18 to 20 minutes until the grains are tender and the broth turns silky from their starch.","Fold in the spinach off the heat so it wilts into emerald ribbons, then finish each bowl with a drizzle of sesame oil.","Serve steaming, when the broth is savory-sweet and the ginger warms the back of your throat."],"tip":"The soup thickens overnight as the rice keeps drinking — thin leftovers with a splash of water and nobody will know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_stuffed_peppers', '{"id":"korean_beef_stuffed_peppers","name":"Soy-Glazed Beef Stuffed Peppers","emoji":"🫑","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"ground_beef","q":350},{"f":"rice","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"spinach","q":100},{"f":"sesame_oil","q":8}],"steps":["Heat the oven to 200C, halve the peppers through the stem, scoop out the seeds, and roast the empty shells cut-side up for 10 minutes to give them a head start.","Meanwhile, simmer the rice in 200ml water for 15 minutes, and brown the beef with the diced onion in a hot skillet for 6 minutes until crumbly and crusted.","Stir the soy sauce, honey, garlic, and ginger into the beef and let it bubble for 2 minutes into a dark glaze, then fold in the cooked rice and spinach until the leaves collapse.","Mound the filling generously into the pepper halves, pressing it in so each one is heaped like a small hill.","Bake for 15 to 18 minutes until the peppers slump slightly and the tops of the filling turn crisp and burnished.","Drizzle with sesame oil and rest 5 minutes before serving — the peppers are lava straight from the oven."],"tip":"Pre-roasting the empty peppers means no more biting into a stuffed pepper that crunches like a raw apple."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_ginger_beef_romaine_salad', '{"id":"crispy_ginger_beef_romaine_salad","name":"Crispy Ginger Beef Romaine Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1.5},{"f":"cucumber","q":1},{"f":"carrots","q":80},{"f":"onion","q":0.3},{"f":"soy_sauce","q":35},{"f":"sesame_oil","q":12},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"olive_oil","q":10}],"steps":["Chop the romaine into wide ribbons, slice the cucumber thin, shave the carrots into strips, and sliver the onion, then chill the whole pile while you cook.","Heat a large skillet over high heat until a drop of water skitters, then brown the ground beef for 7 to 8 minutes, undisturbed at first, until it crisps into dark, crunchy nuggets.","Add the minced garlic and grated ginger for the final minute, stirring constantly so they toast without scorching.","Splash in the soy sauce and let it sizzle and evaporate for 30 seconds, seasoning the beef down to the crumb.","Whisk the sesame oil and olive oil with a spoonful of the warm pan juices to make a quick dressing, and toss it with the cold vegetables.","Top the dressed salad with the hot crispy beef and eat immediately, while the contrast between sizzling and icy is at its peak."],"tip":"Hot beef on cold lettuce waits for no one — dress, top, and eat in that order, fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_skillet_eggs', '{"id":"shakshuka_skillet_eggs","name":"Smoky Skillet Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":4},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"pita","q":2}],"steps":["Warm the olive oil in a wide skillet over medium heat and cook the sliced onion and bell pepper for 8 minutes, until soft and starting to catch color at the edges.","Stir in the minced garlic with a pinch of paprika and cumin, and cook for 60 seconds until fragrant.","Add the chopped tomatoes, season with salt, and simmer for 10 to 12 minutes, until the sauce thickens enough that a spoon dragged through it leaves a brief trail.","Nestle four wells into the sauce with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes until the whites are set but the yolks still wobble.","Crumble the feta over the top, let it soften for a minute, and serve straight from the pan with warm pita for dragging through the sauce."],"tip":"Pull the pan off the heat when the whites look barely underdone — carryover heat finishes eggs faster than your confidence suggests."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_hummus_egg_pita', '{"id":"mediterranean_hummus_egg_pita","name":"Fried Egg and Hummus Breakfast Pitas","emoji":"🥙","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":120},{"f":"eggs","q":4},{"f":"olive_oil","q":15},{"f":"tomato","q":1},{"f":"spinach","q":60},{"f":"feta","q":40}],"steps":["Toast the pitas in a dry skillet over medium heat for about a minute per side, until warm, puffed, and freckled brown, then split them open into pockets.","Swipe a thick layer of hummus inside each pita and tuck in the spinach leaves so the heat starts wilting them.","Heat the olive oil in the same skillet over medium-high until it shimmers, crack in the eggs, and fry 2 to 3 minutes until the edges are lacy and crisp while the yolks stay soft.","Slide two eggs into each pita, then pile in the chopped tomato and crumbled feta.","Season with black pepper and a pinch of oregano, and eat immediately over a plate — the yolk will run, and that is the point."],"tip":"Warm the hummus-side of the pita first so it acts like edible glue instead of cold spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_frittata', '{"id":"spinach_mushroom_frittata","name":"Spinach and Mushroom Frittata","emoji":"🍄","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"milk","q":60},{"f":"parmesan","q":40},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Heat the oven to 190C and whisk the eggs with the milk, half the parmesan, salt, and plenty of black pepper until no streaks remain.","Heat the olive oil in a 25cm ovenproof skillet over medium-high and cook the sliced mushrooms undisturbed for 4 minutes, until browned and squeaking has given way to sizzling.","Add the diced onion and garlic and cook 3 minutes more, then pile in the spinach and stir until it collapses and any liquid evaporates.","Pour in the egg mixture, drag a spatula through it for 30 seconds to form soft curds, then scatter the remaining parmesan on top.","Transfer to the oven and bake 10 to 12 minutes, until the center is just set and puffed at the edges, then rest 5 minutes before slicing into wedges."],"tip":"A frittata that browns on top has already overcooked underneath — pull it while the center still jiggles like it has somewhere to be."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_eggs_florentine_ramekins', '{"id":"baked_eggs_florentine_ramekins","name":"Baked Eggs Florentine","emoji":"🥚","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"spinach","q":200},{"f":"butter","q":15},{"f":"garlic","q":0.2},{"f":"milk","q":80},{"f":"parmesan","q":30},{"f":"bread","q":2}],"steps":["Heat the oven to 180C and butter two ramekins or small gratin dishes generously.","Melt the butter in a skillet over medium heat, sizzle the sliced garlic for 30 seconds, then wilt the spinach in big handfuls until it is glossy and reduced to a fraction of its bravado.","Stir in the milk and half the parmesan, simmer 2 minutes until creamy, then divide the spinach between the ramekins.","Make two hollows in each dish, crack in the eggs, dust with the remaining parmesan, and bake 12 to 15 minutes until the whites are opaque but the yolks still shine.","Meanwhile toast the bread until deeply golden, cut into soldiers, and serve alongside for dunking into the molten centers."],"tip":"Set the ramekins on a preheated baking sheet so the bottoms cook at the same speed as the tops."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_cheddar_omelet', '{"id":"diner_cheddar_omelet","name":"Diner-Style Cheddar Omelet","emoji":"🧀","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cheddar","q":80},{"f":"butter","q":20},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"mushrooms","q":100}],"steps":["Melt half the butter in a nonstick skillet over medium-high heat and saute the diced pepper, onion, and mushrooms for 5 minutes, until browned and dry, then scrape onto a plate.","Whisk three eggs with a pinch of salt until completely uniform and slightly frothy — about 30 vigorous seconds.","Melt half the remaining butter over medium heat, pour in the eggs, and pull the setting edges toward the center with a spatula, tilting so raw egg floods the gaps.","When the surface is glossy but no longer liquid, scatter half the cheddar and half the vegetables over one side and fold the omelet over itself.","Slide onto a warm plate, then repeat with the remaining butter, eggs, cheese, and filling for the second omelet."],"tip":"Low confidence and high heat ruin omelets equally — commit to the fold and forgive the wrinkles."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fried_egg_avocado_sandwich', '{"id":"fried_egg_avocado_sandwich","name":"Crispy Fried Egg and Avocado Sandwich","emoji":"🥪","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"eggs","q":4},{"f":"cheddar","q":50},{"f":"butter","q":15},{"f":"avocado","q":1},{"f":"spinach","q":40}],"steps":["Toast the bread until golden and sturdy, then mash the avocado onto two slices with salt, pepper, and a squeeze of anything acidic you have on hand.","Melt the butter in a skillet over medium-high heat until it foams and just starts to smell nutty.","Crack in the eggs and fry 2 to 3 minutes, spooning butter over the whites, until the edges are shatteringly crisp and browned like lace.","Lay the cheddar over the eggs for the last 30 seconds so it slumps and melts from the residual heat.","Stack spinach, then the cheesy eggs, onto the avocado toast, crown with the remaining slices, press gently, and halve on the diagonal."],"tip":"Mash the avocado all the way to the crust — every under-appointed bite is a small betrayal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_potato_breakfast_hash', '{"id":"crispy_potato_breakfast_hash","name":"Crispy Potato Hash with Fried Eggs","emoji":"🥔","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"eggs","q":4}],"steps":["Dice the potatoes into 1cm cubes, rinse, and pat thoroughly dry — wet potatoes steam, and steamed potatoes never crisp.","Heat two-thirds of the oil in a heavy skillet over medium-high, add the potatoes in one layer, and leave them alone for 5 full minutes before turning; repeat until deeply golden on most sides, about 15 minutes total.","Add the diced onion, bell pepper, and garlic with a big pinch of salt and paprika, and cook 5 minutes more until the vegetables soften and the pan smells sweet.","Push the hash to the edges, add the remaining oil to the center, and crack in the eggs.","Cover and cook 3 to 4 minutes, until the whites are set and the yolks tremble, then serve straight from the skillet with plenty of black pepper."],"tip":"The spatula is the enemy of crispness — stir half as often as you want to."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('scrambled_egg_breakfast_tacos', '{"id":"scrambled_egg_breakfast_tacos","name":"Soft Scramble Breakfast Tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"black_beans","q":120},{"f":"cheddar","q":40},{"f":"avocado","q":1},{"f":"olive_oil","q":10}],"steps":["Warm the black beans in a small pan with a splash of water, a pinch of cumin, and salt, mashing a few against the side until they turn saucy.","Char the tortillas directly over a flame or in a dry skillet for 30 seconds per side, until blistered and pliable, then wrap in a towel to stay warm.","Whisk the eggs with salt, heat the oil in a nonstick skillet over medium-low, and stir slowly with a spatula for 3 to 4 minutes until large, custardy curds form — pull the pan off while they still look slightly wet.","Spread beans down the center of each tortilla and top with the soft scramble.","Finish with grated cheddar so it melts on contact, sliced avocado, and a shake of hot sauce if your morning needs the encouragement."],"tip":"Scrambled eggs keep cooking on the tortilla, so undercook them slightly and let physics do the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('potato_egg_breakfast_burrito', '{"id":"potato_egg_breakfast_burrito","name":"Potato and Egg Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"eggs","q":4},{"f":"potatoes","q":250},{"f":"cheddar","q":60},{"f":"greek_yogurt","q":60},{"f":"olive_oil","q":15},{"f":"onion","q":0.5}],"steps":["Dice the potatoes small, about 1cm, and fry in the olive oil over medium-high heat with the diced onion, salt, and a pinch of chili powder for 12 minutes, until golden and crisp-edged.","Beat the eggs with a pinch of salt, pour them over the potatoes, and stir gently for 2 minutes until just set into soft curds.","Warm the tortillas in a dry skillet until floppy and lightly speckled, then spread each with a swipe of greek yogurt.","Divide the potato-egg filling and the grated cheddar between the tortillas, fold in the sides, and roll tightly away from you.","Return the burritos seam-side down to the hot skillet for 1 to 2 minutes per side, until golden and sealed, then halve and serve while the cheese still stretches."],"tip":"Toasting the seam first welds the burrito shut — skip it and breakfast becomes a hand-held landslide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('indian_egg_bhurji', '{"id":"indian_egg_bhurji","name":"Masala Egg Bhurji with Toast","emoji":"🍛","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"butter","q":20},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"bread","q":2}],"steps":["Melt the butter in a skillet over medium heat and fry the finely chopped onion with a pinch of salt for 6 minutes, until golden at the edges and sweet-smelling.","Add the minced garlic, a half teaspoon each of turmeric and cumin, and a pinch of chili flakes, and toast for 30 seconds until the spices bloom in the fat.","Stir in the chopped tomatoes and cook 4 to 5 minutes, until they slump into a thick, jammy masala that pulls away from the pan.","Pour in the beaten eggs and scramble briskly, breaking them into small, spice-stained curds — about 2 minutes, stopping while they still glisten.","Shower with fresh black pepper and serve piled onto hot buttered toast in place of roti."],"tip":"Bhurji curds should be small and chaotic, not fluffy and polite — keep the spatula moving."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_style_egg_curry', '{"id":"punjabi_style_egg_curry","name":"Weekend Egg Curry with Rice","emoji":"🥘","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"rice","q":140}],"steps":["Simmer the rice in salted water according to its stubbornness, usually 12 to 15 minutes, then drain and keep covered.","Meanwhile boil the eggs for 9 minutes, shock them in cold water, peel, and score each one lightly so the sauce can get in.","Heat the oil in a deep skillet over medium and fry the sliced onion for 8 minutes until deeply browned, then add the garlic, a teaspoon of garam masala, half a teaspoon of turmeric, and chili to taste, stirring for 30 seconds.","Add the chopped tomatoes and a splash of water and simmer 10 minutes, until the sauce thickens and the oil beads at the edges — the classic sign the masala is done.","Halve the eggs, slide them into the sauce cut-side up for 2 minutes to warm through, and serve ladled over the rice."],"tip":"Browning the onions past your comfort zone is where the entire curry''s flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_egg_fried_rice', '{"id":"breakfast_egg_fried_rice","name":"Morning Egg Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"rice","q":150},{"f":"eggs","q":4},{"f":"edamame_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Cook the rice ahead if you can and chill it — day-old grains fry into separate, chewy pieces instead of clumping into porridge.","Heat half the olive oil in a wok or large skillet over high heat, pour in the beaten eggs, and scramble for 45 seconds into big soft folds, then scoop them out.","Add the remaining oil with the diced onion and garlic and stir-fry 2 minutes, until fragrant and just golden.","Add the rice and edamame, pressing the rice against the hot metal and tossing every 30 seconds for about 4 minutes, until you hear it crackle and see toasted spots.","Return the eggs, splash in the soy sauce around the rim of the pan so it sizzles and caramelizes, toss once more, and finish off the heat with the sesame oil."],"tip":"Soy sauce poured down the hot side of the wok toasts into something smoky; poured on the rice it just makes it soggy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('silky_steamed_eggs_rice_bowl', '{"id":"silky_steamed_eggs_rice_bowl","name":"Silky Steamed Egg Rice Bowls","emoji":"🥣","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"rice","q":130},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":8},{"f":"spinach","q":100},{"f":"garlic","q":0.1}],"steps":["Start the rice in salted water and simmer, covered, for 12 to 15 minutes until tender, then let it rest off the heat.","Whisk the eggs with one and a half times their volume of warm water and a pinch of salt, then pour through a fine strainer into two heatproof bowls to remove every bubble and streak.","Cover each bowl tightly with foil and steam over gently simmering water for 10 to 12 minutes, until the custard is set but quivers like fresh tofu when nudged.","While the eggs steam, wilt the spinach with the sliced garlic and a few drops of sesame oil in a hot pan for about a minute.","Spoon rice into bowls, slide the trembling custard on top with the spinach alongside, and finish with the soy sauce and remaining sesame oil drizzled over the surface."],"tip":"A raging boil turns silk into sponge — the steamer should whisper, not roar."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_pancakes_2', '{"id":"lemon_ricotta_pancakes_2","name":"Lemon Ricotta Pancakes","emoji":"🥞","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"ricotta","q":200},{"f":"flour","q":120},{"f":"eggs","q":2},{"f":"milk","q":120},{"f":"sugar","q":25},{"f":"lemon","q":1},{"f":"butter","q":20},{"f":"maple_syrup","q":60},{"f":"berries","q":100},{"f":"salt","q":2}],"steps":["Separate the eggs, then whisk the yolks with the ricotta, milk, all the lemon zest, and the juice of half the lemon until smooth and creamy.","Stir in the flour, sugar, and salt just until no dry streaks remain — a few small lumps are the sign of a tender pancake.","Beat the egg whites to soft, droopy peaks and fold them in gently in two additions to keep the batter cloud-light.","Melt a sliver of butter in a nonstick skillet over medium heat and drop in quarter-cup rounds; cook 2 to 3 minutes until the edges look dry and the undersides are deep golden.","Flip carefully and cook 2 minutes more until the centers spring back when pressed, then serve warm with berries and maple syrup."],"tip":"Those whipped whites are your only leavening, so fold like you are handling a sleeping baby."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cinnamon_berry_french_toast', '{"id":"cinnamon_berry_french_toast","name":"Cinnamon Berry French Toast","emoji":"🍞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"bread","q":6},{"f":"eggs","q":3},{"f":"milk","q":150},{"f":"sugar","q":15},{"f":"cinnamon","q":3},{"f":"butter","q":25},{"f":"berries","q":150},{"f":"maple_syrup","q":60},{"f":"salt","q":1}],"steps":["Whisk the eggs, milk, sugar, cinnamon, and a pinch of salt in a shallow dish until no ribbons of white remain.","Meanwhile, warm the berries with a tablespoon of the maple syrup in a small saucepan over low heat for 5 minutes, mashing a few, until they slump into a loose, glossy compote.","Soak each slice of bread 20 to 30 seconds per side — it should feel saturated but still hold its shape when lifted.","Melt half the butter in a large skillet over medium heat and cook the slices 2 to 3 minutes per side until burnished golden with crisp edges, adding more butter for the second batch.","Stack the slices, spoon over the warm berries, and finish with the remaining maple syrup while everything is still steaming."],"tip":"Slightly stale bread drinks up custard without collapsing; fresh squishy slices turn to pudding on the griddle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_walnut_baked_oatmeal', '{"id":"banana_walnut_baked_oatmeal","name":"Banana Walnut Baked Oatmeal","emoji":"🍌","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","eggs","nuts"],"time":50,"servings":2,"ing":[{"f":"oats","q":140},{"f":"banana","q":2},{"f":"eggs","q":2},{"f":"milk","q":250},{"f":"maple_syrup","q":45},{"f":"walnuts","q":40},{"f":"butter","q":15},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Heat the oven to 375 F and butter a small baking dish generously, corners included.","Mash one and a half bananas in a large bowl until nearly smooth, then whisk in the eggs, milk, maple syrup, cinnamon, and salt.","Stir in the oats and most of the walnuts, pour the mixture into the dish, and shingle the remaining half banana in slices over the top with the last of the nuts.","Bake 30 to 35 minutes until the top is puffed and golden and the center barely jiggles when you nudge the dish.","Rest 5 minutes so it sets sliceable, then scoop into bowls with a splash of cold milk if you like the hot-cold contrast."],"tip":"Bananas with leopard-spotted peels bake up twice as sweet as the pristine yellow ones."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_pie_oatmeal', '{"id":"apple_pie_oatmeal","name":"Apple Pie Stovetop Oatmeal","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":20,"servings":2,"ing":[{"f":"oats","q":120},{"f":"apple","q":2},{"f":"coconut_milk","q":100},{"f":"maple_syrup","q":45},{"f":"almonds","q":30},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Dice the apples small and simmer them in a saucepan with the maple syrup, cinnamon, and a splash of water for 5 minutes until they smell like pie filling and yield to a fork.","Scoop out half the apples and set them aside for topping, then add the oats, coconut milk, a good pinch of salt, and 350 ml of water to the pot.","Simmer over medium-low for 8 to 10 minutes, stirring often, until the oats are plump and the porridge falls lazily off the spoon.","While it cooks, toast the almonds in a dry skillet over medium heat for 3 to 4 minutes, shaking the pan, until they crackle and turn fragrant; chop roughly.","Ladle into bowls and crown with the reserved apples and toasted almonds while the steam still carries the cinnamon."],"tip":"Cooking half the apples into the oats and saving half for the top gives you both jammy and crisp in every bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berries_and_cream_overnight_oats', '{"id":"berries_and_cream_overnight_oats","name":"Berries and Cream Overnight Oats","emoji":"🫐","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":10,"servings":2,"ing":[{"f":"oats","q":100},{"f":"greek_yogurt","q":200},{"f":"milk","q":200},{"f":"berries","q":200},{"f":"honey","q":40},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Stir the oats, yogurt, milk, honey, cinnamon, and a small pinch of salt together in a bowl until every oat is coated and the mixture looks like loose cake batter.","Fold in half the berries, crushing a few against the side of the bowl so violet streaks ripple through.","Divide between two jars, press plastic or lids on top, and chill at least 6 hours or overnight until the oats are soft and the mixture is spoonably thick.","In the morning, loosen with a splash of milk if needed and pile the remaining fresh berries on top for a juicy, cold-on-cold finish."],"tip":"The pinch of salt is not optional — it is the difference between dessert and wet cardboard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_almond_berry_parfait', '{"id":"honey_almond_berry_parfait","name":"Honey Almond Berry Parfait","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"greek_yogurt","q":400},{"f":"oats","q":60},{"f":"almonds","q":40},{"f":"olive_oil","q":10},{"f":"honey","q":50},{"f":"berries","q":200},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Toast the oats and roughly chopped almonds in the olive oil with a pinch of salt in a skillet over medium heat for 4 to 5 minutes, stirring constantly, until golden and smelling like fresh granola.","Stir a tablespoon of the honey into the hot pan so it bubbles and coats the mixture, then spread it on a plate to cool crisp.","Whisk the yogurt with half the remaining honey and the cinnamon until glossy.","Build the parfaits in two glasses: a thick layer of yogurt, a handful of berries, a scatter of the honeyed crunch, then repeat until the glass is full.","Finish with a final drizzle of honey and serve within 15 minutes while the top layer still shatters."],"tip":"Layer the crunch between yogurt strata, not just on top, so the last spoonful is as good as the first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_banana_rice_porridge_2', '{"id":"coconut_banana_rice_porridge_2","name":"Coconut Banana Rice Porridge","emoji":"🥥","cuisine":"Asian","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"rice","q":130},{"f":"coconut_milk","q":250},{"f":"maple_syrup","q":45},{"f":"banana","q":2},{"f":"cashews","q":30},{"f":"lime","q":1},{"f":"ginger","q":5},{"f":"salt","q":1}],"steps":["Rinse the rice until the water runs mostly clear, then simmer it in a saucepan with 400 ml of water and the thinly sliced ginger for 10 minutes.","Pour in the coconut milk and a pinch of salt and cook over low heat for 15 to 20 minutes more, stirring often, until the grains slump into a thick, creamy porridge.","Stir in the maple syrup and one sliced banana, letting the fruit soften into the heat for a minute.","Toast the cashews in a dry skillet over medium heat for 3 minutes until golden at the edges, then chop them roughly.","Serve in deep bowls topped with the second sliced banana, the cashews, lime zest, and a bright squeeze of lime juice to cut the richness."],"tip":"Stir like you mean it during the last five minutes — the released starch is the creaminess, and the pot bottom knows when you slack."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_yogurt_breakfast_crepes', '{"id":"berry_yogurt_breakfast_crepes","name":"Berry Yogurt Breakfast Crepes","emoji":"🍓","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":35,"servings":2,"ing":[{"f":"flour","q":100},{"f":"eggs","q":2},{"f":"milk","q":250},{"f":"butter","q":20},{"f":"sugar","q":20},{"f":"greek_yogurt","q":200},{"f":"honey","q":30},{"f":"berries","q":200},{"f":"lemon","q":0.5},{"f":"salt","q":1}],"steps":["Whisk the flour, eggs, milk, half the sugar, a pinch of salt, and half the butter, melted, into a batter the texture of heavy cream; let it rest 10 minutes so the flour hydrates.","While it rests, simmer the berries with the remaining sugar and a squeeze of lemon over medium-low heat for 5 to 6 minutes until jammy but still holding some whole fruit.","Heat a nonstick skillet over medium, slick it with butter, and swirl in a thin ladle of batter; cook 60 to 90 seconds until the edges lace and lift, then flip for 30 seconds more.","Stack the finished crepes under a towel and repeat, re-buttering every second crepe.","Stir the honey into the yogurt, spread a ribbon down each crepe, fold into quarters, and spoon the warm berry compote over the top."],"tip":"The first crepe is a sacrifice to the pan gods — eat the evidence and carry on."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_pb_breakfast_bowls', '{"id":"sweet_potato_pb_breakfast_bowls","name":"Maple Peanut Butter Sweet Potato Bowls","emoji":"🍠","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":55,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"peanut_butter","q":50},{"f":"maple_syrup","q":30},{"f":"banana","q":1},{"f":"coconut_milk","q":60},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Heat the oven to 400 F, prick the sweet potatoes all over with a fork, and roast them directly on the rack for 45 to 50 minutes until they hiss, wrinkle, and give completely when squeezed.","Split them open and scoop the molten flesh into two bowls, mashing it roughly with the coconut milk, cinnamon, and a pinch of salt until creamy but not baby-smooth.","Warm the peanut butter with the maple syrup in a small pan or microwave for 20 seconds until it pours in ribbons.","Slice the banana over the bowls, drizzle generously with the peanut-maple sauce, and finish with one more dusting of cinnamon.","Serve hot, when the caramelized sugars at the skin edges are still sticky."],"tip":"Roast a tray of sweet potatoes on Sunday and this becomes a five-minute weekday breakfast all week."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('whipped_honey_cottage_cheese_bowls', '{"id":"whipped_honey_cottage_cheese_bowls","name":"Whipped Honey Cottage Cheese Bowls","emoji":"🥣","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"honey","q":40},{"f":"berries","q":200},{"f":"walnuts","q":40},{"f":"lemon","q":0.5},{"f":"cinnamon","q":1}],"steps":["Blend the cottage cheese in a food processor or blender for a full 60 to 90 seconds, scraping down once, until the curds vanish into a silky, mousse-like cream.","Fold in half the honey and a shower of lemon zest, tasting as you go — it should be gently sweet with a bright edge.","Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes until they smell warm and woodsy, then crush them lightly in your fist.","Swoosh the whipped cheese into two shallow bowls, pile on the berries and walnuts, and finish with the remaining honey and a whisper of cinnamon.","Eat immediately, dragging every spoonful through all three layers."],"tip":"The blender is what converts cottage-cheese skeptics — nobody has to know what the mousse used to look like."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cinnamon_tortilla_crisps_with_berries', '{"id":"cinnamon_tortilla_crisps_with_berries","name":"Cinnamon Tortilla Crisps with Honeyed Yogurt","emoji":"🍪","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"butter","q":30},{"f":"sugar","q":30},{"f":"cinnamon","q":4},{"f":"greek_yogurt","q":200},{"f":"honey","q":20},{"f":"berries","q":150},{"f":"lime","q":0.5}],"steps":["Stir the sugar and cinnamon together on a wide plate and cut each tortilla into eight wedges.","Melt half the butter in a large skillet over medium heat and fry the wedges in a single layer for 1 to 2 minutes per side until they blister, stiffen, and turn deep gold, adding butter as the pan dries.","Toss the hot wedges immediately in the cinnamon sugar so it clings like a buñuelo''s jacket, then let them cool for 2 minutes to crisp fully.","Whisk the yogurt with the honey and a squeeze of lime until pourable and tangy-sweet.","Pile the crisps onto plates with the yogurt for dipping and scatter the berries over everything."],"tip":"Sugar the wedges the second they leave the pan — cold crisps shrug the cinnamon sugar right off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_quinoa_kheer', '{"id":"cashew_quinoa_kheer","name":"Cashew Quinoa Kheer","emoji":"🍚","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":35,"servings":2,"ing":[{"f":"quinoa","q":120},{"f":"milk","q":500},{"f":"honey","q":40},{"f":"cashews","q":40},{"f":"butter","q":10},{"f":"ginger","q":5},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Rinse the quinoa thoroughly in a fine sieve to wash off its bitter coating, then toast it in half the butter in a saucepan over medium heat for 2 minutes until it smells nutty and begins to pop.","Pour in the milk with the grated ginger and a pinch of salt, bring to a bare simmer, and cook gently for 20 to 22 minutes, stirring often so the bottom never catches, until the grains uncurl and the milk thickens to a spoon-coating custard.","Meanwhile, fry the cashews in the remaining butter in a small pan for 2 to 3 minutes until evenly golden, and set them aside on a paper towel.","Take the kheer off the heat and stir in the honey and cinnamon — off-heat sweetening keeps the honey''s floral edge intact.","Ladle into bowls, top with the buttery cashews, and serve warm, or chill it for a thicker pudding-style breakfast."],"tip":"Kheer thickens dramatically as it cools, so pull it from the stove one shade looser than you want to eat it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_breakfast_quesadillas', '{"id":"apple_cinnamon_breakfast_quesadillas","name":"Apple Cinnamon Breakfast Quesadillas","emoji":"🫓","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"apple","q":2},{"f":"ricotta","q":150},{"f":"butter","q":20},{"f":"honey","q":25},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Slice the apples thin and saute them in half the butter over medium-high heat with the cinnamon, a pinch of salt, and a tablespoon of the honey for 4 to 5 minutes until their edges caramelize and they bend without breaking.","Stir the ricotta with the remaining honey until it loosens into a sweet, spreadable cream.","Spread the ricotta over half of each tortilla, shingle the caramelized apples on top, and fold the tortillas into half-moons, pressing gently to seal.","Wipe out the skillet, melt the remaining butter over medium heat, and toast the quesadillas 2 to 3 minutes per side until the outsides are crackly gold and the filling is warmed through.","Rest 1 minute so molten filling does not ambush anyone, then cut into wedges and serve."],"tip":"Keep the apple layer to a single shingle — overstuffed quesadillas leak, and caramelized honey is basically lava."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_maple_pancakes', '{"id":"banana_maple_pancakes","name":"Banana Maple Pancakes","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"flour","q":150},{"f":"sugar","q":15},{"f":"cinnamon","q":2},{"f":"salt","q":2},{"f":"eggs","q":2},{"f":"milk","q":200},{"f":"butter","q":30},{"f":"banana","q":2},{"f":"maple_syrup","q":60}],"steps":["Whisk the flour, sugar, cinnamon, and salt in a large bowl, then mash one very ripe banana in a second bowl until nearly smooth.","Beat the eggs and milk into the mashed banana along with half the melted butter, then fold the wet mixture into the dry with about ten lazy strokes, stopping while a few streaks of flour remain.","Let the batter rest for 5 minutes while a nonstick skillet heats over medium until a drop of water skitters across the surface.","Grease the pan with a little of the remaining butter and ladle in batter to form 10-centimeter rounds, cooking 2 to 3 minutes until the edges look dry and the bubbles on top pop and hold their shape.","Flip once and cook 90 seconds more until the undersides are deep golden brown, then stack the pancakes on warm plates.","Top with the second banana in coins, the last of the butter, and a generous flood of maple syrup."],"tip":"A rested batter and an unbothered flipping hand make fluffier pancakes than any amount of frantic whisking ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_french_toast', '{"id":"berry_french_toast","name":"Cinnamon Berry French Toast","emoji":"🍓","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":20,"servings":2,"ing":[{"f":"bread","q":6},{"f":"eggs","q":3},{"f":"milk","q":120},{"f":"cinnamon","q":2},{"f":"sugar","q":10},{"f":"butter","q":20},{"f":"berries","q":150},{"f":"maple_syrup","q":45}],"steps":["Whisk the eggs, milk, cinnamon, and sugar in a wide, shallow dish until no streaks of white remain and the custard smells like a bakery.","Soak each slice of bread for about 20 seconds per side, long enough to saturate the crumb but not so long that it slumps when you lift it.","Melt half the butter in a large skillet over medium heat until the foam subsides, then lay in three slices without crowding.","Cook 2 to 3 minutes per side until each face is burnished mahogany and the centers spring back when pressed, then repeat with the remaining butter and bread.","While the second batch cooks, warm the berries in a small saucepan over low heat for 3 to 4 minutes until they slump and release glossy purple juice.","Shingle the toast on plates, spoon over the warm berries, and finish with maple syrup."],"tip":"Day-old bread drinks custard like a champ; fresh squishy bread turns into a sad omelet sandwich."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_brunch_skillet', '{"id":"shakshuka_brunch_skillet","name":"Feta Shakshuka with Toast Soldiers","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":2},{"f":"paprika","q":3},{"f":"chili_powder","q":1},{"f":"crushed_tomatoes","q":400},{"f":"eggs","q":4},{"f":"feta","q":80},{"f":"parsley","q":0.3},{"f":"bread","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy skillet over medium heat and cook the sliced onion and bell pepper with a pinch of salt for 8 minutes, until soft and sweet at the edges.","Stir in the minced garlic, cumin, paprika, and chili powder and toast for 30 seconds until the spices bloom and the kitchen smells faintly smoky.","Pour in the crushed tomatoes, season with the remaining salt and pepper, and simmer 8 to 10 minutes until the sauce thickens enough that a spoon leaves a brief trail.","Make four wells with the back of the spoon, crack an egg into each, then cover and cook 5 to 7 minutes until the whites are set but the yolks still wobble like custard.","Scatter over the crumbled feta and chopped parsley, letting the cheese soften in the residual heat.","Serve straight from the pan with toasted bread cut into strips for dredging through sauce and yolk."],"tip":"The eggs keep cooking after you kill the heat, so pull the pan when the yolks still scare you a little."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('asparagus_parmesan_frittata', '{"id":"asparagus_parmesan_frittata","name":"Asparagus Parmesan Frittata","emoji":"🥚","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"milk","q":30},{"f":"parmesan","q":50},{"f":"asparagus","q":250},{"f":"scallions","q":0.5},{"f":"olive_oil","q":15},{"f":"lemon","q":0.5},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190 degrees Celsius and whisk the eggs, milk, most of the grated parmesan, salt, and pepper until uniformly pale yellow.","Snap the woody ends off the asparagus, cut the spears into 3-centimeter lengths, and saute them with the sliced scallions in olive oil in an ovenproof skillet over medium heat for 4 minutes, until bright green and just tender.","Pour the egg mixture over the vegetables and cook undisturbed for 2 minutes, until the edges begin to set and pull away from the pan.","Slide the skillet into the oven and bake 10 to 12 minutes, until the center is puffed and barely jiggles when you nudge the handle.","Shower the top with the reserved parmesan and a squeeze of lemon, then rest 3 minutes before cutting into wedges; the frittata will settle into a tender, sliceable custard."],"tip":"An overbaked frittata bounces like a gym mat, so trust the jiggle and get out of the oven early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_toast_poached_eggs', '{"id":"avocado_toast_poached_eggs","name":"Smashed Avocado Toast with Poached Eggs","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"avocado","q":1.5},{"f":"eggs","q":4},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"chili_powder","q":1},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Bring a wide saucepan of water to a bare simmer where small bubbles cling to the bottom but the surface barely trembles.","Crack each egg into a small cup and slide them gently into the water one at a time, poaching 3 to 4 minutes until the whites are opaque and set but the yolks still feel soft when lifted with a slotted spoon.","While the eggs poach, toast the bread until deeply golden and crisp enough to knock on.","Mash the avocado with the lemon juice, salt, and pepper, keeping it chunky rather than smooth, and spread it thickly over the hot toast.","Set a drained poached egg on each slice, drizzle with olive oil, and dust with chili powder and more black pepper.","Cut one open immediately and let the yolk run into the avocado, because that is the entire point."],"tip":"The freshest eggs hold together in the water; save the elderly ones in your carton for hard-boiling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_egg_breakfast_burritos', '{"id":"bacon_egg_breakfast_burritos","name":"Bacon and Egg Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":[],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"bacon","q":80},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"salsa","q":100},{"f":"avocado","q":0.5},{"f":"scallions","q":0.3},{"f":"black_pepper","q":1}],"steps":["Cook the chopped bacon in a cold skillet set over medium heat for 8 to 10 minutes, stirring occasionally, until the fat renders and the pieces are crisp and bronzed; lift them out and pour off all but a thin film of fat.","Whisk the eggs with black pepper, pour them into the same skillet over medium-low heat, and scramble slowly with a spatula for 2 to 3 minutes until they form soft, glossy curds that are just barely set.","Warm the tortillas directly over a burner flame or in a dry pan for 15 seconds per side until pliable and lightly blistered.","Lay each tortilla flat and stack eggs, bacon, grated cheddar, sliced avocado, sliced scallions, and a spoonful of salsa slightly below center.","Fold in the sides, roll each burrito tightly away from you, then sear seam-side down in the hot skillet for a minute until the seal is golden and crackly.","Halve on a diagonal and serve with the remaining salsa for dunking."],"tip":"Starting bacon in a cold pan renders the fat evenly, and that fat is the only cooking oil this recipe respects."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_salmon_potato_hash', '{"id":"crispy_salmon_potato_hash","name":"Crispy Salmon and Potato Hash with Fried Eggs","emoji":"🐟","cuisine":"American","meal":["breakfast","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":35,"servings":2,"ing":[{"f":"salmon","q":250},{"f":"potatoes","q":350},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"eggs","q":2},{"f":"paprika","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Dice the potatoes into 1-centimeter cubes, simmer them in salted water for 6 minutes until just tender, and drain them well so they crisp instead of steam.","Heat most of the olive oil in a large cast-iron skillet over medium-high heat and spread the potatoes in a single layer, leaving them alone for 4 minutes until the undersides turn deep golden and release from the pan.","Add the diced onion and bell pepper with the paprika, salt, and pepper and cook 5 minutes more, tossing occasionally, until the vegetables soften and the edges char lightly.","Nestle in the salmon, cut into large chunks, and cook 3 to 4 minutes, turning once, until the fish flakes at the touch of a spatula but still looks blush in the center.","Push the hash aside, add the last of the oil, and fry the eggs 2 to 3 minutes until the whites are lacy and crisp at the edges and the yolks glow.","Finish with lemon juice and chopped parsley and serve directly from the skillet."],"tip":"Resist the urge to stir the potatoes early; crust only happens to potatoes you ignore."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salsa_chilaquiles_with_eggs', '{"id":"salsa_chilaquiles_with_eggs","name":"Skillet Chilaquiles with Fried Eggs","emoji":"🌶️","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":20},{"f":"salsa","q":250},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"sour_cream","q":40},{"f":"onion","q":0.5},{"f":"cilantro","q":0.3},{"f":"lime","q":0.5},{"f":"salt","q":2}],"steps":["Cut the tortillas into eighths and fry them in the olive oil in a large skillet over medium-high heat for 5 to 6 minutes, tossing now and then, until they are golden, rigid, and audibly crisp.","Pour the salsa over the chips with a splash of water and a pinch of salt, and simmer 2 to 3 minutes, folding gently, until the sauce clings and the chips soften at the edges while keeping some crunch in the middle.","Meanwhile, fry the eggs in a second pan over medium heat for 2 to 3 minutes until the whites are set with frilly brown edges and the yolks remain molten.","Slide the eggs on top of the saucy chips and scatter over the grated cheddar so it melts on contact.","Finish with dollops of sour cream, thinly sliced onion, torn cilantro, and a hard squeeze of lime, then serve immediately while the textures are still arguing."],"tip":"Chilaquiles wait for no one; the gap between saucy-crisp and soggy is roughly the length of one good story."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_turkey_sausage_plate', '{"id":"maple_turkey_sausage_plate","name":"Maple Turkey Sausage Brunch Plate","emoji":"🍁","cuisine":"American","meal":["breakfast"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"maple_syrup","q":20},{"f":"oregano","q":2},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":2},{"f":"sweet_potatoes","q":300},{"f":"olive_oil","q":20},{"f":"eggs","q":4},{"f":"scallions","q":0.3}],"steps":["Mix the ground turkey with half the maple syrup, the oregano, paprika, half the salt, and a generous grind of pepper, then shape it into six thin patties with damp hands.","Dice the sweet potatoes into 1-centimeter cubes, toss with half the olive oil and the remaining salt, and roast at 220 degrees Celsius for 20 to 25 minutes until caramelized at the corners and creamy inside.","Sear the patties in the remaining oil in a skillet over medium heat for 3 to 4 minutes per side, until deeply browned and the centers register 74 degrees Celsius.","Brush the patties with the last of the maple syrup in the final minute so it bubbles into a sticky lacquer.","Fry the eggs in the same glossy pan for 2 to 3 minutes until the whites set and the edges crisp in the sausage drippings.","Plate the patties, sweet potatoes, and eggs together and shower with sliced scallions."],"tip":"Thin patties cook through before they dry out, which is the whole trick to turkey sausage that people actually finish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_berry_yogurt_parfaits', '{"id":"honey_berry_yogurt_parfaits","name":"Honey Berry Parfaits with Toasted Oat Clusters","emoji":"🍯","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"greek_yogurt","q":400},{"f":"oats","q":60},{"f":"walnuts","q":30},{"f":"butter","q":10},{"f":"honey","q":40},{"f":"berries","q":200},{"f":"cinnamon","q":1},{"f":"salt","q":1}],"steps":["Melt the butter in a skillet over medium heat and add the oats, chopped walnuts, cinnamon, and salt, stirring constantly for 4 to 5 minutes until the oats turn tawny and smell like baking cookies.","Drizzle in half the honey and stir 30 seconds more so the mixture clumps into sticky clusters, then scrape it onto a plate to cool and crisp.","Warm half the berries in the same pan for 2 minutes, crushing a few with the spoon, until they collapse into a loose, jammy sauce.","Layer the glasses: a thick spoonful of Greek yogurt, a ribbon of berry sauce, a handful of fresh berries, and a scattering of oat clusters, then repeat.","Finish each parfait with the remaining honey and serve while the clusters still crackle against the cold yogurt."],"tip":"Assemble at the last second, because granola submerged in yogurt has the shelf life of a snowman in July."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_corn_brunch_fritters', '{"id":"zucchini_corn_brunch_fritters","name":"Zucchini Corn Fritters with Lemony Sour Cream","emoji":"🌽","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"corn_frozen","q":150},{"f":"flour","q":80},{"f":"eggs","q":2},{"f":"parmesan","q":30},{"f":"scallions","q":0.5},{"f":"olive_oil","q":30},{"f":"sour_cream","q":60},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Grate the zucchini on the coarse holes of a box grater, toss with half the salt, and let it sit in a colander for 10 minutes before squeezing it in a clean towel until no more liquid weeps out.","Stir together the wrung-out zucchini, thawed corn, flour, eggs, grated parmesan, sliced scallions, remaining salt, and pepper into a thick, scoopable batter.","Heat the olive oil in a wide skillet over medium heat until it shimmers, then drop in heaping spoonfuls of batter and flatten each into a rough disk.","Fry 3 to 4 minutes per side, resisting the flip until the edges brown and the underside releases cleanly with a lacy golden crust.","Drain the fritters briefly on a rack, then serve hot with sour cream whisked with lemon juice and a pinch of salt for swiping."],"tip":"Squeeze the zucchini like it owes you money; watery squash is the number one cause of fritter heartbreak."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('brunch_cobb_salad', '{"id":"brunch_cobb_salad","name":"Brunch Cobb Salad with Jammy Eggs","emoji":"🥗","cuisine":"American","meal":["lunch"],"diets":["gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"romaine","q":1},{"f":"eggs","q":4},{"f":"bacon","q":70},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":150},{"f":"cheddar","q":40},{"f":"olive_oil","q":20},{"f":"balsamic_vinegar","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Lower the eggs into boiling water and cook exactly 7 minutes, then plunge them into ice water so the yolks set jammy and golden rather than chalky.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until crisp, and drain it on a paper towel while it crackles.","Whisk the olive oil, balsamic vinegar, salt, and pepper into a dressing that tastes slightly too sharp on its own; the lettuce will mellow it.","Chop the romaine into ribbons, toss with half the dressing, and spread it over a platter as the base.","Arrange the halved eggs, bacon, sliced avocado, halved cherry tomatoes, and diced cheddar in neat rows across the greens.","Drizzle with the remaining dressing, grind over more pepper, and toss at the table for maximum drama."],"tip":"The tidy rows are for the photo; the violent toss immediately afterward is for the flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_quesadillas_2', '{"id":"spinach_mushroom_quesadillas_2","name":"Spinach and Mushroom Melt Quesadillas","emoji":"🍄","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"mozzarella","q":120},{"f":"garlic","q":0.2},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat most of the olive oil in a large skillet over medium-high heat and cook the sliced mushrooms undisturbed for 3 minutes, until browned on one side, before adding the sliced onion and cooking 3 minutes more.","Stir in the minced garlic, salt, and pepper, then pile in the spinach and toss for a minute until it wilts to a glossy tangle; tip everything into a bowl and let the excess moisture steam off.","Wipe the skillet, film it with the remaining oil, and lay in a tortilla over medium heat.","Scatter half the mozzarella and half the vegetable mixture over the tortilla, cap with a second tortilla, and cook 2 to 3 minutes per side, pressing gently, until each face is spotted deep gold and the cheese oozes at the seam.","Repeat with the remaining tortillas and filling, then rest each quesadilla for one minute before slicing into wedges so the molten interior does not stage an escape."],"tip":"Cook the vegetables until their liquid is gone, because steam trapped between tortillas is how quesadillas turn to laundry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_parmesan_chicken_bites', '{"id":"crispy_parmesan_chicken_bites","name":"Crispy Parmesan Chicken Bites with Charred Broccoli","emoji":"🍗","cuisine":"American","meal":["dinner"],"diets":["high-protein","low-carb"],"allergens":["dairy","gluten","eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"flour","q":30},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"olive_oil","q":20},{"f":"broccoli","q":300},{"f":"lemon","q":0.5},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 220C and line a sheet pan with foil, leaving room for the broccoli on one side.","Cut the chicken into bite-size chunks, season with salt, pepper, and paprika, then run each piece through flour, beaten egg, and finely grated parmesan so every side wears a thin, even crust.","Arrange the bites with space between them, drizzle with half the olive oil, and bake 15 to 18 minutes until deeply golden and an instant-read thermometer hits 74C.","Toss the broccoli florets with the remaining oil and a pinch of salt, spread them on the empty side of the pan, and roast until the edges char and frizzle.","Squeeze the lemon over everything while it is still sizzling and serve the bites hot, when the crust crackles loudest."],"tip":"A pale nugget is a crowded nugget — give them elbow room on the pan and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_pasta_skillet', '{"id":"cheeseburger_pasta_skillet","name":"One-Pan Cheeseburger Penne Skillet","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"penne","q":150},{"f":"cheddar","q":70},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":250},{"f":"broth","q":300},{"f":"sour_cream","q":40},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Brown the beef in a wide skillet over medium-high heat, pressing it flat and leaving it alone for 3 minutes so it develops a crusty, burger-like sear before you break it up.","Stir in the diced onion and garlic and cook until the onion turns translucent and the pan smells like a diner griddle, about 4 minutes.","Add the crushed tomatoes, broth, paprika, salt, and dry penne, scrape up the browned bits, and simmer with a lid ajar for 12 to 14 minutes, stirring now and then so nothing sticks.","When the pasta is tender and the sauce has thickened to coat the noodles, pull the pan off the heat and stir in the cheddar until it melts into glossy ribbons.","Finish each bowl with a spoonful of sour cream and a grind of black pepper."],"tip":"Resist draining every drop of beef fat — that is where the cheeseburger flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_meatball_pastina_soup', '{"id":"turkey_meatball_pastina_soup","name":"Little Turkey Meatball and Broken Noodle Soup","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"bread","q":1},{"f":"spaghetti","q":120},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":1250},{"f":"spinach","q":100},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Tear the bread into crumbs, moisten it with a splash of the broth, and knead it into the turkey with the egg, half the parmesan, oregano, salt, and pepper until just combined.","Roll the mixture into marble-size meatballs with damp hands — small enough to fit on a kid''s spoon — and chill them while you start the soup.","Warm the olive oil in a soup pot over medium heat and sweat the diced carrots, celery, and onion until they smell sweet and the onion goes glassy, about 6 minutes, adding the garlic for the last minute.","Pour in the broth, bring it to a lively simmer, and gently lower in the meatballs; let them poach undisturbed for 8 minutes until they float and firm up.","Snap the spaghetti into thumb-length pieces, stir it in, and cook until al dente, then wilt in the spinach and shower each bowl with the remaining parmesan."],"tip":"Roll the meatballs tiny even if it feels fussy — spoon-sized meatballs are the difference between a soup kids eat and a soup kids excavate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sticky_honey_soy_salmon_rice', '{"id":"sticky_honey_soy_salmon_rice","name":"Sticky Honey-Soy Salmon Rice Bowls","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice","q":140},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"broccoli","q":250},{"f":"scallions","q":0.5}],"steps":["Rinse the rice until the water runs nearly clear, then cook it while you prep everything else so it lands fluffy and hot.","Whisk the soy sauce, honey, grated garlic, and grated ginger into a glaze and cut the salmon into large cubes, patting them very dry so they sear instead of steam.","Heat the olive oil in a nonstick skillet over medium-high and sear the salmon cubes 2 minutes per side until the edges crisp and turn mahogany.","Add the broccoli florets and a splash of water, cover for 2 minutes to steam them bright green, then pour in the glaze and let it bubble until it thickens enough to coat the back of a spoon.","Spoon everything over the rice, drizzle with sesame oil, and scatter the sliced scallions on top while the glaze is still glossy."],"tip":"The glaze goes from sticky to scorched in about 30 seconds, so keep your nose on duty once it starts bubbling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_lime_shrimp_tacos', '{"id":"creamy_lime_shrimp_tacos","name":"Creamy Lime Shrimp Tacos with Crunchy Slaw","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"tortillas","q":4},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"cabbage","q":0.2},{"f":"cilantro","q":0.3},{"f":"garlic","q":0.1},{"f":"chili_powder","q":3},{"f":"cumin","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Stir the sour cream with half the lime''s juice, the grated garlic, and a pinch of salt, then shred the cabbage fine and toss it with a spoonful of the crema so it softens slightly.","Pat the shrimp bone-dry and toss them with chili powder, cumin, and salt — the mild dusting seasons without setting off any spice alarms.","Sear the shrimp in hot olive oil for 1 to 2 minutes per side, just until they blush pink and curl into loose commas; pull them the moment they are opaque.","Warm the tortillas directly over a low flame or in a dry skillet until they puff and pick up a few toasty freckles.","Pile each tortilla with slaw, shrimp, and sliced avocado, drizzle with the remaining crema, and finish with cilantro and the rest of the lime."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the relaxed-comma stage and they stay juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheesy_chicken_quesadillas', '{"id":"cheesy_chicken_quesadillas","name":"Golden Chicken and Pepper Quesadillas","emoji":"🧀","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":225},{"f":"tortillas","q":3},{"f":"cheddar","q":80},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"salsa","q":120},{"f":"sour_cream","q":40},{"f":"olive_oil","q":10},{"f":"cumin","q":2},{"f":"chili_powder","q":2},{"f":"salt","q":3}],"steps":["Dice the chicken thighs small and cook them in olive oil over medium-high heat with cumin, chili powder, and salt until browned at the edges and cooked through, about 6 minutes.","Add the sliced bell pepper and onion to the same pan and cook until they slump and pick up a little char, then scrape everything into a bowl.","Scatter cheddar over half of each tortilla, top with the chicken mixture and a little more cheese — the double layer is the glue that holds the whole operation together.","Fold and toast each quesadilla in the dry skillet over medium heat, 2 to 3 minutes per side, pressing gently until the outside is deep golden and audibly crisp.","Rest them 2 minutes so the cheese sets, then cut into wedges and serve with salsa and sour cream for dunking."],"tip":"Cheese on both sides of the filling is not indulgence, it is structural engineering."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_nuggets_rice', '{"id":"sesame_tofu_nuggets_rice","name":"Sticky Sesame Tofu Nuggets with Rice","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":140},{"f":"flour","q":30},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":25},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"green_beans","q":250},{"f":"scallions","q":0.5},{"f":"salt","q":2}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes while the rice cooks, then tear it into rough nuggets — the craggy edges fry up far crispier than neat cubes.","Toss the nuggets with flour and a pinch of salt and pan-fry them in olive oil over medium-high heat, turning until every side is golden and crunchy, about 8 minutes total.","Push the tofu aside, briefly sizzle the grated garlic and ginger until fragrant, then pour in the soy sauce and maple syrup whisked together.","Let the sauce bubble for a minute until it turns glossy and clings to the nuggets like lacquer, then kill the heat and add the sesame oil.","Steam the green beans until snappy-tender, pile everything over rice, and top with sliced scallions."],"tip":"Torn tofu is ugly on the cutting board and gorgeous in the pan — trust the rags."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hidden_veggie_penne_marinara', '{"id":"hidden_veggie_penne_marinara","name":"Hidden-Veggie Penne Marinara","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"penne","q":160},{"f":"crushed_tomatoes","q":400},{"f":"carrots","q":100},{"f":"zucchini","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"sugar","q":5},{"f":"salt","q":4}],"steps":["Grate the carrots and zucchini on the fine side of a box grater so they can vanish into the sauce without a trace.","Warm the olive oil in a deep skillet over medium heat and cook the grated vegetables with the diced onion and a pinch of salt until they nearly melt, 8 to 10 minutes, adding the garlic for the last minute.","Stir in the crushed tomatoes, oregano, and sugar and simmer gently for 15 minutes until the sauce darkens and thickens to a spoon-coating consistency; blend it smooth if your table has vegetable detectives.","Boil the penne in well-salted water until just shy of al dente, then drag it into the sauce with a splash of pasta water and toss over the heat for a minute so the sauce grips every tube.","Tear the mozzarella over the top, let it soften into molten pockets, and finish with parmesan and basil leaves."],"tip":"Blend the sauce silky and the carrots become a rumor no one can prove."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gentle_butter_chicken_curry', '{"id":"gentle_butter_chicken_curry","name":"Gentle Butter Chicken Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":250},{"f":"butter","q":15},{"f":"crushed_tomatoes","q":250},{"f":"coconut_milk","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"cumin","q":2},{"f":"honey","q":8},{"f":"rice","q":120},{"f":"cilantro","q":0.2},{"f":"salt","q":4}],"steps":["Start the rice, then melt the butter in a saucepan over medium heat and cook the finely diced onion until soft and golden at the edges, about 6 minutes.","Add the grated garlic and ginger, then the garam masala, turmeric, and cumin, and stir for 30 seconds until the spices smell toasty and bloom in the butter.","Pour in the crushed tomatoes with a good pinch of salt and simmer for 10 minutes until the sauce darkens to brick red and the raw tomato edge cooks off.","Stir in the coconut milk and honey, nestle in the bite-size chicken thigh pieces, and simmer gently for 12 to 15 minutes until the chicken is tender and the sauce is velvety.","Taste for salt, spoon over the rice, and scatter with cilantro — the sauce should be fragrant and warming, never sharp."],"tip":"The honey is not cheating, it is diplomacy — a teaspoon buys the spices safe passage past small skeptics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_pork_sweet_potato_sheet_pan', '{"id":"maple_pork_sweet_potato_sheet_pan","name":"Maple-Glazed Pork and Sweet Potato Sheet Pan","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"sweet_potatoes","q":400},{"f":"green_beans","q":200},{"f":"maple_syrup","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"paprika","q":3},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and cube the sweet potatoes into even, dice-size pieces so they cook at the same pace.","Toss the sweet potatoes with half the olive oil, the paprika, cinnamon, and a pinch of salt, spread them on a sheet pan, and give them a 15-minute head start until the edges begin to caramelize.","Season the pork loin all over with salt and pepper, whisk the maple syrup with the remaining oil and grated garlic, and brush the pork generously.","Push the potatoes aside, add the pork and the green beans, and roast 18 to 20 minutes, brushing once more with glaze, until the pork reads 63C at its thickest point.","Rest the pork for 5 minutes under foil — the juices redistribute and the glaze sets to a lacquered sheen — then slice thin against the grain."],"tip":"That 5-minute rest is not optional; carve early and you will watch your juiciness run onto the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mini_greek_beef_meatball_pitas', '{"id":"mini_greek_beef_meatball_pitas","name":"Mini Greek Beef Meatball Pitas with Quick Tzatziki","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"pita","q":2},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2},{"f":"oregano","q":3},{"f":"cumin","q":2},{"f":"onion","q":0.3},{"f":"tomato","q":1},{"f":"romaine","q":0.2},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Grate the onion straight into the beef — grating, not chopping, keeps the meatballs juicy — and knead in half the grated garlic, the oregano, cumin, salt, and pepper.","Roll the mixture into walnut-size meatballs and let them sit 5 minutes so the seasoning settles in.","Meanwhile, grate the cucumber, squeeze it hard in your fist to wring out the water, and stir it into the yogurt with the remaining grated garlic, lemon juice, and a pinch of salt.","Sear the meatballs in olive oil over medium-high heat, turning until deeply browned on all sides and cooked through, about 8 minutes; they should smell like a street-corner grill.","Warm the pitas until soft and puffed, then stuff them with shredded romaine, diced tomato, meatballs, and generous spoonfuls of tzatziki."],"tip":"Squeeze the cucumber like it owes you money, or your tzatziki becomes soup by dinnertime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tortilla_pizza_night', '{"id":"tortilla_pizza_night","name":"Crispy Tortilla Pizza Night","emoji":"🍕","cuisine":"American","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":3},{"f":"crushed_tomatoes","q":150},{"f":"mozzarella","q":120},{"f":"parmesan","q":15},{"f":"bell_pepper","q":0.5},{"f":"mushrooms","q":80},{"f":"olives","q":30},{"f":"garlic","q":0.1},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":2}],"steps":["Heat the oven to 230C and bake the bare tortillas on a sheet pan for 3 minutes so they crisp into sturdy, cracker-thin crusts.","Stir the crushed tomatoes with grated garlic, oregano, olive oil, and a pinch of salt, then spread a thin layer on each tortilla — go light, or the crust surrenders.","Scatter on the mozzarella, then let everyone rig their own with sliced bell pepper, thin mushrooms, and olive rounds.","Bake 6 to 8 minutes until the cheese bubbles and blisters and the tortilla edges turn deep brown and crackly.","Shave parmesan over the top, tear on the basil, and cut into wedges while the cheese still stretches."],"tip":"Sauce is where tortilla pizzas go to die — one thin smear keeps the crust crisp and the critics quiet."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_peanut_noodles_edamame', '{"id":"warm_peanut_noodles_edamame","name":"Warm Peanut Butter Noodles with Edamame","emoji":"🥜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":160},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"edamame_frozen","q":150},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"scallions","q":0.5}],"steps":["Boil the spaghetti in salted water, dropping the edamame into the pot for the final 2 minutes so both finish together.","While it cooks, whisk the peanut butter, soy sauce, maple syrup, sesame oil, lime juice, grated garlic, and grated ginger in a large bowl until smooth.","Thin the sauce with hot pasta water, a spoonful at a time, until it pours like heavy cream — it will seize and look broken first, then come back silky if you keep whisking.","Drain the noodles and edamame, tumble them into the bowl with the coarsely grated carrot, and toss until every strand is slicked and glossy.","Top with thin cucumber half-moons and sliced scallions and serve warm, when the sauce clings best."],"tip":"When the sauce turns to cement mid-whisk, do not panic — one more splash of hot pasta water and it forgives you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tuna_potato_cakes', '{"id":"crispy_tuna_potato_cakes","name":"Crispy Tuna Potato Cakes","emoji":"🐟","cuisine":"American","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","eggs","gluten"],"time":40,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"tuna_canned","q":200},{"f":"eggs","q":1},{"f":"flour","q":30},{"f":"scallions","q":0.5},{"f":"parsley","q":0.3},{"f":"lemon","q":0.5},{"f":"olive_oil","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Peel and chunk the potatoes, then boil them in well-salted water for 12 to 15 minutes until a fork slides in with no resistance.","Drain thoroughly and mash while still steaming, then let the mash cool for 5 minutes so it doesn''t scramble the egg.","Fold in the drained tuna, beaten egg, sliced scallions, chopped parsley, salt, and pepper until the mixture just holds together when squeezed.","Shape into six thick patties, dust each side lightly with flour, and chill them for 10 minutes to firm up.","Heat the olive oil in a heavy skillet over medium heat until it shimmers, then fry the cakes 4 minutes per side until deeply golden and crackly at the edges.","Squeeze the lemon over the hot cakes just before serving so the juice sizzles into the crust."],"tip":"Wet your hands before shaping the patties, or you will end up wearing more tuna mash than you fry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_nicoise_potato_salad_2', '{"id":"tuna_nicoise_potato_salad_2","name":"Tuna Nicoise Potato Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":400},{"f":"green_beans","q":200},{"f":"eggs","q":2},{"f":"tuna_canned","q":160},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Cut the potatoes into bite-size chunks and simmer them in salted water for 10 minutes, then drop the green beans into the same pot for the final 3 minutes until both are just tender.","Meanwhile, lower the eggs into boiling water for exactly 8 minutes, then shock them in ice water so the yolks stay fudgy at the center.","Whisk the lemon juice with the olive oil, oregano, salt, and plenty of black pepper until the dressing looks cloudy and thick.","Toss the warm potatoes and beans with half the dressing so they drink it in while they cool.","Arrange the vegetables on plates with halved cherry tomatoes, olives, flaked tuna, and quartered eggs, then spoon the remaining dressing over everything."],"tip":"Dress the potatoes while they are still warm; cold potatoes are stubborn and refuse to absorb anything."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_cabbage_fried_rice', '{"id":"tuna_cabbage_fried_rice","name":"Tuna and Cabbage Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"cabbage","q":0.3},{"f":"tuna_canned","q":140},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15}],"steps":["Cook the rice, spread it on a plate, and let it cool completely so the grains dry out and separate; day-old rice is even better.","Heat the olive oil in your largest skillet over high heat until it just smokes, then scramble the eggs for 30 seconds until barely set and push them to one side.","Add the shredded cabbage, minced garlic, and grated ginger and stir-fry for 3 to 4 minutes until the cabbage chars lightly at the edges but keeps some crunch.","Tumble in the rice and press it flat against the pan, letting it sizzle undisturbed for a full minute to build crispy bottom bits.","Fold in the drained tuna, peas, and soy sauce, tossing until everything is glossy and steaming, about 2 minutes more.","Kill the heat, drizzle with sesame oil, and shower with sliced scallions before serving straight from the pan."],"tip":"Resist the urge to stir constantly; fried rice earns its name from sitting still in a screaming-hot pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_egg_drop_cabbage_soup', '{"id":"gingery_egg_drop_cabbage_soup","name":"Gingery Egg Drop Cabbage Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":25,"servings":4,"ing":[{"f":"broth","q":1500},{"f":"cabbage","q":0.4},{"f":"eggs","q":5},{"f":"rice_noodles","q":200},{"f":"mushrooms","q":150},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"scallions","q":1},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Bring the broth to a simmer with the sliced ginger and smashed garlic, and let it steep for 5 minutes until the kitchen smells sharp and warm.","Add the sliced mushrooms and shredded cabbage and simmer for 5 to 6 minutes until the cabbage turns silky but not slumped.","Stir in the rice noodles and soy sauce and cook for 3 to 4 minutes until the noodles are tender and slippery.","Beat the eggs well, then pour them into the pot in a thin stream while stirring the soup slowly in one direction so long golden ribbons form.","Turn off the heat the moment the egg sets, then season generously with black pepper and finish with sesame oil and sliced scallions."],"tip":"Stir slowly when the eggs go in; frantic whisking gets you cloudy soup instead of those pretty silk ribbons."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('okonomiyaki_style_cabbage_pancakes', '{"id":"okonomiyaki_style_cabbage_pancakes","name":"Okonomiyaki-Style Cabbage Pancakes","emoji":"🥞","cuisine":"Asian","meal":["dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"eggs","q":3},{"f":"flour","q":100},{"f":"scallions","q":1},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"sesame_oil","q":5},{"f":"olive_oil","q":30},{"f":"salt","q":3}],"steps":["Shred the cabbage as finely as you can manage, then toss it with the salt in a big bowl and let it sit for 10 minutes to soften and release a little water.","Whisk the eggs with the flour and 60 milliliters of water until you have a thick, smooth batter with no dry pockets.","Fold the cabbage and most of the sliced scallions into the batter; it should look like far too much cabbage held together by far too little batter, which is exactly right.","Heat half the olive oil in a nonstick skillet over medium heat, add half the mixture, and press it into a thick 2-centimeter cake.","Cook 5 to 6 minutes per side until deeply browned and crisp, pressing occasionally with a spatula, then repeat with the second pancake.","Stir the soy sauce, honey, and sesame oil together and drizzle this glossy sauce over the hot pancakes with the reserved scallions."],"tip":"Flip with confidence and one decisive motion; a hesitant flip is how cabbage pancakes become cabbage scramble."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potato_onion_tortilla_2', '{"id":"spanish_potato_onion_tortilla_2","name":"Spanish Potato and Onion Tortilla","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"olive_oil","q":45},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Slice the potatoes into thin half-moons and the onion into slivers, then cook them gently in the olive oil in a nonstick skillet over medium-low heat for 15 to 18 minutes, stirring now and then, until tender but not browned.","Beat the eggs with the salt and pepper in a large bowl, then tip in the warm potatoes and onions and let them soak for 5 minutes so every slice gets coated.","Pour off all but a slick of oil from the skillet, return it to medium heat, and add the egg mixture, shaking the pan gently as the edges begin to set.","Cook for 4 to 5 minutes until the bottom is golden and the top is still wobbly, then place a large plate over the pan and flip the whole thing in one brave motion.","Slide the tortilla back into the pan and cook 3 minutes more, until the center is just set but still slightly creamy inside.","Rest it for 5 minutes, then scatter with chopped parsley and cut into fat wedges."],"tip":"A slightly runny center is the sign of a proper tortilla, not an undercooked one, so stop cooking sooner than your nerves suggest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('colcannon_with_fried_eggs', '{"id":"colcannon_with_fried_eggs","name":"Colcannon with Crispy Fried Eggs","emoji":"🥔","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":600},{"f":"cabbage","q":0.4},{"f":"butter","q":40},{"f":"milk","q":100},{"f":"eggs","q":4},{"f":"scallions","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until completely tender, then drain and let them steam dry in the colander for 2 minutes.","While the potatoes cook, melt half the butter in a wide pan and cook the shredded cabbage with a pinch of salt over medium heat for 6 to 8 minutes until sweet, tender, and browning at the edges.","Warm the milk with the remaining butter, then mash it into the potatoes until fluffy, seasoning boldly with salt and pepper.","Fold the cabbage and most of the sliced scallions through the mash and keep it warm.","Heat the olive oil in a skillet over medium-high until it ripples, crack in the eggs, and fry 2 to 3 minutes until the whites are crisp and lacy at the edges but the yolks still tremble.","Pile the colcannon into bowls, top each with fried eggs, and finish with the last of the scallions and a grind of pepper."],"tip":"The broken yolk is the sauce here, so aggressively runny eggs are not optional."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_cabbage_white_bean_stew', '{"id":"tuscan_cabbage_white_bean_stew","name":"Tuscan Cabbage and White Bean Stew","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"white_beans","q":500},{"f":"cabbage","q":0.5},{"f":"potatoes","q":300},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion, carrots, and celery with a pinch of salt for 8 minutes until soft and fragrant.","Stir in the sliced garlic and oregano and cook for 1 minute more, just until the garlic smells toasty rather than raw.","Add the crushed tomatoes, diced potatoes, and 750 milliliters of water, bring to a lively simmer, and cook for 10 minutes.","Pile in the chopped cabbage; it will look like too much, but press it down and let it collapse into the broth over the next 10 minutes.","Add the white beans and simmer gently for 10 minutes more, mashing a spoonful of beans against the side of the pot to thicken the broth to a velvety body.","Season generously with salt and black pepper, and rest the stew off the heat for 5 minutes before ladling into bowls."],"tip":"This stew is one of those dishes that tastes noticeably better tomorrow, so make peace with leftovers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_potato_black_bean_tacos', '{"id":"crispy_potato_black_bean_tacos","name":"Crispy Potato and Black Bean Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":350},{"f":"black_beans","q":250},{"f":"tortillas","q":4},{"f":"salsa","q":120},{"f":"avocado","q":0.5},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":20},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salt","q":4}],"steps":["Dice the potatoes into small 1-centimeter cubes, toss them with the olive oil, cumin, chili powder, and salt, and roast at 220C for 25 minutes, flipping once, until crusty and golden on all sides.","While the potatoes roast, warm the black beans in a small pan with a splash of water and a squeeze of lime, mashing about half of them into a rough, creamy base.","Char the tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until blistered and pliable.","Spread each tortilla with the mashed beans, then pile on the crispy potatoes while they are still crackling hot.","Top with salsa, sliced avocado, torn cilantro, and a final squeeze of lime, and eat immediately while the contrast of crisp and creamy is at its peak."],"tip":"Crowd the potatoes on the baking sheet and they will steam into sadness; give every cube its personal space."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_lime_soup', '{"id":"smoky_black_bean_lime_soup","name":"Smoky Black Bean Lime Soup","emoji":"🫘","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"black_beans","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"carrots","q":100},{"f":"crushed_tomatoes","q":200},{"f":"cumin","q":5},{"f":"chili_powder","q":6},{"f":"paprika","q":4},{"f":"olive_oil","q":45},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"sour_cream","q":100},{"f":"salt","q":5}],"steps":["Heat the olive oil in a soup pot over medium heat and sweat the diced onion, bell pepper, and carrots with a pinch of salt for 7 to 8 minutes until softened and sweet.","Add the minced garlic, cumin, chili powder, and paprika and toast for 1 minute, stirring constantly, until the spices darken and bloom in the oil.","Stir in the black beans, crushed tomatoes, and 900 milliliters of water, then simmer uncovered for 20 minutes so the flavors knit together.","Blend about a third of the soup right in the pot with an immersion blender, or mash vigorously with a potato masher, until the broth turns thick and inky while plenty of whole beans remain.","Season with salt and the juice of the lime, tasting until the soup goes from flat to bright.","Ladle into bowls and finish each with a swirl of sour cream and a flurry of chopped cilantro."],"tip":"The lime at the end is doing salt''s job in disguise, so do not skip it even if you think the soup tastes done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_cabbage_chickpea_skillet', '{"id":"gingery_cabbage_chickpea_skillet","name":"Gingery Cabbage and Chickpea Skillet","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"cabbage","q":0.4},{"f":"rice","q":130},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"turmeric","q":2},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Start the rice cooking so it finishes as the skillet does, about 15 minutes of gentle simmering under a tight lid.","Heat the olive oil in a wide skillet over medium-high heat and sizzle the cumin for 30 seconds until it crackles and smells nutty.","Add the sliced onion and cook 5 minutes until golden at the edges, then stir in the garlic, grated ginger, and turmeric for 1 fragrant minute.","Add the chopped tomatoes and cook them down for 3 to 4 minutes until they slump into a jammy base that pulls away from the pan.","Tumble in the shredded cabbage and chickpeas with the salt, toss to coat, and cook for 8 to 10 minutes until the cabbage is tender-crisp and stained golden.","Finish with garam masala, a big squeeze of lemon, and chopped cilantro, then serve heaped over the steaming rice."],"tip":"Let the cabbage catch a little on the pan bottom; those browned wisps are where the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lentil_potato_curry', '{"id":"coconut_lentil_potato_curry","name":"Coconut Lentil and Potato Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"potatoes","q":400},{"f":"coconut_milk","q":400},{"f":"crushed_tomatoes","q":200},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":8},{"f":"turmeric","q":2},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"salt","q":5}],"steps":["Warm the olive oil in a large pot over medium heat and cook the diced onion for 6 minutes until translucent and lightly golden.","Add the minced garlic, grated ginger, curry powder, and turmeric and stir for 1 minute until the spices coat the onion in a fragrant paste.","Stir in the rinsed lentils, diced potatoes, crushed tomatoes, and 800 milliliters of water, then simmer with the lid ajar for 25 minutes, stirring occasionally so nothing sticks.","When the lentils are collapsing and the potatoes yield easily to a spoon, pour in the coconut milk and simmer 5 minutes more until the curry turns thick and golden.","Wilt in the spinach off the heat, then season with salt and the juice of the lime until the richness snaps into focus.","Rest for 5 minutes before serving; the curry thickens to a spoon-coating body as it sits."],"tip":"If the curry looks too loose at minute 25, walk away for five more; lentils thicken on their own schedule, not yours."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_style_egg_curry_2', '{"id":"punjabi_style_egg_curry_2","name":"Punjabi-Style Egg Curry","emoji":"🥚","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"rice","q":140},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"garam_masala","q":4},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Boil the eggs for 9 minutes, cool them in ice water, peel, and set aside; start the rice simmering now so it lands with the curry.","Heat the olive oil in a deep skillet over medium heat and fry the finely chopped onion for 8 to 10 minutes, stirring often, until it turns a deep amber brown; this patience is the backbone of the gravy.","Add the minced garlic, grated ginger, cumin, turmeric, and chili powder and cook for 1 minute until the raw edge burns off.","Stir in the chopped tomatoes with the salt and cook 6 to 8 minutes, mashing as they soften, until the oil separates and pools at the edges of a thick masala.","Pour in 250 milliliters of water, simmer for 5 minutes, then nestle in the halved eggs yolk-side up and spoon gravy over them for 2 minutes to warm through.","Dust with garam masala, scatter with cilantro, and serve over the rice."],"tip":"The gravy is done when the oil visibly breaks away from the tomatoes; stop early and the curry tastes like hurried ketchup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_bowl_meal_prep', '{"id":"chicken_burrito_bowl_meal_prep","name":"Lime-Charred Chicken Burrito Bowls","emoji":"🍗","cuisine":"Mexican","meal":["lunch"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":2},{"f":"rice","q":140},{"f":"black_beans","q":240},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"cheddar","q":40}],"steps":["Simmer the rice in a covered pot over low heat for 15 minutes, then let it steam off the heat for 5 more so the grains turn fluffy, not gummy.","Meanwhile, pat the chicken breasts dry, season generously with salt, cumin, and chili powder, and sear in half the olive oil over medium-high heat for 6 to 7 minutes per side until deeply browned and cooked to 165F at the thickest point.","Rest the chicken 5 minutes, then slice against the grain; while it rests, char the sliced pepper and onion in the same skillet until their edges blacken and they smell sweet, about 5 minutes.","Warm the black beans with a splash of water and a pinch of salt, mashing a few against the pan for a creamier texture.","Divide rice, beans, chicken, and peppers between two containers, squeeze lime juice over everything while it is still warm, and scatter the cheddar in a corner so it stays distinct.","Cool uncovered for 20 minutes before lidding to keep condensation from turning the rice soggy."],"tip":"Squeeze the lime on day one but save the cheese-melting microwave blast for day four — acid keeps, texture doesn''t."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_rice_noodle_jars', '{"id":"sesame_tofu_rice_noodle_jars","name":"Sesame-Glazed Tofu Noodle Jars","emoji":"🥢","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice_noodles","q":150},{"f":"broccoli","q":300},{"f":"carrots","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":20},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2},{"f":"lime","q":1}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then cut into 2-centimeter cubes and sear in a dry nonstick pan over medium-high heat until every side is golden and crackly, about 8 minutes total.","Whisk the soy sauce, maple syrup, half the sesame oil, grated garlic, and the juice of the lime into a glossy dressing, then pour a third of it over the hot tofu and toss until it clings like lacquer.","Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still springy, then rinse under cold water and toss with the remaining sesame oil to prevent clumping.","Blanch the broccoli florets in salted boiling water for 90 seconds until bright green, then shock in cold water and drain thoroughly.","Layer each container with noodles, shredded carrots, broccoli, and tofu, and pack the remaining dressing in small cups on the side.","Dress each jar the morning you eat it so the noodles slurp instead of sulk."],"tip":"A dry pan and patience brown tofu better than a puddle of oil ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_couscous_tabbouleh_bowls', '{"id":"chickpea_couscous_tabbouleh_bowls","name":"Herbed Chickpea Couscous Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"chickpeas","q":240},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"onion","q":0.5}],"steps":["Pour boiling salted water over the couscous in a bowl, cover with a plate, and let it steam for 5 minutes before fluffing with a fork until every grain separates.","While it steams, dice the cucumber and tomatoes small, mince the half onion, and soak the onion in the lemon juice for 5 minutes to tame its bite.","Toast the drained chickpeas in the olive oil over medium heat for 6 to 8 minutes, shaking the pan until they blister and pop like tiny drums.","Toss the couscous with the vegetables, lemony onion, warm chickpeas, and a generous pinch of dried oregano and black pepper, tasting for salt as feta will add more.","Divide between containers and crumble the feta over the top in big craggy chunks rather than stirring it through.","Chill fully before sealing; the flavors deepen by day two like a good marinade should."],"tip":"Salt the tomatoes and let them drain in a sieve for 5 minutes, or day three''s lunch will be couscous soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_tuna_chickpea_crunch_salad', '{"id":"lemon_tuna_chickpea_crunch_salad","name":"Lemon Tuna and Chickpea Crunch Salad","emoji":"🐟","cuisine":"American","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"chickpeas","q":240},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Drain the tuna well and flake it into a large bowl in chunky pieces rather than shredding it to paste.","Rinse the chickpeas until the water runs clear, shake them dry, and lightly crush a quarter of them with a fork so they soak up dressing like sponges.","Dice the cucumber, slice the half onion paper-thin, and whisk the olive oil with the lemon juice, a pinch of salt, and plenty of cracked black pepper.","Fold the tuna, chickpeas, cucumber, and onion together with the dressing until everything glistens.","Pack the spinach in the bottom of each container and pile the tuna mixture on top so the leaves stay crisp until you shake it all together at your desk.","Refrigerate up to four days; the flavor peaks around day two when the onion mellows."],"tip":"Buy tuna packed in oil, not water — flavor insurance costs about fifty cents a can."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_turkey_black_bean_chili', '{"id":"smoky_turkey_black_bean_chili","name":"Smoky Turkey and Black Bean Chili","emoji":"🌶️","cuisine":"American","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"black_beans","q":480},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":500},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a heavy pot over medium-high heat and brown the ground turkey hard for 6 to 8 minutes, leaving it undisturbed in patches so it develops crusty, savory edges.","Add the diced onion, bell pepper, and garlic and cook until the onion turns translucent and the bottom of the pot collects a brown film, about 5 minutes.","Stir in a heaping tablespoon of chili powder, a teaspoon of paprika, and a teaspoon of cumin, toasting the spices for 30 seconds until they smell like a campfire.","Add the crushed tomatoes, drained black beans, and broth, scraping up every browned bit, then simmer uncovered for 25 to 30 minutes until the chili thickens enough to mound on a spoon.","Season with salt and a splash of anything acidic you have on hand, then ladle into four containers and cool before sealing.","Reheat gently with a spoonful of water, as the chili tightens up in the fridge like a fist."],"tip":"Chili is the rare coworker that actually improves after three days in the office fridge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_salmon_quinoa_power_bowls', '{"id":"lemon_salmon_quinoa_power_bowls","name":"Lemon-Roasted Salmon Quinoa Bowls","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"quinoa","q":150},{"f":"spinach","q":150},{"f":"cucumber","q":1},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Rinse the quinoa in a fine sieve until the water runs clear, then simmer it in double its volume of salted water for 15 minutes and rest it covered for 5 so it uncoils into little spirals.","Heat the oven to 220C, rub the salmon with half the olive oil, salt, pepper, and the zest of the lemon, and roast for 10 to 12 minutes until it flakes at the nudge of a fork but still looks blushing in the center.","Wilt the spinach in a hot pan with a teaspoon of oil for 60 seconds, just until it collapses and turns glossy, then squeeze out the excess liquid.","Dice the cucumber and whisk the remaining oil with the lemon''s juice and a pinch of salt for a bright dressing.","Fluff the quinoa into two containers, top with spinach, cucumber, and big flakes of salmon, and drizzle the dressing over everything.","Eat cold or barely warmed; blasting salmon in a microwave is how office feuds begin."],"tip":"Pull the salmon at 50C in the center — carryover heat finishes the job and the fridge forgives nothing overcooked."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_edamame_fried_rice', '{"id":"shrimp_edamame_fried_rice","name":"Shrimp and Edamame Fried Rice Boxes","emoji":"🍤","cuisine":"Asian","meal":["lunch"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","eggs","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"rice","q":160},{"f":"eggs","q":2},{"f":"edamame_frozen","q":150},{"f":"carrots","q":100},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cook the rice, spread it on a tray, and chill it for at least 20 minutes so the grains firm up and fry instead of steam.","Sear the shrimp in a screaming-hot wok with a third of the sesame oil for about 90 seconds per side until they curl into loose commas and turn pink, then set them aside.","Scramble the eggs in the same wok until just set into soft curds, push them to one side, and stir-fry the diced carrots, edamame, and minced garlic for 2 minutes until fragrant.","Add the cold rice, pressing it against the hot metal in a thin layer and letting it sizzle for a full minute before tossing, repeating until you hear steady crackling.","Return the shrimp, pour the soy sauce and remaining sesame oil around the rim of the wok so they toast on contact, and toss everything for a final minute.","Cool quickly in shallow containers and refrigerate; the rice reheats to nearly wok-fresh with a 90-second microwave blast."],"tip":"Yesterday''s rice makes today''s fried rice — freshly cooked grains just steam themselves into mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_parmesan_frittata_squares', '{"id":"garden_parmesan_frittata_squares","name":"Garden Parmesan Frittata Squares","emoji":"🍳","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":100},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"parmesan","q":40},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and warm the olive oil in an ovenproof skillet over medium heat.","Soften the diced bell pepper and onion for 5 minutes until sweet and just golden at the edges, then add the spinach and stir until it wilts and its water cooks off completely.","Whisk the eggs with half the parmesan, a good pinch of salt, and black pepper until uniformly pale yellow, then pour them over the vegetables and drag a spatula through twice to distribute everything.","Cook undisturbed on the stove for 3 minutes until the edges set, then scatter the remaining parmesan on top and transfer to the oven for 10 to 12 minutes until the center is puffed and barely jiggles.","Cool in the pan for 10 minutes, cut into squares, and pack two per container with a handful of anything green you have left over.","Eat cold, at room temperature, or gently rewarmed; frittata is agreeable like that for four solid days."],"tip":"Pull it while the middle still wobbles slightly — residual heat sets it, and rubbery eggs have no fridge redemption arc."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_chana_masala_rice', '{"id":"weeknight_chana_masala_rice","name":"Weeknight Chana Masala with Rice","emoji":"🍛","cuisine":"Indian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"rice","q":150},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Start the rice simmering in salted water so it finishes just as the curry does.","Cook the finely diced onion in the oil over medium heat for a patient 8 to 10 minutes until it turns deep amber, because pale onions make a flat masala.","Add the minced garlic with a tablespoon of curry powder, a teaspoon of cumin, and a pinch of cayenne, frying for 45 seconds until the spices darken a shade and bloom fragrantly in the oil.","Stir in the crushed tomatoes and simmer for 8 minutes, stirring until the sauce thickens and the oil separates at the edges in glossy pools.","Add the drained chickpeas with a splash of water, mash a spoonful against the pot to thicken, and simmer 10 minutes more before finishing with salt and the lemon''s juice.","Pack over rice and refrigerate; day three of this curry tastes like it hired a better chef overnight."],"tip":"The oil pooling at the edges is not a mistake — it is the masala announcing it is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_and_broccoli_rice_boxes', '{"id":"beef_and_broccoli_rice_boxes","name":"Honey-Garlic Beef and Broccoli Boxes","emoji":"🥦","cuisine":"Asian","meal":["lunch"],"diets":["high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"broccoli","q":400},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"honey","q":20},{"f":"garlic","q":0.3}],"steps":["Get the rice simmering first, covered and on low, for 15 minutes plus a 5-minute rest.","Brown the ground beef in a dry hot skillet, breaking it into rough crumbles and letting it sit untouched for 2-minute stretches so it crisps instead of stews, about 8 minutes total.","Spoon off all but a slick of fat, add the minced garlic, and cook 30 seconds until it smells sharp and toasty.","Whisk the soy sauce and honey together, pour it over the beef, and simmer 2 minutes until the sauce reduces to a sticky glaze that coats every crumble.","Steam the broccoli florets in a covered pan with a splash of water for 3 minutes until vivid green with a slight crunch, then toss with the sesame oil and a pinch of salt.","Box the rice, beef, and broccoli in neat thirds and cool before sealing; the glaze keeps the beef juicy through day four."],"tip":"Undercook the broccoli on purpose — the microwave will finish what you started whether you like it or not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_lentil_spinach_soup', '{"id":"golden_lentil_spinach_soup","name":"Golden Lentil and Spinach Soup","emoji":"🥣","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":300},{"f":"spinach","q":150},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Sweat the diced onion and carrots in the olive oil over medium heat for 6 to 8 minutes until the onion is translucent and the carrots smell sweet.","Add the minced garlic, a tablespoon of ground turmeric and cumin, and a pinch of chili flakes, stirring for 30 seconds until the pot turns golden and fragrant.","Stir in the rinsed lentils, crushed tomatoes, and 1.2 liters of water, then bring to a boil and simmer uncovered for 25 minutes until the lentils slump and begin to break apart.","Season assertively with salt only now, as salting early keeps lentils stubbornly firm.","Stir in the spinach until it wilts into silky ribbons, then finish with the juice of the lemon to wake the whole pot up.","Portion into four containers and cool before refrigerating; the soup thickens overnight, so loosen with water when reheating."],"tip":"Lemon at the end is the difference between soup and Soup — never skip the acid."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_chicken_salad_pita_kits', '{"id":"lemony_chicken_salad_pita_kits","name":"Lemony Chicken Salad Pita Kits","emoji":"🥙","cuisine":"American","meal":["lunch"],"diets":["high-protein"],"allergens":["dairy","gluten","nuts"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":2},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"onion","q":0.3},{"f":"walnuts","q":40},{"f":"lemon","q":1},{"f":"romaine","q":0.5}],"steps":["Poach the chicken breasts in barely simmering salted water for 12 to 14 minutes until they reach 165F, then rest them 5 minutes and shred into bite-sized pieces while still warm.","Toast the walnuts in a dry pan for 3 to 4 minutes, shaking often, until they smell rich and darken a shade, then chop roughly.","Stir the greek yogurt with the lemon''s zest and juice, a pinch of salt, and plenty of black pepper until smooth and tangy.","Fold the shredded chicken, finely diced cucumber, minced onion, and walnuts into the dressing until every piece is coated.","Pack the chicken salad in containers with the pitas and washed romaine leaves stored separately so nothing goes limp.","Assemble at lunchtime by stuffing each pita with leaves and a generous scoop of salad."],"tip":"The pita rides shotgun, never in the container — soggy bread has ended better lunches than yours."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_sweet_potato_black_bean_bowls', '{"id":"maple_sweet_potato_black_bean_bowls","name":"Maple-Roasted Sweet Potato and Black Bean Bowls","emoji":"🍠","cuisine":"Mexican","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":360},{"f":"quinoa","q":120},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":30},{"f":"maple_syrup","q":15},{"f":"lime","q":1}],"steps":["Heat the oven to 220C and cut the sweet potatoes into 2-centimeter cubes so they roast through evenly.","Toss the cubes and sliced bell pepper with most of the olive oil, the maple syrup, a teaspoon of paprika, and salt, then roast on a single-layer sheet pan for 25 minutes, flipping once, until the edges caramelize to a deep bronze.","Meanwhile, simmer the rinsed quinoa in double its volume of salted water for 15 minutes, then rest it covered until its little tails uncurl.","Warm the black beans with the minced onion, the remaining oil, and a pinch of cumin, simmering with a splash of water for 5 minutes until saucy.","Layer quinoa, beans, and roasted vegetables into two containers and squeeze the lime over everything while warm so it soaks in.","Cool uncovered for 15 minutes before sealing, and eat within four days at your desk with unearned smugness."],"tip":"Crowd the sheet pan and you get steamed potatoes — give every cube its personal space and you get candy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
